export const recipes=[{"id":1,"servings":4,"tipType":"pasta","pairingsType":"pasta","nutrition":{"cal":784,"prot":33,"carb":76,"fat":38,"fib":3},"origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Спагетти Карбонара","en":"Spaghetti Carbonara","ro":"Spaghete Carbonara"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["400г спагетти","200г гуанчале (или панчетта), нарезанного кубиками 1 см","4 яичных желтка + 1 целое яйцо","80г Пекорино Романо, мелко натёртого","40г Пармиджано Реджано, мелко натёртого","1 ч.л. свежемолотого чёрного перца","Мелкая морская соль для воды для пасты"],"en":["400g spaghetti","200g guanciale (or pancetta), cut into 1cm cubes","4 large egg yolks + 1 whole egg","80g Pecorino Romano, finely grated","40g Parmigiano Reggiano, finely grated","1 tsp freshly cracked black pepper","Fine sea salt for pasta water"],"ro":["400g spaghete","200g guanciale (sau pancetta), tăiat cuburi de 1 cm","4 gălbenușuri de ou mari + 1 ou întreg","80g Pecorino Romano, ras fin","40g Parmigiano Reggiano, ras fin","1 linguriță piper negru proaspăt măcinat","Sare de mare fină pentru apa de fiert"]},"howIsMade":{"ru":"Доведите 4 литра воды до бурного кипения, посолите щедро — она должна приятно солониться, как лёгкая морская вода — и варите спагетти на 2 минуты меньше, чем указано на упаковке: они дойдут в соусе. Пока вода закипает, положите гуанчале в холодную широкую сковороду на средне-слабый огонь и дайте жиру вытапливаться медленно, 8–10 минут, пока он не станет золотистым, а края хрустящими; начало в холодной сковороде предотвращает подгорание и раскрывает максимум вкуса. Пока гуанчале вытапливается, взбейте желтки и целое яйцо с обоими сырами и щедрым количеством крупно молотого перца до состояния густой, кремовой, бледно-жёлтой пасты — это соус. Прямо перед сливом отберите не менее 250 мл мутной воды от пасты и держите под рукой; растворённый крахмал делает гладкую эмульсию возможной. Снимите сковороду с гуанчале полностью с огня — этот шаг обязателен — и добавьте отцеженные, ещё дымящиеся спагетти прямо в неё; тосуйте 30 секунд, чтобы каждая нитка впитала вытопленный жир. Влейте яичный крем поверх пасты, затем добавляйте воду небольшими порциями, постоянно помешивая и складывая; остаточное тепло превращает яйцо в гладкий, блестящий соус — прекратите добавлять воду, когда соус покроет пасту, не собираясь на дне. Попробуйте на соль — гуанчале и Пекорино уже солёные — и добавьте ещё немного воды, если соус стянется при сервировке. Подавайте немедленно в тёплых тарелках, завершите тёртым Пекорино и несколькими уверенными оборотами мельницы для перца.","en":"Bring 4 litres of water to a rolling boil, salt it generously until it tastes pleasantly of the sea, then cook the spaghetti for 2 minutes less than the packet's al dente time — it will finish in the sauce. Meanwhile, place the guanciale in a cold, wide pan over medium-low heat and let the fat render slowly for 8–10 minutes until it turns golden and the edges crisp; starting from cold prevents burning and draws out maximum flavour. While the guanciale renders, beat the egg yolks and whole egg with both cheeses and a generous amount of coarsely cracked pepper until you have a thick, pale, creamy paste — this is the sauce. Just before draining, scoop out at least 250 ml of the cloudy pasta water and keep it within reach; the dissolved starch is what makes a smooth emulsion possible. Take the guanciale pan completely off the heat — this step is non-negotiable — then add the drained, steaming spaghetti directly into it and toss for 30 seconds so every strand absorbs the rendered fat. Pour the egg cream over the pasta, then add pasta water a small splash at a time, tossing and folding constantly; the residual heat sets the egg into a smooth, glossy sauce — stop adding water when the sauce coats the pasta without pooling. Taste and adjust salt — the guanciale and Pecorino are already salty — then add a little more pasta water if the sauce tightens as you plate. Serve immediately in warm bowls, finish with an extra shaving of Pecorino and several confident turns of the pepper mill."}},{"id":2,"origin":{"ru":"Румыния","en":"Romania","ro":"România"},"name":{"ru":"Суп из рубца","en":"Tripe Soup","ro":"Ciorbă de burtă"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":27,"carb":8,"fat":20,"fib":1},"ingredients":{"ru":["800г предварительно очищенного и сваренного говяжьего рубца, нарезанного полосками 5×1 см","2 средние моркови (ок. 200г)","1 корень петрушки","1 кусок корневого сельдерея (ок. 150г)","1 большая луковица","4 зубчика чеснока, растёртых","3 яичных желтка","300мл жирной сметаны (не менее 20%)","3 ст.л. белого винного уксуса","соль и белый перец по вкусу","свежие листья любистока (по желанию)"],"en":["800g pre-cleaned beef tripe, cut into 5×1 cm strips","2 medium carrots (about 200g)","1 parsley root","1 piece celeriac (about 150g)","1 large onion","4 garlic cloves, crushed","3 large eggs, yolks only","300ml full-fat sour cream (min. 20%)","3 tbsp white wine vinegar","salt and white pepper to taste","fresh lovage leaves (optional)"],"ro":["800g burtă de vită (precurățată și fiartă), tăiată fâșii de 5×1 cm","2 morcovi medii (aprox. 200g)","1 rădăcină de pătrunjel","1 bucată țelină rădăcină (aprox. 150g)","1 ceapă mare","4 căței de usturoi, pisați","3 ouă mari, gălbenușurile separate","300ml smântână grasă (min. 20%)","3 linguri oțet de vin alb","sare și piper alb după gust","frunze de leuștean proaspăt (opțional)"]},"howIsMade":{"ru":"Если рубец не предварительно очищен, тщательно натрите его крупной солью под холодной проточной водой и промойте 3–4 раза. Варите рубец в подсолённой воде на слабом огне 2–3 часа до мягкости (или 40–50 минут в скороварке). Слейте и нарежьте полосками 5×1 см. Варите морковь, корень петрушки, сельдерей и лук в 2л подсолённой воды 40 минут; вытащите овощи. Добавьте полоски рубца в бульон, варите 15 минут. Разотрите желтки со сметаной до однородности. Темперируйте: добавьте несколько половников горячего бульона в сметанную смесь, постоянно помешивая, затем влейте в кастрюлю — предотвращает свёртывание. Введите давленый чеснок, уксус, соль и белый перец. Не кипятите после добавления заправки. Подавайте горячим.","en":"If tripe is not pre-cleaned, rub thoroughly with coarse salt under cold running water and rinse 3–4 times. Boil tripe in salted water for 2–3 hours on low heat until easily pierced with a fork — or 40–50 minutes in a pressure cooker. Drain and cut into 5×1 cm strips. Simmer carrots, parsley root, celeriac, and onion in 2L salted water for 40 minutes, then discard the vegetables (or blend and return for a thicker soup). Add the tripe strips to the broth and simmer 15 minutes. Whisk egg yolks with sour cream until smooth. Temper the mixture: ladle several spoonfuls of hot broth into the cream gradually, whisking constantly before pouring it back into the pot — this prevents curdling. Stir in crushed garlic, vinegar, salt, and white pepper. Do not boil again after adding the liaison — it will curdle. Serve piping hot with chilli and garlic sauce on the side."}},{"id":3,"servings":6,"tipType":"def","pairingsType":"def","nutrition":{"cal":770,"prot":21,"carb":27,"fat":62,"fib":1},"origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Киш Лорен","en":"Quiche Lorraine","ro":"Quiche Lorraine"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ru":["200г песочного теста (1 лист), предварительно выпеченного","200г копчёных ларданов или нарезанного кубиками копчёного бекона","3 крупных яйца","300мл жирных сливок (мин. 35%)","60г Грюйера, мелко натёртого","1/4 ч. л. свежетёртого мускатного ореха","соль и белый перец по вкусу","масло для смазки формы"],"en":["200g shortcrust pastry (1 sheet), blind-baked","200g smoked lardons or diced smoked bacon","3 large eggs","300ml double cream (min. 35% fat)","60g Gruyère cheese, finely grated","1/4 tsp freshly grated nutmeg","salt and white pepper to taste","butter for greasing"],"ro":["200g aluat scurt (1 foaie), copt în alb","200g lardon afumat sau bacon afumat, tocat cuburi","3 ouă mari","300ml smântână grasă (min. 35%)","60g Gruyère, ras fin","1/4 linguriță nucșoară rasă proaspăt","sare și piper alb după gust","unt pentru uns forma"]},"howIsMade":{"ru":"Раскатайте тесто и выложите в форму для тарта 23см, плотно прижимая к краям. Охладите 20 минут. Слепо выпекайте при 180°C: застелите пергаментом, засыпьте фасолью, выпекайте 15 минут; уберите фасоль и пергамент, выпекайте ещё 5 минут до бледно-золотистого цвета. Тем временем обжарьте ларданы в сухой сковороде до золотистости, около 5 минут; слейте жир. Взбейте яйца со сливками, мускатным орехом, солью и белым перцем. Равномерно разложите ларданы по дну, залейте яичной смесью, посыпьте Грюйером. Выпекайте 25–30 минут при 180°C до застывания — центр должен слегка дрожать при встряхивании. Остудите 10 минут перед нарезкой.","en":"Roll out the pastry and line a 23cm tart tin, pressing firmly into the edges. Chill 20 minutes. Blind-bake at 180°C: line with baking paper, fill with baking beans, bake 15 minutes; remove beans and paper and bake a further 5 minutes until pale golden. Meanwhile, cook the lardons in a dry pan until golden and the fat is rendered, about 5 minutes; drain on paper. Whisk together eggs, cream, nutmeg, salt and white pepper. Scatter the lardons evenly over the base, pour the egg mixture over, and sprinkle with Gruyère. Bake 25–30 minutes at 180°C until just set — the centre should tremble slightly when you shake the tin. Cool 10 minutes before slicing. A true Quiche Lorraine contains no onion or vegetables, only lardons and the classic custard."}},{"id":4,"origin":{"ru":"Испания","en":"Spain","ro":"Spania"},"name":{"ru":"Гаспачо","en":"Gazpacho","ro":"Gazpacho"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":260,"prot":4,"carb":24,"fat":16,"fib":3},"ingredients":{"ru":["800г спелых томатов (Сан-Марцано или сливовидных), крупно нарезанных","1 красный болгарский перец (ок. 200г), без семян, нарезанный","1 средний огурец (ок. 200г), очищенный и нарезанный","2 зубчика чеснока","100г вчерашнего белого хлеба без корки","60мл оливкового масла extra virgin","2 ст.л. красного винного уксуса","1 ч.л. мелкой соли","200мл холодной воды"],"en":["800g ripe tomatoes (San Marzano or plum), roughly chopped","1 red bell pepper (about 200g), deseeded and chopped","1 medium cucumber (about 200g), peeled and chopped","2 garlic cloves","100g day-old white bread, crusts removed","60ml extra-virgin olive oil","2 tbsp red wine vinegar","1 tsp fine salt","200ml cold water"],"ro":["800g roșii coapte (San Marzano sau roșii de câmp), tăiate cuburi","1 ardei gras roșu (aprox. 200g), curățat de semințe și tocat","1 castravete mediu (aprox. 200g), curățat și tocat","2 căței de usturoi","100g pâine albă veche de o zi, fără coajă","60ml ulei de măsline extravirgin","2 linguri oțet de vin roșu","1 linguriță sare fină","200ml apă rece"]},"howIsMade":{"ru":"Разорвите хлеб на кусочки и замочите в 200мл холодной воды на 10 минут. Поместите томаты, перец, огурец и чеснок в блендер и взбивайте 1 минуту на максимальной скорости. Добавьте намоченный хлеб с водой, уксус и соль; взбейте снова. Не выключая блендер, влейте оливковое масло тонкой струйкой — эмульсификация придаёт шелковистую текстуру. Отрегулируйте соль и уксус. Процедите через мелкое сито для гладкой консистенции или оставьте рустикальным. Охладите не менее 2 часов — гаспачо при 6–8°C намного ароматнее, чем при комнатной температуре. Подавайте в охлаждённых тарелках с ниточкой оливкового масла.","en":"Tear the bread into pieces and soak in 200ml cold water for 10 minutes. Put tomatoes, pepper, cucumber, and garlic into a blender and blitz for 1 minute on high. Add the soaked bread along with its soaking water, vinegar, and salt; blitz again. With the motor running, pour olive oil in a thin stream — this emulsification gives the soup its silky texture. Taste and adjust salt and vinegar. Pass through a fine-mesh sieve for a smoother result, or leave it rustic. Chill at least 2 hours — gazpacho at 6–8°C is vastly more flavourful than at room temperature. Serve in chilled bowls with a drizzle of olive oil on top."}},{"id":5,"origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Суши","en":"Sushi","ro":"Sushi"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":430,"prot":15,"carb":51,"fat":14,"fib":3},"ingredients":{"ru":["2 стакана японского круглозёрного риса для суши","2½ стакана воды","60мл рисового уксуса","1 ст.л. сахара","1 ч.л. соли","4 листа нори (20×18 см)","200г филе лосося категории сашими, тонко нарезанного","1 спелый авокадо, нарезанный","½ маленького огурца, соломкой","соевый соус для подачи","васаби и маринованный имбирь (гари) для подачи"],"en":["2 cups Japanese short-grain sushi rice","2½ cups water","60ml rice vinegar","1 tbsp sugar","1 tsp salt","4 nori sheets (20×18 cm)","200g sashimi-grade salmon fillet, thinly sliced","1 ripe avocado, sliced","½ small cucumber, julienned","soy sauce to serve","wasabi and pickled ginger (gari) to serve"],"ro":["2 căni orez japonez pentru sushi (bob scurt)","2½ căni apă","60ml oțet de orez","1 lingură zahăr","1 linguriță sare","4 foi nori (20×18 cm)","200g file de somon sashimi-grade, feliat subțire","1 avocado copt, feliat","½ castravete mic, julienizat","sos de soia pentru servire","wasabi și ghimbir murat (gari) pentru servire"]},"howIsMade":{"ru":"Отварите рис: промойте холодной водой до прозрачности (4–5 раз). Залейте рис 2½ стаканами воды, доведите до кипения, накройте, минимальный огонь 12 минут, 10 минут настаивать. Растворите уксус, сахар и соль в маленькой миске. Разложите рис на большом подносе и вмешайте заправку движениями разрезания — не мешайте по кругу, иначе рис размякнет. Накройте влажной тканью, остудите до комнатной температуры. Положите нори блестящей стороной вниз на бамбуковый коврик. Распределите рис на ¾ нори (3 см пустые у дальнего края). Разложите лосось, авокадо и огурец в ряд. Плотно сверните, запечатайте несколькими зёрнами риса. Нарежьте влажным острым ножом на 8 кружков. Подавайте с соевым соусом, васаби и гари.","en":"Cook the rice: rinse under cold water until the water runs clear (4–5 washes). Bring rice and 2½ cups water to a boil, cover, reduce to lowest heat for 12 minutes, then rest off heat 10 minutes. Dissolve vinegar, sugar, and salt in a small bowl. Spread cooked rice onto a large tray and fold the dressing in using a wooden paddle with cutting motions — do not stir in circles or the rice turns mushy. Cover with a damp cloth and cool to room temperature (not fridge). Lay a nori sheet shiny-side down on the bamboo mat. Spread seasoned rice over ¾ of the nori (leaving a 3 cm gap at the far edge). Arrange salmon, avocado, and cucumber along the near edge in a single row. Roll firmly from the near edge, pressing as you go; seal the bare nori with a few rice grains. Slice with a sharp, lightly wet knife into 8 rounds. Serve at once with soy sauce, wasabi, and pickled ginger."}},{"id":7,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":775,"prot":40,"carb":39,"fat":49,"fib":1},"origin":{"ru":"США","en":"USA","ro":"SUA"},"name":{"ru":"Чизбургер","en":"Cheeseburger","ro":"Cheeseburger"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500г говяжьего фарша (80% мяса, 20% жира)","4 булочки бриошь, разрезанные пополам и поджаренные","4 ломтика американского чеддера","2 спелых помидора, нарезанных толстыми кружками","4 крупных листа салата айсберг","1 средняя луковица, нарезанная тонкими кольцами","2 ст. л. соуса бургер (майонез, кетчуп, горчица, рубленые маринованные огурцы)","соль и свежемолотый чёрный перец"],"en":["500g ground beef (80% lean, 20% fat)","4 brioche buns, halved and toasted","4 slices American cheddar","2 ripe tomatoes, thickly sliced","4 large iceberg lettuce leaves","1 medium onion, thinly sliced into rings","2 tbsp burger sauce (mayo, ketchup, mustard, diced pickles)","salt and freshly ground black pepper"],"ro":["500g carne de vită tocată (80% carne / 20% grăsime)","4 chifle brioche, tăiate și prăjite","4 felii cheddar american","2 roșii coapte, tăiate felii groase","4 frunze de salată iceberg","1 ceapă medie, tăiată rondele subțiri","2 linguri sos de burger (maioneză, ketchup, muștar, castraveți murați tocați)","sare și piper negru proaspăt măcinat"]},"howIsMade":{"ru":"Приправьте фарш солью и перцем, разделите на четыре шарика по 125г. Раскалите чугунную сковороду на максимальном огне до лёгкого дыма. Прижмите каждый шарик прямо на сковороде твёрдой лопаткой — техника smash создаёт хрустящую корочку за 90 секунд. Переверните, положите ломтик чеддера, накройте на 30 секунд для расплавления. Поджарьте булочки срезом вниз 1 минуту. Собирайте: нижняя булочка, соус, салат, помидор, котлета с расплавленным сыром, луковые кольца, верхняя булочка. Подавайте сразу.","en":"Season the ground beef with salt and pepper and divide into four 125g balls. Heat a cast-iron skillet over high heat until smoking. Press each ball flat on the pan with a firm spatula — the smash technique creates a crisp, lacy crust in about 90 seconds. Flip, add a slice of cheddar, and cover for 30 seconds to melt. Toast the buns cut-side down for 1 minute. Assemble: bottom bun, burger sauce, lettuce, tomato, patty with melted cheese, onion rings, top bun. Serve immediately — the crust fades fast."}},{"id":8,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":390,"prot":26,"carb":32,"fat":18,"fib":4},"origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Такос","en":"Tacos","ro":"Tacos"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500г говяжьего фарша (80% мяса)","8 маленьких кукурузных тортилий (15см)","1 ч. л. молотого тмина","1 ч. л. копчёной паприки","2 спелых помидора, мелко нарезанных (для пико-де-гальо)","1 маленькая белая луковица, мелко нарезанная","свежая кинза, дольки лайма, сальса и сметана для подачи","соль и чёрный перец"],"en":["500g ground beef (80% lean)","8 small corn tortillas (15cm)","1 tsp ground cumin","1 tsp smoked paprika","2 ripe tomatoes, finely diced (for pico de gallo)","1 small white onion, finely diced","fresh cilantro, lime wedges, salsa, and sour cream for serving","salt and black pepper"],"ro":["500g carne de vită tocată (80% carne)","8 tortilla mici din porumb (15cm)","1 linguriță chimion măcinat","1 linguriță boia afumată","2 roșii coapte, tocate mărunt (pico de gallo)","1 ceapă albă mică, tocată mărunt","coriandru proaspăt, felii de lime, sos salsa și smântână pentru servit","sare și piper negru"]},"howIsMade":{"ru":"Обжарьте говяжий фарш на сухой сковороде на сильном огне, разламывая его на мелкие кусочки — поначалу не мешайте слишком часто, чтобы образовалась корочка. Слейте лишний жир. Добавьте тмин, паприку, соль и перец; готовьте ещё 2 минуты. Подогрейте тортильи: держите прямо над газовым огнём по 15 секунд с каждой стороны до появления пузырей, или поджарьте без масла на горячей сковороде. Пико-де-гальо: смешайте помидор и лук с щепоткой соли и соком лайма. Складывайте по две тортильи на каждый тако. Выложите мясо, пико-де-гальо, кинзу, сок лайма, сальсу или сметану.","en":"Brown the ground beef in a dry skillet over high heat, breaking it into fine crumbles — do not stir too much at first so the meat develops colour. Drain excess fat. Add cumin, paprika, salt and pepper; cook 2 more minutes. Warm the corn tortillas: hold them directly over a gas flame for 15 seconds per side until they blister and char lightly, or dry-toast in a hot pan. For quick pico de gallo: toss diced tomato with diced onion, a pinch of salt, and a squeeze of lime. Double-stack two tortillas per taco to prevent splitting. Spoon on the seasoned beef, then top with pico de gallo, cilantro leaves, a squeeze of lime, and salsa or sour cream to taste."}},{"id":9,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":375,"prot":23,"carb":11,"fat":19,"fib":3},"origin":{"ru":"Индия","en":"India","ro":"India"},"name":{"ru":"Куриный карри","en":"Chicken Curry","ro":"Curry de pui"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["800г куриных голеней и бедер на кости без кожи","2 большие луковицы (ок. 350г), мелко нарезанные","400г консервированных измельчённых томатов","1 ст.л. имбирной пасты (кусок 3 см)","1 ст.л. чесночной пасты (5 зубчиков)","3 ст.л. подсолнечного масла","1 ч.л. семян тмина","2 ч.л. молотого кориандра","1 ч.л. гарам масала","½ ч.л. куркумы","1 ч.л. кашмирского перца (или сладкой паприки)","200мл жирного йогурта, взбитого","Соль по вкусу","Свежая кинза для подачи"],"en":["800g bone-in chicken thighs and drumsticks, skin removed","2 large onions (about 350g), finely diced","400g canned crushed tomatoes","1 tbsp ginger paste (from a 3cm piece)","1 tbsp garlic paste (from 5 cloves)","3 tbsp sunflower oil","1 tsp cumin seeds","2 tsp ground coriander","1 tsp garam masala","½ tsp turmeric","1 tsp Kashmiri chili powder (or mild paprika)","200ml full-fat yogurt, whisked","Salt to taste","Fresh coriander leaves to finish"],"ro":["800g pulpe de pui cu os, fără piele","2 cepe mari (aprox. 350g), tăiate mărunt","400g roșii tocate din conservă","1 lingură pastă de ghimbir (bucată de 3 cm)","1 lingură pastă de usturoi (5 căței)","3 linguri ulei de floarea-soarelui","1 linguriță semințe de chimen","2 lingurițe coriandru măcinat","1 linguriță garam masala","½ linguriță turmeric","1 linguriță praf de ardei Kashmiri (sau boia dulce)","200ml iaurt gras, bătut","Sare după gust","Frunze de coriandru proaspăt pentru finisare"]},"howIsMade":{"ru":"Разогрейте масло в толстостенной кастрюле на средне-сильном огне. Добавьте тмин и дайте шипеть 30 секунд. Добавьте лук и жарьте, часто помешивая, 15–18 минут до глубоко золотистого цвета — карамелизация создаёт основу вкуса. Добавьте имбирную и чесночную пасту; готовьте 2 минуты. Добавьте кориандр, куркуму и кашмирский перец; помешивайте 1 минуту. Влейте томаты и готовьте на среднем огне, помешивая, 10 минут, пока масло не отойдёт на края. Добавьте курицу, покройте масалой и обжарьте 5 минут. Снимите с огня; добавляйте взбитый йогурт по ложке, чтобы не свернулся. Верните на средний огонь, накройте и тушите 25–30 минут до легкого отделения мяса от кости. Добавьте гарам масала, посолите и подавайте с кинзой, рисом басмати или наан.","en":"Heat oil in a heavy-bottomed pot over medium-high heat. Add cumin seeds and let sizzle 30 seconds. Add diced onions and fry, stirring often, for 15–18 minutes until deep golden — this caramelisation builds the flavour base. Stir in ginger and garlic paste; cook 2 minutes until the raw smell disappears. Add ground coriander, turmeric, and Kashmiri chili; stir 1 minute. Pour in crushed tomatoes and cook over medium heat, stirring often, for 10 minutes until the oil separates to the sides. Add chicken pieces, coat in masala, and sear 5 minutes. Remove from heat; stir in whisked yogurt one tablespoon at a time to prevent curdling. Return to medium-low heat, cover, and simmer 25–30 minutes until the chicken falls easily from the bone. Stir in garam masala, adjust salt, finish with fresh coriander. Serve with basmati rice or naan."}},{"id":10,"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":215,"prot":4,"carb":19,"fat":13,"fib":4},"origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Рататуй","en":"Ratatouille","ro":"Ratatouille"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1 средний баклажан (около 300г), нарезанный кубиками 2см","2 средних кабачка (около 400г), нарезанных кружками 2см","1 красный болгарский перец, очищенный и нарезанный","1 жёлтый болгарский перец, очищенный и нарезанный","4 спелых сливовых помидора (около 400г), грубо нарезанных","1 большая луковица, нарезанная","4 зубчика чеснока, тонко нарезанных","4 ст. л. оливкового масла первого отжима","1 ч. л. сушёных прованских трав","соль и чёрный перец по вкусу"],"en":["1 medium aubergine (about 300g), cut into 2cm cubes","2 medium courgettes (about 400g), cut into 2cm rounds","1 red bell pepper, deseeded and diced","1 yellow bell pepper, deseeded and diced","4 ripe plum tomatoes (about 400g), roughly chopped","1 large onion, diced","4 garlic cloves, thinly sliced","4 tbsp extra-virgin olive oil","1 tsp dried herbes de Provence","salt and black pepper to taste"],"ro":["1 vânătă medie (aprox. 300g), cuburi de 2cm","2 dovlecei medii (aprox. 400g), rondele de 2cm","1 ardei gras roșu, curățat și tocat","1 ardei gras galben, curățat și tocat","4 roșii prune coapte (aprox. 400g), tocate grosier","1 ceapă mare, tocată","4 căței de usturoi, feliați subțire","4 linguri ulei de măsline extravirgin","1 linguriță herbes de Provence uscate","sare și piper negru după gust"]},"howIsMade":{"ru":"Слегка посолите кубики баклажана и оставьте на 15 минут, чтобы вышла горечь, затем обсушите. Разогрейте 1 ст. л. масла на широкой сковороде на среднем огне. Обжарьте баклажан до лёгкой золотистости, около 5 минут; выньте и отложите. Так же обжарьте кабачки (3 минуты), затем перцы (4 минуты). В той же сковороде разогрейте оставшееся масло и пассеруйте лук 5 минут до прозрачности. Добавьте чеснок, готовьте 1 минуту. Добавьте помидоры и травы; тушите 10 минут, пока помидоры не разойдутся. Верните все овощи, аккуратно перемешайте, приправьте и тушите без крышки 15–20 минут. Подавайте тёплым или при комнатной температуре.","en":"Lightly salt the aubergine cubes and set aside for 15 minutes to draw out bitterness, then pat dry. Heat 1 tbsp oil in a wide pan over medium-high heat. Saute the aubergine until lightly golden, about 5 minutes; remove and set aside. Saute the courgettes 3 minutes, then the peppers 4 minutes; remove each in turn. In the same pan, heat the remaining oil and sweat the onion until soft and translucent, 5 minutes. Add garlic and cook 1 minute. Add the tomatoes and herbes de Provence; cook 10 minutes until the tomatoes collapse into a sauce. Return all vegetables, stir gently, season with salt and pepper, and simmer uncovered 15–20 minutes until everything is tender and fragrant. Serve warm or at room temperature — ratatouille tastes even better the next day."}},{"id":11,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Сувлаки","en":"Souvlaki","ro":"Souvlaki"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["700г свиной лопатки, нарезанной кубиками по 3 см","3 ст. л. оливкового масла первого отжима","сок 1 лимона","3 зубчика чеснока, раздавленных","2 ч. л. сушёного греческого орегано","1 ч. л. сушёного тимьяна","соль и свежемолотый чёрный перец","деревянные или металлические шпажки"],"en":["700g pork shoulder, cut into 3cm cubes","3 tbsp extra-virgin olive oil","juice of 1 lemon","3 garlic cloves, crushed","2 tsp dried Greek oregano","1 tsp dried thyme","salt and freshly ground black pepper","wooden or metal skewers"],"ro":["700g ceafă de porc, tăiată cuburi de 3 cm","3 linguri ulei de măsline extravirgin","sucul de la 1 lămâie","3 căței de usturoi, zdrobiți","2 linguriță oregano grecesc uscat","1 linguriță cimbru uscat","sare și piper negru proaspăt măcinat","frigărui de lemn sau metal"]},"howIsMade":{"ru":"Смешайте оливковое масло, лимонный сок, раздавленный чеснок, орегано и тимьян в миске. Добавьте кубики свинины, хорошо перемешайте, накройте и уберите в холодильник минимум на 1 час, лучше на ночь. Деревянные шпажки замочите в воде на 30 минут. Нанизайте по 5-6 кубиков на шпажку, оставляя небольшие промежутки. Жарьте на сильном огне (идеально — на углях) 8-10 минут, переворачивая каждые 2 минуты, до появления румяной корочки и прозрачного сока. Подавайте сразу в тёплой пите с дзадзики, помидорами и красным луком.","en":"Combine olive oil, lemon juice, crushed garlic, oregano and thyme in a bowl. Add the pork cubes, toss to coat thoroughly, cover and refrigerate for at least 1 hour — overnight is better. If using wooden skewers, soak them in water for 30 minutes. Thread 5-6 cubes per skewer, leaving small gaps between pieces. Grill over high heat (charcoal is ideal) for 8-10 minutes total, turning every 2 minutes, until the outside is charred and the juices run clear. The meat should be firm but not dry — pull it at 70°C internal. Serve immediately in warm pita with tzatziki, sliced tomatoes and red onion."},"nutrition":{"cal":420,"prot":35,"carb":3,"fat":29,"fib":0}},{"id":12,"origin":{"ru":"Индия","en":"India","ro":"India"},"name":{"ru":"Дал","en":"Dhal","ro":"Dhal"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"veg","ingredients":{"ru":["300г сушёной красной чечевицы (масур дал)","2 ст.л. ги (или растительного масла)","1 большая луковица, мелко нарезанная","4 зубчика чеснока, измельчённых","2 см свежего имбиря, натёртого","400г консервированных рубленых томатов (или 3 свежих крупных)","1 ч.л. молотой куркумы","1 ч.л. молотого тмина","1 ч.л. молотого кориандра","½ ч.л. гарам масала","½ ч.л. молотого красного перца","400мл кокосового молока (или воды)","соль по вкусу","свежий кориандр и дольки лимона для подачи"],"en":["300g dried red lentils (masoor dal)","2 tbsp ghee (or vegetable oil)","1 large onion, finely chopped","4 garlic cloves, minced","2 cm fresh ginger, grated","400g canned chopped tomatoes (or 3 large fresh tomatoes)","1 tsp ground turmeric","1 tsp ground cumin","1 tsp ground coriander","½ tsp garam masala","½ tsp ground red chilli","400ml coconut milk (or water)","salt to taste","fresh coriander and lemon wedges to serve"],"ro":["300g linte roșie uscată (masoor dal)","2 linguri ghee (sau ulei vegetal)","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","2 cm ghimbir proaspăt, ras","400g roșii din conservă, tăiate cuburi (sau 3 roșii mari proaspete)","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","1 linguriță coriandru măcinat","½ linguriță garam masala","½ linguriță ardei iute roșu măcinat","400ml lapte de nucă de cocos (sau apă)","sare după gust","coriandru proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"ru":"Промойте красную чечевицу холодной водой 3–4 раза до прозрачности воды. В большой кастрюле растопите ги на среднем огне. Обжаривайте лук, часто помешивая, 10–12 минут до золотистого мягкого состояния — не пропускайте этот шаг, карамелизованная основа — фундамент вкуса. Добавьте чеснок и имбирь, жарьте 1 минуту. Всыпьте куркуму, тмин, кориандр и чили, помешивайте 30 секунд до появления аромата. Добавьте томаты, тушите 3–4 минуты. Положите чечевицу и кокосовое молоко (или воду), тушите без крышки на слабом огне 20–25 минут, помешивая, пока чечевица не разварится и дал не станет кремовым. Вмешайте гарам масала, откорректируйте соль. Подавайте с рисом или лепёшкой, свежим кориандром и соком лимона.","en":"Rinse the red lentils under cold water 3–4 times until the water runs clear. In a large pan melt ghee over medium heat. Add the onion and cook, stirring often, for 10–12 minutes until golden and soft — do not skip this step, the caramelised base is the backbone of flavour. Add garlic and ginger, fry 1 minute. Add turmeric, cumin, coriander, and red chilli, stir 30 seconds until fragrant. Add tomatoes, simmer 3–4 minutes until slightly thickened. Add the rinsed lentils and coconut milk (or water), reduce to a gentle simmer and cook uncovered for 20–25 minutes, stirring occasionally, until lentils collapse and the dhal is thick and creamy. Stir in garam masala and adjust salt. Thin with a little hot water if needed. Serve with rice or naan, topped with fresh coriander and a squeeze of lemon."},"nutrition":{"cal":490,"prot":21,"carb":56,"fat":19,"fib":13}},{"id":13,"timeMins":{"total":20,"active":20},"servings":4,"tipType":"def","pairingsType":"veg","origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Гуакамоле","en":"Guacamole","ro":"Guacamole"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["3 спелых авокадо Хасс","сок 2 лаймов (около 3 ст. л.)","1 маленькая красная луковица, мелко нарезанная","2 спелых помидора Рома, без семян и нарезанных","1 маленький халапеньо, мелко нарезанный (без семян для слабой остроты)","15г свежей кинзы, крупно нарезанной","1/2 ч. л. мелкой морской соли, ещё по вкусу"],"en":["3 ripe Hass avocados","juice of 2 limes (about 3 tbsp)","1 small red onion, finely diced","2 ripe Roma tomatoes, deseeded and diced","1 small jalapeño, finely chopped (seeds removed for mild heat)","15g fresh cilantro, roughly chopped","1/2 tsp fine sea salt, plus more to taste"],"ro":["3 avocado Hass coapte","sucul a 2 lime (aprox. 3 linguri)","1 ceapă roșie mică, tocată mărunt","2 roșii Roma coapte, curățate de semințe și tocate","1 ardei jalapeno mic, tocat fin (fără semințe pentru mai puțin iute)","15g coriandru proaspăt, tocat grosier","1/2 linguriță sare fină de mare"]},"howIsMade":{"ru":"Разрежьте авокадо пополам, удалите косточку и выньте мякоть ложкой. Сразу добавьте сок лайма — кислота замедляет потемнение. Разомните вилкой до желаемой текстуры: крупными кусочками или почти гладко. Добавьте лук, помидор, халапеньо и кинзу. Приправьте солью. Попробуйте и отрегулируйте лайм и соль по вкусу. Для хранения прижмите пищевую плёнку прямо к поверхности, чтобы исключить контакт с воздухом — сок лайма защищает лучше, чем косточка. Употребите в течение 2 часов для лучшего цвета и вкуса.","en":"Halve and stone the avocados. Scoop the flesh into a bowl and add the lime juice immediately — the acid slows browning. Mash with a fork to your preferred texture: very chunky or almost smooth. Fold in the diced onion, tomato, jalapeño, and cilantro. Season with salt. Taste and adjust lime and salt. To store, press cling film directly onto the surface of the guacamole to exclude air — the lime juice prevents browning far better than the avocado stone. Serve within 2 hours for best colour and flavour."},"nutrition":{"cal":200,"prot":3,"carb":13,"fat":17,"fib":9}},{"id":14,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ru":"Россия","en":"Russia","ro":"Rusia"},"name":{"ru":"Борщ","en":"Borscht","ro":"Bors"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["500г сырой свёклы, очищенной и крупно натёртой","300г белокочанной капусты, тонко нашинкованной","300г восковых картофелин, нарезанных кубиками 2 см","2 средние моркови, нарезанные соломкой","1 крупная луковица, нарезанная","3 зубчика чеснока, измельчённых","2 ст.л. томатной пасты","1,5 л говяжьего или овощного бульона","2 ст.л. подсолнечного масла","1 ст.л. яблочного уксуса (для фиксации цвета)","Соль и чёрный перец по вкусу","Сметана и свежий укроп для подачи"],"en":["500g raw beetroot, peeled and coarsely grated","300g white cabbage, thinly shredded","300g waxy potatoes, cut into 2cm cubes","2 medium carrots, julienned","1 large onion, diced","3 garlic cloves, minced","2 tbsp tomato paste","1.5 litres beef or vegetable broth","2 tbsp sunflower oil","1 tbsp apple cider vinegar (to fix the deep red colour)","Salt and black pepper to taste","Sour cream and fresh dill to serve"],"ro":["500g sfeclă roșie crudă, curățată și rasă grosier","300g varză albă, feliată subțire","300g cartofi waxy, cuburi de 2 cm","2 morcovi medii, julien","1 ceapă mare, tocată","3 căței de usturoi, tocați","2 linguri pastă de roșii","1,5 litri supă de vită sau legume","2 linguri ulei de floarea-soarelui","1 lingură oțet de mere (pentru culoare vie)","Sare și piper după gust","Smântână și mărar proaspăt pentru servire"]},"howIsMade":{"ru":"Разогрейте масло на среднем огне, добавьте лук и морковь и обжарьте 7–8 минут до мягкости. Добавьте томатную пасту и чеснок; готовьте 2 минуты. Добавьте тёртую свёклу и уксус; готовьте 5 минут — уксус фиксирует глубокий красный цвет. Влейте горячий бульон и добавьте картофель. Доведите до кипения, уменьшите огонь и варите 15 минут. Добавьте капусту и варите ещё 10 минут до мягкости. Посолите, поперчите, при необходимости добавьте уксус. Подавайте в глубоких тарелках со сметаной и свежим укропом.","en":"Heat oil over medium heat, add onion and carrots, and sauté 7–8 minutes until softened. Stir in tomato paste and garlic; cook 2 minutes. Add the grated beetroot and apple cider vinegar; cook 5 minutes — the vinegar fixes the deep red colour. Pour in the hot broth and add potatoes. Bring to a boil, reduce heat and simmer 15 minutes. Add shredded cabbage and simmer another 10 minutes until the cabbage is just tender and the potatoes are soft but not falling apart. Taste for salt, add pepper and extra vinegar if the soup needs brightness. Ladle into deep bowls and top with a generous spoonful of sour cream and fresh chopped dill."},"nutrition":{"cal":260,"prot":5,"carb":28,"fat":9,"fib":7}},{"id":15,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"ru":"США","en":"USA","ro":"SUA"},"name":{"ru":"Панкейки","en":"Pancakes","ro":"Clătite americane"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ru":["200г пшеничной муки","2 ч. л. разрыхлителя","1 ст. л. сахара","1/2 ч. л. соли","240мл цельного молока","2 крупных яйца","30г растопленного сливочного масла, плюс ещё для сковороды","1 ч. л. экстракта ванили"],"en":["200g plain flour","2 tsp baking powder","1 tbsp sugar","1/2 tsp salt","240ml whole milk","2 large eggs","30g melted butter, plus extra for the pan","1 tsp vanilla extract"],"ro":["200g făină albă","2 linguriță praf de copt","1 lingură zahăr","1/2 linguriță sare","240ml lapte integral","2 ouă mari","30g unt topit, plus extra pentru tigaie","1 linguriță extract de vanilie"]},"howIsMade":{"ru":"В большой миске смешайте муку, разрыхлитель, сахар и соль. В другой миске взбейте молоко, яйца, растопленное масло и ваниль. Вылейте жидкие ингредиенты к сухим и аккуратно перемешайте лопаткой — несколько комочков нормально и даже желательно; чрезмерное перемешивание активирует глютен и сделает панкейки жёсткими. Оставьте тесто отдохнуть на 5 минут. Разогрейте антипригарную сковороду на среднем огне, слегка смажьте маслом и удалите излишки. Вылейте по одному половнику (около 80мл) теста. Жарьте 2-3 минуты, пока на поверхности не появятся пузыри и края не станут сухими. Переверните и жарьте ещё 1-2 минуты. Подавайте немедленно с кленовым сиропом, сливочным маслом и свежими фруктами.","en":"In a large bowl, whisk together flour, baking powder, sugar and salt. In a second bowl, whisk milk, eggs, melted butter and vanilla. Pour the wet ingredients into the dry and fold gently with a spatula — a few lumps are fine and even desirable; over-mixing develops gluten and makes the pancakes tough. Rest the batter 5 minutes: the baking powder bubbles will rise to the surface. Heat a non-stick pan over medium heat, add a small knob of butter and wipe away the excess. Pour one ladle (about 80ml) of batter per pancake. Cook 2-3 minutes until bubbles break on the surface and the edges look set and dry. Flip and cook 1-2 minutes more until golden on the underside. Serve immediately — pancakes deflate as they cool. Top with real maple syrup, fresh butter and seasonal fruit."},"nutrition":{"cal":340,"prot":10,"carb":45,"fat":13,"fib":1}},{"id":16,"servings":4,"tipType":"def","pairingsType":"fish","origin":{"ru":"Таиланд","en":"Thailand","ro":"Thailanda"},"name":{"ru":"Пад Тай","en":"Pad Thai","ro":"Pad Thai"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["200г сухой плоской рисовой лапши (замочить на 30 мин)","200г сырых очищенных креветок","2 яйца","2 ст.л. пасты из тамаринда","2 ст.л. рыбного соуса","1 ст.л. устричного соуса","1 ч.л. пальмового или коричневого сахара","2 ст.л. нейтрального масла","2 зубчика чеснока, измельчённых","1 лук-шалот, тонко нарезанный","100г ростков сои","3 перья зелёного лука, нарезанных по 3см","3 ст.л. жареного арахиса, грубо измельчённого","1 лайм, дольками","Сушёный чили по вкусу"],"en":["200g dried flat rice noodles (soaked 30 min)","200g raw medium prawns, peeled and deveined","2 eggs","2 tbsp tamarind paste","2 tbsp fish sauce","1 tbsp oyster sauce","1 tsp palm sugar or brown sugar","2 tbsp neutral oil","2 cloves garlic, minced","1 shallot, thinly sliced","100g bean sprouts","3 spring onions, cut into 3cm pieces","3 tbsp roasted peanuts, roughly crushed","1 lime, cut into wedges","Dried chili flakes to serve"],"ro":["200g tăiței lat de orez (înmuiați 30 min)","200g creveți cruzi, curățați","2 ouă","2 linguri pastă de tamarind","2 linguri sos de pește","1 lingură sos de stridii","1 linguriță zahăr de palmier","2 linguri ulei neutru","2 căței de usturoi, tocați","1 șalotă, feliată","100g germeni de fasole","3 cepe verzi, tăiate 3cm","3 linguri alune prăjite, zdrobite","1 lime, pentru servire","Fulgi de ardei iute, după gust"]},"howIsMade":{"ru":"Замочите рисовую лапшу в холодной воде на 30 минут, слейте воду. Смешайте тамариндовую пасту, рыбный соус, устричный соус и сахар в маленькой миске — это соус. Нагрейте масло в воке на очень сильном огне до лёгкого дымка; обжарьте чеснок и шалот 30 секунд, добавьте креветки и готовьте 2 минуты до розового цвета. Отодвиньте всё в сторону, разбейте яйца и слегка перемешайте 30 секунд, затем соедините с креветками. Добавьте отцеженную лапшу и полейте соусом; постоянно помешивайте 2–3 минуты, пока лапша не впитает соус и не начнёт слегка карамелизоваться по краям. Снимите с огня, добавьте ростки сои и зелёный лук; подавайте немедленно с дроблёным арахисом, долькой лайма и хлопьями чили.","en":"Soak rice noodles in cold water for 30 minutes, then drain. Mix tamarind paste, fish sauce, oyster sauce and sugar in a small bowl to make the sauce. Heat oil in a wok over very high heat until just smoking; fry garlic and shallot for 30 seconds, add prawns and cook 2 minutes until just pink. Push everything to the side, crack in eggs and scramble lightly for 30 seconds, then toss everything together. Add drained noodles and pour the sauce over; toss constantly for 2–3 minutes until the noodles absorb the sauce and begin to caramelise at the edges. Remove from heat, fold in bean sprouts and spring onions; serve immediately topped with crushed peanuts, a lime wedge and chili flakes to taste."},"nutrition":{"cal":380,"prot":18,"carb":40,"fat":13,"fib":2}},{"id":17,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Германия","en":"Germany","ro":"Germania"},"name":{"ru":"Шницель","en":"Schnitzel","ro":"Schnitzel"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["4 бескостных свиных шницеля (около 150г каждый), зачищенных","80г пшеничной муки, приправленной солью и перцем","2 крупных яйца, взбитых","150г мелких сухих сухарей (Semmelbrösel)","200мл нейтрального масла (подсолнечное или рапсовое) для жарки","1 лимон, нарезанный дольками для подачи","соль и белый перец"],"en":["4 boneless pork loin chops (about 150g each), trimmed","80g plain flour, seasoned with salt and pepper","2 large eggs, beaten","150g fine dry breadcrumbs (Semmelbrösel)","200ml neutral oil (sunflower or rapeseed) for frying","1 lemon, cut into wedges for serving","salt and white pepper"],"ro":["4 cotlete de porc din spată (aprox. 150g fiecare), dezosate și degresate","80g făină simplă, condimentată cu sare și piper","2 ouă mari, bătute","150g pesmet fin uscat (Semmelbrösel)","200ml ulei neutru (floarea-soarelui sau rapiță) pentru prăjit","1 lămâie, tăiată fâșii pentru servit","sare și piper alb"]},"howIsMade":{"ru":"Положите каждый шницель между двумя листами пищевой плёнки и отбейте молоточком или скалкой до равномерной толщины 4–5мм — тонкая ровная нарезка — это главная черта настоящего шницеля. Обсушите, приправьте солью и белым перцем. Подготовьте три плоские тарелки: муку с приправами, взбитые яйца, панировочные сухари. Обваляйте каждый шницель в муке (стряхните лишнее), окуните в яйцо, затем плотно прижмите к сухарям — не давите слишком сильно, панировка должна оставаться воздушной, чтобы вздуваться в горячем масле. Налейте масло в широкую сковороду слоем 1см и нагрейте до 170–180°C. Жарьте по 2–3 минуты с каждой стороны до насыщенного золотистого цвета. Выложите на решётку — никогда на бумажное полотенце. Подавайте немедленно с дольками лимона.","en":"Place each pork chop between two sheets of cling film and beat with a meat mallet or rolling pin until evenly 4–5mm thick — the thin, even cut is the defining feature of a proper schnitzel. Pat dry and season with salt and white pepper. Set up three shallow dishes: seasoned flour, beaten eggs, breadcrumbs. Coat each schnitzel in flour (shake off the excess), dip in egg, then press firmly into breadcrumbs to coat evenly — do not press the crumb down too hard; it should stay airy so it puffs and blisters in hot oil. Pour oil into a wide pan to a depth of 1cm and heat to 170–180°C. Fry 2–3 minutes per side until deep golden and crisp. Drain on a wire rack — never on paper towel, which traps steam and kills the crust. Serve immediately with lemon wedges."},"nutrition":{"cal":570,"prot":45,"carb":15,"fat":35,"fib":1}},{"id":18,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Бразилия","en":"Brazil","ro":"Brazilia"},"name":{"ru":"Фейжоада","en":"Feijoada","ro":"Feijoada"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["400г сухой чёрной фасоли, замоченной на ночь","400г копчёных свиных рёбер","200г чоризо или копчёной колбасы, нарезанной","200г копчёного бекона, нарезанного кубиками","1 крупная луковица, измельчённая","4 зубчика чеснока, измельчённых","2 лавровых листа","3 ст. л. оливкового масла","соль, перец и хлопья чили по вкусу"],"en":["400g dried black beans, soaked overnight","400g smoked pork ribs","200g chourico or smoked sausage, sliced","200g smoked bacon, diced","1 large onion, chopped","4 garlic cloves, minced","2 bay leaves","3 tbsp olive oil","salt, pepper and chilli flakes to taste"],"ro":["400g fasole neagră uscată, înmuiată 12 ore","400g coaste de porc afumate","200g chouriço sau cârnați afumați, feliați","200g bacon afumat, tăiat cuburi","1 ceapă mare, tocată","4 căței de usturoi, tocați","2 foi de dafin","3 linguri ulei de măsline","sare, piper și fulgi de ardei iute după gust"]},"howIsMade":{"ru":"Слейте воду с замоченной фасоли и положите в большую кастрюлю с холодной водой, чтобы она покрывала на 5 см. Добавьте копчёные рёбра и лавровые листья. Доведите до кипения, затем тушите на среднем огне 1 час, снимая пену. Тем временем обжарьте лук в оливковом масле 8 минут, добавьте чеснок и жарьте ещё 2 минуты. Добавьте чоризо и бекон, поджарьте 5 минут. Перенесите всё в кастрюлю с фасолью, хорошо перемешайте и тушите на малом огне 45-60 минут, пока фасоль не станет совсем мягкой, а бульон не загустеет. Раздавите несколько бобов ложкой о стенку кастрюли для естественного загустения. Подавайте с белым рисом, ломтиками апельсина и фарофой.","en":"Drain the soaked beans and place in a large pot with fresh cold water to cover by 5cm. Add the smoked ribs and bay leaves. Bring to a boil, then simmer over medium heat for 1 hour, skimming any foam. Meanwhile, heat olive oil in a skillet, saute onion 8 minutes until soft and golden, add garlic and cook 2 minutes more. Add chourico and bacon, brown for 5 minutes. Transfer everything to the bean pot, stir well and simmer on low heat for 45-60 minutes until the beans are completely tender and the broth has thickened. Crush a handful of beans against the pot side with a wooden spoon — this thickens the stew naturally. Adjust salt and pepper. Serve in deep bowls with white rice, fresh orange slices and farofa (toasted manioc flour)."},"nutrition":{"cal":620,"prot":38,"carb":45,"fat":32,"fib":14}},{"id":19,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Китай","en":"China","ro":"China"},"name":{"ru":"Курица Гунбао","en":"Kung Pao Chicken","ro":"Pui Gong Bao"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500г куриной грудки, нарезанной кубиками 2 см","100г несолёного жареного арахиса","8–10 сушёных китайских перцев чили","4 пера зелёного лука, нарезанных кусочками 3 см","3 зубчика чеснока, тонко нарезанных","кусочек имбиря 2 см, тонко нарезанный","2 ст.л. сычуаньского чили-масла или подсолнечного","Маринад: 1 ст.л. соевого соуса, 1 ч.л. крахмала, 1 ч.л. кунжутного масла","Соус: 2 ст.л. соевого соуса, 1 ст.л. чёрного рисового уксуса (Чинкян), 1 ст.л. сахара, 1 ч.л. крахмала, 2 ст.л. воды"],"en":["500g chicken breast, cut into 2cm cubes","100g unsalted roasted peanuts","8–10 dried Chinese chili peppers (Sichuan or similar)","4 spring onions, cut into 3cm pieces","3 garlic cloves, thinly sliced","2cm piece of ginger, thinly sliced","2 tbsp Sichuan chili oil or sunflower oil","Marinade: 1 tbsp soy sauce, 1 tsp cornstarch, 1 tsp sesame oil","Sauce: 2 tbsp soy sauce, 1 tbsp black rice vinegar (Chinkiang), 1 tbsp sugar, 1 tsp cornstarch, 2 tbsp water"],"ro":["500g piept de pui, tăiat cuburi de 2 cm","100g arahide prăjite nesărate","8–10 ardei iuți uscați chinezești (chili Sichuan)","4 cepe verzi, tăiate bucăți de 3 cm","3 căței de usturoi, feliați subțire","1 bucată ghimbir de 2 cm, feliată subțire","2 linguri ulei cu ardei Sichuan sau ulei de floarea-soarelui","Marinată: 1 lingură sos de soia, 1 linguriță amidon de porumb, 1 linguriță ulei de susan","Sos: 2 linguri sos de soia, 1 lingură oțet de orez negru (Chinkiang), 1 lingură zahăr, 1 linguriță amidon de porumb, 2 linguri apă"]},"howIsMade":{"ru":"Перемешайте курицу с маринадом и оставьте на 15 минут. Смешайте ингредиенты соуса в маленькой миске. Разогрейте вок на максимальном огне до дыма; добавьте масло и обжарьте сушёный чили 30 секунд до потемнения. Добавьте курицу и обжаривайте 3–4 минуты без помешивания до золотистой корочки; перемешайте и готовьте ещё 2 минуты. Добавьте чеснок, имбирь и белую часть лука; жарьте 1 минуту. Влейте соус, активно помешивайте 1 минуту до загустения. Добавьте арахис и зелёный лук; перемешайте 30 секунд. Подавайте немедленно с жасминовым рисом.","en":"Toss chicken with marinade ingredients and leave for 15 minutes. Combine sauce ingredients in a small bowl. Heat wok over highest heat until smoking; add oil and fry dried chilis and Sichuan peppercorns 30 seconds until darkened but not black — they should smell toasted, not burnt. Add chicken pieces and sear 3–4 minutes without stirring, until golden on one side; toss and cook 2 more minutes. Add garlic, ginger, and the white parts of the spring onion; stir-fry 1 minute. Pour in the sauce, toss vigorously for 1 minute until thickened and clinging to the chicken. Throw in peanuts and green spring onion tops; toss 30 seconds. Serve immediately with jasmine rice."},"nutrition":{"cal":400,"prot":32,"carb":11,"fat":22,"fib":2}},{"id":20,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ru":"Великобритания","en":"United Kingdom","ro":"Marea Britanie"},"name":{"ru":"Фиш энд чипс","en":"Fish and Chips","ro":"Fish and Chips"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["4 филе трески или пикши (ок. 180г каждое), без кожи","1 кг мучнистого картофеля (Ред Скарлетт или Синеглазка), нарезанного толстыми брусками","Растительное масло для фритюра (ок. 2 литров)","Кляр: 180г пшеничной муки + дополнительно для панировки","1 ч.л. разрыхлителя","1 ч.л. мелкой соли","300мл ледяного светлого пива (лагер или пейл-эль)","Соль и солодовый уксус для подачи"],"en":["4 cod or haddock fillets (about 180g each), skin removed","1kg floury potatoes (Maris Piper or King Edward), cut into thick chips","Vegetable oil for deep-frying (about 2 litres)","Batter: 180g plain flour, plus extra for dusting","1 tsp baking powder","1 tsp fine salt","300ml ice-cold lager or pale ale","Salt and malt vinegar to serve"],"ro":["4 fileuri de cod sau haddock (aprox. 180g fiecare), fără piele","1 kg cartofi floury (Maris Piper sau King Edward), tăiați bețe groase","Ulei vegetal pentru prăjit (aprox. 2 litri)","Pentru aluat: 180g făină tip 550 + extra pentru tăvălit","1 linguriță praf de copt","1 linguriță sare fină","300ml bere blondă rece (lager sau ale)","Sare și oțet de malt pentru servire"]},"howIsMade":{"ru":"Готовьте чипсы в два этапа: фритюр при 140°C 8 минут до мягкости без золотистой корочки; слейте и охладите на решётке. Приготовьте кляр: смешайте муку, разрыхлитель и соль, затем постепенно вбейте ледяное пиво до консистенции густых сливок — не перемешивайте. Промокните рыбные филе бумажными полотенцами. Разогрейте масло до 185°C. Запанируйте каждое филе в муке, стряхните лишнее, окуните в кляр и дайте стечь несколько секунд. Жарьте 6–8 минут — на середине поливайте горячим маслом сверху — до глубоко золотистой хрустящей корочки. Выложите на бумагу. Поднимите температуру до 200°C и дожарьте чипсы 3–4 минуты до золотистости. Подавайте сразу с солью и солодовым уксусом.","en":"Cook chips in two stages: fry at 140°C for 8 minutes until soft but not coloured; drain and cool on a rack. Make the batter by whisking flour, baking powder, and salt together, then gradually whisk in ice-cold beer until the consistency of double cream — do not overmix. Pat fish fillets completely dry with paper towels. Heat oil to 185°C. Dust each fillet in the extra flour, shake off excess, dip into batter and let it drip for a few seconds. Fry 6–8 minutes — halfway through, spoon hot oil over the top for even crisping — until the batter is deep golden and crunchy. Drain on paper. Raise oil to 200°C and fry chips a second time for 3–4 minutes until golden and crisp all over. Serve immediately with salt and malt vinegar."},"nutrition":{"cal":850,"prot":35,"carb":85,"fat":42,"fib":5}},{"id":21,"origin":{"ru":"Вьетнам","en":"Vietnam","ro":"Vietnam"},"name":{"ru":"Фо","en":"Pho","ro":"Pho"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":225,"active":75},"pairingsType":"def","ingredients":{"ru":["400г сушёной рисовой лапши (банх фо, ширина 5мм)","500г говяжьей грудинки или пашины (для бульона)","1кг говяжьих костей (мозговых или суставных)","2 средние луковицы, разрезанные пополам","5 см свежего имбиря, разрезанного вдоль","3 звёздочки бадьяна","1 палочка корицы (5 см)","3 гвоздики","2 ст.л. рыбного соуса (ныок мам)","1 ч.л. сахара","соль по вкусу","200г свежих ростков сои","свежий кориандр и тайский базилик","2 красных чили, нарезанных кружками (на стол)","2 лайма, четвертинками (на стол)","соус хойсин и шрирача (на стол)"],"en":["400g dried rice noodles (banh pho, 5mm width)","500g beef brisket or flank (for the broth)","1kg beef bones (marrow or knuckle)","2 medium onions, halved","5 cm fresh ginger, halved lengthways","3 star anise","1 cinnamon stick (5 cm)","3 cloves","2 tbsp fish sauce (nuoc mam)","1 tsp sugar","salt to taste","200g fresh bean sprouts","fresh coriander and Thai basil","2 red chillies, sliced (at the table)","2 limes, quartered (at the table)","hoisin sauce and sriracha (at the table)"],"ro":["400g tăiței de orez (banh pho, lățime 5mm), uscați","500g piept de vită sau flacără (pentru supă)","1kg oase de vită (măduvă sau coadă)","2 cepe medii, înjumătățite","5 cm ghimbir proaspăt, înjumătățit","3 anasoane stelate","1 baton de scorțișoară (5 cm)","3 cuișoare","2 linguri sos de pește (nuoc mam)","1 linguriță zahăr","sare după gust","200g muguri de soia proaspeți","coriandru proaspăt și busuioc thai","2 ardei iuți roșii, feliați (la masă)","2 lămâi verzi, tăiate în sferturi (la masă)","sos hoisin și sos sriracha (la masă)"]},"howIsMade":{"ru":"Бланшируйте кости в кипятке 5 минут, слейте воду, тщательно промойте. Подпеките половинки лука и имбиря прямо на огне или под грилем до лёгкого обугливания краёв (2–3 минуты с каждой стороны) — это придаёт бульону золотистый цвет и глубину вкуса. В большую кастрюлю налейте 3л холодной воды, добавьте кости, грудинку, обжаренный лук, имбирь, бадьян, корицу и гвоздику. Доведите до кипения, уменьшите до минимального огня, готовьте без крышки 3 часа, периодически снимая жир. Достаньте грудинку через 1,5 часа, охладите и нарежьте тонко. Процедите бульон через мелкое сито, приправьте рыбным соусом, сахаром и солью. Замочите лапшу в холодной воде на 20 минут, варите 30 секунд, процедите. Разложите по тарелкам, залейте кипящим бульоном, добавьте мясо. Подавайте с ростками сои, кориандром, базиликом, чили, лаймом и соусами.","en":"Blanch beef bones in boiling water for 5 minutes, discard water, rinse well — this removes impurities and keeps the broth clear. Char the onion halves and ginger directly over a gas flame or under the grill until lightly blackened on the edges (2–3 minutes per side) — this gives the broth its golden colour and depth. Fill a large pot with 3L cold water, add bones, brisket, charred onion, ginger, star anise, cinnamon, and cloves. Bring to a boil, reduce to a bare simmer, cook uncovered for 3 hours, skimming fat periodically. Remove the brisket after 1½ hours, let cool, slice thinly. Strain broth through a fine sieve, season with fish sauce, sugar, and salt. Soak noodles in cold water 20 minutes, boil 30 seconds, drain. Divide noodles into bowls, ladle boiling broth over, add meat slices. Serve with bean sprouts, coriander, basil, chilli, lime, and sauces at the table."},"nutrition":{"cal":380,"prot":28,"carb":42,"fat":10,"fib":2}},{"id":22,"origin":{"ru":"Испания","en":"Spain","ro":"Spania"},"name":{"ru":"Паэлья","en":"Paella","ro":"Paella"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"fish","ingredients":{"ru":["300г риса бомба (или круглозёрного)","400г куриных бёдер без кости, нарезанных кусками","300г сырых креветок (в панцире или без)","400г мидий, очищенных и разделанных","1 большая луковица, мелко нарезанная","4 зубчика чеснока, измельчённых","1 красный болгарский перец, нарезанный кубиками","400г консервированных рубленых томатов","½ ч.л. нитей шафрана (в 2 ст.л. тёплой воды)","1 ч.л. копчёной паприки (пиментон де ла Вера)","800мл тёплого куриного бульона","3 ст.л. оливкового масла","соль и чёрный перец по вкусу","свежая петрушка и дольки лимона для подачи"],"en":["300g bomba rice (or short-grain rice)","400g boneless chicken thighs, cut into pieces","300g raw prawns (shell-on or peeled)","400g mussels, scrubbed and debearded","1 large onion, finely chopped","4 garlic cloves, minced","1 red bell pepper, diced","400g canned crushed tomatoes","½ tsp saffron threads (soaked in 2 tbsp warm water)","1 tsp smoked paprika (pimentón de la Vera)","800ml warm chicken stock","3 tbsp olive oil","salt and black pepper to taste","fresh parsley and lemon wedges to serve"],"ro":["300g orez bomba (sau orez cu bob scurt)","400g pulpe de pui dezosate, tăiate în bucăți","300g creveți crudi (cu coajă sau fără)","400g midii, spălate și curățate","1 ceapă mare, tocată","4 căței de usturoi, tocați","1 ardei gras roșu, tăiat cuburi","400g roșii din conservă, concasate","½ linguriță șofran (înmuiat în 2 linguri apă caldă)","1 linguriță boia de ardei afumată (pimentón de la Vera)","800ml fond de pui cald","3 linguri ulei de măsline","sare și piper negru după gust","pătrunjel proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"ru":"Замочите шафран в 2 ст.л; тёплой воды. Разогрейте оливковое масло в сковороде паэльера (или широкой неглубокой сковороде) на среднем-сильном огне; приправьте курицу и обжарьте по 4–5 минут с каждой стороны до золотистой корочки; отложите. В том же масле обжаривайте лук 5 минут, добавьте чеснок и перец, готовьте ещё 3 минуты; добавьте томаты и паприку, тушите 3–4 минуты до загустения — это sofrito, душа паэльи. Добавьте рис, перемешайте 1 минуту; влейте тёплый бульон с шафраном равномерно. Верните курицу; установите средний огонь и больше не помешивайте — паэлью нельзя мешать после добавления бульона. Готовьте открытой 10 минут; выложите креветки и мидии, слегка вдавив. Готовьте 8–10 минут пока креветки розовые и мидии открылись; для socarrat последние 2 минуты на сильном огне. Дайте постоять 5 минут; украсьте петрушкой, подавайте с лимоном.","en":"Soak saffron in 2 tbsp warm water; heat olive oil in a paella pan (or wide shallow pan) over medium-high heat. Season chicken, sear 4–5 minutes per side until deeply golden; remove and set aside; in the same pan fry onion 5 minutes, add garlic and red pepper, cook 3 more minutes. Add crushed tomatoes and smoked paprika, cook 3–4 minutes until thickened — this is the sofrito, the soul of the paella; add the rice, stir 1 minute to toast lightly. Pour in the warm stock with the saffron and its soaking water, spread evenly; return the chicken. Adjust to medium heat and do not stir again — never stir paella once the stock is added; cook uncovered for 10 minutes. Place prawns and mussels on top, pressing gently into the rice; cook 8–10 minutes more until prawns are pink and mussels open (discard any that stay shut). For socarrat (the coveted crispy bottom crust), raise to high heat the last 2 minutes — listen for a light crackling; rest 5 minutes; garnish with parsley and serve with lemon wedges."},"nutrition":{"cal":520,"prot":32,"carb":58,"fat":16,"fib":3}},{"id":23,"servings":4,"tipType":"def","pairingsType":"korean","origin":{"ru":"Южная Корея","en":"South Korea","ro":"Coreea de Sud"},"name":{"ru":"Бибимбап","en":"Bibimbap","ro":"Bibimbap"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["2 стакана риса с короткими зёрнами","200г говяжьей вырезки, нарезанной тонко поперёк волокон","1 средний кабачок, нарезанный соломкой","1 средняя морковь, нарезанная соломкой","200г шпината","100г ростков сои","4 гриба шиитаке без ножек","4 яйца","4 ст.л. кочуджан","3 ст.л. кунжутного масла","2 ст.л. соевого соуса","1 ч.л. сахара","3 зубчика чеснока, измельчённых","Кунжут для украшения"],"en":["2 cups short-grain white rice","200g beef sirloin, thinly sliced against the grain","1 medium courgette, julienned","1 medium carrot, julienned","200g baby spinach","100g bean sprouts","4 shiitake mushrooms, stems removed","4 eggs","4 tbsp gochujang (Korean chili paste)","3 tbsp sesame oil","2 tbsp soy sauce","1 tsp sugar","3 cloves garlic, minced","Sesame seeds to garnish"],"ro":["2 căni orez cu bob scurt","200g vită (antricot), felii subțiri","1 dovlecel mediu, julien","1 morcov mediu, julien","200g spanac baby","100g germeni de fasole","4 ciuperci shiitake, fără codiță","4 ouă","4 linguri gochujang (pastă de ardei coreean)","3 linguri ulei de susan","2 linguri sos de soia","1 linguriță zahăr","3 căței de usturoi, tocați","Semințe de susan, pentru decor"]},"howIsMade":{"ru":"Варите рис в 2,5 стаканах воды: доведите до кипения, накройте крышкой и готовьте на минимальном огне 12 минут, затем настаивайте под крышкой 10 минут. Замаринуйте говядину с 1 ст.л. соевого соуса, 1 ст.л. кунжутного масла, 1 ч.л. сахара и половиной чеснока на 15 минут. Бланшируйте шпинат 30 секунд в подсоленной воде, отожмите, заправьте 1 ч.л. кунжутного масла и солью; обжарьте ростки сои 2 минуты с чесноком и солью; отдельно обжарьте морковь и кабачок по 2 минуты с кунжутным маслом. Обжарьте маринованную говядину на сильном огне 3–4 минуты до карамелизации; обжарьте шиитаке 2 минуты с каплей соевого соуса; пожарьте яйца-глазунья на кунжутном масле. Разложите рис по 4 мискам, расположите овощи и мясо секциями, положите яйцо в центр, добавьте 1 ст.л. кочуджан на миску, полейте кунжутным маслом и посыпьте кунжутом — тщательно перемешайте перед едой.","en":"Cook rice in 2.5 cups water: bring to a boil, cover and simmer on the lowest heat for 12 minutes, then rest off the heat for 10 minutes. Marinate beef with 1 tbsp soy sauce, 1 tbsp sesame oil, 1 tsp sugar and half the garlic for 15 minutes. Blanch spinach 30 seconds in boiling salted water, squeeze dry, season with 1 tsp sesame oil and salt; sauté bean sprouts 2 minutes with garlic and salt; stir-fry carrot and courgette separately for 2 minutes each with a drizzle of sesame oil. Sear marinated beef over high heat 3–4 minutes until caramelised; slice shiitake and sauté 2 minutes with a splash of soy sauce; fry eggs sunny-side up in sesame oil. Divide rice among 4 bowls, arrange vegetables and beef in sections, place an egg in the centre, add 1 tbsp gochujang per bowl, drizzle with sesame oil and scatter sesame seeds — mix everything together before eating."},"nutrition":{"cal":450,"prot":22,"carb":65,"fat":12,"fib":5}},{"id":24,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"ru":"Сирия","en":"Syria","ro":"Siria"},"name":{"ru":"Хумус","en":"Hummus","ro":"Hummus"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["400г варёного нута (1 банка), очищенного от кожицы","80г тахини хорошего качества, хорошо перемешанного","сок 2 лимонов (около 4 ст. л.)","2 зубчика чеснока, натёртых","1/2 ч. л. мелкой соли","3–5 ст. л. ледяной воды","2 ст. л. оливкового масла первого отжима для подачи"],"en":["400g (1 can) cooked chickpeas, skins removed","80g tahini (good quality, stirred well)","juice of 2 lemons (about 4 tbsp)","2 garlic cloves, grated","1/2 tsp fine salt","3–5 tbsp ice-cold water","2 tbsp extra-virgin olive oil for finishing"],"ro":["400g năut gătit (1 conservă), coaja îndepărtată","80g pastă de susan (tahini de calitate, bine amestecată)","sucul a 2 lămâi (aprox. 4 linguri)","2 căței de usturoi, rași","1/2 linguriță sare fină","3–5 linguri apă rece cu gheață","2 linguri ulei de măsline extravirgin pentru finalizare"]},"howIsMade":{"ru":"Для самого гладкого хумуса снимите кожицу с нута, легонько сжимая каждую горошину — небольшой шаг, но большая разница. В кухонном комбайне взбейте тахини с лимонным соком отдельно 1 минуту до светло-кремового цвета. Добавьте чеснок и соль; взбейте 30 секунд. Добавьте нут и обрабатывайте 1 минуту. При работающем моторе вливайте ледяную воду по ложке — холодная вода делает хумус лёгким и воздушным. Обрабатывайте всего 3–5 минут, счищая со стенок, до полной однородности. Попробуйте, откорректируйте лимон и соль. Выложите в тарелку, полейте маслом, посыпьте копчёной паприкой или сумахом.","en":"For the smoothest hummus, pop the skins off the chickpeas by gently squeezing each one — a small step that makes a big difference. In a food processor, blitz tahini and lemon juice alone for 1 minute until pale and creamy. Add garlic and salt; blitz 30 seconds. Add the chickpeas and process 1 minute. With the machine running, drizzle in ice-cold water tablespoon by tablespoon — the cold water aerates and lightens the hummus. Process 3–5 minutes total, scraping down the sides, until completely smooth. Taste and adjust lemon and salt. Spread in a bowl, drizzle with olive oil, and finish with smoked paprika or sumac. Keeps refrigerated up to 5 days."},"nutrition":{"cal":220,"prot":8,"carb":22,"fat":12,"fib":6}},{"id":25,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"ru":"Ливан","en":"Lebanon","ro":"Liban"},"name":{"ru":"Табуле","en":"Tabbouleh","ro":"Tabbouleh"},"category":{"ru":"Салат","en":"Salad","ro":"Salate"},"ingredients":{"ru":["200г плосколистной петрушки, только листья, мелко нарезанные","50г мелкого булгура, замоченного в холодной воде 20 мин и хорошо отжатого","3 спелых помидора (около 300г), мелко нарезанных","4 зелёных лука, мелко нарезанных","20г свежих листьев мяты, мелко нарезанных","сок 2 лимонов (около 80мл)","4 ст. л. оливкового масла первого отжима, соль и чёрный перец по вкусу"],"en":["200g flat-leaf parsley, leaves only, finely chopped","50g fine bulgur wheat, soaked in cold water 20 min then squeezed dry","3 ripe tomatoes (about 300g), finely diced","4 spring onions, finely sliced","20g fresh mint leaves, finely chopped","juice of 2 lemons (about 80ml)","4 tbsp extra-virgin olive oil, salt and black pepper to taste"],"ro":["200g pătrunjel plat, frunze tocate mărunt","50g bulgur fin, înmuiat 20 min în apă rece, stors bine","3 roșii coapte (cca 300g), tăiate cuburi mici","4 cepe verzi, tocate fin","20g frunze de mentă proaspătă, tocate mărunt","sucul de la 2 lămâi (cca 80ml)","4 linguri ulei de măsline extravirgin, sare și piper negru după gust"]},"howIsMade":{"ru":"Замочите булгур в холодной воде на 20 минут, затем слейте и хорошо выжмите руками — он должен быть сухим, не мокрым. Нарежьте петрушку как можно мельче; настоящее табуле — это салат из зелени, а не из крупы. Смешайте петрушку, мяту, зелёный лук, помидоры и выжатый булгур в большой миске. Добавьте лимонный сок и оливковое масло, хорошо перемешайте и оставьте на 10 минут — лимон смягчит булгур и раскроет ароматы. Добавьте соль и перец. Подавайте при комнатной температуре.","en":"Soak the bulgur in cold water for 20 minutes, then drain and squeeze out as much water as possible with your hands — it should be dry, not wet. Chop the parsley as finely as you can; authentic tabbouleh is herb-forward, not grain-forward. Combine parsley, mint, spring onions, tomatoes and squeezed bulgur in a large bowl. Add lemon juice and olive oil, toss well and let rest 10 minutes — the lemon juice continues to soften the bulgur and blooms the herbs. Adjust salt and pepper. Serve at room temperature. True tabbouleh is a parsley salad with bulgur, not a bulgur salad with a little parsley."},"nutrition":{"cal":180,"prot":4,"carb":20,"fat":10,"fib":4}},{"id":26,"servings":4,"tipType":"pasta","pairingsType":"pasta","origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Ризотто","en":"Risotto","ro":"Risotto"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["320г риса Арборио или Карнароли","1 крупный шалот или небольшая луковица, мелко нарезанная","50г несолёного сливочного масла, разделённого","100мл сухого белого вина","1,2л тёплого куриного или овощного бульона","40г Пармиджано-Реджано, свежетёртого","1 ст. л. оливкового масла первого отжима","соль и белый перец по вкусу"],"en":["320g Arborio or Carnaroli rice","1 large shallot or small onion, finely diced","50g unsalted butter, divided","100ml dry white wine","1.2L warm chicken or vegetable stock","40g Parmigiano-Reggiano, freshly grated","1 tbsp extra-virgin olive oil","salt and white pepper to taste"],"ro":["320g orez Arborio sau Carnaroli","1 șalotă sau ceapă mică, tocată fin","50g unt nesărat, împărțit","100ml vin alb sec","1,2L supă caldă de pui sau legume","40g Parmigiano-Reggiano, ras proaspăt","1 lingură ulei de măsline extravirgin","sare și piper alb după gust"]},"howIsMade":{"ru":"Держите бульон тёплым на слабом огне на протяжении всего приготовления — холодный бульон останавливает варку и разрушает кремовость. Нагрейте масло и половину сливочного масла в широкой тяжёлой кастрюле на среднем огне. Пассеруйте шалот до мягкости, 3 минуты. Добавьте рис и поджаривайте с помешиванием 2 минуты, пока зёрна не станут слегка прозрачными по краям. Влейте вино и мешайте до полного впитывания. Добавляйте тёплый бульон по одному ковшу, постоянно помешивая и ожидая полного впитывания каждого ковша — этот ключевой этап занимает 16–18 минут. Рис должен быть аль денте. Снимите с огня и энергично вмешайте оставшееся холодное масло и Пармиджано — жир эмульгируется в крахмале, создавая глянцевый соус (это называется мантекатура). Оставьте на 1 минуту и сразу подавайте в тёплых тарелках.","en":"Keep the stock warm over low heat throughout cooking — adding cold stock stops the cooking and ruins the creaminess. Heat oil and half the butter in a wide, heavy pan over medium heat. Sweat the shallot until soft, 3 minutes. Add the rice and toast, stirring, for 2 minutes until grains are slightly translucent at the edges. Pour in the wine and stir until completely absorbed. Add warm stock one ladleful at a time, stirring constantly and waiting for each ladleful to be absorbed before adding the next — this is the essential step and takes 16–18 minutes. The rice should be al dente with a creamy coating. Off the heat, beat in the remaining cold butter and the Parmigiano vigorously — the fat emulsifies into the starches creating a glossy sauce (this is called mantecatura). Rest 1 minute, then serve immediately in warm bowls."}},{"id":27,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Швеция","en":"Sweden","ro":"Suedia"},"name":{"ru":"Шведские фрикадельки","en":"Swedish Meatballs","ro":"Chifteluțe suedeze"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["500г смешанного фарша из свинины и говядины (50/50)","1 средняя луковица, натёртая","1 ломоть белого хлеба без корки, замоченный в 3 ст. л. молока","1 крупное яйцо","1/4 ч. л. молотого душистого перца","1/4 ч. л. свежетёртого мускатного ореха","2 ст. л. сливочного масла для жарки","250мл говяжьего бульона","150мл жирных сливок"],"en":["500g mixed ground pork and beef (50/50)","1 medium onion, grated","1 slice white bread, crusts removed, soaked in 3 tbsp milk","1 large egg","1/4 tsp ground allspice","1/4 tsp freshly grated nutmeg","2 tbsp butter for frying","250ml beef stock","150ml double cream"],"ro":["500g carne tocată amestecată porc și vită (50/50)","1 ceapă medie, rasă","1 felie de pâine albă fără coajă, înmuiată în 3 linguri lapte","1 ou mare","1/4 linguriță ienibahar măcinat","1/4 linguriță nucșoară rasă","2 linguri unt pentru prăjit","250ml supă de vită","150ml smântână pentru frișcă"]},"howIsMade":{"ru":"Отожмите намоченный хлеб, чтобы убрать лишнее молоко, затем смешайте с фаршем, натёртым луком (тоже отожмите), яйцом, душистым перцем, мускатным орехом, солью и перцем. Хорошо перемешайте, но не переусердствуйте — чрезмерное вымешивание делает фрикадельки жёсткими. С мокрыми руками сформируйте шарики диаметром около 3см (20–24 штуки). Растопите масло в широкой сковороде на среднем огне. Обжарьте фрикадельки порциями, аккуратно перекатывая для равномерной румяности, 6–8 минут на порцию. Уберите в сторону. В той же сковороде влейте бульон, соскрябая поджаристый остаток, и доведите до кипения. Добавьте сливки, тушите 5 минут до лёгкого загустения. Верните фрикадельки в соус, готовьте на слабом огне ещё 5 минут. Подавайте с брусничным джемом, отварным или пюрированным картофелем и маринованными огурчиками.","en":"Squeeze the soaked bread to remove excess milk, then mix with the ground meat, grated onion (squeeze out excess liquid), egg, allspice, nutmeg, salt and pepper. Mix well but do not overwork — overworking makes the meatballs tough. With wet hands, roll into balls about 3cm in diameter, yielding about 20–24 meatballs. Melt butter in a wide skillet over medium heat. Fry the meatballs in batches, rolling gently to brown all sides evenly, 6–8 minutes per batch. Remove and set aside. In the same pan, stir in the beef stock, scraping up the fond, and bring to a simmer. Add the cream and simmer 5 minutes until slightly thickened. Return the meatballs to the sauce and cook on low heat 5 more minutes. Serve with lingonberry jam, boiled or mashed potatoes, and pickled cucumber."}},{"id":28,"servings":4,"tipType":"meat","timeMins":{"total":720,"active":75},"pairingsType":"japanese","origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Классический японский рамэн","en":"Classic Japanese Ramen","ro":"Ramen clasic japonez"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["4 порции свежей или сушёной лапши рамен (всего около 400г)","1л куриного или свиного костного бульона","100мл соевого соуса (по вкусу)","2 ст. л. мирина","200г свиной грудинки или лопатки, тонко нарезанной (часю)","4 яйца всмятку, замаринованных на ночь в соевом соусе и мирине","2 листа нори (сушёные водоросли), разрезанных пополам","4 ст. л. ростков бамбука (менма)","2 зелёных лука, тонко нарезанных","1 ст. л. кунжутного масла"],"en":["4 portions fresh or dried ramen noodles (about 400g total)","1L chicken or pork bone broth","100ml soy sauce (or to taste)","2 tbsp mirin","200g pork belly or shoulder, thinly sliced (chashu)","4 soft-boiled eggs (marinated overnight in soy sauce and mirin)","2 sheets nori (dried seaweed), halved","4 tbsp bamboo shoots (menma)","2 spring onions, thinly sliced","1 tbsp sesame oil"],"ro":["4 porții tăiței ramen proaspeți sau uscați (aprox. 400g total)","1L supă de pui sau os de porc","100ml sos de soia (sau după gust)","2 linguri mirin","200g burtă de porc sau pulpă, feliată subțire (chashu)","4 ouă fierte moi (marinate în soia și mirin peste noapte)","2 foi nori (alge uscate), tăiate în jumătate","4 linguri mlădițe de bambus (menma)","2 cepe verzi, feliați subțire","1 lingură ulei de susan"]},"howIsMade":{"ru":"Смешайте бульон с соевым соусом и мирином; варите на медленном огне 10 минут и попробуйте — бульон должен быть насыщенно умами, слегка солёным с нотой сладости. Яйца рамен (лучше готовить накануне): варите яйца ровно 6 минут 30 секунд, охладите в ледяной воде, очистите и маринуйте ночь в 3 ст. л. соевого соуса, 2 ст. л. мирина и 50мл воды. Часю: плотно скрутите свиную грудинку, перевяжите кулинарной нитью и тушите в соевом соусе, мирине, саке и сахаре на слабом огне 2 часа. Нарежьте после охлаждения. Варите лапшу по инструкции (обычно 2–3 минуты), слейте и разложите по тёплым мискам. Налейте горячий бульон. Сверху положите 2–3 ломтика часю, половинку яйца рамен, кусочек нори вертикально, ростки бамбука, зелёный лук и каплю кунжутного масла.","en":"Combine the broth with soy sauce and mirin; simmer 10 minutes and taste — the broth should be deeply savoury, slightly salty, with a hint of sweetness. Ramen eggs (best made the night before): boil eggs for exactly 6 minutes 30 seconds, shock in ice water, peel, and marinate overnight in 3 tbsp soy sauce, 2 tbsp mirin, and 50ml water. Chashu pork: roll pork belly tightly, tie with kitchen string, and braise in soy sauce, mirin, sake, and sugar over a gentle simmer for 2 hours until tender. Slice when cool. Cook noodles per package directions (usually 2–3 minutes), drain, and portion into warmed bowls. Ladle hot broth over. Top with 2–3 slices of chashu pork, a halved ramen egg, a piece of nori standing upright, bamboo shoots, spring onions, and a drop of sesame oil. Serve immediately."}},{"id":29,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"ru":"Аргентина","en":"Argentina","ro":"Argentina"},"name":{"ru":"Эмпанадас","en":"Empanadas","ro":"Empanadas"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["400г пшеничной муки","100г смальца или холодного сливочного масла, кубиками","150мл тёплой воды","1 ч. л. соли","300г говяжьего фарша","1 средняя луковица, мелко нарезанная","2 варёных яйца, нарезанных","12 зелёных оливок без косточек, нарезанных","1 ч. л. молотого кумина","1 ч. л. сладкой паприки"],"en":["400g plain flour","100g lard or cold butter, diced","150ml warm water","1 tsp salt","300g ground beef","1 medium onion, finely chopped","2 hard-boiled eggs, chopped","12 green olives, pitted and sliced","1 tsp ground cumin","1 tsp sweet paprika"],"ro":["400g făină albă","100g untură sau unt rece, cuburi","150ml apă caldă","1 linguriță sare","300g carne de vită tocată","1 ceapă medie, tocată fin","2 ouă fierte tari, tăiate","12 măsline verzi, fără sâmburi și tăiate","1 linguriță chimen măcinat","1 linguriță boia dulce"]},"howIsMade":{"ru":"Приготовьте тесто: смешайте муку с солью, вотрите смалец или холодное масло кончиками пальцев до получения крошки, затем добавляйте тёплую воду постепенно и вымешивайте 5 минут до гладкого и эластичного теста. Оберните плёнкой и оставьте отдохнуть 30 минут. Для начинки обжарьте лук 8 минут, добавьте фарш и готовьте 10 минут на среднем огне, хорошо разбивая. Приправьте кумином, паприкой, солью и перцем. Полностью охладите, затем добавьте нарезанные яйца и оливки. Раскатайте тесто толщиной 3мм и вырежьте круги диаметром 12 см. Положите столовую ложку начинки в центр, смочите края, сложите полумесяцем и защипните закрученным бортиком. Выпекайте при 200 градусах С 20-25 минут до золотистого цвета или жарьте во фритюре при 180 градусах С 3-4 минуты с каждой стороны.","en":"Make the dough: combine flour and salt, rub in the lard or cold butter with your fingertips until the mixture resembles breadcrumbs, then add warm water gradually and knead 5 minutes to a smooth, elastic dough. Wrap and rest 30 minutes. For the filling, saute onion in a little oil for 8 minutes, add ground beef and cook 10 minutes over medium heat, breaking it up well. Season with cumin, paprika, salt and pepper. Cool completely, then fold in the chopped boiled eggs and olives. Roll dough to 3mm thick and cut 12cm circles. Place a tablespoon of filling in the centre, moisten the edges, fold into a half-moon and seal with a twisted rope border (repulge). Bake at 200 degrees C for 20-25 minutes until golden, or deep-fry at 180 degrees C for 3-4 minutes per side."}},{"id":30,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Цацики","en":"Tzatziki","ro":"Tzatziki"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["500г полножирного греческого йогурта (подвешенного на ночь, если возможно)","1 крупный огурец (около 300г), натёртый и хорошо отжатый","2 зубчика чеснока, мелко натёртых","2 ст. л. оливкового масла первого отжима, плюс немного для подачи","1 ст. л. свежего укропа, мелко нарезанного","сок половины лимона","мелкая морская соль по вкусу"],"en":["500g full-fat Greek yogurt (strained overnight if possible)","1 large cucumber (about 300g), grated and well squeezed","2 garlic cloves, finely grated","2 tbsp extra-virgin olive oil, plus a drizzle to serve","1 tbsp fresh dill, finely chopped","juice of half a lemon","fine sea salt to taste"],"ro":["500g iaurt grecesc integral (scurs peste noapte dacă e posibil)","1 castravete mare (cca 300g), ras și bine stors","2 căței de usturoi, rași fin","2 linguri ulei de măsline extravirgin, plus un pic pentru servit","1 lingură mărar proaspăt, tocat mărunt","sucul de la jumătate de lămâie","sare fină după gust"]},"howIsMade":{"ru":"Самый важный шаг: натрите огурец на крупной тёрке, положите в чистую ткань или дуршлаг, посолите и оставьте на 10 минут, затем сильно отожмите — огурец потеряет почти половину веса в виде жидкости. Лишняя влага делает цацики водянистыми. Смешайте йогурт с хорошо отжатым огурцом, тёртым чесноком, оливковым маслом, лимонным соком и укропом. Посолите по вкусу. Накройте и поставьте в холодильник минимум на 30 минут — ароматы раскрываются по мере настаивания. Подавайте с оливковым маслом и свежим укропом, с тёплой питой.","en":"The most important step: grate the cucumber on the coarse side of a box grater and place in a clean tea towel or colander. Sprinkle with a little salt, leave 10 minutes, then squeeze out hard — the cucumber will shed almost half its weight in water. Excess moisture is what makes tzatziki watery and weak. Combine the yogurt with the well-squeezed cucumber, grated garlic, olive oil, lemon juice and dill. Taste and adjust salt. Cover and refrigerate at least 30 minutes before serving — the flavours deepen as it rests. Serve drizzled with olive oil and a few fresh dill sprigs, alongside warm pita bread or souvlaki."}},{"id":31,"servings":4,"tipType":"soup","pairingsType":"french","origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Французский луковый суп","en":"French Onion Soup","ro":"Supă de ceapă franțuzească"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["1кг жёлтого лука, тонко нарезанного","60г несолёного сливочного масла","1 ст. л. муки","200мл сухого белого вина","1,2 л хорошего говяжьего бульона","4 толстых ломтика багета, поджаренных","150г Грюйера, натёртого","соль, чёрный перец и веточки свежего тимьяна"],"en":["1kg yellow onions, thinly sliced","60g unsalted butter","1 tbsp plain flour","200ml dry white wine","1.2 litres good beef stock","4 thick slices baguette, toasted","150g Gruyere, grated","salt, black pepper and fresh thyme sprigs"],"ro":["1kg ceapă galbenă, tăiată julienne","60g unt nesărat","1 lingură făină","200ml vin alb sec","1,2 litri supă bună de vită","4 felii groase de baghetă, prăjite","150g Gruyère, ras","sare, piper negru și crenguțe de cimbru proaspăt"]},"howIsMade":{"ru":"Растопите масло в кастрюле с толстым дном на среднем-малом огне. Добавьте лук со щепоткой соли и готовьте 45-60 минут, помешивая каждые 5 минут — терпение здесь решает всё. Лук должен стать цвета карамели, не подгореть. Добавьте тимьян и муку, помешивайте 1 минуту. Влейте вино и кипятите 3 минуты. Добавьте бульон, доведите до кипения и варите 20 минут. Посолите и поперчите по вкусу. Разлейте по жаростойким мискам, в каждую положите ломтик поджаренного багета, обильно посыпьте Грюйером и поставьте под гриль на 3-4 минуты до образования пузырей и золотистой корочки. Подавайте немедленно.","en":"Melt the butter in a heavy-bottomed pot over medium-low heat. Add the onions with a pinch of salt and cook for 45-60 minutes, stirring every 5 minutes — patience is everything here. The onions must turn the colour of caramel, not burnt. Add a splash of water whenever they stick. Add the thyme and flour, stir for 1 minute. Pour in the wine and let it bubble for 3 minutes. Add the beef stock, bring to a simmer and cook 20 minutes. Taste and adjust salt and pepper. Ladle into oven-safe bowls, float a slice of toasted baguette in each, pile on the Gruyere and grill (broil) for 3-4 minutes until the cheese is bubbling and golden brown. Serve immediately — the cheese will set as it cools."}},{"id":32,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Венгрия","en":"Hungary","ro":"Ungaria"},"name":{"ru":"Гуляш","en":"Goulash","ro":"Gulaș"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["700г говяжьей лопатки или голяшки, нарезанных кубиками 3 см","400г рассыпчатого картофеля, очищенного и нарезанного","2 крупные луковицы, мелко нарезанные","2 красных болгарских перца, нарезанных кубиками","3 ст. л. сладкой венгерской паприки","400г консервированных рубленых помидоров","1 л говяжьего бульона","3 ст. л. смальца или растительного масла","2 ч. л. семян тмина, соль и чёрный перец по вкусу"],"en":["700g beef chuck or shin, cut into 3cm cubes","400g waxy potatoes, peeled and diced","2 large onions, finely chopped","2 red bell peppers, diced","3 tbsp sweet Hungarian paprika","400g canned chopped tomatoes","1 litre beef stock","3 tbsp lard or vegetable oil","2 tsp caraway seeds, salt and black pepper to taste"],"ro":["700g carne de vită (spată sau greabăn), cuburi de 3 cm","400g cartofi cerosi, curățați și tăiați cuburi","2 cepe mari, tocate mărunt","2 ardei grași roșii, tăiați cuburi","3 linguri boia ungurească dulce","400g roșii tocate la conservă","1 litru supă de vită","3 linguri untură sau ulei vegetal","2 linguriță semințe de chimen, sare și piper negru după gust"]},"howIsMade":{"ru":"Промокните кубики говядины бумажным полотенцем и приправьте. Разогрейте смалец в тяжёлой кастрюле на сильном огне и обжарьте мясо порциями до корочки — не перемешивайте слишком часто. Уберите и отложите. Уменьшите огонь до среднего, обжарьте лук 10 минут. Добавьте паприку и помешивайте 1 минуту — не дайте ей подгореть, иначе она станет горькой. Добавьте перец, помидоры, тмин и бульон. Верните говядину, доведите до кипения, накройте крышкой и тушите на малом огне 60-75 минут. Добавьте картофель и готовьте ещё 25 минут. Посолите по вкусу. Подавайте в глубоких мисках с хрустящим хлебом.","en":"Pat the beef cubes dry and season with salt and pepper. Heat the lard or oil in a heavy pot over high heat and brown the meat in batches — do not stir too much; you want a crust, not steamed meat. Remove and set aside. Reduce heat to medium, add the onions and cook 10 minutes. Add the paprika and stir for 1 minute — do not let it burn or it turns bitter. Add the peppers, tomatoes, caraway seeds and beef stock. Return the beef, bring to a boil, cover and simmer on low heat for 60-75 minutes. Add the potatoes and simmer 25 more minutes until tender and the beef flakes easily under pressure. Taste and adjust salt. Serve in deep bowls with crusty bread to mop up the rich broth."}},{"id":33,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ru":"Египет","en":"Egypt","ro":"Egipt"},"name":{"ru":"Кошари","en":"Koshari","ro":"Koshari"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["200г длиннозёрного белого риса","200г зелёной чечевицы","150г маленьких макарон (дitalini или рожки)","400г консервированного нута, осушённого","800г консервированных рубленых томатов","3 крупные луковицы (2 для соуса, 1 для хрустящей посыпки)","4 ст. л. растительного масла","3 зубчика чеснока, измельчённых, соль, кумин и уксус по вкусу"],"en":["200g long-grain white rice","200g green lentils","150g small macaroni or ditalini","400g canned chickpeas, drained","800g canned crushed tomatoes","3 large onions (2 for sauce, 1 for crispy topping)","4 tbsp vegetable oil","3 garlic cloves, minced, salt, cumin and vinegar to taste"],"ro":["200g orez cu bob lung","200g linte verde","150g macaroane mici sau ditalini","400g năut la conservă, scurs","800g roșii tocate la conservă","3 cepe mari (2 pentru sos, 1 pentru topping crocant)","4 linguri ulei vegetal","3 căței de usturoi, tocați, sare, chimen și oțet după gust"]},"howIsMade":{"ru":"Сварите чечевицу в несолёной воде 20 минут до состояния аль денте, слейте. Отварите рис в солёной воде 15 минут. Сварите макароны аль денте и слейте. Нарежьте третью луковицу тонкими кольцами и обжарьте в масле на среднем-сильном огне 15-20 минут, помешивая, до тёмно-золотистого и хрустящего состояния. Выложите на бумажное полотенце. В том же масле обжарьте оставшийся нарезанный лук 10 минут, добавьте чеснок, кумин, консервированные томаты, уксус и соль. Варите соус 20-25 минут до загустения. Добавьте нут и варите ещё 5 минут. Смешайте чечевицу с рисом. Подавайте слоями: рис с чечевицей, макароны, томатный соус с нутом и хрустящий лук сверху.","en":"Cook the lentils in unsalted water for 20 minutes until al dente, then drain. Cook the rice in salted water for 15 minutes. Cook the pasta al dente and drain. Slice the third onion into thin rings and fry in oil over medium-high heat for 15-20 minutes, stirring often, until deep golden brown and crispy — this is the prized topping. Drain on paper towels. In the same oil, saute the remaining chopped onions 10 minutes, add garlic, cumin, canned tomatoes, a splash of vinegar and salt. Simmer the sauce 20-25 minutes until thick. Add the chickpeas and simmer 5 more minutes. Mix lentils into the rice. To serve, layer rice-lentil mixture, pasta, tomato-chickpea sauce, and top with the crispy onion rings. Koshari is eaten at room temperature."}},{"id":35,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"ru":"Турция","en":"Turkey","ro":"Turcia"},"name":{"ru":"Баклава","en":"Baklava","ro":"Baklava"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["500г листов теста фило, размороженных","200г несолёного сливочного масла, растопленного","200г грецких орехов, мелко нарезанных","100г фисташек, мелко нарезанных","1 ч. л. молотой корицы","300г сахара","200мл воды","2 ст. л. мёда плюс 1 ст. л. лимонного сока"],"en":["500g phyllo pastry sheets, thawed","200g unsalted butter, melted","200g walnuts, finely chopped","100g pistachios, finely chopped","1 tsp ground cinnamon","300g sugar","200ml water","2 tbsp honey plus 1 tbsp lemon juice"],"ro":["500g foi de plăcintă (phyllo), dezghețate","200g unt nesărat, topit","200g nuci, tocate mărunt","100g fistic, tocat mărunt","1 linguriță scorțișoară măcinată","300g zahăr","200ml apă","2 linguri miere plus 1 lingură suc de lămâie"]},"howIsMade":{"ru":"Сначала приготовьте сироп: растворите сахар в воде, прокипятите 5 минут, добавьте мёд и лимонный сок, прокипятите ещё 5 минут; полностью охладите — сироп должен быть холодным, когда вы зальёте им горячую баклаву. Смешайте орехи, фисташки и корицу; смажьте форму 33x23см растопленным маслом. Уложите 8 листов фило, смазывая каждый маслом; рассыпьте щедрый слой ореховой смеси. Накройте 4 листами с маслом, затем ещё один слой орехов; повторяйте до конца орехов, завершите 8 листами. Нарежьте ромбами до запекания; запекайте при 160 градусах С 45-50 минут до светло-золотистого цвета. Сразу из духовки залейте холодным сиропом; дайте постоять 2-3 часа.","en":"Make the syrup first: dissolve sugar in water, boil 5 minutes, add honey and lemon juice, boil 5 more minutes; leave to cool completely — the syrup must be cold when poured over hot baklava. Mix the walnuts with pistachios and cinnamon; grease a 33x23cm baking tray with melted butter. Layer 8 phyllo sheets, brushing each with butter; scatter a generous layer of nut mixture. Cover with 4 buttered phyllo sheets, then another nut layer; repeat until the nuts are used up, finishing with 8 buttered phyllo sheets. Cut into diamonds or squares before baking; bake at 160 degrees C for 45-50 minutes until pale golden. The moment it comes out of the oven, pour the cold syrup all over — the temperature contrast helps the baklava absorb every drop; leave to rest 2-3 hours before serving."}},{"id":36,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Чили кон карне","en":"Chili con carne","ro":"Chili con carne"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500г говяжьего фарша (мин. 20% жирности)","400г красной фасоли кидни из банки, осушённой","400г консервированных рубленых томатов","2 крупные луковицы, нарезанные","3 зубчика чеснока, измельчённых","2 ст. л. пасты чипотле или 2 сушёных чили чипотле","1 ст. л. молотого кумина и 1 ст. л. копчёной паприки","2 ст. л. растительного масла","соль и чёрный перец"],"en":["500g beef mince (min. 20% fat)","400g canned red kidney beans, drained","400g canned chopped tomatoes","2 large onions, chopped","3 garlic cloves, minced","2 tbsp chipotle paste or 2 dried chipotle chillies, rehydrated","1 tbsp ground cumin and 1 tbsp smoked paprika","2 tbsp vegetable oil","salt and black pepper"],"ro":["500g carne de vită tocată (min. 20% grăsime)","400g fasole roșie kidney la conservă, scursă","400g roșii tocate la conservă","2 cepe mari, tocate","3 căței de usturoi, tocați","2 linguri pastă de chipotle sau 2 ardei iuți uscați","1 lingură chimen măcinat și 1 lingură boia afumată","2 linguri ulei vegetal","sare și piper negru"]},"howIsMade":{"ru":"Разогрейте масло в большой кастрюле на сильном огне. Обжарьте фарш двумя порциями, хорошо разбивая — нужны маленькие карамелизированные кусочки, а не серая масса. Уберите мясо и в том же масле обжарьте лук 8 минут. Добавьте чеснок, кумин и копчёную паприку, помешивайте 1 минуту. Добавьте пасту чипотле, томаты, фасоль, обжаренное мясо и 200мл воды. Доведите до кипения, уменьшите огонь, прикройте крышкой и варите 45-60 минут. Если слишком жидко, снимите крышку на последние 15 минут. Посолите. Подавайте со сметаной, тёртым чеддером, халапеньо и свежей кинзой.","en":"Heat the oil in a large pot over high heat. Brown the mince in two batches, breaking it up well — you want small caramelised pieces, not a grey steamed mass. Remove the meat and in the same oil, saute the onion for 8 minutes. Add garlic, cumin and smoked paprika, stir for 1 minute. Add chipotle paste, canned tomatoes, drained beans, the browned meat and 200ml water. Bring to a boil, reduce to low, partially cover and simmer 45-60 minutes, stirring occasionally. Chili should be thick, not watery — uncover for the last 15 minutes if too thin. Taste and adjust salt. Serve in bowls with sour cream, grated cheddar, sliced jalapeños, fresh coriander and tortilla chips."}},{"id":37,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Китай","en":"China","ro":"China"},"name":{"ru":"Курица в кисло-сладком соусе","en":"Sweet and Sour Chicken","ro":"Pui dulce-acrișor"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500г куриной грудки, нарезанной кусочками 3 см","1 ст. л. кукурузного крахмала (для обвалки)","200г консервированных кусочков ананаса, сок сохранить","1 красный и 1 зелёный болгарский перец, нарезанных кубиками","1 небольшая луковица, нарезанная кубиками","3 ст. л. рисового уксуса","2 ст. л. сахара, 2 ст. л. соевого соуса, 1 ст. л. кетчупа","2 ст. л. растительного масла плюс 1 ч. л. кунжутного масла"],"en":["500g chicken breast, cut into 3cm pieces","1 tbsp cornstarch (for coating)","200g canned pineapple chunks, juice reserved","1 red and 1 green bell pepper, diced","1 small onion, diced","3 tbsp rice vinegar","2 tbsp sugar, 2 tbsp soy sauce, 1 tbsp ketchup","2 tbsp vegetable oil plus 1 tsp sesame oil"],"ro":["500g piept de pui, tăiat cuburi de 3 cm","1 lingură amidon de porumb (pentru acoperire)","200g bucăți de ananas la conservă, sucul rezervat","1 ardei roșu și 1 ardei verde, tăiați cuburi","1 ceapă mică, tăiată cuburi","3 linguri oțet de orez","2 linguri zahăr, 2 linguri sos de soia, 1 lingură ketchup","2 linguri ulei vegetal plus 1 linguriță ulei de susan"]},"howIsMade":{"ru":"Сначала приготовьте соус: смешайте рисовый уксус, сахар, соевый соус, кетчуп и 3 ст. л. ананасового сока. Обваляйте курицу в крахмале, стряхните лишнее. Разогрейте масло в воке или большой сковороде на сильном огне. Обжарьте курицу порциями 4-5 минут до золотистой хрустящей корочки. Отложите. В том же воке добавьте немного масла, обжарьте лук 2 минуты, добавьте перцы и жарьте ещё 2 минуты — они должны остаться хрустящими. Добавьте ананас, влейте соус и варите 1-2 минуты до загустения и блеска. Верните курицу и перемешайте. Добавьте кунжутное масло. Подавайте сразу с рисом на пару.","en":"Make the sauce first: mix rice vinegar, sugar, soy sauce, ketchup and 3 tbsp of the pineapple juice. Toss the chicken pieces in cornstarch and shake off excess. Heat vegetable oil in a wok or large skillet over high heat. Fry the chicken in batches for 4-5 minutes until crisp and golden — do not crowd the pan. Set aside. In the same wok, add a little more oil and stir-fry the onion 2 minutes, add the peppers and cook 2 more minutes on high — they should stay crisp. Add the pineapple, pour in the sauce and bubble for 1-2 minutes until thick and glossy. Return the chicken and toss everything together. Finish with sesame oil. Serve immediately over steamed rice."}},{"id":38,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"ru":"Австралия","en":"Australia","ro":"Australia"},"name":{"ru":"Павлова","en":"Pavlova","ro":"Pavlova"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["4 крупных яичных белка, комнатная температура","220г мелкого сахара (кастер)","2 ч.л. кукурузного крахмала","1 ч.л. белого винного уксуса","1 ч.л. ванильного экстракта","300мл жирных сливок для взбивания (мин. 35%)","200г свежей клубники, нарезанной","2 маракуйи, мякоть"],"en":["4 large egg whites, room temperature","220g caster sugar","2 tsp cornstarch","1 tsp white wine vinegar","1 tsp vanilla extract","300ml double cream, for whipping","200g fresh strawberries, sliced","2 passion fruits, pulp scooped"],"ro":["4 albușuri mari, la temperatura camerei","220g zahăr fin (caster sugar)","2 lingurițe amidon de porumb","1 linguriță oțet de vin alb","1 linguriță extract de vanilie","300ml smântână pentru frișcă (min. 35% grăsime)","200g căpșuni proaspete, feliate","2 fructe ale pasiunii, pulpă"]},"howIsMade":{"ru":"Разогрейте духовку до 120°C, начертите круг 22 см на пергаменте. Взбейте белки со щепоткой соли до мягких пиков. Добавляйте сахар по столовой ложке, тщательно взбивая после каждого раза — 8-10 минут до глянцевой, плотной меренги без крупинок сахара. Аккуратно вмешайте крахмал, уксус и ваниль лопаткой. Выложите меренгу на круг, чуть приподняв края. Выпекайте 90 минут — корочка должна быть сухой и светло-кремовой. Выключите духовку, оставьте павлову остывать при приоткрытой дверце не менее 2 часов. Перед подачей взбейте сливки и нанесите на меренгу. Украсьте клубникой и мякотью маракуйи.","en":"Preheat oven to 120°C and trace a 22cm circle on baking paper. Whisk egg whites with a pinch of salt to soft peaks. Add caster sugar one tablespoon at a time, whisking well after each addition — takes 8-10 minutes until the meringue is glossy, stiff, and has no sugar grains when rubbed between fingers. Fold in cornstarch, vinegar, and vanilla with a spatula. Mound the meringue onto the paper circle, building the sides slightly higher than the centre. Bake 90 minutes — the shell should be dry and faintly cream-coloured. Turn off oven and leave the pavlova to cool completely inside with the door ajar, at least 2 hours. Just before serving, whip cream to soft peaks and spread over the meringue. Top with strawberries and passion fruit pulp."}},{"id":39,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ru":"Канада","en":"Canada","ro":"Canada"},"name":{"ru":"Путин","en":"Poutine","ro":"Poutine"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["800г картофеля (Рассет или Синеглазка), очищенный","150г свежего сырного творога (cheese curds), комнатная температура","2 ст.л. несолёного сливочного масла","2 ст.л. муки","500мл горячего говяжьего бульона","1 ч.л. соуса Вустершир","растительное масло для жарки","соль и чёрный перец"],"en":["800g Russet or Maris Piper potatoes, peeled","150g fresh cheese curds, room temperature","2 tbsp unsalted butter","2 tbsp plain flour","500ml beef stock, hot","1 tsp Worcestershire sauce","vegetable oil for frying","salt and black pepper"],"ro":["800g cartofi Russet sau Desiree, curatati","150g cas proaspat (cheese curds), la temperatura camerei","2 linguri unt nesarat","2 linguri făină alba","500ml supa de vita, fierbinte","1 lingurita sos Worcestershire","ulei vegetal pentru prajit","sare si piper negru"]},"howIsMade":{"ru":"Нарежьте картофель брусочками 1 см и замочите в холодной воде на 30 минут — это удалит крахмал и сделает их хрустящими. Хорошо обсушите. Первое обжаривание: разогрейте масло до 150°C, обжаривайте 5-6 минут до готовности без румянца. Слейте, дайте отдохнуть 10 минут. Второе обжаривание: масло 190°C, 3-4 минуты до золотистого цвета и хруста. Немедленно посолите. Для соуса: растопите масло на среднем огне, добавьте муку, готовьте 2 минуты помешивая. Добавляйте горячий бульон постепенно, взбивая, пока соус не загустеет, 3-4 минуты. Добавьте Вустершир, посолите. Выложите горячий картофель в глубокую миску, рассыпьте творожный сыр при комнатной температуре и сразу же полейте горячим соусом.","en":"Cut potatoes into 1cm batons and soak in cold water for 30 minutes to remove starch — this is what makes them crispy. Dry thoroughly. First fry: heat oil to 150°C and fry potatoes 5-6 minutes until cooked through but without colour. Drain and rest 10 minutes. Second fry: heat oil to 190°C and fry 3-4 minutes until golden and very crispy. Season immediately with salt. For the gravy: melt butter over medium heat, add flour and cook 2 minutes stirring — it should turn pale golden. Add hot stock gradually, whisking constantly until thickened, 3-4 minutes. Add Worcestershire, season. Pile hot fries into a deep bowl, scatter room-temperature cheese curds over, and immediately pour the hot gravy on top — the heat partially melts the curds while keeping their signature squeak."}},{"id":40,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ru":"Польша","en":"Poland","ro":"Polonia"},"name":{"ru":"Вареники (Пироги)","en":"Pierogi","ro":"Pierogi"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cina"},"ingredients":{"ru":["300г муки плюс немного для раскатки","1 крупное яйцо и 150мл тёплой воды (для теста)","500г рассыпчатого картофеля, варёного и толчёного","200г творога (тварог) или сухого домашнего сыра","2 средних луковицы, мелко нарезанных","40г несолёного сливочного масла","100г копчёного бекона кусочками","соль, белый перец и свежий зелёный лук для подачи"],"en":["300g plain flour, plus extra for dusting","1 large egg plus 150ml warm water (for dough)","500g floury potatoes, boiled and mashed","200g farmer's cheese (twarog) or dry cottage cheese","2 medium onions, finely diced","40g unsalted butter","100g smoked bacon lardons","salt, white pepper and fresh chives to serve"],"ro":["300g făină alba, plus extra pentru intins","1 ou mare plus 150ml apa calda (pentru aluat)","500g cartofi fainosi, fierti si zdrobiti","200g branza de vaci (twarog) sau branza proaspata","2 cepe medii, taiate marunt","40g unt nesarat","100g bacon afumat, taiat cubulete","sare, piper alb si ceapa verde proaspata pentru servit"]},"howIsMade":{"ru":"Смешайте муку с яйцом и тёплой водой, вымесите 5 минут до гладкого эластичного теста, накройте и дайте отдохнуть 30 минут. Сварите картофель до мягкости, разомните с творогом, солью и белым перцем. Обжарьте половину лука в масле до золотистого цвета (10 мин), вмешайте в начинку. Раскатайте тесто до 3мм, вырежьте круги 8см. Положите ложку начинки на каждый диск, сложите пополам и плотно защипите края. Варите в подсолённой воде 3-4 минуты — готовы когда всплывут. Обжарьте бекон до хруста, добавьте оставшийся лук и подрумяньте. Обжарьте отварные вареники в масле по 2-3 минуты с каждой стороны до золотистой корочки. Подавайте с беконом, жареным луком и сметаной.","en":"Mix flour with egg and warm water, knead 5 minutes to a smooth, elastic dough, cover and rest 30 minutes. Boil potatoes until tender, mash with farmer's cheese, salt and white pepper. In a pan, fry half the onion in butter until golden (10 min), stir into filling. Roll dough to 3mm, cut 8cm circles. Place a teaspoon of filling on each disc, fold in half and seal the edges firmly by pressing with fingers or a fork. Boil in salted water 3-4 minutes — they float when done. Meanwhile, fry bacon until crisp, add remaining onion and brown. Pan-fry the boiled pierogi in butter 2-3 minutes per side until golden patches appear. Serve with bacon, fried onion and sour cream."}},{"id":41,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Индонезия","en":"Indonesia","ro":"Indonezia"},"name":{"ru":"Наси Горенг","en":"Nasi Goreng","ro":"Nasi Goreng"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["4 стакана варёного риса жасмин (лучше вчерашнего)","300 г куриных бёдрышек без кости, нарезанных кубиками 1 см","4 яйца","4 луковицы-шалот, тонко нарезанные","4 зубчика чеснока, мелко нарубленных","2 красных перца чили птичий глаз, тонко нарезанных","2 ст. л. кечап манис (сладкого соевого соуса)","1 ст. л. соевого соуса","1 ч. л. креветочной пасты (терасси), обжаренной","3 ст. л. растительного масла","соль и белый перец по вкусу","ломтики огурца и обжаренный лук-шалот для подачи"],"en":["4 cups day-old cooked jasmine rice","300 g boneless chicken thigh, cut into 1 cm cubes","4 eggs","4 shallots, thinly sliced","4 garlic cloves, minced","2 red bird's eye chillies, thinly sliced","2 tbsp kecap manis (sweet soy sauce)","1 tbsp soy sauce","1 tsp shrimp paste (terasi), toasted","3 tbsp vegetable oil","salt and white pepper to taste","cucumber slices and fried shallots to serve"],"ro":["4 căni orez jasmin fiert în ziua precedentă","300 g pulpă de pui dezosată, tăiată cubulețe de 1 cm","4 ouă","4 eșalote, feliate subțire","4 căței de usturoi, tocați","2 ardei iuți roșii, feliați subțire","2 linguri kecap manis (sos de soia dulce)","1 lingură sos de soia","1 linguriță pastă de creveți (terasi), prăjită","3 linguri ulei vegetal","sare și piper alb după gust","felii de castravete și eșalote prăjite pentru servire"]},"howIsMade":{"ru":"Разомните холодный рис руками, чтобы разбить комки. Разогрейте 1 ст. л. масла в воке на сильном огне до появления дыма. Добавьте курицу и обжаривайте 3–4 минуты до готовности и лёгкой золотистости; достаньте и отложите в сторону. Влейте оставшиеся 2 ст. л. масла в вок. Добавьте лук-шалот и обжаривайте 2 минуты до мягкости. Добавьте чеснок, перец чили и креветочную пасту и обжаривайте 1 минуту до появления аромата. Всыпьте рис, разровняйте ровным слоем и оставьте на 1 минуту без перемешивания, чтобы образовалась лёгкая корочка, затем энергично перемешивайте 2–3 минуты. Верните курицу в вок, добавьте кечап манис и соевый соус и перемешайте, чтобы покрыть равномерно. Приправьте солью и белым перцем. Сдвиньте рис в сторону, разбейте яйца, слегка перемешайте, затем вмешайте в рис и готовьте 1 минуту до лёгкого схватывания. Разложите по мискам, украсьте ломтиками огурца и обжаренным луком-шалотом.","en":"Break up the cold rice with your hands to separate any clumps. Heat 1 tbsp of oil in a wok over high heat until smoking. Add the chicken cubes and stir-fry for 3–4 minutes until cooked through and lightly golden; remove and set aside. Add the remaining 2 tbsp of oil to the wok. Add the shallots and stir-fry for 2 minutes until softened. Add the garlic, chilli, and shrimp paste and stir-fry for 1 minute until fragrant. Add the rice, spread into an even layer, and leave untouched for 1 minute to form a slight crust, then toss vigorously for 2–3 minutes. Return the chicken, add the kecap manis and soy sauce, and toss to coat evenly. Season with salt and white pepper. Push the rice to the side, crack in the eggs, scramble briefly, then fold into the rice and cook for 1 minute until just set. Serve in bowls topped with cucumber slices and fried shallots."}},{"id":42,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ru":"Швейцария","en":"Switzerland","ro":"Elveția"},"name":{"ru":"Фондю","en":"Fondue","ro":"Fondue"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["400 г Грюйера, крупно натёртого","200 г Эменталя, крупно натёртого","1 зубчик чеснока, разрезанный пополам","300 мл сухого белого вина (Фендан или Шасла)","1 ст. л. кукурузного крахмала","2 ст. л. кирша (вишнёвого бренди)","щепотка свежетёртого мускатного ореха","свежемолотый чёрный перец по вкусу","1 большой хрустящий багет (ок. 500 г), нарезанный кубиками 2 см","корнишоны и молодой отварной картофель для подачи"],"en":["400 g Gruyère, coarsely grated","200 g Emmental, coarsely grated","1 garlic clove, halved","300 ml dry white wine (Fendant or Chasselas)","1 tbsp cornstarch","2 tbsp kirsch (cherry brandy)","a pinch of freshly grated nutmeg","freshly ground black pepper to taste","1 large crusty baguette (about 500 g), cut into 2 cm cubes","cornichons and boiled new potatoes to serve"],"ro":["400 g Gruyère, ras grosier","200 g Emmental, ras grosier","1 cățel de usturoi, tăiat pe jumătate","300 ml vin alb sec (Fendant sau Chasselas)","1 lingură amidon de porumb","2 linguri kirsch (rachiu de cireșe)","un praf de nucșoară rasă proaspăt","piper negru proaspăt măcinat după gust","1 baghetă mare crocantă (cca. 500 g), tăiată cubulețe de 2 cm","cornișoni și cartofi noi fierți pentru servire"]},"howIsMade":{"ru":"Натрите внутренние стенки фондюшницы разрезанной стороной зубчика чеснока; чеснок выбросить. Влейте вино в кастрюлю и нагрейте на среднем огне до состояния чуть ниже кипения. Смешайте тёртый Грюйер и Эменталь с кукурузным крахмалом до равномерного покрытия. Добавляйте сыр в тёплое вино тремя порциями, каждый раз помешивая восьмёркой до полного расплавления и гладкости, около 8–10 минут в общей сложности. Добавьте кирш, мускатный орех и молотый перец; фондю должно быть достаточно густым, чтобы обволакивать ложку. Поставьте кастрюлю на горелку на минимальный огонь для лёгкого кипения. Насадите хлебные кубики на вилки и опускайте в сыр, достигая дна, чтобы предотвратить образование корки. Подавайте с корнишонами и отварным молодым картофелем.","en":"Rub the inside of a fondue pot with the cut sides of the garlic clove; discard the garlic. Pour the wine into the pot and heat over medium heat until just below simmering. Toss the grated Gruyère and Emmental with the cornstarch until evenly coated. Add the cheese to the warm wine in three batches, stirring in a figure-eight motion after each addition until fully melted and smooth, about 8–10 minutes total. Stir in the kirsch, nutmeg, and a grind of black pepper; the fondue should be thick enough to coat a spoon. Place the pot over a fondue burner set to low to keep it gently bubbling. Spear bread cubes on fondue forks and swirl into the cheese, reaching the bottom of the pot to prevent a crust from forming. Serve with cornichons and boiled new potatoes."}},{"id":43,"servings":4,"tipType":"fish","pairingsType":"middle-eastern","origin":{"ru":"Ирак","en":"Iraq","ro":"Irak"},"name":{"ru":"Масгуф","en":"Masgouf","ro":"Masgouf"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1 целый карп или сибас (ок. 1,5 кг), выпотрошенный и очищенный","4 ст. л. оливкового масла","1 ч. л. соли","1 ч. л. молотой куркумы","1 ч. л. молотого тмина","2 помидора, крупно нарезанных","1 лимон, нарезанный ломтиками","4 зубчика чеснока, мелко нарубленных","1 небольшая луковица, крупно нарезанная","2 ст. л. томатной пасты","свежемолотый чёрный перец по вкусу","4 лепёшки для подачи","нарезанный лук, помидоры и маринованные овощи для подачи"],"en":["1 whole carp or sea bass (about 1.5 kg), gutted and cleaned","4 tbsp olive oil","1 tsp salt","1 tsp ground turmeric","1 tsp ground cumin","2 tomatoes, roughly chopped","1 lemon, sliced","4 garlic cloves, minced","1 small onion, roughly chopped","2 tbsp tomato paste","freshly ground black pepper to taste","4 flatbreads to serve","sliced onion, tomato, and pickles to serve"],"ro":["1 crap sau biban întreg (cca. 1,5 kg), curățat și eviscerat","4 linguri ulei de măsline","1 linguriță sare","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","2 roșii, tăiate grosier","1 lămâie, feliată","4 căței de usturoi, tocați","1 ceapă mică, tocată grosier","2 linguri pastă de roșii","piper negru proaspăt măcinat după gust","4 pâini plate pentru servire","ceapă feliată, roșii și murături pentru servire"]},"howIsMade":{"ru":"Острым ножом сделайте глубокий разрез вдоль хребта, чтобы раскрыть рыбу плашмя. Надрежьте мякоть по диагонали каждые 4 см. Смешайте оливковое масло, куркуму, тмин, соль и перец; натрите всю мякоть и внутреннюю полость. Оставьте мариноваться на 20 минут при комнатной температуре. Тем временем смешайте помидоры, лук, чеснок, ломтики лимона и томатную пасту для соуса. Нанижите рыбу на два длинных шампура, чтобы она оставалась плоской. Жарьте над тлеющими углями (не открытым огнём) 30–40 минут: мякотью вниз первые 20 минут до побеления и отставания от кости, затем кожей вниз 10–15 минут до хрустящей корочки. Смазывайте соусом каждые 5 минут. Подавайте немедленно с лепёшками, нарезанным луком, помидорами и маринадами.","en":"Using a sharp knife, make a deep cut along the backbone to butterfly the fish open flat. Score the flesh diagonally every 4 cm. Mix the olive oil, turmeric, cumin, salt, and pepper; rub all over the flesh and inside the cavity. Leave to marinate for 20 minutes at room temperature. Meanwhile, combine the tomatoes, onion, garlic, lemon slices, and tomato paste to make the basting sauce. Thread the fish onto two long skewers (or use a fish grill basket) to hold it flat. Grill over glowing wood embers or charcoal (not open flames) for 30–40 minutes: flesh side down for the first 20 minutes until the flesh is opaque and pulls away from the bone, then skin side down for 10–15 minutes until the skin is crisp. Baste with the sauce every 5 minutes. Serve immediately with flatbread, sliced onion, tomato, and pickles."}},{"id":44,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ru":"Израиль","en":"Israel","ro":"Israel"},"name":{"ru":"Шакшука","en":"Shakshuka","ro":"Shakshuka"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ru":["2 ст. л. оливкового масла","1 крупная луковица, мелко нарезанная","1 красный болгарский перец, мелко нарезанный","4 зубчика чеснока, мелко нарубленных","1 ч. л. молотого тмина","1 ч. л. сладкой паприки","½ ч. л. копчёной паприки","¼ ч. л. хлопьев чили","2 банки по 400 г измельчённых помидоров","1 ч. л. сахара","соль и свежемолотый чёрный перец по вкусу","6 яиц","небольшая горсть свежей петрушки или кинзы, крупно нарубленных","хрустящий хлеб или пита для подачи"],"en":["2 tbsp olive oil","1 large onion, finely diced","1 red bell pepper, finely diced","4 garlic cloves, minced","1 tsp ground cumin","1 tsp sweet paprika","½ tsp smoked paprika","¼ tsp chilli flakes","2 x 400 g cans crushed tomatoes","1 tsp sugar","salt and freshly ground black pepper to taste","6 eggs","a small handful of fresh flat-leaf parsley or coriander, roughly chopped","crusty bread or pita to serve"],"ro":["2 linguri ulei de măsline","1 ceapă mare, tăiată mărunt","1 ardei kapia roșu, tăiat mărunt","4 căței de usturoi, tocați","1 linguriță chimen măcinat","1 linguriță boia dulce","½ linguriță boia afumată","¼ linguriță fulgi de ardei iute","2 x 400 g roșii zdrobite la conservă","1 linguriță zahăr","sare și piper negru proaspăt măcinat după gust","6 ouă","o mână de frunze de pătrunjel sau coriandru, tocate grosier","pâine crocantă sau pita pentru servire"]},"howIsMade":{"ru":"Разогрейте оливковое масло в широкой глубокой сковороде на среднем огне. Добавьте лук и перец и готовьте, периодически помешивая, 8 минут до мягкости и лёгкого зарумянивания. Добавьте чеснок, тмин, оба вида паприки и хлопья чили и перемешивайте 1 минуту до появления аромата. Влейте помидоры, добавьте сахар и щедро приправьте. Тушите 10 минут до загустения соуса. Ложкой сделайте 6 лунок. В каждую лунку разбейте по яйцу, накройте крышкой и готовьте 8–10 минут, пока белки не схватятся, а желтки останутся жидкими. Посыпьте петрушкой или кинзой и подайте немедленно с хрустящим хлебом или питой.","en":"Heat the olive oil in a wide, deep frying pan over medium heat. Add the onion and red pepper and cook, stirring occasionally, for 8 minutes until softened and beginning to colour. Add the garlic, cumin, sweet paprika, smoked paprika, and chilli flakes and stir for 1 minute until fragrant. Pour in the crushed tomatoes, add the sugar, and season generously with salt and pepper. Simmer for 10 minutes, stirring occasionally, until the sauce thickens and deepens in colour. Make 6 wells in the sauce with a spoon. Crack one egg into each well, then cover the pan with a lid and cook for 8–10 minutes until the whites are just set but the yolks are still runny. Scatter the parsley or coriander over the top and serve immediately from the pan with crusty bread or pita."}},{"id":45,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ru":"Финляндия","en":"Finland","ro":"Finlanda"},"name":{"ru":"Лохикейтто","en":"Salmon Soup","ro":"Lohikeitto"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["600 г свежего филе лосося, без кожи, нарезанного кусками по 3 см","500 г картофеля с плотной мякотью (Шарлотт или аналогичный), очищенного и нарезанного кубиками по 2 см","1 крупный лук-порей, белая и светло-зелёная части, нарезанный тонкими кольцами","2 средние моркови, очищенные и нарезанные кружочками по 5 мм","1 литр хорошего рыбного бульона","200 мл жирных сливок","1 лавровый лист","5 горошин душистого перца","1 ч. л. мелкой морской соли, ещё по вкусу","¼ ч. л. молотого белого перца","1 большой пучок свежего укропа (около 30 г), крупно нарубленного"],"en":["600 g fresh salmon fillet, skin removed, cut into 3 cm chunks","500 g waxy potatoes (Charlotte or similar), peeled and cut into 2 cm cubes","1 large leek, white and pale-green parts, thinly sliced into rings","2 medium carrots, peeled and sliced 5 mm thick","1 litre good-quality fish stock","200 ml double cream","1 bay leaf","5 whole allspice berries","1 tsp fine sea salt, plus more to taste","¼ tsp ground white pepper","1 large bunch fresh dill (about 30 g), roughly chopped"],"ro":["600 g file de somon proaspăt, fără piele, tăiat cuburi de 3 cm","500 g cartofi cu pulpă fermă (Charlotte sau similari), curățați, cuburi de 2 cm","1 praz mare, partea albă și verde deschis, tăiat rondele subțiri","2 morcovi medii, curățați, rondele de 5 mm","1 litru supă de pește bine aromatizată","200 ml smântână dulce pentru gătit","1 frunză de dafin","5 boabe de ienibahar","1 linguriță sare fină, plus după gust","¼ linguriță piper alb măcinat","1 mănunchi mare de mărar proaspăt (cca 30 g), tocat grosier"]},"howIsMade":{"ru":"Влейте рыбный бульон в большую кастрюлю и доведите до тихого кипения на среднем огне. Добавьте картофель, морковь, порей, лавровый лист и душистый перец. Варите на слабом огне 12–15 минут, пока картофель не станет мягким при прокалывании ножом. Уменьшите огонь до минимума — бульон должен едва дрожать, не кипеть. Добавьте кусочки лосося и варите 4–5 минут, пока рыба не станет едва непрозрачной и легко разделится на хлопья. Влейте сливки и прогрейте 2 минуты, не доводя до кипения. Посолите, поперчите белым перцем. Уберите лавровый лист и перец. Разлейте по тёплым тарелкам и щедро посыпьте свежим укропом. Подавайте с тёмным ржаным хлебом.","en":"Pour the fish stock into a large pot and bring to a gentle simmer over medium heat. Add the potatoes, carrots, leek, bay leaf, and allspice berries. Cook at a gentle simmer for 12–15 minutes until the potatoes are just tender when pierced with a knife. Lower the heat so the stock barely trembles — do not boil. Add the salmon chunks and cook for 4–5 minutes until the fish is just opaque and flakes easily when nudged. Stir in the cream and heat for 2 minutes without letting it boil. Season with salt and white pepper. Remove the bay leaf and allspice berries. Ladle into warmed bowls and heap each portion with a generous amount of fresh dill. Serve with dark rye bread alongside."}},{"id":46,"servings":4,"tipType":"meat","timeMins":{"total":300,"active":60},"pairingsType":"middle-eastern","origin":{"ru":"Иран","en":"Iran","ro":"Iran"},"name":{"ru":"Гормех сабзи","en":"Ghormeh Sabzi","ro":"Ghormeh Sabzi"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["700 г бескостной баранины (лопатка) или говядины для тушения, нарезанной кубиками по 4 см","200 г сухой красной фасоли, замоченной на ночь и откинутой на дуршлаг (или 400 г из банки, откинутой)","1 крупная луковица, мелко нарезанная","80 г свежих листьев пажитника (или 3 ст. л. сухого пажитника / кашури метхи)","100 г свежей петрушки с плоскими листьями, мелко нарубленной","80 г свежей кинзы, мелко нарубленной","50 г свежего шпината, мелко нарубленного","4 сушёных персидских лайма (limoo amani), проколотых шпажкой","1 ч. л. молотой куркумы","½ ч. л. молотого чёрного перца","1 ч. л. мелкой морской соли, ещё по вкусу","3 ст. л. растительного масла, разделённого"],"en":["700 g boneless lamb shoulder (or beef chuck), cut into 4 cm cubes","200 g dried red kidney beans, soaked overnight and drained (or 400 g canned, drained)","1 large onion, finely diced","80 g fresh fenugreek leaves (or 3 tbsp dried fenugreek / kasuri methi)","100 g fresh flat-leaf parsley, finely chopped","80 g fresh coriander (cilantro), finely chopped","50 g fresh spinach, finely chopped","4 dried Persian limes (limoo amani), pierced with a skewer","1 tsp ground turmeric","½ tsp ground black pepper","1 tsp fine sea salt, plus more to taste","3 tbsp vegetable oil, divided"],"ro":["700 g carne de miel fără os (spată) sau vită pentru tocăniță, tăiată cuburi de 4 cm","200 g fasole boabe roșie uscată, hidratată peste noapte și scursă (sau 400 g la conservă, scursă)","1 ceapă mare, tăiată mărunt","80 g frunze proaspete de schinduf (sau 3 linguri schinduf uscat / kasoori methi)","100 g pătrunjel frunze plate proaspăt, tocat mărunt","80 g coriandru proaspăt, tocat mărunt","50 g spanac proaspăt, tocat mărunt","4 lămâi persane uscate (limoo amani), înțepate cu un frigărui","1 linguriță turmeric măcinat","½ linguriță piper negru măcinat","1 linguriță sare fină, plus după gust","3 linguri ulei vegetal, separat"]},"howIsMade":{"ru":"В большой тяжёлой кастрюле разогрейте 1 ст; масла на сильном огне. Обжарьте мясо двумя партиями, 3–4 минуты каждая, до тёмно-коричневой корочки со всех сторон; отложите. В той же кастрюле обжаривайте лук на среднем огне 8 минут до золотистости; добавьте куркуму и перец; перемешайте 1 минуту. Верните мясо, добавьте откинутую фасоль и проколотые лаймы; залейте водой вровень. Доведите до кипения, снимите пену, затем уменьшите огонь до минимума; в это время на оставшемся масле в большой сковороде на сильном огне обжаривайте все травы 15–20 минут, постоянно помешивая, пока они не станут очень тёмно-зелёными и вся влага не испарится — это ключевой шаг, создающий характерный вкус блюда. Вмешайте обжаренные травы в тушёнку; посолите. Накройте крышкой и тушите на минимальном огне 2–2,5 часа (сухая фасоль) или 1,5 часа (консерва), периодически помешивая, пока мясо не станет очень мягким; подавайте на пропаренном рисе басмати.","en":"Heat 1 tbsp oil in a large heavy pot over medium-high heat; brown the meat in two batches, 3–4 minutes per batch, until deep brown on all sides. Remove and set aside; in the same pot, cook the onion over medium heat for 8 minutes until golden. Add the turmeric and black pepper; stir for 1 minute; return the meat to the pot. Add the drained kidney beans and pierced dried limes; pour over just enough water to barely cover. Bring to the boil, skim the foam, then reduce to the lowest possible simmer; meanwhile, heat the remaining 2 tbsp oil in a large frying pan over medium-high heat. Add all the herbs (fenugreek, parsley, coriander, spinach) and stir-fry for 15–20 minutes, until the herbs turn very dark green and all moisture has fully evaporated — this step is critical and builds the stew's characteristic deep flavour; stir the fried herbs into the stew. Season with salt; cover and simmer on the lowest heat for 2–2.5 hours (if using dried beans) or 1.5 hours (canned beans), stirring occasionally, until the meat is very tender and pulls apart easily. The stew should be thick and deeply coloured; serve over steamed basmati rice."}},{"id":47,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ru":"Португалия","en":"Portugal","ro":"Portugalia"},"name":{"ru":"Бакальяу а Браш","en":"Bacalhau à Brás","ro":"Bacalhau à Brás"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500г солёной трески, вымоченной 24–48ч и разобранной на хлопья","600г твёрдого картофеля, нарезанного очень тонкими соломками","6 крупных яиц, слегка взбитых","2 средние белые луковицы, тонко нарезанные","4 ст.л. оливкового масла extra virgin","3 зубчика чеснока, тонко нарезанных","Небольшой пучок плоской петрушки, крупно нарубленный","80г чёрных оливок без косточек","Соль и белый перец по вкусу"],"en":["500g salted cod (bacalhau), soaked 24–48h in cold water and shredded into flakes","600g waxy potatoes, peeled and cut into very thin matchstick strips","6 large eggs, lightly beaten","2 medium white onions, thinly sliced","4 tbsp extra-virgin olive oil","3 garlic cloves, thinly sliced","Small bunch of fresh flat-leaf parsley, roughly chopped","80g black olives, pitted, to serve","Salt and white pepper to taste"],"ro":["500g cod sărat (bacalhau), înmuiat 24–48h și desfăcut în fâșii","600g cartofi cerați, curățați și tăiați în bețișoare foarte subțiri","6 ouă mari, ușor bătute","2 cepe medii albe, tăiate felii subțiri","4 linguri ulei de măsline extravirgin","3 căței de usturoi, tăiați felii subțiri","Legătură mică de pătrunjel proaspăt, tocat grosier","80g măsline negre, fără sâmburi","Sare și piper alb"]},"howIsMade":{"ru":"Залейте кусочки трески холодной водой, меняя её четыре раза за 24–48 часов, пока кусочек не станет приятно солоноватым; откиньте и обсушите. Нарежьте картофель тонкими соломками; в 2 см нейтрального масла при 170°C обжаривайте соломку порциями 3–4 минуты до светло-золотистого цвета. Обсушите на бумаге, масло слейте; протрите сковороду. На оливковом масле на слабом огне пассеруйте лук и чеснок, помешивая, 12–15 минут до мягкости; добавьте треску и мешайте 2 минуты. Всыпьте картофельную соломку и осторожно перемешайте; влейте взбитые яйца с белым перцем. Постоянно мешайте на слабом огне широкими медленными движениями 2–3 минуты — яйца должны образовать мягкие кремовые складки; снимите с огня, пока яйца ещё слегка не готовы. Проверьте соль; посыпьте петрушкой, подайте с оливками.","en":"Soak the shredded cod in cold water, changing the water four times over 24–48 hours until a small piece tastes pleasantly savoury rather than sharp; drain and pat dry. Cut potatoes into very thin matchstick strips; heat 2cm of neutral oil in a deep frying pan to 170°C and fry the potato strips in batches for 3–4 minutes until pale golden; drain on paper. Discard the frying oil and wipe the pan; heat olive oil over medium-low heat and cook the onion and garlic, stirring often, for 12–15 minutes until very soft and lightly golden. Add the cod flakes and stir for 2 minutes until warmed through; tip in the potato strips and toss once. Pour in the beaten eggs seasoned with white pepper; stir continuously over low heat with slow, wide folds for 2–3 minutes — the eggs should set in soft, creamy layers, never dry or granular. Remove from heat while the eggs still look slightly underdone; residual heat finishes the dish; taste for salt before adding any — the cod may already hold enough; scatter with parsley and serve straight from the pan with black olives alongside."}},{"id":48,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Филиппины","en":"Philippines","ro":"Filipine"},"name":{"ru":"Адобо","en":"Adobo","ro":"Adobo"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1,2 кг куриных бёдер и голеней на кости с кожей (или 1 кг свиной грудинки, нарезанной кубиками 4 см)","6 зубчиков чеснока, раздавленных","125 мл тростникового уксуса или белого винного уксуса","80 мл соевого соуса","3 лавровых листа","1 ч. л. целых горошин чёрного перца","80 мл воды","2 ст. л. растительного масла"],"en":["1.2 kg chicken thighs and drumsticks, bone-in skin-on (or 1 kg pork belly cut into 4 cm cubes)","6 garlic cloves, crushed","125 ml cane vinegar or white wine vinegar","80 ml soy sauce","3 bay leaves","1 tsp whole black peppercorns","80 ml water","2 tbsp vegetable oil"],"ro":["1,2 kg pulpe și tobe de pui (cu os, cu piele) sau 1 kg burtă de porc tăiată cuburi de 4 cm","6 căței de usturoi, zdrobiți","125 ml oțet de trestie sau oțet alb de vin","80 ml sos de soia","3 frunze de dafin","1 linguriță boabe de piper negru","80 ml apă","2 linguri ulei vegetal"]},"howIsMade":{"ru":"В большой кастрюле смешайте курицу (или свинину), чеснок, уксус, соевый соус, лавровые листья, перец горошком и воду. Маринуйте 30 минут при комнатной температуре. Доведите до кипения на среднем огне, не мешая. После закипания убавьте огонь до минимума, накройте крышкой и тушите 30 минут (курица) или 45 минут (свинина) до мягкости мяса. Откройте крышку, увеличьте огонь до среднего. Продолжайте варить, периодически переворачивая мясо, 15–20 минут, пока соус не уварится до густой блестящей глазури, обволакивающей ложку. В отдельной сковороде разогрейте масло на сильном огне. Выложите кусочки кожей вниз и обжаривайте 3–4 минуты до золотистой хрустящей корочки. Верните в соус и перемешайте. Удалите лавровые листья. Подавайте на пропаренном белом рисе.","en":"Combine the chicken (or pork), garlic, vinegar, soy sauce, bay leaves, peppercorns, and water in a large pot. Marinate for 30 minutes at room temperature. Bring to the boil over medium-high heat without stirring. Once boiling, reduce heat to low, cover, and simmer for 30 minutes (chicken) or 45 minutes (pork) until the meat is tender. Uncover and increase heat to medium. Continue simmering, turning the meat occasionally, for 15–20 minutes until the sauce reduces to a glossy, thick glaze that coats the back of a spoon. In a separate pan, heat the oil over high heat. Add the cooked pieces skin-side down and fry for 3–4 minutes until the skin is golden brown and crisp. Return to the sauce and toss to coat. Discard bay leaves. Serve over steamed white rice."}},{"id":49,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Ямайка","en":"Jamaica","ro":"Jamaica"},"name":{"ru":"Джерк-чикен","en":"Jerk Chicken","ro":"Jerk Chicken"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1,5 кг куриных бёдер и голеней с кожей, глубоко надрезанных","6 стеблей зелёного лука, крупно нарезанных","3 перца Скотч боннет или хабанеро, без семян","5 зубчиков чеснока","Кусок свежего имбиря 2см, очищенный","2 ст.л. тёмного соевого соуса","2 ст.л. коричневого сахара","1 ст.л. молотого душистого перца","1 ч.л. сушёного тимьяна","½ ч.л. молотой корицы","½ ч.л. чёрного перца","2 ст.л. растительного масла","Сок 2 лаймов, плюс дольки для подачи"],"en":["1.5kg chicken thighs and drumsticks, skin-on, scored deeply with a knife","6 spring onions, roughly chopped","3 Scotch bonnet chilies or habaneros, seeds removed for moderate heat","5 garlic cloves","2cm piece fresh ginger, peeled","2 tbsp dark soy sauce","2 tbsp brown sugar","1 tbsp ground allspice","1 tsp dried thyme","½ tsp ground cinnamon","½ tsp black pepper","2 tbsp vegetable oil","Juice of 2 limes, plus wedges to serve"],"ro":["1,5 kg pulpe și copane de pui, cu piele, crestați adânc","6 fire ceapă verde, tăiate grosier","3 ardei Scotch bonnet (sau habanero), semințele îndepărtate","5 căței de usturoi","Bucată de 2cm ghimbir proaspăt, curățat","2 linguri sos de soia închis la culoare","2 linguri zahăr brun","1 lingură ienibahar măcinat","1 linguriță cimbru uscat","½ linguriță scorțișoară măcinată","½ linguriță piper negru","2 linguri ulei vegetal","Suc de la 2 lămi verzi, plus felii pentru servire"]},"howIsMade":{"ru":"Смешайте в блендере зелёный лук, острые перцы, чеснок, имбирь, соевый соус, сахар, душистый перец, тимьян, корицу, чёрный перец, масло и сок лайма до состояния грубой пасты. Глубоко надрежьте каждый кусочек до кости — джерк работает только если маринад проникает внутрь мяса. Тщательно покройте пастой, вдавливая в надрезы. Маринуйте в холодильнике минимум 4 часа, идеально — ночь. Достаньте за 30 минут до приготовления. На углях: готовьте при средне-высокой температуре 35–45 минут, переворачивая каждые 10 минут, до прозрачного сока и характерного обугленного внешнего вида. В духовке: 200°C на решётке 40 минут, затем 5 минут под грилем. Дайте отдохнуть 5 минут. Подавайте с рисом и горохом, жареным бананом и дольками лайма.","en":"Blend spring onions, Scotch bonnets, garlic, ginger, soy sauce, brown sugar, allspice, thyme, cinnamon, black pepper, oil, and lime juice in a food processor until a rough paste forms. Score the chicken pieces deeply down to the bone — jerk only works if the marinade penetrates inside the meat. Rub the paste all over and into every cut. Cover and marinate in the refrigerator for at least 4 hours, ideally overnight. Remove from the fridge 30 minutes before cooking. To grill over charcoal: cook over medium-hot coals for 35–45 minutes, turning every 10 minutes, until the juices run clear and the exterior is deeply charred in places. To oven-roast: place on a rack over a baking tray at 200°C for 40 minutes, then finish under a hot grill for 5 minutes to char the skin. Allspice is the defining spice — do not substitute with mixed spice. Rest 5 minutes before serving. Serve with rice and peas, fried plantain, and lime wedges."}},{"id":50,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Эфиопия","en":"Ethiopia","ro":"Etiopia"},"name":{"ru":"Доро Ват","en":"Doro Wat","ro":"Doro Wat"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1,2 кг куриных кусков (бёдра и голени на кости)","3 ст. л. лимонного сока","4 крупные луковицы (около 800 г), очень мелко нарезанные","80 г нитер кибе (эфиопское пряное топлёное масло) или обычного топлёного масла","6 зубчиков чеснока, мелко нарубленных","2 ст. л. свежего тёртого имбиря (кусок около 3 см)","4 ст. л. смеси специй бербере","1 ч. л. молотого кардамона","½ ч. л. молотого пажитника","250 мл воды или куриного бульона","4 сваренных вкрутую яйца, очищенных и наколотых вилкой","соль по вкусу"],"en":["1.2 kg chicken pieces (thighs and drumsticks, bone-in)","3 tbsp lemon juice","4 large onions (about 800 g), very finely diced","80 g niter kibbeh (Ethiopian spiced butter) or clarified butter","6 garlic cloves, minced","2 tbsp fresh ginger, finely grated (about 3 cm piece)","4 tbsp berbere spice blend","1 tsp ground cardamom","½ tsp ground fenugreek","250 ml water or chicken stock","4 hard-boiled eggs, shelled and scored all over with a fork","salt to taste"],"ro":["1,2 kg piese de pui (pulpe și tobe cu os)","3 linguri suc de lămâie","4 cepe mari (cca 800 g), tăiate mărunt fin","80 g unt etiopian niter kibbeh (sau unt clarificat)","6 căței de usturoi, tocați mărunt","2 linguri ghimbir proaspăt ras (cca 3 cm bucată)","4 linguri amestec de condimente berbere","1 linguriță cardamom măcinat","½ linguriță schinduf măcinat","250 ml apă sau supă de pui","4 ouă fierte tari, curățate, înțepate cu furculița","sare după gust"]},"howIsMade":{"ru":"Проколите курицу вилкой со всех сторон и натрите лимонным соком; очень мелко нарезанный лук без масла положите в большую тяжёлую кастрюлю на слабый огонь. Готовьте, часто помешивая, 25–30 минут, пока лук не станет очень мягким, тёмно-золотистым и не запахнет карамелью — это долгое сухое обжаривание создаёт ароматную базу рагу; добавьте нитер кибе и перемешайте. Добавьте чеснок, имбирь, бербере, кардамон и пажитник; готовьте 5 минут, постоянно помешивая, пока специи не раскроются и масло не станет глубоко красно-оранжевым. Добавьте куриные куски и хорошо обваляйте; готовьте 5 минут, переворачивая, пока не запечатаются со всех сторон. Влейте воду или бульон; доведите до кипения, уменьшите до минимума, накройте и готовьте 40–45 минут, перевернув курицу на полпути, пока мясо не станет очень мягким. Наколите яйца вилкой и положите в соус; варите без крышки 10 минут, пока яйца не покраснеют. Посолите; подавайте на лепёшке инджера или рисе.","en":"Prick the chicken all over with a fork and rub with lemon juice; put the finely diced onions into a large heavy pot over low heat with no oil or fat. Cook, stirring often, for 25–30 minutes until the onions are very soft, deep golden-brown, and smell caramel-like — this long dry fry builds the stew's flavour base; add the niter kibbeh and stir to coat. Add the garlic, ginger, berbere, cardamom, and fenugreek; cook for 5 minutes, stirring constantly, until the spices bloom and the butter turns deep red-orange. Add the chicken pieces and turn to coat completely; cook 5 minutes, turning, until sealed on all sides. Pour in the water or stock; bring to the boil, then reduce to the lowest simmer. Cover and cook for 40–45 minutes, turning the chicken halfway through, until the meat is very tender and nearly falling off the bone; score the eggs all over with a fork and nestle them into the sauce. Simmer uncovered for 10 more minutes until the eggs are stained red from the sauce and the sauce has thickened; season with salt; serve on injera flatbread or steamed rice."}},{"id":51,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"ru":"Сирия","en":"Syria","ro":"Siria"},"name":{"ru":"Киббе","en":"Kibbeh","ro":"Kibbeh"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["Тесто: 300 г мелкого булгура (#1), промытого и хорошо отжатого","400 г очень постного бараньего (или говяжьего) фарша, охлаждённого","1 средняя луковица, мелко натёртая","1 ч. л. молотого душистого перца","1 ч. л. молотой корицы","1 ч. л. мелкой соли","½ ч. л. молотого чёрного перца","Начинка: 300 г бараньего (или говяжьего) фарша","1 средняя луковица, мелко нарезанная","80 г кедровых орехов (или кешью)","1 ч. л. молотого душистого перца","½ ч. л. молотой корицы","1 ст. л. растительного масла","Растительное масло для фритюра (около 1 литра)"],"en":["Shell: 300 g fine bulgur wheat (#1 grade), rinsed and drained","400 g very lean lamb (or beef) mince, chilled","1 medium onion, finely grated","1 tsp ground allspice","1 tsp ground cinnamon","1 tsp fine salt","½ tsp ground black pepper","Filling: 300 g lamb (or beef) mince","1 medium onion, finely diced","80 g pine nuts (or cashews)","1 tsp ground allspice","½ tsp ground cinnamon","1 tbsp vegetable oil","Vegetable oil for deep-frying (about 1 litre)"],"ro":["Coajă: 300 g bulgur fin (#1), clătit și scurs bine","400 g carne de miel sau vită slabă, tocată fin și răcită","1 ceapă medie, rasă sau blenderizată","1 linguriță condiment allspice (ienibahar măcinat)","1 linguriță scorțișoară măcinată","1 linguriță sare fină","½ linguriță piper negru măcinat","Umplutură: 300 g carne de miel sau vită tocată","1 ceapă medie, tăiată mărunt","80 g nuci de pin (sau nuci caju)","1 linguriță allspice","½ linguriță scorțișoară","1 lingură ulei vegetal","Ulei vegetal pentru prăjit adânc (cca 1 litru)"]},"howIsMade":{"ru":"Замочите булгур в холодной воде на 15 минут, затем откиньте и хорошо отожмите руками; смешайте с холодным постным фаршем, тёртым луком, душистым перцем, корицей, солью и перцем в кухонном комбайне. Прокрутите 3–4 минуты, добавляя по столовой ложке ледяной воды при необходимости, пока не получится плотное однородное тесто; уберите в холодильник на 30 минут. Начинка: разогрейте масло на среднем огне; лук обжарьте 5 минут. Добавьте фарш и обжаривайте 6–8 минут, тщательно разминая; добавьте душистый перец, корицу, перец и кедровые орехи; готовьте 2 минуты. Полностью остудите; формовка: смочите руки холодной водой. Возьмите 60 г теста и сформируйте вокруг указательного пальца полую торпеду со стенками 5 мм; наполните 1 ст. начинки; крепко защипните открытый конец в острый кончик. Повторите; поставьте в холодильник на 30 минут. Жарка: разогрейте масло до 175°C; обжаривайте порциями по 4–5 штук 4–5 минут, осторожно переворачивая, до глубокого золотисто-коричневого цвета. Откиньте на бумагу; подавайте горячими с йогуртом или чесночным соусом и питой.","en":"Soak the bulgur in cold water for 15 minutes, then drain and squeeze out all moisture firmly with your hands; combine with the chilled lean mince, grated onion, allspice, cinnamon, salt, and pepper in a food processor. Process for 3–4 minutes, adding ice water a tablespoon at a time if needed, until you have a smooth, stiff dough; refrigerate for 30 minutes. Make the filling: heat the oil over medium heat; cook the onion for 5 minutes until soft. Add the mince and brown, breaking it up, for 6–8 minutes; stir in allspice, cinnamon, pepper, and pine nuts; cook 2 minutes. Cool completely; shape: wet your hands with cold water. Take a 60 g piece of dough and mould it around your index finger into a hollow torpedo shape with 5 mm thick walls; fill the hollow with about 1 tablespoon of filling. Pinch the open end firmly to seal it into a pointed torpedo; repeat with the remaining dough and filling. Refrigerate for at least 30 minutes; fry: heat oil to 175°C. Fry in batches of 4–5 for 4–5 minutes, turning gently, until deep golden brown all over; drain on paper; serve warm with yoghurt or garlic sauce and pita bread."}},{"id":52,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"ru":"Нидерланды","en":"Netherlands","ro":"Olanda"},"name":{"ru":"Стамппот","en":"Stamppot","ro":"Stamppot"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1 кг разваристого картофеля (типа «Синеглазки»), очищенного и разрезанного на четвертинки","400 г кудрявой капусты (бурэнколь), жесткие стебли удалены, листья крупно нарезаны","400 г копченой свиной колбасы (rookworst) или братвурст","80 г несоленого сливочного масла, нарезанного кубиками","100 мл цельного молока, подогретого","1/4 ч. л. свежетертого мускатного ореха","1 1/2 ч. л. мелкой морской соли, разделенной","1/2 ч. л. свежемолотого черного перца"],"en":["1 kg floury potatoes (such as Maris Piper or Russet), peeled and quartered","400 g curly kale (boerenkool), tough stems removed, leaves roughly chopped","400 g smoked pork sausage (rookworst) or bratwurst","80 g unsalted butter, cut into cubes","100 ml whole milk, warmed","1/4 tsp freshly grated nutmeg","1 1/2 tsp fine sea salt, divided","1/2 tsp freshly ground black pepper"],"ro":["1 kg cartofi făinoși (tip Maris Piper sau Russet), curățați și tăiați în sferturi","400 g varză creață (boerenkool), tulpini dure îndepărtate, frunze tocate grosier","400 g cârnați afumați din porc (rookworst) sau bratwurst","80 g unt nesărat, tăiat cubulețe","100 ml lapte integral, încălzit","1/4 linguriță nucșoară proaspăt rasă","1 1/2 linguriță sare fină de mare, împărțită","1/2 linguriță piper negru proaspăt măcinat"]},"howIsMade":{"ru":"Доведите большую кастрюлю воды с 1 ч. л. соли до кипения, добавьте картофель и варите 18-20 минут до полной мягкости — он должен легко протыкаться ножом. Пока варится картофель, доведите в другой кастрюле подсоленную воду до кипения, добавьте кудрявую капусту и бланшируйте 5-6 минут до мягкости; хорошо откиньте на дуршлаг, отожмите лишнюю воду и крупно порубите. Положите копченую колбасу в сковороду, залейте водой так, чтобы она покрывала колбасу, и тушите на среднем огне 20 минут до прогрева — или обжарьте в небольшом количестве масла на среднем огне 8-10 минут, перевернув на половине, до золотистой корочки со всех сторон. Откиньте картофель и верните в горячую кастрюлю на слабый огонь на 1-2 минуты, встряхивая кастрюлю для выпаривания влаги — это сделает пюре не водянистым. Добавьте масло и теплое молоко и энергично разомните толкушкой до однородного кремового пюре. Вмешайте откинутую капусту, приправьте оставшейся солью, черным перцем и мускатным орехом и перемешайте до равномерного соединения. Подавайте сразу в глубоких тарелках, выложив нарезанную колбасу сверху.","en":"Bring a large pot of water with 1 tsp salt to the boil, add the potatoes, and cook for 18-20 minutes until completely tender when pierced with a knife. While the potatoes cook, bring a separate pot of salted water to the boil, add the kale, and blanch for 5-6 minutes until wilted and tender; drain well, squeeze out excess water, and chop roughly. Place the smoked sausage in a pan, add enough water to just cover, and simmer over medium heat for 20 minutes until heated through — or pan-fry in a little oil over medium heat for 8-10 minutes, turning halfway, until browned on all sides. Drain the potatoes and return them to the hot pot over low heat for 1-2 minutes, shaking the pot to steam-dry them and prevent a watery mash. Add the butter and warm milk and mash vigorously with a potato masher until smooth and creamy. Fold in the drained kale, season with the remaining salt, black pepper, and nutmeg, and stir until evenly combined. Serve immediately in deep bowls with the sliced sausage on top."}},{"id":53,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Новая Зеландия","en":"New Zealand","ro":"Noua Zeelandă"},"name":{"ru":"Ханги","en":"Hangi","ro":"Hangi"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["600 г баранины с костью (лопатка или ребра), нарезанной кусками по 4 см","4 куриных голени (около 600 г), с кожей","500 г картофеля для варки, очищенного и разрезанного пополам","300 г кумара (оранжевый батат), очищенного и нарезанного кубиками 4 см","300 г тыквы баттернат, очищенной и нарезанной кубиками 4 см","1/4 головы савойской капусты (около 300 г), разрезанной на 4 части","3 ст. л. растительного масла","1 1/2 ч. л. мелкой соли","1/2 ч. л. молотого черного перца"],"en":["600 g bone-in lamb shoulder or ribs, cut into 4 cm pieces","4 chicken drumsticks (about 600 g total), skin-on","500 g waxy potatoes, peeled and halved","300 g kumara (orange sweet potato), peeled and cut into 4 cm cubes","300 g butternut pumpkin, peeled and cut into 4 cm cubes","1/4 head savoy cabbage (about 300 g), cut into 4 wedges","3 tbsp vegetable oil","1 1/2 tsp fine salt","1/2 tsp ground black pepper"],"ro":["600 g carne de miel cu os (spată sau coaste), tăiată în bucăți de 4 cm","4 pulpe inferioare de pui (cca 600 g total), cu os și piele","500 g cartofi waxy, curățați și tăiați în jumătăți","300 g kumara (batată portocalie), curățată și tăiată cubulețe de 4 cm","300 g dovleac butternut, curățat și tăiat cubulețe de 4 cm","1/4 dintr-un cap de varză Savoy (cca 300 g), tăiată în 4 sferturi","3 linguri ulei vegetal","1 1/2 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ru":"Разогрейте духовку до 180°C (160°C с конвекцией). Обильно приправьте баранину и курицу солью и перцем. Разогрейте масло в большой жаростойкой кастрюле на сильном огне и обжарьте куски баранины 3-4 минуты с каждой стороны до глубокого румянца, затем переложите на тарелку. В той же кастрюле обжарьте куриные голени кожей вниз 4-5 минут до золотистой хрустящей корочки, затем отложите. Разложите всё обжаренное мясо в кастрюле и плотно уложите картофель, кумару, тыкву и капустные дольки между кусками. Влейте 200 мл воды, затем очень плотно запечатайте кастрюлю двойным слоем фольги, прижатой к краям, и накройте крышкой. Готовьте в духовке 2 часа, пока баранина не станет полностью мягкой и будет легко отделяться от кости, а все овощи не станут мягкими при прокалывании вилкой — если ещё не готово, снова накройте и готовьте 30 минут. Снимите крышку и фольгу, повысьте температуру до 220°C и запекайте без крышки 15 минут до хрустящей корочки. Дайте отдохнуть 10 минут, затем переложите всё на большое блюдо и полейте собравшимися соками.","en":"Heat the oven to 180°C (160°C fan). Season the lamb and chicken all over with salt and pepper. Heat the oil in a large flameproof casserole over high heat and brown the lamb pieces for 3-4 minutes per side until deeply coloured, then transfer to a plate. In the same pot, brown the chicken drumsticks skin-side down for 4-5 minutes until the skin is golden and crisp, then set aside. Arrange all the browned meat in the casserole and tuck the potatoes, kumara, pumpkin, and cabbage wedges snugly around and between the pieces. Pour in 200 ml of water, then seal the casserole very tightly with a double layer of foil pressed against the rim and put the lid on. Cook in the oven for 2 hours until the lamb is completely tender and pulls away from the bone easily, and all the vegetables are soft when pierced with a fork — if not quite done, cover again and cook for 30 minutes more. Remove the lid and foil, raise the oven to 220°C, and roast uncovered for 15 minutes until the skin crisps. Rest for 10 minutes before transferring everything to a large platter and spooning the collected juices over the top."}},{"id":54,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ru":"Бельгия","en":"Belgium","ro":"Belgia"},"name":{"ru":"Мидии с картошкой фри","en":"Moules-frites","ro":"Moules-frites"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["2 кг свежих живых мидий, промытых и очищенных от бисуса","800г рассыпчатого картофеля, нарезанного толстыми брусками","50г несолёного сливочного масла","4 луковицы-шалот, мелко нарезанных","4 зубчика чеснока, тонко нарезанных","200мл сухого белого вина","2 стебля сельдерея, тонко нарезанных","Небольшой пучок свежей петрушки, мелко нарубленной","Растительное масло или говяжий жир для жарки","Соль и чёрный перец"],"en":["2kg fresh live mussels, scrubbed and beards removed","800g floury potatoes, peeled and cut into thick batons","50g unsalted butter","4 shallots, finely diced","4 garlic cloves, thinly sliced","200ml dry white wine","2 celery stalks, finely sliced","Small bunch of fresh parsley, finely chopped","Vegetable oil or beef dripping, for deep-frying","Salt and black pepper"],"ro":["2 kg midii proaspete vii, curățate și cu beard-ul îndepărtat","800g cartofi făinoși, curățați și tăiați bețe groase","50g unt nesărat","4 șalote, tocate mărunt","4 căței de usturoi, felii subțiri","200ml vin alb sec","2 tulpini de țelină, feliate subțire","Legătură mică de pătrunjel proaspăt, tocat mărunt","Ulei vegetal sau grăsime de vită, pentru prăjit","Sare și piper negru"]},"howIsMade":{"ru":"Для картофеля фри: нарежьте картофель толстыми брусками и замочите в холодной воде на 30 минут, затем обсушите насухо; первая жарка при 140°C в течение 6–8 минут — до готовности, но без цвета; откиньте и полностью остудите. Постучите каждой открытой мидией о столешницу — выбросьте те, что не закрылись; растопите масло в большой кастрюле при средне-высоком огне. Добавьте шалот и сельдерей и тушите 3 минуты; добавьте чеснок и готовьте 1 минуту. Влейте белое вино, доведите до кипения, добавьте мидии и плотно накройте; готовьте на пару 4–5 минут, раз-два встряхивая кастрюлю, до открытия раковин. Выбросьте закрытые; добавьте петрушку и приправьте бульон. Разогрейте масло до 190°C и обжаривайте бланшированные бруски порциями 2–3 минуты до золотистого цвета и хруста; немедленно посолите; подавайте мидии в бульоне, картофель — рядом.","en":"For the frites: cut potatoes into thick batons and soak in cold water for 30 minutes to remove surface starch, then drain and dry thoroughly; first fry at 140°C for 6–8 minutes until cooked through but uncoloured; drain and cool completely. Tap each open mussel on the counter — discard any that do not close; melt butter in a large heavy pot over medium-high heat. Add shallots and celery and cook for 3 minutes until softened; add garlic and cook for 1 minute. Pour in the white wine, bring to a boil, then add the mussels and cover tightly; steam for 4–5 minutes, shaking the pot once or twice, until the shells have opened wide. Discard any that remain shut; stir in most of the parsley and season the broth. Raise the frying oil to 190°C and fry the blanched batons in batches for 2–3 minutes until golden and very crisp; drain and season immediately with salt; serve the mussels in wide bowls in their broth, the frites alongside, with the remaining parsley and mayonnaise on the side."}},{"id":55,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Мусака","en":"Moussaka","ro":"Moussaka"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["2 крупных баклажана (около 1 кг в общей сложности), нарезанных кружками толщиной 1 см","500 г бараньего фарша (или говяжьего)","1 крупная луковица, мелко нарезанная","3 зубчика чеснока, измельчённых","400 г рубленых томатов в собственном соку (1 банка)","2 ст.л. томатной пасты","100 мл красного вина","1 ч.л. сушёного орегано","1/2 ч.л. молотой корицы","60 г сливочного масла (для бешамеля)","60 г пшеничной муки (для бешамеля)","700 мл тёплого молока","2 яичных желтка","80 г тёртого кефалотири (или пармезана)","3 ст.л. оливкового масла","Соль и свежемолотый чёрный перец"],"en":["2 large eggplants (about 1 kg total), sliced 1 cm thick","500 g lamb mince (or beef mince)","1 large onion, finely diced","3 garlic cloves, minced","400 g chopped tomatoes (1 can)","2 tbsp tomato paste","100 ml red wine","1 tsp dried oregano","1/2 tsp ground cinnamon","60 g butter (for the bechamel)","60 g plain flour (for the bechamel)","700 ml warm milk","2 egg yolks","80 g grated kefalotyri (or parmesan)","3 tbsp olive oil","Salt and freshly ground black pepper"],"ro":["2 vinete mari (aproximativ 1 kg in total), feliate de 1 cm grosime","500 g carne tocata de miel (sau de vita)","1 ceapa mare, tocata marunt","3 căței de usturoi, zdrobiti","400 g rosii tocate in conserva (1 conserva)","2 linguri pasta de rosii","100 ml vin rosu","1 lingurita oregano uscat","1/2 lingurita scortisoara macinata","60 g unt (pentru bechamel)","60 g făină alba (pentru bechamel)","700 ml lapte cald","2 galbenusuri de ou","80 g kefalotyri ras (sau parmezan)","3 linguri ulei de masline","Sare si piper negru proaspat macinat"]},"howIsMade":{"ru":"Нарежьте 2 крупных баклажана кружками толщиной 1 см, обильно посолите и оставьте на дуршлаге на 30 минут, чтобы вышла горькая вода; промокните бумажным полотенцем. Смажьте кружки оливковым маслом и запекайте при 200 C 20-25 минут, перевернув один раз, пока они не станут золотистыми и мягкими. В широкой сковороде разогрейте 2 ст.л масла на сильно-среднем огне и обжаривайте 500 г бараньего фарша с одной нарезанной луковицей и 3 зубчиками чеснока 8-10 минут, затем влейте 100 мл красного вина и дайте ему выпариться. Добавьте 400 г рубленых помидоров, 2 ст.л томатной пасты, половину чайной ложки корицы и 1 ч.л орегано; томите на слабом огне 20 минут, пока соус не загустеет и по краям не перестанет скапливаться жидкость. Для бешамеля растопите 60 г сливочного масла в сотейнике, всыпьте 60 г муки и готовьте 2 минуты до светлого цвета, затем постепенно влейте 700 мл тёплого молока, непрерывно взбивая до густоты; снимите с огня, дайте остыть 30 секунд и вмешайте 2 желтка вместе с 80 г тёртого кефалотири или пармезана. В форму для запекания 30x20 см уложите слой баклажанов, половину мясного соуса, второй слой баклажанов, оставшийся соус, затем сверху вылейте бешамель и разровняйте лопаткой. Запекайте при 180 C 40-45 минут, пока верх не станет насыщенно-золотистым, а соус не закипит по краям. Дайте мусаке отдохнуть 15-20 минут перед нарезкой; этот шаг обязателен, чтобы слои схватились и куски держали форму.","en":"Slice 2 large eggplants into 1 cm rounds, salt them generously and let them sit in a colander for 30 minutes to draw out the bitter water; pat dry with paper towels. Brush the slices with olive oil and roast at 200 C for 20-25 minutes, turning once, until golden and tender. In a wide pan heat 2 tbsp oil over medium-high and brown 500 g minced lamb with one chopped onion and 3 garlic cloves for 8-10 minutes, then deglaze with 100 ml red wine and let it reduce. Add 400 g chopped tomatoes, 2 tbsp tomato paste, half a tsp cinnamon and 1 tsp oregano; simmer 20 minutes until thick and no excess liquid pools at the edge. For the bechamel melt 60 g butter in a saucepan, whisk in 60 g flour and cook 2 minutes until blond, then gradually add 700 ml warm milk whisking constantly until thick; off the heat, let it cool 30 seconds and beat in 2 egg yolks with 80 g grated kefalotyri or parmesan. In a 30x20 cm baking dish layer half the eggplant, all the lamb sauce, the remaining eggplant, then pour the bechamel on top and level it with a spatula. Bake at 180 C for 40-45 minutes until the top is deeply golden and the sauce bubbles at the edges. Rest the moussaka for 15-20 minutes before cutting; this step is non-negotiable so the layers set and the slices hold their shape."},"timeMins":{"total":105,"active":35}},{"id":56,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Чехия","en":"Czech Republic","ro":"Republica Cehă"},"name":{"ru":"Свичкова","en":"Svíčková","ro":"Svíčková"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1,2 кг говяжьей вырезки (огузок или толстый край)","100 г копчёного бекона, тонкие полоски для шпигования (по желанию)","30 г сливочного масла","1 ст. л. растительного масла","1 крупная луковица, кубиками","2 крупные моркови, кубиками","1 корень пастернака, кубиками","150 г корня сельдерея, кубиками","2 лавровых листа","6 ягод душистого перца","10 горошин чёрного перца","Цедра 1/2 лимона","1 ст. л. дижонской горчицы","2 ст. л. томатной пасты","200 мл сухого белого вина","500 мл говяжьего бульона","200 мл жирных сливок (33%)","1 ст. л. муки (по желанию, для загустения)","1 ч. л. сахара","Сок 1/2 лимона","Соль, по вкусу","Для подачи: взбитые сливки, брусничный конфитюр, долька лимона, кнедлики"],"en":["1.2 kg beef sirloin (top round or topside)","100 g smoked bacon, cut in thin strips for larding (optional)","30 g butter","1 tbsp neutral oil","1 large onion, diced","2 large carrots, diced","1 parsnip, diced","150 g celeriac, diced","2 bay leaves","6 allspice berries","10 black peppercorns","Zest of 1/2 lemon","1 tbsp Dijon mustard","2 tbsp tomato paste","200 ml dry white wine","500 ml beef stock","200 ml heavy cream (33% fat)","1 tbsp plain flour (optional, for thickening)","1 tsp sugar","Juice of 1/2 lemon","Salt, to taste","To serve: whipped cream, cranberry compote, lemon slice, knedliky"],"ro":["1,2 kg mușchi de vită (vrabia sau pulpă top)","100 g bacon afumat, tăiat fâșii subțiri pentru lardonare (opțional)","30 g unt","1 lingură ulei neutru","1 ceapă mare, tăiată cuburi","2 morcovi mari, tăiați cuburi","1 rădăcină de păstârnac, tăiată cuburi","150 g țelină rădăcină, tăiată cuburi","2 foi de dafin","6 boabe de ienibahar","10 boabe de piper negru","Coaja de la 1/2 lămâie","1 lingură de muștar Dijon","2 linguri de pastă de roșii","200 ml vin alb sec","500 ml supă de vită","200 ml smântână grasă (33% grăsime)","1 lingură de făină albă (opțional, pentru îngroșare)","1 linguriță de zahăr","Zeama de la 1/2 lămâie","Sare, după gust","Pentru servire: frișcă bătută, dulceață de merișoare, felie de lămâie, knedlíky"]},"howIsMade":{"ru":"Нашпигуйте говяжью вырезку (1,2 кг) тонкими полосками копченого бекона или плотно перевяжите кулинарной нитью; обильно приправьте солью и свежемолотым перцем со всех сторон. Разогрейте 30 г сливочного масла и 1 ст.л растительного масла в тяжелой чугунной кастрюле на среднем сильном огне и обжарьте мясо со всех сторон 8-10 минут до глубокой коричневой корочки, затем переложите на тарелку. В той же кастрюле поджарьте мирпуа (1 большая морковь, 1 корень петрушки, 150 г сельдерея, 1 большая луковица, все кубиками) 10-12 минут до карамелизации по краям; добавьте 2 лавровых листа, 6 ягод душистого перца, 10 горошин черного перца, цедру половины лимона и 1 ст.л горчицы. Вмешайте 2 ст.л томатной пасты и готовьте 2 минуты до потемнения, затем дегласируйте 200 мл сухого белого вина и 500 мл говяжьего бульона, соскребая дно, и верните мясо поверх овощей. Накройте и тушите в духовке при 160°C 1,5-2 часа, переворачивая мясо каждые 30 минут, пока вилка не будет входить без сопротивления. Переложите мясо на доску и накройте фольгой для отдыха; пробейте жидкость с овощами погружным блендером до однородности и протрите соус через мелкое сито обратно в кастрюлю. Добавьте 200 мл жирных сливок и при необходимости 1 ст.л муки, разведенной в небольшом количестве холодной воды; варите 5 минут, пока соус не будет глянцево обволакивать обратную сторону ложки, затем доведите по вкусу солью, 1 ч.л сахара и щепоткой лимонного сока для баланса кисло-сладкого. Нарежьте мясо поперек волокон ломтиками толщиной 1 см, полейте сверху теплым соусом и украсьте ложкой взбитых сливок, брусничным конфитюром и долькой лимона; подавайте с кнедликами (хлебными клецками).","en":"Lard the beef sirloin (1.2 kg) with thin strips of smoked bacon, or truss it tightly with kitchen twine; season generously with salt and freshly ground pepper on all sides. Heat 30 g butter and 1 tbsp oil in a heavy Dutch oven over medium-high and sear the beef on every side for 8-10 minutes until a deep brown crust forms, then transfer to a plate. In the same pot brown the mirepoix (1 large carrot, 1 parsnip, 150 g celeriac, 1 large onion, all diced) for 10-12 minutes until caramelised at the edges; add 2 bay leaves, 6 allspice berries, 10 whole black peppercorns, the zest of half a lemon and 1 tbsp mustard. Stir in 2 tbsp tomato paste and cook 2 minutes until it darkens, then deglaze with 200 ml dry white wine and 500 ml beef stock, scraping the bottom, and nestle the beef back in on top of the vegetables. Cover and braise at 160°C for 1.5 to 2 hours, turning the beef every 30 minutes, until a fork slides in with no resistance. Lift the beef onto a board and tent with foil to rest; blend the cooking liquid and vegetables with a stick blender until smooth and pass the sauce through a fine sieve back into the pot. Stir in 200 ml heavy cream and, if needed, 1 tbsp flour slaked in a little cold water; simmer 5 minutes until the sauce coats the back of a spoon glossily, then adjust with salt, 1 tsp sugar and a squeeze of lemon to balance the sweet-sour. Slice the beef against the grain into 1 cm slices, ladle the warm sauce over the top and garnish with a spoon of whipped cream, cranberry compote and a lemon slice; serve with houskove knedliky (bread dumplings)."}},{"id":57,"servings":4,"tipType":"meat","timeMins":{"total":195,"active":45},"pairingsType":"meat","origin":{"ru":"Норвегия","en":"Norway","ro":"Norvegia"},"name":{"ru":"Фарикол","en":"Fårikål","ro":"Fårikål"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1,2 кг баранины с костью (лопатка или шея), нарезанной кусками по 5 см","1,2 кг белокочанной капусты (около 1 большого кочана), кочерыжка удалена, разрезанной на 8 толстых долей","1 ст. л. целых зерен черного перца","600 мл холодной воды","1 1/2 ч. л. мелкой соли"],"en":["1.2 kg bone-in lamb shoulder or neck, cut into 5 cm pieces","1.2 kg white cabbage (about 1 large head), cored and cut into 8 thick wedges","1 tbsp whole black peppercorns","600 ml cold water","1 1/2 tsp fine salt"],"ro":["1,2 kg carne de miel cu os (spata sau gat), taiata in bucati de 5 cm","1,2 kg varza alba (1 cap mare), miezul indepartat, taiata in 8 sferturi groase","1 lingura boabe intregi de piper negru","600 ml apa rece","1 1/2 lingurita sare fina"]},"howIsMade":{"ru":"Приправьте куски баранины со всех сторон 1 ч. л. соли. Выложите половину капустных долей ровным слоем на дно большой тяжелой кастрюли. Положите куски баранины сверху, рассыпьте зерна перца и оставшуюся 1/2 ч. л. соли, затем разложите оставшуюся капусту сверху. Аккуратно влейте холодную воду по внутренней стенке кастрюли — не перемешивайте. Плотно накройте крышкой и доведите до слабого кипения на среднем огне, около 8-10 минут. Уменьшите огонь до минимально возможного и готовьте без перемешивания 2-2,5 часа, пока баранина не станет полностью мягкой и не будет отваливаться от кости, а капуста не осядет и не впитает мясные соки. После 2 часов проверьте, легко ли баранина отделяется от кости и богатый ли и ароматный ли бульон — если ещё не готово, накройте и готовьте ещё 30 минут. Посолите по вкусу. Разлейте по глубоким тарелкам с бульоном, следя, чтобы в каждой порции было и мясо, и капуста.","en":"Season the lamb pieces all over with 1 tsp of the salt. Arrange half the cabbage wedges in an even layer at the bottom of a large, heavy pot. Lay the lamb pieces on top, scatter over the peppercorns and the remaining 1/2 tsp salt, then arrange the remaining cabbage on top. Pour the cold water carefully down the inside wall of the pot — do not stir. Cover tightly and bring to a gentle boil over medium heat, about 8-10 minutes. Reduce the heat to the lowest possible simmer and cook undisturbed for 2 to 2.5 hours until the lamb is completely tender and falls off the bone, and the cabbage has collapsed and fully absorbed the meat juices. After 2 hours check that the lamb pulls away from the bone with no resistance and the broth is rich and fragrant — if not quite done, cover and simmer for 30 minutes more. Taste and adjust salt. Ladle into deep bowls with the broth, ensuring each serving has both lamb and cabbage."}},{"id":58,"servings":4,"tipType":"veg","pairingsType":"middle-eastern","origin":{"ru":"Судан","en":"Sudan","ro":"Sudan"},"name":{"ru":"Фуль медамес","en":"Ful Medames","ro":"Ful Medames"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ru":["400 г сухих мелких бобов фава, замоченных на ночь в холодной воде (или 800 г консервированных бобов фава, промытых и откинутых)","4 зубчика чеснока, мелко рубленных","60 мл свежего лимонного сока (около 1 крупного лимона), плюс по вкусу","4 ст. л. оливкового масла первого отжима, разделенные","1 ч. л. молотого тмина","1/2 ч. л. молотого кориандра","1/2 ч. л. мелкой морской соли, плюс по вкусу","1/4 ч. л. кайенского перца или острой паприки","2 средних спелых помидора (около 250 г), мелко нарезанных","1 небольшая красная луковица (около 100 г), мелко нарезанная","20 г плосколистной петрушки, листья крупно нарубленные"],"en":["400 g dried small fava beans, soaked overnight in cold water (or 800 g canned fava beans, rinsed and drained)","4 garlic cloves, finely minced","60 ml fresh lemon juice (about 1 large lemon), plus more to taste","4 tbsp extra-virgin olive oil, divided","1 tsp ground cumin","1/2 tsp ground coriander","1/2 tsp fine sea salt, plus more to taste","1/4 tsp cayenne pepper or hot paprika","2 medium ripe tomatoes (about 250 g), finely diced","1 small red onion (about 100 g), finely diced","20 g flat-leaf parsley, leaves roughly chopped"],"ro":["400 g fasole fava uscata, inmuiata peste noapte in apa rece (sau 800 g fasole fava la conserva, clatita si scursa)","4 căței de usturoi, tocati marunt","60 ml suc proaspat de lamaie (cca 1 lamaie mare), plus dupa gust","4 linguri ulei de masline extravirgin, impartit","1 lingurita chimen macinat","1/2 lingurita coriandru macinat","1/2 lingurita sare fina de mare, plus dupa gust","1/4 lingurita ardei iute macinat sau boia picanta","2 rosii mijlocii coapte (cca 250 g), taiate marunt","1 ceapa rosie mica (cca 100 g), taiata marunt","20 g patrunjel plat, frunzele tocate grosier"]},"howIsMade":{"ru":"Если используете сухие бобы, слейте воду и залейте свежей холодной водой на 4-5 см выше уровня бобов; доведите до кипения и варите 1,5-2 часа до полной мягкости (боб должен легко разминаться между пальцами); слейте воду, сохранив 100 мл отвара. Если используете консервированные бобы, промойте, слейте и используйте 100 мл воды. Верните бобы в кастрюлю на слабый огонь, добавьте чеснок, лимонный сок, 3 ст. л. оливкового масла, тмин, кориандр, соль и кайен. Готовьте 3-4 минуты, разминая примерно половину бобов вилкой до кремовой, частично грубой текстуры, добавляя отвар по чуть-чуть, если слишком густо. Попробуйте и отрегулируйте лимон, соль и специи — фуль должен быть кисловатым и пряным. Разложите по неглубоким тарелкам и посыпьте нарезанными помидорами, красным луком и петрушкой. Сбрызните оставшейся 1 ст. л. оливкового масла и сразу подавайте с теплым питой.","en":"If using dried beans, drain the soaked beans and cover with fresh cold water by 4-5 cm; bring to the boil and simmer for 1.5 to 2 hours until the beans are completely soft when pressed between fingers, then drain, reserving 100 ml of cooking liquid. If using canned beans, rinse, drain, and use 100 ml of water as the liquid. Return the beans to the pot over low heat and add the garlic, lemon juice, 3 tbsp of the olive oil, cumin, coriander, salt, and cayenne. Cook for 3-4 minutes, mashing about half the beans with a fork to create a creamy, partly chunky texture, adding reserved cooking liquid a splash at a time if too thick. Taste and adjust lemon, salt, and spice — the ful should be tangy and warmly spiced. Divide into shallow bowls and scatter the diced tomatoes, red onion, and parsley over the top. Drizzle the remaining 1 tbsp olive oil over each serving and serve immediately with warm pita bread."}},{"id":59,"servings":4,"tipType":"fish","timeMins":{"total":50,"active":40},"pairingsType":"mediterranean","origin":{"ru":"Хорватия","en":"Croatia","ro":"Croația"},"name":{"ru":"Црни Рижот","en":"Crni Rizot","ro":"Crni Rižot"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500 г свежих или размороженных кальмаров, очищенных, с 2-3 чернильными мешочками","300 г риса арборио или карнароли","1 средняя луковица (около 150 г), мелко нарезанная","3 зубчика чеснока, мелко рубленных","100 мл сухого далматинского белого вина (или Пошип)","1 литр горячего рыбного бульона (или вода с 1 рыбным кубиком)","60 мл оливкового масла extra virgin","30 г холодного сливочного масла, нарезанного кубиками","2 ст. л. свежей петрушки, нарубленной","1/2 лимона, только сок","1 ч. л. мелкой морской соли","1/2 ч. л. молотого черного перца"],"en":["500 g fresh or thawed squid, cleaned, with 2-3 ink sacs reserved","300 g arborio or carnaroli rice","1 medium onion (about 150 g), finely chopped","3 garlic cloves, finely minced","100 ml dry Dalmatian white wine (or Pošip)","1 litre warm fish stock (or water with 1 fish stock cube)","60 ml extra-virgin olive oil","30 g cold butter, cubed","2 tbsp fresh parsley, chopped","1/2 lemon, juice only","1 tsp fine sea salt","1/2 tsp ground black pepper"],"ro":["500 g calmari proaspeti sau decongelati, curatati, cu 2-3 saculeti de cerneala separati","300 g orez arborio sau carnaroli","1 ceapa medie (cca 150 g), tocata marunt","3 căței de usturoi, tocati marunt","100 ml vin alb sec dalmatian (sau Pošip)","1 litru fond de peste cald (sau apa cu 1 cub de fond de peste)","60 ml ulei de masline extravirgin","30 g unt rece, taiat cubulete","2 linguri patrunjel proaspat, tocat","1/2 lamaie, doar zeama","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat"]},"howIsMade":{"ru":"Аккуратно очистите кальмаров: целыми чернильные мешочки перенесите в маленькую миску с небольшим количеством воды, затем тела нарежьте кольцами 1 см, а щупальца разрежьте пополам. В широкой тяжёлой сковороде разогрейте 4 ст. л. оливкового масла на среднем огне и пассеруйте лук 4-5 минут до мягкости, затем добавьте чеснок ещё на 1 минуту. Положите кольца кальмара и щупальца, обжарьте 2-3 минуты до непрозрачности, влейте вино и дайте полностью выпариться (около 2 минут). Добавьте рис и помешивайте 1 минуту, чтобы он покрылся жиром, затем начинайте вливать горячий рыбный бульон по половнику, постоянно помешивая в общей сложности 16-18 минут. На полпути раздавите чернильные мешочки в оставшийся бульон и влейте в сковороду — ризотто мгновенно становится насыщенно чёрным и обретает глубокий морской вкус. Когда рис al dente и кремовый, а немного бульона ещё остаётся, выключите огонь и добавьте холодное сливочное масло, оставшиеся 2 ст. л. оливкового масла, лимонный сок и петрушку. Энергично помешивайте 30 секунд (мантекатура), накройте и дайте отдохнуть 2 минуты. Подавайте немедленно в глубоких тарелках с дополнительной петрушкой сверху и долькой лимона рядом.","en":"Clean the squid carefully: lift out the ink sacs intact into a small bowl with a splash of water, then cut the bodies into 1 cm rings and halve the tentacles. In a wide heavy pan, heat 4 tbsp olive oil over medium heat and sauté the onion for 4-5 minutes until soft, then add the garlic for 1 minute more. Add the squid rings and tentacles, sauté for 2-3 minutes until just opaque, then pour in the wine and let it evaporate completely (about 2 minutes). Add the rice and stir for 1 minute to coat with fat, then begin adding the hot fish stock one ladle at a time, stirring constantly for 16-18 minutes total. Halfway through, break the ink sacs into the remaining stock and pour it in — the risotto turns deep jet black instantly and gains a profound oceanic depth. When the rice is al dente and creamy with a little stock still pooling, kill the heat and add the cold butter, the remaining 2 tbsp olive oil, the lemon juice, and the parsley. Stir vigorously for 30 seconds for the mantecatura, then cover and rest for 2 minutes. Serve immediately in shallow bowls with extra parsley on top and a wedge of lemon alongside."}},{"id":60,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Монголия","en":"Mongolia","ro":"Mongolia"},"name":{"ru":"Бууз","en":"Buuz","ro":"Buuz"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["Тесто: 300 г пшеничной муки, плюс для раскатки","150 мл теплой воды (около 50 C)","1/2 ч. л. мелкой соли","Начинка: 400 г рубленой баранины (или пополам баранина и говядина)","1 средняя луковица (около 150 г), мелко нарезанная","3 зубчика чеснока, мелко рубленных","2 ст. л. подсолнечного масла","1 ч. л. молотого тмина","1 ч. л. мелкой морской соли","1/2 ч. л. молотого черного перца","50 мл холодной воды"],"en":["Dough: 300 g all-purpose flour, plus extra for dusting","150 ml warm water (about 50 C)","1/2 tsp fine salt","Filling: 400 g ground lamb (or half lamb, half beef)","1 medium onion (about 150 g), finely diced","3 garlic cloves, finely minced","2 tbsp sunflower oil","1 tsp ground cumin","1 tsp fine sea salt","1/2 tsp ground black pepper","50 ml cold water"],"ro":["Aluat: 300 g făină alba, plus extra pentru intins","150 ml apa calda (cca 50 C)","1/2 lingurita sare fina","Umplutura: 400 g carne de miel tocata (sau amestec miel-vita)","1 ceapa medie (cca 150 g), taiata marunt","3 căței de usturoi, tocati marunt","2 linguri ulei de floarea-soarelui","1 lingurita chimen macinat","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat","50 ml apa rece"]},"howIsMade":{"ru":"Сделайте тесто: смешайте муку с солью, влейте теплую воду и месите 5-6 минут до гладкости и эластичности. Накройте влажным полотенцем и дайте отдохнуть 30 минут. Сделайте начинку: смешайте рубленую баранину, лук, чеснок, масло, тмин, соль, перец и холодную воду в миске и хорошо вымешайте руками до однородности и легкой клейкости. Разделите тесто на 20-24 равных кусочка (около 20 г каждый) и раскатайте каждый в тонкий круг диаметром около 10 см, оставляя центр чуть толще краев. Положите 1 с горкой ложку (около 25 г) начинки в центр каждого кружка. Поднимите края вокруг начинки и защипните их вверху, оставив небольшое паровое отверстие в центре — классическая монгольская форма. Выстелите пароварку пергаментом и уложите бузы в один слой с расстоянием 2 см. Доведите воду в воке или широкой кастрюле до бурного кипения, поставьте корзинку и готовьте на пару 20-22 минуты, пока тесто полностью не приготовится, а начинка не перестанет быть розовой внутри. Подавайте немедленно.","en":"Make the dough: mix flour and salt, pour in the warm water, and knead for 5-6 minutes until smooth and elastic. Cover with a damp cloth and rest for 30 minutes. Make the filling: combine the lamb, onion, garlic, oil, cumin, salt, pepper, and cold water in a bowl and mix well with your hands until evenly combined and slightly sticky. Divide the dough into 20-24 equal pieces (about 20 g each) and roll each into a thin round about 10 cm across, keeping the centre slightly thicker than the edges. Place 1 heaped tablespoon (about 25 g) of filling in the centre of each round. Lift the edges up around the filling and pleat them together at the top, leaving a small steam hole in the centre — the classic Mongolian shape. Line a bamboo steamer with parchment paper or cabbage leaves and arrange the buuz in a single layer with 2 cm between each. Fill a wok or wide pot with water and bring to a rolling boil; set the steamer basket over the boiling water and steam for 20-22 minutes until the dough is cooked through and the filling is no longer pink inside. Serve immediately."}},{"id":61,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Пакистан","en":"Pakistan","ro":"Pakistan"},"name":{"ru":"Бирьяни","en":"Biryani","ro":"Biryani"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["800 г куриных бедер без кости (или баранья лопатка), нарезанных крупными кусками, по возможности с костью","200 г натурального йогурта из цельного молока, взбитого","2 ст. л. имбирно-чесночной пасты","1 ч. л. гарам-масалы","1 ч. л. молотого перца чили","1/2 ч. л. куркумы","1 ч. л. соли","3 ст. л. теплого молока + щепотка нитей шафрана","400 г риса басмати","2,5 литра воды (для предварительного отваривания риса)","4 ст. л. гхи","4 коробочки зеленого кардамона","2 коробочки черного кардамона","1 палочка корицы","6 бутонов гвоздики","2 лавровых листа","2 крупные луковицы, нарезанные тонкими полукольцами","2 средних помидора, натертых на терке","2 ст. л. мелко нарезанной свежей мяты","2 ст. л. мелко нарезанной свежей кинзы","1 ст. л. дополнительного гхи, растопленного (для сбрызгивания)","Для подачи: холодная йогуртовая райта, дольки лимона"],"en":["800g boneless chicken thighs (or lamb shoulder), cut into large pieces, bone-in if possible","200g plain whole-milk yoghurt, whisked","2 tbsp ginger-garlic paste","1 tsp garam masala","1 tsp chilli powder","1/2 tsp turmeric","1 tsp salt","3 tbsp warm milk + a pinch of saffron threads","400g basmati rice","2.5 litres water (for par-boiling the rice)","4 tbsp ghee","4 green cardamom pods","2 black cardamom pods","1 cinnamon stick","6 cloves","2 bay leaves","2 large onions, thinly sliced","2 medium tomatoes, grated","2 tbsp chopped fresh mint","2 tbsp chopped fresh coriander","1 tbsp extra ghee, melted (to drizzle)","To serve: cold yoghurt raita, lemon wedges"],"ro":["800 g pulpe de pui dezosate (sau spata de miel), taiate cuburi mari, cu os daca este posibil","200 g iaurt gras de vaca, batut","2 linguri pasta de ghimbir-usturoi","1 lingurita garam masala","1 lingurita pudra de chili","1/2 lingurita turmeric","1 lingurita sare","3 linguri lapte cald + un varf de fire de sofran","400 g orez basmati","2,5 l apa (pentru fierberea partiala a orezului)","4 linguri ghee","4 capsule cardamom verde","2 capsule cardamom negru","1 bat de scortisoara","6 cuișoare","2 foi de dafin","2 cepe mari, taiate solzi subtiri","2 rosii medii, rase","2 linguri menta proaspata, tocata","2 linguri coriandru proaspat, tocat","1 lingura ghee suplimentar, topit (pentru stropit)","Pentru servit: raita de iaurt rece, felii de lamaie"]},"howIsMade":{"ru":"Смешайте 800 г курицы (или баранины) с 200 г взбитого йогурта, 2 ст.л имбирно-чесночной пасты, 1 ч.л гарам-масалы, 1 ч.л перца чили, 1/2 ч.л куркумы, 1 ч.л соли и щепоткой нитей шафрана, замоченных в 3 ст.л тёплого молока; накройте и маринуйте минимум 1 час, идеально 4 часа в холодильнике. Растопите 4 ст.л гхи или масла в тяжёлой кастрюле на среднем огне; когда заблестит, добавьте 4 коробочки зелёного кардамона, 2 коробочки чёрного кардамона, 1 палочку корицы, 4 гвоздики и 1 лавровый лист и дайте им раскрыть аромат 30 секунд, пока они слегка не затрещат. Добавьте 2 крупные луковицы, нарезанные тонкими полукольцами, и жарьте 12-15 минут, часто помешивая, до тёмно-коричневого хрустящего состояния; снимите половину на бумажные полотенца для гарнира, оставив остальное в кастрюле с ароматным маслом. Опустите маринованное мясо в кастрюлю с 2 натёртыми помидорами и готовьте 8-10 минут на среднем огне, помешивая, пока йогурт не разойдётся, а масло не поднимется по краям; уменьшите огонь и тушите под крышкой ещё 15 минут, пока мясо почти не станет мягким, а соус останется густым. Тем временем промойте 400 г басмати до прозрачной воды и замочите на 30 минут; вскипятите 2,5 литра воды с 2 ч.л соли, 3 коробочками кардамона, 1 палочкой корицы и 2 лавровыми листами, всыпьте рис с несколькими каплями масла и варите ровно 5-6 минут, пока зёрна не будут готовы на 70% — ещё твёрдые в центре; сразу слейте. Выложите половину отцеженного риса поверх масалы с мясом, посыпьте половиной жареного лука, 2 ст.л рубленой мяты и 2 ст.л кориандра, затем уложите оставшийся рис; полейте 4 ст.л тёплого шафранового молока и 2 ст.л растопленного гхи, завершите оставшимся луком, мятой и кориандром. Запечатайте кастрюлю плотной крышкой (или закройте фольгой и прижмите крышкой), поставьте на самый малый огонь, в идеале на рассекатель пламени или чугунную плиту, и готовьте на думе 25 минут, не поднимая крышку — пойманный пар одновременно доводит рис и мясо. Выключите огонь и дайте закрытой кастрюле постоять 10 минут; откройте, аккуратно взрыхлите от края к центру, перемешивая слои мяса и риса, и сразу подавайте с холодной йогуртовой райтой и дольками лимона.","en":"Mix 800 g chicken (or lamb) with 200 g whisked yoghurt, 2 tbsp ginger-garlic paste, 1 tsp garam masala, 1 tsp chilli powder, 1/2 tsp turmeric, 1 tsp salt and a pinch of saffron threads soaked in 3 tbsp warm milk; cover and marinate at least 1 hour, ideally 4 hours in the fridge. Melt 4 tbsp ghee or oil in a heavy-bottomed pot over medium heat; when it shimmers, add 4 green cardamom pods, 2 black cardamom pods, 1 cinnamon stick, 4 cloves and 1 bay leaf and let them bloom for 30 seconds until they crackle lightly. Add 2 large onions sliced thin and fry for 12-15 minutes, stirring often, until deep brown and crisp; lift out half onto kitchen paper for garnish and leave the rest in the pot with the aromatic oil. Slide the marinated meat into the pot with 2 grated tomatoes and cook 8-10 minutes over medium heat, stirring until the yoghurt breaks and the oil rises to the edges; lower the heat and simmer covered another 15 minutes until the meat is almost tender but the sauce stays thick. Meanwhile rinse 400 g basmati rice until the water runs clear and soak for 30 minutes; bring 2.5 litres of water to the boil with 2 tsp salt, 3 cardamom pods, 1 cinnamon stick and 2 bay leaves, slip in the rice with a few drops of oil and cook for exactly 5-6 minutes until the grains are 70% done — still firm in the centre; drain at once. Spread half of the drained rice over the meat masala, scatter half of the fried onions, 2 tbsp chopped mint and 2 tbsp coriander, then layer the remaining rice on top; drizzle with 4 tbsp warm saffron milk and 2 tbsp melted ghee, and finish with the remaining onions, mint and coriander. Seal the pot with a tight lid (or cover with foil and press the lid down), set it on the lowest possible flame, ideally over a heat diffuser or a cast-iron tava, and dum cook for 25 minutes without lifting the lid — the trapped steam finishes the rice and meat together. Turn off the heat and let the sealed pot rest for 10 minutes; open, gently fluff from the side inwards to fold the meat and rice layers, and serve straight away with cold yoghurt raita and lemon wedges."},"timeMins":{"total":105,"active":50}},{"id":62,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ru":"Тунис","en":"Tunisia","ro":"Tunisia"},"name":{"ru":"Брик","en":"Brik","ro":"Brik"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["4 листа теста брик (или малсука/уарка), около 30 см в диаметре (или оберточные листы для спринг-роллов)","4 крупных яйца (по 1 на брик)","160 г консервированного тунца в оливковом масле, хорошо отжатого","1 небольшая луковица (около 80 г), мелко нарезанная","3 ст. л. мелких каперсов, промытых и грубо порубленных","20 г плосколистной петрушки, мелко нарубленной","1/2 ч. л. молотого тмина","1/2 ч. л. мелкой морской соли","1/4 ч. л. молотого кайена или пасты хариссы","500 мл растительного масла для фритюра","1 лимон, нарезанный на 4 дольки, для подачи"],"en":["4 sheets of brik pastry (or malsouka/ouarka), about 30 cm in diameter (or spring roll wrappers as substitute)","4 large eggs (1 per brik)","160 g canned tuna in olive oil, well drained","1 small onion (about 80 g), finely diced","3 tbsp small capers, rinsed and roughly chopped","20 g flat-leaf parsley, finely chopped","1/2 tsp ground cumin","1/2 tsp fine sea salt","1/4 tsp cayenne pepper or harissa paste","500 ml vegetable oil for deep-frying","1 lemon, cut into 4 wedges, to serve"],"ro":["4 foi de brik (sau malsouka/ouarka), cca 30 cm diametru (sau foi de spring roll ca substitut)","4 oua mari (1 pe brik)","160 g ton la conserva in ulei de masline, bine scurs","1 ceapa mica (cca 80 g), taiata marunt","3 linguri capere mici, clatite si tocate grosier","20 g patrunjel plat, tocat marunt","1/2 lingurita chimen macinat","1/2 lingurita sare fina de mare","1/4 lingurita ardei iute macinat sau harissa","500 ml ulei vegetal pentru prajit adanc","1 lamaie, taiata in 4, pentru servire"]},"howIsMade":{"ru":"Смешайте в миске отжатый тунец, лук, каперсы, петрушку, тмин, соль и кайен, чтобы сделать начинку. Налейте растительное масло в глубокую широкую сковороду слоем 3-4 см и нагрейте до 175°C. Положите лист теста брик на чистую поверхность и выложите четверть начинки из тунца на нижнюю половину, сделав небольшое углубление в центре. Разбейте 1 яйцо в углубление. Быстро сложите лист пополам в форме полукруга, плотно прижав края, чтобы запечатать и не дать яйцу вытечь. Аккуратно опустите брик в горячее масло и жарьте 1,5-2 минуты с каждой стороны до глубоко золотистого и хрустящего состояния, один раз перевернув широкой лопаткой. Достаньте шумовкой и обсушите на бумажных полотенцах 30 секунд. Подавайте сразу — желток должен быть жидким или чуть схватившимся, а тесто хрустящим. Выдавите дольку лимона сверху.","en":"Combine the drained tuna, onion, capers, parsley, cumin, salt, and cayenne in a bowl and mix well to make the filling. Pour the vegetable oil into a deep, wide pan to a depth of 3-4 cm and heat to 175°C. Lay a brik pastry sheet flat on a clean surface and spoon a quarter of the tuna filling onto the lower half, creating a slight hollow in the centre. Crack 1 egg into the hollow. Working quickly, fold the pastry in half to form a half-moon, pressing the edges firmly together to seal and prevent the egg from escaping. Carefully slide the brik into the hot oil and fry for 1.5-2 minutes per side until deep golden and crisp all over, flipping once with a wide spatula. Lift out with a slotted spoon and drain on paper towels for 30 seconds. Serve immediately — the yolk should be runny to lightly set and the pastry crackling crisp. Squeeze a lemon wedge over the top."}},{"id":63,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ru":"Грузия","en":"Georgia","ro":"Georgia"},"name":{"ru":"Хачапури","en":"Khachapuri","ro":"Khachapuri"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ru":["500 г пшеничной муки высшего сорта, плюс немного для раскатки","7 г сухих быстродействующих дрожжей (1 пакетик)","1 ч. л. сахара","1 ч. л. мелкой морской соли","250 мл тёплой воды (около 40°C)","2 ст. л. оливкового масла","400 г сулугуни или моцареллы, крупно натёртых","200 г сыра фета, раскрошенного","4 крупных яйца (по 1 на каждую хачапури)","40 г сливочного масла без соли, нарезанного на 4 равных кусочка"],"en":["500 g plain flour (all-purpose), plus extra for dusting","7 g instant yeast (1 sachet)","1 tsp caster sugar","1 tsp fine sea salt","250 ml warm water (about 40°C / 105°F)","2 tbsp olive oil","400 g sulguni or mozzarella, coarsely grated","200 g feta cheese, crumbled","4 large eggs (1 per khachapuri)","40 g unsalted butter, cut into 4 equal pieces"],"ro":["500 g făină albă, plus extra pentru pudrare","7 g drojdie instant (1 plic)","1 linguriță zahăr","1 linguriță sare fină de mare","250 ml apă caldă (aproximativ 40°C)","2 linguri ulei de măsline","400 g suluguni sau mozzarella, ras grosier","200 g brânză feta, sfărâmată","4 ouă mari (câte 1 pentru fiecare khachapuri)","40 g unt nesărat, tăiat în 4 bucăți egale"]},"howIsMade":{"ru":"Смешайте муку, дрожжи, сахар и соль в большой миске, добавьте тёплую воду и оливковое масло и замешайте тесто, затем вымешивайте на слегка присыпанной мукой поверхности 8-10 минут, пока тесто не станет гладким и слегка липким. Сформируйте шар, поместите в смазанную маслом миску, накройте влажным полотенцем и оставьте в тёплом месте на 1 час, пока тесто не удвоится в объёме. Пока тесто подходит, смешайте натёртый сулугуни (или моцареллу) и раскрошенную фету в миске; разогрейте духовку до 250°C, поставив внутрь тяжёлый противень или камень для пиццы. Разделите подошедшее тесто на 4 равные части и раскатайте каждую на слегка присыпанной мукой поверхности в овал размером примерно 25 x 15 см. Загните длинные края вовнутрь на 3 см и скрутите в бортики, затем крепко защипните оба коротких конца вместе, придав форму лодочки. Разложите лодочки на пергаменте, полностью заполните каждую четвертью сырной смеси, переложите на горячий противень и выпекайте 12-14 минут, пока корочка не станет золотистой, а сыр не начнёт пузыриться и слегка подрумянится. Выньте из духовки, сделайте небольшое углубление в центре каждой начинки, разбейте по 1 яйцу и верните в духовку на 3-4 минуты, пока белок не схватится, а желток останется жидким. Положите по кусочку масла на каждое яйцо и подавайте немедленно — отрывайте полоски бортика и макайте в расплавленный сыр и желток.","en":"Mix the flour, yeast, sugar, and salt in a large bowl, add the warm water and olive oil and stir to a rough dough, then knead on a lightly floured surface for 8-10 minutes until smooth and slightly tacky. Shape into a ball, place in an oiled bowl, cover with a damp cloth, and leave in a warm place for 1 hour until doubled in size. While the dough rises, mix the grated sulguni (or mozzarella) and crumbled feta together in a bowl; heat the oven to 250°C (230°C fan) with a heavy baking tray or pizza stone inside. Divide the risen dough into 4 equal pieces and roll each on a lightly floured surface into an oval about 25 x 15 cm. Fold the long edges inward by 3 cm and roll them up into a thick raised border, then pinch both short ends firmly together to form a boat shape. Arrange the boats on baking parchment, fill each cavity completely with a quarter of the cheese mixture, then slide onto the hot tray and bake for 12-14 minutes until the crust is golden and the cheese is bubbling and lightly browned. Remove from the oven, press a small hollow in the centre of each cheese filling, crack 1 egg into each hollow, and return to the oven for 3-4 minutes until the white is just set but the yolk remains runny. Place a piece of butter on top of each egg and serve immediately — tear strips of the border and dip into the melted cheese and yolk."}},{"id":64,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Южная Африка","en":"South Africa","ro":"Africa de Sud"},"name":{"ru":"Боботи","en":"Bobotie","ro":"Bobotie"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["750 г нежирного говяжьего или бараньего фарша","2 средние луковицы (около 300 г), мелко нарезанные","2 ломтика белого хлеба (около 60 г), без корки","125 мл цельного молока, разделённого","2 крупных яйца","50 г изюма (светлый, сорт «Султана»)","30 г сушёных абрикосов (около 6 штук), мелко нарезанных","2 ст. л. абрикосового джема или сладкого чатни","2 ст. л. мягкого карри-порошка","1 ч. л. молотой куркумы","2 ст. л. растительного масла","1 ч. л. мелкой морской соли","1/2 ч. л. молотого чёрного перца","4 свежих или сухих лавровых листа"],"en":["750 g lean beef or lamb mince","2 medium onions (about 300 g total), finely diced","2 slices white bread (about 60 g), crusts removed","125 ml whole milk, divided","2 large eggs","50 g sultanas (golden raisins)","30 g dried apricots (about 6), finely chopped","2 tbsp apricot jam or sweet chutney","2 tbsp mild curry powder","1 tsp ground turmeric","2 tbsp vegetable oil","1 tsp fine sea salt","1/2 tsp ground black pepper","4 fresh or dried bay leaves"],"ro":["750 g carne tocată de vită sau miel, slabă","2 cepe medii (aproximativ 300 g), fin tocate","2 felii pâine albă (aproximativ 60 g), fără coajă","125 ml lapte integral, împărțit","2 ouă mari","50 g stafide galbene (sultane)","30 g caise uscate (aproximativ 6 bucăți), fin tocate","2 linguri gem de caise sau chutney dulce-picant","2 linguri pudră de curry blând","1 linguriță turmeric măcinat","2 linguri ulei vegetal","1 linguriță sare fină de mare","1/2 linguriță piper negru măcinat","4 foi de dafin proaspete sau uscate"]},"howIsMade":{"ru":"Замочите хлеб в 60 мл молока на 5 минут, затем отожмите лишнюю жидкость и раскрошите в небольшую миску. Разогрейте масло на большой сковороде на среднем-высоком огне, добавьте лук и жарьте, помешивая, 8-10 минут до мягкости и золотистого цвета. Добавьте карри и куркуму, перемешайте и жарьте 1 минуту до появления аромата, затем добавьте фарш и жарьте 8-10 минут, разбивая комки, пока мясо не подрумянится и жидкость не выпарится. Снимите с огня и смешайте с замоченным хлебом, изюмом, абрикосами, джемом, солью и перцем до равномерного распределения. Разогрейте духовку до 180°C и слегка смажьте маслом среднюю форму для запекания (около 25 x 20 см). Переложите мясную смесь в форму, разровняйте в ровный слой и воткните лавровые листья в поверхность. Взбейте яйца с оставшимися 65 мл молока и щепоткой соли до однородности, затем равномерно вылейте на мясо. Запекайте 35-40 минут, пока заливка не схватится и не станет золотисто-коричневой без дрожания в центре. Дайте отдохнуть 5 минут, затем подавайте с жёлтым рисом и чатни.","en":"Soak the bread in 60 ml of the milk for 5 minutes, then squeeze out the excess liquid and crumble into a small bowl. Heat the oil in a large frying pan over medium-high heat, add the onions and cook, stirring, for 8-10 minutes until soft and golden. Add the curry powder and turmeric and stir for 1 minute until fragrant, then add the mince and cook for 8-10 minutes, breaking up any lumps, until browned and all liquid has evaporated. Remove from the heat and mix in the soaked bread, sultanas, dried apricots, apricot jam, salt, and pepper until evenly combined. Heat the oven to 180°C (160°C fan) and lightly grease a medium baking dish (about 25 x 20 cm). Transfer the meat mixture into the dish, press it into an even layer, and tuck the bay leaves into the surface. Beat the eggs with the remaining 65 ml milk and a pinch of salt until smooth, then pour evenly over the meat. Bake for 35-40 minutes until the custard topping is set and golden brown with no wobble in the centre. Rest for 5 minutes before serving with yellow rice, chutney, and sambals."}},{"id":65,"servings":4,"tipType":"fish","pairingsType":"latin","origin":{"ru":"Перу","en":"Peru","ro":"Peru"},"name":{"ru":"Севиче","en":"Ceviche","ro":"Ceviche"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["700 г очень свежего филе белой рыбы (сибас, камбала или палтус), без кожи и костей","180 мл свежего сока лайма (около 8-10 лаймов), по вкусу больше","1 маленькая красная луковица (около 150 г), разрезанная пополам и нарезанная тонкими полукольцами","1-2 перца ají amarillo или 1 халапеньо, без семян, мелко нарезанных","1 зубчик чеснока, мелко натёртый","1 ч. л. свежего имбиря (около 1 см), мелко натёртого","30 г свежей кинзы, листья и тонкие стебли, крупно нарезанные","1 ч. л. мелкой морской соли","1/4 ч. л. молотого белого перца","2 початка кукурузы, отваренных и нарезанных на кружки 5 см","2 маленьких батата (около 400 г), отваренных до мягкости, очищенных и нарезанных"],"en":["700 g very fresh white fish fillets (sea bass, sole, or halibut), skin and bones removed","180 ml fresh lime juice (about 8-10 limes), plus more to taste","1 small red onion (about 150 g), halved and thinly sliced into half-moons","1-2 ají amarillo chillies or 1 jalapeño, deseeded and finely diced","1 garlic clove, finely grated","1 tsp fresh ginger (about 1 cm piece), finely grated","30 g fresh coriander (cilantro), leaves and fine stems, roughly chopped","1 tsp fine sea salt","1/4 tsp ground white pepper","2 ears of corn, boiled and cut into 5 cm rounds","2 small sweet potatoes (about 400 g), boiled until tender, peeled and sliced"],"ro":["700 g file de pește alb foarte proaspăt (biban de mare, limbă sau halibut), fără piele și oase","180 ml suc proaspăt de lime (aproximativ 8-10 lime-uri), plus extra după gust","1 ceapă roșie mică (aproximativ 150 g), tăiată felii subțiri în jumătate de lună","1-2 ardei ají amarillo sau 1 jalapeño, fără semințe, fin tocați","1 căței de usturoi, fin ras","1 linguriță ghimbir proaspăt (aproximativ 1 cm), fin ras","30 g coriandru proaspăt, frunze și tulpini subțiri, grosier tocat","1 linguriță sare fină de mare","1/4 linguriță piper alb măcinat","2 știuleți de porumb, fierți și tăiați în rondele de 5 cm","2 cartofi dulci mici (aproximativ 400 g), fierți, curățați și feliați"]},"howIsMade":{"ru":"Обсушите рыбу бумажными полотенцами, нарежьте кубиками 2 см, удалив оставшиеся кости, и поместите в неокисляемую миску (стекло или керамика). Посыпьте солью и белым перцем и перемешайте. Добавьте красный лук, чили, чеснок и имбирь и осторожно перемешайте. Вылейте сок лайма — он должен почти покрыть рыбу — затем аккуратно помешайте и прижмите рыбу, чтобы она погрузилась как можно глубже. Накройте и поставьте в холодильник на 10-15 минут, один раз перемешав на полпути, пока снаружи каждый кубик не станет непрозрачным и слегка упругим на ощупь, но сердцевина останется чуть прозрачной — классический перуанский стиль. Попробуйте и скорректируйте соль и сок лайма. Вмешайте большую часть кинзы, оставив немного для украшения. Подавайте немедленно в охлаждённых тарелках с кружками кукурузы и ломтиками батата, посыпав оставшейся кинзой.","en":"Pat the fish dry with paper towels and cut into 2 cm cubes, removing any remaining pin bones, then place in a non-reactive bowl (glass or ceramic). Season with the salt and white pepper and toss to coat. Add the red onion, chilli, garlic, and ginger and mix gently. Pour over the lime juice — it should nearly cover the fish — then stir gently and press the fish down to submerge it as much as possible. Cover and refrigerate for 10-15 minutes, stirring once halfway through, until the outside of each cube is opaque and just firm to the touch while the very centre remains slightly translucent — the classic Peruvian style, not fully cooked through. Taste and adjust salt and lime juice. Stir in most of the coriander, reserving a little for garnish. Serve immediately in chilled bowls alongside the corn rounds and sweet potato slices, with the remaining coriander scattered over the top."}},{"id":66,"servings":8,"tipType":"korean","pairingsType":"korean","origin":{"ru":"Южная Корея","en":"South Korea","ro":"Coreea de Sud"},"name":{"ru":"Кимчи","en":"Kimchi","ro":"Kimchi"},"category":{"ru":"Гарнир","en":"Side dish","ro":"Garnitură"},"ingredients":{"ru":["1 большая пекинская капуста (около 2 кг)","3 ст.л. морской соли (без йода)","4 ст.л. кочукару (корейские хлопья чили)","5 зубчиков чеснока, мелко нарезанных","1 ч.л. свежего тёртого имбиря","1 ст.л. рыбного соуса (или соевого для веганов)","1 ч.л. сахара","6 перьев зелёного лука по 3 см","1 средняя морковь, нарезанная соломкой"],"en":["1 large napa cabbage (about 2 kg)","3 tbsp sea salt (non-iodised)","4 tbsp gochugaru (Korean red pepper flakes)","5 cloves garlic, finely minced","1 tsp fresh ginger, grated","1 tbsp fish sauce (or soy sauce for vegan)","1 tsp sugar","6 spring onions, cut into 3cm pieces","1 medium carrot, julienned"],"ro":["1 varză napa mare (aprox. 2 kg)","3 linguri sare de mare (fără iod)","4 linguri gochugaru (fulgi de ardei coreean)","5 căței de usturoi, tocați mărunt","1 linguriță ghimbir proaspăt, ras","1 lingură sos de pește (sau sos de soia pentru variantă vegană)","1 linguriță zahăr","6 cepe verzi, tăiate în bucăți de 3 cm","1 morcov mediu, julien"]},"howIsMade":{"ru":"Разрежьте пекинскую капусту вдоль на четверти, затем поперёк на куски по 5 см. Перемешайте с солью, помните руками 2–3 минуты, оставьте на 1–2 часа (периодически переворачивая), пока капуста не обмякнет и не даст сок. Промойте 2–3 раза в холодной воде, откиньте и хорошо отожмите; должна оставаться приятно солёной. Смешайте кочукару, чеснок, имбирь, рыбный соус и сахар в миске; добавьте зелёный лук и морковь. Добавьте отжатую капусту к пасте и тщательно перемешайте руками в перчатках — каждый кусочек должен быть равномерно покрыт красной пастой. Плотно уложите в чистые банки объёмом 1 л, утрамбуйте, оставьте 3–4 см свободного места; выдержите при комнатной температуре 1–2 дня, затем уберите в холодильник — готово через 3–5 дней.","en":"Quarter the napa cabbage lengthwise, then cut crosswise into 5cm pieces. Toss with sea salt and massage 2–3 minutes, let sit 1–2 hours turning occasionally until the cabbage has wilted and released water. Rinse the cabbage thoroughly in cold water 2–3 times, drain and squeeze firmly to remove excess moisture; it should taste pleasantly salty — rinse once more if too salty. Mix gochugaru, garlic, ginger, fish sauce and sugar in a bowl; add spring onions and carrot. Add drained cabbage to the paste and mix thoroughly with your hands (wear gloves) — every piece should be evenly coated in red paste. Pack tightly into clean 1-litre jars, press down firmly to eliminate air pockets, leaving 3–4 cm of headspace; leave at room temperature for 1–2 days, then refrigerate — kimchi is ready in 3–5 days and best after 1 week."}},{"id":67,"servings":4,"tipType":"meat","timeMins":{"total":285,"active":60},"pairingsType":"vietnamese","origin":{"ru":"Вьетнам","en":"Vietnam","ro":"Vietnam"},"name":{"ru":"Бань Ми","en":"Banh Mi","ro":"Banh Mi"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["4 маленьких багета (около 20 см каждый), разрезанных вдоль","400 г свиной вырезки, тонко нарезанной (около 5 мм)","2 ст. л. соевого соуса","1 ст. л. рыбного соуса","1 ч. л. кунжутного масла + 1 ч. л. сахара + 1/4 ч. л. чёрного перца (для маринада)","2 средние морковки (около 200 г), очищенные и нарезанные соломкой","100 г дайкона, очищенного и нарезанного соломкой (или дополнительная морковь)","3 ст. л. рисового уксуса","1 ст. л. сахара + 1/2 ч. л. мелкой соли (для маринования)","60 г куриного паштета из печени","4 ст. л. майонеза","1 большой огурец, нарезанный тонкими палочками","2 перца халапеньо или красный чили, нарезанных тонкими кольцами","20 г свежей кинзы, веточки"],"en":["4 small baguettes or demi-baguettes (about 20 cm each), halved lengthwise","400 g pork tenderloin, thinly sliced (about 5 mm)","2 tbsp soy sauce","1 tbsp fish sauce","1 tsp sesame oil + 1 tsp sugar + 1/4 tsp black pepper (marinade)","2 medium carrots (about 200 g), peeled and julienned","100 g daikon, peeled and julienned (or extra carrot)","3 tbsp rice vinegar","1 tbsp sugar + 1/2 tsp fine salt (for pickling)","60 g chicken liver pâté","4 tbsp mayonnaise","1 large cucumber, cut into thin batons","2 jalapeños or red chillies, thinly sliced","20 g fresh coriander, sprigs"],"ro":["4 baghetele mici (de circa 20 cm), tăiate pe lungime","400 g mușchi de porc, tăiat felii subțiri (circa 5 mm)","2 linguri sos de soia","1 lingură sos de pește","1 linguriță ulei de susan + 1 linguriță zahăr + 1/4 linguriță piper negru (pentru marinadă)","2 morcovi medii (aproximativ 200 g), curățați și tăiați julienne","100 g daikon (ridiche asiatică), curățat și juliennat (sau morcov în plus)","3 linguri oțet de orez","1 lingură zahăr + 1/2 linguriță sare (pentru murat)","60 g pate de ficat de pui","4 linguri maioneză","1 castravete mare, tăiat bețe subțiri","2 jalapeño sau ardei roșii, tăiați rondele","20 g coriandru proaspăt, crenguțe"]},"howIsMade":{"ru":"Смешайте морковь и дайкон с рисовым уксусом, сахаром и солью, хорошо перемешайте и оставьте мариноваться минимум на 20 минут (или до 4 часов в холодильнике), пока они слегка не размякнут, но останутся хрустящими. Смешайте соевый соус, рыбный соус, кунжутное масло, сахар и чёрный перец в миске, добавьте нарезанную свинину и перемешайте; маринуйте 15-20 минут при комнатной температуре. Разогрейте тяжёлую сковороду на сильном огне до лёгкого дымка, выложите свинину в один слой партиями по 2-3 и жарьте 1-2 минуты с каждой стороны до карамелизации и золотистого цвета по краям. Поджарьте багеты в духовке при 200°C 4-5 минут до хрустящей корочки. Срезы хлеба обильно намажьте паштетом и майонезом. Выложите тёплые ломтики свинины, отжатые маринованные морковь и дайкон, огуречные палочки, кольца халапеньо и щедрые веточки кинзы. Слегка придавите и подавайте немедленно.","en":"Combine the carrots and daikon with the rice vinegar, sugar, and salt, toss well, and leave to pickle for at least 20 minutes (or up to 4 hours in the fridge) until slightly softened but still crunchy. Mix the soy sauce, fish sauce, sesame oil, sugar, and black pepper in a bowl, add the sliced pork, and toss to coat; marinate for 15-20 minutes at room temperature. Heat a heavy frying pan or griddle over high heat until smoking, add the pork in a single layer in 2-3 batches, and cook for 1-2 minutes per side until caramelised and golden brown at the edges. Toast the baguettes in a 200°C oven for 4-5 minutes until the crust is crisp. Spread the cut sides generously with pâté and mayonnaise. Layer in the warm pork slices, the drained pickled carrots and daikon, cucumber batons, jalapeño slices, and generous sprigs of coriander. Press gently and serve immediately."}},{"id":68,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Индонезия","en":"Indonesia","ro":"Indonezia"},"name":{"ru":"Сатай","en":"Satay","ro":"Satay"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["700 г куриных бёдер без кожи и костей, нарезанных кубиками 2 см","3 ст. л. соевого соуса","2 ст. л. кокосового молока","1 ст. л. светло-коричневого сахара","2 ч. л. молотого кориандра","1 ч. л. молотого тмина","1 ч. л. молотой куркумы","2 зубчика чеснока, мелко натёртых","1 стебель лемонграсса, светлая часть, мелко нарубленная","200 г гладкого арахисового масла","200 мл кокосового молока (для соуса)","2 ст. л. кечап маниса (сладкого соевого соуса)","1 ст. л. сока лайма","1 ч. л. самбала оелек или шрирача","20 бамбуковых шпажек, замоченных в холодной воде 30 минут"],"en":["700 g boneless skinless chicken thighs, cut into 2 cm cubes","3 tbsp soy sauce","2 tbsp coconut milk","1 tbsp light brown sugar","2 tsp ground coriander","1 tsp ground cumin","1 tsp ground turmeric","2 garlic cloves, finely grated","1 lemongrass stalk, pale part only, finely minced","200 g smooth peanut butter","200 ml coconut milk (for sauce)","2 tbsp kecap manis (sweet soy sauce)","1 tbsp lime juice","1 tsp sambal oelek or sriracha","20 bamboo skewers, soaked in cold water for 30 minutes"],"ro":["700 g pulpe de pui dezosate și fără piele, tăiate cubulețe de 2 cm","3 linguri sos de soia","2 linguri lapte de cocos","1 lingură zahăr brun pal","2 lingurițe coriandru măcinat","1 linguriță chimen măcinat","1 linguriță turmeric măcinat","2 căței de usturoi, fin rași","1 tulpină lemongrass, partea palidă, fin tocată","200 g unt de arahide cremos","200 ml lapte de cocos (pentru sos)","2 linguri kecap manis (sos de soia dulce)","1 lingură suc de lime","1 linguriță sambal oelek sau sriracha","20 bețișoare de bambus, înmuiate în apă rece 30 de minute"]},"howIsMade":{"ru":"Смешайте соевый соус, кокосовое молоко, коричневый сахар, молотый кориандр, тмин, куркуму, чеснок и лемонграсс в миске для маринада. Добавьте кусочки курицы, перемешайте и маринуйте минимум 30 минут при комнатной температуре или до 4 часов в холодильнике. Приготовьте арахисовый соус: соедините арахисовое масло, кокосовое молоко, кечап манис, сок лайма и самбал в маленькой кастрюле на слабом огне и помешивайте 3-4 минуты до однородной шелковистой консистенции; при необходимости разбавьте водой. Нанижите по 4-5 кусочков курицы на каждую замоченную шпажку, плотно прижимая их друг к другу. Разогрейте угольный гриль, чугунную сковороду-гриль на сильном огне и смажьте маслом. Жарьте шашлычки по 3-4 минуты с каждой стороны, один раз перевернув, пока курица не обуглится местами и легко не будет отделяться от шпажки — внутренняя температура должна достигнуть 75°C. Подавайте немедленно с тёплым арахисовым соусом и нарезанным огурцом.","en":"Mix the soy sauce, coconut milk, brown sugar, ground coriander, cumin, turmeric, garlic, and lemongrass in a bowl to make the marinade. Add the chicken cubes, toss to coat, and marinate for at least 30 minutes at room temperature or up to 4 hours in the refrigerator. Make the peanut sauce: combine the peanut butter, coconut milk, kecap manis, lime juice, and sambal in a small saucepan over low heat and stir for 3-4 minutes until smooth and silky; thin with a splash of water if too thick. Thread 4-5 chicken pieces onto each soaked skewer, pressing them close together. Heat a charcoal grill, cast-iron griddle, or grill pan over high heat and brush lightly with oil. Grill the skewers for 3-4 minutes per side, turning once, until deeply charred in spots and the chicken pulls away from the skewer easily — internal temperature should reach 75°C. Serve immediately with the warm peanut sauce for dipping and sliced cucumber alongside."}},{"id":69,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"ru":"Малайзия","en":"Malaysia","ro":"Malaysia"},"name":{"ru":"Лакса","en":"Laksa","ro":"Laksa"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["3 ст. л. пасты лакса (или красной карри-пасты с 1 ч. л. пасты из креветок)","2 ст. л. растительного масла","800 мл кокосового молока (2 банки по 400 мл)","600 мл куриного бульона или воды","2 ст. л. рыбного соуса","1 ч. л. сахара","400 г сырых средних креветок, очищенных и без кишечника","200 г твёрдого тофу, обсушенного и нарезанного кубиками 2 см","200 г свежих ростков сои","200 г рисовой вермишели, замоченной в кипятке на 3 минуты и отцеженной","4 крупных яйца, сваренных вкрутую (7 минут), очищенных и разрезанных пополам","100 г стручковой фасоли, обрезанной и разрезанной пополам","2 лайма, нарезанных дольками","20 г свежей кинзы, только листья","2 зелёных лука, тонко нарезанных"],"en":["3 tbsp laksa paste (or red curry paste with 1 tsp shrimp paste added)","2 tbsp vegetable oil","800 ml coconut milk (2 x 400 ml cans)","600 ml chicken stock or water","2 tbsp fish sauce","1 tsp sugar","400 g raw medium prawns, peeled and deveined","200 g firm tofu, drained and cut into 2 cm cubes","200 g fresh bean sprouts","200 g rice vermicelli noodles, soaked in boiling water 3 minutes and drained","4 large eggs, hard-boiled (7 minutes), peeled and halved","100 g green beans, trimmed and halved","2 limes, cut into wedges","20 g fresh coriander, leaves only","2 spring onions, thinly sliced"],"ro":["3 linguri pastă laksa (sau pastă de curry roșu cu 1 linguriță pastă de creveți)","2 linguri ulei vegetal","800 ml lapte de cocos (2 conserve de 400 ml)","600 ml supă de pui sau apă","2 linguri sos de pește","1 linguriță zahăr","400 g creveți cruzi medii, curățați și devenați","200 g tofu ferm, scurs și tăiat cuburi de 2 cm","200 g muguri de soia proaspeți","200 g vermicelli de orez, înmuiați în apă clocotită 3 minute și scurși","4 ouă mari, fierte tari (7 minute), decojite și tăiate jumătate","100 g fasole verde, curățată și tăiată în jumătăți","2 lime, tăiate felii","20 g coriandru proaspăt, frunze","2 cepe verzi, feliate subțire"]},"howIsMade":{"ru":"Замочите рисовую вермишель в кипятке на 3 минуты, откиньте на дуршлаг, промойте холодной водой и отложите. Сварите яйца вкрутую 7 минут, охладите в ледяной воде, очистите и разрежьте пополам. Разогрейте масло в большом воке или кастрюле на среднем огне, добавьте пасту лакса и жарьте, постоянно помешивая, 2-3 минуты до появления аромата и начала отделения масла. Влейте кокосовое молоко и куриный бульон и доведите до ровного кипения. Добавьте рыбный соус и сахар, попробуйте и скорректируйте — бульон должен быть насыщенным и слегка солёным. Добавьте стручковую фасоль и варите 3 минуты, затем добавьте креветки и тофу и готовьте 2-3 минуты, пока креветки не станут розовыми. Разложите лапшу по 4 глубоким мискам и влейте горячий бульон с креветками, тофу и фасолью. Украсьте каждую миску ростками сои, половинками яиц, зелёным луком и кинзой. Подавайте немедленно с дольками лайма.","en":"Soak the rice vermicelli in boiling water for 3 minutes, drain, rinse under cold water, and set aside. Hard-boil the eggs for 7 minutes, cool in iced water, peel, and halve. Heat the oil in a large wok or saucepan over medium heat, add the laksa paste, and fry, stirring constantly, for 2-3 minutes until fragrant and the oil begins to separate. Pour in the coconut milk and chicken stock and bring to a steady simmer. Add the fish sauce and sugar, taste, and adjust — the broth should be rich and slightly salty. Add the green beans and cook for 3 minutes, then add the prawns and tofu and cook for 2-3 minutes until the prawns are pink and just cooked through. Divide the noodles between 4 deep bowls and ladle the hot broth with prawns, tofu, and beans on top. Finish each bowl with bean sprouts, 2 halved eggs, spring onions, and coriander. Serve immediately with lime wedges on the side."}},{"id":70,"servings":4,"tipType":"def","pairingsType":"mexican","origin":{"ru":"Сальвадор","en":"El Salvador","ro":"El Salvador"},"name":{"ru":"Пупуса","en":"Pupusa","ro":"Pupusa"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["400 г маса харина (нихтамализированная кукурузная мука, например Maseca), плюс немного","350 мл тёплой воды (около 40°C), при необходимости больше","1 ч. л. мелкой морской соли","200 г консервированных жареных чёрных или пинто бобов, подогретых","200 г кесо кесильо или моцареллы, крупно натёртых","2 ст. л. растительного масла (для жарки)","300 г белокочанной капусты (около 1/4 головки), очень тонко нашинкованной","1 небольшая морковь (около 80 г), очищенная и крупно натёртая","1/2 небольшой белой луковицы (около 60 г), тонко нарезанной","100 мл яблочного уксуса или белого уксуса","100 мл воды (для куртидо)","1 ч. л. соли + 1 ч. л. сахара (для куртидо)","1/2 ч. л. сушёного орегано","200 мл томатной сальсы для подачи"],"en":["400 g masa harina (nixtamalized corn flour, such as Maseca), plus extra","350 ml warm water (about 40°C), plus more if needed","1 tsp fine sea salt","200 g canned refried black or pinto beans, warmed","200 g queso quesillo or mozzarella, coarsely grated","2 tbsp vegetable oil (for cooking)","300 g white cabbage (about 1/4 head), very finely shredded","1 small carrot (about 80 g), peeled and coarsely grated","1/2 small white onion (about 60 g), thinly sliced","100 ml apple cider vinegar or white vinegar","100 ml water (for curtido)","1 tsp fine salt + 1 tsp sugar (for curtido)","1/2 tsp dried oregano","200 ml tomato salsa, to serve"],"ro":["400 g masa harina (făină de porumb nixtamalizată, ex. Maseca), plus extra","350 ml apă caldă (circa 40°C), plus dacă e nevoie","1 linguriță sare fină de mare","200 g fasole neagră sau pinto refulată (din conservă, încălzită)","200 g queso quesillo sau mozzarella, ras grosier","2 linguri ulei vegetal (pentru prăjit)","300 g varză albă (aprox. 1/4 căpățână), fin feliată","1 morcov mic (aprox. 80 g), curățat și ras","1/2 ceapă albă mică (aprox. 60 g), felii subțiri","100 ml oțet de mere sau oțet alb","100 ml apă (pentru curtido)","1 linguriță sare fină + 1 linguriță zahăr (pentru curtido)","1/2 linguriță oregano uscat","200 ml salsa de roșii pentru servit"]},"howIsMade":{"ru":"Сначала приготовьте куртидо: смешайте капусту, морковь и лук в миске, соедините уксус, воду, соль, сахар и орегано, полейте овощи, хорошо перемешайте и оставьте мариноваться минимум 30 минут (или на ночь в холодильнике). Приготовьте тесто: смешайте маса харина и соль в большой миске, постепенно влейте тёплую воду и вымешивайте руками до получения гладкого и пластичного теста — оно должно держаться без трещин; добавляйте воду по столовой ложке при необходимости. Смешайте жареные бобы с тёртым сыром для начинки. Разделите тесто на 8 равных шаров (около 90 г каждый). Расплющите шар во влажной ладони в диск диаметром около 12 см, положите 2 полных столовых ложки начинки в центр, подогните края поверх начинки и крепко защипните; аккуратно разровняйте в диск около 1 см толщиной и 12 см в диаметре, заделывая трещины. Разогрейте тяжёлую сковороду-гриль или чугунную сковороду на средне-сильном огне и смажьте маслом. Жарьте пупусас партиями по 3-4 минуты с каждой стороны, пока не появятся тёмно-золотистые пятна и тесто не перестанет быть липким. Подавайте горячими с куртидо сверху и сальсой рядом.","en":"Make the curtido first: combine the cabbage, carrot, and onion in a bowl, mix the vinegar, water, salt, sugar, and oregano, pour over the vegetables, toss well, and set aside to pickle for at least 30 minutes (or overnight in the fridge). Make the dough: combine the masa harina and salt in a large bowl, pour in the warm water gradually, and mix with your hands until a smooth, pliable dough forms — it should hold together without cracking; add a tablespoon of water at a time if needed. Mix the refried beans and grated cheese together to make the filling. Divide the dough into 8 equal balls (about 90 g each). Press a ball flat in your damp palm into a disc about 12 cm across, place 2 heaped tablespoons of filling in the centre, then fold the edges up over the filling and pinch firmly to seal; gently re-flatten into a disc about 1 cm thick and 12 cm wide, patching any cracks. Heat a heavy griddle or cast-iron skillet over medium-high heat and brush with oil. Cook the pupusas in batches for 3-4 minutes per side until dark golden-brown patches appear and the dough feels dry rather than tacky. Serve hot with the curtido piled on top and salsa alongside."}},{"id":72,"servings":4,"tipType":"fish","pairingsType":"vietnamese","origin":{"ru":"Камбоджа","en":"Cambodia","ro":"Cambodgia"},"name":{"ru":"Амок","en":"Amok","ro":"Amok"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["600 г филе белой рыбы (тилапия, снаппер или сом), без кожи, нарезанные кусками 3 см","400 мл кокосового молока (1 банка 400 мл)","2 крупных яйца, слегка взбитых","3 ст. л. рыбного соуса","1 ч. л. сахара","2 стебля лемонграсса, только светлая часть, очень мелко нарубленных","3 зубчика чеснока, мелко нарубленных","3 шалота (около 100 г), мелко нарубленных","1 ч. л. пасты галангала (или 1 см свежего галангала, натёртого)","1/2 ч. л. молотой куркумы","1/2 ч. л. сухих хлопьев чили или 1 свежий красный чили, мелко нарезанный","4 листа каффир-лайма, стебли удалены, очень тонко нарезанных","4 больших квадрата банановых листьев (30 x 30 см), размягчённых над огнём, или 4 формочки","20 г свежего базилика или тайского базилика для украшения"],"en":["600 g white fish fillets (tilapia, snapper, or catfish), skin removed, cut into 3 cm pieces","400 ml coconut milk (1 x 400 ml can)","2 large eggs, lightly beaten","3 tbsp fish sauce","1 tsp caster sugar","2 lemongrass stalks, pale parts only, very finely minced","3 garlic cloves, finely minced","3 shallots (about 100 g), finely minced","1 tsp galangal paste (or 1 cm fresh galangal, grated)","1/2 tsp ground turmeric","1/2 tsp dried chilli flakes or 1 fresh red chilli, finely sliced","4 kaffir lime leaves, stems removed, very finely shredded","4 large banana leaf squares (30 x 30 cm), softened over a flame, or 4 ramekins","20 g fresh basil or Thai basil leaves, to garnish"],"ro":["600 g file de pește alb (tilapia, biban sau somn), fără piele, tăiat bucăți de 3 cm","400 ml lapte de cocos (1 conservă de 400 ml)","2 ouă mari, ușor bătute","3 linguri sos de pește","1 linguriță zahăr","2 tulpini lemongrass, doar partea palidă, fin tocate","3 căței de usturoi, fin tocați","3 șalote (aproximativ 100 g), fin tocate","1 linguriță pastă de galangal (sau 1 cm galangal proaspăt, ras)","1/2 linguriță turmeric măcinat","1/2 linguriță fulgi de ardei iute uscat sau 1 ardei roșu, fin tocat","4 frunze de kaffir lime, cotoare îndepărtate, fin feliate","4 pătrate mari de frunze de bananier (30 x 30 cm), înmuiate, sau ramekine","20 g frunze de busuioc proaspăt sau busuioc thai, pentru garnitură"]},"howIsMade":{"ru":"Истолките или измельчите в блендере лемонграсс, чеснок, шалот, галангал, куркуму и чили в однородную пасту. В большой миске взбейте кокосовое молоко, взбитые яйца, рыбный соус и сахар до объединения. Вмешайте пасту из специй и половину нарезанных листьев каффир-лайма. Добавьте кусочки рыбы и осторожно перемешайте, чтобы покрыть их; маринуйте 15 минут. Размягчите квадраты банановых листьев над газовым огнём или в горячей воде 30 секунд до мягкости. Сложите каждый в форму стакана около 12 см в ширину и 4 см в глубину, закрепив зубочисткой. Равномерно распределите рыбную смесь по 4 стаканам из банановых листьев, заполнив каждый примерно на две трети; сверху посыпьте оставшимися листьями каффир-лайма. Поставьте стаканы в бамбуковую пароварку над кипящей водой, плотно накройте и готовьте на пару 18-20 минут, пока амок не застынет — при осторожном наклоне стакана не должна вытекать жидкость — и поверхность не станет слегка упругой. Украсьте базиликом и подавайте немедленно с паровым жасминовым рисом.","en":"Pound or blend the lemongrass, garlic, shallots, galangal, turmeric, and chilli into a smooth paste. In a large bowl, whisk together the coconut milk, beaten eggs, fish sauce, and sugar until combined. Stir in the spice paste and half the shredded kaffir lime leaves. Add the fish pieces and fold gently to coat; marinate for 15 minutes. Soften the banana leaf squares over a gas flame or in hot water for 30 seconds until pliable. Fold each into a cup shape about 12 cm across and 4 cm deep, securing with a toothpick. Divide the fish mixture evenly among the 4 banana leaf cups, filling each about two-thirds full, then scatter the remaining kaffir lime leaves on top. Set the cups in a bamboo steamer over boiling water, cover tightly, and steam for 18-20 minutes until the amok is just set — no longer liquid when the cup is gently tilted — and the top is slightly firm to the touch. Garnish with fresh basil leaves and serve immediately with steamed jasmine rice."}},{"id":73,"servings":4,"tipType":"meat","pairingsType":"indian","origin":{"ru":"Непал","en":"Nepal","ro":"Nepal"},"name":{"ru":"Момо","en":"Momo","ro":"Momo"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["300 г пшеничной муки, плюс немного для раскатки","150 мл тёплой воды","500 г фарша из курицы или свинины","1 средняя луковица (около 120 г), очень мелко нарезанная","3 зубчика чеснока, мелко нарезанных","1 ст. л. свежего имбиря (около 2 см), мелко натёртого","30 г свежей кинзы, мелко нарезанной","1 ч. л. молотого тмина","1/2 ч. л. молотого кориандра","1/4 ч. л. куркумы","1 ч. л. мелкой соли, поделённой на порции","4 средних помидора (около 400 г), разрезанных пополам","2 сушёных красных чили или 1/2 ч. л. хлопьев чили","1 ст. л. растительного масла"],"en":["300 g plain flour (all-purpose), plus extra for dusting","150 ml warm water","500 g ground chicken or pork","1 medium onion (about 120 g), very finely diced","3 garlic cloves, finely minced","1 tbsp fresh ginger (about 2 cm piece), finely grated","30 g fresh coriander (cilantro), finely chopped","1 tsp ground cumin","1/2 tsp ground coriander","1/4 tsp ground turmeric","1 tsp fine sea salt, divided","4 medium tomatoes (about 400 g), halved","2 dried red chillies or 1/2 tsp chilli flakes","1 tbsp vegetable oil"],"ro":["300 g făină albă (tip 550), plus extra pentru pudrat","150 ml apă caldă","500 g carne tocată de pui sau porc","1 ceapă medie (circa 120 g), tocată mărunt","3 căței de usturoi, tocați mărunt","1 lingură ghimbir proaspăt (circa 2 cm), ras fin","30 g coriandru proaspăt, tocat mărunt","1 linguriță chimen măcinat","1/2 linguriță coriandru măcinat","1/4 linguriță turmeric","1 linguriță sare fină, împărțită","4 roșii medii (circa 400 g), tăiate în jumătăți","2 ardei iuți uscați sau 1/2 linguriță fulgi de ardei iute","1 lingură ulei vegetal"]},"howIsMade":{"ru":"Смешайте муку и 1/2 ч. л. соли, постепенно добавьте тёплую воду и месите 5-6 минут до получения гладкого, упругого и не липкого теста; накройте влажным полотенцем и дайте отдохнуть 30 минут. В отдельной миске смешайте фарш, лук, чеснок, имбирь, кинзу, тмин, молотый кориандр, куркуму, оставшиеся 1/2 ч. л. соли и масло; уберите в холодильник на 15 минут. Для соуса поджарьте половинки помидоров и сушёный чили на сухой сковороде на сильном огне 4-5 минут до мягкости и подпалин, затем измельчите с чесноком и солью до однородного соуса. Разделите тесто на 24 равные части (по 15 г каждая) и раскатайте каждую в тонкий круг диаметром около 8 см. Положите в центр горку фарша, соберите края небольшими перекрывающимися складками и плотно защипните сверху. Выложите момо на слегка смазанный пергамент в пароварку, оставляя не менее 1 см между ними. Готовьте на пару 12-15 минут, пока оболочка не станет прозрачной, а момо при лёгком нажатии будет пружинить. Подавайте сразу с томатно-чили соусом.","en":"Combine flour and 1/2 tsp of the salt in a bowl, then add warm water a little at a time, mixing until a rough dough forms; knead for 5-6 minutes until smooth, firm, and no longer sticky, then cover with a damp cloth and rest for 30 minutes. In a separate bowl, mix the ground meat, onion, garlic, ginger, coriander leaves, cumin, ground coriander, turmeric, the remaining 1/2 tsp salt, and oil until well combined; refrigerate for 15 minutes to let the flavours meld. Meanwhile, make the dipping sauce: char the tomato halves and dried chillies in a dry heavy skillet over high heat for 4-5 minutes until softened and blackened in spots, then blend with the garlic and remaining salt until smooth. Divide the rested dough into 24 equal pieces (about 15 g each) and roll each into a thin round about 8 cm across. Place a heaped teaspoon of filling in the centre of each round, then gather the edges and pleat them together with small overlapping folds, pinching firmly at the top to seal. Line a bamboo or metal steamer with lightly oiled parchment paper and arrange the momo at least 1 cm apart. Set over a pot of vigorously boiling water, cover tightly, and steam for 12-15 minutes until the wrappers turn translucent and a gently pressed momo springs back without feeling doughy inside. Serve immediately with the tomato-chilli sauce."}},{"id":74,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ru":"Эквадор","en":"Ecuador","ro":"Ecuador"},"name":{"ru":"Энсебольядо","en":"Encebollado","ro":"Encebollado"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["700 г свежего тунца или 2 банки тунца в воде (400 г всего), откинутых на дуршлаг","600 г маниока (юки), очищенного и нарезанного кусочками по 4 см","1 большая красная луковица (около 200 г), нарезанная тонкими полукольцами","4 средних помидора (около 400 г), крупно нарезанных","4 зубчика чеснока, крупно нарезанных","1 ч. л. молотого тмина","1 ч. л. пасты ачиоте или 1/2 ч. л. сладкой паприки","1,5 л рыбного бульона или воды","3 ст. л. сока лайма (около 2 лаймов)","2 ст. л. растительного масла","1 ч. л. мелкой соли","30 г свежей кинзы, поделённой — половина для варки, половина для подачи","1 халапеньо или ахи, без семян, тонко нарезанный","2 стебля зелёного лука, тонко нарезанных (для украшения)"],"en":["700 g fresh tuna or 2 cans tuna in water (400 g total), drained","600 g cassava (yuca), peeled and cut into 4 cm chunks","1 large red onion (about 200 g), thinly sliced into half-moons","4 medium tomatoes (about 400 g), roughly chopped","4 garlic cloves, roughly chopped","1 tsp ground cumin","1 tsp achiote paste or 1/2 tsp sweet paprika","1.5 litres fish stock or water","3 tbsp fresh lime juice (about 2 limes)","2 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), divided — half to cook, half to garnish","1 jalapeño or aji pepper, deseeded and finely sliced","2 spring onions, thinly sliced (to garnish)"],"ro":["700 g ton proaspăt sau 2 conserve ton în apă (400 g total), scurse","600 g yuca (manioc), curățată și tăiată bucăți de 4 cm","1 ceapă roșie mare (circa 200 g), tăiată în felii subțiri","4 roșii medii (circa 400 g), tăiate grosier","4 căței de usturoi, tăiați grosier","1 linguriță chimen măcinat","1 linguriță pastă de achiote sau 1/2 linguriță paprika dulce","1,5 litri supă de pește sau apă","3 linguri zeamă de lămâie verde (circa 2 lămâi)","2 linguri ulei vegetal","1 linguriță sare fină","30 g coriandru proaspăt, împărțit — jumătate pentru gătit, jumătate pentru servit","1 jalapeno sau ardei iute, fără semințe, feliat subțire","2 fire ceapă verde, tăiate subțire (pentru decor)"]},"howIsMade":{"ru":"Нагрейте масло в большой кастрюле на среднем огне, добавьте лук, чеснок, помидоры, халапеньо и тмин и готовьте 8-10 минут, периодически помешивая, пока лук не станет очень мягким, а помидоры не превратятся в густую пасту. Вмешайте пасту ачиоте и готовьте 1 минуту, пока масло не приобретёт насыщенный оранжевый цвет. Влейте бульон, доведите до кипения, добавьте маниок и варите 20-25 минут до полной мягкости, пока он не начнёт слегка разваливаться по краям. Если используете свежего тунца, припустите стейки в чуть подсоленной воде 5-6 минут до готовности, немного остудите и разберите на крупные кусочки. Добавьте тунца, половину кинзы и сок лайма в кастрюлю; варите на слабом огне 3-4 минуты для объединения вкусов. Посолите по вкусу и разлейте суп в глубокие тарелки. Посыпьте оставшейся кинзой и зелёным луком и подавайте с тостадас или чипсами из подорожника.","en":"Heat the oil in a large pot over medium heat, add the onion, garlic, tomatoes, jalapeño, and cumin, and cook for 8-10 minutes, stirring occasionally, until the onion is very soft and the tomatoes have broken down into a thick paste. Stir in the achiote paste and cook for 1 minute until the oil turns a deep orange. Pour in the stock, bring to a boil, then add the cassava and cook for 20-25 minutes until completely tender and just beginning to break apart at the edges. If using fresh tuna, poach the steaks in lightly salted simmering water for 5-6 minutes until just cooked through, cool slightly, and flake into large chunks. Add the flaked tuna (or drained canned tuna), half the coriander, and the lime juice to the pot; simmer for 3-4 minutes to marry the flavours. Season with salt to taste, then ladle the soup into deep bowls. Top with the remaining coriander and spring onions, and serve with tostadas or plantain chips on the side."}},{"id":75,"servings":4,"tipType":"soup","pairingsType":"middle-eastern","origin":{"ru":"Марокко","en":"Morocco","ro":"Maroc"},"name":{"ru":"Харира","en":"Harira","ro":"Harira"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["400 г бараньей лопатки, нарезанной кусочками по 3 см","400 г консервированного нута (1 банка 400 г), откинутого и промытого","150 г зелёной или коричневой чечевицы, промытой","4 средних помидора (около 400 г), крупно нарезанных","1 большая луковица (около 200 г), очень мелко нарезанная","3 стебля сельдерея с листьями (около 150 г), тонко нарезанных","3 зубчика чеснока, мелко нарезанных","1 ч. л. молотого тмина","1 ч. л. корицы + 1 ч. л. молотого имбиря","1/2 ч. л. куркумы + 1 ч. л. мелкой соли","2 ст. л. оливкового масла","1,5 л воды или бараньего бульона","60 г тонкой вермишели, сломанной на кусочки по 2 см","30 г свежей кинзы и плоской петрушки, крупно нарезанных"],"en":["400 g lamb shoulder, cut into 3 cm chunks","400 g canned chickpeas (1 x 400 g can), rinsed and drained","150 g green or brown lentils, rinsed","4 medium tomatoes (about 400 g), roughly chopped","1 large onion (about 200 g), finely diced","3 celery stalks with leaves (about 150 g), finely sliced","3 garlic cloves, finely minced","1 tsp ground cumin","1 tsp ground cinnamon + 1 tsp ground ginger","1/2 tsp ground turmeric + 1 tsp fine sea salt","2 tbsp olive oil","1.5 litres water or lamb stock","60 g thin vermicelli, broken into 2 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped"],"ro":["400 g spata de miel, taiata bucati de 3 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","150 g linte verde sau bruna, clatita","4 rosii medii (circa 400 g), taiate grosier","1 ceapa mare (circa 200 g), tocata marunt","3 tulpini de telina cu frunze (circa 150 g), feliate subtire","3 căței de usturoi, tocati marunt","1 lingurita chimen macinat","1 lingurita scortisoara + 1 lingurita ghimbir macinat","1/2 lingurita turmeric + 1 lingurita sare fina","2 linguri ulei de masline","1,5 litri apa sau supa de miel","60 g vermicelli subtire, rupt in bucati de 2 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier"]},"howIsMade":{"ru":"Разогрейте масло в большой кастрюле на сильном огне, добавьте куски баранины и обжарьте 4-5 минут, периодически переворачивая, до равномерной корочки. Добавьте лук, сельдерей и чеснок и готовьте 5 минут до мягкости. Вмешайте тмин, корицу, имбирь, куркуму и соль и жарьте 1 минуту до появления аромата. Добавьте помидоры, нут, чечевицу и влейте воду или бульон; доведите до кипения и снимите пену. Убавьте огонь, накройте наполовину и варите 45-50 минут, пока баранина не станет нежной, а чечевица не растворится в бульоне, слегка загустив его. Добавьте вермишель и варите 5-6 минут. Снимите с огня, вмешайте кинзу и петрушку, выдавите лимонный сок по вкусу. Разлейте по тарелкам и подавайте с хлебом и финиками.","en":"Heat the oil in a large pot over medium-high heat, add the lamb chunks and sear for 4-5 minutes, turning occasionally, until browned on all sides. Add the onion, celery, and garlic and cook for 5 minutes until softened. Stir in the cumin, cinnamon, ginger, turmeric, and salt and cook for 1 minute until fragrant. Add the tomatoes, chickpeas, and lentils, pour in the water or stock, and bring to a boil; skim any foam from the surface. Reduce the heat to low, cover partially, and simmer for 45-50 minutes until the lamb is tender and the lentils have dissolved into the broth, thickening it slightly. Stir in the vermicelli and cook for 5-6 minutes until tender. Remove from the heat, stir in the coriander and parsley, and squeeze in lemon juice to taste. Ladle into bowls and serve immediately with crusty bread and dates."}},{"id":76,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"ru":"Грузия","en":"Georgia","ro":"Georgia"},"name":{"ru":"Лобио","en":"Lobio","ro":"Lobio"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500 г сушёной красной фасоли (или 2 банки по 400 г, промытых)","1 большая луковица (около 200 г), очень мелко нарезанная","4 зубчика чеснока, мелко нарезанных","100 г половинок грецких орехов, мелко смолотых или мелко нарезанных","1 ч. л. молотого кориандра","1/2 ч. л. молотого пажитника (уцхо-сунели)","1/2 ч. л. корицы","1/2 ч. л. хлопьев чили или 1 маленький чили без семян нарезанный","2 ст. л. белого или красного винного уксуса","3 ст. л. растительного масла","1 ч. л. мелкой соли","30 г свежей кинзы, мелко нарезанной","4 ст. л. зёрен граната (около 1/2 граната)","4 стебля зелёного лука, тонко нарезанных"],"en":["500 g dried red kidney beans (or 2 x 400 g cans, rinsed)","1 large onion (about 200 g), finely diced","4 garlic cloves, finely minced","100 g walnut halves, finely ground or very finely chopped","1 tsp ground coriander","1/2 tsp ground fenugreek (utsho suneli)","1/2 tsp ground cinnamon","1/2 tsp dried chilli flakes or 1 small red chilli, deseeded and minced","2 tbsp white wine vinegar or red wine vinegar","3 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), finely chopped","4 tbsp pomegranate seeds (about 1/2 pomegranate)","4 spring onions, thinly sliced"],"ro":["500 g fasole rosie uscata (sau 2 x 400 g conserve, clatite)","1 ceapa mare (circa 200 g), tocata marunt","4 căței de usturoi, tocati marunt","100 g miez de nuca, macinat fin sau tocat marunt","1 lingurita coriandru macinat","1/2 lingurita schinduf macinat (utsho suneli)","1/2 lingurita scortisoara","1/2 lingurita fulgi de ardei iute sau 1 ardei iute mic, fara seminte, tocat","2 linguri otet alb sau de vin rosu","3 linguri ulei vegetal","1 lingurita sare fina","30 g coriandru proaspat, tocat marunt","4 linguri boabe de rodie (circa 1/2 rodie)","4 fire ceapa verde, taiate subtire"]},"howIsMade":{"ru":"Если используете сушёную фасоль, замочите её на ночь в холодной воде, слейте воду, залейте свежей холодной водой в большой кастрюле, доведите до кипения, снимите пену и варите 45-60 минут до полной мягкости, пока фасоль не начнёт разваливаться, а жидкость не станет тёмно-красной и густой. Разогрейте масло на сковороде на среднем огне, добавьте лук и готовьте 10-12 минут, периодически помешивая, до глубокого золотистого цвета и очень мягкого состояния. Добавьте чеснок, молотый кориандр, пажитник, корицу и чили и готовьте 2 минуты до появления аромата. Вмешайте луковую зажарку, молотые грецкие орехи и уксус в фасоль и варите на слабом огне 10 минут, периодически помешивая, пока вкусы не смешаются, а фасоль не станет очень мягкой с густым соусом — раздавите несколько фасолин о стенки кастрюли для загустения. Посолите и отрегулируйте количество уксуса. Снимите с огня и вмешайте половину свежей кинзы. Переложите в блюдо и украсьте зелёным луком, зёрнами граната и оставшейся кинзой. Подавайте тёплым с лепёшками.","en":"If using dried beans, soak them overnight in cold water, then drain, cover with fresh cold water in a large pot, bring to a boil, skim any foam, and simmer for 45-60 minutes until completely tender and starting to break apart, with a thick dark-red cooking liquid. Heat the oil in a frying pan over medium heat, add the onion and cook for 10-12 minutes, stirring occasionally, until deep golden and very soft. Add the garlic, ground coriander, fenugreek, cinnamon, and chilli and cook for 2 minutes until fragrant. Stir the onion mixture, ground walnuts, and vinegar into the cooked beans and simmer over low heat for 10 minutes, stirring occasionally, until the flavours meld and the beans are very soft with a thick sauce — mash a few beans against the side of the pot to help thicken. Season with salt and more vinegar to taste. Remove from the heat and stir in half the fresh coriander. Transfer to a shallow dish and top with the spring onions, pomegranate seeds, and remaining coriander. Serve warm with flatbread."}},{"id":77,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"ru":"Алжир","en":"Algeria","ro":"Algeria"},"name":{"ru":"Шакшука","en":"Chakhchoukha","ro":"Chakhchoukha"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["600 г бараньей лопатки с костью или шеи, нарезанной кусочками по 4 см","400 г консервированного нута (1 банка 400 г), откинутого и промытого","4 средних помидора (около 400 г), крупно нарезанных","2 средние луковицы (около 300 г), очень мелко нарезанных","4 зубчика чеснока, мелко нарезанных","2 ст. л. растительного масла","1 ч. л. молотого тмина","1 ч. л. молотого кориандра","1 ч. л. сладкой паприки","1/2 ч. л. корицы + 1/2 ч. л. молотого чёрного перца","1 ч. л. мелкой соли","600 мл воды или бараньего бульона","4 большие лепёшки ругаг (алжирский хлеб) или лаваш, разорванный на куски по 5 см","30 г свежей кинзы и плоской петрушки, крупно нарезанных (для украшения)"],"en":["600 g bone-in lamb shoulder or neck, cut into 4 cm pieces","400 g canned chickpeas (1 x 400 g can), rinsed and drained","4 medium tomatoes (about 400 g), roughly chopped","2 medium onions (about 300 g), finely diced","4 garlic cloves, finely minced","2 tbsp vegetable oil","1 tsp ground cumin","1 tsp ground coriander","1 tsp sweet paprika","1/2 tsp ground cinnamon + 1/2 tsp ground black pepper","1 tsp fine sea salt","600 ml water or lamb stock","4 large sheets of rougag (Algerian flatbread) or large tortillas, torn into 5 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped (to garnish)"],"ro":["600 g spata de miel cu os sau gat, taiata bucati de 4 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","4 rosii medii (circa 400 g), taiate grosier","2 cepe medii (circa 300 g), tocate marunt","4 căței de usturoi, tocati marunt","2 linguri ulei vegetal","1 lingurita chimen macinat","1 lingurita coriandru macinat","1 lingurita boia dulce","1/2 lingurita scortisoara + 1/2 lingurita piper negru","1 lingurita sare fina","600 ml apa sau supa de miel","4 foi mari de rougag (lipie algeriana) sau 4 tortilla mari, rupte bucati de 5 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier (pentru decor)"]},"howIsMade":{"ru":"Разогрейте масло в большой тяжёлой кастрюле на сильном огне, добавьте куски баранины порциями и обжарьте по 4-5 минут до румяной корочки со всех сторон. Добавьте лук и чеснок и готовьте 5 минут до мягкости и золотистости. Вмешайте тмин, кориандр, паприку, корицу, соль и перец и жарьте 1 минуту до появления аромата специй. Добавьте помидоры и готовьте 8-10 минут, периодически помешивая, до образования густого соуса. Влейте воду или бульон, добавьте нут и доведите до кипения; убавьте огонь, накройте и варите 50-60 минут, пока баранина не станет полностью нежной и не будет легко отходить от кости. Разложите кусочки лепёшки на дне большого блюда и щедро полейте горячим мясом и соусом, осторожно прижимая хлеб, чтобы он впитал жидкость и стал мягким. Украсьте свежей кинзой и петрушкой и подавайте немедленно.","en":"Heat the oil in a large heavy pot over medium-high heat, add the lamb in batches and sear for 4-5 minutes until browned on all sides. Add the onion and garlic and cook for 5 minutes until softened and golden. Stir in the cumin, coriander, paprika, cinnamon, salt, and pepper and cook for 1 minute until the spices smell toasted. Add the tomatoes and cook for 8-10 minutes, stirring occasionally, until they break down into a thick sauce. Pour in the water or stock, add the chickpeas, and bring to a boil; reduce the heat to low, cover, and simmer for 50-60 minutes until the lamb is completely tender and falling off the bone. Scatter the torn flatbread pieces over the bottom of a large serving dish and ladle the hot meat and sauce generously on top, pressing the bread down gently so it absorbs the liquid and softens — it should be soaked through but not dissolving. Garnish with the fresh coriander and parsley and serve immediately."}},{"id":78,"servings":4,"tipType":"meat","timeMins":{"total":330,"active":60},"pairingsType":"meat","origin":{"ru":"Индонезия","en":"Indonesia","ro":"Indonezia"},"name":{"ru":"Ренданг","en":"Rendang","ro":"Rendang"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1 кг говядины (лопатка или грудинка), нарезанной кубиками по 5 см","800 мл жирного кокосового молока (2 банки по 400 мл)","5 луковиц лук-шалот (около 150 г), крупно нарезанных","4 зубчика чеснока, крупно нарезанных","2 ст. л. свежего имбиря (около 3 см), крупно нарезанного","1 ст. л. свежего галангала (около 2 см) или 1 ч. л. пасты галангала","3 стебля лемонграсса, бледные части, нарезанных","4-6 сушёных красных чили, замоченных в тёплой воде 15 минут, откинутых","4 листа кафир-лайма, черешки удалены, мелко нарезанных","1 ч. л. молотой куркумы","1 ч. л. молотого кориандра","1 ч. л. молотого тмина","1 ч. л. мелкой соли","1 ст. л. растительного масла"],"en":["1 kg beef chuck or brisket, cut into 5 cm cubes","800 ml full-fat coconut milk (2 x 400 ml cans)","5 shallots (about 150 g), roughly chopped","4 garlic cloves, roughly chopped","2 tbsp fresh ginger (about 3 cm piece), roughly chopped","1 tbsp fresh galangal (about 2 cm) or 1 tsp galangal paste","3 lemongrass stalks, pale parts only, roughly sliced","4-6 dried red chillies, soaked in warm water 15 minutes and drained","4 kaffir lime leaves, stems removed, very finely shredded","1 tsp ground turmeric","1 tsp ground coriander","1 tsp ground cumin","1 tsp fine sea salt","1 tbsp vegetable oil"],"ro":["1 kg muschi de vita sau piept, taiat cuburi de 5 cm","800 ml lapte de cocos integral (2 x 400 ml)","5 esalote (circa 150 g), taiate grosier","4 căței de usturoi, tăiați grosier","2 linguri ghimbir proaspat (circa 3 cm), taiat grosier","1 lingura galangal proaspat (circa 2 cm) sau 1 lingurita pasta galangal","3 tulpini de lemongrass, partile palide, feliate grosier","4-6 ardei iuti rosii uscati, înmuiați in apa calda 15 minute, scursi","4 frunze de kafir lime, coada indepartata, maruntite fin","1 lingurita turmeric macinat","1 lingurita coriandru macinat","1 lingurita chimen macinat","1 lingurita sare fina","1 lingura ulei vegetal"]},"howIsMade":{"ru":"Измельчите лук-шалот, чеснок, имбирь, галангал, лемонграсс и размоченный чили с 2 ст. л. кокосового молока до полностью однородной пасты — около 2 минут. Разогрейте масло в большой тяжёлой кастрюле на среднем огне, добавьте пряную пасту и готовьте 5-6 минут, постоянно помешивая, пока паста не станет глубокого золотистого цвета и не исчезнет запах сырых специй. Добавьте кубики говядины и перемешайте, чтобы покрыть пастой; готовьте 3-4 минуты до лёгкого зарумянивания. Влейте оставшееся кокосовое молоко, добавьте листья каффир-лайма, куркуму, кориандр, тмин и соль и перемешайте. Доведите до кипения, убавьте огонь до минимума и варите без крышки 1,5 часа, помешивая каждые 15-20 минут, пока кокосовое молоко значительно не загустеет и не станет светло-коричневым. Продолжайте готовить, помешивая чаще (каждые 5-10 минут), ещё 30-45 минут, пока соус почти полностью не выпарится и масло не отделится; мясо начнёт жариться в собственном жире и станет тёмно-коричневым. Подавайте с варёным белым рисом.","en":"Blend the shallots, garlic, ginger, galangal, lemongrass, and soaked chillies with 2 tbsp of the coconut milk until completely smooth — about 2 minutes in a food processor. Heat the oil in a large heavy pot over medium heat, add the spice paste and cook for 5-6 minutes, stirring constantly, until deep golden and the raw smell has gone. Add the beef cubes and stir to coat with the paste; cook for 3-4 minutes until lightly coloured. Pour in the remaining coconut milk, add the kaffir lime leaves, turmeric, coriander, cumin, and salt, and stir to combine. Bring to a boil, then reduce to medium-low and simmer uncovered for 1.5 hours, stirring every 15-20 minutes, until the coconut milk thickens significantly and turns light brown. Continue cooking, stirring more frequently (every 5-10 minutes), for another 30-45 minutes as the sauce reduces to almost nothing and the oil splits from the coconut; the beef will begin to fry in its own fat and turn deep mahogany brown — this is when rendang is ready. Serve with steamed white rice."}},{"id":79,"servings":4,"tipType":"fish","timeMins":{"total":4380,"active":45},"pairingsType":"fish","origin":{"ru":"Швеция","en":"Sweden","ro":"Suedia"},"name":{"ru":"Гравлакс","en":"Gravlax","ro":"Gravlax"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["600 г филе лосося с кожей, без костей","3 ст. л. крупной морской соли","2 ст. л. сахарного песка","1 ч. л. белых горошин перца, крупно раздробленных","60 г свежего укропа (1 большой пучок), крупно нарезанного","2 ст. л. аквавита или водки (по желанию)"],"en":["600 g salmon fillet, skin-on and pin-boned","3 tbsp coarse sea salt","2 tbsp caster sugar","1 tsp white peppercorns, coarsely crushed","60 g fresh dill (1 large bunch), roughly chopped","2 tbsp aquavit or vodka (optional)"],"ro":["600 g file de somon cu piele, cu oasele îndepărtate","3 linguri sare grunjoasă de mare","2 linguri zahăr tos","1 linguriță boabe de piper alb, zdrobite grosier","60 g mărar proaspăt (1 legătură mare), tocat grosier","2 linguri aquavit sau vodcă (opțional)"]},"howIsMade":{"ru":"Смешайте крупную соль, сахар и раздробленные горошины перца в небольшой миске. Положите лосося кожей вниз на большой лист пищевой плёнки; равномерно прижмите половину укропа к мякоти, равномерно распределите посолочную смесь сверху, сбрызните аквавитом если используете, затем накройте оставшимся укропом. Плотно заверните в плёнку и положите в глубокую посуду, поставив сверху тяжёлую тарелку для прессования. Уберите в холодильник на 48-72 часа, переворачивая свёрток каждые 12 часов пока рыба просаливается — рассол будет скапливаться в посуде. Разверните, промойте под холодной водой и обсушите бумажными полотенцами. Нарежьте очень тонко по диагонали гибким ножом и подавайте на тёмном ржаном хлебе с горчично-укропным соусом.","en":"Mix the coarse salt, sugar, and crushed peppercorns in a small bowl. Lay the salmon skin-side down on a large piece of cling film; press half the dill evenly over the flesh, spread the cure uniformly over the top, drizzle with aquavit if using, then cover with the remaining dill. Wrap tightly in the cling film and place in a deep dish, setting a heavy plate on top to press the fish. Refrigerate for 48-72 hours, turning the parcel every 12 hours as it cures — brine will pool in the dish. Unwrap, rinse under cold water, and pat dry with paper towels. Slice very thinly on the diagonal with a sharp flexible knife and serve on dark rye bread with a mustard-dill sauce."}},{"id":80,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Бельгия","en":"Belgium","ro":"Belgia"},"name":{"ru":"Стувфлес","en":"Stoofvlees","ro":"Stoofvlees"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1 кг говядины для тушения (лопатка или грудинка), нарезанной кубиками 4 см","330 мл тёмного бельгийского пива (Leffe Brune или аналог)","500 г репчатого лука (около 3 средних), тонко нарезанного","2 ст. л. дижонской горчицы","2 толстых ломтика (около 80 г) подсохшего ржаного хлеба без корки","2 ст. л. нейтрального масла","2 лавровых листа","3 веточки свежего тимьяна","1 ст. л. коричневого сахара","1 ст. л. красного винного уксуса","1 ч. л. мелкой соли","1/2 ч. л. молотого чёрного перца"],"en":["1 kg beef stew meat (chuck or brisket), cut into 4 cm cubes","330 ml dark Belgian ale (Leffe Brune or similar)","500 g onions (about 3 medium), thinly sliced","2 tbsp Dijon mustard","2 thick slices (about 80 g) stale brown bread, crusts removed","2 tbsp neutral oil","2 bay leaves","3 fresh thyme sprigs","1 tbsp brown sugar","1 tbsp red wine vinegar","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["1 kg carne de vită pentru tocăniță (capac sau piept), tăiată cuburi de 4 cm","330 ml bere belgiană brună (Leffe Brune sau similară)","500 g ceapă (circa 3 medii), feliată subțire","2 linguri muștar Dijon","2 felii groase (circa 80 g) pâine brună veche, fără coajă","2 linguri ulei neutru","2 foi de dafin","3 crenguțe de cimbru proaspăt","1 lingură zahăr brun","1 lingură oțet de vin roșu","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ru":"Посолите и поперчите мясо. Разогрейте масло в большой тяжёлой кастрюле на средне-сильном огне и обжарьте мясо порциями по 3-4 минуты с каждой стороны до глубокого золотистого цвета; отложите. Уменьшите огонь, добавьте в ту же кастрюлю лук и готовьте 12-15 минут, периодически помешивая, до мягкости и золотистого цвета. Верните мясо в кастрюлю, добавьте лавровый лист и тимьян, влейте пиво — оно должно почти покрыть мясо. Намажьте одну сторону каждого ломтика хлеба горчицей и положите горчицей вниз поверх тушёного мяса; хлеб растворится и загустит соус. Добавьте коричневый сахар и уксус, доведите до тихого кипения, накройте крышкой с небольшой щелью и тушите на малом огне 2 часа, помешивая каждые 30 минут, пока мясо не станет очень мягким. Снимите крышку на последние 20-30 минут, чтобы соус уварился до тёмного блестящего состояния, покрывающего тыльную сторону ложки; уберите лавровый лист и тимьян и подавайте с жареным картофелем или пюре.","en":"Season the beef with salt and pepper. Heat the oil in a large heavy casserole over medium-high and brown the beef in batches for 3-4 minutes per side until deeply golden; transfer to a plate. Reduce heat to medium, add the onions to the same pot and cook for 12-15 minutes, stirring occasionally, until soft and golden. Return the beef to the pot, tuck in the bay leaves and thyme, and pour in the beer — it should nearly cover the meat. Spread one side of each bread slice thickly with mustard and lay them mustard-side down on top of the stew; the bread will dissolve and thicken the sauce. Stir in the brown sugar and vinegar, bring to a gentle simmer, cover with the lid slightly ajar, and cook over low heat for 2 hours, stirring every 30 minutes, until the beef is very tender. Remove the lid for the final 20-30 minutes to reduce the sauce to a glossy dark gravy that coats the back of a spoon; discard the bay leaves and thyme and serve with frites or mashed potato."}},{"id":81,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ru":"Молдова","en":"Moldova","ro":"Moldova"},"name":{"ru":"Зяма","en":"Zeama","ro":"Zeamă"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["1 кг курицы на кости (голени и бёдра)","2 средних моркови (около 200 г), очищенных и разрезанных пополам","1 средняя луковица, разрезанная пополам","2 стебля сельдерея с листьями","150 г тонкой яичной лапши","200 мл борша или 4 ст. л. свежего лимонного сока","1 маленький пучок свежего любистока (около 15 г), крупно нарезанного, или петрушки","1 ч. л. мелкой соли","1/2 ч. л. белого перца"],"en":["1 kg bone-in chicken pieces (legs and thighs)","2 medium carrots (about 200 g), peeled and halved","1 medium onion, halved","2 celery stalks with leaves","150 g thin egg noodles","200 ml borș (fermented wheat bran liquid) or 4 tbsp fresh lemon juice","1 small bunch fresh lovage (about 15 g), roughly chopped, or flat-leaf parsley","1 tsp fine salt","1/2 tsp white pepper"],"ro":["1 kg bucăți de pui cu os (pulpe și coapse)","2 morcovi medii (circa 200 g), curățați și tăiați în jumătate","1 ceapă medie, tăiată în jumătate","2 tulpini de țelină cu frunze","150 g tăiței subțiri de ou","200 ml borș sau 4 linguri suc proaspăt de lămâie","1 legătură mică leuștean proaspăt (circa 15 g), tocat grosier, sau pătrunjel","1 linguriță sare fină","1/2 linguriță piper alb"]},"howIsMade":{"ru":"Положите курицу в большую кастрюлю, залейте 2 литрами холодной воды и доведите до кипения на среднем огне; снимайте пену, поднимающуюся на поверхность, в течение первых 5-10 минут до прозрачности бульона. Добавьте морковь, лук и сельдерей, уменьшите огонь до слабого, частично накройте крышкой и варите 45-50 минут до полной готовности курицы — мясо должно легко отделяться от костей. Достаньте курицу и овощи; выбросьте лук, нарежьте морковь кружочками и разберите курицу на небольшие кусочки, удалив кожу и кости. Верните измельчённую курицу и кружки моркови в кастрюлю и снова доведите до тихого кипения на среднем огне. Добавьте лапшу и варите 5-7 минут (или согласно инструкции на упаковке) до мягкости. Влейте борш или лимонный сок, перемешайте и попробуйте — суп должен иметь приятную кислинку; добавьте ещё по вкусу. Посолите, добавьте белый перец, любисток или петрушку и подавайте немедленно.","en":"Place the chicken in a large pot, cover with 2 litres of cold water, and bring to a boil over medium-high heat; skim the foam that rises for the first 5-10 minutes until the broth runs clear. Add the carrots, onion, and celery, reduce heat to medium-low, partially cover, and simmer for 45-50 minutes until the chicken is cooked through and falling from the bone. Lift out the chicken and vegetables; discard the onion, slice the carrots into rounds, and shred the chicken into bite-sized pieces, discarding skin and bones. Return the shredded chicken and carrot rounds to the pot and bring back to a simmer over medium heat. Add the noodles and cook for 5-7 minutes (or per packet) until just tender. Pour in the borș or lemon juice, stir, and taste — the soup should have a pleasant sour edge; add more as needed. Season with salt and white pepper, stir in the lovage or parsley, and serve immediately."}},{"id":82,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Австралия","en":"Australia","ro":"Australia"},"name":{"ru":"Мясной пирог","en":"Meat Pie","ro":"Meat Pie"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["375 г готового песочного теста","250 г готового слоёного теста","500 г нежирного говяжьего фарша","1 средняя луковица (около 150 г), мелко нарезанная","2 зубчика чеснока, измельчённых","250 мл говяжьего бульона","2 ст. л. томатной пасты","1 ст. л. соуса Вустершир","2 ст. л. пшеничной муки","1 яйцо, слегка взбитое, для смазки","1 ч. л. мелкой соли","1/2 ч. л. молотого чёрного перца"],"en":["375 g ready-made shortcrust pastry","250 g ready-made puff pastry","500 g lean beef mince","1 medium onion (about 150 g), finely diced","2 garlic cloves, minced","250 ml beef stock","2 tbsp tomato paste","1 tbsp Worcestershire sauce","2 tbsp plain flour","1 egg, lightly beaten, for brushing","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["375 g aluat fraged gata preparat","250 g aluat foietaj gata preparat","500 g carne de vită tocată (slabă)","1 ceapă medie (circa 150 g), tăiată mărunt","2 căței de usturoi, pisați","250 ml supă de vită","2 linguri pastă de roșii","1 lingură sos Worcestershire","2 linguri făină albă","1 ou, bătut ușor, pentru uns","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ru":"Разогрейте духовку до 200°C (180°C с вентилятором). Разогрейте немного масла на большой сковороде на средне-сильном огне, добавьте лук и чеснок и готовьте 3-4 минуты до мягкости. Добавьте фарш и готовьте, разбивая ложкой, 6-8 минут до равномерного обжаривания. Вмешайте муку, готовьте 1 минуту, затем добавьте бульон, томатную пасту, соус Вустершир, соль и перец; хорошо перемешайте. Варите на среднем огне 12-15 минут, периодически помешивая, пока соус не загустеет — начинка должна быть влажной, но не жидкой; снимите с огня и остудите 15 минут. Раскатайте песочное тесто и вырежьте 4 круга для 4 форм для пирога (около 12 см в диаметре); уложите в формы и наколите дно вилкой. Равномерно распределите начинку, покройте кружками из слоёного теста, прижмите края и смажьте взбитым яйцом. Выпекайте 25-30 минут до глубокого золотистого цвета и хрустящих крышечек; дайте отдохнуть 5 минут и подавайте с томатным соусом.","en":"Preheat the oven to 200°C (180°C fan). Heat a drizzle of oil in a large frying pan over medium-high heat, add the onion and garlic and cook for 3-4 minutes until softened. Add the beef mince and cook, breaking it up with a spoon, for 6-8 minutes until browned all over. Stir in the flour, cook for 1 minute, then add the stock, tomato paste, Worcestershire sauce, salt, and pepper; stir to combine. Simmer over medium heat for 12-15 minutes, stirring occasionally, until the gravy thickens to coat the back of a spoon — the filling should be moist but not runny; remove from heat and cool for 15 minutes. Roll out the shortcrust pastry and cut 4 circles to line 4 individual pie tins (about 12 cm diameter); press into the tins and prick the bases with a fork. Divide the filling evenly between the tins, top with puff pastry lids, press the edges to seal, and brush with beaten egg. Bake for 25-30 minutes until deep golden and the lids are puffed and crisp; rest for 5 minutes then serve with tomato sauce."}},{"id":83,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ru":"Сирия","en":"Syria","ro":"Siria"},"name":{"ru":"Фатте","en":"Fatteh","ro":"Fatteh"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ru":["2 большие питы (около 200 г), разорванные на кусочки","400 г консервированного нута (1 банка 400 г), откинутого и промытого","500 г жирного натурального йогурта","3 зубчика чеснока, измельчённых","2 ст. л. тахини","2 ст. л. свежего лимонного сока","3 ст. л. несолёного сливочного масла","50 г кедровых орешков","1 ч. л. молотого зиры","1 ч. л. сладкой паприки","1/2 ч. л. мелкой соли","2 ст. л. свежей петрушки, мелко нарезанной"],"en":["2 large pita breads (about 200 g), torn into bite-sized pieces","400 g canned chickpeas (1 x 400 g can), drained and rinsed","500 g full-fat plain yogurt","3 garlic cloves, minced","2 tbsp tahini","2 tbsp fresh lemon juice","3 tbsp unsalted butter","50 g pine nuts","1 tsp ground cumin","1 tsp sweet paprika","1/2 tsp fine salt","2 tbsp fresh parsley, finely chopped"],"ro":["2 pâini pita mari (circa 200 g), rupte în bucăți","400 g năut din conservă (1 x 400 g), scurs și clătit","500 g iaurt integral simplu","3 căței de usturoi, pisați","2 linguri tahini","2 linguri suc proaspăt de lămâie","3 linguri unt nesărat","50 g semințe de pin","1 linguriță chimion măcinat","1 linguriță boia dulce","1/2 linguriță sare fină","2 linguri pătrunjel proaspăt, tocat fin"]},"howIsMade":{"ru":"Разогрейте духовку до 200°C. Смешайте кусочки питы с небольшим количеством масла, разложите на противне и запекайте 8-10 минут до золотистого цвета и хруста. Откиньте нут на дуршлаг; разогрейте в небольшой кастрюле с щепоткой соли и зирой на среднем огне 3-4 минуты. Взбейте йогурт, чеснок, тахини, лимонный сок и соль до однородного соуса; скорректируйте вкус. Разложите запечённые кусочки питы ровным слоем на большом блюде. Равномерно выложите тёплый нут на питу. Щедро полейте йогуртным соусом, покрывая всё. Растопите масло на небольшой сковороде на среднем огне; добавьте кедровые орешки и жарьте 2-3 минуты до золотистого цвета; вмешайте паприку и немедленно полейте горячим маслом поверх йогурта. Посыпьте рубленой петрушкой и подавайте сразу, пока пита не размокла.","en":"Preheat the oven to 200°C. Toss the pita pieces with a drizzle of oil, spread on a baking tray and bake for 8-10 minutes until golden and crisp. Drain the chickpeas; heat in a small saucepan with a pinch of salt and cumin over medium heat for 3-4 minutes until warmed through. Whisk the yogurt, garlic, tahini, lemon juice, and salt until smooth; taste and adjust seasoning. Spread the toasted pita pieces in an even layer on a large serving platter. Spoon the warm chickpeas evenly over the pita. Pour the yogurt sauce over the chickpeas, covering everything generously. Melt the butter in a small pan over medium heat; add the pine nuts and cook for 2-3 minutes, stirring, until golden; stir in the paprika and immediately drizzle the hot butter and pine nuts over the yogurt. Scatter the chopped parsley on top and serve immediately before the pita softens."}},{"id":84,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ru":"Дания","en":"Denmark","ro":"Danemarca"},"name":{"ru":"Смёрребрёд","en":"Smørrebrød","ro":"Smørrebrød"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ru":["8 ломтиков тёмного датского ржаного хлеба (ругбрёд), около 400 г","100 г несолёного сливочного масла, размягчённого","400 г маринованных филе сельди (8 штук), откинутых на дуршлаг","4 яйца, сваренных вкрутую (10 минут), очищенных и нарезанных кружочками","1 небольшая красная луковица (около 80 г), очень тонко нарезанная кольцами","4 редиски, тонко нарезанные кружочками","2 ст. л. каперсов, откинутых","4 ст. л. сметаны или крем-фреш","1 ч. л. дижонской горчицы","1 небольшой пучок свежего укропа (около 15 г)","1/2 ч. л. мелкой соли"],"en":["8 slices dark rye bread (rugbrød), about 400 g","100 g unsalted butter, softened","400 g pickled herring fillets (8 fillets), drained","4 eggs, hard-boiled (10 minutes), peeled and sliced into rounds","1 small red onion (about 80 g), very finely sliced into rings","4 radishes, thinly sliced into rounds","2 tbsp capers, drained","4 tbsp soured cream or crème fraîche","1 tsp Dijon mustard","1 small bunch fresh dill (about 15 g)","1/2 tsp fine salt"],"ro":["8 felii de pâine daneză de secară (rugbrød), circa 400 g","100 g unt nesărat, înmuiat","400 g hering murat (8 fileuri), scurs","4 ouă fierte tari (10 minute), decojite și feliate în rondele","1 ceapă roșie mică (circa 80 g), feliată subțire în inele","4 ridichi, feliate subțire în rondele","2 linguri capere, scurse","4 linguri smântână sau crème fraîche","1 linguriță muștar Dijon","1 legătură mică de mărar proaspăt (circa 15 g)","1/2 linguriță sare fină"]},"howIsMade":{"ru":"Сварить яйца вкрутую: опустить в кипящую воду и варить 10 минут, затем перенести в холодную воду на 5 минут; очистить и нарезать кружочками. Смешать сметану с дижонской горчицей и щепоткой соли в небольшой миске. Щедро намазать каждый ломтик ржаного хлеба мягким маслом до краёв — примерно 1 столовая ложка на ломтик. Разложить 1-2 ломтика маринованной сельди на каждый намазанный ломтик, позволяя им естественно изогнуться. Добавить небольшую порцию горчичного крема поверх сельди, затем разложить 2-3 кружочка яйца рядом. Посыпать кольцами красного лука, кружочками редиса и каперсами. Украсить веточками свежего укропа и подавать немедленно с холодным пивом или аквавитом.","en":"Hard-boil the eggs: lower into boiling water and cook for 10 minutes, then transfer to cold water for 5 minutes before peeling and slicing into rounds. Mix the soured cream with the Dijon mustard and a pinch of salt in a small bowl. Spread each slice of rye bread generously with softened butter right to the edges — about 1 tablespoon per slice. Lay 1-2 pickled herring fillets on each buttered slice, letting them curve naturally over the surface. Spoon a small dollop of mustard cream onto the herring, then arrange 2-3 egg rounds alongside. Scatter red onion rings, radish slices, and capers over the top. Finish with fresh dill sprigs and serve immediately with a cold beer or aquavit."}},{"id":85,"origin":{"ru":"Северная Корея","en":"North Korea","ro":"Coreea de Nord"},"name":{"ru":"Нэнмён","en":"Naengmyeon","ro":"Naengmyeon"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","timeMins":{"total":600,"active":60},"pairingsType":"korean","ingredients":{"ru":["400г сушёной гречневой лапши (мемиль-гуксу)","300г говяжьей грудинки, варёной до мягкости, охлаждённой и тонко нарезанной","1,5л бульона из говяжьей грудинки, полностью охлаждённого и обезжиренного","1 корейская груша (нashi), очищенная и тонко нарезанная","1 средний огурец, нарезанный соломкой","4 варёных вкрутую яйца, разрезанных пополам","2 ст.л. рисового уксуса","1 ч.л. корейской горчицы (кёджа) или английской горчицы","1 ст.л. кочугару (по желанию, как столовая приправа)","соль и сахар по вкусу для бульона","кубики льда по необходимости"],"en":["400g dried buckwheat noodles (memil-guksu)","300g beef brisket, simmered until tender, chilled, thinly sliced","1.5L beef brisket broth, fully chilled and defatted","1 Korean pear (nashi), peeled, thinly sliced","1 medium cucumber, julienned","4 hard-boiled eggs, halved","2 tbsp rice vinegar","1 tsp Korean mustard (gyeoja) or English mustard","1 tbsp gochugaru (optional, as table condiment)","salt and sugar to taste for the broth","ice cubes as needed"],"ro":["400g tăiței de hrișcă uscați (memil-guksu)","300g piept de vită, fiert și refrigerat, feliat subțire","1.5L supă de piept de vită (răcită complet la frigider, degresată)","1 pară coreeană (nashi), curățată, feliată subțire","1 castravete mediu, feliat julien","4 ouă fierte tari, înjumătățite","2 linguri oțet de orez","1 linguriță muștar coreean (gyeoja) sau muștar englez","1 lingură gochugaru (opțional, pentru condiment la masă)","sare și zahăr după gust pentru supa de bază","cuburi de gheață — câte este necesar"]},"howIsMade":{"ru":"Накануне: тушите грудинку в 2л воды с 1 ч.л. соли, кусочком имбиря 2 см и 3 зелёными луковицами на слабом огне 1,5–2 часа. Дайте мясу остыть в бульоне, затем уберите в холодильник на ночь. На следующий день снимите застывший слой жира. Приправьте холодный бульон рисовым уксусом, сахаром и солью — он должен быть слегка кисловатым и едва сладким. При необходимости охладите льдом. Отварите лапшу по инструкции (3–4 минуты), слейте и сразу промойте под холодной водой 30 секунд, растирая руками. Разложите по глубоким тарелкам, налейте холодный бульон, сверху положите грудинку, грушу, огурец и яйцо. Подавайте сразу с уксусом и горчицей.","en":"Day before: simmer beef brisket in 2L water with 1 tsp salt, a 2 cm piece of ginger, and 3 spring onions over low heat for 1.5–2 hours. Let meat cool in the broth, then refrigerate overnight. Next day, lift off the solidified fat layer. Season the cold broth with rice vinegar, sugar, and salt — it should be lightly tart and subtly sweet. Chill further with ice if needed. Cook noodles per packet (usually 3–4 minutes), drain and immediately rinse under cold running water for 30 seconds, rubbing with hands to remove starch and chill completely. Nest noodles in deep bowls. Ladle cold broth to cover. Top with sliced brisket, pear, julienned cucumber, and halved egg. Serve at once with vinegar and mustard on the side."}},{"id":86,"origin":{"ru":"Пакистан","en":"Pakistan","ro":"Pakistan"},"name":{"ru":"Нихари","en":"Nihari","ro":"Nihari"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"ru":["1 кг говяжьей рульки с костью, нарезанной кусками по 5 см","2 трубчатые кости с мозгом, каждая около 5 см","4 ст. л. гхи или топлёного масла","2 большие луковицы (~300 г), тонко нарезанные","2 ст. л. пасты из имбиря и чеснока","1,5 ч. л. красного острого перца","1 ч. л. молотого кориандра","1/2 ч. л. молотой куркумы","1,5 ч. л. соли","1 ч. л. нихари масала или гарам масала","3 ст. л. муки, смешанной со 100 мл холодной воды","5 см свежего имбиря, очищенного и нарезанного соломкой, для подачи","1 лимон дольками и горсть листьев свежей кинзы, для подачи"],"en":["1 kg bone-in beef shanks, cut into 5 cm pieces","2 marrow bones, each about 5 cm long","4 tbsp ghee or clarified butter","2 large onions (~300 g), thinly sliced","2 tbsp ginger-garlic paste","1.5 tsp red chilli powder","1 tsp ground coriander","1/2 tsp ground turmeric","1.5 tsp salt","1 tsp nihari masala or garam masala","3 tbsp plain flour mixed with 100 ml cold water","5 cm piece of fresh ginger, peeled and julienned, to serve","1 lemon cut into wedges and a handful of fresh coriander leaves, to serve"],"ro":["1 kg rasol de vită cu os, tăiat în bucăți de 5 cm","2 oase cu măduvă, fiecare de aproximativ 5 cm","4 linguri unt clarificat (ghee) sau ulei","2 cepe mari (~300 g), feliate subțire","2 linguri pastă de ghimbir și usturoi","1,5 linguriță praf de ardei iute roșu","1 linguriță coriandru măcinat","1/2 linguriță turmeric măcinat","1,5 linguriță sare","1 linguriță masala nihari sau garam masala","3 linguri făină albă amestecate cu 100 ml apă rece","5 cm ghimbir proaspăt, curățat și juliennat, pentru servire","1 lămâie tăiată în felii și un mănunchi de frunze de coriandru, pentru servire"]},"howIsMade":{"ru":"Разогрейте 3 ст. л. гхи в большой тяжёлой кастрюле на среднем огне и обжарьте лук 12–15 минут, часто помешивая, до глубокого золотистого цвета, затем шумовкой достаньте и отложите. Добавьте оставшееся гхи, увеличьте огонь до сильного и обжарьте куски рульки и мозговые кости порциями по 3–4 минуты с каждой стороны, затем отложите в сторону. Уменьшите огонь до среднего, добавьте пасту из имбиря и чеснока и жарьте 1–2 минуты до аромата, всыпьте перец, кориандр и куркуму и перемешайте 30 секунд. Верните мясо и жареный лук в кастрюлю, добавьте соль и воду так, чтобы она покрывала мясо на 5 см (около 1,2 л), доведите до кипения и снимите пену. Убавьте огонь до минимума, плотно накройте крышкой и томите 3–4 часа, пока мясо не начнёт легко отходить от кости. Добавьте нихари масала, тонкой струйкой влейте мучную болтушку, непрерывно помешивая, и варите без крышки 10–15 минут, пока бульон не загустеет и не покроет ложку. Подавайте в пиалах, украсив имбирной соломкой, кинзой и долькой лимона, с лепёшкой наан или хрустящим хлебом.","en":"Heat 3 tbsp ghee in a large heavy pot over medium-high heat and fry the onions for 12–15 minutes, stirring often, until deep golden brown, then remove with a slotted spoon and set aside. Add the remaining ghee, raise the heat to high, and sear the beef shanks and marrow bones in batches for 3–4 minutes per side until browned, then set aside. Reduce heat to medium, add the ginger-garlic paste and fry for 1–2 minutes until fragrant, then add the chilli powder, coriander, and turmeric and stir for 30 seconds. Return the meat and fried onions to the pot, add the salt and enough water to cover by 5 cm (about 1.2 litres), bring to a boil and skim any foam. Reduce heat to the lowest setting, cover tightly, and simmer for 3–4 hours until the beef is completely tender and falling from the bone. Stir in the nihari masala, pour in the flour slurry in a thin stream while stirring, and simmer uncovered for 10–15 minutes until the broth thickens to a glossy consistency that coats the back of a spoon. Ladle into bowls, top with julienned ginger, coriander leaves, and a squeeze of lemon, and serve with naan or crusty bread."}},{"id":87,"origin":{"ru":"Вьетнам","en":"Vietnam","ro":"Vietnam"},"name":{"ru":"Бун бо Хюэ","en":"Bún bò Huế","ro":"Bún bò Huế"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":195,"active":75},"pairingsType":"vietnamese","ingredients":{"ru":["600 г свиной рульки с костью, нарезанной кусками по 4 см","500 г говяжьих костей, бланшированных","400 г говяжьей рульки, тонко нарезанной","400 г сухой круглой рисовой вермишели (бун)","3 стебля лемонграсса, размятых и нарезанных кусками по 5 см","3 шалота, разрезанных пополам и обжжённых","4 зубчика чеснока, раздавленных","2 ст. л. ферментированной креветочной пасты (мам руок)","3 ст. л. рыбного соуса","2 ст. л. чилийного масла или 1 ч. л. сухих хлопьев чили","1 ч. л. сахара","1 ч. л. соли","для подачи: 200 г ростков сои, свежая зелень (мята, перилла или вьетнамская кинза), 2 лайма дольками и 2 красных чили в кружочках"],"en":["600 g bone-in pork hock, cut into 4 cm pieces","500 g beef bones, blanched","400 g beef shank, thinly sliced","400 g dried round rice vermicelli (bún)","3 lemongrass stalks, bruised and cut into 5 cm pieces","3 shallots, halved and charred","4 garlic cloves, bruised","2 tbsp fermented shrimp paste (mắm ruốc)","3 tbsp fish sauce","2 tbsp chilli oil or 1 tsp dried chilli flakes","1 tsp sugar","1 tsp salt","to serve: 200 g bean sprouts, fresh herbs (mint, perilla or Vietnamese coriander), 2 limes cut into wedges, and 2 red chillies sliced"],"ro":["600 g picior de porc cu os, tăiat în bucăți de 4 cm","500 g oase de vită, opărite","400 g rasol de vită, feliat subțire","400 g tăiței rotunzi de orez uscați (bún)","3 tulpini de lemongrass, zdrobite și tăiate în bucăți de 5 cm","3 șalote, tăiate pe jumătate și pârlite","4 căței de usturoi, zdrobiți","2 linguri pastă de creveți fermentați (mắm ruốc)","3 linguri sos de pește","2 linguri ulei de ardei iute sau 1 linguriță fulgi de ardei iute","1 linguriță zahăr","1 linguriță sare","pentru servit: 200 g muguri de fasole, ierburi proaspete (mentă sau coriandru vietnamez), 2 lămâi verzi în sferturi și 2 ardei iuți roșii felieți"]},"howIsMade":{"ru":"Бланшируйте свиную рульку и говяжьи кости в кипящей воде 5 минут, слейте и промойте холодной водой. Обуглите шалот и чеснок срезом вниз на сухой сковороде на сильном огне 3–4 минуты до лёгкого почернения. Сложите рульку, кости, лемонграсс, обуглённый шалот и чеснок в большую кастрюлю, залейте 2,5 л холодной воды, доведите до кипения, снимите пену, затем варите на слабом огне 1 час. Растворите креветочную пасту в 100 мл горячего бульона, влейте в кастрюлю и добавьте рыбный соус, сахар, соль и чилийное масло, регулируя вкус до насыщенного, слегка острого и ароматного. Добавьте ломтики говяжьей рульки и пашируйте на слабом огне 15–20 минут до полной готовности и мягкости, затем выньте и тонко нарежьте. Отварите рисовую вермишель согласно инструкции (обычно 3–5 минут), слейте воду и распределите по 4 глубоким мискам. Залейте горячим бульоном, разложите поверх ломтики свинины и говядины, сразу подавайте с ростками сои, свежей зеленью, дольками лайма и нарезанным чили.","en":"Blanch the pork hock and beef bones in boiling water for 5 minutes, drain and rinse under cold water. Char the shallots and garlic cut-side down in a dry pan over high heat for 3–4 minutes until lightly blackened. Place the pork hock, bones, lemongrass, charred shallots, and garlic in a large pot, add 2.5 litres of cold water, bring to a boil, skim well, then simmer over low heat for 1 hour. Dissolve the shrimp paste in 100 ml of hot broth, stir into the pot, then add fish sauce, sugar, salt, and chilli oil, adjusting until the broth is savoury, lightly spicy, and fragrant. Add the beef shank slices and poach over gentle heat for 15–20 minutes until just cooked through and tender, then remove and slice thinly. Cook the rice vermicelli according to packet instructions (usually 3–5 minutes), drain, and divide among 4 deep bowls. Ladle the hot broth over the noodles, top with slices of pork hock and beef shank, and serve immediately with bean sprouts, fresh herbs, lime wedges, and sliced chilli on the side."}},{"id":88,"origin":{"ru":"Бразилия","en":"Brazil","ro":"Brazilia"},"name":{"ru":"Мукека","en":"Moqueca","ro":"Moqueca"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"ru":["800 г филе плотной белой рыбы (морской окунь, треска или морской чёрт), нарезанного кусками по 5 см","2 лайма, только сок","1 ч. л. соли","1 большая луковица (~180 г), тонко нарезанная","4 зубчика чеснока, мелко рубленных","1 красный болгарский перец (~150 г), без семян, нарезанный","1 зелёный болгарский перец (~150 г), без семян, нарезанный","2 крупных спелых помидора (~300 г), нарезанных кубиками","400 мл жирного кокосового молока","2 ст. л. красного пальмового масла (дендэ)","20 г свежей кинзы, крупно нарубленной, плюс ещё для подачи","1/2 ч. л. молотого чёрного перца"],"en":["800 g firm white fish fillets (sea bass, cod, or monkfish), cut into 5 cm chunks","2 limes, juice only","1 tsp salt","1 large onion (~180 g), thinly sliced","4 garlic cloves, finely minced","1 red bell pepper (~150 g), deseeded and sliced","1 green bell pepper (~150 g), deseeded and sliced","2 large ripe tomatoes (~300 g), diced","400 ml full-fat coconut milk","2 tbsp dendê (red palm oil)","20 g fresh coriander, roughly chopped, plus extra to serve","1/2 tsp ground black pepper"],"ro":["800 g fileuri de pește alb ferm (biban de mare, cod sau merluciu), tăiate în bucăți de 5 cm","2 lămâi verzi (lime), sucul","1 linguriță sare","1 ceapă mare (~180 g), feliată subțire","4 căței de usturoi, tocați mărunt","1 ardei gras roșu (~150 g), curat și feliat","1 ardei gras verde (~150 g), curat și feliat","2 roșii coapte mari (~300 g), tocate cuburi","400 ml lapte de cocos integral","2 linguri ulei de palmier roșu (dendê)","20 g coriandru proaspăt, tocat grosier, plus extra pentru garnit","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ru":"Перемешайте кусочки рыбы с соком лайма, 1/2 ч. л. соли и чёрным перцем и оставьте мариноваться 15–20 минут, пока готовите овощи. Разогрейте 1 ст. л. масла дендэ в большой широкой сковороде на среднем огне, добавьте лук и жарьте 6–8 минут до мягкости и лёгкого золотистого цвета. Добавьте чеснок, оба перца и помидоры, хорошо перемешайте и тушите 5 минут, пока помидоры не начнут распадаться. Выложите маринованную рыбу поверх овощей в один слой, залейте кокосовым молоком и аккуратно утопите рыбу в жидкости, не перемешивая. Доведите до лёгкого кипения, накройте крышкой и готовьте 12–15 минут, пока рыба не станет непрозрачной и не начнёт легко распадаться. Сбрызните оставшейся ложкой масла дендэ, посыпьте кинзой и отрегулируйте соль. Подавайте прямо со сковороды с белым рисом или хлебом, с дольками лайма.","en":"Toss the fish chunks with the lime juice, 1/2 tsp salt, and the black pepper and leave to marinate for 15–20 minutes while you prepare the vegetables. Heat 1 tbsp dendê oil in a large wide pan over medium heat, add the onion slices, and cook for 6–8 minutes until softened and lightly golden. Add the garlic, bell peppers, and tomatoes, stir well, and cook for 5 minutes until the tomatoes begin to break down. Lay the marinated fish over the vegetables in a single layer, pour the coconut milk over the top, and gently push the fish down into the liquid without stirring. Bring to a gentle simmer, cover, and cook for 12–15 minutes until the fish is opaque and flakes easily when pressed. Drizzle the remaining 1 tbsp dendê oil over the surface, scatter the coriander on top, and taste for salt. Serve directly from the pan with white rice or crusty bread, with lime wedges on the side."}},{"id":89,"origin":{"ru":"Израиль","en":"Israel","ro":"Israel"},"name":{"ru":"Сабих","en":"Sabich","ro":"Sabich"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"def","pairingsType":"middle-eastern","ingredients":{"ru":["4 большие лепёшки пита","1 большой баклажан (~400 г), нарезанный кружочками по 1 см","4 ст. л. масла для жарки","4 яйца","300 г восковых картофелин, отваренных до мягкости и нарезанных кружочками по 1 см","4 ст. л. пасты тахини","1 лимон, только сок","1 зубчик чеснока, давленый","4 ст. л. соуса амба (соус из ферментированного манго)","2 помидора (~200 г), мелко нарезанных","1 огурец (~150 г), мелко нарезанный","1 ч. л. соли","4 кружочка маринованного огурца и свежая петрушка для подачи"],"en":["4 large pita breads","1 large aubergine (~400 g), cut into 1 cm rounds","4 tbsp oil for frying","4 eggs","300 g waxy potatoes, boiled until tender and sliced 1 cm thick","4 tbsp tahini paste","1 lemon, juice only","1 garlic clove, crushed","4 tbsp amba sauce (fermented mango pickle sauce)","2 tomatoes (~200 g), finely diced","1 cucumber (~150 g), finely diced","1 tsp salt","4 slices pickled cucumber and fresh parsley, to serve"],"ro":["4 lipii pita mari","1 vânătă mare (~400 g), tăiată în felii de 1 cm","4 linguri ulei pentru prăjit","4 ouă","300 g cartofi galbeni, fierți până sunt moi și feliați la 1 cm grosime","4 linguri pastă de tahini","1 lămâie, sucul","1 cățel de usturoi, zdrobit","4 linguri sos amba (sos din mango murat)","2 roșii (~200 g), tăiate mărunt","1 castravete (~150 g), tăiat mărunt","1 linguriță sare","4 felii castraveți murați și pătrunjel proaspăt, pentru servire"]},"howIsMade":{"ru":"Отварите яйца вкрутую: опустите в кипящую воду, варите 10 минут, затем остудите в холодной воде 5 минут, очистите и нарежьте кружочками. Посыпьте кружочки баклажана с обеих сторон 1/2 ч. л. соли и оставьте на 10 минут, затем промокните бумажными полотенцами. Разогрейте масло в большой сковороде на среднем огне и жарьте баклажан порциями по 3–4 минуты с каждой стороны до глубокого золотистого цвета и мягкости, затем обсушите на бумаге. Взбейте тахини с соком лимона, чесноком и 3–4 ст. л. холодной воды до кремовой льющейся консистенции. Смешайте нарезанные помидоры и огурец с 1/2 ч. л. соли и каплей оливкового масла. Прогрейте каждую питу по 1 минуте с каждой стороны на сухой сковороде, затем осторожно раскройте карман. Наполните каждую питу жареным баклажаном, кружочками картофеля и яйца, салатом, обильным тахини, ложкой амбы, маринованным огурцом и свежей петрушкой и подавайте сразу.","en":"Hard-boil the eggs: lower into boiling water, cook for 10 minutes, then transfer to cold water for 5 minutes, peel, and slice into rounds. Sprinkle the aubergine slices on both sides with 1/2 tsp salt and leave for 10 minutes, then pat dry with kitchen paper. Heat the oil in a large non-stick pan over medium-high heat and fry the aubergine in batches for 3–4 minutes per side until deep golden and tender throughout, then drain on kitchen paper. Whisk the tahini with the lemon juice, crushed garlic, and 3–4 tbsp cold water until creamy and pourable. Combine the diced tomatoes and cucumber with the remaining 1/2 tsp salt and a drizzle of olive oil. Warm each pita for 1 minute per side in a dry pan, then carefully open the pocket without tearing. Layer each pita with fried aubergine, sliced potato and egg, the tomato-cucumber salad, a generous drizzle of tahini sauce, a spoonful of amba sauce, pickled cucumber, and fresh parsley, and serve immediately."}},{"id":90,"origin":{"ru":"Куба","en":"Cuba","ro":"Cuba"},"name":{"ru":"Ропа Вьеха","en":"Ropa Vieja","ro":"Ropa Vieja"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"ru":["700 г говяжьей пашины или грудинки","2 ст. л. оливкового масла","1 большая луковица (~200 г), тонко нарезанная","1 красный болгарский перец и 1 зелёный болгарский перец (~150 г каждый), без семян, нарезанные","4 зубчика чеснока, мелко рубленных","400 г консервированных измельчённых помидоров","2 ст. л. томатной пасты","100 мл сухого белого вина","1 ч. л. молотого тмина","1 ч. л. сухого орегано","2 лавровых листа","1 ч. л. соли и 1/2 ч. л. молотого чёрного перца"],"en":["700 g beef flank steak or brisket","2 tbsp olive oil","1 large onion (~200 g), thinly sliced","1 red bell pepper and 1 green bell pepper (~150 g each), deseeded and sliced","4 garlic cloves, finely minced","400 g canned crushed tomatoes","2 tbsp tomato paste","100 ml dry white wine","1 tsp ground cumin","1 tsp dried oregano","2 bay leaves","1 tsp salt and 1/2 tsp ground black pepper"],"ro":["700 g antricot sau piept de vită","2 linguri ulei de măsline","1 ceapă mare (~200 g), feliată subțire","1 ardei gras roșu și 1 ardei gras verde (~150 g fiecare), curățați și feliați","4 căței de usturoi, tocați mărunt","400 g roșii zdrobite la conservă","2 linguri pastă de roșii","100 ml vin alb sec","1 linguriță chimion măcinat","1 linguriță oregano uscat","2 foi de dafin","1 linguriță sare și 1/2 linguriță piper negru măcinat"]},"howIsMade":{"ru":"Положите говядину в кастрюлю, залейте холодной подсоленной водой, доведите до кипения, снимите пену, убавьте огонь и варите под крышкой 1,5–2 часа, пока мясо не будет легко разбираться на волокна. Достаньте мясо, отлейте 200 мл бульона и разберите мясо на длинные нити. В широкой сковороде разогрейте масло на среднем огне, добавьте лук и оба вида перца и жарьте 8–10 минут до мягкости и лёгкого золотистого цвета. Добавьте чеснок, тмин и орегано, перемешайте 1 минуту, влейте вино и выпаривайте 2 минуты вдвое. Добавьте измельчённые помидоры, томатную пасту, отложенный бульон и лавровые листья, посолите и поперчите и тушите 10 минут до лёгкого загустения. Добавьте разобранное мясо, перемешайте и тушите ещё 10–15 минут, пока мясо не пропитается соусом. Уберите лавровые листья и подавайте с белым рисом и жареными бананами.","en":"Place the beef in a pot, cover with cold salted water, bring to a boil, skim, reduce heat, and simmer covered for 1.5–2 hours until the meat pulls apart easily. Remove the beef, reserve 200 ml of the cooking liquid, and shred the meat into long strips. Heat the oil in a wide heavy pan over medium heat, add the onion and both bell peppers, and cook for 8–10 minutes until softened and beginning to colour. Add the garlic, cumin, and oregano and stir for 1 minute, then pour in the white wine and cook for 2 minutes until reduced by half. Stir in the crushed tomatoes, tomato paste, reserved cooking liquid, and bay leaves, season with salt and pepper, and simmer for 10 minutes until the sauce thickens slightly. Add the shredded beef, stir to combine, and simmer for 10–15 minutes more until the beef absorbs the sauce and the mixture is juicy but not soupy. Remove the bay leaves and serve with white rice and fried plantains."}},{"id":91,"origin":{"ru":"Шотландия","en":"Scotland","ro":"Scoția"},"name":{"ru":"Каллен Скинк","en":"Cullen Skink","ro":"Cullen Skink"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ru":["600 г копчёных филе пикши (желательно без красителей)","700 мл цельного молока","500 г рассыпчатого картофеля, очищенного и нарезанного кубиками по 2 см","1 большая луковица (~200 г), мелко нарезанная","2 ст. л. несолёного сливочного масла","2 лавровых листа","100 мл жирных сливок","10 г свежей петрушки, мелко рубленной","1/2 ч. л. белого перца","1/2 ч. л. соли"],"en":["600 g undyed smoked haddock fillets","700 ml whole milk","500 g floury potatoes (such as Maris Piper), peeled and cut into 2 cm cubes","1 large onion (~200 g), finely diced","2 tbsp unsalted butter","2 bay leaves","100 ml double cream","10 g fresh parsley, finely chopped","1/2 tsp white pepper","1/2 tsp salt"],"ro":["600 g fileuri de eglefin afumat (de preferință necolorat)","700 ml lapte integral","500 g cartofi făinoși, curățați și tăiați cuburi de 2 cm","1 ceapă mare (~200 g), tăiată mărunt","2 linguri unt fără sare","2 foi de dafin","100 ml frișcă grasă","10 g pătrunjel proaspăt, tocat mărunt","1/2 linguriță piper alb","1/2 linguriță sare"]},"howIsMade":{"ru":"Выложите филе пикши кожей вниз в широкую кастрюлю, залейте молоком, добавьте лавровые листья и доведите до лёгкого кипения на среднем огне; пашируйте 8–10 минут, пока рыба не станет непрозрачной и не начнёт расслаиваться в самом толстом месте. Достаньте рыбу шумовкой, удалите кожу и кости, разберите мясо на крупные куски и процедите молоко через сито. В той же кастрюле растопите масло, добавьте лук и готовьте 8–10 минут, периодически помешивая, до полной мягкости без подрумянивания. Добавьте картофельные кубики и процеженное молоко, доведите до лёгкого кипения, накройте неплотно и варите 15–18 минут, пока картофель не станет полностью мягким. Грубо разомните около трети картофеля обратной стороной ложки, чтобы загустить суп. Влейте сливки, верните разобранную пикшу и прогрейте 2–3 минуты на слабом огне; посолите и поперчите белым перцем с осторожностью, так как рыба уже солёная. Разлейте по подогретым тарелкам, посыпьте петрушкой и подавайте с хрустящим хлебом.","en":"Place the smoked haddock skin-side down in a wide pan, pour over the milk, add the bay leaves, and bring to a gentle simmer over medium heat; poach for 8–10 minutes until the fish is just opaque and flakes at the thickest part. Lift the fish out with a slotted spoon, remove the skin and any bones, break the flesh into large flakes, and strain the poaching milk through a sieve into a jug. Melt the butter in the same pan over medium heat, add the diced onion, and cook for 8–10 minutes, stirring occasionally, until completely soft but not coloured. Add the potato cubes and the strained milk, bring to a simmer, cover loosely, and cook for 15–18 minutes until the potatoes are completely tender when pierced with a knife. Lightly mash about one-third of the potatoes against the side of the pan with the back of a spoon to thicken the soup, leaving the rest in chunks. Stir in the double cream, return the flaked haddock to the pan, and simmer gently for 2–3 minutes until just heated through; season with white pepper and salt, tasting carefully as the haddock is already salty. Ladle into warmed bowls, scatter with chopped parsley, and serve with crusty bread."}},{"id":92,"origin":{"ru":"Индонезия","en":"Indonesia","ro":"Indonezia"},"name":{"ru":"Гадо-Гадо","en":"Gado-Gado","ro":"Gado-Gado"},"category":{"ru":"Салат","en":"Salad","ro":"Salată"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ru":["400 г твёрдого тофу, отжатого и нарезанного кубиками по 2 см","150 г темпе, нарезанного кубиками по 2 см","4 крупных яйца","300 г картофеля с плотной мякотью, очищенного и нарезанного на четвертинки","200 г стручковой фасоли, с обрезанными концами","200 г белокочанной капусты, тонко нашинкованной","150 г соевых ростков","1 огурец (~200 г), нарезанный полукольцами","3 ст. л. растительного масла","200 г однородного арахисового масла","200 мл кокосового молока","2 ст. л. kecap manis (сладкий соевый соус)","2 ст. л. тамариндовой пасты, растворённой в 4 ст. л. тёплой воды","1 ч. л. пальмового сахара или мягкого коричневого сахара","2 зубчика чеснока, мелко натёртых","1/2 ч. л. хлопьев чили","1/2 ч. л. соли","креветочные чипсы (крупук) и дольки лайма для подачи"],"en":["400 g firm tofu, pressed and cut into 2 cm cubes","150 g tempeh, cut into 2 cm cubes","4 large eggs","300 g waxy potatoes, peeled and quartered","200 g green beans, trimmed","200 g white cabbage, thinly shredded","150 g bean sprouts","1 cucumber (~200 g), sliced into half-moons","3 tbsp vegetable oil","200 g smooth peanut butter","200 ml coconut milk","2 tbsp kecap manis (sweet soy sauce)","2 tbsp tamarind paste dissolved in 4 tbsp warm water","1 tsp palm sugar or soft brown sugar","2 garlic cloves, finely grated","1/2 tsp chilli flakes","1/2 tsp salt","prawn crackers (krupuk) and lime wedges to serve"],"ro":["400 g tofu ferm, presat și tăiat în cuburi de 2 cm","150 g tempeh, tăiat în cuburi de 2 cm","4 ouă mari","300 g cartofi cu coajă crocantă, curățați și tăiați în sferturi","200 g fasole verde, curățată de capete","200 g varză albă, feliată subțire","150 g germeni de soia","1 castravete (~200 g), tăiat în felii semilună","3 linguri ulei vegetal","200 g unt de arahide cremos","200 ml lapte de cocos","2 linguri kecap manis (sos de soia dulce)","2 linguri pastă de tamarind dizolvată în 4 linguri apă caldă","1 linguriță zahăr de palmier sau zahăr brun","2 căței de usturoi, rași fin","1/2 linguriță fulgi de ardei iute","1/2 linguriță sare","chipsuri de creveți (krupuk) și felii de lămâie verde pentru servit"]},"howIsMade":{"ru":"Сварите яйца вкрутую в слабо кипящей воде 9 минут, переложите в миску с ледяной водой, затем очистите и разрежьте пополам, когда остынут. Отварите картофель в хорошо подсоленной кипящей воде 12–15 минут до мягкости при прокалывании; достаньте шумовкой, затем бланшируйте стручковую фасоль в той же воде 3 минуты до ярко-зелёного цвета и лёгкой хрусткости, слейте. Залейте нашинкованную капусту кипятком в дуршлаге, считайте 30 секунд, отожмите лишнюю воду. Разогрейте масло на сковороде с антипригарным покрытием на среднем-сильном огне и обжарьте кубики тофу 3–4 минуты с каждой стороны до золотистой корочки; уберите, затем обжарьте темпе на той же сковороде 2–3 минуты с каждой стороны до насыщенно-золотистого цвета. Смешайте арахисовое масло, кокосовое молоко, kecap manis, тамариндовую воду, пальмовый сахар, тёртый чеснок и хлопья чили в маленьком ковшике; готовьте на слабом огне, постоянно помешивая, 5–7 минут до однородного и достаточно густого соуса — разбавьте водой при необходимости. Разложите капусту, картофель, фасоль, ростки и огурец на большом блюде; сверху выложите тофу, темпе и половинки яиц. Полейте тёплым арахисовым соусом и подайте с креветочными чипсами и дольками лайма.","en":"Hard-boil the eggs in simmering water for 9 minutes, transfer to a bowl of ice water, then peel and halve when cool. Cook the potatoes in well-salted boiling water for 12–15 minutes until just tender when pierced; lift out with a slotted spoon and drain, then blanch the green beans in the same water for 3 minutes until bright green and still with some bite, and drain. Blanch the shredded cabbage by pouring boiling water over it in a colander, count 30 seconds, then press out excess water. Heat the oil in a non-stick frying pan over medium-high heat and fry the tofu cubes for 3–4 minutes per side until golden and crisp; remove, then fry the tempeh in the same pan for 2–3 minutes per side until deep golden. Combine the peanut butter, coconut milk, kecap manis, tamarind water, palm sugar, grated garlic, and chilli flakes in a small saucepan; cook over low heat, stirring constantly, for 5–7 minutes until smooth and thick enough to coat the back of a spoon — thin with a splash of water if needed. Arrange the cabbage, potatoes, green beans, bean sprouts, and cucumber slices on a large platter or individual plates; place the tofu, tempeh, and egg halves on top. Pour the warm peanut sauce over everything, and serve with prawn crackers and lime wedges on the side."}},{"id":93,"origin":{"ru":"Швеция","en":"Sweden","ro":"Suedia"},"name":{"ru":"Булочка с корицей","en":"Cinnamon Bun","ro":"Kanelbulle"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"servings":12,"tipType":"dessert","pairingsType":"dessert","ingredients":{"ru":["500 г пшеничной муки высшего сорта, плюс немного для подпыла","250 мл цельного молока","7 г сухих быстродействующих дрожжей (1 пакетик)","10 г сахарного песка (для теста)","1 крупное яйцо","100 г сливочного масла без соли, размягчённого","1 ч. л. молотого кардамона","1/2 ч. л. соли","75 г сливочного масла без соли, размягчённого (начинка)","75 г сахарного песка (начинка)","1 ст. л. молотой корицы","1 ч. л. молотого кардамона (начинка)","1 яйцо, взбитое (для смазки)","2 ст. л. жемчужного сахара"],"en":["500 g plain flour, plus extra for dusting","250 ml whole milk","7 g fast-action dried yeast (1 sachet)","10 g caster sugar (for dough)","1 large egg","100 g unsalted butter, softened","1 tsp ground cardamom","1/2 tsp salt","75 g unsalted butter, softened (filling)","75 g caster sugar (filling)","1 tbsp ground cinnamon","1 tsp ground cardamom (filling)","1 egg, beaten (for egg wash)","2 tbsp pearl sugar"],"ro":["500 g făină albă, plus extra pentru presărat","250 ml lapte integral","7 g drojdie uscată instant (1 plic)","10 g zahăr tos (pentru aluat)","1 ou mare","100 g unt nesărat, la temperatura camerei","1 linguriță cardamom măcinat","1/2 linguriță sare","75 g unt nesărat, la temperatura camerei (umplutură)","75 g zahăr tos (umplutură)","1 lingură scorțișoară măcinată","1 linguriță cardamom măcinat (umplutură)","1 ou bătut (pentru uns)","2 linguri zahăr perle"]},"howIsMade":{"ru":"Нагрейте молоко до 37°C, растворите дрожжи и 10 г сахара и оставьте на 5–10 минут до появления пузырьков. Смешайте муку, кардамон и соль в большой миске; сделайте углубление, влейте дрожжевую смесь и яйцо, замесите грубое тесто. Добавляйте 100 г размягчённого масла по кусочку и вымешивайте на слегка посыпанной мукой поверхности 8–10 минут, пока тесто не станет гладким, эластичным и не прилипает к рукам; накройте и оставьте в тёплом месте на 60–90 минут до увеличения вдвое. Смешайте 75 г масла, 75 г сахара, корицу и вторую чайную ложку кардамона в начинку. Раскатайте поднявшееся тесто на слегка посыпанной мукой поверхности в прямоугольник 40×50 см; равномерно распределите начинку, сложите тесто втрое по длине, раскатайте снова и нарежьте на 12 полосок. Каждую полоску скрутите и сверните узлом, подворачивая конец под низ; выложите на застеленные противни с расстоянием, слегка накройте и оставьте расстаиваться 30–45 минут до заметного подъёма, разогревая духовку до 200°C (конвекция 180°C). Смажьте взбитым яйцом, посыпьте жемчужным сахаром и выпекайте 12–15 минут до насыщенного золотистого цвета; переложите на решётку и накройте кухонным полотенцем.","en":"Warm the milk to 37°C, stir in the yeast and the 10 g of caster sugar, and leave for 5–10 minutes until frothy. Combine the flour, cardamom, and salt in a large bowl; make a well, pour in the yeast mixture and beaten egg, then bring together into a rough dough. Add the 100 g of softened butter a piece at a time and knead on a lightly floured surface for 8–10 minutes until the dough is smooth, elastic, and no longer sticks to your hands; cover and leave in a warm place for 60–90 minutes until doubled in size. Beat together the 75 g of butter, 75 g of caster sugar, cinnamon, and the second teaspoon of cardamom until smooth for the filling. Turn the risen dough onto a lightly floured surface and roll into a 40×50 cm rectangle; spread the filling evenly, fold the dough lengthways into thirds, roll again, and cut into 12 strips. Twist each strip and coil into a knot, tucking the end underneath, then space on lined baking trays; cover loosely and prove 30–45 minutes until noticeably puffed, while preheating the oven to 200°C (fan 180°C). Brush with beaten egg, scatter with pearl sugar, and bake for 12–15 minutes until deep golden brown; transfer to a wire rack and cover with a tea towel to keep them soft."}},{"id":94,"origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Чили эн ногада","en":"Chiles en nogada","ro":"Chiles en nogada"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"ru":["4 крупных перца поблано (~700 г)","400 г свиного фарша","2 ст. л. оливкового масла или сала","1 средняя луковица (~150 г), мелко нарезанная","3 зубчика чеснока, измельчённых","2 спелых помидора (~300 г), очищенных и нарезанных","50 г изюма","50 г бланшированного миндаля, крупно рубленного","1 спелый персик или груша (~150 г), очищенные и нарезанные кубиками","1 ч. л. молотой корицы, 1/2 ч. л. молотой гвоздики, 1 ч. л. соли, 1/2 ч. л. чёрного перца","150 г половинок грецких орехов, замоченных на 30 минут в тёплом молоке и слитых","150 г сливочного сыра, мягкого","100 мл сметаны","зёрна 1 граната (~100 г)","горсть свежих листьев плосколистной петрушки"],"en":["4 large poblano chiles (~700 g total)","400 g ground pork","2 tbsp olive oil or lard","1 medium onion (~150 g), finely diced","3 garlic cloves, minced","2 ripe tomatoes (~300 g), peeled and diced","50 g raisins","50 g blanched almonds, roughly chopped","1 ripe peach or pear (~150 g), peeled and diced","1 tsp ground cinnamon, 1/2 tsp ground cloves, 1 tsp salt, 1/2 tsp black pepper","150 g walnut halves, soaked in warm milk 30 minutes then drained","150 g cream cheese, softened","100 ml soured cream","seeds of 1 pomegranate (~100 g)","small handful of fresh flat-leaf parsley leaves"],"ro":["4 ardei poblano mari (~700 g total)","400 g carne de porc tocată","2 linguri ulei de măsline sau untură","1 ceapă medie (~150 g), tăiată mărunt","3 căței de usturoi, tocați","2 roșii coapte (~300 g), curățate de coajă și tocate","50 g stafide","50 g migdale decojite, tocate grosier","1 piersică sau pară coaptă (~150 g), curățată și tăiată cubulețe","1 linguriță scorțișoară, 1/2 linguriță cuișoare, 1 linguriță sare, 1/2 linguriță piper negru","150 g miez de nucă, înmuiat 30 minute în lapte cald și scurs","150 g cremă de brânză, la temperatura camerei","100 ml smântână fermentată","semințele unui rodiu (~100 g)","o mână de frunze de pătrunjel plat proaspăt"]},"howIsMade":{"ru":"Обожгите перцы поблано над открытым огнём или под горячим грилем 8–10 минут, переворачивая щипцами, пока кожица не обуглится со всех сторон; переложите в закрытую миску на 10 минут, затем сотрите кожицу, сделайте продольный разрез и удалите семена и прожилки маленькой ложкой, сохранив перцы целыми. Разогрейте масло в широкой сковороде на среднем огне, добавьте лук и готовьте 5–6 минут до полной мягкости; добавьте чеснок и готовьте 1 минуту. Добавьте свиной фарш и обжаривайте 8 минут, разбивая, пока не исчезнет розовый цвет; добавьте помидоры и готовьте 5 минут до их распада. Добавьте изюм, миндаль, персик, корицу, гвоздику, соль и перец; готовьте 5 минут до мягкости фруктов и относительной сухости массы, снимите с огня и остудите. Слейте орехи и взбейте с творожным сыром и сметаной до полной однородности; приправьте щепоткой соли. Плотно начините каждый перец остывшей мясной начинкой, слегка прижимая разрез; разложите по тарелкам. Обильно полейте ореховым соусом, посыпьте зёрнами граната и листьями петрушки и подайте при комнатной температуре.","en":"Char the poblano chiles over an open gas flame or under a hot grill for 8–10 minutes, turning with tongs until the skin is completely blackened on all sides; place in a covered bowl for 10 minutes, then rub off the skin, make a single lengthways slit, and remove the seeds and veins with a small spoon while keeping each chile intact. Heat the oil in a wide frying pan over medium heat, add the onion, and cook for 5–6 minutes until completely soft; add the garlic and cook 1 minute more until fragrant. Add the ground pork and cook, breaking it up with a wooden spoon, for 8 minutes until no pink remains; add the diced tomatoes and cook for 5 minutes until they collapse and the liquid reduces. Stir in the raisins, almonds, peach, cinnamon, cloves, salt, and pepper; cook for 5 minutes until the fruit softens and the mixture is fairly dry, then remove from heat and cool to room temperature. Drain the soaked walnuts and blend with the cream cheese and soured cream until completely smooth; season with a pinch of salt — the nogada should be thick enough to coat a spoon. Stuff each poblano firmly with the cooled meat filling, pressing gently to close the slit; arrange on individual plates or a large serving dish. Spoon the walnut sauce generously over each chile, scatter pomegranate seeds and parsley leaves on top, and serve at room temperature."}},{"id":95,"origin":{"ru":"Ливан","en":"Lebanon","ro":"Liban"},"name":{"ru":"Чечевичный суп","en":"Lentil Soup","ro":"Supă de linte"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"ru":["300 г красной чечевицы, промытой до прозрачной воды","2 ст. л. оливкового масла","1 крупная луковица (~200 г), мелко нарезанная","2 средние моркови (~200 г), очищенные и нарезанные кубиками","3 зубчика чеснока, измельчённых","2 ч. л. молотого тмина","1 ч. л. молотого кориандра","1/2 ч. л. куркумы","1/4 ч. л. кайенского перца","1,2 л овощного или куриного бульона","сок 1 лимона","2 ст. л. сливочного масла (для подачи)","1 ч. л. сладкой паприки (для подачи)","соль и чёрный перец по вкусу","свежая кинза или петрушка и дольки лимона для подачи"],"en":["300 g red lentils, rinsed until water runs clear","2 tbsp olive oil","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), peeled and diced","3 garlic cloves, minced","2 tsp ground cumin","1 tsp ground coriander","1/2 tsp ground turmeric","1/4 tsp cayenne pepper","1.2 litres vegetable or chicken stock","juice of 1 lemon","2 tbsp unsalted butter (for topping)","1 tsp sweet paprika (for topping)","salt and black pepper to taste","fresh coriander or parsley and lemon wedges to serve"],"ro":["300 g linte roșie, clătită până apa devine limpede","2 linguri ulei de măsline","1 ceapă mare (~200 g), tăiată mărunt","2 morcovi medii (~200 g), curățați și tăiați cubulețe","3 căței de usturoi, tocați","2 lingurițe chimen măcinat","1 linguriță coriandru măcinat","1/2 linguriță turmeric","1/4 linguriță ardei cayenne","1,2 litri supă de legume sau pui","sucul de la 1 lămâie","2 linguri unt nesărat (pentru topping)","1 linguriță paprika dulce (pentru topping)","sare și piper negru după gust","coriandru proaspăt sau pătrunjel, felii de lămâie pentru servit"]},"howIsMade":{"ru":"Разогрейте оливковое масло в большой кастрюле на среднем огне, добавьте лук и морковь и готовьте 8–10 минут, периодически помешивая, пока овощи не станут мягкими и лук прозрачным. Добавьте чеснок, тмин, кориандр, куркуму и кайенский перец; помешивайте 1–2 минуты до появления аромата. Добавьте промытую чечевицу и бульон, доведите до кипения, уменьшите огонь, частично накройте крышкой и варите 20–25 минут, пока чечевица полностью не станет мягкой и не начнёт разваливаться. Пробейте примерно половину супа погружным блендером для кремовой текстуры с кусочками — или весь суп для полностью однородного; разбавьте бульоном при необходимости. Добавьте лимонный сок и щедро приправьте солью и чёрным перцем. Растопите масло в маленькой сковороде на среднем огне, добавьте паприку и дайте шипеть 30 секунд до аромата. Разлейте горячий суп по подогретым тарелкам, полейте масляной заправкой с паприкой, посыпьте свежей кинзой и подайте с дольками лимона и хрустящим хлебом.","en":"Heat the olive oil in a large saucepan over medium heat, add the onion and carrots, and cook for 8–10 minutes, stirring occasionally, until softened and the onion is translucent. Add the garlic, cumin, coriander, turmeric, and cayenne; stir for 1–2 minutes until the spices are fragrant and toasted. Add the rinsed lentils and stock, bring to a boil, then reduce the heat, partially cover, and simmer for 20–25 minutes until the lentils are completely tender and beginning to dissolve into the liquid. Use an immersion blender to puree about half the soup directly in the pot for a creamy yet textured finish — or blend it all smooth if you prefer; thin with a splash of extra stock or water if needed. Stir in the lemon juice and season generously with salt and black pepper. Melt the butter in a small pan over medium heat, add the sweet paprika, and let it sizzle for 30 seconds until fragrant and deep red. Ladle the hot soup into warmed bowls, drizzle the paprika butter over each portion, scatter fresh coriander on top, and serve with lemon wedges and crusty bread."}},{"id":96,"origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Спанакопита","en":"Spanakopita","ro":"Spanakopita"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"servings":6,"tipType":"veg","pairingsType":"veg","ingredients":{"ru":["500г теста фило, размороженного если из морозильника","1кг свежего шпината, промытого (или 600г замороженного, размороженного и хорошо отжатого)","300г сыра фета, раскрошенного","2 средние луковицы, мелко нарезанные","4 пера зелёного лука, тонко нарезанных","3 крупных яйца, взбитых","30г свежего укропа, мелко нарезанного","20г свежей петрушки, мелко нарезанной","150мл оливкового масла extra virgin","100г тёртого кефалотири или пекорино (по желанию)","1/2 ч. л. свежемолотого мускатного ореха","соль и свежемолотый чёрный перец по вкусу"],"en":["500g phyllo pastry, thawed if frozen","1kg fresh spinach, washed (or 600g frozen spinach, thawed and squeezed dry)","300g feta cheese, crumbled","2 medium onions, finely chopped","4 spring onions, finely sliced","3 large eggs, beaten","30g fresh dill, chopped","20g fresh parsley, chopped","150ml extra virgin olive oil","100g grated kefalotyri or pecorino (optional)","1/2 tsp freshly grated nutmeg","salt and freshly ground black pepper to taste"],"ro":["500g foi de plăcintă (phyllo), decongelate dacă sunt din congelator","1kg spanac proaspăt, spălat (sau 600g spanac congelat, decongelat și stors bine)","300g brânză feta, sfărâmată","2 cepe medii, tocate fin","4 cepe verzi, tăiate fin","3 ouă mari, bătute","30g mărar proaspăt, tocat","20g pătrunjel proaspăt, tocat","150ml ulei de măsline extravirgin","100g kefalotyri sau pecorino, ras (opțional)","1/2 linguriță nucșoară proaspăt rasă","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"ru":"Разогрейте духовку до 180°C (с конвекцией 160°C); промойте 1кг шпината и припустите его в большой кастрюле на среднем огне 4–5 минут, пока он не осядет; откиньте на дуршлаг, отожмите тыльной стороной ложки, затем выжмите небольшими порциями между бумажными полотенцами. Разогрейте 3 ст; л; оливкового масла в сковороде и обжарьте нарезанный лук на среднем огне 8 минут, пока он не станет мягким и прозрачным; добавьте зелёный лук и готовьте ещё 2 минуты. В большой миске соедините отжатый шпинат, луковую смесь, 300г раскрошенной феты, тёртый кефалотири (если используете), 3 взбитых яйца, укроп, петрушку, мускатный орех, соль и перец; перемешайте аккуратно — если месить слишком долго, шпинат снова даст влагу. Смажьте форму 25×35 см оливковым маслом; уложите один лист фило, смажьте маслом, положите сверху второй; продолжайте, пока не наберёте 8 слоёв в качестве основы; неиспользованные листы держите под слегка влажным полотенцем. Равномерно распределите начинку по основе из фило; накройте ещё 8 листами фило, обильно смазывая маслом каждый слой. Подверните края внутрь; острым ножом наметьте верх на 6–8 порций, разрезая только верхние слои — это убережёт пирог от крошения при подаче; брызните сверху несколько капель воды, чтобы тесто не закручивалось. Выпекайте 40–45 минут, пока верх не станет тёмно-золотистым, а тесто не зазвучит хрустяще при лёгком постукивании; дайте отдохнуть 15 минут и разрежьте по намеченным линиям.","en":"Preheat the oven to 180°C (fan 160°C); wash 1kg of spinach and wilt it in a large pot over medium heat for 4–5 minutes, until just collapsed; tip into a colander and press out as much water as possible, then squeeze handfuls dry between paper towels. Warm 3 tablespoons of olive oil in a pan and cook the chopped onions over medium heat for 8 minutes, until soft and translucent; add the spring onions and cook 2 more minutes. In a large bowl, combine the squeezed spinach, the onion mixture, 300g crumbled feta, the kefalotyri if using, 3 beaten eggs, dill, parsley, nutmeg, salt and pepper; mix gently — do not overwork or the spinach will release more water. Brush a 25×35 cm baking dish with olive oil; lay one sheet of phyllo, brush with olive oil, and top with another sheet; continue until you have 8 layers as the base; keep unused phyllo covered with a slightly damp cloth. Spread the filling evenly over the phyllo base; top with 8 more sheets of phyllo, brushing each layer generously with olive oil. Tuck the edges in; with a sharp knife, score the top into 6–8 portions, cutting only through the top layers — this prevents shattering when serving; sprinkle a few drops of water on top to stop the pastry curling. Bake for 40–45 minutes, until the top is deep golden brown and the pastry sounds crisp when tapped; rest 15 minutes before cutting along the scored lines."},"timeMins":{"total":90,"active":40}},{"id":97,"origin":{"ru":"Нигерия","en":"Nigeria","ro":"Nigeria"},"name":{"ru":"Джоллоф-рис","en":"Jollof Rice","ro":"Jollof Rice"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"def","ingredients":{"ru":["400г длиннозёрного парбоилд риса (или басмати), промытого до прозрачной воды","6 спелых помидоров Рома, крупно нарезанных (или 400г резаных томатов в банке)","2 крупных красных болгарских перца, без семян, крупно нарезанных","1 перец чили скотч-боннет или красный чили, без семян","2 крупные луковицы (1 в блендер, 1 нарезанная кольцами)","4 зубчика чеснока, очищенных","30г свежего имбиря, очищенного","3 ст. л. томатной пасты","120мл растительного масла (традиционно арахисового)","750мл горячего куриного или овощного бульона","2 лавровых листа","1 ч. л. карри-порошка","1 ч. л. сушёного тимьяна","1 ч. л. копчёной паприки","соль и свежемолотый чёрный перец по вкусу"],"en":["400g long-grain parboiled rice (or basmati), rinsed until water runs clear","6 ripe Roma tomatoes, roughly chopped (or 400g canned chopped tomatoes)","2 large red bell peppers, deseeded and roughly chopped","1 scotch bonnet or red chilli, deseeded","2 large onions (1 blended, 1 sliced)","4 garlic cloves, peeled","30g fresh ginger, peeled","3 tbsp tomato paste","120ml vegetable oil (groundnut oil is traditional)","750ml hot chicken or vegetable stock","2 bay leaves","1 tsp curry powder","1 tsp dried thyme","1 tsp smoked paprika","salt and freshly ground black pepper to taste"],"ro":["400g orez cu bob lung parboiled (sau basmati), spălat până apa rămâne limpede","6 roșii Roma coapte, tăiate grosier (sau 400g roșii din conservă)","2 ardei kapia roșii mari, fără semințe și tăiați grosier","1 ardei scotch bonnet sau ardei iute roșu, fără semințe","2 cepe mari (una mixată, una feliată)","4 căței de usturoi, curățați","30g ghimbir proaspăt, curățat","3 linguri pastă de roșii","120ml ulei vegetal (tradițional, ulei de arahide)","750ml supă fierbinte de pui sau legume","2 foi de dafin","1 linguriță pudră de curry","1 linguriță cimbru uscat","1 linguriță boia afumată","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"ru":"Промойте 400г риса под холодной водой до прозрачной воды и слейте — это удалит лишний крахмал и сохранит зёрна рассыпчатыми. В блендере измельчите помидоры, болгарские перцы, чили, одну луковицу, чеснок и имбирь в однородное пюре. Разогрейте 120мл масла в кастрюле с толстым дном на среднем огне; добавьте нарезанный лук и обжаривайте 5–6 минут до лёгкой золотистости. Вмешайте 3 ст; л; томатной пасты и готовьте 3 минуты, пока она не потемнеет и не уйдёт сырой запах. Влейте перцово-томатное пюре, добавьте лавровый лист, карри, тимьян и копчёную паприку; готовьте без крышки на среднем огне 18–20 минут, часто помешивая, пока соус не уварится, не приобретёт тёмно-красный цвет и масло не выступит на поверхность — это критический этап. Добавьте промытый рис и перемешайте так, чтобы каждое зерно было покрыто соусом; влейте 750мл горячего бульона, посолите, поперчите и доведите до кипения. Уменьшите огонь до минимума, плотно закройте крышкой (для аутентичного результата сначала закройте обод фольгой, затем крышкой) и готовьте, не открывая, 25–30 минут, пока рис не станет мягким, а жидкость не впитается. Выключите огонь и оставьте под крышкой ещё на 10 минут; аккуратно взрыхлите вилкой — нижний слой должен иметь лёгкую дымную корочку; подавайте с жареным платаном, курицей-гриль или простым салатом.","en":"Rinse 400g of rice in cold water until the water runs clear, then drain — this removes excess starch and keeps the grains separate. Blend the tomatoes, red bell peppers, chilli, one onion, garlic and ginger to a smooth paste in a blender. Heat 120ml oil in a heavy-bottomed pot over medium heat; add the sliced onion and fry for 5–6 minutes, until lightly golden. Stir in 3 tablespoons of tomato paste and cook for 3 minutes, until darkened and the raw aroma is gone. Pour in the blended pepper mixture, add the bay leaves, curry powder, thyme and smoked paprika; cook uncovered over medium heat for 18–20 minutes, stirring often, until the sauce reduces, deepens to a dark red and the oil rises to the surface — this is the critical step. Add the rinsed rice and stir until every grain is coated in sauce; pour in 750ml hot stock, season with salt and pepper, and bring back to a boil. Reduce the heat to the lowest setting, cover the pot tightly (seal the rim with foil before placing the lid for an authentic finish), and cook undisturbed for 25–30 minutes, until the rice is tender and the liquid is absorbed. Turn off the heat and leave covered for 10 more minutes; fluff gently with a fork — the bottom layer should have a slight smoky crust; serve with fried plantain, grilled chicken, or a simple salad."}},{"id":98,"origin":{"ru":"Самоа","en":"Samoa","ro":"Samoa"},"name":{"ru":"Ока и'а","en":"Oka i'a","ro":"Oka i'a"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ru":["500г тунца или махи-махи качества сашими, без кожи и костей, нарезанные кубиками 1,5 см","120мл свежевыжатого сока лайма (примерно 6 лаймов)","200мл жирного кокосового молока (свежевскрытого или из банки)","1 средний огурец, очищенный, без семян, мелко нарезанный кубиками","1 небольшая красная луковица, мелко нарезанная кубиками","2 спелых помидора, без семян, нарезанные кубиками","1 небольшой красный чили, мелко нарезанный (по желанию)","1 зелёный лук, тонко нарезанный","1 ч. л. мелкой морской соли","свежемолотый чёрный перец","листья свежей кинзы для подачи"],"en":["500g sashimi-grade tuna or mahi-mahi, skinned and boned, cut into 1.5 cm cubes","120ml fresh lime juice (about 6 limes)","200ml full-fat coconut milk (freshly opened or canned)","1 medium cucumber, peeled, deseeded, and finely diced","1 small red onion, finely diced","2 ripe tomatoes, deseeded and diced","1 small red chilli, finely chopped (optional)","1 spring onion, finely sliced","1 tsp fine sea salt","freshly ground black pepper","fresh coriander leaves, to garnish"],"ro":["500g ton sau mahi-mahi de calitate sashimi, fără piele și oase, tăiat cuburi de 1,5 cm","120ml suc proaspăt de lime (aproximativ 6 lime)","200ml lapte de cocos integral (proaspăt deschis sau din conservă)","1 castravete mediu, curățat, fără semințe, tăiat cuburi mici","1 ceapă roșie mică, tăiată cuburi mici","2 roșii coapte, fără semințe, tăiate cuburi","1 ardei iute roșu mic, tocat fin (opțional)","1 ceapă verde, tăiată fin","1 linguriță sare fină de mare","piper negru proaspăt măcinat","frunze de coriandru proaspăt, pentru ornat"]},"howIsMade":{"ru":"Положите кубики рыбы в инертную миску (стекло или керамика); полейте 120мл свежевыжатого сока лайма и перемешайте, чтобы каждый кусочек был покрыт; поставьте в холодильник на 15–20 минут — поверхность должна стать матовой, а сердцевина — оставаться прозрачной. Пока рыба маринуется, замочите нарезанный красный лук в холодной воде на 10 минут, затем слейте; этот шаг смягчит его резкий вкус, сохранив хруст. Хорошо процедите рыбу через мелкое сито; большую часть сока выбросьте, но 2 столовые ложки оставьте. Верните рыбу в чистую миску; добавьте огурец, отжатый красный лук, помидоры, чили и зелёный лук; аккуратно перемешайте, чтобы рыба осталась целой. Влейте 200мл кокосового молока и отложенные 2 ст; л; сока лайма; добавьте соль и несколько поворотов перечной мельницы; аккуратно вмешайте — молоко должно обволакивать рыбу, а не разрушать её. Попробуйте, при необходимости добавьте соли или лайма; подавайте сразу, очень холодным, в неглубоких мисках; посыпьте свежими листьями кинзы.","en":"Place the cubed fish in a non-reactive (glass or ceramic) bowl; pour over 120ml fresh lime juice and toss until every piece is coated; refrigerate for 15–20 minutes — the surface should turn opaque while the centre stays translucent. While the fish marinates, soak the diced red onion in cold water for 10 minutes, then drain; this softens its raw bite without losing the crunch. Drain the fish thoroughly through a fine sieve; discard most of the lime juice but reserve 2 tablespoons. Return the fish to a clean bowl; add the cucumber, drained red onion, tomatoes, chilli and spring onion; toss gently so the fish stays intact. Pour in 200ml coconut milk and the reserved 2 tbsp lime juice; add the salt and a few grinds of pepper; fold everything together gently — the coconut milk should coat without breaking the fish. Taste and adjust salt or lime; serve immediately, very cold, in shallow bowls; scatter fresh coriander leaves on top."}},{"id":99,"origin":{"ru":"Армения","en":"Armenia","ro":"Armenia"},"name":{"ru":"Хоровац","en":"Khorovats","ro":"Khorovats"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["800г свиной лопатки или говяжьей вырезки, нарезанной кубиками 4 см","2 крупные красные луковицы (1 нарезанная для маринада, 1 нарезанная дольками для шампуров)","1 красный болгарский перец, нарезанный кусочками 4 см","1 зелёный болгарский перец, нарезанный кусочками 4 см","1 средний баклажан, нарезанный кольцами 3 см","4 спелых помидора (для гриля целиком)","3 ст. л. подсолнечного масла","1 ч. л. свежемолотого чёрного перца","2 ч. л. крупной соли","небольшой пучок свежего базилика и петрушки для подачи","лаваш или другая лепёшка для подачи"],"en":["800g pork shoulder or beef tenderloin, cut into 4 cm cubes","2 large red onions (1 sliced for the marinade, 1 cut into wedges for skewering)","1 red bell pepper, cut into 4 cm pieces","1 green bell pepper, cut into 4 cm pieces","1 medium aubergine, cut into 3 cm rounds","4 ripe tomatoes (to be grilled whole alongside)","3 tbsp sunflower oil","1 tsp freshly ground black pepper","2 tsp coarse salt","a small handful of fresh basil and parsley, to serve","lavash or another flatbread, to serve"],"ro":["800g pulpă de porc sau mușchi de vită, tăiat cuburi de 4 cm","2 cepe roșii mari (una feliată pentru marinadă, una tăiată felii pentru frigărui)","1 ardei gras roșu, tăiat bucăți de 4 cm","1 ardei gras verde, tăiat bucăți de 4 cm","1 vânătă medie, tăiată rondele de 3 cm","4 roșii coapte (pentru grătar întregi)","3 linguri ulei de floarea-soarelui","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare grunjoasă","un mănunchi de busuioc și pătrunjel proaspăt, pentru servit","lavaș sau alt tip de pâine plată"]},"howIsMade":{"ru":"Один лук тонко нарежьте; в большой миске соедините 800г нарезанного кубиками мяса, нарезанный лук, 2 ч; л; соли, 1 ч; л; чёрного перца и 3 ст; л; подсолнечного масла; хорошо помассируйте руками и поставьте в холодильник на 4–8 часов или на ночь. Разожгите угли и дайте им прогореть до красных рдеющих углей с белыми краями — около 30–40 минут; установите решётку в 15 см над углями. Нанижите маринованное мясо на металлические шампуры, чередуя с дольками лука, оставляя небольшие промежутки между кусками, чтобы горячий воздух циркулировал. Положите целые перцы, кружки баклажана и помидоры прямо на решётку, в стороне от мяса; часто поворачивайте, пока кожица не почернеет со всех сторон — всего 12–15 минут. Разместите шампуры с мясом над самой горячей частью углей; жарьте 10–14 минут, переворачивая каждые 2 минуты, пока мясо снаружи не станет глубоко карамелизованным, а внутри ещё розовым — внутренняя температура 60°C для свинины. Переложите овощи на тарелку, накройте фольгой на 5 минут, затем снимите обугленную кожицу; крупно нарежьте и смешайте с выделившимся соком, солью и нарезанной петрушкой — получится грубая приправа. Подавайте шампуры горячими с овощной приправой, свежим базиликом, дольками лимона и тёплым лавашем для заворачивания.","en":"Thinly slice one onion; in a large bowl, combine 800g cubed meat, the sliced onion, 2 tsp salt, 1 tsp black pepper, and 3 tbsp sunflower oil; massage well by hand and refrigerate 4–8 hours, or overnight. Light a charcoal fire and let it burn down to glowing red embers with white edges — about 30–40 minutes; position the grill 15 cm above the coals. Thread the marinated meat onto metal skewers, alternating with wedges of onion and leaving small gaps between pieces so the hot air can circulate. Lay the whole peppers, aubergine slices and tomatoes directly on the grill, away from the meat; char them rotating frequently, until the skins blacken on every side — about 12–15 minutes total. Place the meat skewers over the hottest part of the embers; grill 10–14 minutes, turning every 2 minutes, until the meat is deeply caramelised outside but still pink in the centre — internal temperature 60°C for pork. Transfer the grilled vegetables to a plate, cover with foil for 5 minutes, then strip off the blackened skins; roughly chop and mix with the resting juices, salt, and chopped parsley to make a rustic relish. Serve the skewers hot with the vegetable relish, fresh basil, lemon wedges, and warm lavash for wrapping."}},{"id":100,"origin":{"ru":"Эстония","en":"Estonia","ro":"Estonia"},"name":{"ru":"Вериворст","en":"Verivorst","ro":"Verivorst"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["500г свиной крови (свежей или размороженной)","200г свиного сала или жирной свиной грудинки, мелко нарезанной кубиками","200г перловой крупы, отваренной и охлаждённой","2 крупные луковицы, мелко нарезанные","1 ч. л. сушёного майорана","1 ч. л. молотого душистого перца","1 ч. л. молотого чёрного перца","2 ч. л. крупной соли","1,5м очищенной натуральной колбасной оболочки","2 ст. л. свиного смальца для жарки","брусничный джем и солёные огурцы для подачи"],"en":["500g pig's blood (fresh or thawed)","200g pork fat or fatty pork belly, finely diced","200g pearl barley, cooked and cooled","2 large onions, finely chopped","1 tsp dried marjoram","1 tsp ground allspice","1 tsp ground black pepper","2 tsp coarse salt","1.5m cleaned natural sausage casing","2 tbsp pork lard, for cooking","lingonberry jam and pickled cucumbers, to serve"],"ro":["500g sânge de porc (proaspăt sau decongelat)","200g slănină sau piept de porc gras, tăiat cuburi mici","200g orz perlat, fiert și răcit","2 cepe mari, tocate fin","1 linguriță maghiran uscat","1 linguriță ienibahar măcinat","1 linguriță piper negru măcinat","2 lingurițe sare grunjoasă","1,5m maț natural curățat","2 linguri untură de porc, pentru gătit","gem de lingonberry și castraveți murați, pentru servit"]},"howIsMade":{"ru":"В большой сковороде обжаривайте кубики свиного сала на слабом огне 8–10 минут, пока большая часть жира не вытопится, а кусочки не подрумянятся; добавьте нарезанный лук и готовьте ещё 6–8 минут, пока он не станет мягким и прозрачным; полностью охладите. В большой миске соедините отваренный ячмень, обжаренные лук и сало (со всем жиром), майоран, душистый перец, соль и чёрный перец; хорошо перемешайте. Кровь слегка взбейте венчиком, чтобы разбить возможные сгустки, и постепенно вмешайте в ячменную смесь; начинка должна получиться блестящей и текучей, но не слишком жидкой. Промойте натуральную оболочку под холодной проточной водой 5 минут; завяжите один конец кухонной нитью. Натяните открытый конец оболочки на широкую воронку или насадку для колбас; постепенно заполняйте оболочку, оставляя её заполненной на две трети, чтобы было место для расширения при варке; перевяжите на колбаски длиной 12–15 см и проколите каждую иглой в нескольких местах. В большой кастрюле доведите воду до 80°C — не до кипения; опустите колбаски и аккуратно варите 30–40 минут, пока они не станут плотными на ощупь, а сок при проколе не станет прозрачным. Достаньте колбаски и дайте им отдохнуть 10 минут; разогрейте духовку до 200°C. Смажьте колбаски топлёным салом и запекайте на противне 12–15 минут, один раз перевернув, пока оболочка не станет хрустящей и блестяще-золотистой; подавайте горячими с брусничным джемом и солёными огурцами.","en":"In a large pan, fry the diced pork fat over low heat for 8–10 minutes, until most of its fat has rendered and the cubes are golden; add the chopped onions and cook 6–8 minutes more, until soft and translucent; set aside to cool completely. In a large bowl, combine the cooked pearl barley, the fried onions and pork fat (with all their fat), the marjoram, allspice, salt and pepper; mix well. Whisk the blood briefly to break up any clots, then stir it gradually into the barley mixture; the filling should look glossy and pourable, but not too liquid. Rinse the sausage casing under cold running water for 5 minutes; tie off one end with kitchen twine. Slide the open end of the casing onto a wide funnel or sausage stuffer; pipe the mixture in gradually, leaving the casing two-thirds full to allow expansion during cooking; tie off into 12–15 cm sausages and prick each with a needle in several places. Bring a large pot of water to 80°C — not boiling; slip the sausages in and poach gently for 30–40 minutes, until they feel firm to the touch and the juices run clear when pricked. Lift the sausages out and let them rest 10 minutes; preheat the oven to 200°C. Brush the sausages with melted lard and roast on a tray for 12–15 minutes, turning once, until the skins are crisp and burnished; serve hot with lingonberry jam and pickled cucumbers."}},{"id":102,"origin":{"ru":"Южная Корея","en":"South Korea","ro":"Coreea de Sud"},"name":{"ru":"Ттокпокки","en":"Tteokbokki","ro":"Tteokbokki"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"ru":["500г цилиндрических рисовых лепёшек (гарэ-тток), свежих или размороженных","150г омук (корейский рыбный пирог), нарезанный треугольниками","3 ст.л. кочудяна (ферментированная паста из красного перца)","1 ст.л. кочугару (корейские хлопья красного перца)","1 ст.л. сахара","1 ч.л. соевого соуса","500мл анчоусного бульона (или воды с даши)","2 зелёных лука, нарезанных кусочками по 5 см","2 варёных вкрутую яйца, очищенных","1 ч.л. кунжутного масла","1 ч.л. жареного кунжута"],"en":["500g cylindrical rice cakes (garae-tteok), fresh or thawed","150g eomuk (Korean fish cake), cut into triangles","3 tbsp gochujang (fermented red chili paste)","1 tbsp gochugaru (Korean red pepper flakes)","1 tbsp sugar","1 tsp soy sauce","500ml anchovy stock (or water with a dashi packet)","2 spring onions, cut into 5 cm pieces","2 hard-boiled eggs, peeled","1 tsp sesame oil","1 tsp toasted sesame seeds"],"ro":["500g tteok cilindric (garae-tteok) proaspăt sau dezghețat","150g eomuk (prăjitură de pește coreeană), tăiat în triunghiuri","3 linguri gochujang (pastă de ardei iute fermentat)","1 lingură gochugaru (fulgi de ardei iute coreean)","1 lingură zahăr","1 linguriță sos de soia","500ml supă de hamsii (sau apă cu dashi)","2 cepe verzi, tăiate în bucăți de 5 cm","2 ouă fierte tari, decojite","1 linguriță ulei de susan","1 linguriță semințe de susan prăjite"]},"howIsMade":{"ru":"Если рисовые лепёшки твёрдые или из холодильника, замочите их в тёплой воде на 20–30 минут до мягкости; слейте. В широкой сковороде доведите 500мл анчоусного бульона до кипения на среднем-сильном огне. Вмешайте 3 ст; л; кочудяна, 1 ст; л; кочугару, 1 ст; л; сахара и 1 ч; л; соевого соуса; взбейте венчиком, пока паста не растворится полностью, а соус не станет блестящим и красным. Добавьте процеженные лепёшки; аккуратно перемешайте, чтобы каждая была покрыта соусом, затем готовьте на среднем огне 8–10 минут, часто помешивая, пока лепёшки не станут мягкими, а соус не загустеет до сиропообразной консистенции, обволакивающей тыльную сторону ложки. Добавьте кусочки омук и готовьте ещё 3–4 минуты, пока они не впитают соус и не станут ярко-красными. Опустите 2 варёных яйца, чтобы они прогрелись; попробуйте и при необходимости добавьте щепотку сахара или немного соевого соуса. Сбрызните кунжутным маслом, посыпьте зелёным луком и кунжутом; подавайте сразу, очень горячим, прямо из сковороды.","en":"If the rice cakes are hard or refrigerated, soak them in warm water for 20–30 minutes until pliable; drain. In a wide shallow pan, bring 500ml of anchovy stock to a boil over medium-high heat. Stir in 3 tbsp gochujang, 1 tbsp gochugaru, 1 tbsp sugar and 1 tsp soy sauce; whisk until the paste fully dissolves and the sauce turns glossy red. Add the drained rice cakes; stir gently to coat every piece, then simmer over medium heat for 8–10 minutes, stirring often, until the rice cakes are tender and the sauce has thickened to a syrupy consistency that coats the back of a spoon. Add the eomuk pieces and cook for another 3–4 minutes, until they have absorbed the sauce and turned bright red. Slip in the 2 hard-boiled eggs to warm through; taste and adjust with a pinch of sugar or a splash of soy if needed. Drizzle with sesame oil, sprinkle with the spring onions and sesame seeds; serve immediately, very hot, straight from the pan."}},{"id":103,"origin":{"ru":"Эквадор","en":"Ecuador","ro":"Ecuador"},"name":{"ru":"Севиче из креветок","en":"Shrimp Ceviche","ro":"Ceviche de camarón"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ru":["600г средних креветок, очищенных и без жилки","180мл свежевыжатого сока лайма (примерно 8 лаймов)","120мл свежевыжатого апельсинового сока","1 крупная красная луковица, мелко нарезанная","3 спелых помидора, без семян, нарезанных кубиками","1 красный чили (ахи), мелко нарезанный (по желанию)","30г свежей кинзы, нарезанной","3 ст. л. оливкового масла","1 ч. л. мелкой морской соли","свежемолотый чёрный перец","чифлес (чипсы из плантана) или поджаренная кукуруза для подачи"],"en":["600g medium shrimp, peeled and deveined","180ml fresh lime juice (about 8 limes)","120ml fresh orange juice","1 large red onion, finely diced","3 ripe tomatoes, deseeded and diced","1 red chili (ají), finely chopped (optional)","30g fresh coriander leaves, chopped","3 tbsp olive oil","1 tsp fine sea salt","freshly ground black pepper","chifles (plantain chips) or toasted corn, to serve"],"ro":["600g creveți medii, decojiți și fără vene","180ml suc proaspăt de lime (aproximativ 8 lime)","120ml suc proaspăt de portocale","1 ceapă roșie mare, tăiată cuburi mici","3 roșii coapte, fără semințe și tăiate cuburi","1 ardei iute roșu (ají), tocat fin (opțional)","30g frunze de coriandru proaspăt, tocate","3 linguri ulei de măsline","1 linguriță sare fină de mare","piper negru proaspăt măcinat","chifles (chipsuri de plantain) sau porumb prăjit, pentru servit"]},"howIsMade":{"ru":"Доведите большую кастрюлю подсоленной воды до кипения; опустите креветки и варите 60–90 секунд, пока они не станут розовыми и непрозрачными; сразу слейте воду и шокируйте в миске с ледяной водой. Слейте креветки, разрежьте пополам или оставьте целыми по вкусу и положите в инертную миску (стекло или керамика). Залейте креветки 180мл сока лайма и 120мл апельсинового сока; перемешайте, накройте и оставьте в холодильнике на 15–20 минут. Пока креветки маринуются, замочите нарезанный красный лук в подсоленной ледяной воде на 10 минут, затем слейте — это смягчит резкий вкус, сохранив хруст. Добавьте в миску с креветками лук, помидоры, чили, кинзу, 3 ст; л; оливкового масла и 1 ч; л; соли; аккуратно перемешайте. Попробуйте и при необходимости добавьте соли, лайма или чили; дайте постоять 5 минут, чтобы ароматы устоялись. Подавайте очень холодным в неглубоких мисках, с чифлес или поджаренной кукурузой для хрустящего контраста.","en":"Bring a large pot of salted water to a boil; add the shrimp and boil for 60–90 seconds, until pink and opaque; drain immediately and shock in a bowl of ice water. Drain the shrimp, halve them or leave them whole as you prefer, and place in a non-reactive (glass or ceramic) bowl. Pour 180ml lime juice and 120ml orange juice over the shrimp; toss, cover, and refrigerate for 15–20 minutes. While the shrimp marinates, soak the diced red onion in salted ice water for 10 minutes, then drain — this softens the harsh bite without losing crunch. Add the drained onion, tomatoes, chili, coriander, 3 tbsp olive oil and 1 tsp salt to the shrimp bowl; toss gently. Taste and adjust salt, lime, or chili; let rest for 5 minutes so the flavours settle. Serve very cold in shallow bowls, with chifles or toasted corn alongside for crisp contrast."}},{"id":104,"origin":{"ru":"Доминиканская Республика","en":"Dominican Republic","ro":"Republica Dominicană"},"name":{"ru":"Ла Бандера","en":"La Bandera","ro":"La Bandera"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"ru":["400г длиннозёрного белого риса","250г сухой красной фасоли (или 800г готовой/консервированной, откинутой)","600г куриных бёдер на кости или говяжьей шейки, нарезанных кубиками 4 см","2 крупных зелёных платана, очищенных, нарезанных кружками 1 см","1 средний зелёный болгарский перец, мелко нарезанный","1 небольшой красный болгарский перец, мелко нарезанный","1 крупная луковица, мелко нарезанная","4 зубчика чеснока, мелко рубленных","30г свежей кинзы, нарезанной (или кулантро)","2 спелых помидора, нарезанных кубиками (или 200г резаных томатов из банки)","2 ст. л. томатной пасты","60мл растительного масла (плюс для жарки плантанов)","1 ч. л. сушёного орегано","сок 1 лайма","соль и свежемолотый чёрный перец"],"en":["400g long-grain white rice","250g dried red kidney beans (or 800g cooked/canned, drained)","600g bone-in chicken thighs or beef chuck, cut into 4 cm cubes","2 large green plantains, peeled and sliced 1 cm thick","1 medium green bell pepper, finely diced","1 small red bell pepper, finely diced","1 large onion, finely chopped","4 garlic cloves, minced","30g fresh coriander, chopped (or culantro if available)","2 ripe tomatoes, diced (or 200g canned chopped tomatoes)","2 tbsp tomato paste","60ml vegetable oil (plus more for frying plantains)","1 tsp dried oregano","juice of 1 lime","salt and freshly ground black pepper"],"ro":["400g orez cu bob lung alb","250g fasole roșie uscată (sau 800g fasole gătită)","600g pulpe de pui cu os sau pulpă de vită, tăiată cuburi de 4 cm","2 banane plantain verzi mari, decojite, tăiate rondele de 1 cm","1 ardei gras verde mediu, tăiat cuburi mici","1 ardei gras roșu mic, tăiat cuburi mici","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","30g coriandru proaspăt, tocat (sau culantro)","2 roșii coapte, tăiate cuburi (sau 200g roșii din conservă)","2 linguri pastă de roșii","60ml ulei vegetal (plus mai mult pentru prăjit)","1 linguriță oregano uscat","zeamă de la 1 lime","sare și piper negru proaspăt măcinat"]},"howIsMade":{"ru":"Замочите сухую фасоль на ночь, если используете; слейте воду, залейте 1л свежей воды с щепоткой соли и варите 60–75 минут до полной мягкости; сохраните 250мл отвара. Приправьте мясо солью, перцем, орегано и соком лайма; дайте постоять 15 минут, пока готовите соферито. Разогрейте 2 ст; л; масла в тяжёлой кастрюле; сделайте соферито: обжаривайте лук 5 минут, затем добавьте чеснок, оба перца и половину кинзы; готовьте 4 минуты до мягкости. Сдвиньте соферито в сторону; в освободившееся место положите мясо и обжарьте по 3–4 минуты с каждой стороны; вмешайте 2 ст; л; томатной пасты и нарезанные помидоры, готовьте 3 минуты; влейте 500мл воды, накройте крышкой и тушите 35–40 минут, пока мясо не станет нежным, а соус не загустеет. Тем временем сварите рис: промойте 400г риса до прозрачной воды; в широкой кастрюле разогрейте 1 ст; л; масла и 1 ч; л; соли, всыпьте рис, залейте 700мл воды, доведите до кипения, затем уменьшите огонь до минимума и томите под крышкой 18–20 минут; снимите с огня и дайте постоять 10 минут. Доведите фасоль: в небольшой кастрюле разогрейте 1 ст; л; масла и ложку соферито, отложенного на шаге 3; добавьте процеженную фасоль плюс 250мл сохранённого отвара и 1 ч; л; соли; готовьте 12–15 минут, разминая горсть бобов о стенку кастрюли, чтобы получился густой соус. Разогрейте слой масла 5 см до 175°C; обжаривайте кружки платана 3–4 минуты до золотистости; откиньте на бумагу, придавите прессом или дном стакана и обжаривайте ещё 1–2 минуты до хруста; посолите горячими. На тарелке: рис как основа, половник фасоли рядом, щедрая порция тушёного мяса в соусе и 4–5 кружков платана; завершите оставшейся кинзой, дольками лайма и простым зелёным салатом.","en":"Soak the dried beans overnight if using; drain, cover with 1L fresh water and a pinch of salt, and simmer for 60–75 minutes, until fully tender; reserve 250ml of the cooking liquid. Season the meat with salt, pepper, oregano, and lime juice; rest for 15 minutes while you prepare the sofrito. Heat 2 tbsp oil in a heavy pot; make a sofrito: sauté the onion for 5 minutes, then add the garlic, both peppers, and half the coriander; cook 4 minutes until soft. Push the sofrito to one side; add the meat to the empty space and brown for 3–4 minutes per side; stir in 2 tbsp tomato paste and the diced tomatoes, cook for 3 minutes; pour in 500ml water, cover, and simmer for 35–40 minutes, until the meat is fork-tender and the sauce has thickened. Meanwhile cook the rice: rinse 400g of rice until the water runs clear; in a wide pot, heat 1 tbsp oil and 1 tsp salt, add the rice, cover with 700ml water, bring to a boil, then reduce to the lowest heat and steam, covered, for 18–20 minutes; rest 10 minutes off heat. Finish the beans: in a small pot, heat 1 tbsp oil and a spoonful of the sofrito set aside in step 3; add the drained beans plus 250ml reserved cooking liquid and 1 tsp salt; simmer for 12–15 minutes, mashing a handful against the side of the pot to thicken to a saucy consistency. Heat 5 cm of oil in a frying pan to 175°C; fry the plantain slices for 3–4 minutes until golden; drain on paper, flatten with a press or the back of a cup, and refry for 1–2 minutes until crisp; salt while hot. Plate each portion with rice as the base, a ladle of beans alongside, a generous portion of braised meat with its sauce, and 4–5 plantain rounds; finish with the remaining coriander, lime wedges, and a simple green salad."}},{"id":105,"origin":{"ru":"Иран","en":"Iran","ro":"Iran"},"name":{"ru":"Фесенджан","en":"Fesenjan","ro":"Fesenjan"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"ru":["800г бескостных куриных бёдер, или 1 небольшая утка (1,5кг), разделанная","300г очищенных грецких орехов, обжаренных и мелко молотых","120мл гранатового сиропа","2 крупные луковицы, мелко нарезанные","3 ст. л. растительного масла","1 ч. л. молотой куркумы","1 ч. л. молотой корицы","1/2 ч. л. свежемолотого мускатного ореха","1 ст. л. коричневого сахара (или по вкусу)","1 л горячего куриного бульона или воды","свежие зёрна граната для подачи","соль и свежемолотый чёрный перец","рис басмати для подачи"],"en":["800g boneless chicken thighs, or 1 small duck (1.5kg) jointed","300g shelled walnuts, toasted and finely ground","120ml pomegranate molasses","2 large onions, finely chopped","3 tbsp vegetable oil","1 tsp ground turmeric","1 tsp ground cinnamon","1/2 tsp freshly grated nutmeg","1 tbsp brown sugar (or to taste)","1 litre hot chicken stock or water","fresh pomegranate seeds, to garnish","salt and freshly ground black pepper","basmati rice, to serve"],"ro":["800g pulpe de pui dezosate, sau 1 rață mică (1,5kg) tăiată","300g miez de nucă, prăjit și măcinat fin","120ml melasă de rodie","2 cepe mari, tocate fin","3 linguri ulei vegetal","1 linguriță turmeric măcinat","1 linguriță scorțișoară măcinată","1/2 linguriță nucșoară proaspăt rasă","1 lingură zahăr brun (sau după gust)","1 litru supă de pui sau apă fierbinte","semințe de rodie proaspete, pentru ornat","sare și piper negru proaspăt măcinat","orez basmati pentru servit"]},"howIsMade":{"ru":"Обжарьте 300г грецких орехов на сухой сковороде на среднем огне 4–5 минут, постоянно встряхивая, пока они не станут ароматными и немного темнее; остудите и измельчите в кухонном комбайне как можно мельче. В тяжёлой кастрюле разогрейте 3 ст; л; масла на среднем огне; добавьте нарезанный лук и обжаривайте 12–15 минут, пока он не станет глубоко золотым и сладким; вмешайте куркуму, корицу и мускатный орех и готовьте 1 минуту. Приправьте мясо солью и перцем; положите в кастрюлю и обжарьте по 4–5 минут с каждой стороны, только до цвета; переложите на тарелку. Добавьте ореховую пасту в кастрюлю и помешивайте деревянной ложкой 3 минуты, пока она не начнёт выделять масло и не запахнет прожаренным — этот шаг создаёт глубину соуса. Влейте 1 литр горячего бульона, верните мясо с соком и томите без крышки на медленном огне 30–40 минут, часто помешивая, чтобы паста не пригорела. Добавьте гранатовый сироп и коричневый сахар; попробуйте: соус должен быть кисло-сладким и насыщенным; продолжайте варить на медленном огне ещё 30–40 минут, пока мясо не станет совсем мягким, соус не потемнеет почти до чёрного, а ореховое масло не выступит на поверхность. Доведите до вкуса солью, добавьте больше сиропа (для кислоты) или сахара (для округлости); подавайте на тёплом рисе басмати, посыпьте свежими зёрнами граната.","en":"Toast 300g of walnuts in a dry pan over medium heat for 4–5 minutes, tossing constantly, until fragrant and slightly darker; cool, then grind to as fine a paste as possible in a food processor. In a heavy pot, heat 3 tbsp oil over medium heat; add the chopped onions and cook for 12–15 minutes, until deeply golden and sweet; stir in the turmeric, cinnamon, and nutmeg and cook for 1 minute. Season the meat with salt and pepper; add to the pot and brown for 4–5 minutes per side, just for colour; lift onto a plate. Add the walnut paste to the pot and stir with a wooden spoon for 3 minutes, until it starts releasing oil and smells toasted — this is the step that builds the sauce's depth. Pour in 1 litre of hot stock, return the meat with its juices, and simmer uncovered over low heat for 30–40 minutes, stirring often so the nut paste does not scorch. Add the pomegranate molasses and brown sugar; taste: the sauce should be tart-sweet and deeply savoury; continue to simmer over low heat for another 30–40 minutes, until the meat is fully tender, the sauce has darkened to almost black, and walnut oil rises to the surface. Adjust with salt, more molasses (for tartness) or sugar (to round it); serve over warm basmati rice, scattered with fresh pomegranate seeds."}},{"id":106,"origin":{"ru":"Филиппины","en":"Philippines","ro":"Filipine"},"name":{"ru":"Каре-Каре","en":"Kare-Kare","ro":"Kare-Kare"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["1,2кг бычьего хвоста, разрезанного по суставам (или говяжьей голяшки с костью)","200г несладкой арахисовой пасты (или 250г жареного арахиса, молотого)","2 ст. л. семян аннато (ачуэте) — или 1 ст. л. порошка аннато","4 ст. л. сырого риса, обжаренного в сухой сковороде и смолотого","1 крупная луковица, мелко нарезанная","6 зубчиков чеснока, мелко нарубленных","1 крупный баклажан, нарезанный четвертинками","200г длинной зелёной фасоли (ситав), нарезанной кусочками 7 см","1 крупный бок-чой или 200г печай, разрезанный пополам вдоль","1,5л воды (или говяжьего бульона)","60мл растительного масла","соль по вкусу","багоонг (филиппинская креветочная паста) для подачи","паровой рис для подачи"],"en":["1.2kg oxtail, cut at the joints (or bone-in beef shank)","200g unsweetened peanut butter (or 250g roasted peanuts, ground)","2 tbsp annatto (achuete) seeds — or 1 tbsp annatto powder","4 tbsp raw rice, toasted in a dry pan and ground","1 large onion, finely chopped","6 garlic cloves, minced","1 large eggplant, cut into quarters","200g long green beans (sitaw), cut into 7 cm lengths","1 large bok choy or 200g pechay, halved lengthwise","1.5L water (or beef stock)","60ml vegetable oil","salt to taste","bagoong (Filipino shrimp paste), to serve","steamed rice, to serve"],"ro":["1,2kg coadă de vită, tăiată în bucăți la articulație (sau pulpă de vită cu os)","200g pastă de arahide neîndulcită (sau 250g arahide prăjite, măcinate)","2 linguri semințe de annatto (achiote) — sau 1 lingură pudră de annatto","4 linguri orez crud, prăjit într-o tigaie uscată și măcinat","1 ceapă mare, tocată fin","6 căței de usturoi, tocați","1 vânătă mare, tăiată sferturi","200g fasole verde lungă, tăiată în bucăți de 7 cm","1 bok choy mare sau 200g pak choi, tăiat pe lungime","1,5L apă (sau supă de vită)","60ml ulei vegetal","sare după gust","bagoong (pastă de creveți filipineză) pentru servit","orez fiert, pentru servit"]},"howIsMade":{"ru":"Положите бычий хвост в большую кастрюлю с 1,5л воды; доведите до кипения, снимите пену и варите 5 минут; слейте воду и промойте мясо — это даст прозрачный бульон. Верните мясо в кастрюлю с 1,5л свежей воды (или говяжьего бульона) и томите 2,5–3 часа на медленном огне, пока мясо не начнёт почти отваливаться от костей; достаньте мясо и сохраните 1л бульона. Замочите семена аннато в 3 ст; л; горячей воды на 10 минут, затем процедите до интенсивно красно-оранжевой жидкости (или растворите порошок аннато сразу). В чистой кастрюле разогрейте 60мл масла; обжарьте лук 5 минут, добавьте чеснок и готовьте ещё 1 минуту. Вмешайте арахисовую пасту, жидкость аннато и 1л сохранённого бульона; венчиком взбейте до гладкости; варите 5 минут, затем добавьте обжаренный молотый рис — соус начнёт заметно густеть. Верните мясо в соус и томите на медленном огне 10–15 минут, разводя бульоном, если становится слишком густым; подсолите умеренно — багоонг за столом очень солёный. Добавьте четвертинки баклажана и стручковую фасоль, варите 5 минут; положите сверху бок-чой, накройте и готовьте ещё 3 минуты, пока овощи не станут мягкими, но останутся яркими. Подавайте в глубоких мисках на паровом рисе с багоонгом в маленькой пиале сбоку — каждый добавляет по вкусу.","en":"Put the oxtail in a large pot with 1.5L water; bring to a boil, skim the foam, and boil for 5 minutes; drain and rinse the meat for a clear broth. Return the meat to the pot with 1.5L fresh water (or beef stock) and simmer gently for 2.5–3 hours, until the meat falls almost off the bone; lift out the meat and reserve 1L of the broth. Steep the annatto seeds in 3 tbsp hot water for 10 minutes, then strain to a deep red-orange liquid (or dissolve the annatto powder directly). In a clean pot, heat 60ml oil; sauté the onion for 5 minutes, add the garlic and cook 1 minute more. Stir in the peanut butter, annatto liquid, and 1L of the reserved broth; whisk to keep it smooth; simmer 5 minutes, then add the toasted ground rice — the sauce will begin to thicken visibly. Return the meat to the sauce and simmer over low heat for 10–15 minutes, loosening with more broth if it becomes too thick; season with salt (sparingly — the bagoong at the table is very salty). Add the eggplant quarters and long beans, simmer 5 minutes; lay the bok choy on top, cover, and cook for another 3 minutes, until the vegetables are tender but still vibrant. Serve in deep bowls over steamed rice, with bagoong in a small bowl alongside — each diner stirs in as much as they like."}},{"id":107,"origin":{"ru":"Португалия","en":"Portugal","ro":"Portugalia"},"name":{"ru":"Франсезинья","en":"Francesinha","ro":"Francesinha"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["8 толстых ломтиков белого хлеба (тостового)","400г стейка рибай или вырезки, нарезанных 4 тонкими ломтиками","4 колбаски лингуиса или копчёные колбаски, разрезанные вдоль","8 ломтиков варёной ветчины","8 ломтиков острого салями или чоризо","12 ломтиков чеддера или гауды (плавкого сорта)","4 яйца сверху","30г сливочного масла","масло для жарки яиц","Для соуса:","400мл светлого пива","200мл говяжьего бульона","200г томатной пасты","60мл виски или бренди","1 небольшая луковица, мелко нарезанная","2 зубчика чеснока, мелко нарубленных","1 лавровый лист","1/2 ч. л. хлопьев чили (или пири-пири)","1 ст. л. муки","соль, перец, сахар по вкусу","картофель фри для подачи"],"en":["8 thick slices white bread (sandwich loaf)","400g rib-eye or sirloin steak, cut into 4 thin slices","4 linguiça or smoked sausage links, halved lengthwise","8 slices cooked ham","8 slices spicy salami or chouriço","12 slices Cheddar or Gouda, melting type","4 eggs, for topping","30g butter","oil for frying eggs","For the sauce:","400ml lager beer","200ml beef stock","200g tomato paste","60ml whisky or brandy","1 small onion, finely chopped","2 garlic cloves, minced","1 bay leaf","1/2 tsp chili flakes (or piri-piri)","1 tbsp flour","salt, pepper, sugar to taste","fries, to serve"],"ro":["8 felii groase de pâine albă (tip toast)","400g antricot sau mușchi de vită, în 4 felii subțiri","4 cârnați linguiça (sau cabanos afumat), tăiați pe lungime","8 felii de șuncă (presunto) fiartă","8 felii salami picant (chouriço)","12 felii brânză cheddar sau Gouda topit","4 ouă (pentru deasupra)","30g unt","ulei pentru prăjit ouăle","Pentru sos:","400ml bere blondă","200ml bulion de vită","200g pastă de roșii","60ml whisky sau brandy","1 ceapă mică, tocată","2 căței de usturoi, tocați","1 frunză de dafin","1/2 linguriță fulgi de chili (sau piri-piri)","1 lingură făină","sare, piper, zahăr după gust","cartofi prăjiți, pentru servit"]},"howIsMade":{"ru":"Сначала соус: разогрейте 1 ст; л; сливочного масла в кастрюле, обжарьте лук 5 минут, добавьте чеснок и 1 ст; л; муки, готовьте 1 минуту; вмешайте томатную пасту и варите 2 минуты. Влейте пиво и виски, варите 2 минуты, чтобы испарился алкоголь; добавьте бульон, лавровый лист, хлопья чили, щепотку соли и сахара; томите на медленном огне 25–30 минут, пока соус не станет густым и блестящим; процедите для гладкости. Приправьте стейк солью и перцем; растопите оставшееся масло в сковороде и обжарьте мясо по 1,5 минуты с каждой стороны до подрумянивания; достаньте. В той же сковороде обжарьте половинки лингуисы по 2–3 минуты с каждой стороны. Для каждого сэндвича обжарьте 2 ломтика хлеба в масле или сливочном масле с обеих сторон (по 1 минуте); уложите: 1 ломтик хлеба, 2 ломтика ветчины, 1 ломтик стейка, 2 ломтика салями, 2 половинки лингуисы, второй ломтик хлеба; слегка прижмите. Положите сэндвичи в смазанную форму; накройте каждый 3 ломтиками сыра и поместите под гриль при 220°C на 3–4 минуты, пока сыр не расплавится, не пузырится и не подрумянится местами. Пожарьте по 1 яйцу на сэндвич в масле, оставляя желток жидким. Поставьте каждый сэндвич на глубокую тарелку, положите яичницу поверх сыра и щедро залейте горячим соусом вокруг — он должен собраться на дне тарелки; подавайте сразу с картофелем фри.","en":"Make the sauce first: heat 1 tbsp of the butter in a saucepan, sauté the onion for 5 minutes, add the garlic and 1 tbsp flour, cook for 1 minute; stir in the tomato paste and cook for 2 minutes. Pour in the beer and whisky, simmer 2 minutes to burn off the alcohol; add the beef stock, bay leaf, chili flakes, a pinch each of salt and sugar; simmer over low heat for 25–30 minutes, until the sauce is thick and glossy; strain for a smooth finish. Season the steak slices with salt and pepper; melt the remaining butter in a frying pan and sear the steak for 1.5 minutes per side, until browned; lift out. In the same pan, fry the linguiça halves for 2–3 minutes per side, until coloured. For each sandwich, toast 2 slices of bread in butter or oil on both sides (1 minute per side); layer: 1 slice bread, 2 slices ham, 1 slice steak, 2 slices salami, 2 linguiça halves, top with second slice of bread; press gently. Place the sandwiches in a greased baking dish; cover each with 3 slices of cheese and slide under a grill at 220°C for 3–4 minutes, until the cheese melts, bubbles and browns in spots. Fry 1 egg per sandwich in oil, leaving the yolk runny. Set each sandwich in a deep plate, place a fried egg on top of the cheese, and pour the hot sauce generously around the sandwich — it should pool at the base of the plate; serve immediately with fries on the side."}},{"id":109,"origin":{"ru":"Перу","en":"Peru","ro":"Peru"},"name":{"ru":"Аррос Чауфа","en":"Arroz Chaufa","ro":"Arroz Chaufa"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"ru":["500г длиннозёрного риса, отваренного и охлаждённого (желательно вчерашнего)","300г куриной грудки или свиной корейки, нарезанных кубиками 1,5 см","3 крупных яйца, взбитых","1 красный болгарский перец, мелко нарезанный","6 зелёных луковиц, белые части мелко нарезаны, зелёные оставлены","3 зубчика чеснока, мелко нарубленных","20г свежего имбиря, мелко нарезанного","60мл соевого соуса","1 ст. л. устричного соуса","1 ст. л. поджаренного кунжутного масла","60мл нейтрального растительного масла","1 ч. л. пасты ahi-амарильо (или 1/2 ч. л. чили-порошка)","соль и белый перец по вкусу"],"en":["500g long-grain rice, cooked and cooled (preferably day-old)","300g chicken breast or pork loin, cut into 1.5 cm cubes","3 large eggs, beaten","1 red bell pepper, finely diced","6 spring onions, white parts finely sliced, green parts reserved","3 garlic cloves, minced","20g fresh ginger, finely minced","60ml soy sauce","1 tbsp oyster sauce","1 tbsp toasted sesame oil","60ml neutral vegetable oil","1 tsp ají amarillo paste (or 1/2 tsp chili powder)","salt and white pepper to taste"],"ro":["500g orez cu bob lung fiert și răcit (preferabil de o zi)","300g piept de pui sau pulpă de porc, tăiat cuburi de 1,5 cm","3 ouă mari, bătute","1 ardei kapia roșu, tăiat cuburi mici","6 cepe verzi, partea albă tăiată fin, verdele păstrat","3 căței de usturoi, tocați","20g ghimbir proaspăt, tocat fin","60ml sos de soia","1 lingură sos de stridii","1 lingură ulei de susan","60ml ulei vegetal neutru","1 linguriță aji amarillo pastă (sau 1/2 linguriță pudră de chili)","sare și piper alb după gust"]},"howIsMade":{"ru":"Взбейте яйца со щепоткой соли; разогрейте 1 ст; л; масла в воке на среднем огне, влейте яйца и быстро сделайте тонкий омлет, помешивая; переложите на тарелку и нарежьте маленькими кубиками; отложите. Очень разогретый вок, добавьте ещё 1 ст; л; масла; обжаривайте мясо со щепоткой соли 3–4 минуты, пока края не подрумянятся и оно не приготовится внутри; переложите к яйцам. Влейте оставшееся растительное масло в вок и нагрейте, пока оно не начнёт слегка дымиться; добавьте чеснок, имбирь и перец и обжаривайте 30 секунд до появления аромата. Добавьте белые части зелёного лука и пасту ahi-амарильо; обжаривайте 30 секунд, чтобы ароматы проникли в масло. Всыпьте холодный рис; лопаточкой разбейте его на мелкие частицы, прижимая ко дну вока между переворачиваниями 3–4 минуты, пока каждое зерно не станет отдельным и не раздастся лёгкое шипение. Полейте рис соевым и устричным соусом, перемешивайте 1 минуту, чтобы соусы распределились и придали цвет; верните мясо и яйца в вок. Выключите огонь; полейте кунжутным маслом и добавьте зелёные части лука; приправьте белым перцем; подавайте сразу, горячим, прямо из вока.","en":"Beat the eggs with a pinch of salt; heat 1 tbsp of vegetable oil in a wok over medium heat, pour in the eggs, and quickly make a thin omelette by stirring; tip onto a plate and cut into small cubes; set aside. With the wok very hot, add another 1 tbsp oil; stir-fry the meat with a pinch of salt for 3–4 minutes, until browned at the edges and cooked through; move to the plate with the eggs. Pour the remaining vegetable oil into the wok and heat until it just begins to smoke; add the garlic, ginger, and bell pepper, and stir-fry for 30 seconds, until fragrant. Add the white parts of the spring onions and the ají amarillo paste; stir-fry for 30 seconds, letting the flavours infuse the oil. Add the cold rice; use a spatula to break it into small pieces, pressing it against the bottom of the wok between tosses for 3–4 minutes, until every grain is separate and you hear a slight sizzle. Pour the soy sauce and oyster sauce over the rice, tossing for 1 minute to distribute evenly and pick up colour; return the meat and egg to the wok. Turn off the heat; drizzle with the sesame oil and add the green parts of the spring onions; season with white pepper; serve immediately, hot, straight from the wok."}},{"id":110,"origin":{"ru":"Сингапур","en":"Singapore","ro":"Singapore"},"name":{"ru":"Краб чили","en":"Chili Crab","ro":"Chili Crab"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ru":["2 живых грязевых краба (1,5кг в сумме), очищенных и разрезанных по суставам","4 ст. л. томатной пасты","3 ст. л. самбала-олёк (или пасты чили)","2 ст. л. сладкого соуса чили","60мл кетчупа","30г свежего имбиря, тёртого","6 зубчиков чеснока, мелко нарубленных","2 крупных яйца, взбитых","3 зелёных лука, мелко нарезанных","1 ст. л. рисового уксуса","2 ч. л. сахара","1 ч. л. соли","500мл куриного бульона (или воды)","60мл растительного масла","1 ст. л. кукурузного крахмала, смешанного с 2 ст. л. воды","жареные мантоу (китайские булочки) для подачи"],"en":["2 live mud crabs (1.5kg total), cleaned and halved at the joints","4 tbsp tomato paste","3 tbsp sambal oelek (or chili paste)","2 tbsp sweet chili sauce","60ml ketchup","30g fresh ginger, grated","6 garlic cloves, minced","2 large eggs, beaten","3 spring onions, chopped","1 tbsp rice vinegar","2 tsp sugar","1 tsp salt","500ml chicken stock (or water)","60ml vegetable oil","1 tbsp cornstarch mixed with 2 tbsp water","fried mantou (Chinese buns), to serve"],"ro":["2 crabi de noroi vii (1,5kg în total), curățați și tăiați în jumătăți la articulații","4 linguri pastă de roșii","3 linguri sos sambal oelek (sau pastă de chili)","2 linguri sos dulce de chili","60ml ketchup","30g ghimbir proaspăt, ras","6 căței de usturoi, tocați","2 ouă mari, bătute","3 cepe verzi, tocate","1 lingură oțet de orez","2 lingurițe zahăr","1 linguriță sare","500ml supă de pui (sau apă)","60ml ulei vegetal","1 lingură amidon de porumb amestecat cu 2 linguri apă","mantou prăjit (chifle chinezești), pentru servit"]},"howIsMade":{"ru":"Положите крабов в морозильник на 30 минут, чтобы гуманно их оглушить; очистите, снимите верхний панцирь, удалите мягкие внутренности и разрежьте каждого краба пополам по суставам; расколите клешни обухом ножа, чтобы аромат проникал внутрь. Взбейте яйца в маленькой миске; в другой миске смешайте томатную пасту, самбал, сладкий соус чили, кетчуп, уксус, сахар и соль — это основа соуса. Разогрейте 60мл масла в большом воке или глубокой кастрюле на сильном огне; добавьте куски краба и обжаривайте 3–4 минуты, переворачивая, пока панцири не покраснеют; переложите на тарелку. В том же масле обжарьте тёртый имбирь и чеснок 30 секунд, до сильного аромата. Влейте томатную смесь и 500мл куриного бульона; доведите до кипения, при необходимости добавьте самбал для остроты. Верните куски краба, накройте вок и тушите 8–10 минут, перевернув один раз посередине, пока мясо не приготовится и не станет нежным. Введите крахмальную суспензию тонкой струйкой, помешивая, чтобы соус загустел и заблестел; влейте взбитые яйца спиралью по воку, не помешивая — они застынут шёлковыми лентами; подождите 30 секунд и подверните один раз. Посыпьте мелко нарезанным зелёным луком; подавайте сразу на большом блюде с жареными мантоу рядом, чтобы вымакивать соус.","en":"Place the crabs in the freezer for 30 minutes to humanely stun them; clean them, lift off the top shell, remove the soft inner organs, and chop the crab in half at the joints; crack the claws with the back of a knife so the flavour penetrates. Beat the eggs in a small bowl; in another bowl, stir together the tomato paste, sambal, sweet chili sauce, ketchup, vinegar, sugar and salt — this is the sauce base. Heat 60ml of oil in a large wok or deep pot over high heat; add the crab pieces and stir-fry for 3–4 minutes, turning, until the shells turn red; lift onto a plate. In the same oil, sauté the grated ginger and garlic for 30 seconds, until very fragrant. Pour in the tomato-paste mixture and 500ml chicken stock; bring to a boil, adjust with more sambal for more heat. Return the crab pieces, cover the wok and simmer for 8–10 minutes, turning once halfway, until the meat is fully cooked and tender. Stir the cornstarch slurry into the sauce in a thin stream so the sauce thickens to a glossy coat; pour the beaten eggs around the wok in a spiral without stirring — they will set as silky ribbons; wait 30 seconds, then fold once. Scatter with the chopped spring onions; serve immediately on a large platter with fried mantou alongside to soak up the sauce."}},{"id":111,"origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Тамале","en":"Tamale","ro":"Tamale"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"mexican","ingredients":{"ru":["20–24 сухих кукурузных листа","500г маса-харина (никстамализованная кукурузная мука)","250г свиного смальца комнатной температуры","500мл тёплого куриного бульона","1 ст. л. разрыхлителя","2 ч. л. соли","Для начинки:","500г свиной лопатки без кости, отваренной и разобранной на волокна","4 сухих перца гуахильо, без плодоножек и семян","2 сухих перца анчо, без плодоножек и семян","1 небольшая луковица, четвертинками","3 зубчика чеснока","1 ч. л. молотого зира","1 ч. л. мексиканского орегано","2 ст. л. растительного масла","соль по вкусу","красная или зелёная сальса для подачи"],"en":["20–24 dried corn husks","500g masa harina (nixtamalized corn flour)","250g pork lard, at room temperature","500ml warm chicken stock","1 tbsp baking powder","2 tsp salt","For the filling:","500g boneless pork shoulder, simmered and shredded","4 dried guajillo chilies, stems and seeds removed","2 dried ancho chilies, stems and seeds removed","1 small onion, quartered","3 garlic cloves","1 tsp ground cumin","1 tsp Mexican oregano","2 tbsp vegetable oil","salt to taste","red or green salsa, to serve"],"ro":["20–24 foi de porumb uscate (chiote)","500g masa harina (făină de porumb nixtamalizată)","250g untură de porc, la temperatura camerei","500ml supă de pui caldă","1 lingură praf de copt","2 lingurițe sare","Pentru umplutură:","500g pulpă de porc dezosată, fiartă și mărunțită","4 ardei iuți guajillo uscați, fără semințe","2 ardei iuți ancho uscați, fără semințe","1 ceapă mică, tăiată sferturi","3 căței de usturoi","1 linguriță chimion măcinat","1 linguriță oregano mexican","2 linguri ulei vegetal","sare după gust","salsă roșie sau verde, pentru servit"]},"howIsMade":{"ru":"Замочите кукурузные листья в тёплой воде на 30 минут до гибкости; прижмите тарелкой, чтобы они оставались под водой. Приготовьте соус: обжарьте перцы гуахильо и анчо на сухой сковороде по 1 минуте с каждой стороны до появления аромата; залейте горячей водой на 15 минут; измельчите размоченные перцы с луком, чесноком, зиром, орегано и 250мл воды из-под перцев; процедите соус. Разогрейте 2 ст; л; масла в сковороде, влейте соус и томите 8–10 минут до загустения; добавьте мясо, посолите и готовьте ещё 5 минут; дайте остыть. Взбивайте смалец миксером 3 минуты, пока он не станет пышным и светлым; добавьте разрыхлитель и соль, взбейте ещё 30 секунд. Добавляйте маса-харину поочерёдно с тёплым бульоном, непрерывно взбивая; тесто должно быть лёгким, пышным и прилипать к лопатке; проверка: бросьте маленький шарик в холодную воду — он должен всплыть. Слейте листья; на каждый тамале намажьте 3 ст; л; теста тонким слоем на лист, оставляя 2 см по бокам и 5 см сверху; в центр положите 2 ст; л; начинки. Сложите бока листа над начинкой, затем подверните узкий конец вверх, оставив верх открытым; поставьте тамале вертикально в пароварку открытым концом вверх. Готовьте на пару 60–75 минут, пока тесто не будет легко отделяться от листа; дайте отдохнуть 10 минут перед подачей; подавайте тёплыми с красной или зелёной сальсой.","en":"Soak the corn husks in warm water for 30 minutes, until pliable; weight them down with a plate so they stay submerged. Make the sauce: toast the guajillo and ancho chilies in a dry pan for 1 minute per side, until fragrant; cover with hot water for 15 minutes; blend the rehydrated chilies with the onion, garlic, cumin, oregano and 250ml of the soaking liquid; strain the sauce. Heat 2 tbsp oil in a pan, pour in the chili sauce and simmer for 8–10 minutes, until thickened; add the shredded pork, season with salt and cook another 5 minutes; let it cool. Beat the lard with a mixer for 3 minutes, until fluffy and pale; add the baking powder and salt, mix 30 seconds more. Add the masa harina alternately with warm chicken stock, beating continuously; the dough should be light, fluffy, and cling to the spatula; test by dropping a small ball into cold water — it should float. Drain the corn husks; for each tamale, spread 3 tbsp of dough in a thin layer on a husk, leaving a 2 cm border on the sides and 5 cm at the top; place 2 tbsp filling down the centre. Fold the sides of the husk over the filling, then fold the narrow end up, leaving the top open; stand the tamales vertically in a steamer basket, open ends up. Steam for 60–75 minutes, until the dough peels cleanly away from the husk when you open one; let them rest 10 minutes before serving; serve warm with red or green salsa alongside."}},{"id":112,"origin":{"ru":"Таиланд","en":"Thailand","ro":"Thailanda"},"name":{"ru":"Том-ям","en":"Tom Yum","ro":"Tom Yum"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"thai","ingredients":{"ru":["1 л куриного бульона или бульона из морепродуктов","300г сырых очищенных креветок","2 стебля лемонграсса, нарезанных по 3 см и расплющенных","30г галангала (или имбиря), тонко нарезанного","6 листьев каффирского лайма","3–4 тайских красных чили, разрезанных пополам","200г вешенок или шампиньонов, нарезанных","3 ст.л. рыбного соуса","2 ст.л. свежего сока лайма","1 ст.л. пальмового сахара","2 ст.л. пасты том-ям (по желанию)","1 перо зелёного лука для подачи","Свежий кориандр для подачи"],"en":["1L chicken or seafood stock","300g raw prawns, peeled and deveined","2 stalks lemongrass, cut into 3cm pieces and bruised","30g galangal (or ginger), thinly sliced","6 kaffir lime leaves","3–4 Thai red chillies, halved","200g oyster or button mushrooms, sliced","3 tbsp fish sauce","2 tbsp fresh lime juice","1 tbsp palm sugar","2 tbsp tom yum paste (optional)","1 spring onion stalk, to garnish","Fresh coriander to serve"],"ro":["1 L supă de pui sau stoc de fructe de mare","300g creveți cruzi, curățați","2 tulpini lemongrass, secționate în bucăți de 3 cm și zdrobite","30g galangal (sau ghimbir), felii subțiri","6 frunze de kaffir lime","3–4 ardei iuți roșii thailandezi, tăiați pe jumătate","200g ciuperci pleurotus sau champignon, feliate","3 linguri sos de pește","2 linguri suc proaspăt de lime","1 lingură zahăr de palmier","2 linguri pastă tom yum (opțional)","1 tulpină ceapă verde, pentru servire","Coriandru proaspăt, pentru servire"]},"howIsMade":{"ru":"Доведите 1л бульона до лёгкого кипения в большой кастрюле. Добавьте расплющенные стебли лемонграсса, тонкие ломтики галангала и листья каффирского лайма; варите 10 минут, чтобы ароматизаторы насыщили бульон. Вмешайте пасту том-ям (если используете), разрезанные пополам чили и нарезанные грибы; готовьте 3–4 минуты, пока грибы не станут слегка мягкими. Добавьте креветки и варите ровно 2–3 минуты — они станут розовыми и скрутятся; не переваривайте, иначе станут резиновыми. Снимите кастрюлю с огня; добавьте 3 ст; л; рыбного соуса, 2 ст; л; свежего сока лайма и 1 ст; л; пальмового сахара. Попробуйте и сбалансируйте: суп должен быть кислым, солёным, острым и слегка сладким одновременно; больше лайма — для остроты кислинки, больше рыбного соуса — для соли. Подавайте сразу в глубоких мисках, посыпав зелёным луком и кинзой; лемонграсс, галангал и листья лайма — ароматические и не предназначены для еды.","en":"Bring 1L of stock to a gentle simmer in a large pot. Add the bruised lemongrass stalks, sliced galangal, and kaffir lime leaves; simmer for 10 minutes to infuse the aromatics and turn the broth deeply fragrant. Stir in the tom yum paste (if using), halved chillies, and sliced mushrooms; cook for 3–4 minutes, until the mushrooms soften slightly. Add the prawns and cook for exactly 2–3 minutes — they should turn pink and curl; do not overcook or they will become rubbery. Take the pot off the heat; stir in 3 tbsp fish sauce, 2 tbsp fresh lime juice, and 1 tbsp palm sugar. Taste and adjust the balance: the soup should be sour, salty, spicy, and lightly sweet all at once; add more lime for sharpness or more fish sauce for salt. Serve immediately in deep bowls, scattered with spring onion and fresh coriander; the lemongrass, galangal, and lime leaves are aromatics and are not meant to be eaten."}},{"id":113,"origin":{"ru":"Аргентина","en":"Argentina","ro":"Argentina"},"name":{"ru":"Миланеса","en":"Milanesa","ro":"Milanesa"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"ru":["4 тонких куска говядины (огузок или вырезка), около 150г каждый","2 крупных яйца","2 зубчика чеснока, мелко нарубленных","20г свежей петрушки, мелко нарезанной","150г сухих панировочных сухарей (можно панко для воздушной корочки)","100г пшеничной муки","1 ч. л. соли","1/2 ч. л. свежемолотого чёрного перца","500мл растительного масла для жарки","1 лимон, нарезанный дольками, для подачи"],"en":["4 thin beef steaks (top round or sirloin), about 150g each","2 large eggs","2 garlic cloves, finely minced","20g fresh parsley, finely chopped","150g dried breadcrumbs (panko works for a lighter crust)","100g plain flour","1 tsp salt","1/2 tsp freshly ground black pepper","500ml vegetable oil, for frying","1 lemon, cut into wedges, to serve"],"ro":["4 felii subțiri de vită (vrăbioară sau pulpă), aproximativ 150g fiecare","2 ouă mari","2 căței de usturoi, tocați fin","20g pătrunjel proaspăt, tocat","150g pesmet uscat (eventual panko pentru o crustă mai aerată)","100g făină simplă","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","500ml ulei vegetal, pentru prăjit","1 lămâie, tăiată felii, pentru servit"]},"howIsMade":{"ru":"Положите кусочки говядины между двумя листами плёнки; отбейте молотком до 5 мм толщиной; приправьте половиной соли и перца с обеих сторон. Взбейте яйца в плоской миске с измельчённым чесноком, петрушкой и оставшейся солью и перцем. Подготовьте две плоские тарелки: одну с мукой, другую с сухарями; линия панировки: мука → яичная смесь → сухари. Обваляйте каждый кусок в муке, стряхните излишек, затем в яйце (дайте стечь 2 секунды), затем прижмите в сухарях с обеих сторон; панировка должна полностью покрывать мясо. Дайте панированным кускам отдохнуть на решётке 10 минут — панировка лучше прилипает. Разогрейте 1 см масла в большой сковороде до 175°C (термометром или кубиком хлеба — он должен подрумяниться за 30 секунд). Жарьте куски по одному или по два по 2 минуты с каждой стороны, пока корочка не станет глубоко-золотистой, а мясо мягким; откиньте на решётку над противнем (не на бумагу — корочка размякнет). Подавайте сразу с дольками лимона, выжимая сок поверх корочки прямо перед укусом.","en":"Place the beef slices between two sheets of cling film; pound with a meat mallet until 5 mm thick; season with half the salt and pepper on both sides. Beat the eggs in a wide shallow bowl with the minced garlic, parsley, and the remaining salt and pepper. Set up two shallow plates: one with the flour, one with the breadcrumbs; breading line: flour → beaten egg → breadcrumbs. Dip each slice in flour, shaking off the excess, then in the egg mixture (let it drip for 2 seconds), then press into the breadcrumbs on both sides; the crumbs should fully coat the meat. Let the breaded slices rest on a wire rack for 10 minutes — the breading adheres better this way. Heat 1 cm of oil in a large frying pan to 175°C (use a thermometer or test with a bread cube — it should brown in 30 seconds). Fry the slices one or two at a time for 2 minutes per side, until the crust is deep golden and the meat is tender; drain on a rack over a tray (not on paper — it steams the crust). Serve immediately with lemon wedges to squeeze over the crust just before eating."}},{"id":114,"origin":{"ru":"Камбоджа","en":"Cambodia","ro":"Cambodgia"},"name":{"ru":"Лок лак","en":"Lok Lak","ro":"Lok Lak"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"vietnamese","ingredients":{"ru":["600г говяжьей вырезки или огузка, нарезанных кубиками 2,5 см","3 ст. л. устричного соуса","2 ст. л. соевого соуса","1 ст. л. пальмового сахара (или коричневого)","1 ст. л. томатной пасты","6 зубчиков чеснока, мелко нарубленных","2 ч. л. свежемолотого чёрного перца (с горкой)","3 ст. л. растительного масла","1 крупная луковица, тонко нарезанная","4 яйца (для жарки)","1 небольшой кочан салата (айсберг или ромэн), листья отделены","2 помидора, нарезанных","1 огурец, нарезанный","Для соуса для макания:","сок 2 лаймов","1 ч. л. крупной соли","1/2 ч. л. свежемолотого чёрного перца","паровой рис для подачи"],"en":["600g beef tenderloin or sirloin, cut into 2.5 cm cubes","3 tbsp oyster sauce","2 tbsp soy sauce","1 tbsp palm sugar (or brown sugar)","1 tbsp tomato paste","6 garlic cloves, minced","2 tsp freshly ground black pepper (generous)","3 tbsp vegetable oil","1 large onion, thinly sliced","4 eggs (for frying)","1 small head of lettuce (iceberg or romaine), leaves separated","2 tomatoes, sliced","1 cucumber, sliced","For the dipping sauce:","juice of 2 limes","1 tsp coarse salt","1/2 tsp freshly ground black pepper","steamed rice, to serve"],"ro":["600g vrăbioară sau mușchi de vită, tăiată cuburi de 2,5 cm","3 linguri sos de stridii","2 linguri sos de soia","1 lingură zahăr de palmier (sau zahăr brun)","1 lingură pastă de roșii","6 căței de usturoi, tocați","2 lingurițe piper negru proaspăt măcinat (din belșug)","3 linguri ulei vegetal","1 ceapă mare, tăiată felii subțiri","4 ouă (pentru ochiuri)","1 cap mic de salată verde (iceberg sau romană), frunzele separate","2 roșii, feliate","1 castravete, feliat","Pentru sos:","zeama de la 2 lime","1 linguriță sare grunjoasă","1/2 linguriță piper negru proaspăt măcinat","orez fiert, pentru servit"]},"howIsMade":{"ru":"В миске смешайте говядину с устричным соусом, соевым соусом, пальмовым сахаром, томатной пастой, половиной чеснока и 1 ч; л; чёрного перца; маринуйте при комнатной температуре 30 минут. Приготовьте соус для макания: в небольшой пиале смешайте сок лайма, крупную соль и оставшийся перец. Соберите блюдо для подачи: на большой тарелке выложите листья салата, ломтики помидоров и огурцов. Поджарьте 4 яичницы-глазуньи в сковороде с небольшим количеством масла, оставляя желток жидким; отложите на тёплую тарелку. Разогрейте 3 ст; л; масла в большом воке на сильнейшем огне до лёгкого дымка. Добавьте лук и оставшийся чеснок, обжаривайте 30 секунд до появления аромата. Выложите маринованное мясо одним слоем; не трогайте 1 минуту для образования корочки, затем энергично перемешивайте ещё 2 минуты; мясо должно быть подгоревшим снаружи и розовым внутри — не пережаривайте. Выложите горячее мясо на салат, на каждую порцию положите яичницу; подавайте сразу с соусом из лайма сбоку и паровым рисом для каждого.","en":"In a bowl, combine the beef with oyster sauce, soy sauce, palm sugar, tomato paste, half the garlic, and 1 tsp black pepper; let it marinate at room temperature for 30 minutes. Make the dipping sauce: stir lime juice, coarse salt, and the remaining pepper in a small bowl; set aside. Arrange the serving platter: lettuce leaves, tomato slices, and cucumber slices laid out on a large platter. Fry 4 eggs in a pan with a little oil, leaving the yolks runny; set them aside on a warm plate. Heat 3 tbsp oil in a large wok over very high heat until it just begins to smoke. Add the sliced onion and remaining garlic, stir-fry for 30 seconds, until fragrant. Add the marinated beef in a single layer; leave it untouched for 1 minute to sear, then stir-fry vigorously for 2 more minutes; the beef should be charred outside and pink inside — do not overcook. Spoon the hot beef over the salad platter, place a fried egg on each portion; serve immediately with the lime dipping sauce alongside and steamed rice for each diner."}},{"id":115,"origin":{"ru":"Узбекистан","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"ru":"Манты","en":"Manti","ro":"Manti"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["Для теста:","500г пшеничной муки","250мл тёплой воды","1 яйцо","1 ч. л. соли","Для начинки:","600г говядины или баранины, рубленных ножом (не молотых)","3 крупных луковицы, мелко нарезанные (соотношение лук:мясо 1:1 по объёму — обязательно)","1 ч. л. молотого зира","1 ч. л. свежемолотого чёрного перца","2 ч. л. соли","100г курдючного сала или сала кубиками (по желанию, традиционно)","Для подачи:","100г сливочного масла","200г жирного йогурта (или сметаны)","1 ст. л. сладкой паприки","свежая кинза или петрушка, нарезанная"],"en":["For the dough:","500g all-purpose flour","250ml warm water","1 egg","1 tsp salt","For the filling:","600g coarsely chopped beef or lamb (knife-cut, not ground)","3 large onions, finely chopped (use a 1:1 onion-to-meat ratio by volume — essential)","1 tsp ground cumin","1 tsp freshly ground black pepper","2 tsp salt","100g lamb-tail fat or pork lardons in tiny cubes (optional, traditional)","To serve:","100g butter","200g full-fat yogurt (or sour cream)","1 tbsp sweet paprika","fresh coriander or parsley leaves, chopped"],"ro":["Pentru aluat:","500g făină","250ml apă caldă","1 ou","1 linguriță sare","Pentru umplutură:","600g carne tocată grosier de vită sau miel","3 cepe mari, tăiate fin (foarte importantă proporția 1:1 cu carnea după volum)","1 linguriță chimion măcinat","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare","100g grăsime de coadă de oaie sau slănină tăiată cuburi mici (opțional, dar tradițional)","Pentru servit:","100g unt","200g iaurt gras (sau smântână)","1 lingură boia dulce","frunze de coriandru sau pătrunjel proaspăt, tocate"]},"howIsMade":{"ru":"Приготовьте тесто: в большой миске смешайте муку с солью; взбейте яйцо с тёплой водой и влейте в муку; месите 10 минут до гладкости и эластичности; накройте плёнкой и оставьте отдыхать 30 минут. Приготовьте начинку: смешайте рубленое мясо, лук, зира, соль, перец и курдючное сало (если используете); перемешайте руками до однородности; лук даст сок — оставьте его в фарше. Разделите тесто на 4 части; раскатайте каждую как можно тоньше (1–2 мм); нарежьте на квадраты 10x10 см. На центр каждого квадрата положите щедрую столовую ложку начинки; поднимите четыре угла теста над начинкой и защипните их вверху, затем защипните четыре боковые края, формируя закрытый узелок. Смажьте корзину пароварки маслом; расположите манты в один слой, не касаясь друг друга (они увеличатся в размере). Готовьте на пару 35–40 минут на среднем огне с постоянным кипением воды; тесто станет полупрозрачным и слегка глянцевым. Растопите масло в небольшой кастрюле, вмешайте сладкую паприку; дайте постоять 1 минуту вне огня. Разложите манты на большом блюде, посыпьте петрушкой и полейте паприковым маслом; подавайте с йогуртом в небольшой пиале сбоку.","en":"Make the dough: in a large bowl, combine the flour with salt; beat the egg with warm water and pour over the flour; knead for 10 minutes until smooth and elastic; cover with cling film and rest for 30 minutes. Make the filling: combine the knife-cut meat, onions, cumin, salt, pepper, and lamb-tail fat (if using); mix by hand until uniform; the onions will release liquid — keep it in. Divide the dough into 4 pieces; roll each as thin as possible (1–2 mm); cut into 10x10 cm squares. Place a generous tablespoon of filling in the centre of each square; lift the four corners of the dough up over the filling and pinch them together at the top, then pinch the four side edges closed to form a sealed parcel. Brush a steamer basket with oil; arrange the manti in a single layer, not touching (they will swell as they cook). Steam for 35–40 minutes over medium heat with the water at a steady boil; the dough should become translucent and slightly glossy when done. Melt the butter in a small saucepan, stir in the sweet paprika; let it rest 1 minute off the heat. Arrange the manti on a large platter, scatter with chopped parsley, and spoon the paprika butter over the top; serve with yogurt in a small bowl alongside."}},{"id":116,"origin":{"ru":"Грузия","en":"Georgia","ro":"Georgia"},"name":{"ru":"Чахохбили","en":"Chakhokhbili","ro":"Chakhokhbili"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["1,2кг куриных бёдер и голеней на кости","4 крупные луковицы (около 600г), тонко нарезанные — соотношение лук:курица 1:1 по весу традиционно","6 спелых помидоров (около 700г), очищенных и крупно нарезанных","1 красный болгарский перец, без семян, нарезанный кубиками","6 зубчиков чеснока, мелко нарубленных","2 ст. л. томатной пасты","1 ч. л. хмели-сунели (грузинская смесь специй)","1/2 ч. л. молотого голубого пажитника (уцхо-сунели)","1 ч. л. сушёного чабера или майорана","30г свежей кинзы, листья и стебли отдельно, оба нарезаны","20г свежей петрушки, нарезанной","1 ч. л. соли","свежемолотый чёрный перец","1 ст. л. белого винного уксуса (по желанию, для свежести)","грузинская лепёшка или любой плотный хлеб, для подачи"],"en":["1.2kg bone-in chicken thighs and drumsticks","4 large onions (about 600g), thinly sliced — a 1:1 onion-to-chicken ratio by weight is traditional","6 ripe tomatoes (about 700g), peeled and roughly chopped","1 red bell pepper, deseeded and diced","6 garlic cloves, minced","2 tbsp tomato paste","1 tsp khmeli-suneli (Georgian spice blend)","1/2 tsp ground blue fenugreek (utskho suneli)","1 tsp dried savory or marjoram","30g fresh coriander, leaves and stems separated, both chopped","20g fresh parsley, chopped","1 tsp salt","freshly ground black pepper","1 tbsp white wine vinegar (optional, for brightness)","Georgian flatbread or any sturdy bread, to serve"],"ro":["1,2kg pulpe de pui cu os (pulpe superioare și ciocănele)","4 cepe mari (aproximativ 600g), feliate subțire — raportul 1:1 ceapă:pui după greutate este tradițional","6 roșii coapte (aproximativ 700g), decojite și tăiate grosier","1 ardei kapia roșu, fără semințe, tăiat cuburi","6 căței de usturoi, tocați","2 linguri pastă de roșii","1 linguriță khmeli-suneli (amestec de condimente georgian)","1/2 linguriță schinduf albastru măcinat (utskho suneli)","1 linguriță cimbru de iarnă uscat (sau maghiran)","30g coriandru proaspăt, frunze și tulpini separate, ambele tocate","20g pătrunjel proaspăt, tocat","1 linguriță sare","piper negru proaspăt măcinat","1 lingură oțet de vin alb (opțional, pentru prospețime)","pâine georgiană sau alt tip de pâine rustică, pentru servit"]},"howIsMade":{"ru":"Разогрейте тяжёлую кастрюлю на среднем-сильном огне всухую, без масла; уложите курицу кожей вниз и обжаривайте 6–8 минут с каждой стороны до глубокого золотистого цвета; курица сама выделяет жир — это «сухое обжаривание», определяющее чахохбили. Переложите курицу на тарелку; в кастрюле должно остаться 3–4 ст; л; вытопившегося жира — сохраните его. Всыпьте в этот жир нарезанный лук; готовьте на среднем огне 12–15 минут, часто помешивая, до глубокой золотистой мягкости. Добавьте болгарский перец, половину чеснока, нарезанные стебли кинзы, хмели-сунели, голубой пажитник и чабер; готовьте 2 минуты до появления аромата. Введите томатную пасту и готовьте ещё 2 минуты до потемнения; добавьте нарезанные помидоры и верните курицу с соком обратно в кастрюлю. Уменьшите огонь, накройте крышкой и тушите 35–45 минут, перевернув курицу один раз посередине; курица должна почти отделяться от костей, а помидоры — разойтись в густой блестящий соус. Снимите крышку и потушите ещё 5 минут открытым, если соус нуждается в уплотнении; вмешайте оставшийся чеснок, уксус (если используете) и большую часть нарезанной кинзы и петрушки. Попробуйте, доведите до вкуса солью и перцем; подавайте горячим в неглубоких мисках с грузинской лепёшкой (или любым плотным хлебом) для соуса; сверху посыпьте оставшейся зеленью.","en":"Heat a heavy dry pot over medium-high heat — no oil; lay the chicken pieces skin-side down and cook for 6–8 minutes per side, until deeply golden; the chicken renders its own fat — this is the dry-brown step that defines chakhokhbili. Lift the chicken onto a plate; the pot should hold 3–4 tbsp of rendered fat — keep it. Add the sliced onions to the rendered fat; cook over medium heat for 12–15 minutes, stirring often, until deeply golden and soft. Stir in the bell pepper, half the garlic, the chopped coriander stems, khmeli-suneli, blue fenugreek, and savory; cook 2 minutes, until fragrant. Add the tomato paste and cook 2 more minutes, until it darkens; add the chopped tomatoes and return the chicken with its juices to the pot. Reduce the heat to low, cover, and braise for 35–45 minutes, turning the chicken once halfway; the chicken should be falling off the bone and the tomatoes broken down into a thick, glossy sauce. Lift the lid and simmer uncovered 5 more minutes to thicken the sauce if needed; stir in the remaining garlic, the vinegar (if using), and most of the chopped coriander leaves and parsley. Taste, adjust salt and pepper; serve hot in shallow bowls with Georgian flatbread (or any sturdy bread) to mop up the sauce; scatter the remaining herbs on top."}},{"id":117,"origin":{"ru":"Перу","en":"Peru","ro":"Peru"},"name":{"ru":"Ломо сальтадо","en":"Lomo Saltado","ro":"Lomo Saltado"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"ru":["600г говяжьей вырезки или огузка, нарезанной полосками 1 см толщиной","3 крупных картофелины (около 700г), нарезанных толстым картофелем фри","1 крупная красная луковица, нарезанная дольками толщиной 1 см","2 средних помидора Рома, нарезанных дольками (или толстыми кружками)","1 жёлтый ahi-амарильо (или 1 красный болгарский перец + 1 ч. л. пасты ahi-амарильо)","4 зубчика чеснока, мелко нарубленных","2 ст. л. свежего имбиря, тёртого","3 ст. л. соевого соуса","2 ст. л. красного винного уксуса","30г свежей кинзы, крупно нарезанной","3 ст. л. растительного масла (плюс 500мл для жарки картофеля)","1 ч. л. соли","1/2 ч. л. свежемолотого чёрного перца","400г белого риса басмати, сваренного","1 лайм, нарезанный дольками (по желанию)"],"en":["600g beef sirloin or tenderloin, cut into 1 cm strips","3 large potatoes (about 700g), cut into thick fries","1 large red onion, cut into 1 cm-thick wedges","2 medium Roma tomatoes, cut into wedges (or thick slices)","1 yellow ají amarillo pepper (or 1 red bell pepper + 1 tsp ají amarillo paste)","4 garlic cloves, minced","2 tbsp fresh ginger, grated","3 tbsp soy sauce","2 tbsp red wine vinegar","30g fresh coriander, roughly chopped","3 tbsp vegetable oil (plus 500ml for frying potatoes)","1 tsp salt","1/2 tsp freshly ground black pepper","400g white basmati rice, cooked","1 lime, cut into wedges (optional)"],"ro":["600g vrăbioară sau mușchi de vită, tăiată fâșii de 1 cm grosime","3 cartofi mari (aproximativ 700g), tăiați cartofi prăjiți groși","1 ceapă roșie mare, feliată în pene groase de 1 cm","2 roșii Roma medii, tăiate sferturi (sau felii groase)","1 ardei aji amarillo galben (sau 1 ardei kapia + 1 linguriță pastă aji amarillo)","4 căței de usturoi, tocați","2 linguri ghimbir proaspăt, ras","3 linguri sos de soia","2 linguri oțet de vin roșu","30g coriandru proaspăt, tocat grosier","3 linguri ulei vegetal (plus 500ml pentru cartofi)","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","400g orez basmati alb, gătit","1 lime, tăiat felii (opțional)"]},"howIsMade":{"ru":"Приправьте полоски говядины солью и перцем; дайте им отдохнуть 10 минут при комнатной температуре — лучше прожарятся на сильном огне. Разогрейте 500мл масла в глубокой сковороде до 175°C; обжаривайте картофель 6–7 минут до золотистого хрустящего состояния; откиньте на решётку и слегка посолите горячим. Разогрейте большой вок или чугунную сковороду на сильнейшем огне с 2 ст; л; растительного масла — масло должно слегка дымиться; это критический этап: сковорода должна быть очень горячей для перуанского эффекта «вок-хей». Выложите говядину одним слоем; не трогайте 30 секунд для образования корочки, затем энергично перемешивайте 90 секунд — мясо должно быть подрумяненным снаружи и розовым в центре; переложите на тарелку. В том же воке добавьте ещё 1 ст; л; масла; обжаривайте дольки лука и ahi-амарильо 90 секунд — лук должен остаться хрустящим, не размякнуть. Добавьте чеснок и имбирь, обжаривайте 30 секунд до появления аромата; добавьте помидоры и готовьте 1 минуту — они должны слегка размягчиться, но не развалиться. Влейте соевый соус и красный винный уксус по краю сковороды (они испарятся и дадут ароматный дым); верните мясо с соками и добавьте картофель фри; энергично перемешивайте 30 секунд, чтобы всё пропиталось. Выключите огонь, посыпьте нарезанной кинзой и один раз перемешайте; подавайте сразу на тёплом рисе басмати с дольками лайма сбоку.","en":"Season the beef strips with salt and pepper; let them rest for 10 minutes at room temperature — they will sear better at high heat. Heat 500ml of oil in a deep pan to 175°C; fry the potatoes for 6–7 minutes until golden and crisp; drain on a rack and salt lightly while hot. Heat a large wok or cast-iron pan over very high heat with 2 tbsp of vegetable oil — the oil should just begin to smoke; this is the critical step: the pan must be very hot for the Peruvian \"wok hei\" effect. Add the beef in a single layer; leave untouched for 30 seconds to sear, then stir-fry vigorously for 90 seconds — the beef should be browned outside but still pink in the centre; lift onto a plate. In the same wok, add 1 tbsp more oil; stir-fry the onion wedges and ají amarillo for 90 seconds — the onion should stay crisp, not soft. Add the garlic and ginger, stir-fry for 30 seconds until fragrant; add the tomatoes and cook for 1 minute — they should soften slightly but not break down. Pour the soy sauce and red wine vinegar around the edge of the pan (they will steam and create aromatic smoke); return the beef with its juices and add the fries; toss vigorously for 30 seconds, until everything is coated. Turn off the heat, scatter the chopped coriander, and toss once; serve immediately over warm basmati rice with lime wedges on the side."}},{"id":118,"origin":{"ru":"Марокко","en":"Morocco","ro":"Maroc"},"name":{"ru":"Куриный тажин","en":"Chicken Tagine","ro":"Chicken Tagine"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"ru":["1,2 кг куриных бёдер с кожей и костью (около 8 штук), излишки кожи срезаны","2 крупные жёлтые луковицы (~400 г), одна натёртая на мелкой тёрке для маринада, одна тонко нарезанная для тушения","6 зубчиков чеснока, мелко нарубленных","4 см свежего имбиря, мелко натёртого","1 ч. л. молотого кумина + 1 ч. л. молотого имбиря + 1 ч. л. молотого кориандра + 0,5 ч. л. куркумы + 0,5 ч. л. сладкой паприки + 0,5 ч. л. белого перца + щедрая щепотка нитей шафрана (8-10 нитей, замоченных в 2 ст. л. горячей воды)","1 небольшой пучок свежей кинзы, ~25 г, мелко нарезанной (половина в маринад, половина для подачи)","1 небольшой пучок плосколистной петрушки, ~25 г, мелко нарезанной (половина в маринад, половина для подачи)","1,5 ч. л. соли + 0,5 ч. л. свежемолотого чёрного перца","3 ст. л. оливкового масла + 1 ст. л. несолёного сливочного масла (или смен для самого традиционного вкуса)","2 консервированных лимона, ополоснутых, мякоть удалена, цедра нарезана тонкими полосками (около 80 г цедры)","150 г зелёных марокканских оливок (или сорта Castelvetrano), ополоснутых, крупные — без косточек","400 мл горячей воды или куриного бульона с пониженной солью","Сок половинки свежего лимона (добавляется в конце, для свежести)","Для подачи: тёплая марокканская лепёшка хобз, чтобы собирать соус, или приготовленный на пару кускус"],"en":["1.2 kg bone-in skin-on chicken thighs (about 8 pieces), trimmed of excess skin","2 large yellow onions (~400 g), one finely grated for the marinade, one thinly sliced for the stew base","6 garlic cloves, minced","4 cm fresh ginger, finely grated","1 tsp ground cumin + 1 tsp ground ginger + 1 tsp ground coriander + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground white pepper + a generous pinch of saffron threads (8-10 strands, bloomed in 2 tbsp hot water)","1 small bunch fresh coriander (cilantro), about 25 g, finely chopped (half for the marinade, half for garnish)","1 small bunch flat-leaf parsley, about 25 g, finely chopped (half for the marinade, half for garnish)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","3 tbsp olive oil + 1 tbsp unsalted butter (or smen for the most traditional flavour)","2 preserved lemons, rinsed, flesh discarded, peel cut into thin strips (about 80 g of peel total)","150 g green Moroccan olives (or Castelvetrano), rinsed, pitted if large","400 ml hot water or low-salt chicken stock","Juice of half a fresh lemon (added at the end, to brighten)","To serve: warm khobz flatbread to mop up the sauce, or steamed couscous"],"ro":["1.2 kg pulpe de pui cu os și piele (aproximativ 8 bucăți), curățate de pielea în exces","2 cepe galbene mari (~400 g), una rasă fin pentru marinadă, una tăiată felii subțiri pentru baza tocăniței","6 căței de usturoi, tocați","4 cm ghimbir proaspăt, ras fin","1 linguriță chimion măcinat + 1 linguriță ghimbir măcinat + 1 linguriță coriandru măcinat + 0.5 linguriță turmeric + 0.5 linguriță boia dulce + 0.5 linguriță piper alb măcinat + un vârf generos de șofran (8-10 fire, înflorite în 2 linguri apă fierbinte)","1 legătură mică de coriandru proaspăt (cilantro), ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1 legătură mică de pătrunjel cu frunza lată, ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1.5 linguriță sare + 0.5 linguriță piper negru proaspăt măcinat","3 linguri ulei de măsline + 1 lingură unt nesărat (sau smen pentru aroma cea mai tradițională)","2 lămâi conservate, clătite, pulpa îndepărtată, coaja tăiată fâșii subțiri (aproximativ 80 g de coajă)","150 g măsline verzi marocane (sau Castelvetrano), clătite, fără sâmburi dacă sunt mari","400 ml apă fierbinte sau supă de pui cu puțină sare","Zeama de la jumătate de lămâie proaspătă (adăugată la final, pentru prospețime)","Pentru servit: pâine plată khobz caldă pentru a culege sosul, sau couscous aburit"]},"howIsMade":{"ru":"МАРИНУЕМ КУРИЦУ: в большой миске смешайте натёртый лук, чеснок, имбирь, все сухие специи, замоченный шафран с его водой, половину кинзы, половину петрушки, 1,5 ч. л. соли, 0,5 ч. л. чёрного перца и 1,5 ст. л. оливкового масла. Добавьте куриные бёдра и тщательно вотрите маринад в кожу и под неё. Накройте и поставьте в холодильник минимум на 1 час; 4 часа заметно лучше, ночь — идеально.\n\nОБЖАРИВАЕМ И СТРОИМ ОСНОВУ: разогрейте оставшиеся 1,5 ст. л. масла и сливочное масло в таджине или тяжёлой кастрюле на среднем огне. Добавьте нарезанный лук и тушите 8 минут, помешивая, до мягкости и лёгкой золотистости. Сдвиньте лук в сторону, положите бёдра кожей вниз и обжарьте 3-4 минуты до тёмно-золотистой корочки, затем переверните.\n\nТУШИМ: соскребите весь маринад из миски в кастрюлю. Влейте 400 мл горячей воды или бульона. Доведите до лёгкого кипения, накройте и убавьте огонь до минимума. Готовьте 30 минут — конический колпак улавливает пар, который и определяет таджин.\n\nДОБАВЛЯЕМ ЛИМОН И ОЛИВКИ: приподнимите крышку, разложите полоски лимонной цедры и зелёные оливки вокруг (не сверху) курицы — оба компонента отдают рассол, поэтому не мешайте резко. Накройте и готовьте ещё 10-15 минут, пока курица не покажет 75 °C в самой толстой части, а соус не станет блестящим и слегка густым, обволакивающим тыльную сторону ложки.\n\nЗАВЕРШАЕМ И ПОДАЁМ: снимите крышку, выжмите сок половины свежего лимона и посыпьте оставшейся кинзой и петрушкой. Перед тем как солить, попробуйте — солёные лимоны и оливки уже добавляют соль. Подавайте прямо из таджина с тёплой марокканской лепёшкой хобз для соуса или с кускусом на пару.","en":"MARINATE THE CHICKEN: in a large bowl combine the grated onion, garlic, ginger, all the dry spices, the bloomed saffron with its water, half the chopped coriander, half the parsley, 1.5 tsp salt, 0.5 tsp black pepper and 1.5 tbsp olive oil. Add the chicken thighs and massage the marinade thoroughly into and under the skin. Cover and refrigerate at least 1 hour; 4 hours is markedly better, overnight is best.\n\nSEAR AND BUILD THE BASE: heat the remaining 1.5 tbsp olive oil and the butter in a tagine vessel or wide heavy-bottomed pot over medium heat. Add the sliced onion and cook 8 minutes, stirring, until soft and lightly golden. Push the onions to one side, lay the marinated chicken skin-side down and sear 3-4 minutes until the skin is deep golden, then flip.\n\nSIMMER: scrape every drop of marinade from the bowl into the pot. Pour in the 400 ml hot water or stock. Bring to a gentle simmer, then cover and reduce the heat to its lowest setting. Cook 30 minutes — the conical lid traps the steam that defines a tagine.\n\nADD PRESERVED LEMON AND OLIVES: lift the lid, tuck the preserved-lemon strips and green olives around (not on top of) the chicken — both release brine, so resist the urge to stir vigorously. Re-cover and cook 10-15 minutes more, until the chicken reads 75 °C / 170 °F at the thickest part and the sauce has reduced to a glossy, brothy consistency that coats the back of a spoon.\n\nFINISH AND SERVE: uncover, squeeze the half-lemon juice over the dish, and scatter the reserved coriander and parsley on top. Taste before salting — preserved lemons and olives both contribute salt, so the dish often needs nothing more. Serve straight from the tagine with warm khobz flatbread to mop up the sauce, or alongside steamed couscous."}},{"id":120,"origin":{"ru":"Венесуэла","en":"Venezuela","ro":"Venezuela"},"name":{"ru":"Арепа","en":"Arepa","ro":"Arepa"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"latin","ingredients":{"ru":["Для теста:","400г harina P.A.N. (предварительно приготовленная белая кукурузная мука)","500мл тёплой воды","1 ч. л. соли","2 ст. л. растительного масла","Для reina pepiada (классическая начинка курица-авокадо):","2 куриные грудки (около 500г), отварные и разобранные на волокна","1 спелый авокадо, нарезанный кубиками","3 ст. л. майонеза","1 ст. л. сока лайма","1 зелёный лук, тонко нарезанный","10г свежей кинзы, нарезанной","соль и перец","Другие популярные начинки:","200г свежего белого сыра (queso fresco), нарезанного","100г тушёной говядины (carne mechada)","растительное масло для сковороды"],"en":["For the dough:","400g harina P.A.N. (pre-cooked white corn flour)","500ml warm water","1 tsp salt","2 tbsp vegetable oil","For reina pepiada (classic chicken-avocado filling):","2 chicken breasts (about 500g), poached and shredded","1 ripe avocado, diced","3 tbsp mayonnaise","1 tbsp lime juice","1 spring onion, finely sliced","10g fresh coriander, chopped","salt and pepper","Other popular fillings:","200g fresh white cheese (queso fresco), sliced","100g shredded beef (carne mechada)","vegetable oil for griddle"],"ro":["Pentru aluat:","400g harina P.A.N. (făină de porumb pre-fiartă)","500ml apă caldă","1 linguriță sare","2 linguri ulei vegetal","Pentru reina pepiada (umplutura clasică):","2 piepți de pui (aproximativ 500g), fierți și mărunțiți","1 avocado copt, tăiat cuburi","3 linguri maioneză","1 lingură zeamă de lime","1 ceapă verde, tăiată fin","10g coriandru proaspăt, tocat","sare și piper","Alte umpluturi populare:","200g brânză albă proaspătă (queso fresco), feliată","100g carne de vită mărunțită (carne mechada)","ulei vegetal pentru prăjit pe plită"]},"howIsMade":{"ru":"В большой миске смешайте 500мл тёплой воды с солью и маслом; постепенно добавьте 400г harina P.A.N., перемешивая рукой или лопаткой. Месите 3–4 минуты до гладкости и податливости; накройте полотенцем и дайте отдохнуть 5 минут — мука впитает воду, тесто станет легче формовать. Проверьте тесто: оно должно быть слегка липким, но не сырым; если трескается при формовке, добавьте ещё одну столовую ложку воды. Разделите на 8 равных шариков (около 100г каждый); сплющите каждый между ладонями в диск 8 см в диаметре и 1,5 см толщиной, разглаживая края влажными пальцами. Разогрейте тяжёлую сковороду или плансу на среднем огне с небольшим количеством масла; положите арепы и обжаривайте 4–5 минут с каждой стороны до образования золотистой корочки с тёмными пятнами. Переложите на противень и доведите в духовке при 180°C 10–15 минут, пока при лёгком постукивании не раздастся пустой звук; это тест готовности. Пока арепы отдыхают, приготовьте reina pepiada: смешайте разобранную курицу с авокадо, майонезом, соком лайма, зелёным луком, кинзой, солью и перцем. Острым ножом надрежьте каждую арепу горизонтально (как карман пита), не разделяя полностью; наполните reina pepiada (или другой начинкой); подавайте сразу, пока арепа тёплая и хрустящая снаружи.","en":"In a large bowl, combine 500ml warm water with salt and oil; gradually add 400g harina P.A.N., mixing with your hand or a spatula. Knead for 3–4 minutes until the dough is smooth and pliable; cover with a cloth and let it rest for 5 minutes — the flour absorbs the water and the dough becomes easier to shape. Test the dough: it should be slightly sticky but not raw; if it cracks while shaping, add a tablespoon more water. Divide into 8 equal balls (about 100g each); flatten each between your palms into a 8 cm wide, 1.5 cm thick disc, smoothing the edges with damp fingers. Heat a heavy pan or griddle over medium heat with a little oil; add the arepas and cook for 4–5 minutes per side, until a golden crust with darker spots forms. Transfer to a baking tray and finish in a preheated 180°C oven for 10–15 minutes, until they sound hollow when tapped lightly; this is the doneness test. While the arepas rest, make the reina pepiada: mix the shredded chicken with avocado, mayonnaise, lime juice, spring onion, coriander, salt, and pepper. Slice each arepa horizontally with a sharp knife (like a pita pocket), without cutting all the way through; stuff with reina pepiada (or your chosen filling); serve immediately while the arepa is warm and crisp on the outside."}},{"id":121,"origin":{"ru":"Финляндия","en":"Finland","ro":"Finlanda"},"name":{"ru":"Карельский пирог","en":"Karelian Pie","ro":"Karjalanpiirakka"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ru":["Для теста:","150г ржаной муки","100г пшеничной белой муки","150мл холодной воды","1/2 ч. л. соли","1 ст. л. растительного масла","Для рисовой начинки:","200г круглозёрного риса (для пудинга)","1 литр цельного молока","1/2 ч. л. соли","20г сливочного масла","Для muna voi (яичное масло, классическая подача):","100г мягкого несолёного масла","2 яйца, сваренных вкрутую, очищенных и мелко нарубленных","1/4 ч. л. соли","1/4 ч. л. белого перца"],"en":["For the dough:","150g rye flour","100g plain white flour","150ml cold water","1/2 tsp salt","1 tbsp vegetable oil","For the rice porridge filling:","200g short-grain rice (pudding rice)","1 litre whole milk","1/2 tsp salt","20g butter","For muna voi (egg butter, classic topping):","100g soft unsalted butter","2 hard-boiled eggs, peeled and finely chopped","1/4 tsp salt","1/4 tsp white pepper"],"ro":["Pentru aluat:","150g făină de secară","100g făină albă","150ml apă rece","1/2 linguriță sare","1 lingură ulei vegetal","Pentru umplutura de orez:","200g orez cu bob rotund (orez pudding)","1 litru lapte integral","1/2 linguriță sare","20g unt","Pentru muna voi (untul de ouă pentru servire):","100g unt moale","2 ouă fierte tari, decojite și tocate fin","1/4 linguriță sare","1/4 linguriță piper alb"]},"howIsMade":{"ru":"Приготовьте рисовую кашу (можно сделать накануне): соедините 200г риса с 250мл горячей воды в кастрюле; варите 8 минут на среднем огне до впитывания воды. Добавьте 1 литр молока и 1/2 ч; л; соли; варите на медленном огне, часто помешивая, 35–45 минут до очень кремовой и густой каши; вмешайте 20г сливочного масла и полностью охладите. Для теста: смешайте ржаную муку, белую муку и соль в миске; добавьте холодную воду и масло, месите 5 минут до плотного, но эластичного теста. Разделите тесто на 16 равных частей и скатайте в шарики; на поверхности, посыпанной ржаной мукой, раскатайте каждый шарик в очень тонкий овал (1 мм толщиной, 12 см длиной). Положите 1–2 ст; л; холодной каши в центр каждого овала, оставляя 2 см бортика. Поднимите тесто с обеих длинных сторон над начинкой, оставив центр открытым; защипывайте тесто пальцами, создавая характерные зигзагообразные складки — это традиционный карельский шов. Разложите пирожки на противне с пергаментом; выпекайте в духовке, разогретой до 250°C, 15–20 минут, пока края не подрумянятся. Пока пирожки пекутся, приготовьте muna voi: разотрите мягкое масло с нарезанными яйцами, солью и белым перцем; подавайте пирожки тёплыми, щедро намазав muna voi на открытую рисовую поверхность.","en":"Make the rice porridge (can be made a day ahead): combine 200g rice with 250ml hot water in a pot; cook 8 minutes over medium heat, until the water is absorbed. Add 1 litre milk and 1/2 tsp salt; simmer over low heat, stirring often, for 35–45 minutes, until the porridge is very creamy and thick; stir in 20g butter and cool completely. For the dough: combine rye flour, white flour, and salt in a bowl; add cold water and oil, knead for 5 minutes until firm but elastic. Divide the dough into 16 equal pieces and roll into balls; on a rye-floured surface, roll each ball into a very thin oval (1 mm thick, 12 cm long). Spoon 1–2 tbsp cold rice porridge into the centre of each oval, leaving a 2 cm border. Lift the dough over the filling on both long sides, leaving the centre exposed; pinch the dough with your fingers to create the characteristic zigzag pleats — this is the traditional Karelian seal. Arrange the pies on a lined baking tray; bake in a preheated 250°C oven for 15–20 minutes, until the edges are golden brown. While the pies bake, make muna voi: mash the soft butter with the chopped eggs, salt, and white pepper; serve the pies warm, generously spread with muna voi over the exposed rice surface."}},{"id":123,"origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Паста э фаджоли","en":"Pasta e fagioli","ro":"Pasta e fagioli"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"ru":["200г короткой пасты (диталини, тубетти или орекьетте)","400г консервированной фасоли борлотти или каннеллини, откинутой (или 200г сухой, замоченной на ночь и сваренной)","1 крупная луковица, мелко нарезанная","2 моркови, мелко нарезанные кубиками","2 стебля сельдерея, мелко нарезанные кубиками","3 зубчика чеснока, мелко нарубленных","100г панчетты или бекона, нарезанных кубиками (по желанию)","400г резаных томатов в банке","2 ст. л. томатной пасты","1 лавровый лист","1 веточка свежего розмарина","1 веточка свежего тимьяна","1,2 литра горячего куриного или овощного бульона","4 ст. л. оливкового масла extra virgin","1 кусок корочки пармезана (по желанию, для аромата)","соль и свежемолотый чёрный перец","тёртый пармезан и оливковое масло extra virgin для подачи"],"en":["200g short pasta (ditalini, tubetti, or orecchiette)","400g canned borlotti or cannellini beans, drained (or 200g dried, soaked overnight and cooked)","1 large onion, finely chopped","2 carrots, finely diced","2 celery stalks, finely diced","3 garlic cloves, minced","100g pancetta or bacon, diced (optional)","400g canned chopped tomatoes","2 tbsp tomato paste","1 bay leaf","1 sprig fresh rosemary","1 sprig fresh thyme","1.2L hot chicken or vegetable stock","4 tbsp extra-virgin olive oil","1 piece Parmigiano rind (optional, for flavour)","salt and freshly ground black pepper","grated Parmigiano and extra-virgin olive oil, to serve"],"ro":["200g paste scurte (ditalini, tubetti sau orecchiette)","400g fasole borlotti sau cannellini din conservă, scurse (sau 200g fasole uscată înmuiată peste noapte și fiartă)","1 ceapă mare, tocată fin","2 morcovi, tăiați cuburi mici","2 tulpini de țelină, tăiate cuburi mici","3 căței de usturoi, tocați","100g pancetta sau bacon, tăiat cuburi (opțional)","400g roșii sfărâmate din conservă","2 linguri pastă de roșii","1 frunză de dafin","1 crenguță de rozmarin proaspăt","1 crenguță de cimbru proaspăt","1,2 litri supă de pui sau legume fierbinte","4 linguri ulei de măsline extravirgin","1 bucată coajă de Parmigiano (opțional, pentru aromă)","sare și piper negru proaspăt măcinat","Parmigiano ras și ulei de măsline extravirgin, pentru servit"]},"howIsMade":{"ru":"В большой кастрюле с толстым дном разогрейте 3 ст; л; оливкового масла на среднем огне; добавьте кубики панчетты (если используете) и готовьте 5 минут до подрумянивания и вытапливания жира. Всыпьте лук, морковь, сельдерей и щепотку соли; обжаривайте 10–12 минут до мягкости и лёгкой карамелизации — это соффритто, ароматическая основа. Вмешайте чеснок, томатную пасту, розмарин и тимьян; готовьте 2 минуты до потемнения пасты. Добавьте резаные томаты, лавровый лист и корочку пармезана (если используете); варите 5 минут на среднем огне. Половину фасоли добавьте целиком, другую половину разомните вилкой или венчиком (традиционная текстура требует обоих); влейте 1,2л горячего бульона; доведите до кипения. Добавьте пасту и варите 8–10 минут на среднем огне, часто помешивая, до состояния al dente; жидкость загустеет от выделяющегося крахмала. Попробуйте и при необходимости подсолите; удалите корочку пармезана, розмарин и тимьян; дайте супу отдохнуть 5 минут — он ещё загустеет до плотного кремового рагу. Подавайте горячим в глубоких мисках; венчайте щедрым свежемолотым чёрным перцем, обильной горкой тёртого пармезана и финальной струйкой оливкового масла extra virgin.","en":"In a large heavy-bottomed pot, heat 3 tbsp olive oil over medium heat; add the diced pancetta (if using) and cook for 5 minutes, until browned and the fat has rendered. Add the onion, carrots, celery and a pinch of salt; sauté for 10–12 minutes, until soft and lightly caramelised — this is the soffritto, the aromatic foundation. Stir in the garlic, tomato paste, rosemary, and thyme; cook for 2 minutes, until the paste darkens. Add the chopped tomatoes, bay leaf, and Parmigiano rind (if using); simmer for 5 minutes over medium heat. Add half the beans whole and the other half mashed with a fork or hand whisk (the traditional texture calls for both); pour in 1.2L hot stock; bring to a boil. Add the pasta and cook for 8–10 minutes over medium heat, stirring often, until al dente; the liquid will thicken as the pasta releases starch. Taste and adjust salt; remove the Parmigiano rind, rosemary, and thyme stems; let the soup rest 5 minutes — it will thicken further into a dense, creamy stew. Serve hot in deep bowls; crown with generous fresh black pepper, a heavy drift of grated Parmigiano, and a final drizzle of extra-virgin olive oil."}},{"id":124,"origin":{"ru":"Шри-Ланка","en":"Sri Lanka","ro":"Sri Lanka"},"name":{"ru":"Котту","en":"Kottu","ro":"Kottu"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"ru":["8 лепёшек годхамба роти или парата (около 640 г в общей сложности), нарезанных тонкими полосками шириной 1 см","600 г куриного бедра без кости и кожи, нарезанного кусочками по 1,5 см","5 крупных яиц, слегка взбитых со щепоткой соли","2 средние красные луковицы (около 240 г), тонко нашинкованные","1 крупный лук-порей (около 200 г), очищенный, тонко нарезанный и промытый","2 небольшие морковки (около 140 г), нарезанные жульеном","3 свежих зелёных перца чили, тонко нарезанных (без семян для более мягкой остроты)","2 ст. л. свежего имбиря, мелко натёртого","5 зубчиков чеснока, мелко нарезанных","2 ч. л. шри-ланкийского карри-порошка","1 ч. л. молотой куркумы","2 ч. л. кашмирского чили-порошка или сладкой паприки","15 свежих листьев карри","400 мл тёплого куриного или кокосового карри-соуса","3 ст. л. соевого соуса","4 ст. л. кокосового или растительного масла","1,5 ч. л. соли, плюс по вкусу","2 ст. л. сока лайма, для финиша"],"en":["8 godhamba roti or paratha (about 640 g total), thinly sliced into 1 cm-wide strips","600 g boneless, skinless chicken thigh, cut into 1.5 cm pieces","5 large eggs, lightly beaten with a pinch of salt","2 medium red onions (about 240 g), thinly sliced","1 large leek (about 200 g), trimmed, thinly sliced, and washed","2 small carrots (about 140 g), julienned","3 fresh green chillies, finely sliced (seeded for a milder finish)","2 tbsp finely grated fresh ginger","5 garlic cloves, finely chopped","2 tsp Sri Lankan curry powder","1 tsp ground turmeric","2 tsp Kashmiri chilli powder or sweet paprika","15 fresh curry leaves","400 ml warm chicken or coconut curry sauce","3 tbsp soy sauce","4 tbsp coconut or vegetable oil","1.5 tsp salt, plus more to taste","2 tbsp lime juice, to finish"],"ro":["8 lipii godhamba sau paratha (aproximativ 640 g în total), tăiate în fâșii subțiri de 1 cm lățime","600 g pulpă de pui dezosată, fără piele, tăiată în bucăți de 1,5 cm","5 ouă mari, bătute ușor cu un praf de sare","2 cepe roșii medii (aproximativ 240 g), feliate subțire","1 praz mare (aproximativ 200 g), curățat, feliat subțire și spălat","2 morcovi mici (aproximativ 140 g), tăiați julienne","3 ardei iuți verzi proaspeți, feliați subțire (fără semințe pentru un gust mai blând)","2 linguri ghimbir proaspăt, ras fin","5 căței de usturoi, tocați fin","2 lingurițe pudră de curry srilankez","1 linguriță turmeric măcinat","2 lingurițe pudră de ardei iute Kashmiri sau boia dulce","15 frunze de curry proaspete","400 ml sos de curry de pui sau de cocos, cald","3 linguri sos de soia","4 linguri ulei de cocos sau vegetal","1,5 lingurițe sare, plus după gust","2 linguri suc de lime, pentru finisare"]},"howIsMade":{"ru":"Разогрейте 1 ст; л; масла в большой сковороде или воке на среднем-сильном огне; приправьте курицу 0,5 ч; л; соли и щепоткой карри-порошка; готовьте 7–8 минут, периодически помешивая, до лёгкой золотистой корочки и полной готовности (без розового в центре); переложите на тарелку. Добавьте оставшиеся 3 ст; л; масла в ту же сковороду; когда оно заблестит, всыпьте листья карри — они потрескают 5–10 секунд; добавьте нарезанный красный лук и обжаривайте 3–4 минуты, пока он не размягчится и края не станут прозрачными, но он будет ещё плотным. Добавьте лук-порей, морковь и зелёный перец чили и обжаривайте 2–3 минуты — овощи должны оставаться хрустяще-нежными, не мягкими. Сдвиньте овощи на один край сковороды; в освободившееся место добавьте имбирь и чеснок и готовьте 30 секунд до появления аромата, но не до подрумянивания; вмешайте оставшийся карри-порошок, куркуму и кашмирский чили-порошок; прогрейте 20–30 секунд до раскрытия аромата. Вылейте взбитые яйца в центр сковороды и аккуратно перемешивайте 60–90 секунд, пока они не схватятся, но останутся блестящими — разбейте массу на мелкие кусочки лопаткой. Верните курицу в сковороду вместе с нарезанным роти; перемешайте всё 1–2 минуты, чтобы роти впитал цвет специй и куриного сока. Влейте соевый соус и тёплый карри-соус по краю сковороды; двумя металлическими лопаточками (или обратной стороной тяжёлой деревянной ложки) рубите-перемешивайте смесь энергично 3–4 минуты — продолжайте резать кучу, чтобы полоски роти распадались на мелкие неровные кусочки и впитывали соус; смесь должна выглядеть блестящей и однородной, не водянистой. Попробуйте и при необходимости добавьте соли; выжмите сок лайма, перемешайте ещё раз и подавайте сразу, пока котту ещё парит, с дополнительной ложкой карри-соуса сбоку.","en":"Heat 1 tbsp of the oil in a large skillet or wok over medium-high heat; season the chicken with 0.5 tsp of the salt and a pinch of the curry powder; cook for 7–8 minutes, stirring occasionally, until lightly golden and just cooked through (no pink in the centre); transfer to a plate. Add the remaining 3 tbsp of oil to the same pan; when shimmering, add the curry leaves — they will crackle for 5–10 seconds; add the sliced red onions and cook for 3–4 minutes until softened and translucent at the edges but still firm. Add the leek, carrots, and green chillies and stir-fry for 2–3 minutes — the vegetables should remain crisp-tender, not soft. Push the vegetables to one side of the pan; add the ginger and garlic to the open space and cook for 30 seconds, until fragrant but not browned; stir in the remaining curry powder, the turmeric, and the Kashmiri chilli powder; toast for 20–30 seconds until aromatic. Pour the beaten eggs into the centre of the pan and gently scramble for 60–90 seconds until set but still glossy — break the curd into small pieces with the spatula. Return the chicken to the pan along with the sliced roti; toss everything together for 1–2 minutes so the roti picks up colour from the spices and chicken juices. Pour the soy sauce and warm curry sauce around the edge of the pan; use two metal spatulas (or the back of a heavy wooden spoon) and chop-and-toss the mixture vigorously for 3–4 minutes — keep cutting through the pile so the roti strips break down into small irregular pieces and soak up the sauce; the mixture should look glossy and unified, not soupy. Taste and add more salt if needed; squeeze over the lime juice, toss once more, and serve immediately while the kottu still steams, with an extra ladle of curry sauce on the side."}},{"id":125,"origin":{"ru":"Латвия","en":"Latvia","ro":"Letonia"},"name":{"ru":"Пираги","en":"Piragi","ro":"Piragi"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"servings":8,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["500 г сильной пшеничной муки для хлеба, плюс для подсыпания","250 мл цельного молока, слегка подогретого до 38°C","1 пакетик 7 г (2 ч. л.) сухих быстрых дрожжей","50 г сахарного песка","1 ч. л. мелкой морской соли","70 г несолёного сливочного масла, растопленного и слегка остывшего","1 крупное яйцо, слегка взбитое","350 г копчёной полосатой грудинки (или копчёного шпика), нарезанной кубиками 5 мм","1 крупная луковица (около 180 г), очень мелко нарезанная","1 ст. л. нейтрального масла (только если бекон очень постный)","0,5 ч. л. свежемолотого чёрного перца","Щепотка семян тмина, слегка раздавленных (по желанию)","1 крупный желток, взбитый с 1 ст. л. молока, для смазывания","Хлопья морской соли, для посыпки (по желанию)"],"en":["500 g strong white bread flour, plus extra for dusting","250 ml whole milk, gently warmed to 38°C","7 g sachet (2 tsp) instant dry yeast","50 g caster sugar","1 tsp fine sea salt","70 g unsalted butter, melted and slightly cooled","1 large egg, lightly beaten","350 g smoked streaky bacon (or smoked speck), in small 5 mm dice","1 large onion (about 180 g), very finely diced","1 tbsp neutral oil (only if the bacon is very lean)","0.5 tsp freshly ground black pepper","Pinch of caraway seeds, lightly crushed (optional)","1 large egg yolk beaten with 1 tbsp milk, for glazing","Flaky sea salt, for sprinkling (optional)"],"ro":["500 g făină albă de pâine, plus pentru tăvălit","250 ml lapte integral, încălzit ușor la 38°C","1 plic de 7 g (2 lingurițe) drojdie instant uscată","50 g zahăr tos","1 linguriță sare fină de mare","70 g unt nesărat, topit și ușor răcit","1 ou mare, bătut ușor","350 g bacon afumat (sau speck afumat), tăiat cuburi mici de 5 mm","1 ceapă mare (aproximativ 180 g), tocată foarte fin","1 lingură ulei neutru (doar dacă baconul este foarte slab)","0,5 linguriță piper negru proaspăt măcinat","Un vârf de semințe de chimen, ușor zdrobite (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru glazură","Fulgi de sare de mare, pentru presărat (opțional)"]},"howIsMade":{"ru":"Влейте тёплое молоко в большую миску, посыпьте сверху дрожжами и сахаром и слегка размешайте; дайте постоять 5–10 минут до образования пены на поверхности — это подтверждает, что дрожжи живые. Добавьте растопленное масло, взбитое яйцо и соль в молоко; всыпьте муку и перемешайте деревянной ложкой до образования лохматого теста; выложите на слегка подпылённую мукой поверхность и месите 8–10 минут до гладкости, эластичности и лишь лёгкой липкости. Сформуйте тесто в шар, переложите в слегка смазанную маслом миску, накройте влажным полотенцем и оставьте подходить в тёплом месте на 1 час — 1 час 15 минут, до удвоения объёма. Тем временем приготовьте начинку; обжаривайте нарезанный кубиками бекон в сухой сковороде на среднем огне 5–6 минут, часто помешивая, пока жир не вытопится, а края не начнут лишь чуть румяниться — бекон не должен стать хрустящим; добавьте лук (и масло при необходимости) и готовьте ещё 4–5 минут до прозрачности лука, без подрумянивания; приправьте перцем и тмином; полностью остудите. Обомните подошедшее тесто и разделите на 24 равные части (около 35 г каждая); скатайте каждую в гладкий шарик, затем раскатайте скалкой в овал 8 см толщиной около 4 мм. Положите 1 ч; л; остывшей начинки на одну половину каждого овала, сложите тесто и плотно защипите края для герметичности; аккуратно потяните запечатанные концы друг к другу, чтобы получилась классическая форма полумесяца, со швом вниз на противне. Разложите пираги на двух противнях, застеленных пергаментом, с расстоянием 3 см; слегка накройте и оставьте подходить ещё 20–25 минут, пока они заметно не вспухнут; тем временем разогрейте духовку до 220°C (425°F / конвекция 200°C). Смажьте верх желтковой глазурью, посыпьте хлопьями соли по желанию и выпекайте 12–15 минут — они готовы, когда верх насыщенно-золотистый, швы крепко держатся, а дно при постукивании звучит полым; остудите на решётке 5 минут и подавайте тёплыми.","en":"Pour the warm milk into a large bowl, scatter the yeast and sugar over it, and stir lightly; let stand 5–10 minutes until foamy on the surface — this confirms the yeast is alive. Add the melted butter, beaten egg, and salt to the milk; pour in the flour and stir with a wooden spoon until a shaggy dough forms; tip onto a lightly floured surface and knead for 8–10 minutes, until smooth, elastic, and only slightly tacky to the touch. Shape the dough into a ball, place it in a lightly oiled bowl, cover with a damp cloth, and leave to rise in a warm spot for 1 hour to 1 hour 15 minutes, until doubled. Meanwhile, prepare the filling; cook the diced bacon in a dry frying pan over medium heat for 5–6 minutes, stirring often, until the fat has rendered and the edges just begin to colour but the bacon is not crisp; add the onion (and the oil if needed) and cook for another 4–5 minutes, until the onion is translucent but not browned; season with the pepper and caraway; cool completely. Knock back the risen dough and divide it into 24 equal pieces (about 35 g each); roll each piece into a smooth ball, then flatten with a rolling pin into an 8 cm oval, about 4 mm thick. Spoon 1 tsp of cold filling onto one half of each oval, fold the dough over to enclose, and pinch the edges firmly to seal; pull the sealed ends gently toward each other to form the classic crescent shape, with the seam facing down on the tray. Arrange the piragi on two parchment-lined trays, leaving 3 cm between them; cover lightly and let rise for another 20–25 minutes, until visibly puffy; meanwhile heat the oven to 220°C (425°F / fan 200°C). Brush the tops with the egg-yolk glaze, sprinkle with flaky salt if using, and bake for 12–15 minutes — they are ready when the tops are deep golden brown, the seams hold tight, and the bottoms sound hollow when tapped; cool on a rack for 5 minutes and serve warm."}},{"id":126,"origin":{"ru":"Вьетнам","en":"Vietnam","ro":"Vietnam"},"name":{"ru":"Бань сео","en":"Banh Xeo","ro":"Bánh xèo"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"vietnamese","ingredients":{"ru":["250 г рисовой муки","30 г кукурузного крахмала","1 ч. л. молотой куркумы","0,5 ч. л. мелкой морской соли, плюс ещё для свинины","1 ч. л. сахарного песка","400 мл жирного кокосового молока","350 мл холодной газированной воды (или холодной негазированной воды)","4 зелёных лука, зелёные части тонко нарезанные (около 30 г)","300 г свиной грудинки или лопатки, нарезанной полосками толщиной 5 мм","300 г сырых очищенных креветок (около 24 средних), без жилки","200 г свежих ростков маша","1 средняя луковица (около 120 г), тонко нарезанная","60 мл нейтрального масла (арахисового или растительного), для жарки","1 ст. л. рыбного соуса, плюс 3 ст. л. для нуок-чам","3 ст. л. свежего сока лайма","2 ст. л. сахарного песка (для нуок-чам)","1 зубчик чеснока мелко нарезанный и 1 маленький красный чили тонко нарезанный (для нуок-чам)","1 кочан масляного или римского салата, листья разделены, плюс большой пучок свежих трав (мята, перилла, кинза, тайский базилик) и 1 огурец, нарезанный жульеном, для подачи"],"en":["250 g rice flour","30 g cornflour (cornstarch)","1 tsp ground turmeric","0.5 tsp fine sea salt, plus more for the pork","1 tsp caster sugar","400 ml full-fat coconut milk","350 ml cold sparkling water (or cold still water)","4 spring onions, green tops finely sliced (about 30 g)","300 g pork belly or shoulder, cut into 5 mm-thick strips","300 g raw peeled prawns (about 24 medium), deveined","200 g fresh mung bean sprouts","1 medium onion (about 120 g), thinly sliced","60 ml neutral oil (peanut or vegetable), for frying","1 tbsp fish sauce, plus 3 tbsp for the nuoc cham","3 tbsp fresh lime juice","2 tbsp caster sugar (for the nuoc cham)","1 garlic clove, finely minced, and 1 small red chilli, finely sliced (for the nuoc cham)","1 head butter lettuce or romaine, leaves separated, plus a large bunch of fresh herbs (mint, perilla, coriander, Thai basil) and 1 cucumber, julienned, to serve"],"ro":["250 g făină de orez","30 g amidon de porumb","1 linguriță turmeric măcinat","0,5 linguriță sare fină de mare, plus în plus pentru carnea de porc","1 linguriță zahăr tos","400 ml lapte de cocos integral","350 ml apă minerală rece (sau apă plată rece)","4 cepe verzi, părțile verzi feliate subțire (aproximativ 30 g)","300 g piept sau pulpă de porc, tăiat fâșii de 5 mm grosime","300 g creveți cruzi decojiți (aproximativ 24 medii), curățați de venă","200 g germeni proaspeți de fasole mung","1 ceapă medie (aproximativ 120 g), feliată subțire","60 ml ulei neutru (de arahide sau vegetal), pentru prăjit","1 lingură sos de pește, plus 3 linguri pentru nuoc cham","3 linguri suc de lime proaspăt","2 linguri zahăr tos (pentru nuoc cham)","1 cățel de usturoi tocat fin și 1 ardei iute roșu mic feliat subțire (pentru nuoc cham)","1 căpățână de salată verde de unt sau romană, frunze separate, plus o legătură mare de ierburi proaspete (mentă, perilla, coriandru, busuioc thailandez) și 1 castravete tăiat julienne, pentru servit"]},"howIsMade":{"ru":"Приготовьте тесто минимум за 30 минут; в большой миске взбейте венчиком рисовую муку, кукурузный крахмал, куркуму, 0,5 ч; л; соли и 1 ч; л; сахара; влейте кокосовое молоко и газированную воду и взбивайте до гладкости; добавьте зелёные части лука; накройте и оставьте в холодильнике минимум 30 минут (до 4 часов) — выстаивание гидрирует муку для более хрустящего блина. Пока тесто отдыхает, смешайте нуок-чам; в миске размешайте 3 ст; л; рыбного соуса, 3 ст; л; сока лайма, 2 ст; л; сахара и 4 ст; л; тёплой воды, пока сахар не растворится; добавьте чеснок и чили; отложите. Полоски свинины смешайте с 1 ст; л; рыбного соуса и 0,5 ч; л; перца; креветки промойте и обсушите; промойте ростки и стряхните воду; выложите салат, травы и огурец на блюдо для подачи. Разогрейте 24-сантиметровую антипригарную сковороду на среднем-сильном огне; добавьте 1 ч; л; масла, распределите его, затем положите 2–3 креветки и горсть полосок свинины; обжаривайте 60–90 секунд, пока креветки не свернутся и не порозовеют, а края свинины подрумянятся, не дойдя до полной готовности. Размешайте тесто и налейте поварёшкой около 100 мл в сковороду, сразу же вращая её, чтобы тесто покрыло дно тонким слоем и поднялось до середины бортиков; посыпьте небольшой горстью нарезанного лука одну половину блина. Накройте крышкой на 60 секунд — пар поможет приготовиться верху; снимите крышку, влейте 1 ч; л; масла по краю и готовьте ещё 2–3 минуты, пока края не станут глубоко золотыми и не будут чисто отходить от сковороды тонкой лопаткой. Положите горсть ростков на половину со свининой и креветками; загните пустую половину сверху, чтобы получился полумесяц, и переложите на тёплую тарелку; повторите с оставшимся тестом, креветками, свининой и ростками; должно получиться 4–5 блинов. Подавайте сразу, пока блины громко хрустят; как есть: оторвите кусок, заверните в листе салата с травами и огурцом и обмакните в нуок-чам; блин должен слышимо хрустеть при сгибании — если становится мягким, следующему нужна более горячая сковорода и чуть более тонкий слой теста.","en":"Make the batter at least 30 minutes ahead; whisk together the rice flour, cornflour, turmeric, 0.5 tsp salt, and 1 tsp sugar in a large bowl; pour in the coconut milk and sparkling water and whisk until smooth; stir in the sliced spring-onion greens; cover and rest in the fridge for at least 30 minutes (up to 4 hours) — the resting hydrates the flour for a crisper crepe. While the batter rests, mix the nuoc cham; stir 3 tbsp fish sauce, 3 tbsp lime juice, 2 tbsp sugar, and 4 tbsp warm water in a bowl until the sugar dissolves; add the minced garlic and sliced chilli; set aside. Toss the pork strips with 1 tbsp fish sauce and 0.5 tsp pepper; rinse and pat dry the prawns; wash the bean sprouts and shake dry; arrange the lettuce, herbs, and cucumber on a serving platter. Heat a 24 cm non-stick pan over medium-high heat; add 1 tsp oil, swirl to coat, then add 2–3 prawns and a handful of pork strips; stir-fry for 60–90 seconds until the prawns curl pink and the pork edges are golden but not fully cooked through. Stir the batter, then ladle about 100 ml into the pan, immediately swirling so the batter coats the base in a thin layer and reaches halfway up the sides; drop a small handful of sliced onion over one half of the crepe. Cover with a lid for 60 seconds — the steam helps cook the top; then uncover, drizzle 1 tsp oil around the edge, and cook for a further 2–3 minutes, until the edges turn deep golden and lift cleanly from the pan with a thin spatula. Pile a handful of bean sprouts onto the half topped with pork and prawns; fold the empty half over to form a half-moon, then slide onto a warmed plate; repeat with the remaining batter, prawns, pork, and bean sprouts; you should get 4–5 crepes. Serve immediately, while the crepes are still loud-crispy; to eat: tear a piece, wrap it in lettuce with herbs and cucumber, and dip into the nuoc cham; the crepe should crackle audibly as it bends — if it goes soft, the next one needs a hotter pan and a slightly thinner pour."}},{"id":127,"origin":{"ru":"Перу","en":"Peru","ro":"Peru"},"name":{"ru":"Кауса Лименья","en":"Causa Limeña","ro":"Causa Limeña"},"category":{"ru":"Закуска","en":"Appetizer","ro":"Aperitiv"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"ru":["1 кг жёлтого перуанского картофеля (или Yukon Gold или другого восковидного жёлтого картофеля), очищенного и нарезанного крупными кусками","60 мл свежего сока лайма (около 2 лаймов)","60 мл нейтрального масла (подсолнечного или оливкового)","2 ст. л. пасты ají amarillo (или 1 ст. л. ají amarillo + 1 ч. л. корейского кочхуджан в качестве заменителя)","1,5 ч. л. мелкой морской соли, плюс по вкусу","0,5 ч. л. свежемолотого белого перца","2 банки по 160 г качественного тунца в оливковом масле, без жидкости (или 320 г варёной разделанной куриной грудки)","120 г хорошего майонеза","2 зелёных лука, очень тонко нарезанных (около 20 г)","1 небольшой стебель сельдерея, мелко нарезанный (около 30 г, по желанию)","0,5 ч. л. мелкой морской соли","1 крупный спелый авокадо (около 200 г), нарезанный пластинами 5 мм и сбрызнутый 1 ч. л. сока лайма","12 чёрных оливок (ботия или каламата), разрезанных пополам и без косточек","2 яйца, сваренных вкрутую, разрезанных пополам или на четвертинки","Веточки свежей кинзы или петрушки"],"en":["1 kg yellow Peruvian potatoes (or Yukon Gold or other waxy yellow potatoes), peeled and cut into chunks","60 ml fresh lime juice (about 2 limes)","60 ml neutral oil (sunflower or olive)","2 tbsp ají amarillo paste (or 1 tbsp ají amarillo + 1 tsp Korean gochujang as substitute)","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground white pepper","2 × 160 g tins of high-quality tuna in olive oil, drained (or 320 g cooked shredded chicken breast)","120 g good mayonnaise","2 spring onions, very finely sliced (about 20 g)","1 small celery stalk, finely diced (about 30 g, optional)","0.5 tsp fine sea salt","1 large ripe avocado (about 200 g), sliced 5 mm thick and tossed with 1 tsp lime juice","12 black olives (botija or kalamata), halved and pitted","2 hard-boiled eggs, halved or quartered","Sprigs of fresh coriander or parsley"],"ro":["1 kg cartofi galbeni peruvieni (sau Yukon Gold ori alți cartofi galbeni cu pastă fermă), curățați și tăiați în bucăți","60 ml suc proaspăt de lime (aproximativ 2 lime)","60 ml ulei neutru (de floarea-soarelui sau de măsline)","2 linguri pastă de ají amarillo (sau 1 lingură ají amarillo + 1 linguriță gochujang ca substitut)","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper alb proaspăt măcinat","2 conserve de 160 g de ton de calitate în ulei de măsline, scurse (sau 320 g piept de pui fiert și mărunțit)","120 g maioneză bună","2 cepe verzi, feliate foarte fin (aproximativ 20 g)","1 tulpină mică de țelină, tocată fin (aproximativ 30 g, opțional)","0,5 linguriță sare fină de mare","1 avocado mare copt (aproximativ 200 g), feliat la 5 mm și amestecat cu 1 linguriță suc de lime","12 măsline negre (botija sau Kalamata), tăiate în două și fără sâmburi","2 ouă fierte tare, tăiate în jumătăți sau sferturi","Crenguțe de coriandru sau pătrunjel proaspăt"]},"howIsMade":{"ru":"Отварите картофель в хорошо подсолённой воде (около 1 ст; л; соли на литр) 18–20 минут, пока нож не будет входить без сопротивления, но картофель не развалится; откиньте и дайте обсохнуть на решётке 5 минут на пару. Пока ещё тёплый, пропустите картофель через картофелемялку или мелкое сито в широкую миску; добавьте пасту ají amarillo, сок лайма, масло, 1,5 ч; л; соли и белый перец; аккуратно вымесите руками 2–3 минуты — пюре должно быть гладким, шелковистым и слегка эластичным, держать форму при сжатии. Попробуйте и при необходимости добавьте соли или лайма; накройте и остудите до комнатной температуры, затем поставьте в холодильник на 20 минут, чтобы пюре слегка стало плотнее. Приготовьте начинку; в миску разломите слитый тунец (или разделанную курицу); добавьте майонез, зелёный лук, сельдерей (если используете) и 0,5 ч; л; соли; аккуратно перемешайте — оставьте видимые хлопья рыбы, а не однородное пюре; уберите в холодильник до использования. Застелите форму для кекса 22 × 12 см (или круглое кольцо 18 см) пищевой плёнкой, оставляя щедрые свисающие края; утрамбуйте в основание треть картофельного пюре ровным слоем 1,5 см, разглаживая обратной стороной влажной ложки. Распределите половину тунцовой или куриной начинки поверх картофеля слоем 1 см, оставив бортик 5 мм; уложите ломтики авокадо одним плотным внахлёст слоем; утрамбуйте вторую треть пюре над авокадо, затем выложите оставшуюся начинку и финальный слой пюре. Загните плёнку поверх и плотно прижмите ладонью или небольшой доской, чтобы спрессовать террин; уберите в холодильник минимум на 1 час (до 6 часов), чтобы слои схватились. Достаньте террин за плёнку, снимите её и нарежьте на 8 щедрых порций горячим влажным ножом (ополаскивайте лезвие между разрезами); украсьте каждый ломтик половинкой оливки, четвертинкой варёного яйца и веточкой кинзы; подавайте холодным, в течение 2 часов после нарезки.","en":"Boil the potatoes in well-salted water (about 1 tbsp salt per litre) for 18–20 minutes, until a knife slides in with no resistance but the potatoes are not falling apart; drain and leave to steam-dry on a rack for 5 minutes. While still warm, pass the potatoes through a ricer or fine sieve into a wide bowl; add the ají amarillo paste, lime juice, oil, 1.5 tsp salt, and white pepper; knead gently with your hands for 2–3 minutes — the mash should be smooth, silky, and slightly elastic, holding its shape when pinched. Taste and adjust with more salt or lime; cover and let cool to room temperature, then chill for 20 minutes to firm slightly. Make the filling; flake the drained tuna (or shred the chicken) into a bowl; add the mayonnaise, spring onions, celery (if using), and 0.5 tsp salt; fold gently — keep visible flakes of fish rather than a smooth purée; chill until needed. Line a 22 × 12 cm loaf tin (or a round 18 cm cake ring) with cling film, leaving a generous overhang; press one-third of the potato mash into the base in an even 1.5 cm layer, using the back of a damp spoon to smooth. Spread half the tuna or chicken filling over the potato in a 1 cm layer, leaving a 5 mm border; arrange the avocado slices on top in a tight overlapping single layer; press a second third of potato over the avocado, then top with the remaining filling and a final layer of potato. Fold the cling film over the top and press firmly with the flat of your hand or a small board to compact the terrine; refrigerate for at least 1 hour (or up to 6 hours) to set the layers. Lift the terrine out using the cling film, peel back, and slice into 8 generous portions with a hot wet knife (rinse the blade between cuts); top each slice with an olive half, a wedge of hard-boiled egg, and a sprig of coriander; serve cold, within 2 hours of slicing."}},{"id":129,"origin":{"ru":"Киргизия","en":"Kyrgyzstan","ro":"Kârgâzstan"},"name":{"ru":"Бешбармак","en":"Beshbarmak","ro":"Beshbarmak"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["1,2 кг бараньей лопатки с костью или говяжьей грудинки (или смеси), нарезанной на 4 крупных куска","3 литра холодной воды","1 ст. л. мелкой морской соли, плюс по вкусу","1 луковица, разрезанная пополам (для бульона)","1 морковь, разрезанная пополам (для бульона)","2 лавровых листа","10 горошин чёрного перца целиком","400 г обычной пшеничной муки, плюс для подсыпки","2 крупных яйца","150 мл тёплой воды","1 ч. л. мелкой морской соли","2 крупные луковицы (около 350 г), разрезанные пополам и тонко нарезанные полумесяцами","0,5 ч. л. свежемолотого чёрного перца","Щепотка сахара","Свежий укроп или петрушка, крупно нарезанные"],"en":["1.2 kg bone-in lamb shoulder or beef brisket (or a mix), cut into 4 large pieces","3 litres cold water","1 tbsp fine sea salt, plus more to taste","1 onion, halved (for the broth)","1 carrot, halved (for the broth)","2 bay leaves","10 whole black peppercorns","400 g plain (all-purpose) flour, plus extra for dusting","2 large eggs","150 ml warm water","1 tsp fine sea salt","2 large onions (about 350 g), halved and thinly sliced into half-moons","0.5 tsp freshly ground black pepper","Pinch of sugar","Fresh dill or parsley, roughly chopped"],"ro":["1,2 kg umăr de miel sau piept de vită cu os (sau un amestec), tăiat în 4 bucăți mari","3 litri apă rece","1 lingură sare fină de mare, plus după gust","1 ceapă, tăiată în două (pentru bulion)","1 morcov, tăiat în două (pentru bulion)","2 frunze de dafin","10 boabe de piper negru întregi","400 g făină albă obișnuită, plus pentru tăvălit","2 ouă mari","150 ml apă caldă","1 linguriță sare fină de mare","2 cepe mari (aproximativ 350 g), tăiate în două și feliate subțire în semilune","0,5 linguriță piper negru proaspăt măcinat","Un vârf de zahăr","Mărar sau pătrunjel proaspăt, tocat grosier"]},"howIsMade":{"ru":"Положите мясо в большую кастрюлю, залейте холодной водой и медленно доведите до кипения на среднем огне — медленный нагрев максимально вытягивает вкус в бульон; аккуратно снимайте серую пену первые 10 минут, пока поверхность не станет прозрачной. Добавьте 1 ст; л; соли, разрезанную пополам луковицу, морковь, лавровые листья и горошины перца; убавьте огонь до едва заметного кипения (поверхность почти не должна шевелиться) и варите без крышки 2–2,5 часа, пока мясо не начнёт отделяться от кости. Пока мясо варится, приготовьте тесто; в широкой миске взбейте муку и 1 ч; л; соли, сделайте углубление, добавьте яйца и тёплую воду; размешайте вилкой, затем месите на подпылённой мукой поверхности 8–10 минут до плотной, гладкой и эластичной массы; накройте плёнкой и оставьте при комнатной температуре на 30 минут. Разделите тесто на 4 части; работая по одной (остальные накройте), раскатайте на подпылённой мукой поверхности как можно тоньше — около 1 мм; нарежьте на квадраты примерно 8 × 8 см (или ромбы 10 × 5 см); щедро присыпьте мукой и разложите плоско на подносе, чтобы не слипались. Достаньте мясо из бульона на доску, неплотно накройте фольгой и дайте отдохнуть; процедите бульон в чистую кастрюлю через мелкое сито и выбросьте варившиеся овощи; держите бульон на лёгком кипении. Налейте 500 мл горячего бульона в отдельную небольшую кастрюлю; добавьте тонко нарезанный лук и щепотку сахара и варите 5–6 минут — лук должен остаться прозрачным и едва мягким, не разваленным; добавьте 0,5 ч; л; чёрного перца. Снова доведите процеженный бульон до сильного кипения; опускайте квадраты теста партиями, аккуратно перемешивая, чтобы не слипались, и варите 3–4 минуты на партию, пока они не всплывут и не дойдут до al dente; вынимайте шумовкой на тёплое сервировочное блюдо. Нарежьте мясо толстыми ломтями поперёк волокон и уложите поверх лапши; щедро полейте луком с его бульоном; посыпьте рубленым укропом и подайте каждому гостю чашку горячего прозрачного бульона, чтобы пить между кусками; подавайте сразу, пока всё парит.","en":"Place the meat in a large stockpot, cover with the cold water, and bring slowly to the boil over medium heat — slow heating draws maximum flavour into the broth; skim the grey foam carefully for the first 10 minutes until the surface runs clear. Add the 1 tbsp salt, halved onion, carrot, bay leaves, and peppercorns; reduce the heat to a bare simmer (the surface should barely move) and cook uncovered for 2–2.5 hours, until the meat is fork-tender and falling from the bone. While the meat simmers, make the dough; whisk the flour and 1 tsp salt in a wide bowl, make a well, and add the eggs and warm water; stir with a fork, then knead on a floured surface for 8–10 minutes until firm, smooth, and elastic; cover with cling film and rest at room temperature for 30 minutes. Divide the rested dough into 4 pieces; working with one piece at a time and keeping the rest covered, roll out as thinly as possible on a floured surface — about 1 mm thick; cut into rough 8 × 8 cm squares (or 10 × 5 cm diamonds); dust generously with flour and lay flat on a tray so they do not stick. Lift the meat out of the broth onto a board, cover loosely with foil, and rest; strain the broth into a clean pot through a fine sieve and discard the boiling vegetables; keep the broth at a gentle simmer. Ladle 500 ml of the hot broth into a separate small pot; add the thinly sliced onions and a pinch of sugar and simmer for 5–6 minutes — the onions should stay translucent and just tender, not collapsed; stir in 0.5 tsp black pepper. Bring the strained broth back to a vigorous boil; drop the dough squares in batches, stir gently to prevent sticking, and cook 3–4 minutes per batch until they float and are al dente; lift out with a slotted spoon onto a warmed serving platter. Slice the meat thickly against the grain and arrange over the noodles; spoon the onions and their broth liberally over the meat; scatter with chopped dill, then ladle a cup of the hot clear broth on the side for each diner to sip between bites; serve immediately while everything is steaming hot."}},{"id":130,"origin":{"ru":"Таиланд","en":"Thailand","ro":"Thailanda"},"name":{"ru":"Кокосовый рис","en":"Coconut Rice","ro":"Orez cu lapte de cocos"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ru":["400 г длиннозёрного риса (тайский жасминовый или басмати)","400 мл жирного кокосового молока (1 стандартная банка)","250 мл холодной воды","1 ч. л. мелкой морской соли","1 ч. л. сахарного песка","2 свежих листа пандана, завязанных узлом (или 1 ч. л. экстракта пандана — по желанию, но традиционно)","1 маленький шалот (около 30 г), тонко нарезанный","1 стебель лемонграсса, слегка размятый (по желанию, для юго-восточного аромата)","1 полоска цедры лайма длиной 3 см (по желанию, для свежести)","1 ст. л. кокосового или нейтрального масла","30 г несладкой сушёной кокосовой стружки, слегка обжаренной (для украшения)","Небольшая горсть свежих листьев кинзы (для украшения)"],"en":["400 g long-grain rice (Thai jasmine or basmati)","400 ml full-fat coconut milk (1 standard tin)","250 ml cold water","1 tsp fine sea salt","1 tsp caster sugar","2 fresh pandan leaves, tied into a knot (or 1 tsp pandan extract — optional but traditional)","1 small shallot (about 30 g), finely sliced","1 stalk lemongrass, lightly bruised (optional, for Southeast Asian aroma)","3 cm strip lime zest (optional, for brightness)","1 tbsp coconut oil or neutral oil","30 g unsweetened desiccated coconut, lightly toasted (for garnish)","Small handful fresh coriander leaves (for garnish)"],"ro":["400 g orez cu bob lung (jasmine thailandez sau basmati)","400 ml lapte de cocos integral (1 conservă standard)","250 ml apă rece","1 linguriță sare fină de mare","1 linguriță zahăr tos","2 frunze de pandan proaspete, legate în nod (sau 1 linguriță extract de pandan — opțional, dar tradițional)","1 eșalotă mică (aproximativ 30 g), feliată fin","1 tulpină de lemongrass, ușor zdrobită (opțional, pentru aroma sud-est asiatică)","Coajă de lime de 3 cm, fâșie subțire (opțional, pentru prospețime)","1 lingură ulei de cocos sau ulei neutru","30 g cocos rasă neîndulcită, ușor prăjită (pentru garnitură)","Un pumn mic de frunze de coriandru proaspete (pentru garnitură)"]},"howIsMade":{"ru":"Промойте рис в сите под холодной проточной водой около 1 минуты, перебирая рукой, пока вода не станет почти прозрачной; хорошо обсушите; этот шаг удаляет поверхностный крахмал и сохраняет зёрна раздельными. Разогрейте кокосовое масло в кастрюле с толстым дном объёмом 2 литра на среднем огне; добавьте нарезанный шалот и обжаривайте 90 секунд–2 минуты, пока он не размягчится и не приобретёт лёгкий золотистый оттенок по краям, но не поджарится. Всыпьте обсушенный рис и помешивайте 30 секунд, чтобы каждое зерно покрылось маслом; влейте кокосовое молоко и воду, добавьте соль, сахар, завязанные узлом листья пандана, размятый лемонграсс и цедру лайма. Перемешайте один раз, чтобы соль растворилась, и доведите до лёгкого кипения на среднем-сильном огне — продолжайте аккуратно помешивать около 2 минут, чтобы кокосовое молоко не пригорало. Уменьшите огонь до минимума, накройте плотно прилегающей крышкой и варите, не открывая, 12 минут; не поднимайте крышку — заключённый пар равномерно проваривает рис. Выключите огонь (не открывая крышку) и оставьте рис настояться 10 минут — этот завершающий пар подсушивает зёрна и не даёт им слипнуться. Снимите крышку, удалите и выбросьте пандан, лемонграсс и цедру лайма; аккуратно распушите рис вилкой, посыпьте обжаренной кокосовой стружкой и листьями кинзы и подайте сразу с карри, самболами или рыбой на гриле.","en":"Rinse the rice thoroughly in a sieve under cold running water for about 1 minute, swirling with your hand, until the water runs almost clear; drain well; this removes surface starch and keeps the grains separate at the end. Heat the coconut oil in a heavy-based 2-litre pan over medium heat; add the sliced shallot and stir-fry for 90 seconds–2 minutes, until softened and lightly golden at the edges but not browned. Add the drained rice to the pan and stir for 30 seconds to coat each grain in oil; pour in the coconut milk and water, then add the salt, sugar, knotted pandan leaves, bruised lemongrass, and lime zest. Stir once to dissolve the salt and bring to a gentle boil over medium-high heat — keep stirring gently for about 2 minutes so the coconut milk does not catch on the base. Lower the heat to the lowest possible setting, cover with a tight-fitting lid, and cook undisturbed for 12 minutes; do not lift the lid — the trapped steam is what cooks the rice evenly. Turn off the heat (leave the pan covered) and rest the rice for 10 minutes — this finishing steam dries the grains and stops them clumping. Lift the lid, remove and discard the pandan, lemongrass, and lime zest; fluff the rice gently with a fork, scatter the toasted desiccated coconut and coriander leaves over the top, and serve immediately alongside curry, sambols, or grilled fish."}},{"id":131,"origin":{"ru":"Малайзия","en":"Malaysia","ro":"Malaezia"},"name":{"ru":"Наси-лемак","en":"Nasi lemak","ro":"Nasi lemak"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ru":["400 г длиннозёрного жасминового риса","400 мл жирного кокосового молока","200 мл холодной воды","1 ч. л. мелкой морской соли","2 свежих листа пандана, завязанных узлом, плюс 1 размятый стебель лемонграсса и 3 тонких ломтика свежего имбиря (для риса)","60 г сырых очищенных арахисов","60 г икан билис (сушёных малайских анчоусов)","4 крупных яйца","1 средний огурец (около 200 г), нарезанный кружками по 5 мм","10 сушёных красных перцев чили, замоченных в горячей воде на 15 минут и обсушенных","4 свежих красных перца чили (мягких)","2 крупных шалота (около 120 г), очищенных, плюс 3 зубчика чеснока и кусочек свежего имбиря размером с большой палец (15 г)","1 ст. л. белакан (обжаренная креветочная паста) или 1,5 ч. л. рыбного соуса как заменитель","2 ст. л. пасты тамаринда, разведённой с 4 ст. л. тёплой воды (или 3 ст. л. сока лайма)","2 ст. л. пальмового сахара или тёмного коричневого сахара","1 средняя красная луковица (около 120 г), нарезанная тонкими кольцами","60 мл плюс 250 мл нейтрального масла (60 мл для самбала; остальное для жарки анчоусов и арахиса)","0,5 ч. л. мелкой морской соли для самбала"],"en":["400 g long-grain jasmine rice","400 ml full-fat coconut milk","200 ml cold water","1 tsp fine sea salt","2 fresh pandan leaves tied into a knot, plus 1 bruised stalk of lemongrass and 3 thin slices of fresh ginger (for the rice)","60 g raw skinless peanuts","60 g ikan bilis (dried Malaysian anchovies)","4 large eggs","1 medium cucumber (about 200 g), sliced into 5 mm rounds","10 dried red chillies, soaked in hot water for 15 minutes and drained","4 fresh red chillies (mild)","2 large shallots (about 120 g), peeled, plus 3 garlic cloves and 1 thumb-sized piece of fresh ginger (15 g)","1 tbsp belacan (toasted shrimp paste), or 1.5 tsp fish sauce as a substitute","2 tbsp tamarind paste mixed with 4 tbsp warm water (or 3 tbsp lime juice)","2 tbsp palm sugar or dark brown sugar","1 medium red onion (about 120 g), sliced into thin rings","60 ml plus 250 ml neutral oil (split: 60 ml for the sambal, the rest for frying anchovies and peanuts)","0.5 tsp fine sea salt for the sambal"],"ro":["400 g orez jasmine cu bob lung","400 ml lapte de cocos integral","200 ml apă rece","1 linguriță sare fină de mare","2 frunze de pandan proaspete, legate în nod, plus 1 tulpină de lemongrass zdrobită și 3 felii subțiri de ghimbir proaspăt (pentru orez)","60 g arahide crude fără pieliță","60 g ikan bilis (anșoa malaezieni uscați)","4 ouă mari","1 castravete mediu (aproximativ 200 g), tăiat rondele de 5 mm","10 ardei iuți roșii uscați, înmuiați în apă fierbinte 15 minute și scurși","4 ardei iuți roșii proaspeți (blânzi)","2 eșalote mari (aproximativ 120 g), decojite, plus 3 căței de usturoi și o bucată de ghimbir cât degetul mare (15 g)","1 lingură belacan (pastă de creveți prăjită) sau 1,5 linguriță sos de pește ca substitut","2 linguri pastă de tamarin amestecată cu 4 linguri apă caldă (sau 3 linguri suc de lime)","2 linguri zahăr de palmier sau zahăr brun închis","1 ceapă roșie medie (aproximativ 120 g), feliată inele subțiri","60 ml plus 250 ml ulei neutru (împărțit: 60 ml pentru sambal, restul pentru prăjit anșoa și arahide)","0,5 linguriță sare fină de mare pentru sambal"]},"howIsMade":{"ru":"Промойте рис в сите под холодной проточной водой 1 минуту, пока вода не станет почти прозрачной, и хорошо обсушите; положите в кастрюлю с толстым дном объёмом 2 литра вместе с кокосовым молоком, водой, 1 ч; л; соли, панданом, лемонграссом и имбирём; доведите до лёгкого кипения на среднем-сильном огне, перемешав один раз; убавьте огонь до минимума, накройте плотной крышкой и варите, не открывая, 12 минут; выключите огонь и дайте настояться под крышкой ещё 10 минут — заключённый пар довершает варку и подсушивает зёрна; удалите ароматические травы перед подачей. Пока рис варится, обжарьте арахис; разогрейте 250 мл масла в небольшой кастрюле до 160°C; жарьте арахис 3–4 минуты до бледно-золотистого цвета (при остывании потемнеет), затем выньте шумовкой на бумажное полотенце; слегка посолите. Обсушите икан билис; в том же масле обжарьте его двумя партиями по 60–90 секунд, помешивая один раз, до хрустящей корочки и насыщенно-золотистого цвета; выложите на отдельный лист бумаги; масло сохраните. Сварите яйца вкрутую: опустите в едва кипящую воду и варите ровно 8 минут для плотных желтков (или 7 минут — для слегка кремовых); сразу переложите в ледяную воду на 3 минуты, очистите и разрежьте пополам. Сделайте пасту самбал; замоченные сушёные перцы, свежие перцы, шалоты, чеснок, кусочек имбиря 15 г и белакан перемолите в блендере или ступке с 2 ст; л; сохранённого масла до грубой пасты. В воке или широкой сковороде разогрейте 60 мл свежего масла на среднем огне; добавьте пасту самбал и жарьте, непрерывно помешивая, 12–15 минут, пока масло не отделится по краям, а паста не приобретёт глубокий кирпично-красный цвет; это длительное обжаривание убирает сырой привкус ароматов. Вмешайте кольца красного лука, тамариндовую воду, пальмовый сахар и 0,5 ч; л; соли; готовьте на слабом огне ещё 6–8 минут, пока лук не станет мягким, а самбал не приобретёт глянцевую, джемовую консистенцию, которая держит чёткую линию при проведении ложкой по сковороде; попробуйте и сбалансируйте — должно быть остро, сладко, кисло и солоновато в примерно равных долях. Подача: положите порцию риса горкой на тарелку; окружите половинкой варёного яйца, щедрой ложкой самбала, кучкой арахиса, кучкой хрустящих анчоусов и веером ломтиков огурца; едят, смешивая в каждом кусочке немного из каждой горки.","en":"Rinse the rice in a sieve under cold running water for 1 minute, until the water runs almost clear, then drain well; put it in a heavy 2-litre pan with the coconut milk, water, 1 tsp salt, pandan, lemongrass, and ginger; bring to a gentle boil over medium-high heat, stirring once; lower the heat to the lowest setting, cover with a tight lid, and cook undisturbed for 12 minutes; turn off the heat and rest, covered, for another 10 minutes — the trapped steam finishes cooking and dries the grains; discard the aromatics before serving. While the rice cooks, fry the peanuts; heat the 250 ml oil in a small pan to 160°C; fry the peanuts for 3–4 minutes until pale gold (they will darken as they cool), then lift onto paper towels with a slotted spoon; salt lightly. Pat the ikan bilis dry; in the same oil, fry them in two batches for 60–90 seconds per batch, stirring once, until crisp and deep gold; lift onto a separate sheet of paper; reserve the oil. Hard-boil the eggs: lower them into gently simmering water and cook for exactly 8 minutes for set yolks (or 7 minutes for slightly jammy); transfer immediately to iced water for 3 minutes, then peel and halve. Make the sambal paste; combine the drained dried chillies, fresh chillies, shallots, garlic, the 15 g ginger piece, and belacan in a blender or mortar with 2 tbsp of the reserved oil and process to a coarse paste. Heat 60 ml fresh oil in a wok or wide pan over medium heat; add the sambal paste and fry, stirring continuously, for 12–15 minutes, until the oil splits out around the edges and the paste turns deep brick-red; this long fry is what kills the raw bite of the aromatics. Stir in the red onion rings, tamarind water, palm sugar, and 0.5 tsp salt; simmer for 6–8 minutes more, until the onions are softened and the sambal has a glossy, jammy texture that holds a clean line when you drag a spoon across the pan; taste and balance — it should be hot, sweet, sour, and savoury in roughly equal measure. To serve: mound a portion of rice on each plate; surround with a hard-boiled egg half, a generous spoonful of sambal, a small heap of peanuts, a small heap of crispy anchovies, and a fan of cucumber slices; eat by mixing small amounts from each pile into each bite."}},{"id":132,"origin":{"ru":"Швейцария","en":"Switzerland","ro":"Elveția"},"name":{"ru":"Рёсти","en":"Rösti","ro":"Rösti"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ru":["1 кг плотного картофеля (Yukon Gold, Charlotte или похожих сортов), неочищенного","60 г несолёного сливочного масла, разделённого на две порции по 30 г","2 ст. л. нейтрального масла (подсолнечного или виноградных косточек), разделённых на две порции по 1 ст. л.","1 ч. л. мелкой морской соли, плюс по вкусу","0,5 ч. л. свежемолотого чёрного перца","Щепотка тёртого мускатного ореха (по желанию, традиционно в бернской версии)","1 маленькая луковица (около 80 г), очень мелко нарезанная (по желанию, частая вариация)","60 г выдержанного грюйера, крупно натёртого (по желанию, для более насыщенного финиша)","1 ст. л. мелко нарубленного свежего шнитт-лука, для подачи"],"en":["1 kg waxy potatoes (Yukon Gold, Charlotte, or similar), unpeeled","60 g unsalted butter, in two 30 g portions","2 tbsp neutral oil (sunflower or grapeseed), in two 1 tbsp portions","1 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","Pinch of grated nutmeg (optional, traditional in Bernese versions)","1 small onion (about 80 g), very finely diced (optional, common variation)","60 g aged gruyère, coarsely grated (optional, for a richer finish)","1 tbsp finely chopped fresh chives, to garnish"],"ro":["1 kg cartofi cu pastă fermă (Yukon Gold, Charlotte sau similari), necurățați","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru (de floarea-soarelui sau de struguri), împărțit în două porții de 1 lingură","1 linguriță sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","Un vârf de nucșoară rasă (opțional, tradițional în versiunea berneză)","1 ceapă mică (aproximativ 80 g), tăiată foarte fin (opțional, variantă obișnuită)","60 g gruyère maturat, ras grosier (opțional, pentru finisare mai bogată)","1 lingură arpagic proaspăt tocat fin, pentru garnitură"]},"howIsMade":{"ru":"Накануне отварите картофель целиком и в кожуре в хорошо подсолённой воде (1 ст; л; соли на литр) 8–10 минут — нож должен встречать некоторое сопротивление, центр оставаться сырым; слейте и полностью остудите; поставьте без крышки в холодильник на ночь, чтобы поверхность подсохла, а крахмал укрепился. На следующий день очистите холодный картофель — кожура снимается легко; натрите на крупной стороне тёрки длинной ровной соломкой, работая быстро, чтобы он не нагрелся. В миске приправьте натёртый картофель солью, перцем и мускатным орехом и аккуратно перемешайте — кончиками пальцев, без сжатия, чтобы соломка осталась длинной. Разогрейте 1 ст; л; масла и 30 г сливочного масла в сковороде 24 см с антипригарным покрытием или хорошо разогретой чугунной на среднем огне до тех пор, пока сливочное масло не вспенится и не приобретёт ореховый оттенок; добавьте нарезанный лук (если используете) и обжаривайте 90 секунд–2 минуты до мягкости и лёгкой золотистости. Выложите приправленный картофель ровным слоем, слегка прижимая обратной стороной лопатки, чтобы сформировать лепёшку толщиной 1,5 см и диаметром около 22 см — не утрамбовывайте, воздушные карманы дают хрустящую сердцевину; жарьте, не двигая, 8–10 минут, пока низ не станет тёмно-золотистым и не будет легко отделяться от сковороды при поддевании лопаткой. Накройте сковороду плоской тарелкой, переверните рёшти на неё и снова сдвиньте в сковороду готовой стороной вверх; положите по краям оставшиеся 30 г сливочного масла и 1 ст; л; масла, чтобы они стекли под лепёшку; жарьте ещё 7–9 минут, пока вторая сторона не станет такой же золотистой, а середина — горячей и мягкой (нож, вставленный в середину, не должен встречать сопротивления). Сдвиньте рёшти на разделочную доску, посыпьте натёртым грюйером по желанию (остаточный жар слегка его растопит), украсьте шнитт-луком и разрежьте на 4 части; подавайте сразу с яичницей сверху, копчёной ветчиной или братвурстом.","en":"The day before, parboil the potatoes whole and unpeeled in well-salted water (1 tbsp salt per litre) for 8–10 minutes — a knife should meet some resistance, the centre should still be raw; drain and cool completely; refrigerate uncovered overnight so the surface dries and the starches firm up. The next day, peel the cold potatoes — the skins should slip off easily; grate them on the large holes of a box grater into long, even shreds, working briskly so they do not warm. In a bowl, season the grated potatoes with the salt, pepper, and nutmeg, and toss gently to distribute — use your fingertips, not a heavy hand, so the strands stay long. Heat 1 tbsp oil and 30 g of the butter in a 24 cm non-stick or well-seasoned cast-iron pan over medium heat until the butter foams and just turns nut-brown; add the diced onion (if using) and cook for 90 seconds–2 minutes, until soft and lightly golden. Add the seasoned potato to the pan in one even layer, lightly pressing with the back of a spatula to form a 1.5 cm cake about 22 cm across — do not pack it down hard, the air gaps are what crisp the inside; cook undisturbed for 8–10 minutes, until the underside is deep golden brown and pulls cleanly from the pan when you slide a spatula under it. Hold a flat plate over the pan, invert the rösti onto it, then slide it back into the pan with the cooked side up; add the remaining 30 g butter and 1 tbsp oil around the edges so they run under the cake; cook for a further 7–9 minutes, until the second side is equally deep golden and the centre is hot and tender (a paring knife pushed into the middle should meet no resistance). Slide the rösti onto a board, scatter with the grated gruyère if using (the residual heat will melt it lightly), top with chopped chives, and cut into 4 wedges; serve immediately with a fried egg on top, smoked ham, or Bratwurst."}},{"id":133,"origin":{"ru":"Румыния","en":"Romania","ro":"România"},"name":{"ru":"Фасоль с колбасой","en":"Beans with Sausages","ro":"Fasole cu cârnați"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["500 г сушёной белой фасоли (каннеллини, нэви или греческая гигантская), замоченной в холодной воде на ночь","4 копчёных свиных колбаски (около 500 г; например, кырнаци Плешкой или копчёная польская колбаса)","150 г копчёной грудинки (кайзер) или копчёных свиных рёбрышек, нарезанных кусками по 2 см (по желанию, для глубины)","2 крупные луковицы (около 350 г), мелко нарезанные","2 средние моркови (около 200 г), мелко нарезанные","1 средний красный болгарский перец, мелко нарезанный","4 зубчика чеснока, мелко нарезанных","3 ст. л. томатной пасты","200 г консервированных дроблёных помидоров (или 2 свежих помидора, натёртых)","3 лавровых листа","1 ч. л. сладкой паприки","0,5 ч. л. сушёного тимьяна (или 1 свежая веточка)","0,5 ч. л. свежемолотого чёрного перца","1,5 ч. л. мелкой морской соли, плюс по вкусу","60 мл подсолнечного масла (или 30 г смальца)","1,5–2 литра воды (или несолёного куриного бульона для более насыщенного вкуса)","2 ст. л. мелко нарубленного свежего укропа или петрушки, для подачи","1 ст. л. белого винного уксуса (по желанию, для баланса в конце)"],"en":["500 g dried white beans (cannellini, navy, or Greek elephant), soaked overnight in cold water","4 smoked pork sausages (about 500 g; e.g. cârnați Pleșcoi or smoked Polish sausage)","150 g smoked bacon (kaiser) or smoked pork ribs, cut into 2 cm pieces (optional, for extra depth)","2 large onions (about 350 g), finely diced","2 medium carrots (about 200 g), finely diced","1 medium red bell pepper, finely diced","4 garlic cloves, finely chopped","3 tbsp tomato paste","200 g canned crushed tomatoes (or 2 fresh tomatoes, grated)","3 bay leaves","1 tsp sweet paprika","0.5 tsp dried thyme (or 1 sprig fresh)","0.5 tsp freshly ground black pepper","1.5 tsp fine sea salt, plus more to taste","60 ml sunflower oil (or 30 g lard)","1.5–2 litres water (or unsalted chicken stock for richer flavour)","2 tbsp finely chopped fresh dill or parsley, to finish","1 tbsp white wine vinegar (optional, to balance at the end)"],"ro":["500 g fasole albă uscată (cannellini, navy sau fasole gigant grecească), înmuiată peste noapte în apă rece","4 cârnați afumați de porc (aproximativ 500 g, ex. cârnați Pleșcoi sau cârnați polonezi afumați)","150 g kaiser afumat sau coaste de porc afumate, tăiate bucăți de 2 cm (opțional, pentru profunzime)","2 cepe mari (aproximativ 350 g), tocate fin","2 morcovi medii (aproximativ 200 g), tocați mărunt","1 ardei kapia roșu mediu, tocat fin","4 căței de usturoi, tocați fin","3 linguri bulion (pastă de roșii)","200 g roșii sfărâmate din conservă (sau 2 roșii proaspete, date pe răzătoare)","3 foi de dafin","1 linguriță boia dulce","0,5 linguriță cimbru uscat (sau 1 crenguță proaspătă)","0,5 linguriță piper negru proaspăt măcinat","1,5 lingurițe sare fină de mare, plus după gust","60 ml ulei de floarea-soarelui (sau 30 g untură)","1,5–2 litri apă (sau supă neagră de pui pentru o aromă mai bogată)","2 linguri mărar sau pătrunjel proaspăt tocat fin, pentru finisare","1 lingură oțet de vin alb (opțional, pentru echilibru la final)"]},"howIsMade":{"ru":"Накануне положите сушёную фасоль в большую миску, залейте не менее чем 2 литрами холодной воды и оставьте замачиваться 8–12 часов; зёрна увеличатся примерно вдвое и потеряют значительную часть сахаров, вызывающих газообразование. На следующий день слейте и промойте фасоль; поместите её в тяжёлую кастрюлю, залейте свежей водой так, чтобы покрыло на 5 см выше, доведите до кипения и варите без крышки 10 минут; снова слейте — это первое быстрое отваривание смягчает бобы и сокращает основное время варки. Верните фасоль в кастрюлю с 1,5 литра свежей воды (или бульона), копчёной грудинкой (если используется) и 2 лавровыми листами; доведите до лёгкого кипения и варите полузакрытой 50–60 минут — фасоль должна быть чуть мягкой, но не разваливаться; соль пока не добавляйте (на этом этапе она делает кожицу жёсткой). Пока фасоль варится, разогрейте масло в широкой глубокой сковороде на среднем огне; положите нарезанный лук и щедрую щепотку соли и готовьте 8–10 минут, часто помешивая, до мягкости и золотистости по краям; добавьте морковь и красный болгарский перец и готовьте ещё 5–6 минут до размягчения. Сдвиньте овощи в сторону, добавьте чеснок в свободное место и готовьте 30 секунд, затем вмешайте паприку и тимьян — прогрейте 20–30 секунд до аромата; добавьте томатную пасту и дроблёные помидоры и готовьте, помешивая, 3–4 минуты, пока томат не потемнеет и масло не выйдет на края. Нарежьте 2 колбаски кружочками по 2 см; остальные 2 оставьте целыми для подачи сверху; добавьте нарезанные кружочки к томатной основе и готовьте 2–3 минуты, чтобы вытопился жир. Влейте кастрюлю с фасолью и её жидкость в томатную основу, добавьте оставшийся лавровый лист, 1,5 ч; л; соли и чёрный перец; утопите целые колбаски в рагу; тушите без крышки 35–45 минут, изредка помешивая, пока фасоль не станет мягкой, а жидкость не загустеет в лёгкую подливу, обволакивающую ложку; добавьте немного воды, если становится слишком густо. Попробуйте, доведите до вкуса солью и при желании добавьте белый винный уксус (немного кислинки оттеняет копчёность); достаньте целые колбаски и нарежьте по диагонали; разлейте фасоль по глубоким мискам, сверху положите веер ломтиков колбаски, посыпьте рубленым укропом и подайте с солёностями и домашним хлебом или мамалыгой.","en":"The night before, place the dried beans in a large bowl, cover with at least 2 litres of cold water, and leave to soak for 8–12 hours; they will roughly double in size and lose much of the gas-producing sugars. The next day, drain and rinse the beans; put them in a heavy pot with fresh water to cover by 5 cm, bring to a boil, and cook uncovered for 10 minutes; drain again — this first quick boil mellows the beans and shortens the final cooking time. Return the beans to the pot with 1.5 litres of fresh water (or stock), the smoked bacon (if using), and 2 of the bay leaves; bring to a gentle simmer and cook partially covered for 50–60 minutes — the beans should be just tender but not falling apart; do not salt yet (salt at this stage toughens the skins). While the beans simmer, heat the oil in a wide deep pan over medium heat; add the diced onions and a generous pinch of salt and cook for 8–10 minutes, stirring often, until soft and golden brown at the edges; add the carrots and red bell pepper and cook for another 5–6 minutes, until softened. Push the vegetables to one side, add the garlic to the empty space and cook for 30 seconds, then stir in the paprika and thyme — toast for 20–30 seconds until fragrant; add the tomato paste and crushed tomatoes and cook, stirring, for 3–4 minutes, until the tomato is deeper red and the oil splits out around the edges. Slice 2 of the smoked sausages into 2 cm rounds; keep the other 2 whole for the top; add the sliced sausage to the tomato base and cook for 2–3 minutes to render some fat. Tip the bean pot and its liquid into the tomato base, add the remaining bay leaf, the 1.5 tsp salt, and the black pepper; bury the whole sausages in the stew; simmer uncovered for 35–45 minutes, stirring occasionally, until the beans are soft and the liquid has thickened to a thin gravy that coats the back of a spoon; add a splash of water if it tightens too much. Taste, adjust with salt, and add the white wine vinegar if using (a touch of acid brightens the smoke); lift out the whole sausages and slice on the diagonal; ladle the beans into deep bowls, top each with a fan of sausage slices, scatter with chopped dill, and serve with pickles and crusty bread or polenta."}},{"id":134,"origin":{"ru":"Венгрия","en":"Hungary","ro":"Ungaria"},"name":{"ru":"Паприкаш из курицы","en":"Chicken Paprikash","ro":"Chicken Paprikash"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["1,5 кг куриных бёдер и голеней на кости с кожей (около 8 кусков)","2 крупные луковицы (около 400 г), мелко нарезанные","3 ст. л. сладкой венгерской паприки (Édesnemes, желательно из Калочи или Сегеда), плюс 0,5 ч. л. острой венгерской паприки (по желанию)","3 зубчика чеснока, мелко нарезанных","1 средний красный болгарский перец, мелко нарезанный","1 средний помидор (около 100 г), очищенный и мелко нарезанный (или 2 ст. л. томатной пасты)","60 г смальца (или 4 ст. л. нейтрального масла)","500 мл горячего несолёного куриного бульона или воды","200 г жирной сметаны (не менее 20% жирности — НЕ берите лёгкую, она расслоится)","1 ст. л. пшеничной муки","1,5 ч. л. мелкой морской соли, плюс по вкусу","0,5 ч. л. свежемолотого чёрного перца","1 ч. л. семян тмина (по желанию, традиционно в некоторых регионах)","Свежий укроп или петрушка, рубленые, для подачи"],"en":["1.5 kg bone-in, skin-on chicken thighs and drumsticks (about 8 pieces)","2 large onions (about 400 g), finely diced","3 tbsp sweet Hungarian paprika (Édesnemes, preferably from Kalocsa or Szeged), plus 0.5 tsp hot Hungarian paprika (optional)","3 garlic cloves, finely chopped","1 medium red bell pepper, finely diced","1 medium tomato (about 100 g), peeled and finely diced (or 2 tbsp tomato paste)","60 g lard (or 4 tbsp neutral oil)","500 ml hot unsalted chicken stock or water","200 g full-fat sour cream (at least 20% fat — do NOT use light sour cream, it will split)","1 tbsp plain (all-purpose) flour","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","1 tsp caraway seeds (optional, traditional in some regions)","Fresh dill or parsley, chopped, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","2 cepe mari (aproximativ 400 g), tocate fin","3 linguri paprika dulce maghiară (Édesnemes, de preferință din Kalocsa sau Szeged), plus 0,5 linguriță paprika iute maghiară (opțional)","3 căței de usturoi, tocați fin","1 ardei gras roșu mediu, tăiat cuburi mici","1 roșie medie (aproximativ 100 g), curățată și tăiată cuburi mici (sau 2 linguri pastă de roșii)","60 g untură (sau 4 linguri ulei neutru)","500 ml supă de pui fierbinte nesărată sau apă","200 g smântână grasă (cel puțin 20% grăsime — NU smântână ușoară, se taie)","1 lingură făină albă","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","1 linguriță semințe de chimen (opțional, tradițional în unele regiuni)","Mărar sau pătrunjel proaspăt tocat, pentru garnitură"]},"howIsMade":{"ru":"Промокните курицу бумажными полотенцами и приправьте обе стороны 1 ч; л; соли и чёрным перцем; дайте постоять 15 минут при комнатной температуре. Растопите смалец в тяжёлом 28-см казане или широкой глубокой сковороде на среднем-сильном огне; двумя партиями обжарьте курицу кожей вниз 4–5 минут, затем 3 минуты с другой стороны, пока кожа не станет тёмно-золотистой — не перегружайте сковороду; переложите на тарелку. Убавьте огонь до среднего и слейте вытопленный жир, оставив около 3 ст; л; добавьте лук и щепотку соли и готовьте 12–15 минут, часто помешивая, до мягкости, блеска и полного золотистого цвета — этот медленный пассеровка является основой вкуса паприкаша. Добавьте чеснок, красный болгарский перец и семена тмина (если используете) и готовьте ещё 2–3 минуты, пока перец слегка не размягчится. Полностью снимите сковороду с огня; вмешайте сладкую паприку (и острую, если используется) — паприка горит и становится горькой на прямом огне, поэтому сковорода должна быть снята с огня; перемешивайте 30 секунд, пока лук не окрасится в насыщенный кирпично-красный цвет и аромат не станет тёплым и сладким. Верните сковороду на средний огонь; добавьте нарезанный помидор (или томатную пасту) и помешивайте 1 минуту; влейте горячий бульон и оставшиеся 0,5 ч; л; соли, затем уложите курицу обратно в соус кожей вверх; доведите до лёгкого кипения. Накройте и тушите на самом малом огне 35–45 минут, пока курица не будет легко отделяться от кости, а внутренняя температура не достигнет 75°C; переложите курицу на тёплое блюдо и накройте фольгой, пока заканчиваете соус. Вмешайте муку в сметану до гладкости, затем добавьте половник горячего соуса, чтобы темперировать; сняв сковороду с огня, влейте темперированную сметану обратно в соус и размешайте до шелковистости; верните курицу в соус только для прогрева, попробуйте и доведите до вкуса солью, затем подавайте над нокедли, свежей пастой или лапшой со сливочным маслом, с рубленым укропом сверху.","en":"Pat the chicken dry with paper towels and season both sides with 1 tsp of the salt and the black pepper; rest at room temperature for 15 minutes. Melt the lard in a heavy 28 cm Dutch oven or wide deep pan over medium-high heat; working in two batches, sear the chicken skin-side down for 4–5 minutes, then 3 minutes on the other side, until the skin is deep golden — do not crowd the pan; lift onto a plate. Reduce the heat to medium and pour off all but about 3 tbsp of the rendered fat; add the onions and a pinch of salt and cook for 12–15 minutes, stirring often, until soft, glossy, and fully golden — this slow sweat is the foundation of paprikash flavour. Add the garlic, red bell pepper, and caraway seeds (if using) and cook for another 2–3 minutes, until the pepper is just softened. Take the pan off the heat completely; stir in the sweet paprika (and hot paprika if using) — paprika scorches and turns bitter on direct heat, so the pan must be off when it goes in; stir for 30 seconds until the onions are stained a deep brick red and the spice smells warm and sweet. Return the pan to medium heat; add the diced tomato (or tomato paste) and stir for 1 minute; pour in the hot stock and the remaining 0.5 tsp salt, then nestle the chicken back into the sauce, skin-side up; bring to a gentle simmer. Cover and braise on the lowest heat for 35–45 minutes, until the chicken pulls easily from the bone and the internal temperature reads 75°C; lift the chicken onto a warm plate and tent with foil while you finish the sauce. Whisk the flour into the sour cream until smooth, then whisk in a ladle of the hot pan sauce to temper; off the heat, pour the tempered cream back into the pan and stir until silky; return the chicken to the sauce just to warm through, taste and adjust salt, then serve over nokedli, fresh pasta, or buttered noodles with chopped dill on top."}},{"id":135,"origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Паста алла Норма","en":"Pasta alla Norma","ro":"Pasta alla Norma"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"ru":["2 средних баклажана (около 700 г в общей сложности), неочищенных, нарезанных кубиками 2 см","1,5 ч. л. мелкой морской соли для подсаливания баклажана, плюс для воды пасты","300 мл оливкового масла extra virgin для жарки баклажана","400 г ригатони, пенне ригате или маккерони","3 ст. л. оливкового масла extra virgin для соуса","3 зубчика чеснока, тонко нарезанных","0,5 ч. л. сушёных хлопьев чили (по желанию)","800 г целых очищенных помидоров (San Marzano, если есть), раздавленных руками, или 700 г пассаты","1 ч. л. сахарного песка (только если помидоры кислые)","0,5 ч. л. свежемолотого чёрного перца","1 большой пучок свежего базилика (около 30 г), листья сорваны и порваны вручную","120 г рикотты салата, мелко натёртой, плюс для подачи","1 ст. л. крупной морской соли для воды пасты"],"en":["2 medium aubergines (about 700 g total), unpeeled, cut into 2 cm cubes","1.5 tsp fine sea salt for salting the aubergine, plus more for the pasta water","300 ml extra-virgin olive oil for shallow-frying the aubergine","400 g rigatoni, penne rigate, or maccheroni","3 tbsp extra-virgin olive oil for the sauce","3 garlic cloves, sliced thin","0.5 tsp dried chilli flakes (optional)","800 g whole peeled tomatoes (San Marzano if available), crushed by hand, or 700 g passata","1 tsp caster sugar (only if the tomatoes are sharp)","0.5 tsp freshly ground black pepper","1 large bunch fresh basil (about 30 g), leaves picked and torn","120 g ricotta salata, finely grated, plus more to serve","1 tbsp coarse sea salt for the pasta water"],"ro":["2 vinete medii (aproximativ 700 g în total), necurățate, tăiate cuburi de 2 cm","1,5 lingurițe sare fină de mare pentru asezonarea vinetelor, plus mai multă pentru apa pastelor","300 ml ulei de măsline extravirgin pentru prăjit vinetele","400 g rigatoni, penne rigate sau maccheroni","3 linguri ulei de măsline extravirgin pentru sos","3 căței de usturoi, feliați subțire","0,5 linguriță fulgi de ardei iute uscat (opțional)","800 g roșii întregi, decojite (San Marzano dacă e posibil), zdrobite cu mâna, sau 700 g pasată","1 linguriță zahăr tos (doar dacă roșiile sunt acrișoare)","0,5 linguriță piper negru proaspăt măcinat","1 legătură mare de busuioc proaspăt (aproximativ 30 g), frunzele rupte","120 g ricotta salata, rasă fin, plus în plus pentru servit","1 lingură sare grunjoasă de mare pentru apa pastelor"]},"howIsMade":{"ru":"Перемешайте кубики баклажана с 1,5 ч; л; мелкой соли в дуршлаге и оставьте стекать над миской 30 минут — это вытягивает горькую воду и не даёт баклажану впитать слишком много масла при жарке; слегка прижмите бумажным полотенцем и обсушите. Разогрейте 300 мл оливкового масла в широкой глубокой сковороде до 170°C; проверьте одним кубиком — он должен бойко шипеть; жарьте баклажаны тремя партиями по 3–4 минуты, часто переворачивая, до глубокого золотистого цвета со всех сторон и мягкости внутри (нож должен входить легко); выньте шумовкой на бумажные полотенца; отложите. Пока баклажаны жарятся, доведите большую кастрюлю с 4 литрами воды и 1 ст; л; крупной соли до бурного кипения. В широкой сотейнике разогрейте 3 ст; л; оливкового масла на среднем огне; добавьте нарезанный чеснок и хлопья чили (по желанию) и готовьте 60–90 секунд — чеснок должен лишь слегка золотиться по краям, ни в коем случае не темнеть. Добавьте раздавленные помидоры, сахар (если используете), 0,5 ч; л; соли и перец; перемешайте и доведите до лёгкого кипения; готовьте 12–15 минут, изредка помешивая, пока соус слегка не загустеет и масло не поднимется наверх; в последнюю минуту вмешайте половину разорванного базилика. Опустите пасту в кипящую воду и варите на 1 минуту меньше, чем указано на упаковке, для al dente; сохраните 250 мл крахмалистой воды от пасты, затем слейте. Вмешайте обжаренные баклажаны в томатный соус, затем добавьте сцеженную пасту; энергично перемешивайте на среднем огне 1–2 минуты, по необходимости добавляя брызги воды от пасты, пока соус не покроет глянцево каждый кусок — он должен стекать при наклоне сковороды, но не быть жидким. Снимите с огня, посыпьте половиной натёртой рикотты салата и почти всем оставшимся базиликом и перемешайте один раз; разложите по четырём тёплым тарелкам, дополните каждую дополнительной рикоттой салата, оставшимися листьями базилика и каплей сырого оливкового масла; подавайте сразу.","en":"Toss the aubergine cubes with the 1.5 tsp fine salt in a colander and leave to drain over a bowl for 30 minutes — this draws out bitter water and stops the aubergine from drinking too much oil during frying; press lightly with a paper towel and pat dry. Heat the 300 ml olive oil in a wide deep frying pan to 170°C; test with a single aubergine cube — it should sizzle briskly; fry the aubergine in three batches for 3–4 minutes per batch, turning often, until deeply golden on all sides and tender inside (a knife should pass through easily); lift onto paper towels with a slotted spoon to drain; reserve. While the aubergine fries, bring a large pot with 4 litres of water and 1 tbsp coarse salt to a rolling boil. In a wide sauté pan, heat the 3 tbsp olive oil over medium heat; add the sliced garlic and chilli flakes (if using) and cook for 60–90 seconds — the garlic should just turn pale gold around the edges, never brown. Add the crushed tomatoes, the sugar (if using), 0.5 tsp salt, and the black pepper; stir and bring to a simmer; cook for 12–15 minutes, stirring occasionally, until the sauce has thickened slightly and the oil rises to the surface; tear in half of the basil for the last minute. Drop the pasta into the boiling water and cook 1 minute less than the package says for al dente; reserve 250 ml of starchy pasta water, then drain. Fold the fried aubergine into the tomato sauce, then add the drained pasta; toss vigorously over medium heat for 1–2 minutes, adding splashes of pasta water as needed, until the sauce clings glossy to every piece — it should be loose enough to flow when you tilt the pan but not watery. Off the heat, scatter half the grated ricotta salata and most of the remaining basil and toss once; divide between four warmed bowls, finish each with more ricotta salata, the last basil leaves, and a drizzle of raw olive oil; serve immediately."}},{"id":137,"origin":{"ru":"Туркмения","en":"Turkmenistan","ro":"Turkmenistan"},"name":{"ru":"Ичлекли","en":"Ichlekli","ro":"Ichlekli"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["500 г пшеничной муки общего назначения, плюс для подсыпания","1 ч. л. мелкой морской соли","240 мл тёплой воды","1 ст. л. нейтрального масла (подсолнечного или виноградных косточек)","500 г бараньей лопатки или говяжьего огузка, мелко нарубленных (или крупно нарезанных и взбитых в комбайне импульсами)","100 г бараньего курдючного жира или говяжьего нутряного, нарезанного мелкими кубиками (или 30 г несолёного сливочного масла как заменитель)","2 крупные луковицы (около 350 г), мелко нарезанные","200 г плотного картофеля, очищенного и нарезанного кубиками 5 мм (по желанию, но традиционно)","1,5 ч. л. мелкой морской соли","1 ч. л. свежемолотого чёрного перца","1 ч. л. молотой зиры","0,5 ч. л. молотого кориандра","0,5 ч. л. сушёных хлопьев красного перца (по желанию)","1 крупный желток, взбитый с 1 ст. л. молока, для смазывания"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","1 tsp fine sea salt","240 ml warm water","1 tbsp neutral oil (sunflower or grapeseed)","500 g lamb shoulder or beef chuck, finely minced (or coarsely diced and pulsed in a processor)","100 g lamb-tail fat or beef suet, finely diced (or 30 g unsalted butter as substitute)","2 large onions (about 350 g), finely diced","200 g waxy potatoes, peeled and diced into 5 mm cubes (optional but traditional)","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground coriander","0.5 tsp dried red pepper flakes (optional)","1 large egg yolk, beaten with 1 tbsp milk, for brushing"],"ro":["500 g făină albă obișnuită, plus pentru întins","1 linguriță sare fină de mare","240 ml apă caldă","1 lingură ulei neutru (de floarea-soarelui sau de struguri)","500 g umăr de miel sau pulpă de vită, tocate fin (sau cuburi mărunte pulsate într-un robot)","100 g grăsime de coadă de miel sau seu de vită, tăiate fin (sau 30 g unt nesărat ca substitut)","2 cepe mari (aproximativ 350 g), tocate fin","200 g cartofi cu pastă fermă, curățați și tăiați cuburi de 5 mm (opțional, dar tradițional)","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță coriandru măcinat","0,5 linguriță fulgi de ardei iute uscat (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru uns"]},"howIsMade":{"ru":"Приготовьте тесто; венчиком смешайте в широкой миске муку и соль; сделайте углубление, влейте тёплую воду и масло и размешайте деревянной ложкой до образования лохматого теста; на слегка подпылённой мукой поверхности замесите 6–8 минут до гладкости, плотности и эластичности — немного крепче хлебного теста; заверните в плёнку и оставьте на 30 минут при комнатной температуре, пока готовите начинку. В большой миске соедините нарубленное мясо, жир, лук, кубики картофеля (если используете), соль, перец, зиру, кориандр и хлопья перца; перемешайте руками 1 минуту, пока масса не станет липкой и хорошо связанной; не пропекайте — начинка готовится внутри теста. Разогрейте духовку до 220°C (425°F / конвекция 200°C) и поставьте перевёрнутый тяжёлый противень или пиццу-камень на средний уровень, чтобы он прогрелся не менее 20 минут; горячая поверхность придаст донышку хрустящую корку. Разделите отдохнувшее тесто на две равные части; на слегка подпылённой мукой поверхности раскатайте одну часть в круг 32 см толщиной около 2 мм — края делайте тоньше центра, чтобы шов не был слишком толстым. Сдвиньте круг на лист пергамента; распределите начинку равномерно по диску, оставляя 2 см бортика, и слегка прижмите её в слой 1,5 см. Раскатайте вторую часть теста в такой же круг 32 см и положите сверху; плотно прижмите два слоя по краю, затем закатайте и защипите бортик внутрь в плотный канат, чтобы не вытек сок. Смажьте верх желтковой глазурью и проколите центр вилкой в 6–8 местах для выхода пара; сдвиньте пирог на пергаменте на горячий противень в духовке; выпекайте 30–35 минут, пока верх не станет насыщенно-золотистым, а дно при постукивании не зазвучит полым. Дайте пирогу отдохнуть на доске 5 минут (пар оседает, начинка стабилизируется), затем разрежьте острым ножом на 8 кусков; подавайте горячим с зелёным чаем, натуральным йогуртом или кислым молоком.","en":"Make the dough; whisk the flour and salt in a wide bowl; make a well, pour in the warm water and oil, and stir with a wooden spoon until a shaggy dough forms; knead on a lightly floured surface for 6–8 minutes until smooth, firm, and elastic — slightly stiffer than bread dough; wrap in cling film and rest at room temperature for 30 minutes while you prepare the filling. In a large bowl, combine the minced lamb, fat, onions, potato cubes (if using), salt, pepper, cumin, coriander, and pepper flakes; mix with your hands for 1 minute until the mixture is sticky and well bound; do not pre-cook — the filling cooks inside the dough. Heat the oven to 220°C (425°F / fan 200°C) and place an upturned heavy baking tray or pizza stone on the middle rack to heat through for at least 20 minutes; the hot surface is what crisps the bottom. Divide the rested dough into two equal pieces; on a lightly floured surface, roll one piece into a 32 cm round, about 2 mm thick — work the edges thinner than the centre so the seal will not be too thick. Slide the round onto a sheet of baking parchment; spread the filling evenly over the disc, leaving a 2 cm border, and press it down lightly into a 1.5 cm layer. Roll out the second piece of dough to the same 32 cm round and lay it on top; press the two layers together firmly around the edge, then roll and pinch the rim inward into a tight rope-like border so no juice can escape. Brush the top with the egg-yolk glaze and prick the centre in 6–8 places with a fork to let steam vent; slide the pie, on its parchment, onto the hot tray in the oven; bake for 30–35 minutes, until the top is deep golden brown and the bottom sounds hollow when you tap it. Rest the pie on a board for 5 minutes (the steam settles and the filling firms up), then cut into 8 wedges with a sharp knife; serve hot with green tea, plain yoghurt, or soured milk."}},{"id":138,"origin":{"ru":"Украина","en":"Ukraine","ro":"Ucraina"},"name":{"ru":"Котлета по-киевски","en":"Chicken Kiev","ro":"Pui Kiev"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["100 г несолёного сливочного масла, размягчённого до комнатной температуры","3 зубчика чеснока, очень мелко нарубленных (или 1 ст. л. чесночной пасты)","30 г листовой петрушки, очень мелко нарубленной","1 ст. л. лимонного сока","0,5 ч. л. мелкой морской соли","0,25 ч. л. свежемолотого чёрного перца","4 крупных куриных грудки без кожи и кости (около 200 г каждая)","1 ч. л. мелкой морской соли для грудок","0,5 ч. л. свежемолотого чёрного перца для грудок","80 г пшеничной муки","2 крупных яйца, взбитых с 1 ст. л. холодной воды","150 г панко или мелких сухих панировочных сухарей","750 мл нейтрального масла (подсолнечного или рапсового) для глубокого жарения","1 ст. л. несолёного сливочного масла для финиширования (по желанию, для более ореховой корочки)","Дольки лимона и небольшой пучок петрушки для подачи"],"en":["100 g unsalted butter, softened to room temperature","3 garlic cloves, very finely minced (or 1 tbsp garlic paste)","30 g flat-leaf parsley, very finely chopped","1 tbsp lemon juice","0.5 tsp fine sea salt","0.25 tsp freshly ground black pepper","4 large skinless chicken breasts (about 200 g each)","1 tsp fine sea salt for the breasts","0.5 tsp freshly ground black pepper for the breasts","80 g plain (all-purpose) flour","2 large eggs, beaten with 1 tbsp cold water","150 g panko or fine dry breadcrumbs","750 ml neutral oil (sunflower or rapeseed), for deep-frying","1 tbsp unsalted butter, for finishing the oil (optional, for a nuttier crust)","Lemon wedges and a small bunch of parsley, to serve"],"ro":["100 g unt nesărat, înmuiat la temperatura camerei","3 căței de usturoi, tocați foarte fin (sau 1 lingură pastă de usturoi)","30 g pătrunjel cu frunze plate, tocat foarte fin","1 lingură suc de lămâie","0,5 linguriță sare fină de mare","0,25 linguriță piper negru proaspăt măcinat","4 piepți mari de pui dezosați și fără piele (aproximativ 200 g fiecare)","1 linguriță sare fină de mare pentru piepți","0,5 linguriță piper negru proaspăt măcinat pentru piepți","80 g făină albă obișnuită","2 ouă mari, bătute cu 1 lingură apă rece","150 g panko sau pesmet fin uscat","750 ml ulei neutru (de floarea-soarelui sau de rapiță), pentru prăjire adâncă","1 lingură unt nesărat, pentru aromatizarea uleiului (opțional, pentru o crustă cu unt prăjit)","Felii de lămâie și o legătură mică de pătrunjel, pentru servit"]},"howIsMade":{"ru":"Приготовьте травяное масло; взбейте мягкое масло в миске с мелко нарубленным чесноком, петрушкой, лимонным соком, 0,5 ч; л; соли и 0,25 ч; л; перца до однородности; выложите на пищевую плёнку, сформуйте колбаску длиной 12 см и толщиной 2 см, плотно заверните и заморозьте не менее 1 часа до плотности, удобной для нарезки. Нарежьте охлаждённую колбаску на 4 равных цилиндра; верните их в морозильник, пока готовите курицу — масло должно быть очень холодным, иначе оно вытечет при жарке. Острым ножом сделайте глубокий горизонтальный карман с толстой стороны каждой грудки, остановившись примерно за 1 см до противоположного края — не прорезайте насквозь; раскройте грудку как книгу, положите между двумя листами плёнки и аккуратно отбейте кухонным молоточком от центра к краям до равномерной толщины 5 мм; приправьте внутри 1 ч; л; соли и 0,5 ч; л; перца. Положите по одному холодному цилиндру масла в центр каждой отбитой грудки; сложите длинные стороны над маслом, затем плотно сверните грудку в закрытый рулет, прижимая, чтобы выпустить воздух; подверните свободные края под низ; каждый рулет заверните в плёнку и охладите 30 минут в холодильнике. Подготовьте три неглубокие миски: одну с мукой, одну с взбитыми яйцами и водой, одну с панировочными сухарями; возьмите рулет, обваляйте в муке и отряхните излишки, затем в яйце (дайте стечь), затем в сухарях — плотно прижмите со всех сторон; снова обмакните в яйцо и сухари: эта двойная панировка не даёт маслу вытечь при жарке; повторите с остальными тремя. Разогрейте масло в глубокой кастрюле до 170°C; проверьте сухариком — он должен зашипеть и стать светло-золотистым за 20 секунд; аккуратно опустите два Киева и жарьте 6–7 минут, перевернув один раз, пока корочка не станет насыщенно-золотистой со всех сторон; выньте на решётку над противнем; повторите с другими двумя. Завершите в духовке, если нужно; положите Киевы на решётку над противнем и выпекайте при 180°C (350°F) 8–10 минут, пока термощуп в мясе (не в масле) не покажет 70°C; так курица прогревается до готовности без перегрева корочки. Дайте 2 минуты отдохнуть на решётке и подавайте; проколите верх каждой котлеты прямо на столе — растопленное масло вырвется золотой струёй; подавайте сразу с дольками лимона и петрушкой, с картофельным пюре или маслянистым рисом.","en":"Make the herb butter; beat the softened butter in a bowl with the minced garlic, chopped parsley, lemon juice, 0.5 tsp salt, and 0.25 tsp pepper until evenly combined; scrape onto cling film, shape into a 12 cm long, 2 cm thick log, wrap tightly, and freeze for at least 1 hour, until firm enough to slice. Slice the chilled butter log into 4 equal cylinders; return them to the freezer while you prepare the chicken — the butter must be very cold or it will leak out during frying. With a sharp knife, cut a deep horizontal pocket into the thick side of each chicken breast, stopping about 1 cm before the opposite edge — do not cut through; open the breast like a book, lay it between two sheets of cling film, and pound gently with a meat mallet to an even 5 mm thickness, working from the centre outwards; season the inside with 1 tsp salt and 0.5 tsp pepper. Place one cold butter cylinder along the centre of each pounded breast; fold the two long sides over the butter, then roll the breast tightly into a sealed cylinder, pressing to expel air; tuck any loose flaps underneath; wrap each parcel in cling film and refrigerate for 30 minutes. Set up three shallow bowls: one with the flour, one with the beaten eggs and water, one with the breadcrumbs; take a parcel, dip in flour and pat off excess, then egg, draining well, then breadcrumbs — press firmly on all sides; dip the egg and breadcrumbs again for a second coat: this double coat is what stops the butter from blowing out during frying; repeat with the other three. Heat the oil in a deep pan to 170°C; test with a breadcrumb — it should sizzle and turn pale gold in 20 seconds; lower two Kievs in carefully and fry for 6–7 minutes, turning once, until the crust is deeply golden brown all over; lift onto a wire rack set over a tray; repeat with the other two. Finish in the oven if needed; place the fried Kievs on a rack over a baking tray and bake at 180°C (350°F) for 8–10 minutes, until a temperature probe pushed into the chicken (not the butter) reads 70°C; this ensures the chicken is cooked through without overcooking the crust. Rest for 2 minutes on the rack, then plate; pierce the top of each Kiev at the table — the molten herb butter will spill out in a golden stream; serve immediately with lemon wedges and parsley, alongside mashed potatoes or buttered rice."}},{"id":139,"origin":{"ru":"Литва","en":"Lithuania","ro":"Lituania"},"name":{"ru":"Цепелинай","en":"Cepelinai","ro":"Cepelinai"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["1,5 кг сырого плотного картофеля (Yukon Gold или похожих сортов), очищенного и взвешенного","500 г рассыпчатого картофеля (Russet или King Edward), очищенного и взвешенного","1 ст. л. лимонного сока или 1 ч. л. лимонной кислоты (чтобы натёртый сырой картофель не темнел)","1 ч. л. мелкой морской соли для теста","2 ст. л. кукурузного крахмала — только если сырой картофель слишком влажный","500 г грубо нарубленной свиной лопатки (или 50% свинина + 50% говядина)","1 средняя луковица (около 150 г), очень мелко нарезанная","1 ч. л. мелкой морской соли для начинки","0,5 ч. л. свежемолотого чёрного перца","1 ч. л. сушёного майорана или сушёного чабера","60 мл холодной воды для начинки","200 г копчёной полосатой грудинки, кубиками","1 крупная луковица (около 200 г), тонко нарезанная","200 г жирной сметаны","Укроп или петрушка, мелко рубленные, для подачи","1 ст. л. крупной морской соли для воды варки"],"en":["1.5 kg raw waxy potatoes (Yukon Gold or similar), peeled and weighed","500 g floury potatoes (Russet or King Edward), peeled and weighed","1 tbsp lemon juice or 1 tsp citric acid (to prevent the raw grated potato from greying)","1 tsp fine sea salt for the dough","2 tbsp cornflour (cornstarch) — only if the raw potato is very wet","500 g coarsely minced pork shoulder (or 50% pork + 50% beef)","1 medium onion (about 150 g), very finely diced","1 tsp fine sea salt for the filling","0.5 tsp freshly ground black pepper","1 tsp dried marjoram or dried savory","60 ml cold water for the filling","200 g smoked streaky bacon, cubed","1 large onion (about 200 g), finely sliced","200 g full-fat sour cream","Dill or parsley, finely chopped, to garnish","1 tbsp coarse sea salt for the cooking water"],"ro":["1,5 kg cartofi cu pastă fermă (Yukon Gold sau similari), curățați și cântăriți după curățare","500 g cartofi făinoși (Russet sau King Edward), curățați și cântăriți după curățare","1 lingură suc de lămâie sau 1 linguriță acid citric (pentru a împiedica înnegrirea cartofului ras crud)","1 linguriță sare fină de mare pentru aluat","2 linguri amidon de porumb — doar dacă aluatul rămâne prea umed","500 g carne de porc tocată grosier (sau 50% porc + 50% vită)","1 ceapă medie (aproximativ 150 g), tocată foarte fin","1 linguriță sare fină de mare pentru umplutură","0,5 linguriță piper negru proaspăt măcinat","1 linguriță maghiran uscat sau cimbru de munte uscat","60 ml apă rece pentru umplutură","200 g bacon afumat striat, tăiat cuburi","1 ceapă mare (aproximativ 200 g), feliată fin","200 g smântână grasă","Mărar sau pătrunjel, tocat fin, pentru garnitură","1 lingură sare grunjoasă de mare pentru apa de fierbere"]},"howIsMade":{"ru":"Сначала приготовьте начинку, чтобы вкусы сошлись; в миске смешайте рукой свиной фарш, мелко нарезанный лук, 1 ч; л; соли, перец, майоран и 60 мл холодной воды в течение 1–2 минут, пока масса не станет липкой и хорошо связанной; накройте и охладите в холодильнике, пока готовите картофельное тесто. Сварите 500 г рассыпчатого картофеля целиком, неочищенным, в подсолённой воде 25–30 минут до мягкости; слейте, очистите горячими и пропустите через картофелемялку или разомните до гладкости; распределите по противню, чтобы остыл до комнатной температуры — горячая мялка проварит сырой картофель на следующем шаге. Натрите 1,5 кг сырого картофеля на мелкой стороне тёрки в большую миску, выстеленную чистым полотенцем; соберите полотенце и сильно отожмите над второй миской, чтобы выжать как можно больше жидкости; получится примерно 250 мл жидкости; дайте ей отстояться 5 минут. Аккуратно слейте прозрачную воду из миски с выжатой жидкостью, оставив белый крахмал, осевший на дне; соскребите этот крахмал обратно к отжатой натёртой картошке — это естественный связующий компонент, который держит цепеллины; добавьте остывшее пюре, лимонный сок и 1 ч; л; соли; энергично вымешивайте руками 2–3 минуты до клейкого, эластичного теста; кукурузный крахмал добавьте только если тесто остаётся слишком влажным. Мокрыми руками разделите тесто на 8 равных частей (около 220 г каждая); расплющите одну часть на мокрой ладони в овал 12 × 8 см, положите в центр около 60 г охлаждённой начинки и обтяните тесто вокруг начинки, защипывая по краям, чтобы полностью запечатать; сформуйте 12-см «цеппелин», без трещин, через которые могли бы попасть пар или вода. В широкой глубокой кастрюле доведите 4 литра воды с 1 ст; л; крупной соли до лёгкого кипения (не бурного — сильная вода разорвёт цепеллины); опустите цепеллины двумя партиями, аккуратно один раз перемешайте, чтобы они не прилипли ко дну, и варите 25–30 минут на самом слабом кипении, пока поверхность не перейдёт от матовой к прозрачной и они не всплывут высоко. Пока они варятся, приготовьте соус; обжарьте кубики бекона на сухой сковороде на среднем огне 6–8 минут, пока жир не вытопится, а кубики не станут хрустящими; добавьте нарезанный лук и готовьте ещё 5–6 минут до мягкости и лёгкой золотистости; перемешайте, снимите с огня и держите в тепле. Достаньте готовые цепеллины шумовкой на тёплые тарелки — по 2 на человека; щедро посыпьте смесью бекона с луком и её жиром, увенчайте горкой холодной сметаны и завершите рубленым укропом; подавайте сразу, пока всё горячее, а серединки сочные.","en":"Make the filling first so the flavours marry; mix the minced pork, finely diced onion, 1 tsp salt, pepper, marjoram, and 60 ml cold water in a bowl with your hand for 1–2 minutes, until the mixture is sticky and well bound; cover and chill while you prepare the potato dough. Boil the 500 g floury potatoes whole and unpeeled in salted water for 25–30 minutes, until very tender; drain, peel while hot, and pass through a ricer or mash smoothly; spread out on a tray to cool to room temperature — hot mash would cook the raw potato in the next step. Grate the 1.5 kg waxy potatoes on the fine side of a box grater into a large bowl lined with a clean kitchen towel; gather the towel and squeeze hard over a second bowl to extract as much liquid as possible; you should end up with about 250 ml of liquid; leave it to settle for 5 minutes. Carefully pour off the clear water from the bowl of squeezed liquid, leaving the white starch settled at the bottom; scrape this starch back into the squeezed grated potato — it is the natural binder that holds the dumplings together; add the cooled mashed potato, the lemon juice, and 1 tsp salt; mix vigorously by hand for 2–3 minutes, until you have a sticky, elastic dough; add the cornflour only if the dough still feels wet. With wet hands, divide the dough into 8 equal pieces (about 220 g each); flatten one piece on a wet palm into a 12 × 8 cm oval, place about 60 g of the chilled filling in the centre, then wrap the dough up and around the filling, pinching to seal completely; smooth into a 12 cm zeppelin shape, with no cracks where steam or water could enter. Bring a wide deep pan with 4 litres of water and 1 tbsp coarse salt to a gentle simmer (not a rolling boil — vigorous water can break the dumplings); lower the cepelinai in 2 batches, stir gently once to keep them off the base, and cook for 25–30 minutes at the gentlest simmer, until the surface goes from matte to translucent and the dumplings float high. While they cook, make the sauce; cook the cubed bacon in a dry frying pan over medium heat for 6–8 minutes until the fat renders and the cubes are crisp; add the sliced onion and cook for another 5–6 minutes until soft and lightly golden; stir off the heat and keep warm. Lift the cooked cepelinai out with a slotted spoon onto warmed plates — 2 per person; scatter generously with the bacon-onion mixture and its fat, top with a heap of cold sour cream, and finish with chopped dill; serve immediately while everything is hot and the centres are juicy."}},{"id":140,"origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Фрикасе из курицы","en":"Chicken Fricassée","ro":"Fricassée de Poulet"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"french","ingredients":{"ru":["1,5 кг куриных бёдер и голеней с костью и кожей (около 8 кусков), или цельная курица 1,5 кг, разделанная на 8 частей","1 ч. л. мелкой морской соли + 0,5 ч. л. свежемолотого белого перца (чёрный перец сгодится, но даст крапины в соусе)","60 г несолёного сливочного масла, разделённого на 30 г + 30 г","2 ст. л. нейтрального масла","250 г жемчужного лука или мелкого шалота, очищенного (или 1 средняя луковица мелко нарезанная)","200 г шампиньонов (белых или коричневых), разрезанных пополам или на четвертинки","2 средние моркови (около 200 г), очищенные и нарезанные брусочками по 5 см","2 зубчика чеснока, мелко нарубленных","30 г пшеничной муки общего назначения","150 мл сухого белого вина (Riesling или Sauvignon Blanc)","500 мл горячего несолёного куриного бульона","1 небольшой букет гарни (1 лавровый лист + 4 веточки тимьяна + 4 стебля петрушки, связанные ниткой)","200 мл сливок 35% жирности или выше, плюс 2 желтка по желанию для более насыщенной лиезон","1 ст. л. свежего лимонного сока","2 ст. л. мелко нарубленной свежей листовой петрушки для подачи"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces), or a 1.5 kg whole chicken jointed into 8","1 tsp fine sea salt + 0.5 tsp freshly ground white pepper (black pepper works but speckles the sauce)","60 g unsalted butter, divided into 30 g + 30 g","2 tbsp neutral oil","250 g pearl onions or small shallots, peeled (or 1 medium onion finely diced)","200 g chestnut or button mushrooms, halved or quartered if large","2 medium carrots (about 200 g), peeled and cut into 5 cm batons","2 garlic cloves, finely minced","30 g plain (all-purpose) flour","150 ml dry white wine (Riesling or Sauvignon Blanc)","500 ml hot unsalted chicken stock","1 small bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks tied with string)","200 ml double cream (heavy cream, 35% fat or higher), plus 2 optional egg yolks for a richer liaison","1 tbsp fresh lemon juice","2 tbsp finely chopped fresh flat-leaf parsley, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți) sau 1,5 kg pui întreg dezasamblat în 8 bucăți","1 linguriță sare fină de mare + 0,5 linguriță piper alb proaspăt măcinat (piperul negru funcționează dar pătează sosul)","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru","250 g cepe de primăvară sau eșalote mici, decojite (sau 1 ceapă medie tocată fin)","200 g ciuperci champignon (albe sau brune), tăiate în jumătăți sau sferturi dacă sunt mari","2 morcovi medii (aproximativ 200 g), curățați și tăiați bastonașe de 5 cm","2 căței de usturoi, tocați fin","30 g făină albă obișnuită","150 ml vin alb sec (Riesling sau Sauvignon Blanc)","500 ml supă de pui fierbinte nesărată","1 bouquet garni mic (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel legate cu sfoară)","200 ml smântână grasă (cel puțin 35% grăsime), plus 2 gălbenușuri opționale pentru o legătură mai bogată","1 lingură suc de lămâie proaspăt","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură"]},"howIsMade":{"ru":"Промокните куски курицы бумажными полотенцами и приправьте обе стороны 1 ч; л; соли и белым перцем; оставьте на 15 минут при комнатной температуре. Разогрейте 30 г сливочного масла и 2 ст; л; растительного масла в широком сотейнике 28 см или казане на среднем огне; когда масло вспенится, выложите курицу кожей вниз в один слой (партиями при необходимости) и обжаривайте по 5–6 минут с каждой стороны — поверхность должна стать бледно-золотистой, НЕ коричневой; тёмная корочка замутнила бы соус; переложите на тарелку. Убавьте огонь до средне-малого; положите в сковороду жемчужный лук и обжаривайте 5–6 минут, помешивая, до лёгкой золотистости, оставаясь светлым; переложите к курице. Добавьте морковь и грибы и готовьте 4–5 минут — грибы отдадут воду и снова её впитают; добавьте чеснок и помешивайте 30 секунд. Посыпьте овощи мукой и непрерывно помешивайте 2 минуты, чтобы выпарить сырой вкус муки — вокруг овощей образуется бледная заправка; влейте вино, доведите до энергичного кипения, поскрёбывая дно, и уварите наполовину за 1–2 минуты. Верните курицу и лук в сковороду одним слоем; влейте горячий бульон почти до покрытия, добавьте букет гарни и доведите до самого слабого кипения; накройте крышкой и тушите 30–35 минут для бёдер (или 25 минут для грудки, снятой раньше), пока мясо не будет легко отделяться от кости, а внутренняя температура не достигнет 75°C. Переложите курицу и овощи на тёплое блюдо и накройте фольгой; удалите букет гарни; доведите соус на среднем огне до интенсивного кипения и уварите 3–5 минут, пока он не будет покрывать обратную сторону ложки (около 350 мл). Приготовьте лиезон; взбейте сливки с желтками в небольшой миске; введите половник горячего соуса, чтобы темперировать, затем влейте темперированную смесь обратно в сковороду, сняв с огня; аккуратно перемешайте — НЕ ДОВОДИТЬ ДО КИПЕНИЯ, иначе желтки свернутся; добавьте лимонный сок, попробуйте и при необходимости подсолите; полейте курицу, посыпьте рубленой петрушкой и подавайте сразу с рисом, лапшой со сливочным маслом или картофелем на пару.","en":"Pat the chicken pieces dry with paper towels and season both sides with 1 tsp salt and the white pepper; rest at room temperature for 15 minutes. Heat 30 g of the butter and 2 tbsp oil in a wide 28 cm heavy-based sauté pan or Dutch oven over medium heat; when the butter foams, add the chicken skin-side down in one layer (work in batches if needed) and cook 5–6 minutes per side — the surface should turn pale gold and gilded, NOT brown; a brown crust would muddy the sauce; lift onto a plate. Reduce the heat to medium-low; add the pearl onions to the same pan and cook for 5–6 minutes, stirring, until lightly gilded but still pale; lift onto the plate with the chicken. Add the carrots and mushrooms to the pan and cook for 4–5 minutes — the mushrooms will release their water and reabsorb it; add the garlic and stir for 30 seconds. Sprinkle the flour over the vegetables and stir constantly for 2 minutes to cook out the raw taste — a pale roux will form around the vegetables; pour in the wine and bring to a brisk simmer, scraping up any sediment from the pan base, until reduced by half (1–2 minutes). Return the chicken and pearl onions to the pan in a single layer; pour in the hot stock to nearly cover, tuck in the bouquet garni, and bring to the gentlest simmer; cover and cook for 30–35 minutes for thighs (or 25 minutes for breasts removed earlier), until the meat pulls easily from the bone and the internal temperature reads 75°C. Lift the chicken and vegetables to a warmed dish and cover with foil; discard the bouquet garni; bring the sauce to a brisk simmer over medium heat and reduce for 3–5 minutes, until it coats the back of a spoon (about 350 ml). Make the liaison; whisk the cream and egg yolks together in a small bowl; whisk in a ladle of hot sauce to temper, then pour the tempered mixture back into the pan off the heat; stir gently — DO NOT BOIL, or the yolks will scramble; add the lemon juice, taste and adjust the salt; pour over the chicken, scatter with chopped parsley, and serve immediately with rice, buttered noodles, or steamed potatoes."}},{"id":141,"origin":{"ru":"Кувейт","en":"Kuwait","ro":"Kuweit"},"name":{"ru":"Мачбус","en":"Machboos","ro":"Machboos"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"ru":["1,5 кг куриных бёдер и голеней с костью и кожей (или 1,2 кг бараньей лопатки на кости, нарезанной кусками по 6 см)","400 г риса басмати, промытого и замоченного в холодной воде на 30 минут, затем откинутого","60 мл нейтрального масла (или 30 г топлёного масла гхи + 2 ст. л. растительного масла для большей насыщенности)","3 крупные луковицы (около 600 г), тонко нарезанные — небольшую часть оставить сырой для подачи","6 зубчиков чеснока, мелко нарезанных","Кусочек свежего имбиря размером с большой палец (около 30 г), мелко натёртый","3 средних помидора (около 300 г), натёртые (или 200 г консервированных рубленых томатов)","2 ст. л. томатной пасты","2 сушёных лайма (loomi), проколотых ножом в 3 местах (или 2 ст. л. свежего сока лайма как менее традиционная замена)","1 ст. л. бахарат (или 1 ч. л. молотой корицы + 1 ч. л. молотой зиры + 1 ч. л. молотого кориандра + 0,5 ч. л. молотого кардамона + 0,5 ч. л. молотого чёрного перца)","0,5 ч. л. молотой куркумы","4 целые зелёные коробочки кардамона, слегка надрезанные + 1 палочка корицы (5 см) + 4 целые гвоздики + 2 лавровых листа","1 небольшой пучок свежей кинзы (около 30 г), стебли мелко нарезаны для кастрюли, листья оставлены для подачи","2 свежих зелёных перца чили, надрезанных вдоль","1,2 литра горячей воды (или несолёного куриного бульона для большей насыщенности)","1,5 ч. л. мелкой морской соли, плюс по вкусу","60 г миндальных лепестков и 40 г светлого изюма, слегка обжаренных в 1 ч. л. гхи (для посыпки)","0,5 ч. л. нитей шафрана, замоченных в 2 ст. л. тёплой воды (по желанию, для финиша риса)"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (or 1.2 kg bone-in lamb shoulder cut into 6 cm chunks)","400 g basmati rice, rinsed and soaked in cold water for 30 minutes, then drained","60 ml neutral oil (or 30 g ghee + 2 tbsp oil for a richer flavour)","3 large onions (about 600 g), finely sliced — reserve a small handful raw for serving","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 30 g), finely grated","3 medium tomatoes (about 300 g), grated (or 200 g canned chopped tomatoes)","2 tbsp tomato paste","2 dried limes (loomi), pierced with a knife in 3 places (or 2 tbsp fresh lime juice as a less-traditional substitute)","1 tbsp baharat (or 1 tsp ground cinnamon + 1 tsp ground cumin + 1 tsp ground coriander + 0.5 tsp ground cardamom + 0.5 tsp ground black pepper)","0.5 tsp ground turmeric","4 whole green cardamom pods, lightly cracked + 1 cinnamon stick (5 cm) + 4 whole cloves + 2 bay leaves","1 small bunch fresh coriander (about 30 g), stems chopped fine for the pot, leaves reserved for garnish","2 fresh green chillies, slit lengthwise","1.2 litres hot water (or unsalted chicken stock for more depth)","1.5 tsp fine sea salt, plus more to taste","60 g flaked almonds and 40 g sultanas, lightly toasted in 1 tsp ghee (to scatter on top)","0.5 tsp saffron threads soaked in 2 tbsp warm water (optional, for finishing the rice)"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (sau 1,2 kg umăr de miel cu os tăiat bucăți de 6 cm)","400 g orez basmati, clătit și înmuiat în apă rece 30 de minute, apoi scurs","60 ml ulei neutru (sau 30 g ghee + 2 linguri ulei pentru aromă mai bogată)","3 cepe mari (aproximativ 600 g), feliate fin — păstrează o mică parte crudă pentru servit","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 30 g), ras fin","3 roșii medii (aproximativ 300 g), date pe răzătoare (sau 200 g roșii sfărâmate din conservă)","2 linguri pastă de roșii","2 lămâi uscate (loomi), înțepate cu cuțitul în 3 locuri (sau 2 linguri suc proaspăt de lime ca substitut mai puțin tradițional)","1 lingură baharat (sau 1 linguriță scorțișoară măcinată + 1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 0,5 linguriță cardamom măcinat + 0,5 linguriță piper negru măcinat)","0,5 linguriță turmeric măcinat","4 capsule întregi de cardamom verde, ușor crăpate + 1 baton de scorțișoară (5 cm) + 4 cuișoare + 2 foi de dafin","1 legătură mică de coriandru proaspăt (aproximativ 30 g), tijele tocate fin pentru oală, frunzele păstrate pentru garnitură","2 ardei iuți verzi proaspeți, crestați pe lungime","1,2 litri apă fierbinte (sau supă de pui nesărată pentru profunzime)","1,5 lingurițe sare fină de mare, plus după gust","60 g migdale feliate și 40 g stafide blonde, ușor prăjite în 1 linguriță ghee (pentru deasupra)","0,5 linguriță fire de șofran înmuiate în 2 linguri apă caldă (opțional, pentru finisarea orezului)"]},"howIsMade":{"ru":"Промойте рис басмати под холодной проточной водой до почти прозрачной воды, затем замочите в свежей холодной воде на 30 минут; это смывает избыток крахмала и сокращает финальное время варки; слейте непосредственно перед использованием. Обсушите куски курицы и приправьте 0,5 ч; л; соли; разогрейте масло (или гхи + масло) в тяжёлой кастрюле 28 см на среднем-сильном огне; когда оно заблестит, выложите курицу кожей вниз и обжаривайте 4–5 минут с каждой стороны до насыщенно-золотистой корочки; переложите на тарелку. Убавьте огонь до среднего; добавьте нарезанный лук и щепотку соли в ту же кастрюлю и готовьте 12–15 минут, часто помешивая, до тёмно-золотистого цвета и мягкости; добавьте чеснок и имбирь и готовьте 1 минуту до появления аромата. Вмешайте коробочки кардамона, палочку корицы, гвоздику, лавровые листья, бахарат и куркуму; прогрейте 30 секунд — специи раскроют аромат и потемнеют; добавьте томатную пасту и натёртые помидоры и готовьте, помешивая, 4–5 минут, пока смесь не станет тёмно-красной, а масло не выйдет на края. Верните курицу в кастрюлю одним слоем; влейте горячую воду (или бульон), добавьте сушёные лаймы, надрезанные перцы, рубленые стебли кинзы и оставшуюся соль; доведите до лёгкого кипения, накройте крышкой, убавьте до минимального кипения и варите 35–40 минут (курица) или 1 ч 30 мин (баранина), пока мясо не будет легко отделяться от кости, а бульон не станет глубоко ароматным. Достаньте курицу на тарелку и неплотно накройте фольгой; снимите излишний жир с поверхности бульона. Добавьте промытый рис в кастрюлю, аккуратно прижмите, чтобы он был только покрыт бульоном (при необходимости долейте горячей воды — слой жидкости над рисом должен быть около 2,5 см); доведите до лёгкого кипения, накройте плотной крышкой, уменьшите до минимума и варите без перемешивания 18 минут. Выключите огонь; сбрызните рис шафрановой водой (по желанию), уложите куриные куски сверху, верните крышку и дайте настояться 10 минут — пар довершит готовку курицы, а рис распушится; распушите рис вилкой, переложите на широкое блюдо, сверху положите курицу и посыпьте обжаренным миндалём, изюмом, кольцами сырого лука и листьями кинзы; подавайте с диибой (тамариндовый соус) или йогуртом.","en":"Rinse the basmati rice under cold running water until the water runs almost clear, then soak in fresh cold water for 30 minutes; this removes excess starch and shortens the final cooking step; drain just before use. Pat the chicken pieces dry and season with 0.5 tsp of the salt; heat the oil (or ghee + oil) in a heavy 28 cm pot over medium-high heat; when shimmering, add the chicken skin-side down and sear for 4–5 minutes per side until deep golden; lift onto a plate. Reduce the heat to medium; add the sliced onions and a pinch of salt to the same pot and cook for 12–15 minutes, stirring often, until deeply golden and very soft; add the garlic and ginger and cook for 1 minute until fragrant. Stir in the cardamom pods, cinnamon stick, cloves, bay leaves, baharat, and turmeric; toast for 30 seconds — the spices should turn aromatic and deepen in colour; add the tomato paste and grated tomatoes and cook, stirring, for 4–5 minutes, until the mixture darkens to a rich red and the oil splits out around the edges. Return the chicken to the pot in a single layer; pour in the hot water (or stock), add the dried limes, slit chillies, chopped coriander stems, and remaining salt; bring to a gentle boil, then cover, reduce to the lowest simmer, and cook for 35–40 minutes (chicken) or 1 h 30 min (lamb), until the meat is fork-tender and the broth is deeply flavoured. Lift the chicken onto a plate and cover loosely with foil to keep warm; skim any excess fat from the broth. Add the drained rice to the pot, gently pushing it down so it is just covered by the broth (top up with hot water if needed — you want about 2.5 cm of liquid above the rice); bring back to a gentle boil, then cover with a tight lid, reduce to the lowest possible heat, and cook undisturbed for 18 minutes. Turn off the heat; drizzle the saffron water (if using) over the rice, place the chicken pieces on top, replace the lid, and rest for 10 minutes — the steam finishes cooking the chicken and the rice grains separate; fluff the rice with a fork, transfer to a wide platter with the chicken on top, and scatter with toasted almonds, sultanas, raw onion slices, and fresh coriander leaves; serve with deeba (tamarind sauce) or yoghurt on the side."}},{"id":142,"origin":{"ru":"Республика Конго","en":"Republic of the Congo","ro":"Republica Congo"},"name":{"ru":"Курица муамбе","en":"Moambe chicken","ro":"Pui Moambe"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["1,5 кг куриных бёдер и голеней с костью и кожей (около 8 кусков)","1 ч. л. мелкой морской соли + 0,5 ч. л. свежемолотого чёрного перца для курицы","60 мл красного пальмового масла (или 30 мл пальмового + 2 ст. л. нейтрального, если вкус слишком интенсивный)","2 крупные луковицы (около 400 г), мелко нарезанные","6 зубчиков чеснока, мелко нарезанных","Кусочек свежего имбиря размером с большой палец (около 20 г), мелко натёртый","400 г спелых помидоров, натёртых, или 1 × 400 г консервированных рубленых томатов","2 ст. л. томатной пасты","100 г несладкой кремовой арахисовой пасты (или 200 г консервированной пасты моамбе, если доступна)","2 свежих перца скотч-боннет или хабанеро, надрезанных вдоль (или 1 ч. л. сушёных хлопьев чили; по вкусу — моамбе острая)","2 лавровых листа","500 мл горячего несолёного куриного бульона или воды","1,5 ч. л. мелкой морской соли, плюс по вкусу","2 ст. л. мелко нарубленной листовой петрушки (или 2 ст. л. лимонного базилика), для подачи","Белый рис на пару, фуфу или варёные бананы плантан, для подачи"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces)","1 tsp fine sea salt + 0.5 tsp freshly ground black pepper for the chicken","60 ml red palm oil (or 30 ml palm + 2 tbsp neutral oil if the flavour is too strong)","2 large onions (about 400 g), finely diced","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 20 g), finely grated","400 g ripe tomatoes, grated, or 1 × 400 g can chopped tomatoes","2 tbsp tomato paste","100 g unsweetened smooth peanut butter (or 200 g canned moambe palm paste when available)","2 fresh scotch bonnet or habanero chillies, slit lengthwise (or 1 tsp dried chilli flakes; adjust to taste — moambe is hot)","2 bay leaves","500 ml hot unsalted chicken stock or water","1.5 tsp fine sea salt, plus more to taste","2 tbsp finely chopped flat-leaf parsley (or 2 tbsp lemon basil), to garnish","Steamed white rice, fufu, or boiled plantains, to serve"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","1 linguriță sare fină de mare + 0,5 linguriță piper negru proaspăt măcinat pentru pui","60 ml ulei de palmier roșu (sau 30 ml palmier + 2 linguri ulei neutru dacă aroma e prea puternică)","2 cepe mari (aproximativ 400 g), tocate fin","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 20 g), ras fin","400 g roșii coapte, date pe răzătoare (sau 1 × 400 g conservă de roșii tocate)","2 linguri pastă de roșii","100 g unt de arahide neîndulcit, fin (sau 200 g pastă de moambe la conservă, când e disponibilă)","2 ardei iuți proaspeți scotch bonnet sau habanero, crestați pe lungime (sau 1 linguriță fulgi de ardei iute; ajustează după gust — muambe este picant)","2 foi de dafin","500 ml supă de pui fierbinte nesărată sau apă","1,5 lingurițe sare fină de mare, plus după gust","2 linguri pătrunjel cu frunze plate tocat fin (sau 2 linguri busuioc de lămâie), pentru garnitură","Orez alb fiert, fufu sau banane plantain fierte, pentru servit"]},"howIsMade":{"ru":"Обсушите куски курицы и приправьте обе стороны 1 ч; л; соли и 0,5 ч; л; перца; дайте 15 минут постоять при комнатной температуре. Разогрейте пальмовое масло в тяжёлой кастрюле 28 см на среднем-сильном огне — оно тает в насыщенно-оранжево-красную жидкость; когда заблестит, выложите курицу кожей вниз одним слоем (двумя партиями при необходимости) и обжаривайте по 4–5 минут с каждой стороны до глубокого золотистого цвета кожи; переложите на тарелку. Убавьте огонь до среднего; добавьте нарезанный лук и щепотку соли в ту же кастрюлю и готовьте 8–10 минут, часто помешивая, до мягкости, блеска и лёгкой золотистости без подрумянивания. Добавьте чеснок и имбирь и готовьте 1 минуту до аромата; вмешайте томатную пасту и натёртые помидоры и готовьте 5–6 минут, помешивая, пока смесь не приобретёт насыщенный кирпично-красный цвет, а пальмовое масло не начнёт отделяться по краям — это разделение масла фирменный признак моамбе. Взбейте арахисовую пасту с 200 мл горячего бульона в маленькой миске до гладкости, затем влейте в кастрюлю и перемешайте; добавьте оставшиеся 300 мл бульона, лавровые листья, надрезанные перцы чили и оставшиеся 0,5 ч; л; соли. Верните курицу в кастрюлю одним слоем, утопив куски в соусе кожей вверх, чтобы кожа оставалась над жидкостью; доведите до лёгкого кипения. Накройте крышкой с небольшим зазором и тушите на минимальном огне 35–40 минут, перемешав один раз посередине, пока курица не будет легко отделяться от кости, а внутренняя температура не достигнет 75°C; соус должен быть кораллово-оранжевым и достаточно густым, чтобы покрывать обратную сторону ложки — если слишком уварится, разбавьте небольшим количеством горячей воды. Попробуйте и подкорректируйте соль или добавьте чили; переложите курицу в тёплое блюдо, щедро полейте соусом, посыпьте рубленой петрушкой и сразу подавайте с рисом на пару, фуфу или варёным плантаном, чтобы впитать соус.","en":"Pat the chicken pieces dry and season both sides with 1 tsp salt and 0.5 tsp pepper; rest at room temperature for 15 minutes. Heat the palm oil in a heavy 28 cm pot over medium-high heat — palm oil melts into a deep orange-red liquid; when shimmering, add the chicken pieces skin-side down in one layer (work in two batches if needed) and sear for 4–5 minutes per side until the skin is deep golden; lift onto a plate. Reduce the heat to medium; add the diced onions and a pinch of salt to the same pot and cook for 8–10 minutes, stirring often, until soft, glossy, and lightly golden but not browned. Add the garlic and ginger and cook for 1 minute until fragrant; stir in the tomato paste and grated tomatoes and cook for 5–6 minutes, stirring, until the mixture darkens to a rich brick-red and the palm oil starts to separate around the edges — this oil split is the signature look of moambe. Whisk the peanut butter with 200 ml of the hot stock in a small bowl until smooth, then pour into the pot and stir to combine; add the remaining 300 ml stock, the bay leaves, slit chillies, and the remaining 0.5 tsp salt. Return the chicken to the pot in a single layer, nestling the pieces into the sauce skin-side up so the skin stays above the liquid; bring to a gentle simmer. Cover with a lid set slightly ajar and cook on the lowest heat for 35–40 minutes, stirring once at the halfway mark, until the chicken pulls easily from the bone and the internal temperature reads 75°C; the sauce should be coral-orange and thick enough to coat the back of a spoon — if it tightens too much, loosen with a splash of hot water. Taste and adjust with salt or extra chilli; lift the chicken into a warmed serving dish, spoon the sauce generously over the top, scatter with chopped parsley, and serve immediately with steamed rice, fufu, or boiled plantain to soak up the sauce."}},{"id":143,"origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Кассуле","en":"Cassoulet","ro":"Cassoulet"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["500 г сушёной белой фасоли (haricot tarbais или cannellini), замоченной в холодной воде на ночь","4 ножки утиного конфи (cuisses de canard confites), при комнатной температуре, жир сохранён","400 г свиной лопатки, нарезанной кусками по 4 см","300 г свиной грудинки со шкурой, нарезанной кусками по 3 см","4 тулузские колбаски (около 500 г) — или копчёные свиные колбаски как замена","1 крупная морковь (около 150 г), очищенная и нарезанная кусками по 2 см","1 крупная луковица (около 200 г), очищенная и наколотая 4 целыми гвоздичками","1 головка чеснока (около 60 г), разрезанная горизонтально пополам","1 букет гарни (1 лавровый лист + 4 веточки тимьяна + 4 стебля петрушки + кусочек сушёной апельсиновой цедры, связанные)","1 свиная рулька на кости или окорок (около 400 г, по желанию, но традиционно)","200 г консервированных рубленых томатов (или 2 спелых помидора, очищенных от кожуры и нарезанных)","2 ст. л. томатной пасты","1,5 литра несолёного куриного или свиного бульона (или воды)","60 г крупных белых панировочных сухарей","1,5 ч. л. мелкой морской соли, плюс по вкусу","1 ч. л. свежемолотого чёрного перца","2 ст. л. мелко нарубленной листовой петрушки, для подачи","2 ст. л. утиного жира (от конфи), для обжарки мяса"],"en":["500 g dried white beans (haricot tarbais or cannellini), soaked in cold water overnight","4 confit duck legs (cuisses de canard confites), at room temperature, fat reserved","400 g pork shoulder, cut into 4 cm pieces","300 g pork belly with rind, cut into 3 cm pieces","4 Toulouse sausages (about 500 g) — or smoked pork sausages as a substitute","1 large carrot (about 150 g), peeled and cut into 2 cm chunks","1 large onion (about 200 g), peeled and studded with 4 whole cloves","1 head of garlic (about 60 g), halved horizontally","1 bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks + a piece of dried orange peel, tied)","1 pork knuckle bone or ham hock (about 400 g, optional but traditional)","200 g canned chopped tomatoes (or 2 ripe tomatoes, peeled and chopped)","2 tbsp tomato paste","1.5 litres unsalted chicken or pork stock (or water)","60 g coarse white breadcrumbs","1.5 tsp fine sea salt, plus more to taste","1 tsp freshly ground black pepper","2 tbsp finely chopped fresh flat-leaf parsley, to garnish","2 tbsp duck fat (from the confit), for browning the meats"],"ro":["500 g fasole albă uscată (haricot tarbais sau cannellini), înmuiată în apă rece peste noapte","4 pulpe de rață confit (cuisses de canard confites), la temperatura camerei, grăsimea păstrată","400 g umăr de porc, tăiat bucăți de 4 cm","300 g piept de porc cu șorici, tăiat bucăți de 3 cm","4 cârnați de Toulouse (aproximativ 500 g) — sau cârnați afumați de porc ca substitut","1 morcov mare (aproximativ 150 g), curățat și tăiat bucăți de 2 cm","1 ceapă mare (aproximativ 200 g), curățată și înfiptă cu 4 cuișoare întregi","1 căpățână de usturoi (aproximativ 60 g), tăiată orizontal","1 bouquet garni (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel + o bucată de coajă uscată de portocală, legate)","1 os de jambon afumat sau o ciolan de porc (aproximativ 400 g, opțional dar tradițional)","200 g roșii sfărâmate din conservă (sau 2 roșii coapte, decojite și tocate)","2 linguri pastă de roșii","1,5 litri supă de pui sau de porc nesărată (sau apă)","60 g pesmet alb grosier","1,5 lingurițe sare fină de mare, plus după gust","1 linguriță piper negru proaspăt măcinat","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură","2 linguri grăsime de rață (din confit), pentru rumenirea cărnurilor"]},"howIsMade":{"ru":"Накануне поместите фасоль в большую миску, залейте не менее 2 литрами холодной воды и замочите на 10–12 часов; она увеличится примерно вдвое; на следующий день слейте и промойте. Приготовьте фасолевый бульон; положите слитую фасоль в тяжёлую 5-литровую кастрюлю с рулькой (если используется), луковицей с гвоздикой, разрезанной головкой чеснока, морковью, букетом гарни и 1,5 литра холодного бульона; доведите до лёгкого кипения и варите без крышки 50–60 минут, пока фасоль не будет чуть мягкой, но не разваливаться; соль пока не добавляйте. Тем временем обжарьте мясо; растопите 2 ст; л; утиного жира в широкой сковороде на среднем-сильном огне; обсушите свиную лопатку и грудинку и обжаривайте партиями 4–5 минут с каждой стороны до глубокого золотистого цвета; переложите на тарелку; в том же жире обжарьте тулузские колбаски 2–3 минуты с каждой стороны, только чтобы окрасить оболочку; добавьте на тарелку. Разогрейте духовку до 160°C (320°F / конвекция 140°C); достаньте из кастрюли с фасолью рульку, лук, чеснок, морковь и букет гарни и выбросьте ароматные ингредиенты; снимите мясо с косточки рульки, крупно разделите и отложите; вмешайте томатную пасту и рубленые помидоры в бульон, попробуйте и добавьте 1,5 ч; л; соли и перец. Соберите кассуле в широком 26-см кассоле (или любой широкой жаропрочной кастрюле); распределите треть фасоли на дне, затем сверху уложите обжаренную свиную лопатку, грудинку, мясо рульки и холодные ножки утиного конфи; накройте ещё одной третью фасоли, выложите сверху обжаренные колбаски и завершите оставшейся фасолью; залейте бульоном так, чтобы он только покрывал верхний слой — остальной бульон держите тёплым для долива. Равномерно посыпьте сухарями; поставьте кассоле в духовку без крышки и готовьте 1 час; сухари позолотятся и образуют коричневую корочку. Через 1 час разбейте корочку, прижав её в кассуле обратной стороной деревянной ложки — не перемешивайте; при необходимости долейте половник тёплого бульона; верните в духовку ещё на 1 час, снова разбив корочку через 30 минут, пока не образуется свежая корочка, а кассуле не будет глубоко пузыриться по краям. Повторите ещё раз: разбейте корочку, долейте жидкости и запекайте финальные 30–40 минут; общее время в духовке около 2 ч 30 мин — три корочки в целом; дайте кассуле отдохнуть 10 минут вне духовки, чтобы фасоль впитала жидкость; посыпьте рубленой петрушкой и подавайте прямо из кассоле с хрустящим хлебом и зелёным салатом.","en":"The night before, place the beans in a large bowl, cover with at least 2 litres of cold water, and soak for 10–12 hours; they will roughly double in size; drain and rinse the next day. Make the bean stock; put the drained beans in a heavy 5-litre pot with the pork knuckle (if using), the studded onion, the halved garlic head, the carrot chunks, the bouquet garni, and 1.5 litres of cold stock; bring to a gentle simmer and cook uncovered for 50–60 minutes, until the beans are just tender but not falling apart; do not salt yet. Meanwhile, brown the meats; heat 2 tbsp duck fat in a wide skillet over medium-high heat; pat the pork shoulder and pork belly dry and brown in batches for 4–5 minutes per side until deep golden; lift onto a plate; in the same fat, brown the Toulouse sausages for 2–3 minutes per side just to colour the casings; add to the plate. Heat the oven to 160°C (320°F / fan 140°C); lift the cooked knuckle, onion, garlic, carrot, and bouquet garni out of the bean pot and discard the aromatics; pull any meat from the knuckle bone, shred coarsely, and reserve; stir the tomato paste and chopped tomatoes into the bean liquid, then taste and add 1.5 tsp salt and the pepper. Assemble the cassoulet in a wide 26 cm cassole (or any wide oven-safe pot); spread one-third of the beans on the bottom, then arrange the browned pork shoulder, pork belly, knuckle meat, and the cold confit duck legs on top; cover with another third of the beans, lay the browned sausages on top, then finish with the remaining beans; pour over enough bean liquid to just cover the top layer of beans — keep the rest warm for topping up. Sprinkle the breadcrumbs evenly over the top; place the cassole in the oven, uncovered, and cook for 1 hour; the breadcrumbs will gild and form a brown crust. After 1 hour, break the crust by pressing it down into the cassoulet with the back of a wooden spoon — do not stir; top up with a ladle of reserved bean liquid if it looks dry; return to the oven and cook for another hour, breaking the crust again after 30 minutes, until a fresh crust has formed and the cassoulet is bubbling deeply around the edges. Repeat once more: break the crust, top up the liquid, and bake a final 30–40 minutes; the total oven time is about 2 h 30 m — three crusts in all; rest the cassoulet for 10 minutes out of the oven so the beans drink back the liquid; scatter with chopped parsley and serve straight from the pot, with crusty bread and a green salad."},"timeMins":{"total":240,"active":45}},{"id":144,"origin":{"ru":"Хорватия","en":"Croatia","ro":"Croația"},"name":{"ru":"Пастицаде","en":"Pasticada","ro":"Pašticada"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["1,2 кг говяжьего огузка или толстого края, цельным куском","100 г свиного хребтового сала или панчетты, нарезанных полосками 5 мм × 5 см для шпигования","2 средние моркови (около 200 г): 1 нарезана соломкой для шпигования, 1 мелко нарезана для соуса","10 целых гвоздичек (5 для шпигования, 5 для маринада) + 0,5 ч. л. молотой гвоздики для соуса","6 зубчиков чеснока, очищенных — 3 раздавлены для маринада, 3 мелко нарезаны для соуса","200 мл белого винного уксуса + 200 мл холодной воды + 3 лавровых листа + 1 ч. л. чёрного перца горошком + 4 ягоды можжевельника (для маринада)","2 крупные луковицы (около 400 г), мелко нарезанные","200 г чернослива без косточек","100 мл сладкого вина прошек (или сладкого Марсала, или 1 ст. л. коричневого сахара + 80 мл портвейна)","500 мл сухого красного вина (Plavac Mali, Merlot или любой плотный сухой красный)","300 мл несолёного говяжьего бульона","2 ст. л. томатной пасты + 200 г консервированных рубленых томатов","1 ч. л. молотой корицы + 0,5 ч. л. свежемолотого мускатного ореха","50 г смальца (или 3 ст. л. оливкового масла), для обжарки","1,5 ч. л. мелкой морской соли, плюс по вкусу","0,5 ч. л. свежемолотого чёрного перца, для финиша","Свежая петрушка, мелко нарубленная, для подачи","Ньокки или свежая паста (около 500 г), для подачи"],"en":["1.2 kg beef rump or topside, in one piece","100 g pork fat back or pancetta, cut into 5 mm × 5 cm strips for larding","2 medium carrots (about 200 g): 1 cut into matchsticks for larding, 1 finely diced for the sauce","10 whole cloves (5 for larding, 5 for the marinade) + 0.5 tsp ground cloves for the sauce","6 garlic cloves, peeled — 3 crushed for the marinade, 3 finely chopped for the sauce","200 ml white wine vinegar + 200 ml cold water + 3 bay leaves + 1 tsp black peppercorns + 4 juniper berries (for the marinade)","2 large onions (about 400 g), finely diced","200 g pitted prunes (dried plums)","100 ml prošek dessert wine (or sweet Marsala or 1 tbsp brown sugar + 80 ml port)","500 ml dry red wine (Plavac Mali, Merlot, or any robust dry red)","300 ml unsalted beef stock","2 tbsp tomato paste + 200 g canned chopped tomatoes","1 tsp ground cinnamon + 0.5 tsp freshly grated nutmeg","50 g lard (or 3 tbsp olive oil), for browning","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper, for finishing","Fresh parsley, finely chopped, to garnish","Gnocchi or fresh pasta (about 500 g), to serve"],"ro":["1,2 kg vrăbioară sau pulpă de vită, într-o singură bucată","100 g slană de porc sau pancetta, tăiată fâșii de 5 mm × 5 cm pentru împănat","2 morcovi medii (aproximativ 200 g): 1 tăiat fâșii subțiri pentru împănat, 1 tăiat cuburi mici pentru sos","10 cuișoare întregi (5 pentru împănat, 5 pentru marinadă) + 0,5 linguriță cuișoare măcinate pentru sos","6 căței de usturoi decojiți — 3 zdrobiți pentru marinadă, 3 tocați fin pentru sos","200 ml oțet de vin alb + 200 ml apă rece + 3 foi de dafin + 1 linguriță boabe de piper negru + 4 boabe de ienupăr (pentru marinadă)","2 cepe mari (aproximativ 400 g), tocate fin","200 g prune uscate fără sâmburi","100 ml vin dulce prošek (sau Marsala dulce, sau 1 lingură zahăr brun + 80 ml porto)","500 ml vin roșu sec (Plavac Mali, Merlot sau orice vin sec robust)","300 ml supă de vită nesărată","2 linguri pastă de roșii + 200 g roșii sfărâmate din conservă","1 linguriță scorțișoară măcinată + 0,5 linguriță nucșoară proaspăt rasă","50 g untură (sau 3 linguri ulei de măsline), pentru rumenire","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat, pentru finisare","Pătrunjel proaspăt tocat fin, pentru garnitură","Gnocchi sau paste proaspete (aproximativ 500 g), pentru servit"]},"howIsMade":{"ru":"День 1, шпигуем мясо; острым ножом сделайте 16 глубоких надрезов по поверхности куска; в каждый вставьте полоску свиного сала, морковную соломку и (в чередующиеся надрезы) половинку целой гвоздички; жир смазывает мясо изнутри, морковь подслащает соус, гвоздика ароматизирует. Приготовьте маринад; в нереактивной миске, ровно вмещающей мясо, соедините 200 мл винного уксуса, 200 мл холодной воды, 3 раздавленных зубчика чеснока для маринада, 3 лавровых листа, перец, можжевельник и оставшиеся 5 целых гвоздичек; полностью погрузите мясо, накройте и поставьте в холодильник на 24 часа (до 48), дважды переворачивая. День 2, выньте мясо, удалите налипшие специи и тщательно обсушите — мокрое мясо не подрумянивается; маринад выбросьте; приправьте мясо 1 ч; л; соли и 0,5 ч; л; перца. Разогрейте смалец в тяжёлой посуде или казане (28 см) на среднем-сильном огне; обжаривайте мясо со всех сторон по 3–4 минуты на каждую — всего 12–15 минут, пока оно не станет равномерно тёмно-коричневым; переложите на тарелку. Убавьте огонь до среднего; добавьте нарезанный лук и щепотку соли в вытопленный жир и готовьте 10–12 минут, часто помешивая, до глубокого золотисто-коричневого цвета — эта медленная карамелизация выстраивает соус; добавьте кубики моркови и нарубленный чеснок и готовьте ещё 3–4 минуты; вмешайте томатную пасту, молотую гвоздику, корицу и мускатный орех и прогрейте 1 минуту. Влейте прошек и перемешивайте 1 минуту, отскребая дно; влейте красное вино, увеличьте огонь и уварите наполовину (около 6–8 минут); добавьте рубленые помидоры, бульон, чернослив и оставшиеся 0,5 ч; л; соли; верните мясо в кастрюлю, утопив его в жидкости — соус должен доходить примерно до трёх четвертей высоты мяса. Накройте плотной крышкой и тушите на самом малом огне (или в духовке при 150°C) 2 ч 30 мин – 3 ч, переворачивая мясо каждые 45 минут, пока нож не будет легко входить в центр; переложите мясо на доску и дайте отдохнуть под фольгой 15 минут. Завершите соус; достаньте чернослив, оставив горсть для подачи; остальное вместе с соусом измельчите погружным блендером до густого, глянцевого соуса (или протрите через сито); при необходимости уварите без крышки 5–8 минут — соус должен покрывать обратную сторону ложки и иметь глубокий кисло-сладко-пряный вкус; нарежьте отдохнувшее мясо поперёк волокон ломтями по 1 см, выложите веером на тёплые ньокки или свежую пасту, обильно полейте соусом, посыпьте сохранёнными черносливинами и рубленой петрушкой и подайте сразу.","en":"Day 1, lard the beef; using a sharp paring knife, make 16 deep slits across the surface of the beef joint; slide a strip of pork fat, a carrot matchstick, and (in alternate slits) half of a whole clove into each slit; the fat will baste the meat from the inside, the carrot will sweeten the sauce, and the cloves perfume the meat. Make the marinade; in a non-reactive bowl just large enough to hold the beef, combine 200 ml wine vinegar, 200 ml cold water, the 3 crushed marinade garlic cloves, 3 bay leaves, peppercorns, juniper berries, and the remaining 5 whole cloves; submerge the beef, cover, and refrigerate 24 hours (up to 48 hours), turning twice. Day 2, lift the beef out, scrape off any clinging spices, and pat thoroughly dry — wet meat will not brown; discard the marinade; season the meat with 1 tsp salt and 0.5 tsp pepper. Heat the lard in a heavy Dutch oven or braiser (28 cm) over medium-high heat; sear the beef on all sides for 3–4 minutes per side, about 12–15 minutes total, until evenly mahogany brown all over; lift onto a plate. Reduce the heat to medium; add the diced onion and a pinch of salt to the rendered fat and cook for 10–12 minutes, stirring often, until deeply golden brown — this slow caramelisation builds the sauce; add the diced carrot and chopped garlic and cook for another 3–4 minutes; stir in the tomato paste, ground cloves, cinnamon, and nutmeg and toast for 1 minute. Pour in the prošek and stir for 1 minute, scraping the base; add the red wine, raise the heat, and reduce by half (about 6–8 minutes); add the chopped tomatoes, beef stock, prunes, and the remaining 0.5 tsp salt; return the beef to the pot, settling it into the liquid — the sauce should come about three-quarters of the way up the meat. Cover with a tight lid and braise on the lowest hob heat (or in a 150°C oven) for 2 h 30 m – 3 h, turning the beef every 45 minutes, until a knife slides into the centre with no resistance; lift the beef onto a board and rest, tented with foil, for 15 minutes. Finish the sauce; lift out the prunes and reserve a handful for garnish; blend the rest with the sauce using a stick blender to a thick, glossy gravy (or push through a sieve for a finer finish); reduce uncovered for 5–8 minutes if it needs thickening — it should coat the back of a spoon and taste deeply sweet-sour-spiced; slice the rested beef across the grain into 1 cm slices, fan over warm gnocchi or fresh pasta, spoon the sauce generously, scatter with reserved prunes and chopped parsley, and serve immediately."}},{"id":145,"origin":{"ru":"Кипр","en":"Cyprus","ro":"Cipru"},"name":{"ru":"Шефталья","en":"Sheftalia","ro":"Sheftalia"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mediterranean","ingredients":{"ru":["400 г грубого фарша из свиной лопатки (15–20% жира)","300 г грубого фарша из бараньей лопатки (или 700 г только свинины, если нет баранины)","300 г сальника (бараньего или свиного), замоченного в холодной слегка подсолённой воде 30 минут, затем обсушенного — лист примерно 30 × 30 см","1 крупная луковица (около 200 г), натёртая и отжатая от лишней жидкости","30 г листовой петрушки, мелко нарубленной","20 г свежей мяты (кипрский диосмос), мелко нарубленной (по желанию, но традиционно)","4 зубчика чеснока, мелко нарубленных","1,5 ч. л. мелкой морской соли","1 ч. л. свежемолотого чёрного перца","1 ч. л. молотой зиры","0,5 ч. л. молотой корицы","60 мл сухого белого вина или 2 ст. л. красного винного уксуса (для связывания и смягчения)","1 ст. л. оливкового масла в фарш","1 ст. л. оливкового масла для смазывания решётки","Дольки лимона, кольца красного лука, ломтики помидора и тёплая пита или кипрский лемони-хлеб, для подачи","Цацики или хумус, для подачи"],"en":["400 g coarsely minced pork shoulder (15–20% fat)","300 g coarsely minced lamb shoulder (or 700 g all pork if lamb is unavailable)","300 g caul fat (lamb or pork), soaked in cold lightly-salted water for 30 minutes then drained — about a 30 × 30 cm sheet","1 large onion (about 200 g), grated and squeezed of excess liquid","30 g flat-leaf parsley, finely chopped","20 g fresh mint (Cypriot dyosmos), finely chopped (optional but traditional)","4 garlic cloves, finely minced","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground cinnamon","60 ml dry white wine or 2 tbsp red wine vinegar (to bind and tenderise)","1 tbsp olive oil for the meat mixture","1 tbsp olive oil for brushing the grill","Lemon wedges, sliced red onion, sliced tomato, and warm pitta or Cypriot lemoni-bread, to serve","Tzatziki or hummus, to serve"],"ro":["400 g umăr de porc tocat grosier (15–20% grăsime)","300 g umăr de miel tocat grosier (sau 700 g doar porc, dacă mielul nu este disponibil)","300 g prapure (de porc sau miel), înmuiat în apă rece ușor sărată 30 de minute, apoi scurs — o foaie de aproximativ 30 × 30 cm","1 ceapă mare (aproximativ 200 g), dată pe răzătoare și stoarsă de lichidul în exces","30 g pătrunjel cu frunze plate, tocat fin","20 g mentă proaspătă (dyosmos cipriot), tocată fin (opțional, dar tradițional)","4 căței de usturoi, tocați fin","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță scorțișoară măcinată","60 ml vin alb sec sau 2 linguri oțet de vin roșu (pentru a lega și a frăgezi)","1 lingură ulei de măsline pentru compoziție","1 lingură ulei de măsline pentru uns grătarul","Felii de lămâie, ceapă roșie feliată, roșii feliate și pita caldă sau pâine cipriotă de lămâie (lemoni), pentru servit","Tzatziki sau hummus, pentru servit"]},"howIsMade":{"ru":"Приготовьте мясную смесь; в широкой миске соедините свиной и бараний фарш, натёртый лук, петрушку, мяту (если используете), чеснок, соль, перец, зиру, корицу, вино (или уксус) и 1 ст; л; оливкового масла; вымешивайте рукой 2–3 минуты, пока масса не станет липкой и однородной; накройте и охладите в холодильнике не менее 1 часа (до 12 часов), чтобы вкусы сошлись. Подготовьте сальник; аккуратно расправьте отжатый и обсушенный сальник на чистой доске — он легко рвётся; ножницами нарежьте на 12 квадратов примерно 12 × 12 см; закройте отверстия наложением кусочков. Сформуйте шефталию; возьмите порцию мяса размером со столовую ложку (около 50–60 г) и сформуйте слегка сужающийся цилиндр длиной 7–8 см; положите его на край квадрата сальника; заверните бока поверх мяса и плотно скатайте в форму колбаски швом вниз; если есть, нанижите на металлический шампур — иначе шов и так удержит; повторите с остальным мясом и сальником: получится 12 шефталий, по 3 на персону. Разложите завёрнутые колбаски на противне и охлаждайте не менее 15 минут (до 4 часов), чтобы сальник стал плотнее — они лучше держатся на гриле. Разогрейте угольный гриль или тяжёлую рифлёную сковороду до среднего-сильного огня (поверхность около 200°C); слегка смажьте 1 ст; л; оливкового масла; шефталия должны шипеть при касании, но не вспыхивать резко — на слишком сильном огне сальник сгорит раньше, чем мясо доготовится. Жарьте шефталии в общей сложности 12–15 минут, переворачивая каждые 3–4 минуты на каждую из четырёх сторон, пока сальник не вытопится в тонкую кружевную корочку, а температура в центре не достигнет 70°C; они должны быть глубоко золотистыми и упругими, но не жёсткими. Переложите шефталии на доску и накройте фольгой неплотно, оставьте на 5 минут; соки распределятся, а мясо дойдёт за счёт остаточного тепла. Подогрейте пита или лимони-хлеб на гриле по 30 секунд с каждой стороны; на тарелку положите по 3 шефталии на человека вместе с тёплым хлебом, дольками лимона, красным луком и помидорами; к боку положите цацики или хумус; едят, разрывая кусочки шефталии и заворачивая их в пита с салатом и соусом.","en":"Make the meat mixture; in a wide bowl combine the minced pork, minced lamb, grated onion, parsley, mint (if using), garlic, salt, pepper, cumin, cinnamon, wine (or vinegar), and 1 tbsp olive oil; knead with your hand for 2–3 minutes until sticky and homogeneous; cover and chill in the fridge for at least 1 hour (up to 12 hours) so the seasoning matures. Prepare the caul fat; spread the soaked and drained caul fat carefully on a clean board — it tears very easily; use scissors to cut it into 12 squares of about 12 × 12 cm; patch holes by overlapping pieces. Shape the sheftalia; take a tablespoon-sized portion of meat (about 50–60 g) and shape into a slightly tapered cylinder 7–8 cm long; place at the edge of one caul-fat square; fold the sides over the meat, then roll up tightly into a sausage shape, finishing with the seam underneath; pierce onto a metal skewer if you have one — otherwise the wrapped seam will hold; repeat with the remaining meat and caul fat: you should get 12 sheftalia, 3 per person. Rest the wrapped sausages on a tray and chill for at least 15 minutes (up to 4 hours) so the caul fat firms — they hold together better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 200°C / 390°F surface); brush lightly with 1 tbsp olive oil; the sheftalia should hiss when they touch the grill but not flare aggressively — too high and the caul fat will burn before the meat cooks through. Grill the sheftalia for 12–15 minutes total, turning every 3–4 minutes onto each of their four sides, until the caul fat has rendered down into a thin lacy crust and the meat reaches 70°C in the centre; they should be deep golden brown and feel firm but not hard. Lift the sheftalia onto a board and rest, loosely tented with foil, for 5 minutes; the juices settle and the meat finishes cooking from residual heat. Warm the pitta or Cypriot lemoni-bread on the grill for 30 seconds per side; pile 3 sheftalia per person on each plate with the warm bread, lemon wedges, sliced red onion, and tomato; spoon tzatziki or hummus to the side; eat by tearing pieces of sheftalia into the pitta with the salad and dip."}},{"id":146,"origin":{"ru":"Босния и Герцеговина","en":"Bosnia and Herzegovina","ro":"Bosnia și Herțegovina"},"name":{"ru":"Чевапи","en":"Cevapi","ro":"Cevapi"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["500 г грубо нарубленной говяжьей лопатки (около 15% жира)","300 г грубо нарубленной бараньей лопатки (или 800 г только говядины, если нет баранины)","4 зубчика чеснока, растёртых с 0,5 ч. л. соли в гладкую пасту","60 мл холодной газированной воды","1 ч. л. пищевой соды — ключ к пружинистой текстуре","1,5 ч. л. мелкой морской соли","1 ч. л. свежемолотого чёрного перца","1 ч. л. сладкой венгерской паприки","0,5 ч. л. сушёного майорана или орегано (по желанию, но традиционно)","1 ст. л. нейтрального масла для смазывания","4 лепёшки сомун (или 4 пита), примерно 18 см в диаметре каждая, для подачи","1 крупная красная луковица (около 200 г), очень мелко нарезанная","200 г айвара (паста из печёных красных перцев)","100 г каймака (балканский густой кисломолочный сыр) или густой крем-фреш как замена","1 небольшой пучок листовой петрушки, листья оборваны, для подачи"],"en":["500 g coarsely minced beef chuck (about 15% fat)","300 g coarsely minced lamb shoulder (or 800 g all beef if lamb is unavailable)","4 garlic cloves, crushed with 0.5 tsp salt to a fine paste","60 ml chilled sparkling water","1 tsp baking soda (sodium bicarbonate) — the key to the springy texture","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp sweet Hungarian paprika","0.5 tsp dried marjoram or oregano (optional but traditional)","1 tbsp neutral oil for brushing","4 somun flatbreads (or 4 pittas), about 18 cm across each, to serve","1 large red onion (about 200 g), very finely diced","200 g ajvar (roasted red-pepper relish)","100 g kajmak (Balkan clotted cream) or thick crème fraîche, as a substitute","1 small bunch flat-leaf parsley, leaves picked, to scatter"],"ro":["500 g pulpă de vită tocată grosier (15% grăsime)","300 g umăr de miel tocat grosier (sau 800 g doar vită, dacă nu există miel)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă fină","60 ml apă minerală rece (carbogazoasă)","1 linguriță bicarbonat de sodiu — cheia texturii elastice","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță boia dulce maghiară","0,5 linguriță maghiran sau oregano uscat (opțional, dar tradițional)","1 lingură ulei neutru pentru uns","4 lipii somun (sau 4 pita) de aproximativ 18 cm fiecare, pentru servit","1 ceapă roșie mare (aproximativ 200 g), tocată foarte fin","200 g ajvar (pastă de ardei copți)","100 g kajmak (smântână groasă balcanică) sau crème fraîche groasă ca substitut","1 legătură mică de pătrunjel cu frunze plate, frunzele păstrate, pentru servit"]},"howIsMade":{"ru":"Сделайте мясную смесь; в широкой миске соедините говяжий и бараний фарш, чесночно-солевую пасту, холодную газированную воду, соду, соль, перец, паприку и майоран; энергично вымешивайте рукой 4–5 минут — смесь должна стать заметно липкой и хорошо собраться; длительный замес и сода дают чевапи их фирменную пружинистую упругость. Накройте миску плёнкой и поставьте в холодильник минимум на 4 часа, идеально 12–24; вкусы созревают, а белки расслабляются. Смочите руки холодной водой; возьмите порцию мяса размером со столовую ложку (около 35–40 г) и скатайте между ладонями в цилиндр в форме пальца длиной 7–8 см и толщиной 2 см; повторите с оставшимся фаршем, чтобы получить около 24 чевапи (по 6 на человека); раскладывайте на противне по мере формовки. Охладите сформованные чевапи минимум 20 минут (до 4 часов), чтобы они уплотнились — будут лучше держать форму на гриле. Разогрейте угольный гриль или тяжёлую рифлёную сковороду до среднего-сильного огня (поверхность около 220°C); смажьте чевапи маслом очень тонким слоем — чуть-чуть; гриль должен шипеть, но не дымить агрессивно. Жарьте чевапи в общей сложности 8–10 минут, переворачивая каждые 2 минуты на все четыре стороны, пока поверхность не станет тёмно-коричневой с хрустящими краями, а центр не достигнет 65°C (на тарелке они дойдут); не прижимайте — цель: сочное упругое внутри. Пока чевапи отдыхают 2 минуты, подогрейте сомун (или пита) на гриле по 30 секунд с каждой стороны, чтобы они слегка вздулись и подпеклись; разрежьте каждый по шву, чтобы получился кармашек. Положите по 6 чевапи в каждый тёплый лаваш (или 6 рядом с хлебом на тарелке); положите 1–2 столовые ложки айвара на один край, добавьте щедрую ложку каймака (или крем-фреш) и горку мелко нарезанного сырого красного лука; посыпьте листьями петрушки и подавайте сразу — соки чевапи должны пропитать сомун.","en":"Make the meat mixture; in a wide bowl combine the minced beef, minced lamb, garlic-salt paste, chilled sparkling water, baking soda, salt, pepper, paprika, and marjoram; knead vigorously with your hand for 4–5 minutes — the mixture should become noticeably sticky and start to pull together; this long knead and the bicarbonate are what give cevapi their characteristic springy bounce. Cover the bowl with cling film and rest the mixture in the fridge for at least 4 hours, ideally 12–24 hours; the flavour matures and the proteins relax. Wet your hands with cold water; take a tablespoon-sized portion of meat (about 35–40 g) and roll it between your palms into a finger-shaped cylinder about 7–8 cm long and 2 cm thick; repeat with the remaining meat to make about 24 cevapi (6 per person); arrange on a tray as you go. Chill the shaped cevapi for at least 20 minutes (up to 4 hours) to firm — they hold their shape better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 220°C surface); brush the cevapi very lightly with oil — barely a glaze; the grill should hiss but not smoke aggressively. Grill the cevapi for 8–10 minutes total, turning every 2 minutes onto all four sides, until the surface is mahogany brown with crisp edges and the centre reaches 65°C (they continue cooking on the plate); do not press them down; the goal is juicy, springy interiors. While the cevapi rest for 2 minutes, warm the somun (or pittas) on the grill 30 seconds per side until just puffed and lightly charred; split each one open along the seam to make a pocket. Pile 6 cevapi inside each warm flatbread (or arrange 6 on each plate beside the bread); spoon 1–2 tablespoons of ajvar to one side, add a generous knob of kajmak (or crème fraîche), and a small mound of diced raw red onion; scatter parsley leaves and serve immediately — the cevapi juices should soak into the somun."}},{"id":147,"origin":{"ru":"Гана","en":"Ghana","ro":"Ghana"},"name":{"ru":"Фуфу","en":"Fufu","ro":"Fufu"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ru":["700 г свежего корня маниоки, очищенного и нарезанного кусками по 5 см (или 500 г замороженной уже очищенной маниоки, размороженной)","500 г полуспелого плантана, примерно 3 крупных, очищенных и нарезанных кусками по 5 см (жёлтая кожура с чёрными пятнами даёт правильный баланс сладости и крахмала)","1 ст. л. мелкой морской соли для воды варки","2 литра холодной воды для варки","Около 150 мл горячего отвара, оставленного в кувшине и сохранённого тёплым","1 ст. л. нейтрального масла (пальмового или подсолнечного), для смазывания рук и сервировочной миски","Большая кастрюля с горячим западноафриканским супом (600 мл–1 л light soup, пальмового, арахисового или эгуси), для подачи","Тонко нарезанный свежий перец скотч-боннет, для любителей острого","Жареный арахис или дроблёные орехи, для посыпки супа (по желанию)"],"en":["700 g fresh cassava root, peeled and cut into 5 cm chunks (or 500 g pre-peeled frozen cassava chunks, thawed)","500 g semi-ripe plantains, about 3 large, peeled and cut into 5 cm chunks (yellow skin streaked with black gives the right balance of sweet and starchy)","1 tbsp fine sea salt for the cooking water","2 litres cold water for boiling","About 150 ml hot cooking water reserved from the pot, kept warm in a jug","1 tbsp neutral oil (palm or sunflower), for oiling hands and the serving bowl","1 large pot of hot West African soup (600 ml–1 L of light soup, palmnut, groundnut, or egusi), for serving","Sliced fresh scotch bonnet chilli, for those who want extra heat","Roasted peanuts or crushed groundnuts, to scatter over the soup (optional)"],"ro":["700 g manioc proaspăt, curățat și tăiat bucăți de 5 cm (sau 500 g cassava decongelată, deja curățată)","500 g banane plantain semi-coapte, aproximativ 3 mari, decojite și tăiate bucăți de 5 cm (coaja galbenă cu pete negre dă echilibrul potrivit între dulce și amidonos)","1 lingură sare fină de mare pentru apa de fierbere","2 litri apă rece pentru fierbere","Aproximativ 150 ml apă fierbinte de fierbere păstrată separat, ținută caldă într-un vas","1 lingură ulei neutru (palmier sau floarea-soarelui), pentru a unge mâinile și bolul de servit","O cratiță mare cu supă vest-africană caldă (600 ml–1 L de light soup, palmnut, groundnut sau egusi), pentru servit","Ardei iute scotch bonnet feliat, pentru cei care vor mai mult picant","Arahide prăjite sau pisate, pentru presărat peste supă (opțional)"]},"howIsMade":{"ru":"Подготовьте маниоку; промойте куски под холодной водой от пыли; острым ножом надрежьте толстую коричневую кожуру вдоль и снимите её вместе с розовым подслоем, обнажая белую сердцевину; удалите центральное волокно из каждого куска. В тяжёлой 5-литровой кастрюле соедините очищенные куски маниоки, куски плантана, 1 ст; л; соли и 2 литра холодной воды; доведите до лёгкого кипения на среднем-сильном огне, убавьте до средне-слабого и варите 30–40 минут, пока и маниока, и плантан не станут мягкими при проколе вилкой — маниока должна ощущаться как варёный картофель. Слейте через дуршлаг, но сохраните не менее 250 мл горячего отвара в кувшине на потом; удалите видимые волокна. Истолките фуфу; традиционный метод: переложите горячую смесь в тяжёлую деревянную ступу, смазанную несколькими каплями масла, партиями; длинным деревянным пестиком ритмично толчите, второй человек (со слегка смазанными руками) переворачивает массу между ударами; работайте 8–10 минут на партию, пока паста не станет плотной, идеально гладкой и заметно эластичной — без комков. Без ступки: положите горячие маниоку и плантан в крепкий стационарный миксер с крюком для теста; минуту на низкой скорости — раздробить куски, затем средняя на 6–8 минут, очищая чашу каждые 2 минуты, пока масса не сформируется в единый эластичный шар вокруг крюка; если слишком сухо — по столовой ложке горячего отвара; цель: блестящий и эластичный, без сырости. Проверьте текстуру; отщипните маленький кусочек (около 50 г) и скатайте его в гладкий шарик слегка смазанными ладонями; поверхность должна быть глянцевой и без швов, шарик должен держать форму на тарелке, не оседая и не растрескиваясь; если треснет — добавьте ложку горячей воды; если осядет — вымешивайте ещё 2 минуты. Сформуйте порции слегка смазанными руками: 4 крупных шара примерно по 250 г (или 8 поменьше для традиционных индивидуальных порций); положите каждый шар в слегка смазанную широкую миску, чтобы не прилипал; накройте влажной тканью до подачи — на воздухе фуфу быстро твердеет. Подавайте сразу; налейте горячий западноафриканский суп (light soup, пальмовый, арахисовый или эгуси) в широкую тарелку вокруг каждого шара фуфу; едят, отщипывая правой рукой маленький кусочек, продавливая большим пальцем углубление-чашечку и зачерпывая суп — фуфу не жуют, его глотают целиком, чтобы аромат супа его пронёс; посыпьте нарезанным скотч-боннетом и арахисом по вкусу.","en":"Prepare the cassava; wash the cassava chunks under cold water to remove any clinging grit; with a paring knife slit the thick brown skin lengthwise, then peel it away (along with the pink underlayer) to expose the white core; cut out the fibrous central string from each piece and discard. In a heavy 5-litre pot, combine the peeled cassava chunks, the plantain chunks, the 1 tbsp salt, and the 2 litres cold water; bring to a gentle boil over medium-high heat, then reduce to medium-low and cook for 30–40 minutes, until both cassava and plantain are fork-tender — the cassava should feel like a cooked potato when pierced. Drain into a colander but reserve at least 250 ml of the hot cooking liquid in a jug for later; pick out and discard any visible fibres or strings. Pound the fufu; traditional method: transfer the hot cassava-plantain mixture in batches to a heavy wooden mortar lubricated with a few drops of oil; with a long wooden pestle, pound rhythmically while a second person (lightly oiled hands) turns and gathers the mass between strokes; work for 8–10 minutes per batch until the paste is dense, perfectly smooth, and noticeably elastic — no lumps remain. Mortar-free method: place the hot cassava and plantain together in a sturdy stand mixer with the dough-hook attachment; run at low speed for 1 minute to break down the chunks, then increase to medium and beat for 6–8 minutes, scraping the bowl every 2 minutes, until the mass forms a single elastic dough around the hook; add a tablespoon of reserved hot cooking water at a time if it is too dry — the goal is glossy and elastic without being wet. Test the texture; pinch off a small piece (about 50 g) and roll it in lightly oiled palms into a smooth ball; the surface should be glossy and seamless, and the ball should hold its shape on a plate without sagging or cracking; if it cracks, work in another spoonful of hot water; if it slumps, knead for another 2 minutes. Shape the serving portions with lightly oiled hands: form 4 large balls of about 250 g each (or 8 smaller balls for traditional individual servings); place each ball in a slightly oiled wide bowl so it does not stick; cover with a damp cloth until ready to serve — fufu hardens quickly when exposed to air. Serve immediately; ladle hot West African soup (light soup, palmnut, groundnut, or egusi) into a wide soup bowl around each fufu ball; eat by pinching off a small piece of fufu with the right hand, pressing a depression into it with the thumb to form a cup, and using it to scoop up the soup — do not chew the fufu, swallow it whole so the flavour of the soup carries it down; scatter chopped scotch bonnet and roasted peanuts to taste."}},{"id":148,"origin":{"ru":"Грузия","en":"Georgia","ro":"Georgia"},"name":{"ru":"Хинкали","en":"Khinkali","ro":"Khinkali"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["500 г пшеничной муки, плюс для раскатки","250 мл холодной воды","1 крупное яйцо, слегка взбитое (по желанию — некоторые грузинские семьи используют яйцо для более мягкого теста)","1 ч. л. мелкой морской соли для теста","1 ст. л. нейтрального масла для теста","500 г грубо нарубленной говядины (около 15% жира)","200 г грубо нарубленной свиной лопатки (или 700 г только говядины для более постного результата)","1 крупная луковица (около 200 г), очень мелко нарезанная — НЕ натирать, важна текстура","3 зубчика чеснока, мелко нарубленных","20 г свежей кинзы, мелко нарубленной — стебли и листья","1 ч. л. молотой зиры + 1 ч. л. свежемолотого чёрного перца + 0,5 ч. л. хмели-сунели (или 0,25 ч. л. молотого тмина + 0,25 ч. л. молотого пажитника как замена)","1,5 ч. л. мелкой морской соли для начинки","200 мл ледяного говяжьего бульона или холодной воды (медленно выделяет пар при варке — секрет знаменитого мешочка с бульоном)","1 ст. л. крупной морской соли для воды варки","Щедро свежемолотого чёрного перца, для подачи на стол"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","250 ml cold water","1 large egg, lightly beaten (optional — some Georgian families use an egg for a softer dough)","1 tsp fine sea salt for the dough","1 tbsp neutral oil for the dough","500 g coarsely minced beef (around 15% fat)","200 g coarsely minced pork shoulder (or 700 g all beef for a leaner result)","1 large onion (about 200 g), very finely diced — do NOT grate, the texture matters","3 garlic cloves, finely minced","20 g fresh coriander, finely chopped — stems and leaves","1 tsp ground cumin + 1 tsp freshly ground black pepper + 0.5 tsp khmeli suneli (or 0.25 tsp caraway + 0.25 tsp ground fenugreek as substitute)","1.5 tsp fine sea salt for the filling","200 ml ice-cold beef stock or cold water (releases steam slowly during boiling — this is what creates the famous broth pocket)","1 tbsp coarse sea salt for the cooking water","Plenty of freshly cracked black pepper, to scatter at the table"],"ro":["500 g făină albă obișnuită, plus pentru întins","250 ml apă rece","1 ou mare, bătut ușor (opțional — unele familii georgiene folosesc un ou pentru un aluat mai moale)","1 linguriță sare fină de mare pentru aluat","1 lingură ulei neutru pentru aluat","500 g vită tocată grosier (în jur de 15% grăsime)","200 g umăr de porc tocat grosier (sau 700 g doar vită pentru un rezultat mai slab)","1 ceapă mare (aproximativ 200 g), tocată foarte fin — NU rasă, textura contează","3 căței de usturoi, tocați fin","20 g coriandru proaspăt, tocat fin — tulpini și frunze","1 linguriță chimion măcinat + 1 linguriță piper negru proaspăt măcinat + 0,5 linguriță khmeli suneli (sau 0,25 linguriță chimion negru + 0,25 linguriță schinduf măcinat ca substitut)","1,5 lingurițe sare fină de mare pentru umplutură","200 ml supă de vită rece ca gheața sau apă rece (eliberează aburi încet în timpul fierberii — acesta este secretul pungii de bulion)","1 lingură sare grunjoasă de mare pentru apa de fierbere","Mult piper negru proaspăt măcinat, pentru presărat la masă"]},"howIsMade":{"ru":"ТЕСТО: смешайте 500 г муки с 1 ч; л; соли в большой миске; постепенно влейте 250 мл холодной воды (и при желании 1 взбитое яйцо + 1 ст; л; масла), перемешивая вилкой, затем месите на столе 8–10 минут, пока тесто не станет гладким, плотным и эластичным — оно должно быть достаточно крепким, чтобы раскатываться тонко без разрывов; накройте плёнкой и оставьте на 30 минут при комнатной температуре. НАЧИНКА: в миске вручную смешайте 500 г говядины + 200 г свинины крупного помола с 200 г очень мелко нарезанного лука, 3 зубчиками чеснока, 20 г рубленой кинзы, 1 ч; л; зиры, 1 ч; л; перца, 0,5 ч; л; хмели-сунели и 1,5 ч; л; соли; медленно влейте 200 мл ледяного бульона, по 50 мл за раз, перемешивая после каждой порции — начинка должна быть рыхлой и влажной, но не жидкой; накройте и охладите 30 минут. РАСКАТКА: разделите тесто на 4 части; работайте по одной части (остальные накройте); раскатайте до толщины 2 мм на слегка присыпанной мукой поверхности; вырежьте круги диаметром 12–14 см блюдцем или большим стаканом; соберите обрезки, кратко вымесите и раскатайте снова. ФОРМОВКА: положите круг на ладонь, поместите около 30 мл (2 ст; л.) начинки в центр; другой рукой сформируйте 18–20 складок вокруг начинки, защипывая каждую складку между большим и указательным пальцами и слегка закручивая её к центру; в конце соберите все складки наверху и закрутите хвостик, чтобы запечатать; положите хинкали на присыпанную мукой поверхность. ВОДА ДЛЯ ВАРКИ: доведите 4 литра воды до сильного кипения в большой кастрюле и добавьте 1 ст; л; крупной соли. ВАРКА: опускайте по 5–6 хинкали в кипящую воду (не загружайте плотно); как только они всплывут (через 2–3 минуты), запустите таймер: варите ещё 8–10 минут; всего 12–14 минут; готовы, когда складки становятся полупрозрачными и видно, как внутри движется бульон. ВЫНИМАНИЕ: достаньте шумовкой, дайте кратко стечь и выложите на тёплую тарелку; сразу обильно посыпьте свежемолотым чёрным перцем; без соусов — хинкали едят как есть. КАК ЕСТЬ: держите хинкали за хвостик пальцами, слегка наклоните и откусите небольшое отверстие у шва, затем сначала отпейте горячий бульон изнутри, пока он не пролился; съешьте остальное, оставив закрученный хвостик на тарелке; количество хвостиков = сколько вы съели.","en":"DOUGH: mix 500 g flour with 1 tsp salt in a large bowl; gradually pour in 250 ml cold water (and optionally 1 beaten egg + 1 tbsp oil), stirring with a fork, then knead on the bench 8–10 minutes until the dough is smooth, firm and elastic — it needs to be tough enough to roll thin without tearing; cover with film and rest 30 minutes at room temperature. FILLING: in a bowl, mix by hand 500 g beef + 200 g pork coarse-mince with 200 g very finely diced onion, 3 garlic cloves, 20 g chopped coriander, 1 tsp cumin, 1 tsp black pepper, 0.5 tsp khmeli suneli and 1.5 tsp salt; slowly pour in 200 ml ice-cold stock, 50 ml at a time, mixing after each addition — the filling should be loose and wet but not soupy; cover and chill 30 minutes. ROLLING: divide the dough into 4 pieces; work one piece at a time (keep the rest covered); roll out to a 2 mm thin sheet on a lightly floured surface; cut 12–14 cm diameter circles with a saucer or large glass; gather scraps, knead briefly and roll again. SHAPING: place a circle in your palm, put about 30 ml (2 tbsp) of filling in the centre; with the other hand, form 18–20 pleats around the filling, pinching each pleat between thumb and forefinger and twisting it gently toward the centre; at the end, gather all pleats at the top and twist the tip — the tail — to seal; set the khinkali on a floured surface. COOKING WATER: bring 4 litres of water to a vigorous rolling boil in a large pot and add 1 tbsp coarse salt. BOILING: drop 5–6 khinkali at a time into the boiling water (do not crowd); the moment they float to the surface (after 2–3 minutes), start your timer: boil another 8–10 minutes; total 12–14 minutes; they are done when the pleats turn translucent and you can see the broth moving inside. REMOVING: lift them out with a slotted spoon, let drain briefly and arrange on a warm plate; immediately scatter plenty of freshly cracked black pepper over the top; no sauce — khinkali are eaten plain. HOW TO EAT: hold the khinkali by the tail with your fingers, tilt slightly and bite a small hole near the seam, then sip the hot broth from inside first before it spills; then eat the rest of the dumpling, leaving the twisted tail on the plate; the number of tails left = how many you ate."}},{"id":149,"origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Посоле","en":"Pozole","ro":"Pozole"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":6,"tipType":"meat","pairingsType":"mexican","ingredients":{"ru":["1,2 кг свиной лопатки без кости, нарезанной кубиками 4 см","500 г свиных шейных или хвостовых костей (для более насыщенного бульона)","1 крупная белая луковица, разрезанная пополам, с шелухой (для цвета) + 1 мелкая луковица, мелко нарезанная, для подачи","8 зубчиков чеснока (6 для бульона, 2 для соуса из чили)","3 лавровых листа","1 ст. л. крупной соли для бульона + соль по вкусу","4 литра холодной воды для бульона","800 г кукурузы хомини в банке, слитой и промытой (или 250 г сухой, замоченной на ночь и сваренной отдельно)","6 сушёных перцев гуахильо, без плодоножек и семян","4 сушёных перца анчо, без плодоножек и семян","2 сушёных перца де арболь (по желанию, для остроты)","1 ч. л. молотой зиры","1 ч. л. сушёного мексиканского орегано","200 г зелёной капусты, мелко нашинкованной, для подачи","150 г красной редиски, тонко нарезанной","4–6 лаймов, нарезанных дольками","12 тостадас (хрустящих кукурузных лепёшек)","Свежий или сушёный орегано для посыпки на стол"],"en":["1.2 kg boneless pork shoulder, cut into 4 cm cubes","500 g pork neck bones or pork tail (for a richer broth)","1 large white onion halved, skin on (for color) + 1 small onion finely diced for serving","8 garlic cloves (6 for the broth, 2 for the chili sauce)","3 bay leaves","1 tbsp coarse salt for the broth + salt to taste","4 litres cold water for the broth","800 g canned hominy, drained and rinsed (or 250 g dried hominy soaked overnight and boiled separately)","6 dried guajillo chilies, stemmed and deseeded","4 dried ancho chilies, stemmed and deseeded","2 dried árbol chilies (optional, for heat)","1 tsp ground cumin","1 tsp dried Mexican oregano","200 g green cabbage, finely shredded for serving","150 g red radishes, thinly sliced","4–6 limes cut into wedges","12 tostadas (crisp corn tortillas)","Fresh or dried oregano to scatter at the table"],"ro":["1,2 kg umăr de porc dezosat, tăiat în cuburi de 4 cm","500 g oase de porc cu carne (gât sau coadă) pentru un bulion mai bogat","1 ceapă albă mare tăiată în jumătăți (cu coajă, pentru culoare) + 1 ceapă mică tocată fin pentru servire","8 căței de usturoi (6 pentru bulion, 2 pentru sosul de ardei)","3 frunze de dafin","1 lingură sare grunjoasă pentru bulion + sare după gust","4 litri apă rece pentru bulion","800 g hominy din conservă, scurs și clătit (sau 250 g hominy uscat înmuiat peste noapte și fiert separat)","6 ardei guajillo uscați, decotorați și fără semințe","4 ardei ancho uscați, decotorați și fără semințe","2 ardei de árbol uscați (opțional, pentru iuțeală)","1 linguriță chimion măcinat","1 linguriță oregano mexican uscat","200 g varză verde tocată mărunt, pentru servire","150 g ridichi roșii feliate subțire","4–6 lime tăiate în sferturi","12 tostadas (lipii de porumb crocante)","Oregano proaspăt sau uscat de presărat la masă"]},"howIsMade":{"ru":"ОСНОВА БУЛЬОНА: в большую кастрюлю положите 1,2 кг свиной лопатки кубиками + 500 г свиных костей, 1 разрезанную пополам луковицу (с шелухой), 6 зубчиков чеснока, 3 лавровых листа и 1 ст; л; соли; залейте 4 литрами холодной воды; доведите до кипения, снимайте пену первые 5 минут, затем убавьте до слабого кипения. ВАРКА СВИНИНЫ: варите без крышки 1,5–2 часа, пока мясо не станет распадаться вилкой; достаньте мясо и кости, разделите мясо на крупные волокна двумя вилками, отложите; процедите бульон (~3,5 л), твёрдое — выбросьте. ОБЖАРКА ПЕРЦЕВ: разогрейте сухую сковороду на среднем огне; обжаривайте 6 перцев гуахильо + 4 анчо + 2 де арболь (по желанию), прижимая лопаткой, по 30 секунд с каждой стороны до аромата и лёгких пузырьков — не сожгите, иначе бульон станет горьким; переложите в миску, залейте кипятком и замочите 15 минут до мягкости. СОУС ИЗ ПЕРЦА: переложите вымоченные перцы в блендер с 2 зубчиками чеснока, 1 ч; л; зиры, 1 ч; л; орегано и 500 мл тёплого бульона; взбивайте на максимальной скорости 2–3 минуты до полной однородности; протрите пюре через мелкое сито в миску, продавливая мякоть — кусочки кожицы выбросьте. СБОРКА: верните процеженный соус обратно в кастрюлю с бульоном; добавьте разобранное мясо и 800 г слитого хомини; доведите до кипения и варите без крышки 30–40 минут, периодически помешивая, пока бульон слегка не загустеет и вкусы не объединятся; попробуйте и отрегулируйте соль — должно быть глубоко насыщенно. ГАРНИРЫ: пока посоле варится, мелко нашинкуйте 200 г капусты, тонко нарежьте 150 г редиса, мелко порежьте 1 луковицу, нарежьте 4–6 лаймов дольками, подготовьте орегано; разложите всё в маленькие пиалы на столе. ТОСТАДАС: прогрейте 12 тостадас на сухой сковороде по 30 секунд с каждой стороны до хрусткости и лёгкой румяности; уложите в корзинку на стол. ПОДАЧА: разлейте посоле по глубоким тарелкам; каждый гость собирает свою тарелку: горсть капусты, россыпь редиса, щепоть лука и орегано, выжимка лайма; тостадас едят рядом — ломают в бульон или используют как ложку; подают сразу, очень горячим.","en":"BROTH BASE: place 1.2 kg cubed pork shoulder + 500 g pork bones, 1 halved onion (skin on), 6 garlic cloves, 3 bay leaves and 1 tbsp salt in a large stockpot; cover with 4 litres of cold water; bring to a boil, skim the foam for the first 5 minutes, then reduce to a gentle simmer. SIMMER THE PORK: simmer uncovered 1.5–2 hours until the pork is fork-tender; lift out meat and bones, shred the meat coarsely with two forks, set aside; strain the broth (~3.5 L) and discard the solids. TOAST THE CHILIES: heat a dry skillet over medium heat; toast 6 guajillo + 4 ancho + 2 árbol chilies (optional), pressing them down with a spatula, 30 seconds per side until fragrant and lightly blistered — do not burn or the broth will turn bitter; transfer to a bowl, cover with boiling water, and soak 15 minutes until softened. CHILI SAUCE: transfer the soaked chilies to a blender with 2 garlic cloves, 1 tsp cumin, 1 tsp oregano and 500 ml of the warm broth; blend on high 2–3 minutes until completely smooth; strain the puree through a fine sieve into a bowl, pressing the pulp through — discard the skin bits left behind. COMBINE: pour the strained chili sauce back into the broth pot; add the shredded pork and 800 g drained hominy; bring to a simmer and cook uncovered 30–40 minutes, stirring occasionally, until the broth thickens slightly and the flavours meld; taste and adjust salt — it should be deeply savoury. PREP THE GARNISHES: while the pozole simmers, finely shred 200 g cabbage, thinly slice 150 g radishes, finely dice 1 onion, cut 4–6 limes into wedges, prepare oregano; arrange each in small bowls on the table. TOSTADAS: warm 12 tostadas in a dry skillet 30 seconds per side until crisp and lightly toasted; place in a basket for the table. SERVE: ladle the pozole into deep bowls; each guest customises their bowl: a handful of cabbage, scattering of radish, pinch of onion and oregano, squeeze of lime; tostadas eaten alongside — broken into the broth or used to scoop; eaten immediately while piping hot."}},{"id":150,"origin":{"ru":"Гватемала","en":"Guatemala","ro":"Guatemala"},"name":{"ru":"Пепиан","en":"Pepian","ro":"Pepian"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"ru":["1,2 кг куриных бёдер и голеней на кости (около 8 кусков)","1,5 л холодной воды + 1 ч. л. соли для пашот курицы","100 г сырых очищенных тыквенных семечек (пепитас)","50 г кунжутных семян","4 сушёных перца гуахильо, без плодоножек и семян","2 сушёных перца анчо или пасилла, без плодоножек и семян","1 сушёный чипотле (по желанию, для копчёного оттенка)","4 средних помидора (~500 г), разрезанных пополам","4 томатильо (~200 г), очищенных от шелухи и разрезанных пополам","1 средняя луковица (~150 г), нарезанная на четвертинки","5 неочищенных зубчиков чеснока","1 палочка цейлонской корицы (~5 см)","2 целые гвоздички","1 ч. л. молотого чёрного перца + 0,5 ч. л. молотого ямайского перца","1 кукурузная тортилья, разорванная на куски (для загущения)","200 г чайоте (или цуккини как замена), очищенного и нарезанного кубиками 2 см","300 г картофеля, очищенного и нарезанного кубиками 2 см","2 ст. л. растительного масла для обжарки пасты","2 ст. л. свежей кинзы, мелко нарубленной, для подачи","Соль по вкусу","500 г готового белого риса + тёплые тортильи для подачи"],"en":["1.2 kg bone-in chicken thighs and drumsticks (about 8 pieces)","1.5 L cold water + 1 tsp salt for poaching","100 g raw hulled pumpkin seeds (pepitas)","50 g sesame seeds","4 dried guajillo chilies, stemmed and deseeded","2 dried ancho or pasilla chilies, stemmed and deseeded","1 dried chipotle chili (optional, for smokiness)","4 medium tomatoes (~500 g), halved","4 tomatillos (~200 g), husked and halved","1 medium onion (~150 g), quartered","5 unpeeled garlic cloves","1 Ceylon cinnamon stick (~5 cm)","2 whole cloves","1 tsp ground black pepper + 0.5 tsp ground allspice","1 corn tortilla, torn into pieces (for thickening)","200 g güisquil (chayote squash) or zucchini, peeled and cubed 2 cm","300 g potatoes, peeled and cubed 2 cm","2 tbsp vegetable oil for cooking the paste","2 tbsp fresh cilantro, finely chopped, to garnish","Salt to taste","500 g cooked white rice + warm tortillas to serve"],"ro":["1,2 kg pulpe și pulpe inferioare de pui cu os (aproximativ 8 bucăți)","1,5 L apă rece + 1 linguriță sare pentru fierberea puiului","100 g semințe crude de dovleac decojite (pepitas)","50 g semințe de susan","4 ardei guajillo uscați, decotorați și fără semințe","2 ardei ancho sau pasilla uscați, decotorați și fără semințe","1 ardei chipotle (opțional, pentru afumare)","4 roșii medii (~500 g), tăiate în jumătăți","4 tomatillos (~200 g), curățați de coajă și tăiați în jumătăți","1 ceapă medie (~150 g), tăiată în sferturi","5 căței de usturoi, necurățați","1 batjoc de scorțișoară Ceylon (~5 cm)","2 cuișoare întregi","1 linguriță piper negru măcinat + 0,5 linguriță ienibahar măcinat","1 tortilla de porumb, ruptă în bucăți (pentru îngroșare)","200 g chayote (sau dovlecel ca substitut), curățat și tăiat cuburi de 2 cm","300 g cartofi, curățați și tăiați cuburi de 2 cm","2 linguri ulei vegetal pentru sotare","2 linguri coriandru proaspăt, tocat fin, pentru ornare","Sare după gust","500 g orez alb gătit + tortillas calde pentru servire"]},"howIsMade":{"ru":"ВАРКА КУРИЦЫ: положите 1,2 кг куриных кусков в 1,5 л холодной воды с 1 ч; л; соли в большой кастрюле; доведите до кипения, снимите пену, убавьте до слабого кипения; варите 25–30 минут, пока курица не будет едва готова (соки прозрачные); достаньте курицу на тарелку, сохраните бульон (~1,2 л). ОБЖАРКА СЕМЯН: в сухой сковороде на среднем огне обжаривайте 100 г тыквенных семечек, постоянно помешивая, 3–4 минуты, пока они не вздуются и не станут золотисто-коричневыми — не сжигайте; переложите в миску; в той же сковороде обжарьте 50 г кунжута 1–2 минуты до золотистого цвета и аромата, постоянно помешивая; добавьте в ту же миску. ОБЖИГ ОВОЩЕЙ: в сухой сковороде или комале на среднем-сильном огне обжигайте 4 половинки помидоров (сначала срезом вниз), 4 половинки томатильо, 1 четвертинку лука и 5 неочищенных зубчиков чеснока; время от времени переворачивайте 8–10 минут, пока кожица не почернеет местами и овощи не размягчатся; очистите чеснок после остывания. ОБЖАРКА ПЕРЦА И СПЕЦИЙ: в той же сковороде кратко обжаривайте 4 гуахильо + 2 анчо + 1 чипотле (по желанию), прижимая лопаткой, по 20–30 секунд с каждой стороны до аромата — не сжигайте; переложите в миску и залейте кипятком; замочите на 15 минут; в той же сковороде кратко обжарьте палочку корицы, 2 гвоздички, 1 ч; л; перца и 0,5 ч; л; ямайского перца 30 секунд; обжарьте кусочки тортильи по 30 секунд с каждой стороны до хрусткости. ВЗБИВАНИЕ ПАСТЫ: в блендер положите процеженные перцы, обожжённые овощи, очищенный чеснок, обжаренные семена, кусочки тортильи и 500 мл куриного бульона; взбивайте на максимальной скорости 3–4 минуты до полной однородности — процедите через мелкое сито для шёлковой текстуры. ВАРКА СОУСА: разогрейте 2 ст; л; масла в кастрюле на среднем огне; влейте взбитую пасту — осторожно, она брызгается; тушите 10 минут, часто помешивая деревянной ложкой, пока соус не потемнеет и сырой вкус не исчезнет; соус должен покрывать обратную сторону ложки. ТУШЕНИЕ КУРИЦЫ: верните куриные куски в кастрюлю, затем влейте оставшиеся 700 мл бульона + 200 г чайоте + 300 г картофельных кубиков; тушите на медленном огне, частично прикрыв, 25–30 минут, пока картофель и чайоте не станут мягкими, а курица — насыщенной соусом; помешивайте время от времени; отрегулируйте соль. ПОДАЧА: разложите пепиан по глубоким тарелкам поверх белого риса; посыпьте каждую порцию свежей кинзой и сбрызните лаймом (по желанию); подавайте с тёплыми кукурузными тортильями для собирания соуса.","en":"POACH THE CHICKEN: place 1.2 kg chicken pieces in 1.5 L cold water with 1 tsp salt in a large pot; bring to a boil, skim the foam, then reduce to a gentle simmer; cook 25–30 minutes until the chicken is just cooked through (juices run clear); remove the chicken to a plate and reserve the broth (~1.2 L). TOAST THE SEEDS: in a dry skillet over medium heat, toast 100 g pumpkin seeds, stirring constantly, 3–4 minutes until they puff up and turn golden brown — do not burn; transfer to a bowl; in the same skillet, toast 50 g sesame seeds 1–2 minutes until golden and fragrant, stirring constantly; add to the same bowl. CHAR THE VEGETABLES: in a dry skillet or comal over medium-high heat, char 4 halved tomatoes (cut side down first), 4 halved tomatillos, 1 quartered onion, and 5 unpeeled garlic cloves; turn occasionally for 8–10 minutes until the skins are blackened in spots and the vegetables soften; peel the garlic after they cool. TOAST THE CHILIES AND SPICES: in the same skillet, briefly toast 4 guajillo + 2 ancho + 1 chipotle (optional) chilies, pressing them flat with a spatula, 20–30 seconds per side until fragrant — do not burn; transfer to a bowl and cover with boiling water; soak 15 minutes; in the same skillet, briefly toast 1 cinnamon stick, 2 cloves, 1 tsp pepper, and 0.5 tsp allspice for 30 seconds; toast the torn tortilla pieces 30 seconds per side until crisp. BLEND THE PASTE: in a blender, combine the drained chilies, the charred vegetables, peeled garlic, toasted seeds, toasted tortilla pieces, and 500 ml of the chicken broth; blend on high 3–4 minutes until the paste is completely smooth — strain through a fine sieve if you want it silky. COOK THE SAUCE: heat 2 tablespoons of oil in the pot over medium heat; pour in the blended paste — be careful, it will splutter; simmer 10 minutes, stirring frequently with a wooden spoon, until the sauce darkens and the rawness cooks off; the sauce should coat the back of the spoon. STEW THE CHICKEN: return the chicken pieces to the pot, then pour in the remaining 700 ml broth + 200 g chayote + 300 g potato cubes; simmer gently, partially covered, 25–30 minutes until the potatoes and chayote are fork-tender and the chicken is fully infused with the sauce; stir occasionally to prevent sticking; adjust salt to taste — the sauce should taste deeply spiced and slightly sweet. SERVE: spoon the pepian into deep plates over a bed of steamed white rice; top each serving with a sprinkle of fresh cilantro and a squeeze of lime (optional); serve with warm corn tortillas on the side for scooping up the sauce."}},{"id":151,"origin":{"ru":"Россия","en":"Russia","ro":"Rusia"},"name":{"ru":"Окрошка","en":"Okroshka","ro":"Okroshka"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"ru":["1 л натурального кефира 3,2% жирности, хорошо охлаждённого","500 мл холодной негазированной минеральной воды (или холодной кипячёной воды), охлаждённой","500 г средней крахмалистой картошки (4 шт.), сваренной в кожуре, затем очищенной и нарезанной кубиками 1 см","4 крупных яйца, сваренных вкрутую, очищенных и нарезанных кубиками 1 см","400 г огурцов (3 средних), очищенных, крупные семена удалены, нарезанных кубиками 0,5 см","300 г варёной докторской колбасы или ветчины, нарезанной кубиками 0,5 см","150 г красной редиски, очищенной и нарезанной кубиками 0,5 см","6 зелёных луковиц (белые и зелёные части отдельно), тонко нарезанных","30 г свежего укропа, мелко нарубленного (плюс 1 ст. л. для подачи)","1 ст. л. дижонской горчицы (по желанию, но традиционно)","1,5 ч. л. мелкой соли + 0,5 ч. л. свежемолотого чёрного перца","1 ч. л. сахара (уравновешивает кислинку кефира)","1 ч. л. лимонного сока или белого винного уксуса","Сметана для подачи","Кубики льда и свежий ржаной хлеб для подачи"],"en":["1 L plain kefir (3.2% fat), well chilled","500 ml cold still mineral water (or cold boiled water), chilled","500 g medium starchy potatoes (4 pieces), boiled in skins then peeled and diced 1 cm","4 large hard-boiled eggs, peeled and diced 1 cm","400 g cucumbers (3 medium), peeled, large seeds scooped out, diced 0.5 cm","300 g cooked doktorskaya sausage or boiled ham, diced 0.5 cm","150 g red radishes, trimmed and diced 0.5 cm","6 spring onions (whites and greens kept separate), thinly sliced","30 g fresh dill, finely chopped (plus 1 tbsp to garnish)","1 tbsp Dijon-style mustard (optional but traditional)","1.5 tsp fine salt + 0.5 tsp freshly ground black pepper","1 tsp sugar (balances the kefir tang)","1 tsp lemon juice or white-wine vinegar","Sour cream (smetana) to drizzle when serving","Ice cubes and fresh dark rye bread for serving"],"ro":["1 L chefir simplu 3,2% grăsime, bine răcit","500 ml apă minerală plată rece sau apă fiartă rece, răcită","500 g cartofi medii (4 bucăți) fierți în coajă, decojiți și tăiați cuburi de 1 cm","4 ouă mari fierte tari, decojite și tăiate cuburi de 1 cm","400 g castraveți (3 bucăți medii), decojiți, fără sâmburi mari și tăiați cuburi de 0,5 cm","300 g cârnați doktorskaya sau șuncă fiartă, tăiată cuburi de 0,5 cm","150 g ridichi roșii, tăiate cuburi de 0,5 cm","6 cepe verzi (cu părți albe și verzi separate), feliate subțire","30 g mărar proaspăt, tocat fin (plus 1 lingură pentru ornare)","1 lingură muștar Dijon (opțional, dar tradițional)","1,5 lingurițe sare fină + 0,5 linguriță piper negru proaspăt măcinat","1 linguriță zahăr (echilibrează aciditatea chefirului)","1 linguriță suc de lămâie sau oțet de vin alb","Smântână (smetana) pentru servire","Cuburi de gheață și pâine neagră proaspătă pentru servire"]},"howIsMade":{"ru":"ОТВАРИВАНИЕ КАРТОФЕЛЯ И ЯИЦ: в кастрюле с холодной подсоленной водой отварите 500 г картофеля целиком (в кожуре, отскоблив) 20–25 минут до мягкости при проколе вилкой; во второй кастрюле положите 4 яйца в холодную воду, доведите до кипения, затем варите 9 минут для крутых; слейте обе, картофель залейте холодной водой для лёгкого очищения, яйца положите в ледяную воду на 5 минут; очистите и нарежьте оба кубиками 1 см; разложите на подносе и охладите 30 минут в холодильнике — всё должно быть холодным перед смешиванием. ОГУРЦЫ: очистите 400 г огурцов, разрежьте вдоль, ложкой выньте крупные водянистые семена, затем нарежьте кубиками 0,5 см — мелкий ровный кубик существенен, более крупные куски тонут и портят суп; промокните бумажным полотенцем для удаления лишней влаги. БЕЛКОВЫЙ ИНГРЕДИЕНТ: нарежьте 300 г варёной колбасы или ветчины кубиками 0,5 см — такого же размера, как огурцы, чтобы каждая ложка была сбалансированной. РЕДИС И ЛУК: подравняйте и нарежьте 150 г редиса кубиками 0,5 см; нарежьте 6 зелёных луковиц (белые и зелёные части отдельно); мелко нарубите 30 г укропа, отложите 1 ст; л; для подачи; в маленькой миске разотрите 2 ст; л; белой части лука с щепоткой соли тыльной стороной ложки — это раскроет аромат в супе. ЗАПРАВКА: в большой миске взбейте венчиком 1 л холодного кефира + 500 мл холодной воды + 1 ст; л; горчицы + 1 ч; л; лимонного сока + 1,5 ч; л; соли + 0,5 ч; л; перца + 1 ч; л; сахара; взбивайте 30 секунд до гладкости, затем попробуйте — основа должна быть кисловатой и слегка сладкой, щедро приправленной, так как нарезанные ингредиенты её разбавят. СБОРКА: добавьте все нарезанные ингредиенты (картофель, яйца, огурцы, колбасу, редис, зелёные части лука, размятую белую часть, укроп) в кефирную основу; аккуратно перемешайте половником для равномерного распределения, не давя ничего. ОХЛАЖДЕНИЕ: накройте и поставьте окрошку в холодильник минимум на 30 минут (идеально на 1 час), чтобы вкусы слились и суп стал ледяным; не держите дольше 3 часов — огурцы начнут отдавать воду и суп станет жидким. ПОДАЧА: аккуратно перемешайте перед подачей; разлейте в глубокие, хорошо охлаждённые тарелки; на каждую тарелку положите 1 ст; л; сметаны, несколько веточек укропа и 2 кубика льда в летнюю жару; подавайте сразу со свежим ржаным хлебом; горчица на столе для любителей более острого.","en":"BOIL THE POTATOES AND EGGS: in a pot of cold salted water, boil 500 g whole potatoes (skins on, scrubbed) 20–25 min until fork-tender; in a second pot, place 4 eggs in cold water, bring to a boil, then simmer 9 min for hard-boiled; drain both, cover potatoes with cold water to peel easily, plunge eggs into ice water 5 min; peel and dice both 1 cm; spread on a tray and chill 30 min in the fridge — everything must be cold before mixing. DICE THE CUCUMBERS: peel 400 g cucumbers, halve lengthwise, scoop out any large watery seeds with a spoon, then dice 0.5 cm — the small even cube is essential, larger pieces sink and ruin the soup; pat with paper towel to remove excess water. DICE THE PROTEIN: dice 300 g cooked sausage or boiled ham into 0.5 cm cubes — the same size as the cucumbers so each spoonful balances. DICE RADISH AND ONIONS: trim and dice 150 g radishes 0.5 cm; slice 6 spring onions (whites and greens kept separate); finely chop 30 g dill, reserve 1 tbsp for garnish; in a small bowl, mash 2 tbsp of the spring-onion whites with a pinch of salt using the back of a spoon — this releases their aroma into the soup. THE DRESSING: in a large mixing bowl, whisk together 1 L cold kefir + 500 ml cold water + 1 tbsp mustard + 1 tsp lemon juice + 1.5 tsp salt + 0.5 tsp pepper + 1 tsp sugar; whisk 30 seconds until smooth, then taste — the base should be tangy and slightly sweet, generously seasoned because the diced ingredients will dilute it. ASSEMBLE: add all diced ingredients (potatoes, eggs, cucumbers, sausage, radish, spring-onion greens and mashed whites, dill) to the kefir base; stir gently with a ladle to distribute evenly without crushing anything. CHILL: cover and refrigerate the okroshka 30 minutes minimum (ideally 1 hour) so the flavours mingle and the soup becomes ice-cold; do not chill longer than 3 hours — the cucumbers will start to release water and the soup turns thin. SERVE: stir gently before serving; ladle into deep, well-chilled bowls; top each bowl with 1 tablespoon sour cream, a few extra dill fronds, and 2 ice cubes per bowl in summer heat; serve immediately with fresh dark rye bread on the side; mustard on the table for those who like it sharper."}},{"id":152,"origin":{"ru":"Узбекистан","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"ru":"Плов","en":"Plov","ro":"Plov"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"ru":["600 г бараньей лопатки или говяжьей шеи с небольшим количеством жира, нарезанной кубиками 3 см","100 г курдючного жира (бараний хвостовой жир) для аутентичного вкуса — ИЛИ 150 мл нейтрального подсолнечного масла как замена","500 г девзиры или длиннозёрного риса басмати","500 г жёлтой моркови (или 600 г оранжевой моркови), нарезанной соломкой 0,5 × 0,5 × 5 см — НЕ натирать","2 крупные жёлтые луковицы (~300 г), нарезанные тонкими полукольцами","2 целые головки чеснока (без внешней шелухи, но головки целые)","1 ст. л. целых семян зиры (не молотых)","1 ст. л. сушёных ягод барбариса (зира/барбарис) — по желанию, традиционно","0,5 ч. л. молотой куркумы (для цвета)","1 целый сушёный острый красный перец (по желанию)","1 ч. л. молотого чёрного перца","1,5 ст. л. мелкой соли + соль по вкусу","1,2 л кипятка (резерв)","100 г нута, замоченного на ночь (по желанию, традиционный ташкентский стиль)","Для подачи: тонко нарезанный красный лук с уксусом, ачичук — салат из помидоров и огурцов, лепёшка (нон)"],"en":["600 g lamb shoulder or beef chuck with some fat, cut into 3 cm cubes","100 g lamb-tail fat (kurdyuk) for authentic flavour — OR 150 ml neutral sunflower oil as a substitute","500 g devzira or long-grain basmati rice","500 g yellow carrots (or 600 g orange carrots), cut into julienne matchsticks 0.5 × 0.5 × 5 cm — do NOT grate","2 large yellow onions (~300 g), thinly sliced","2 whole heads of garlic (papery outer skins removed but heads intact)","1 tbsp whole cumin seeds (not ground)","1 tbsp dried barberries (zira/barbaris) — optional but traditional","0.5 tsp ground turmeric (for colour)","1 dried whole hot red chili (optional)","1 tsp ground black pepper","1.5 tbsp fine salt + extra to season","1.2 L boiling water (reserve)","100 g chickpeas, soaked overnight (optional, traditional Tashkent style)","To serve: thinly sliced red onion with vinegar, achichuk tomato-cucumber salad, flatbread (non)"],"ro":["600 g umăr de miel sau gulaș de vită cu puțină grăsime, tăiat cuburi de 3 cm","100 g grăsime de coadă de oaie (kurdyuk) — opțional pentru aromă autentică — SAU 150 ml ulei neutru de floarea-soarelui ca substitut","500 g orez devzira sau basmati cu bob lung","500 g morcovi galbeni (sau 600 g morcovi portocalii), tăiați julien în bețișoare de 0,5 × 0,5 × 5 cm — NU dați prin răzătoare","2 cepe galbene mari (~300 g), feliate subțire","2 căpățâni de usturoi întregi (cu coaja exterioară curățată, dar capul păstrat întreg)","1 lingură semințe de chimion întregi (nu măcinate)","1 lingură fructe uscate de cătină (zira/barbaris) — opțional, tradițional","0,5 linguriță turmeric măcinat (pentru culoare)","1 ardei roșu iute uscat întreg (opțional)","1 linguriță piper negru măcinat","1,5 linguri sare fină + sare după gust","1,2 L apă clocotită (rezerve)","100 g năut, înmuiat peste noapte (opțional, tradițional Tashkent)","Pentru servire: ceapă roșie feliată subțire cu oțet, salată de roșii cu castraveți (achichuk), pâine plată non"]},"howIsMade":{"ru":"ЗАМАЧИВАНИЕ РИСА: промойте 500 г риса в холодной воде 4–5 раз до прозрачной воды, затем замочите в тёплой подсоленной воде (1 ч; л; соли на литр) на 1 час; этот шаг обязателен для плова — зёрна остаются отдельными и равномерно впитывают бульон; слейте воду непосредственно перед добавлением в казан. ВЫТАПЛИВАНИЕ ЖИРА: в тяжёлом чугунном казане или утятнице на среднем огне вытопите 100 г курдючного жира до золотистых шкварок (около 8 минут), затем удалите их шумовкой; с маслом: разогрейте 150 мл масла, пока оно не заблестит и слегка не задымится (около 3 минут на сильном огне) — это необходимо для нейтрализации сырого вкуса. ОБЖАРКА МЯСА: увеличьте огонь до сильного и добавьте 600 г кубиков мяса в один слой в горячий жир; обжаривайте, не трогая, 2–3 минуты с каждой стороны, всего 8–10 минут, до глубокой румяной корочки со всех сторон; достаньте мясо на тарелку. ЛУК + МОРКОВЬ: в оставшемся жире добавьте 300 г нарезанного лука и жарьте, помешивая, 5–6 минут до золотисто-коричневого цвета; верните мясо и положите сверху 500 г моркови соломкой в один слой — НЕ перемешивайте первые 5 минут (пусть морковь распарится); затем аккуратно перемешайте и тушите ещё 8–10 минут до увядания, золотистости и начала карамелизации моркови. ЗИРВАК (БУЛЬОННАЯ ОСНОВА): влейте 1,2 л кипятка (должен покрывать мясо и морковь на 1 см); добавьте 1 ст; л; зиры (предварительно потёртой в ладонях, чтобы выделились масла), 1 ст; л; барбариса, 0,5 ч; л; куркумы, 1 сушёный перец, 1 ч; л; перца, 100 г нута, 1,5 ст; л; соли и 2 целые головки чеснока, воткнутые в центр; доведите до кипения, убавьте огонь и варите без крышки 30 минут — это и есть зирвак; бульон должен быть чуть пересолен; рис уравновесит. ДОБАВЛЕНИЕ РИСА: аккуратно слейте замоченный рис и равномерно распределите его поверх зирвака (не перемешивайте); рис должен быть едва покрыт жидкостью — если нет, осторожно долейте кипяток; увеличьте огонь до сильного и варите без крышки 10–12 минут, пока видимая вода не опустится до уровня поверхности риса (проверьте палочкой); похлопайте рис плоско шумовкой, но никогда не смешивайте со слоем мяса. НАКРЫВАНИЕ + ПРОПАРИВАНИЕ: когда поверхностная вода испарится и на поверхности риса появятся маленькие отверстия для пара, сформируйте рис в купол, проделайте 4–5 глубоких отверстий до дна ручкой деревянной ложки (для выхода пара), убавьте огонь до минимума, накройте казан плотной крышкой (положите чистое полотенце под крышку для впитывания конденсата) и варите 25 минут; затем снимите с огня и дайте настояться под крышкой 15 минут — не поднимайте крышку. ПОДАЧА: снимите крышку и достаньте головки чеснока и перец; аккуратно копайте ложкой, поднимая рис и доставая мясо и морковь со дна, перемешивая при перекладывании на большое общее блюдо; положите мясо и чеснок в центр, окружив рисом; подавайте сразу с тонко нарезанным красным луком, сбрызнутым уксусом, свежим салатом из помидоров и лепёшкой.","en":"SOAK THE RICE: wash 500 g rice in cold water 4–5 times until the water runs clear, then soak it in warm salted water (1 tsp salt per litre) for 1 hour; this step is non-negotiable for plov — the grains stay separate and absorb the broth evenly; drain just before adding to the pot. RENDER THE FAT: in a heavy cast-iron kazan or Dutch oven over medium heat, melt 100 g lamb-tail fat until the cracklings are golden brown (about 8 minutes), then remove them with a slotted spoon; if using oil: heat 150 ml oil until it shimmers and faintly smokes (about 3 minutes at high heat) — essential to neutralize the raw taste. SEAR THE MEAT: raise heat to high and add 600 g cubed meat in a single layer to the hot fat; sear undisturbed 2–3 minutes per side, total 8–10 minutes, until deeply browned on all sides; lift the meat out to a plate. ONION + CARROT: in the remaining fat, add 300 g sliced onion and fry, stirring, 5–6 minutes until golden brown; return the meat and add 500 g julienned carrots in a single layer on top — do NOT stir for the first 5 minutes (this lets the carrots steam); then stir gently and cook another 8–10 minutes until the carrots are wilted, golden, and just starting to caramelize. ZIRVAK (BROTH BASE): pour in 1.2 L boiling water (it should cover the meat and carrots by 1 cm); add 1 tbsp cumin seeds (first rubbed briefly between your palms to release the oils), 1 tbsp barberries, 0.5 tsp turmeric, 1 dried chili, 1 tsp black pepper, 100 g chickpeas, 1.5 tbsp salt, and the 2 whole garlic heads pushed into the centre; bring to a boil, reduce heat to low and simmer uncovered 30 minutes — this is the zirvak; the broth must taste slightly over-seasoned; the rice will tame it. ADD THE RICE: drain the soaked rice carefully and spread it evenly over the zirvak (do not stir it in); the rice should just be submerged — if not, add boiling water carefully; raise heat to high and cook uncovered 10–12 minutes until the visible water has reduced to the surface of the rice (poke with a chopstick to check); tap the rice flat with a slotted spoon but never mix it with the meat layer below. COVER + STEAM: once the surface water has evaporated and small steam holes appear on the rice surface, mound the rice into a dome, poke 4–5 deep holes through to the bottom with the handle of a wooden spoon (for steam to escape), reduce heat to the lowest setting, cover the pot with a tight lid (place a clean kitchen towel under the lid to absorb condensation), and cook 25 minutes; then remove from heat and let rest, covered, 15 minutes — do not lift the lid. SERVE: uncover and lift out the garlic heads and chili; gently dig down with a spoon, lifting the rice and bringing the meat and carrots from the bottom to the top, mixing as you transfer to a large communal platter; arrange the meat and garlic on top in the centre, surrounded by rice; serve immediately with sliced red onion sprinkled with vinegar, fresh tomato salad, and flatbread on the side."}},{"id":153,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"ru":"Словения","en":"Slovenia","ro":"Slovenia"},"name":{"ru":"Потица","en":"Potica","ro":"Potica"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["Для теста: 500 г хлебной муки (или муки высшего сорта), плюс дополнительно для замеса","7 г сухих быстродействующих дрожжей ИЛИ 21 г свежих дрожжей","50 г сахара (1 ч. л. для активации дрожжей, остальное в тесто)","5 г мелкой соли","250 мл тёплого цельного молока (38 °C)","100 г несолёного сливочного масла, растопленного и охлаждённого до тёплого","2 крупных желтка + 1 целое яйцо для теста","1 ст. л. тёмного рома (по желанию, традиционно)","Мелко натёртая цедра 1 необработанного лимона","Для ореховой начинки: 400 г очищенных грецких орехов, мелко смолотых (свежесмолотых — готовые не подойдут)","200 мл горячего цельного молока","150 г акациевого мёда (или мягкого цветочного мёда)","100 г несолёного сливочного масла, растопленного, для начинки","100 г сахара для начинки","2 желтка + 2 белка (взбитых отдельно до устойчивых пиков)","1 ст. л. тёмного рома, 1 ч. л. молотой корицы, 0,5 ч. л. молотой гвоздики, 1 ст. л. свежей панировки","Для отделки: 1 яйцо, взбитое с 1 ст. л. молока (для смазки), сахарная пудра для посыпки после выпечки"],"en":["For the dough: 500 g bread flour (or strong all-purpose), plus extra for kneading","7 g instant dry yeast OR 21 g fresh yeast","50 g caster sugar (1 tsp to feed the yeast, the rest in the dough)","5 g fine salt","250 ml warm whole milk (38 °C)","100 g unsalted butter, melted and cooled to lukewarm","2 large egg yolks + 1 whole egg for the dough","1 tbsp dark rum (optional, traditional)","Finely grated zest of 1 unwaxed lemon","For the walnut filling: 400 g finely ground shelled walnuts (freshly ground — pre-ground will not work)","200 ml hot whole milk","150 g acacia honey (or mild floral honey)","100 g unsalted butter, melted, for the filling","100 g caster sugar for the filling","2 large egg yolks + 2 egg whites (whipped to stiff peaks separately)","1 tbsp dark rum, 1 tsp ground cinnamon, 0.5 tsp ground cloves, 1 tbsp fresh breadcrumbs","For finishing: 1 egg beaten with 1 tbsp milk (egg wash), icing sugar to dust after baking"],"ro":["Pentru aluat: 500 g făină pentru pâine (T550), plus pentru frământare","7 g drojdie uscată instant SAU 21 g drojdie proaspătă","50 g zahăr fin (1 linguriță pentru a hrăni drojdia, restul în aluat)","5 g sare fină","250 ml lapte integral cald (38 °C)","100 g unt nesărat topit și răcit la călduț","2 gălbenușuri mari + 1 ou întreg pentru aluat","1 lingură rom întunecat (opțional, tradițional)","Coaja rasă fin de la 1 lămâie netratată","Pentru umplutură: 400 g miez de nucă măcinat fin (proaspăt măcinat, nu pre-măcinat — esențial)","200 ml lapte integral fierbinte","150 g miere de salcâm (sau miere florală blândă)","100 g unt nesărat topit pentru umplutură","100 g zahăr fin pentru umplutură","2 gălbenușuri + 2 albușuri (bătute spumă tare separat)","1 lingură rom întunecat, 1 linguriță scorțișoară măcinată, 0,5 linguriță cuișoare măcinate, 1 lingură pesmet proaspăt","Pentru finisare: 1 ou bătut cu 1 lingură lapte (spălătură), zahăr pudră pentru presărat după coacere"]},"howIsMade":{"ru":"АКТИВАЦИЯ ДРОЖЖЕЙ: в маленькой миске растворите 7 г сухих быстродействующих дрожжей (или 21 г свежих) в 250 мл тёплого молока (~38 °C) с 1 ч; л; сахара; оставьте на 10 минут, пока сверху не появится кремовая пена — если не пенится, дрожжи мертвы, начните заново. ТЕСТО: в миксере с крюком (или вручную) смешайте 500 г муки с оставшимися 47 г сахара, 5 г соли и цедрой лимона; влейте вспенившуюся опару, 2 желтка + 1 целое яйцо, 100 г растопленного-и-остывшего масла, 1 ст; л; рома; месите на средней скорости 10 минут (или 15 вручную), пока тесто не станет гладким, эластичным и не начнёт чисто отходить от стенок — мягким, но не липким; накройте плёнкой и поставьте в тёплое место на 1,5–2 часа до удвоения. ОРЕХОВАЯ НАЧИНКА: положите 400 г свежемолотых орехов в большую миску; залейте 200 мл горячего молока, 100 г растопленного масла, 150 г мёда и 100 г сахара; перемешайте, чтобы ошпарить орехи и растворить сахар; остудите 10 минут, затем вмешайте 2 желтка, 1 ст; л; рома, 1 ч; л; корицы, 0,5 ч; л; гвоздики, 1 ст; л; панировки и щепотку соли; в другой миске взбейте 2 белка до устойчивых пиков и аккуратно вмешайте их в ореховую массу в 3 приёма — начинка должна быть воздушной и легко намазываемой. РАСКАТАЙТЕ ТЕСТО: слегка присыпьте мукой чистое полотенце и переверните поднявшееся тесто на него; аккуратно обомните, затем раскатайте тонкий прямоугольник 60 × 40 см толщиной 4–5 мм — работайте от центра к краям, поднимая и поворачивая, чтобы не прилипало; тесто должно быть достаточно тонким, чтобы спираль была видна после выпечки, но достаточно толстым, чтобы удерживать начинку. РАСПРЕДЕЛИТЕ НАЧИНКУ: распределите ореховую начинку равномерно по тесту, оставив бортик 2 см по длинным краям; аккуратно приплюсните лопаткой — не перегружайте, начинка должна быть 5–6 мм толщиной; если где-то слишком тонко, посыпьте дополнительными молотыми орехами. СВЕРНИТЕ В РУЛЕТ: используя полотенце, плотно сверните тесто с длинной стороны, формируя длинный рулет; сворачивайте плотно, но не настолько, чтобы сжимать начинку; защипните шов и подверните концы; рулет должен быть около 60 см. ФОРМА + ВТОРАЯ РАССТОЙКА: тщательно смажьте маслом трубчатую форму для потицы (или 24 см форму Бундт, или кугельхопф) и присыпьте мукой; уложите рулет швом вниз, соединяя концы в замкнутое кольцо (зажмите вместе); накройте неплотно и оставьте в тёплом месте на 45–60 минут, пока тесто заметно не поднимется, почти заполнив форму; тем временем разогрейте духовку до 175 °C. ВЫПЕКАЙТЕ: смажьте верх яичной смазкой; выпекайте на средней решётке духовки при 175 °C 45–55 минут — накройте неплотно фольгой через 30 минут, если верх слишком быстро темнеет; потица готова, когда шпажка выходит чистой, а внутренняя температура достигает 92–95 °C; дайте отдохнуть 15 минут в форме, затем осторожно опрокиньте на решётку и полностью охладите; перед нарезкой щедро посыпьте сахарной пудрой; подавайте при комнатной температуре с крепким кофе или чаем.","en":"ACTIVATE THE YEAST: in a small bowl, dissolve 7 g instant dry yeast (or 21 g fresh yeast) into 250 ml warm milk (~38 °C) with 1 tsp sugar; let stand 10 minutes until a creamy foam appears on top — if it doesn't foam, the yeast is dead, start over. THE DOUGH: in a stand mixer with dough hook (or by hand), combine 500 g flour with the remaining 47 g sugar, 5 g salt, and lemon zest; pour in the foamed yeast-milk, 2 egg yolks + 1 whole egg, 100 g melted-and-cooled butter, and 1 tbsp rum; knead on medium speed 10 minutes (or 15 by hand) until the dough is smooth, elastic, and pulls cleanly from the bowl — it should be soft but not sticky; cover with film and proof in a warm place 1.5–2 hours until doubled. THE WALNUT FILLING: place 400 g freshly ground walnuts in a large bowl; pour over 200 ml hot milk, 100 g melted butter, 150 g honey, and 100 g sugar; stir well to scald the walnuts and dissolve the sugars; cool 10 minutes, then mix in 2 egg yolks, 1 tbsp rum, 1 tsp cinnamon, 0.5 tsp cloves, 1 tbsp breadcrumbs, and a pinch of salt; in a separate bowl, whip 2 egg whites to stiff peaks, then fold them gently into the walnut mixture in 3 additions — the filling should be airy and spreadable. ROLL THE DOUGH: lightly flour a clean tea towel and turn the proofed dough out onto it; punch down gently, then roll out into a thin rectangle 60 × 40 cm and 4–5 mm thick — work from the centre outward, lifting and rotating to prevent sticking; the dough must be thin enough that the spiral is visible after baking, but thick enough to hold the filling. SPREAD THE FILLING: spread the walnut filling evenly over the rolled dough, leaving a 2 cm border along the long edges; pat it gently with a spatula — do not overload, the filling should be 5–6 mm thick; sprinkle a few extra ground walnuts if any spot oozes thin. ROLL UP: using the tea towel to help, roll up the dough tightly from the long side, forming a long log; roll snug but not so tight you compress the filling; pinch the seam closed and tuck in the ends; the log should be about 60 cm long. SHAPE IN MOLD + SECOND PROOF: grease a tubular potica mold (or a 24 cm Bundt pan or a kugelhopf form) thoroughly with butter and dust with flour; lay the log in the mold, seam side down, joining the ends to form a closed ring (pinch them together); cover loosely and proof again in a warm place 45–60 minutes until the dough has risen visibly to almost fill the mold; meanwhile, preheat the oven to 175 °C. BAKE: brush the top with the egg wash; bake on the middle rack of the 175 °C oven 45–55 minutes — cover loosely with foil after 30 min if the top is browning too fast; the potica is done when a skewer comes out clean and the internal temperature reaches 92–95 °C; let it rest 15 minutes in the mold, then carefully invert onto a wire rack to cool completely; dust generously with icing sugar before slicing; serve at room temperature with strong coffee or tea."}},{"id":154,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"ru":"Нигерия","en":"Nigeria","ro":"Nigeria"},"name":{"ru":"Суп эгуси","en":"Egusi soup","ro":"Egusi soup"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["250 г сырых семян эгуси, мелко смолотых (или 200 г готового молотого эгуси)","600 г козлятины или говяжьей грудинки на кости, нарезанной кусками 4 см","200 г копчёной рыбы (скумбрия или сом) — очищенной, без костей, поломанной (по желанию, традиционно)","100 г сушёных креветок или стокфиша, замоченных 30 мин и порванных мелко (по желанию)","1 средняя луковица (~150 г), крупно нарезанная","2 перца Скотч-боннет (или 3 хабанеро) — по вкусу к остроте","2 красных болгарских перца (~300 г), без семян","100 мл красного пальмового масла","3 крупных свежих помидора (~400 г) ИЛИ 200 г томатной пасты, смешанной с 200 мл воды","4 зубчика чеснока, мелко рубленых","5 см свежего имбиря, очищенного и натёртого","2 бульонных кубика (Maggi или похожих, 10 г)","1 ст. л. молотого крайфиша (необходимо для аутентичного вкуса) — замена: 1 ст. л. молотых сушёных креветок","1 лавровый лист (или 1 ч. л. молотого)","200 г свежего шпината или листьев тыквы угу, помытых и крупно нарубленных","1,5 ч. л. соли + соль по вкусу","1 ст. л. семян ируа/давадавы — по желанию, традиционно йоруба","Для подачи: толчёный ямс, фуфу, эба (гари) или варёный белый рис"],"en":["250 g raw egusi seeds, finely ground (or 200 g pre-ground egusi)","600 g goat meat or beef chuck on the bone, cut into 4 cm pieces","200 g smoked fish (mackerel or catfish) — cleaned, boned, broken into chunks (optional, traditional)","100 g dried prawns or stockfish (panla), soaked 30 min and torn small (optional)","1 medium onion (~150 g), roughly chopped","2 Scotch bonnet peppers (or 3 habaneros) — adjust to heat tolerance","2 red bell peppers (~300 g), seeded","100 ml red palm oil","3 large fresh tomatoes (~400 g) OR 200 g tomato paste blended with 200 ml water","4 garlic cloves, finely minced","5 cm fresh ginger, peeled and grated","2 stock cubes (Maggi or similar, 10 g)","1 tbsp ground crayfish (essential for authentic flavour) — substitute: 1 tbsp ground dried shrimp","1 bay leaf (or 1 tsp ground bay)","200 g fresh spinach or ugu pumpkin leaves, washed and roughly chopped","1.5 tsp salt + more to taste","1 tbsp locust beans (iru/dawadawa) — optional, traditional Yoruba addition","To serve: pounded yam, fufu, eba (gari), or boiled white rice"],"ro":["250 g semințe egusi brute, măcinate fin (sau 200 g egusi pre-măcinat)","600 g carne de capră sau gulaș de vită cu os, tăiată în bucăți de 4 cm","200 g pește afumat (macrou sau somn) — curățat, dezosat, rupt în bucăți (opțional, tradițional)","100 g creveți uscați sau stockfish, înmuiat 30 minute și rupt mic (opțional)","1 ceapă medie (~150 g), tocată grosier","2 ardei iuți Scotch bonnet (sau 3 habanero) — ajustează după toleranța la iuțeală","2 ardei roșii grași (~300 g), fără semințe","100 ml ulei roșu de palmier","3 roșii mari proaspete (~400 g) sau 200 g pastă de roșii amestecată cu 200 ml apă","4 căței de usturoi, tocați fin","5 cm rădăcină de ghimbir proaspăt, curățată și rasă","2 cuburi Maggi sau pentru condimentare (10 g)","1 lingură crayfish măcinat (esențial pentru aroma autentică) — substitut: 1 lingură creveți uscați măcinați","1 frunză de dafin (sau 1 linguriță dafin măcinat)","200 g spanac proaspăt sau frunze de ugu (pumpkin leaves), spălate și tocate","1,5 lingurițe sare + sare după gust","1 lingură semințe de locust (iru/dawadawa) — opțional, tradițional Yoruba","Pentru servire: igname pisată, fufu, eba (gari) sau orez fiert"]},"howIsMade":{"ru":"ПАСТА ИЗ ЭГУСИ: измельчите 250 г семян эгуси в кофемолке или процессоре 30 секунд до мелкого помола, но не до пасты; в маленькой миске смешайте с 200 мл тёплой воды до густой пасты типа хумуса; дайте постоять 10 минут для полной гидратации — это секрет фирменной текстуры: зернистой снаружи, кремовой внутри. ВАРКА МЯСА: в тяжёлой кастрюле соедините 600 г нарезанного мяса с 1 нарезанной луковицей, 4 зубчиками чеснока, тёртым имбирём, 2 бульонными кубиками, 1 ч; л; соли и 1 л воды; доведите до кипения, затем варите под крышкой 40–50 минут (дольше с козлятиной), пока мясо не станет нежным, но не распадётся; процедите и сохраните 800 мл бульона; мясо отложите. ОСНОВА ИЗ ПЕРЦА: в блендере соедините 2 болгарских перца, 2 Скотч-боннет и 3 свежих помидора (или пасту с водой); взбивайте 1–2 минуты до полной однородности; перелейте в широкую сковороду и тушите на среднем огне 15 минут — смесь должна уменьшиться вдвое, а цвет углубиться до густо-кирпичного; эта концентрация необходима, иначе суп получится водянистым. ОБЖАРКА В ПАЛЬМОВОМ МАСЛЕ: в супной кастрюле на среднем огне разогрейте 100 мл пальмового масла 2 минуты, пока не блеснёт (НЕ доводите до дыма — пережаривание разрушает аромат); добавьте уменьшенную основу из перца-помидоров и обжаривайте, помешивая, 8–10 минут, пока масло не всплывёт на поверхность и смесь не потемнеет; это называется \"обжарка основы\". ДОБАВЛЕНИЕ ЭГУСИ: возьмите гидратированную пасту из эгуси по столовым ложкам и опускайте её клёцками в кипящую основу — НЕ перемешивайте; дайте клёцкам готовиться 5 минут без вмешательства, затем аккуратно вмешайте; некоторые сохранят форму (комочки), другие распадутся и загустят соус — это желаемая текстура. БУЛЬОН + МЯСО + РЫБА: влейте 800 мл сохранённого бульона; добавьте сваренное мясо, 200 г копчёной рыбы (кусками), 100 г замоченных сушёных креветок/стокфиша (по желанию), 1 ст; л; молотого крайфиша, 1 ст; л; ируа (по желанию) и 1 лавровый лист; аккуратно перемешайте, доведите до кипения и варите без крышки 15–20 минут, пока суп не уварится до пудинговой консистенции — он должен горкой держаться на ложке, а не литься как бульон. ЗЕЛЕНЬ: вмешайте 200 г нарубленного шпината (или угу/листьев тыквы) в кипящий суп; готовьте 5–7 минут без крышки, пока зелень не увянет, но останется ярко-зелёной; попробуйте и отрегулируйте соль и остроту; суп должен быть глубоко насыщенным, слегка ореховым (от эгуси), с чистым финишем пальмового масла и нарастающей остротой. ОТДЫХ И ПОДАЧА: выключите огонь и дайте супу постоять 5 минут — вкусы драматически объединяются; подавайте в глубоких тарелках с гарниром-«глотком» (толчёный ямс, фуфу, эба или амала) рядом; ешьте правой рукой: возьмите маленький комочек, обмакните в суп и проглотите не жуя; варёный белый рис — более мягкий вариант.","en":"EGUSI PASTE: pulse 250 g egusi seeds in a spice grinder or food processor 30 seconds until finely ground but not yet pasty; in a small bowl, mix with 200 ml warm water into a thick, hummus-like paste; let it sit 10 minutes to hydrate fully — this is the secret to the signature lumpy-creamy texture. COOK THE MEAT: in a heavy pot, combine 600 g cut meat with 1 chopped onion, 4 minced garlic, grated ginger, 2 stock cubes, 1 tsp salt and 1 L water; bring to boil, then simmer covered 40–50 minutes (longer if using goat) until the meat is tender enough to bite easily but not falling apart; strain and reserve 800 ml of the broth; set the meat aside. BLEND THE PEPPER BASE: in a blender, combine 2 red bell peppers, 2 Scotch bonnet peppers, and 3 fresh tomatoes (or paste-and-water mix); blend 1–2 minutes until completely smooth; pour into a wide pan and simmer over medium heat 15 minutes — the mix should reduce by half and the colour deepen to a rich brick-red; this concentration is essential or the soup will be watery. FRY THE PALM-OIL BASE: in your soup pot over medium heat, warm 100 ml palm oil 2 minutes until it just shimmers (do NOT smoke it — over-smoking destroys the flavour); add the reduced pepper-tomato base and fry, stirring, 8–10 minutes until the oil floats to the surface and the mixture darkens slightly; this is called \"frying the base\". ADD THE EGUSI: take the hydrated egusi paste by tablespoons and drop dumpling-style into the simmering pepper base — do NOT stir; let the dumplings cook undisturbed 5 minutes, then gently fold them in; some will hold their shape (the lumps) while others break apart and thicken the sauce — this is the desired texture. ADD STOCK + MEAT + FISH: pour in 800 ml reserved meat broth; add the cooked meat, 200 g smoked fish (broken into chunks), 100 g soaked dried prawns/stockfish (optional), 1 tbsp ground crayfish, 1 tbsp locust beans (optional), and 1 bay leaf; stir gently, bring to a simmer and cook uncovered 15–20 minutes until the soup has reduced and thickened to a pudding-like consistency — it should mound on a spoon, not pour like broth. ADD GREENS: stir in 200 g chopped spinach (or ugu/pumpkin leaves) into the simmering soup; cook 5–7 minutes uncovered until the greens are wilted but still bright green; taste and adjust salt and heat; the soup should taste deeply savoury, slightly nutty (from the egusi), with a clean palm-oil finish and a building chili heat. REST AND SERVE: turn off the heat and let the soup rest 5 minutes — the flavours meld dramatically in this short rest; serve in deep bowls with the swallow of choice (pounded yam, fufu, eba, or amala) on the side; eat with the right hand: take a small lump of swallow, dip into the soup, and swallow without chewing; boiled white rice is a milder option."}},{"id":155,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Польша","en":"Poland","ro":"Polonia"},"name":{"ru":"Котлет схабовы","en":"Kotlet schabowy","ro":"Kotlet schabowy"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["4 свиных корейка без кости (~180–200 г каждый, ~1,5–2 см толщиной) — около 800 г в общей сложности","1 ч. л. мелкой соли для свинины","0,5 ч. л. свежемолотого белого перца","200 мл цельного молока для размягчающей замачивания (польский приём)","80 г пшеничной муки для панировки","3 крупных яйца, взбитых с 1 ст. л. молока и щепоткой соли","200 г свежей мелкой панировки (домашняя из вчерашнего хлеба — лучше всего) или панко","80 г смальца (традиционно) ИЛИ 100 мл нейтрального подсолнечного масла для жарки","30 г несолёного сливочного масла для финальной поливки","1 лимон, нарезанный дольками (современная гарнировка)","Для картофеля с укропом: 800 г рассыпчатого картофеля, очищенного + 30 г сливочного масла + 1 небольшой пучок нарубленного укропа + соль для воды","Для тушёной квашеной капусты: 400 г слитой квашеной капусты + 1 мелко нарезанная луковица + 1 ст. л. смальца + 100 мл воды"],"en":["4 boneless pork loin chops (~180–200 g each, ~1.5–2 cm thick) — about 800 g total","1 tsp fine salt for the pork","0.5 tsp freshly ground white pepper","200 ml whole milk for the tenderizing soak (the Polish trick)","80 g all-purpose flour for breading","3 large eggs beaten with 1 tbsp milk and a pinch of salt","200 g fine fresh breadcrumbs (homemade from day-old bread is best) or panko","80 g lard (traditional) OR 100 ml neutral sunflower oil for frying","30 g unsalted butter for the finishing baste","1 lemon, cut into wedges (modern garnish)","For dill potatoes: 800 g floury potatoes peeled + 30 g butter + 1 small bunch chopped dill + salt for the cooking water","For sautéed sauerkraut: 400 g drained sauerkraut + 1 small onion finely chopped + 1 tbsp lard + 100 ml water"],"ro":["4 cotlete de porc din mușchi (~180–200 g fiecare, ~1,5–2 cm grosime) — aproximativ 800 g total","1 linguriță sare fină pentru carne","0,5 linguriță piper alb proaspăt măcinat","200 ml lapte integral pentru marinada de tendierare","80 g făină pentru panare","3 ouă mari bătute cu 1 lingură lapte și un vârf de sare","200 g pesmet fin proaspăt (de casă, din pâine de o zi) sau panko","80 g untură (tradițional) SAU 100 ml ulei neutru de floarea-soarelui pentru prăjit","30 g unt nesărat pentru finisare","1 lămâie tăiată în sferturi (garnitură modernă)","Pentru cartofi cu mărar: 800 g cartofi făinoși decojiți + 30 g unt + 1 bunch mic de mărar tocat + sare pentru apa de fierbere","Pentru varza murată: 400 g varză murată scursă + 1 ceapă mică tocată + 1 lingură untură + 100 ml apă"]},"howIsMade":{"ru":"ОТБИВАНИЕ СВИНИНЫ: положите каждую отбивную между двумя листами пленки и отбейте плоским молоточком от центра к краям, 30 секунд с каждой стороны, пока отбивные не станут толщиной 6–7 мм и почти не удвоятся в размере — толщина должна быть равномерной для одинаковой прожарки; надрежьте жирный край 3–4 раза, чтобы предотвратить скручивание. МОЛОЧНАЯ ВЫМОЧКА: обсушите отбитые отбивные и натрите каждую сторону солью и белым перцем; положите в плоское блюдо, залейте 200 мл молока так, чтобы отбивные были почти покрыты, накройте и поставьте в холодильник на 30 минут (до 2 часов) — молочная кислота смягчит мясо, не изменив вкуса. СТАНЦИЯ ПАНИРОВКИ: три плоские тарелки в ряд: тарелка 1 с 80 г муки; тарелка 2 с 3 взбитыми яйцами + 1 ст; л; молока + щепотка соли; тарелка 3 с 200 г мелких сухарей; последовательность важна: каждая отбивная должна пройти муку → яйцо → сухари без пропуска шагов. ПАНИРОВКА ОТБИВНЫХ: достаньте отбивную из молока, дайте лишнему стечь и обваляйте в муке, стряхните излишки — мука должна покрывать тонко и равномерно, иначе яйцо не пристанет; затем окуните в яйцо, дайте стечь 2 секунды, затем плотно прижмите к сухарям с обеих сторон, похлопывая, чтобы прилипли; положите на тарелку; повторите для всех 4 отбивных; дайте отдохнуть 5 минут — панировка увлажнится и схватится. ВАРКА КАРТОФЕЛЯ: тем временем очистите 800 г картофеля и нарежьте кусками 4 см; положите в холодную подсоленную воду, доведите до кипения и варите 15–18 минут до мягкости при проколе вилкой; слейте воду, верните в кастрюлю без огня на 2 минуты для подсушивания, затем перемешайте с 30 г масла и нарубленным укропом. ТУШЕНИЕ КВАШЕНОЙ КАПУСТЫ: в отдельной сковороде растопите 1 ст; л; смальца на среднем огне; добавьте 1 мелко нарезанную луковицу, жарьте 5 минут до золотистости; добавьте 400 г слитой квашеной капусты и 100 мл воды; тушите под крышкой 15 минут, затем откройте и готовьте ещё 5 минут, пока большая часть жидкости не выпарится; приправьте поворотом перца. ЖАРКА ШНИЦЕЛЕЙ: разогрейте 80 г смальца (или 100 мл масла) в большой тяжёлой сковороде на сильном-среднем огне до мерцания (175 °C, или крошка сухарей шипит при контакте); жарьте отбивные по 2 за раз, чтобы сковорода не была переполнена, 3–4 минуты с каждой стороны без вмешательства, пока не станут глубоко золотистыми и хрустящими; внутренняя температура должна достичь 70 °C; в последние 30 секунд добавьте 15 г масла в сковороду и наклоните, чтобы полить шницели — масло пузырится коричневым и придаёт панировке знаменитый аромат польского воскресенья; переложите на решётку с бумажным полотенцем (НЕ на тарелку, которая сделает низ мягким). ПОДАЙТЕ СРАЗУ: положите каждый шницель рядом с горкой картофеля с укропом и горкой квашеной капусты; украсьте долькой лимона, если хотите (выжимка осветлит жир); ешьте ножом и вилкой — никогда только вилкой, это блюдо уважающих классику; шницель нужно съесть в течение 5 минут после жарки для максимальной хрусткости.","en":"POUND THE PORK: place each pork chop between two sheets of cling film and pound with a flat meat mallet from the centre outward, 30 seconds per side, until the chops are 6–7 mm thick and almost doubled in size — they must be even thickness for uniform cooking; score the fatty rim 3–4 times to prevent curling. MILK SOAK: pat the pounded chops dry and rub each side with salt and white pepper; place in a shallow dish, pour over 200 ml milk so the chops are mostly submerged, cover and refrigerate 30 minutes (up to 2 hours) — the lactic acid tenderizes the meat without altering the flavour. SET UP THE BREADING STATION: three shallow plates in a row: plate 1 with 80 g flour; plate 2 with 3 beaten eggs + 1 tbsp milk + a pinch of salt; plate 3 with 200 g fine breadcrumbs; the line-up matters: every chop must travel flour → egg → breadcrumbs without skipping. BREAD THE CHOPS: lift one chop from the milk, let the excess drip off, and dredge in flour, shaking off the excess — the flour must coat thinly and evenly or the egg won't stick; then dip into the egg, letting it drip 2 seconds, then press firmly into the breadcrumbs on both sides, patting them on so they adhere; set on a plate; repeat for all 4 chops; let them rest 5 minutes — the breading hydrates and binds. BOIL THE POTATOES: meanwhile, peel 800 g potatoes and cut into 4 cm chunks; place in cold salted water, bring to boil, and simmer 15–18 minutes until fork-tender; drain, return to the pot off heat for 2 minutes to dry, then toss with 30 g butter and chopped dill. SAUTÉ THE SAUERKRAUT: in a separate pan, melt 1 tbsp lard over medium heat; add 1 finely chopped onion, fry 5 minutes until golden; add 400 g drained sauerkraut and 100 ml water; simmer covered 15 minutes, then uncover and cook 5 minutes more until most of the liquid has evaporated and the kraut is tender; season with a twist of pepper. FRY THE SCHNITZELS: heat 80 g lard (or 100 ml oil) in a large heavy skillet over medium-high heat until shimmering (175 °C, or a breadcrumb sizzles immediately on contact); fry the chops 2 at a time so the pan isn't crowded, 3–4 minutes per side undisturbed until deeply golden brown and crisp; the internal temperature should reach 70 °C; in the last 30 seconds, add 15 g butter to the pan and tilt to baste the schnitzels — the butter foams brown and gives the breading its iconic Polish-Sunday aroma; transfer to a rack lined with paper towels to drain (NOT a plate, which would steam the bottom soggy). SERVE IMMEDIATELY: plate each schnitzel alongside a mound of dill potatoes and a heap of sauerkraut; garnish with a lemon wedge if you like (the squeeze brightens the fat); eat with a knife and fork — never just a fork, this is a respect-the-classics dish; the schnitzel should be eaten within 5 minutes of frying for maximum crunch."}},{"id":156,"origin":{"ru":"Южная Корея","en":"South Korea","ro":"Coreea de Sud"},"name":{"ru":"Кимбап","en":"Kimbap","ro":"Kimbap"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"ru":["360 г (2 стакана) короткозёрного белого риса, сырого — на ~4 ролла","540 мл (2¼ стакана) холодной воды для варки риса","4 листа жареного нори (гим, 20 × 18 см)","4 полоски данмуджи (жёлтой маринованной редьки), нарезанные по длине нори, толщиной ~1 см","100 г молодого шпината (или 1 небольшой пучок обычного шпината)","2 средние моркови (~150 г), нарезанные соломкой 0,5 × 0,5 × 8 см","3 крупных яйца","200 г крабовых палочек (или варёной ветчины, или консервированного тунца с майонезом)","100 г огурца (1 маленький корейский или 1/3 английского), без семян, нарезанного длинными брусками","3 ст. л. жареного кунжутного масла (1,5 ст. л. для риса, 0,5 ч. л. для шпината, остальное для внешней обмазки)","1,5 ч. л. мелкой соли (1 ч. л. для риса, щепотки для овощей и яиц)","2 ч. л. жареного кунжута","1 ст. л. нейтрального масла для жарки яиц и моркови","0,5 ч. л. молотого белого перца","Бамбуковый коврик (гимбаль) + пищевая плёнка"],"en":["360 g (2 cups) short-grain white rice, uncooked — makes ~4 rolls","540 ml (2¼ cups) cold water for cooking the rice","4 sheets toasted nori (gim, 20 × 18 cm)","4 strips danmuji (yellow pickled radish), cut to nori length, ~1 cm thick","100 g baby spinach (or 1 small bunch regular spinach)","2 medium carrots (~150 g), julienned 0.5 × 0.5 × 8 cm matchsticks","3 large eggs","200 g imitation crab sticks (or cooked ham, or tuna mixed with mayo)","100 g cucumber (1 small Korean cucumber or 1/3 English cucumber), seeded and cut into long batons","3 tbsp toasted sesame oil (1.5 tbsp for the rice, 0.5 tsp for spinach, the rest for the outer rub)","1.5 tsp fine salt (1 tsp for the rice, pinches for veg and eggs)","2 tsp toasted sesame seeds","1 tbsp neutral oil for cooking the eggs and carrots","0.5 tsp ground white pepper","Bamboo rolling mat (gimbal) + plastic wrap"],"ro":["360 g (2 căni) orez cu bob scurt necopt, pentru ~4 rulouri","540 ml (2¼ căni) apă rece pentru fierberea orezului","4 foi de nori prăjit (gim, 20 × 18 cm)","4 fâșii de danmuji (ridiche galbenă murată), tăiate la lungimea norii, grosime ~1 cm","100 g spanac baby (sau 1 mănunchi mic de spanac obișnuit)","2 morcovi medii (~150 g), tăiați julien 0,5 × 0,5 × 8 cm","3 ouă mari, bătute","200 g bețe de crab imitație (sau șuncă fiartă sau ton conservat amestecat cu maioneză)","100 g castraveți (1 mic castravete coreean sau 1/3 castravete englezesc), fără sâmburi, tăiat fâșii lungi","3 linguri ulei de susan prăjit (1,5 lingură pentru orez, 0,5 linguriță pentru spanac, restul pentru exterior)","1,5 linguriță sare fină (1 linguriță pentru orez, restul pentru legume)","2 lingurițe semințe de susan prăjite","1 lingură ulei neutru pentru gătit ouăle și sotat morcovii","0,5 linguriță piper alb măcinat","Covoraș de bambus (kimbal) + folie alimentară"]},"howIsMade":{"ru":"РИС: промойте 360 г риса в холодной воде 3–4 раза, пока вода не станет прозрачной, Хорошо слейте, затем положите в тяжёлую кастрюлю с 540 мл свежей холодной воды, Доведите до кипения без крышки на сильном-среднем огне (3–4 минуты), затем накройте, убавьте до минимума и варите 12 минут — не поднимайте крышку, Снимите с огня и дайте постоять под крышкой 10 минут, Рис должен быть нежным, слегка липким, с отдельными зёрнами. ПРИПРАВЛЕНИЕ РИСА: пока он горячий, переложите в широкую миску, Сбрызните 1,5 ст, л, кунжутного масла, 1 ч, л, соли и 2 ч, л, жареного кунжута, Аккуратно сложите рисовой лопаткой режущими движениями — НИКОГДА не перемешивайте резко, зёрна ломаются, Накройте влажной тканью и дайте остыть до тёплого (10–15 минут). ШПИНАТ: доведите небольшую кастрюлю солёной воды до кипения, Бланшируйте 100 г шпината 30 секунд до едва увядшего состояния, Слейте и сразу промойте под холодной водой, чтобы остановить варку и сохранить ярко-зелёный цвет, Сожмите в кулаке как можно сильнее, чтобы удалить всю воду — мокрый шпинат портит ролл, Заправьте 0,5 ч, л, кунжутного масла и щепоткой соли. МОРКОВЬ: нагрейте 1 ч, л, нейтрального масла в маленькой сковороде на среднем огне, Добавьте 150 г моркови соломкой и щепотку соли, обжаривайте 2 минуты, пока она едва не размягчится, но останется хрустящей, Переложите на тарелку остывать — вялая, маслянистая морковь сломает ролл. ЯЙЦА: взбейте 3 яйца с щепоткой соли и 0,5 ч, л, белого перца, Разогрейте 1 ч, л, нейтрального масла в антипригарной сковороде на среднем-малом огне, влейте яйца и наклоните, чтобы образовался тонкий ровный лист 25 × 20 см, Готовьте 2 минуты, пока сверху не схватится, не переворачивайте, Сдвиньте на доску, остудите 2 минуты, затем нарежьте на 4 длинные полоски шириной с нори. НАЧИНКА: нарежьте 100 г огурца вдоль на 8 длинных брусков, удалите семенную сердцевину чайной ложкой, Разрежьте 200 г крабовых палочек пополам вдоль, Нарежьте 4 полоски данмуджи по длине нори, Разложите всё на подносе в порядке выкладки: шпинат → морковь → огурец → краб → яйцо → данмуджи. КАЖДЫЙ КИМБАП: положите бамбуковый коврик планками горизонтально; положите лист нори блестящей стороной вниз, Влажными пальцами распределите ~150 г риса тонким ровным слоем на 3/4 нори, оставив 4 см у дальнего края, В 3 см от ближнего края выложите плотным пучком: шпинат, морковь, огурец, краб, яйцо и данмуджи, Поднимите ближний край коврика и плотно скатывайте вперёд, заправляя начинку под рис при первом обороте, затем продолжайте плотно скатывать до дальнего края, Прижмите шов, чтобы запечатать. РЕЗКА И ПОДАЧА: смажьте внешнюю сторону каждого ролла 0,5 ч, л, кунжутного масла, чтобы нори блестел и не прилипал к ножу, Протирайте острый нож влажной тканью между разрезами, Нарежьте каждый ролл на 8 одинаковых кружков одним решительным движением (без пиления) — всего 32 кусочка, Разложите на тарелке и посыпьте кунжутом, Ешьте в течение 4 часов после скатывания; никогда не охлаждайте кимбап в холодильнике (рис твердеет, нори становится мокрым при разогреве).","en":"Rinse 360 g rice in cold water 3–4 times until the water runs clear, drain well, then put in a heavy pot with 540 ml fresh cold water, bring to a boil uncovered over medium-high heat (3–4 min), cover, reduce to the lowest possible heat and cook 12 minutes without lifting the lid, then remove from heat and rest covered 10 minutes until the rice is tender, slightly sticky, with separate grains. While the rice is still hot, transfer it to a wide bowl, drizzle 1.5 tbsp sesame oil, 1 tsp salt and 2 tsp toasted sesame seeds over the top and fold gently with a rice paddle in cutting motions — never stir aggressively or the grains break and turn mushy — then cover with a damp cloth and let cool to lukewarm (10–15 min). Bring a small pot of salted water to a boil and blanch 100 g spinach for 30 seconds until just wilted, then drain and rinse under cold water immediately to stop the cooking and preserve the bright green colour, squeeze in your fist as hard as possible to remove all water (wet spinach ruins the roll) and season with 0.5 tsp sesame oil and a pinch of salt. Heat 1 tsp neutral oil in a small pan over medium heat, add 150 g julienned carrot and a pinch of salt and stir-fry 2 minutes until just softened but still crisp, then tip onto a plate to cool — limp, oily carrots will break the roll. Beat 3 eggs with a pinch of salt and 0.5 tsp white pepper, heat 1 tsp neutral oil in a non-stick pan over medium-low heat, pour in the eggs and tilt the pan to form a thin even sheet 25 × 20 cm, cook 2 minutes until set on top without flipping, then slide onto a board, let cool 2 minutes and cut into 4 long strips the width of the nori. Cut 100 g cucumber lengthwise into 8 long batons and scrape the seedy core out with a teaspoon, split 200 g crab sticks in half lengthwise and cut 4 strips of danmuji to nori length, then arrange everything on a tray in the order you'll lay them: spinach, carrot, cucumber, crab, egg, danmuji. Place the bamboo mat with the slats running horizontally and lay a sheet of nori shiny-side down, then with wet fingers spread ~150 g rice in a thin even layer over the bottom 3/4 of the nori while leaving a clean 4 cm strip at the far edge, and about 3 cm in from the near edge line up one strip each of spinach, carrot, cucumber, crab, egg and danmuji in a tight bundle, then lift the near edge of the mat and roll firmly forward, tucking the fillings under the rice with the first roll and continuing to roll tightly to the far edge, then press along the seam to seal. Brush the outside of each roll lightly with 0.5 tsp sesame oil to make the nori glossy and prevent it from sticking to the knife, wipe a sharp knife with a damp cloth between cuts, then slice each roll into 8 even rounds with one decisive push (no sawing) for 32 pieces total, arrange on a plate and sprinkle with sesame seeds — eat within 4 hours of rolling and never refrigerate kimbap."},"timeMins":{"total":60,"active":50}},{"id":157,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"ru":"Чили","en":"Chile","ro":"Chile"},"name":{"ru":"Пастель де Чокло","en":"Pastel de Choclo","ro":"Pastel de Choclo"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["Для пино (мясной начинки): 600 г говяжьего фарша (грудинка или огузок, 20% жира)","2 крупные луковицы (~400 г), мелко нарезанные","4 зубчика чеснока, мелко рубленые","2 ст. л. нейтрального масла для пассеровки","1,5 ч. л. соли + 1 ч. л. свежемолотого чёрного перца для пино","1 ч. л. молотой зиры + 1 ч. л. сладкой паприки + 1 ч. л. сушёного орегано + 1 ч. л. ahi color (или копчёная паприка как замена)","60 мл говяжьего бульона или воды","80 г тёмного изюма, замоченного 15 минут в 100 мл тёплой воды и слитого","4 куриных бедра с кожей и костью (~600 г) — отваренные и разобранные (традиционно)","1 лавровый лист + 800 мл воды для варки курицы","6 яиц вкрутую, очищенных и разрезанных пополам (1 на порцию)","18–24 чёрные оливки без косточек (типа каламата)","Для кукурузной пасты (чокло): 1,2 кг свежих зёрен белой кукурузы (~6–8 початков) ИЛИ 1 кг размороженной замороженной кукурузы","80 мл цельного молока","60 г несолёного сливочного масла","1 ст. л. свежих листьев базилика, мелко нарубленных (чилийская подпись)","1 ч. л. мелкой соли + 1 ст. л. сахарного песка для кукурузной пасты","2 ст. л. сахарного песка для посыпки сверху перед выпеканием (культовая карамелизированная корочка)"],"en":["For the pino (meat filling): 600 g ground beef (chuck or sirloin, 20% fat)","2 large onions (~400 g), finely diced","4 garlic cloves, finely minced","2 tbsp neutral oil for sautéing","1.5 tsp salt + 1 tsp freshly ground black pepper for the pino","1 tsp ground cumin + 1 tsp sweet paprika + 1 tsp dried oregano + 1 tsp aji color (or pimentón as substitute)","60 ml beef stock or water","80 g dark raisins, soaked 15 min in 100 ml warm water, then drained","4 bone-in skin-on chicken thighs (~600 g) — poached and pulled (traditional addition)","1 bay leaf + 800 ml water to poach the chicken","6 hard-boiled eggs, peeled and halved (1 per portion)","18–24 pitted black olives (kalamata-style)","For the corn paste (choclo): 1.2 kg fresh white corn kernels (~6–8 ears) OR 1 kg thawed frozen corn","80 ml whole milk","60 g unsalted butter","1 tbsp fresh basil leaves, finely chopped (the Chilean signature)","1 tsp fine salt + 1 tbsp granulated sugar for the corn paste","2 tbsp granulated sugar to sprinkle over the top before baking (for the iconic caramelized crust)"],"ro":["Pentru pino: 600 g vită tocată (gulaș sau pulpă, 20% grăsime)","2 cepe mari (~400 g), tăiate fin","4 căței de usturoi, tocați fin","2 linguri ulei neutru pentru sotat","1,5 lingurițe sare + 1 linguriță piper negru proaspăt măcinat (pentru pino)","1 linguriță chimion măcinat + 1 linguriță boia dulce + 1 linguriță oregano uscat + 1 linguriță aji color (sau pimentón pentru substitut)","60 ml supă de vită sau apă","80 g stafide negre, înmuiate 15 minute în 100 ml apă caldă, apoi scurse","4 pulpe de pui cu os și piele (~600 g) — fierte și destrămate (tradițional)","1 frunză de dafin + 800 ml apă pentru fiertul puiului","6 ouă tari, decojite și tăiate în jumătăți (1 per porție)","18–24 măsline negre cu sâmbure scos (stil kalamata)","Pentru pasta de porumb: 1,2 kg boabe proaspete de porumb alb (~6–8 știuleți) SAU 1 kg porumb congelat dezghețat","80 ml lapte integral","60 g unt nesărat","1 lingură busuioc proaspăt, tocat fin (semnătura chiliană)","1 linguriță sare fină + 1 lingură zahăr granulat pentru pasta de porumb","2 linguri zahăr granulat pentru presărat pe suprafață înainte de coacere (crusta caramelizată iconică)"]},"howIsMade":{"ru":"КАРАМЕЛИЗАЦИЯ ЛУКА: в тяжёлой сковороде на среднем огне разогрейте 2 ст; л; масла и добавьте 400 г мелко нарезанного лука с 0,5 ч; л; соли; пассеруйте 12–15 минут, часто помешивая, до глубоко золотистого и прозрачного состояния — НЕ торопитесь, карамелизованный лук — основа вкуса пино; добавьте 4 зубчика чеснока и готовьте ещё 1 минуту до аромата. ОБЖАРЬТЕ ГОВЯДИНУ: увеличьте огонь до сильного-среднего; добавьте 600 г фарша к луку, разбивая деревянной лопаткой; готовьте 6–8 минут, пока мясо не перестанет быть розовым и жидкость не выпарится; добавьте 1 ч; л; зиры, 1 ч; л; паприки, 1 ч; л; орегано, 1 ч; л; ahi color (если используете), оставшуюся 1 ч; л; соли и 1 ч; л; перца; перемешивайте 1 минуту, чтобы раскрылись специи. ЗАВЕРШИТЕ ПИНО: влейте 60 мл бульона и слитый изюм; варите 3–4 минуты, пока смесь не станет влажной, но не водянистой — пино должно быть глянцевым и держать форму на ложке; снимите с огня и дайте остыть 15 минут — отдых углубляет вкус и предотвращает соскальзывание кукурузной начинки. ОТВАРИТЕ КУРИЦУ: пока пино отдыхает, варите 4 куриных бедра в 800 мл слегка подсолённой воды с 1 лавровым листом 25 минут до готовности; слейте, слегка остудите и оторвите мясо от костей большими кусками (кожу выбросьте); сохраните бульон для подачи к пастелю. КУКУРУЗНАЯ ПАСТА: в комбайне или блендере импульсами измельчите 1,2 кг кукурузных зёрен с 80 мл молока и 1 ч; л; соли 30 секунд до грубого пюре — сохраните текстуру, не взбивайте до гладкого крема; переложите в тяжёлую кастрюлю с 60 г масла на среднем огне; готовьте 10–15 минут, постоянно помешивая деревянной ложкой, пока пюре не загустеет до консистенции поленты, отстающей от стенок; вмешайте 1 ст; л; рубленного базилика и снимите с огня. СБОРКА: разогрейте духовку до 200 °C с решёткой в верхней трети; распределите пино между 6 индивидуальными глиняными paila (или одной формой 28 см); поверх каждой порции положите куски отваренной курицы, 1 половинку яйца, 3–4 оливки и небольшую горку изюма декоративно; распределите тёплую кукурузную пасту сверху ровным слоем 2 см, разглаживая обратной стороной ложки, чтобы запечатать до краёв. САХАРНАЯ КОРОЧКА: равномерно посыпьте 2 ст; л; сахарного песка по кукурузной пасте; этот шаг неоспорим — сахар карамелизуется во время выпекания в культовую тёмную почти-обугленную золотистую корочку, которая отличает пастель де чокло от любого другого пирога пастуха. ВЫПЕЧКА: поместите пастели на верхнюю решётку духовки при 200 °C и выпекайте 25–30 минут, пока кукурузная паста не станет золотисто-коричневой, а сахар не карамелизуется в тёмные пятна на поверхности; уголки могут пузыриться — это правильно; дайте отдохнуть 10 минут перед подачей (начинка должна схватиться); подавайте прямо из paila с соусом pebre сбоку и бокалом чилийского Carmenère.","en":"CARAMELIZE THE ONIONS: in a heavy skillet over medium heat, warm 2 tbsp oil and add 400 g finely diced onion with 0.5 tsp salt; sauté 12–15 minutes, stirring often, until deeply golden and translucent — DO NOT rush this step, the caramelized onion is the foundation of pino flavour; add 4 minced garlic cloves and cook 1 minute more until fragrant. BROWN THE BEEF: raise the heat to medium-high; add 600 g ground beef to the onions, breaking it apart with a wooden spoon; cook 6–8 minutes until the meat is no longer pink and any liquid has evaporated; add 1 tsp cumin, 1 tsp paprika, 1 tsp oregano, 1 tsp aji color (if using), the remaining 1 tsp salt and 1 tsp pepper; stir 1 minute to bloom the spices. FINISH THE PINO: pour in 60 ml beef stock and the drained raisins; simmer 3–4 minutes until the mixture is moist but not soupy — the pino should be glossy and able to hold its shape on a spoon; remove from heat and let cool 15 minutes — letting it rest deepens the flavour and prevents the corn topping from sliding off. POACH THE CHICKEN: while the pino rests, simmer 4 chicken thighs in 800 ml lightly salted water with 1 bay leaf for 25 minutes until cooked through; drain, cool slightly, then pull the meat from the bones in large chunks (skin discarded); reserve the stock for serving alongside the pastel. CORN PASTE: in a food processor or blender, pulse 1.2 kg fresh corn kernels with 80 ml milk and 1 tsp salt 30 seconds until coarsely pureed — keep some texture, do not blend to a smooth cream; transfer to a heavy saucepan with 60 g butter over medium heat; cook 10–15 minutes, stirring constantly with a wooden spoon, until the puree thickens to a polenta-like consistency that pulls away from the sides of the pan; stir in 1 tbsp chopped basil and remove from heat. ASSEMBLE: preheat oven to 200 °C with a rack in the upper third; divide the pino between 6 individual earthenware pailas (or one 28 cm baking dish); top each portion with chunks of poached chicken, 1 hard-boiled egg half, 3–4 olives, and a small pile of raisins arranged decoratively; spoon the warm corn paste over the top in an even 2 cm layer, smoothing with the back of a spoon to seal all the way to the edges. SUGAR CRUST: sprinkle 2 tbsp granulated sugar evenly over the corn topping; this is non-negotiable — the sugar caramelizes during baking into the iconic dark, almost-burnt golden crust that distinguishes pastel de choclo from any other shepherd's pie. BAKE: place the pastels on the upper rack of the 200 °C oven and bake 25–30 minutes until the corn topping is golden brown and the sugar has caramelized into dark spots across the surface; the corners may bubble — that's correct; let rest 10 minutes before serving (the filling needs to set); serve straight from the paila with a side of pebre salsa and a glass of Chilean Carmenère."}},{"id":158,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Сербия","en":"Serbia","ro":"Serbia"},"name":{"ru":"Плескавица","en":"Pljeskavica","ro":"Pljeskavica"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500 г говяжьей рульки, грубо рубленой (~20% жира)","300 г грубо рубленой бараньей лопатки (или свиной для более мягкого варианта)","1 крупная луковица (~200 г), мелко натёртая и хорошо отжатая (секрет сочности котлет)","4 зубчика чеснока, размятых с 0,5 ч. л. соли в пасту","1 ст. л. сладкой венгерской паприки","1 ч. л. острой паприки (копчёной или кашмирской, по желанию)","1,5 ч. л. мелкой соли","1 ч. л. свежемолотого чёрного перца","1 ч. л. пищевой соды (балканский приём — сохраняет котлеты сочными и нежными)","100 мл ледяной газированной минеральной воды (для воздушной упругой текстуры)","0,5 ч. л. сушёного майорана или орегано","1 ст. л. растительного масла для гриля или сковороды","Для подачи: 4 лепёшки сомун или питы (~18 см), 1 средняя красная луковица (~150 г) тонко нарезанная, 200 г айвара, 100 г каймака или сметаны, свежая петрушка, дольки лимона (по желанию)"],"en":["500 g coarsely ground beef chuck (~20% fat)","300 g coarsely ground lamb shoulder (or pork shoulder for a milder version)","1 large onion (~200 g), finely grated and water squeezed out (the secret to juicy patties)","4 garlic cloves, crushed with 0.5 tsp salt into a paste","1 tbsp sweet Hungarian paprika","1 tsp hot paprika (smoked or Kashmiri, optional)","1.5 tsp fine salt","1 tsp freshly ground black pepper","1 tsp baking soda (the Balkan trick — helps keep them juicy and tender)","100 ml ice-cold sparkling water (for the fluffy springy texture)","0.5 tsp dried marjoram or oregano","1 tbsp vegetable oil for the grill or pan","To serve: 4 somun or pita breads (~18 cm rounds), 1 medium red onion (~150 g) thinly sliced, 200 g ajvar red-pepper relish, 100 g kajmak or sour cream, fresh parsley, lemon wedges (optional)"],"ro":["500 g vită tocată grosier (ceafă, ~20% grăsime)","300 g umăr de miel tocat grosier (sau umăr de porc pentru o versiune mai blândă)","1 ceapă mare (~200 g), rasă fin și stoarsă bine (secretul cărnurilor suculente)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă","1 lingură boia ungurească dulce","1 linguriță boia iute (afumată sau Kashmir, opțional)","1,5 lingurițe sare fină","1 linguriță piper negru proaspăt măcinat","1 linguriță bicarbonat de sodiu (trucul balcanic — păstrează carnea suculentă și frageda)","100 ml apă minerală carbogazoasă rece ca gheața (pentru textura pufoasă)","0,5 linguriță maghiran uscat sau oregano","1 lingură ulei vegetal pentru grătar sau tigaie","Pentru servire: 4 chifle somun sau pita (~18 cm), 1 ceapă roșie medie (~150 g) tăiată subțire, 200 g ajvar, 100 g kajmak sau smântână, pătrunjel proaspăt, lămâie (opțional)"]},"howIsMade":{"ru":"ЛУК: натрите 200 г лука на мелкой стороне тёрки; переложите в чистое полотенце и СИЛЬНО отожмите над раковиной, чтобы удалить как можно больше жидкости — должно выйти не менее 80 мл сока; мокрый лук делает котлеты разваливающимися на гриле; сохраните 2 ст; л; отжатой мякоти для мяса. ФАРШ: в большой миске соедините 500 г говядины + 300 г баранины (или свинины); добавьте 2 ст; л; отжатой луковой мякоти, 4 зубчика чеснока, размятых с 0,5 ч; л; соли, 1 ст; л; сладкой паприки, 1 ч; л; острой паприки (если используете), 1 ч; л; соли, 1 ч; л; перца, 0,5 ч; л; майорана и 1 ч; л; соды; энергично месите руками 4–5 минут — смесь должна стать липкой и заметно подтянутой, что придаёт плескавице её фирменную пружинистость. ГАЗИРОВАННАЯ ВОДА: медленно вливайте 100 мл ледяной газированной воды, продолжая месить, в 4 порции по 25 мл каждая; вода аэрирует фарш и в сочетании с содой делает котлеты сочными и нежными; накройте плёнкой и охладите минимум 4 часа, идеально на ночь — отдых не обсуждается для развития вкуса и связывания. ФОРМОВКА: разделите отдохнувшее мясо на 4 равные порции по ~225 г каждая; мокрыми руками (чтобы не прилипало) скатайте каждую порцию в шар, затем сплющите в плоский диск диаметром 18–20 см и толщиной 8 мм; диск должен совпадать в диаметре с хлебом, в котором будет подаваться; слегка нажмите большим пальцем в центре, чтобы создать углубление — это предотвратит купольное выпучивание на гриле. ВТОРОЕ ОХЛАЖДЕНИЕ: разместите сформированные котлеты на противне, выстеленном пергаментом; накройте неплотно и охладите 20 минут для уплотнения; тем временем разогрейте угольный гриль до средне-сильного огня (200 °C) или нагрейте тяжёлую сковороду-гриль с 1 ст; л; масла до лёгкого дымка. ГРИЛЬ: смажьте котлеты тонко маслом; жарьте 4–5 минут с каждой стороны, не двигая — переворачивайте ТОЛЬКО ОДИН РАЗ; котлеты готовы, когда внутренняя температура достигает 65 °C (medium) и на обеих сторонах образовалась глубокая корка цвета красного дерева с видимыми отметинами решётки; не давите на них — потеряете весь сок и сведёте на нет работу шага 3. ХЛЕБ: за последнюю минуту жарки положите 4 сомун или пита на гриль на 30 секунд с каждой стороны до подогрева и лёгкого подрумянивания; разрежьте каждую пита по одному краю, чтобы сделать карман достаточно большой для котлеты. ПОДАЧА: вложите по одной котлете в каждый тёплый кармашек пита; сверху — 1 ст; л; айвара, кусочек каймака, щедрая горка нарезанного сырого красного лука, посыпка петрушки и выжим лимона по желанию; ешьте сразу руками, пока хлеб тёплый — контраст горячего сочного мяса, прохладного каймака и копчёного айвара — душа балканского стрит-фуда.","en":"ONION PREP: grate 200 g onion on the fine side of a box grater; transfer to a clean tea towel and squeeze HARD over the sink to remove as much liquid as possible — at least 80 ml of juice should come out; wet onion makes the patties fall apart on the grill; reserve 2 tbsp of the squeezed pulp for the meat. MIX THE MEAT: in a large bowl, combine 500 g beef + 300 g lamb (or pork); add 2 tbsp squeezed onion pulp, 4 garlic cloves crushed with 0.5 tsp salt, 1 tbsp sweet paprika, 1 tsp hot paprika (if using), 1 tsp salt, 1 tsp pepper, 0.5 tsp marjoram and 1 tsp baking soda; knead vigorously by hand 4–5 minutes — the mixture should become sticky and noticeably tightened, which gives pljeskavica its signature springy bounce. ADD SPARKLING WATER: slowly drizzle in 100 ml ice-cold sparkling water while continuing to knead, in 4 additions of 25 ml each; the water aerates the mince and combines with the baking soda to keep the patties juicy and tender; cover with film and refrigerate at least 4 hours, ideally overnight — the rest is non-negotiable for flavour development and binding. SHAPE THE PATTIES: divide the rested meat into 4 equal portions of ~225 g each; with wet hands (to prevent sticking), roll each portion into a ball, then flatten into a flat disc 18–20 cm in diameter and 8 mm thick; the disc must be the same diameter as the bread it will be served in; press the centre slightly with your thumb to create a dimple — this prevents the patty from doming up on the grill. SECOND CHILL: place the shaped patties on a parchment-lined tray; cover loosely and refrigerate 20 minutes to firm up; meanwhile, fire up a charcoal grill to medium-high (200 °C) or heat a heavy ridged griddle pan with 1 tbsp oil until just smoking. GRILL: brush the patties lightly with oil; grill 4–5 minutes per side without moving — turn ONCE only; the patties are done when the internal temperature reaches 65 °C (medium) and a deep mahogany crust has formed on both sides with visible grill marks; resist pressing them — you'll lose all the juice and undo the work you did in step 3. WARM THE BREAD: during the last minute of grilling, place 4 somun or pita on the grill for 30 seconds per side until warmed and lightly toasted; split each pita open at one edge to make a pocket large enough for the patty. SERVE: slip one patty into each warm pita pocket; top with 1 tbsp ajvar, a knob of kajmak, a generous mound of sliced raw red onion, a sprinkle of parsley, and a squeeze of lemon if you like; eat immediately with your hands while the bread is warm — the contrast of hot juicy meat, cool kajmak, and smoky ajvar is the soul of Balkan street food."}},{"id":159,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"ru":"Нидерланды","en":"Netherlands","ro":"Olanda"},"name":{"ru":"Поффертьес","en":"Poffertjes","ro":"Poffertjes"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["250 г гречневой муки (традиционно, даёт фирменный вкус) — ИЛИ 100 г гречневой + 150 г пшеничной муки как более мягкая замена","7 г сухих быстрых дрожжей (или 21 г свежих)","1 ст. л. сахарного песка (1 ч. л. для активации дрожжей, остальное в тесто)","0,5 ч. л. мелкой соли","350 мл тёплого цельного молока (38 °C)","2 крупных яйца","30 г несолёного сливочного масла, растопленного и остывшего до тёплого, для теста","50 г дополнительного несолёного сливочного масла для сковороды и подачи","1 ст. л. тёмного рома или ванильного экстракта (по желанию, традиционно)","Для подачи: 30 г холодных кубиков несолёного сливочного масла для подачи, 60 г сахарной пудры для посыпки, сироп stroopwafel или кленовый (по желанию), свежие ягоды (по желанию)","Оборудование: чугунная сковорода poffertjespan с 24–30 углублениями (или aebleskiver); деревянная шпажка для переворачивания"],"en":["250 g buckwheat flour (traditional, gives the signature flavour) — OR 100 g buckwheat + 150 g all-purpose flour as a milder substitute","7 g instant dry yeast (or 21 g fresh yeast)","1 tbsp granulated sugar (1 tsp to feed the yeast, the rest in the batter)","0.5 tsp fine salt","350 ml warm whole milk (38 °C)","2 large eggs","30 g unsalted butter, melted and cooled to lukewarm for the batter","50 g additional unsalted butter for the pan + finishing","1 tbsp dark rum or vanilla extract (optional, traditional)","To serve: 30 g cold unsalted butter cubes for topping, 60 g icing sugar to dust, stroopwafel syrup or maple syrup (optional), fresh berries (optional)","Equipment: poffertjespan cast-iron pan with 24–30 dimples (or aebleskiver pan); small wooden skewer or chopstick for flipping"],"ro":["250 g făină de hrișcă (tradițional, dă aroma signature) — SAU 100 g hrișcă + 150 g făină albă ca substitut mai blând","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 lingură zahăr (1 linguriță pentru drojdie, restul în aluat)","0,5 linguriță sare fină","350 ml lapte integral cald (38 °C)","2 ouă mari","30 g unt nesărat topit și răcit la călduț pentru aluat","50 g unt nesărat suplimentar pentru tigaie și finisare","1 lingură rom întunecat sau extract de vanilie (opțional, tradițional)","Pentru servire: 30 g unt rece în cuburi pentru a pune deasupra, 60 g zahăr pudră pentru presărat, sirop stroopwafel sau de arțar (opțional), fructe de pădure proaspete (opțional)","Echipament: tigaie poffertjespan din fontă cu 24–30 adâncituri (sau tigaie aebleskiver); bețișoară de lemn pentru întors"]},"howIsMade":{"ru":"АКТИВАЦИЯ ДРОЖЖЕЙ: разогрейте 350 мл молока в кастрюле до ~38 °C (тёплое — комфортно на запястье); перелейте в большую миску, посыпьте сверху 7 г сухих быстрых дрожжей и 1 ч; л; сахара, дайте постоять 10 минут, пока сверху не появится кремовая пена; если пены нет — дрожжи мертвы, начните заново со свежими. ТЕСТО: вбейте 2 яйца в молоко с пеной и взбейте до гладкости; в отдельной миске просейте 250 г гречневой муки (или гречневой+пшеничной смеси), оставшиеся 2 ч; л; сахара и 0,5 ч; л; соли; добавьте сухое к жидкому в 2 этапа, каждый раз взбивая до гладкости — без комков; вмешайте 30 г растопленного остывшего масла и 1 ст; л; рома (по желанию); тесто должно иметь консистенцию жидких сливок, стекающих лентой с венчика. ПЕРВАЯ РАССТОЙКА: накройте миску чистым полотенцем и оставьте подходить в тёплом месте 60 минут, пока поверхность не покроется пузырьками, а тесто заметно не поднимется (~1,5× объёма); дрожжи развивают фирменный воздушный, чуть кисловатый вкус настоящих поффертьес. ВЫМЕСИТЕ И ОТДОХНИТЕ: аккуратно перемешайте подошедшее тесто, чтобы выпустить крупные пузыри; переложите в бутылку с дозатором, кувшин или кондитерский мешок — самый удобный способ дозированно наполнить маленькие лунки; оставьте отдыхать 10 минут, пока греется сковорода. РАЗОГРЕЙТЕ POFFERTJESPAN: поставьте чугунную poffertjespan с 24 или 30 лунками на средне-малый огонь на 3 минуты до равномерного нагрева (проверка: капля воды должна шипеть и испаряться за 2 секунды); сложенным бумажным полотенцем, смоченным в растопленном масле, обильно смажьте каждую лунку — каждая должна быть покрыта, иначе поффертьес прилипнут. НАПОЛНИТЕ ЛУНКИ: быстро наполняйте тестом каждую лунку до 3/4 (примерно 1 ст; л.); подождите 60–90 секунд, пока края не схватятся и вокруг каждой не образуется золотистый ободок, на поверхности появятся пузыри. ПЕРЕВЕРНИТЕ КАЖДЫЙ: деревянной шпажкой подцепите каждый полуготовый поффертье по краю лунки и переверните — сырое верхнее тесто стечёт в лунку, образуя круглый шарик; готовьте ещё 60–90 секунд, пока вторая сторона не станет тёмно-золотистой; каждый поффертье должен быть пышным круглым шариком, золотистым с обеих сторон, примерно 3 см в ширину. ПОДАВАЙТЕ СРАЗУ: переложите 8–10 поффертьес на каждую тёплую тарелку; положите сверху маленький кубик холодного масла (он растает и впитается) и щедро посыпьте сахарной пудрой через мелкое сито; подавайте сразу — поффертьес становятся резиновыми через 5 минут; по желанию: полейте сиропом stroopwafel или посыпьте свежими ягодами.","en":"ACTIVATE THE YEAST: warm 350 ml milk in a saucepan to about 38 °C (lukewarm — comfortable on your wrist); pour into a large bowl, sprinkle 7 g instant dry yeast and 1 tsp sugar over the surface, and let stand 10 minutes until a creamy foam appears on top; if no foam, the yeast is dead — start over with fresh yeast. MAKE THE BATTER: whisk 2 eggs into the foamed yeast-milk until smooth; in a separate bowl, sift together 250 g buckwheat flour (or the buckwheat+all-purpose mix), the remaining 2 tsp sugar and 0.5 tsp salt; add the dry to the wet in two additions, whisking each time until smooth — no lumps; whisk in 30 g melted cooled butter and 1 tbsp rum (if using); the batter should be the consistency of thin cream that ribbons off the whisk. FIRST PROOF: cover the bowl with a clean cloth and let rise in a warm spot for 60 minutes, until the surface is covered with bubbles and the batter has risen noticeably (about 1.5× volume); the yeast develops the signature airy, slightly sour flavour of true poffertjes. STIR DOWN AND REST: gently stir the risen batter to deflate large bubbles; transfer to a squeeze bottle, jug or piping bag — the easiest way to portion accurately into the small dimples; let rest 10 minutes while the pan heats. HEAT THE POFFERTJESPAN: place a 24- or 30-dimple cast-iron poffertjespan over medium-low heat for 3 minutes until evenly hot (test with a drop of water — it should sizzle and evaporate in 2 seconds); use a folded paper towel dipped in melted butter to grease each dimple generously — every dimple must be coated or the poffertjes will stick. FILL THE DIMPLES: working fast, squeeze or pour batter into each dimple until 3/4 full (about 1 tbsp per dimple); wait 60–90 seconds until the edges are set and a golden ring forms around each one, with bubbles forming on the surface. FLIP EACH ONE: using a wooden skewer, pull each half-set poffertje up the side of its dimple and flip it upside down — the uncooked top batter will flow into the dimple, filling out a round ball; cook another 60–90 seconds until the second side is deep golden brown; each poffertje should be a fluffy round ball, golden on both sides, about 3 cm wide. SERVE IMMEDIATELY: slide 8–10 poffertjes onto each warm plate; top with a small knob of cold butter (it will melt and soak in) and a generous dust of icing sugar through a fine sieve; serve immediately — poffertjes turn rubbery within 5 minutes of being made; optional: drizzle stroopwafel syrup or scatter fresh berries."}},{"id":160,"origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Японское карри","en":"Japanese Curry Rice","ro":"Curry japonez"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"ru":["2 стакана круглого риса (сухого)","400г куриных бёдер без кости и кожи (или говяжьей лопатки), нарезанных кусками по 3 см","2 большие луковицы, средним кубиком","2 средние картофелины, кубики 3 см","2 средние моркови, кружки 1,5 см","1 ст.л. растительного масла","800мл воды","1 упаковка блоков японского карри-ру (напр. S&B Golden Curry средней остроты, ок. 100г)","1 ч.л. соуса Вустершир","1 ч.л. кетчупа (по желанию, для глубины)","соль и чёрный перец по вкусу"],"en":["2 cups short-grain rice (uncooked)","400g boneless skinless chicken thighs (or beef chuck), cut into 3 cm pieces","2 large onions, cut into medium dice","2 medium potatoes, cut into 3 cm cubes","2 medium carrots, cut into 1.5 cm rounds","1 tbsp vegetable oil","800ml water","1 pack Japanese curry roux blocks (e.g. S&B Golden Curry, medium, approx. 100g)","1 tsp Worcestershire sauce","1 tsp ketchup (optional, for depth)","salt and black pepper to taste"],"ro":["2 căni orez cu bob scurt (nepreparare)","400g pulpe de pui dezosate fără piele (sau vită pentru friptură), tăiate cuburi de 3 cm","2 cepe mari, tăiate cuburi medii","2 cartofi medii, tăiați cuburi de 3 cm","2 morcovi medii, tăiați rondele de 1,5 cm","1 lingură ulei vegetal","800ml apă","1 pachet blocuri de roux curry japonez (ex. S&B Golden Curry, mediu picant, aprox. 100g)","1 linguriță sos Worcestershire","1 linguriță ketchup (opțional, pentru rotunjimea gustului)","sare și piper negru după gust"]},"howIsMade":{"ru":"РИС: промойте 360 г (2 стакана) короткозёрного риса в холодной воде 3–4 раза, пока вода не станет прозрачной; положите в кастрюлю с 540 мл (2½ стакана) холодной воды; доведите до кипения без крышки, накройте, убавьте до минимального огня и варите 13 минут; снимите с огня и дайте постоять под крышкой 10 минут; не поднимайте крышку. КАРАМЕЛИЗАЦИЯ ЛУКА: в большой кастрюле разогрейте 1 ст; л; масла на среднем огне; добавьте 2 средне нарезанных луковицы и обжаривайте, часто помешивая, 15–20 минут до мягкости и золотистого цвета — НЕ пропускайте этот шаг; карамелизованный лук — основа вкуса. ОБЖАРЬТЕ МЯСО: добавьте 400 г куриных бёдер или говяжьей лопатки, нарезанных кусками 3 см, приправьте солью и перцем, обжарьте со всех сторон 3–4 минуты; мясо должно иметь глубокую золотистую корочку — дополнительный вкус. ОВОЩИ: добавьте 2 моркови кружками 1,5 см и 2 картофелины кубиками 3 см; перемешайте 1 минуту, чтобы покрыть овощи маслом. ВАРИТЕ ОСНОВУ: влейте 800 мл воды, доведите до кипения, убавьте до слабого огня и варите без крышки 15 минут, или пока картофель не станет почти мягким (проверьте шпажкой). ДОБАВЬТЕ РУ: снимите кастрюлю с огня; разломайте 100 г блоков японского карри-ру на мелкие кусочки и размешайте до полного растворения — добавление вне огня предотвращает комочки. ЗАГУСТИТЕ СОУС: верните кастрюлю на слабый огонь и варите, часто помешивая, 10 минут, пока соус не станет густым и блестящим — он должен покрывать обратную сторону ложки; добавьте 1 ч; л; соуса Вустершир и 1 ч; л; кетчупа для глубины, попробуйте и отрегулируйте соль. ПОДАЧА: щедрую порцию карри на горячий рис в глубоких тарелках; традиционные сопровождения: котлета катсу, нашинкованная капуста, маринованная красная редька (фукудзинзуке); на одной тарелке и рис, и карри без смешивания — соединяют ложкой за столом.","en":"THE RICE: rinse 360 g (2 cups) short-grain rice in cold water 3–4 times until the water runs clear; place in a pot with 540 ml (2½ cups) cold water; bring to a boil uncovered, cover, reduce to lowest heat and cook 13 minutes; remove from heat and rest covered 10 minutes; do not lift the lid. CARAMELIZE THE ONIONS: in a large pot, heat 1 tbsp oil over medium heat; add 2 medium-diced onions and cook, stirring often, for 15–20 minutes until soft and golden — DO NOT skip this step; the caramelized onions are the backbone of flavour. BROWN THE MEAT: add 400 g boneless chicken thighs or beef chuck cut in 3 cm pieces, season with salt and pepper, sear on all sides 3–4 minutes; the meat must have a deep golden crust — extra flavour. VEGETABLES: add 2 carrots cut in 1.5 cm rounds and 2 potatoes cut in 3 cm cubes; stir 1 minute to coat the vegetables in the oil. SIMMER THE BASE: pour in 800 ml water, bring to a boil, reduce to a gentle simmer uncovered for 15 minutes, or until the potato is just tender (check with a skewer). ADD THE ROUX: remove the pot from the heat; break 100 g Japanese curry roux blocks into small pieces and stir into the pot until fully dissolved — adding off heat prevents lumps. THICKEN THE SAUCE: return the pot to low heat and simmer, stirring frequently, for 10 minutes until the sauce is thick and glossy — it should coat the back of a spoon; stir in 1 tsp Worcestershire sauce and 1 tsp ketchup for depth, taste and adjust salt. SERVE: spoon a generous portion of curry over hot rice in deep plates; traditional accompaniments: katsu schnitzel, shredded cabbage, pickled red radishes (fukujinzuke); a single plate holds both rice and curry without mixing them — you spoon them together at the table."}},{"id":161,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Фасолада","en":"Fasolada","ro":"Fasolada"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["400 г сухой белой фасоли (каннеллини, navy или крупных греческих gigantes), замоченной на ночь в холодной воде","2 средние моркови (~200 г), очищенные и нарезанные кубиками 1 см","2 стебля сельдерея (~150 г), нарезанных кубиками 1 см + 30 г рубленых листьев сельдерея (по желанию, традиционно)","1 крупная луковица (~200 г), мелко нарезанная","4 зубчика чеснока, мелко нарубленных","400 г спелых помидоров (4 средних) — очищенных и натёртых ИЛИ 1 банка × 400 г измельчённых помидоров","1 ст. л. томатной пасты","100 мл оливкового масла extra virgin для сотированной базы + 60 мл дополнительно для завершения","2 лавровых листа","1 ч. л. сушёного орегано","1,5 ч. л. соли + соль по вкусу","0,5 ч. л. свежемолотого чёрного перца","1 ст. л. красного винного уксуса (по желанию, осветляет в конце)","1,5 л воды (или овощного бульона)","Для подачи: хрустящий деревенский хлеб, оливки каламата, раскрошенный сыр фета, свежая петрушка"],"en":["400 g dried white beans (cannellini, navy, or large Greek gigantes), soaked overnight in cold water","2 medium carrots (~200 g), peeled and diced 1 cm","2 celery stalks (~150 g), diced 1 cm + 30 g celery leaves chopped (optional, traditional)","1 large onion (~200 g), finely diced","4 garlic cloves, finely minced","400 g ripe tomatoes (4 medium) — peeled and grated OR 1 × 400 g can crushed tomatoes","1 tbsp tomato paste","100 ml extra-virgin olive oil for the soffritto + 60 ml more for finishing","2 bay leaves","1 tsp dried oregano","1.5 tsp salt + more to taste","0.5 tsp freshly ground black pepper","1 tbsp red wine vinegar (optional, brightens at the end)","1.5 L water (or vegetable stock)","To serve: crusty country bread, Kalamata olives, crumbled feta cheese, fresh parsley"],"ro":["400 g fasole albă uscată (cannellini, navy sau gigantes grecești), înmuiate peste noapte în apă rece","2 morcovi medii (~200 g), curățați și tăiați cuburi de 1 cm","2 tulpini de țelină (~150 g), tăiate cuburi de 1 cm + 30 g frunze de țelină tocate (opțional, tradițional)","1 ceapă mare (~200 g), tăiată fin","4 căței de usturoi, tocați fin","400 g roșii coapte (4 medii) — decojite și rase SAU 1 conservă × 400 g de roșii zdrobite","1 lingură pastă de roșii","100 ml ulei de măsline extravirgin pentru sotat + 60 ml suplimentar pentru finisare","2 frunze de dafin","1 linguriță oregano uscat","1,5 lingurițe sare + sare după gust","0,5 linguriță piper negru proaspăt măcinat","1 lingură oțet de vin roșu (opțional, dă luminozitate la final)","1,5 L apă (sau supă de legume)","Pentru servire: pâine de țară crocantă, măsline Kalamata, brânză feta sfărâmată, pătrunjel proaspăt"]},"howIsMade":{"ru":"ЗАМОЧИТЕ ФАСОЛЬ: положите 400 г сухой белой фасоли в большую миску, залейте холодной водой так, чтобы покрыть на 5 см, и замочите 8 часов или на ночь; слейте и промойте — замачивание сокращает время варки и помогает равномерно сварить целые фасолины. ПРЕДВАРИТЕЛЬНОЕ ОТВАРИВАНИЕ: положите слитую фасоль в большую кастрюлю, залейте холодной водой на 3 см выше и доведите до кипения; варите сильно 10 минут, затем слейте — этот шаг удаляет неперевариваемые соединения, вызывающие газы, и даёт более чистый бульон. СОФРИТТО: в тяжёлой кастрюле 5 л разогрейте 100 мл оливкового масла на среднем огне; добавьте 200 г нарезанного лука + 200 г моркови + 150 г сельдерея и обжаривайте, часто помешивая, 12–15 минут до очень мягкости и начала золотистости — эта медленная овощная база — основа глубины фасолады; добавьте 4 рубленых зубчика чеснока и готовьте ещё 1 минуту до аромата. РАСКРОЙТЕ ТОМАТ: добавьте 1 ст; л; томатной пасты и варите помешивая 2 минуты, пока не потемнеет; добавьте 400 г тёртых помидоров (или из банки) и тушите 5 минут, пока сырая кислотность не выпарится и смесь не станет насыщенно-красной. ДОБАВЬТЕ ФАСОЛЬ И ВОДУ: верните предварительно отваренную фасоль в кастрюлю; добавьте 1,5 л воды (или овощного бульона), 2 лавровых листа, 1 ч; л; орегано, 1,5 ч; л; соли и 0,5 ч; л; перца; доведите до кипения, убавьте до слабого огня. МЕДЛЕННО ВАРИТЕ: варите без крышки 60–90 минут, периодически помешивая, пока фасоль не станет полностью мягкой и кремовой в центре, но не сохранит форму — пробуйте фасолину каждые 15 минут после 1 часа варки; бульон должен уменьшиться примерно вдвое и загустеть до консистенции супа; доливайте воду, если сильно высыхает. ЗАВЕРШЕНИЕ: удалите лавровые листья; вмешайте 30 г рубленых листьев сельдерея (если используете) и 1 ст; л; красного винного уксуса для яркости; попробуйте и отрегулируйте соль; сняв с огня, полейте 60 мл свежего оливкового масла extra virgin поверхность — это финальное масло, делающее суп блестящим и ароматным; дайте постоять 10 минут. ПОДАЧА: разлейте в глубокие миски, полейте каждую порцию ещё 1 ч; л; оливкового масла и сверху сдобрите свежемолотым чёрным перцем; подавайте с хрустящим деревенским хлебом, маленькой пиалой оливок каламата, раскрошенным фета и нарубленной свежей петрушкой на столе; ещё лучше на следующий день.","en":"SOAK THE BEANS: place 400 g dried white beans in a large bowl, cover with cold water by 5 cm, and soak 8 hours or overnight; drain and rinse — the soak shortens the cooking time and helps even, intact beans. PARBOIL THE BEANS: place the drained beans in a large pot, cover with cold water by 3 cm, and bring to a boil; boil hard 10 minutes, then drain — this removes the indigestible compounds that cause gas and gives a cleaner-tasting broth. SOFFRITTO: in a heavy 5 L pot, heat 100 ml olive oil over medium heat; add 200 g diced onion + 200 g diced carrot + 150 g diced celery and cook, stirring often, 12–15 minutes until very soft and starting to gold — this slow vegetable base is the foundation of fasolada's depth; add 4 minced garlic cloves and cook 1 more minute until fragrant. BLOOM THE TOMATO: add 1 tbsp tomato paste and cook stirring 2 minutes until darkened; add 400 g grated tomato (or canned crushed) and simmer 5 minutes until the raw acidity cooks off and the mixture turns deep red. ADD BEANS AND WATER: return the parboiled beans to the pot; add 1.5 L water (or vegetable stock), 2 bay leaves, 1 tsp oregano, 1.5 tsp salt and 0.5 tsp pepper; bring to a boil, reduce to a gentle simmer. SLOW SIMMER: cook uncovered 60–90 minutes, stirring occasionally, until the beans are completely tender and creamy at the centre but still hold their shape — taste a bean every 15 minutes after the 1 hour mark; the broth should reduce by about half and thicken to a soupy consistency; add more water if it dries out too fast. FINISH: discard the bay leaves; stir in 30 g chopped celery leaves (if using) and 1 tbsp red wine vinegar for brightness; taste and adjust salt; off the heat, drizzle 60 ml fresh extra-virgin olive oil over the surface — this is the finishing oil that makes the soup glossy and aromatic; let rest 10 minutes for flavours to settle. SERVE: ladle into deep bowls, drizzle each portion with another teaspoon of olive oil, and grind fresh black pepper over the top; serve with crusty country bread, a small bowl of Kalamata olives, crumbled feta, and chopped fresh parsley on the table; even better the next day."}},{"id":162,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Тлайудас","en":"Tlayudas","ro":"Tlayudas"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["4 тортильи тлайюда (~30 см, полусушёные) или 4 большие пшеничные тортильи как замена","250 г сухой чёрной фасоли, замоченной на ночь (или 1 банка × 400 г)","100 г смальца или 100 мл растительного масла для жарки фасоли + готовки","1 крупная луковица (~200 г): половина четвертинками для фасоли, другая половина мелко нарезанная для подачи","4 зубчика чеснока (2 для фасоли, 2 для мяса)","1 ч. л. молотой зиры + 1 ч. л. сушёного орегано + 1 ч. л. соли для фасоли","500 г пашины или диафрагмы, нарезанной очень тонко против волокон (в стиле тасахо)","200 г свежего мексиканского чоризо (или испанского), вынутого из оболочки","300 г кесильо (сыр Оахака) или моцарелла low-moisture, тёртые","200 г салата айсберг, нарезанного","2 спелых авокадо (~300 г), нарезанных","4 спелых помидора (~400 г), нарезанных","200 г сальсы роха или верде (домашней или магазинной)","1 лайм дольками + свежая кинза для подачи"],"en":["4 tlayuda tortillas (~30 cm, semi-dried) or 4 large flour tortillas as substitute","250 g dried black beans soaked overnight (or 1 × 400 g can)","100 g lard or 100 ml vegetable oil for frying beans + cooking","1 large onion (~200 g): half quartered for the beans, the other half finely diced for serving","4 garlic cloves (2 for beans, 2 for meat)","1 tsp ground cumin + 1 tsp dried oregano + 1 tsp salt for the beans","500 g flank or skirt steak, sliced very thinly across the grain (tasajo-style)","200 g fresh Mexican chorizo (or Spanish), removed from casing","300 g quesillo (Oaxaca string cheese) or low-moisture mozzarella, shredded","200 g shredded iceberg lettuce","2 ripe avocados (~300 g), sliced","4 ripe tomatoes (~400 g), sliced","200 g salsa roja or salsa verde (homemade or store-bought)","1 lime cut into wedges + fresh cilantro for serving"],"ro":["4 tortillas tlayuda (~30 cm, semi-uscate) sau 4 tortillas mari de făină","250 g fasole neagră uscată înmuiată peste noapte (sau 1 conservă × 400 g)","100 g untură sau 100 ml ulei vegetal pentru prăjit fasolea + sotat","1 ceapă mare (~200 g): jumătate tăiată sferturi pentru fasole, cealaltă jumătate tocată fin pentru servire","4 căței de usturoi (2 pentru fasole, 2 pentru carne)","1 linguriță chimion măcinat + 1 linguriță oregano uscat + 1 linguriță sare pentru fasole","500 g flank steak sau skirt steak, feliat foarte subțire în diagonală (stil tasajo)","200 g chorizo proaspăt mexican (sau spaniol), scos din maț","300 g quesillo (brânză Oaxaca) sau mozzarella low-moisture, rasă","200 g salată iceberg, tocată","2 avocado coapte (~300 g), feliate","4 roșii coapte (~400 g), feliate","200 g salsa roja sau verde (de casă sau de la magazin)","1 lime tăiată sferturi + coriandru proaspăt pentru servire"]},"howIsMade":{"ru":"ФАСОЛЬ: слейте 250 г замоченной чёрной фасоли; варите в 1,5 л воды с половиной лука четвертинками, 2 целыми зубчиками чеснока, 1 ч; л; зиры, 1 ч; л; орегано и 1 ч; л; соли 60–90 минут до очень мягкости; слейте, сохраняя 200 мл варочной жидкости. ОБЖАРЬТЕ ФАСОЛЬ (frijoles refritos): на сковороде разогрейте 50 г смальца на среднем огне; добавьте варёную фасоль и разминайте картофелемялкой или лопаткой, постепенно добавляя сохранённую жидкость, до густой кремовой пасты; готовьте 5–7 минут, помешивая, пока слегка не потемнеет и не появится копчёный аромат. ОБЖАРЬТЕ МЯСО: разогрейте 1 ст; л; масла в большой сковороде на сильном-среднем огне; приправьте 500 г говядины солью и перцем, обжаривайте 2 минуты с каждой стороны в один слой (не загромождайте, работайте партиями); оставьте под фольгой. ОБЖАРЬТЕ ЧОРИЗО: в той же сковороде добавьте 200 г чоризо без оболочки, разломайте деревянной ложкой и жарьте 5–7 минут на среднем огне, пока красное масло не выделится и мясо не приготовится; оставьте в сковороде с маслом. ПОДГОТОВЬТЕ ТОППИНГИ: нарежьте 2 авокадо, 4 помидора и оставшуюся половину лука (мелко); нашинкуйте 200 г салата; каждое — в отдельную миску для быстрой сборки. СБОРКА ТЛАЙЮДЫ: разогрейте планчу или большую сковороду-гриль на сильном-среднем огне; положите тортилью-тлайюду на сухую поверхность и намажьте щедрым слоем refried beans до 1 см от краёв; посыпьте 75 г тёртого сыра; добавьте порцию мяса и чоризо. ХРУСТКОСТЬ: готовьте на планче 5–7 минут без переворачивания — низ тортильи должен стать золотистым, хрустящим и с лёгкими подпалинами; сыр должен полностью расплавиться; накройте крышкой на последние 2 минуты для ускорения. ПОДАЧА: переложите тлайюду на тарелку широкой лопаткой; сверху — салат, ломтики помидоров, авокадо, нарезанный лук, сальса; выжимка лайма и кинза; сложите пополам или ешьте раскрытой руками; повторите с остальными 3; подавайте сразу — становится резиновой, если стоит.","en":"THE BEANS: drain 250 g soaked black beans; boil in 1.5 L water with half an onion in quarters, 2 whole garlic cloves, 1 tsp cumin, 1 tsp oregano and 1 tsp salt for 60–90 minutes until very tender; drain, reserving 200 ml of the cooking liquid. REFRY THE BEANS (frijoles refritos): in a skillet, heat 50 g lard over medium heat; add the cooked beans and mash with a potato masher or spatula, adding the reserved liquid gradually until you have a thick creamy paste; cook 5–7 minutes, stirring, until slightly blackened and smoky. SEAR THE STEAK: heat 1 tbsp oil in a large skillet over medium-high; season 500 g beef with salt and pepper, sear 2 minutes per side in a single layer (do not crowd the pan, work in batches); rest the meat on a foil-tented plate. FRY THE CHORIZO: in the same skillet, add 200 g chorizo from its casing, break it up with a wooden spoon, and fry 5–7 minutes over medium heat until the red oil is released and the meat is fully cooked; leave it in the pan with its oil. PREP THE TOPPINGS: slice 2 avocados, 4 tomatoes and the remaining onion half (finely diced); shred 200 g lettuce; place each in a separate bowl for fast assembly. ASSEMBLE THE TLAYUDA: preheat a plancha or large griddle over medium-high heat; place a tlayuda tortilla on the dry surface and spread it with a generous layer of refried beans to within 1 cm of the edges; scatter 75 g shredded cheese over the beans; add a portion of seared steak and chorizo. CRISP IT UP: cook on the plancha over medium heat 5–7 minutes without flipping — the bottom of the tortilla must turn golden brown, crunchy, and show light scorch marks; the cheese must melt completely; cover with a lid for the last 2 minutes to speed melting. SERVE: slide the tlayuda onto a plate with a wide spatula; top with lettuce, tomato slices, avocado, diced onion, salsa; squeeze lime and scatter cilantro; fold in half or eat open with your hands; repeat for the remaining 3 tlayudas; serve immediately — it gets chewy if it sits."}},{"id":163,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"ru":"Колумбия","en":"Colombia","ro":"Columbia"},"name":{"ru":"Бандеха пайса","en":"Bandeja Paisa","ro":"Bandeja Paisa"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["Для фрихолес антиокеньос: 400 г сухой красной фасоли (кардамонто или кидни), замоченной на ночь","1 средняя морковь (~100 г) натёртая + 2 средних помидора (~250 г) натёртых + 1 луковица (~150 г) мелко нарезанная + 4 зубчика чеснока для огао","2 ст. л. масла + 1 ст. л. томатной пасты + 1 ч. л. зиры + 1 ч. л. соли для фасоли","1 спелый плантан (~150 г) кубиками для фасоли","Для арроса бланко: 360 г (2 стакана) среднезёрного риса + 540 мл воды + 0,5 ч. л. соли","Для карне молида: 500 г говяжьего фарша + 1 мелко нарезанная луковица + 4 зубчика чеснока + 2 тёртых помидора + 2 ст. л. масла + 1 ч. л. зиры + 1 ч. л. соли + 0,5 ч. л. перца + 50 мл говяжьего бульона","Для чичаррона: 800 г свиной грудинки с кожей, нарезанной 8 полосками по ~10 см + 1 ч. л. соли","4 сырых колумбийских чоризо (~80 г каждый)","4 морсильи (кровяные колбаски, ~80 г каждая)","Для 4 маленьких арепас: 200 г предварительно сваренной белой кукурузной муки (Harina P.A.N.) + 240 мл тёплой воды + 0,5 ч. л. соли + 1 ст. л. масла для сковороды","Для мадуро: 2 очень спелых плантана (с чёрной кожурой) + 2 ст. л. масла","4 крупных яйца для яичницы + 1 ст. л. масла + соль и перец","2 спелых авокадо, разрезанных пополам без косточек","4 ломтика хрустящего белого хлеба + 4 дольки лайма + соль для подачи"],"en":["For frijoles antioqueños: 400 g dried red kidney or cargamanto beans, soaked overnight","1 medium carrot (~100 g) grated + 2 medium tomatoes (~250 g) grated + 1 onion (~150 g) finely diced + 4 garlic cloves for the hogao","2 tbsp oil + 1 tbsp tomato paste + 1 tsp ground cumin + 1 tsp salt for the beans","1 ripe plantain (~150 g) diced for the beans","For arroz blanco: 360 g (2 cups) medium-grain white rice + 540 ml water + 0.5 tsp salt","For carne molida: 500 g ground beef + 1 onion finely diced + 4 garlic cloves + 2 grated tomatoes + 2 tbsp oil + 1 tsp cumin + 1 tsp salt + 0.5 tsp pepper + 50 ml beef stock","For chicharrón: 800 g pork belly skin-on cut into 8 strips of ~10 cm + 1 tsp salt","4 raw Colombian chorizos (~80 g each)","4 morcillas (blood sausages, ~80 g each)","For 4 small arepas: 200 g precooked white corn flour (Harina P.A.N.) + 240 ml warm water + 0.5 tsp salt + 1 tbsp oil for the griddle","For maduro: 2 very ripe plantains (deep black skin) + 2 tbsp oil","4 large eggs for sunny-side up + 1 tbsp oil + salt and pepper","2 ripe avocados, halved and pitted","4 slices of crusty white bread + 4 lime wedges + salt to serve"],"ro":["Pentru frijoles antioqueños: 400 g fasole roșie uscată (cargamanto sau kidney) înmuiată peste noapte","1 morcov mediu (~100 g) ras + 2 roșii medii (~250 g) rase + 1 ceapă (~150 g) tocată fin + 4 căței usturoi pentru hogao","2 linguri ulei + 1 lingură pastă de roșii + 1 linguriță chimion + 1 linguriță sare pentru fasole","1 banană plantain coaptă (~150 g) tocată în cuburi pentru fasole","Pentru arroz blanco: 360 g (2 căni) orez cu bob mediu + 540 ml apă + 0,5 linguriță sare","Pentru carne molida: 500 g vită tocată + 1 ceapă tocată + 4 căței usturoi + 2 roșii rase + 2 linguri ulei + 1 linguriță chimion + 1 linguriță sare + 0,5 linguriță piper + 50 ml supă de vită","Pentru chicharrón: 800 g costiță de porc cu coajă tăiată în 8 fâșii lungi de 10 cm + 1 linguriță sare","4 chorizos columbieni cruzi (~80 g fiecare)","4 morcillas (cârnați de sânge, ~80 g fiecare)","Pentru arepas (4 mici): 200 g făină de porumb precoaptă (Harina P.A.N.) + 240 ml apă caldă + 0,5 linguriță sare + 1 lingură ulei pentru tigaie","Pentru maduro: 2 banane plantain foarte coapte (coaja neagră) + 2 linguri ulei","4 ouă mari pentru ochiuri + 1 lingură ulei + sare și piper","2 avocado coapte, jumătățite și fără sâmbure","4 felii pâine albă crocantă + 4 felii de lime + sare pentru servire"]},"howIsMade":{"ru":"ЗАМАЧИВАНИЕ И ПОДГОТОВКА: замочите 400 г красной фасоли на ночь; бандеха пайса требует 6 параллельных компонентов — соберите все ингредиенты и инструменты до начала, плюс 3 кастрюли и 2 сковороды. ФАСОЛЬ: слейте воду с фасоли, варите в 1,5 л воды с натёртой морковью + 1 натёртым помидором + луком + 2 зубчиками чеснока + 1 ч; л; зиры + 1 ч; л; соли 60–90 минут до мягкости; в последние 15 минут приготовьте огао: на 2 ст; л; масла обжарьте оставшийся лук + 2 чеснока + 1 натёртый помидор + 1 ст; л; томатной пасты 5 минут; вмешайте в фасоль с кубиками плантана и варите ещё 10 минут. РИС: промойте 360 г риса в холодной воде 3 раза; залейте 540 мл воды и 0,5 ч; л; соли; доведите до кипения, накройте, убавьте до минимального огня 12 минут, дайте постоять под крышкой 10 минут. КАРНЕ МОЛИДА: разогрейте 2 ст; л; масла в сковороде на сильном-среднем огне; обжарьте лук и чеснок 5 минут до мягкости; добавьте 500 г говяжьего фарша, разломайте ложкой и обжарьте 8 минут; добавьте 2 натёртых помидора, 1 ч; л; зиры, 1 ч; л; соли и 0,5 ч; л; перца, готовьте 5 минут; деглазируйте 50 мл бульона. ЧИЧАРРОН: положите 8 полосок свиной грудинки с кожей в кастрюлю с 200 мл холодной воды и 1 ч; л; соли; доведите до кипения, накройте и варите 30 минут; полностью слейте; в той же кастрюле обжарьте свинину в собственном жире на сильном-среднем огне 8–10 минут, часто переворачивая, до золотистой хрустящей корочки; (Альтернатива: духовка 200 °C 40 минут на решётке.). АРЕПЫ: смешайте 200 г кукурузной муки с 240 мл тёплой воды и 0,5 ч; л; соли в миске до влажного теста; дайте постоять 5 минут; сформируйте 4 лепёшки диаметром 10 см и толщиной 1 см; жарьте на горячей сковороде с 1 ст; л; масла на среднем огне 4–5 минут с каждой стороны до золотистости с тёмными пятнами. МАДУРО + ЯЙЦА + КОЛБАСКИ: нарежьте 2 чёрных плантана кружками 1 см; жарьте в 2 ст; л; масла на среднем огне 2 минуты с каждой стороны до карамелизации; в другой сковороде жарьте 4 сырых чоризо по 5 минут с каждой стороны и 4 морсильи по 3 минуты с каждой стороны; затем жарьте 4 яйца в 1 ч; л; масла 2 минуты, пока белки не схватятся, но желтки останутся жидкими. СБОРКА: на 4 больших тарелках разложите в таком порядке: горка риса, щедрая ложка фасоли, порция карне молида, 2 куска чичаррона, 1 чоризо, 1 морсилья, 1 жареное яйцо сверху мяса, 2 ломтика мадуро, 1/2 авокадо, 1 арепа, 1 ломтик хлеба, 1 долька лайма; подавайте сразу — бандеха пайса едят ножом и вилкой, каждый кусочек комбинируя разные компоненты.","en":"SOAK & PLAN: soak 400 g red beans overnight; bandeja paisa runs 6 parallel components — gather all ingredients and tools before starting, plus 3 pots and 2 skillets. THE BEANS: drain the beans, simmer in 1.5 L water with grated carrot + 1 grated tomato + onion + 2 garlic cloves + 1 tsp cumin + 1 tsp salt 60–90 minutes until tender; in the final 15 minutes make the hogao: sauté in 2 tbsp oil the remaining onion + 2 garlic + 1 grated tomato + 1 tbsp tomato paste 5 minutes; stir into the beans with the diced plantain and cook 10 more minutes. THE RICE: rinse 360 g rice in cold water 3 times; place with 540 ml water and 0.5 tsp salt; bring to a boil, cover, reduce to lowest heat 12 minutes, rest covered 10 minutes. CARNE MOLIDA: heat 2 tbsp oil in a skillet over medium-high; sauté onion and garlic 5 minutes until soft; add 500 g ground beef, break up with the spoon and brown 8 minutes; add 2 grated tomatoes, 1 tsp cumin, 1 tsp salt and 0.5 tsp pepper, cook 5 minutes; deglaze with 50 ml stock. CHICHARRÓN: place 8 strips of pork belly skin-on in a pot with 200 ml cold water and 1 tsp salt; bring to a boil, cover and simmer 30 minutes; drain completely; in the same pot, fry the pork in its own fat over medium-high heat 8–10 minutes turning often until the skin is golden and crackling; (Alternative: 200 °C oven 40 minutes on a rack.). AREPAS: mix 200 g corn flour with 240 ml warm water and 0.5 tsp salt in a bowl until a damp dough forms; rest 5 minutes; shape into 4 patties of 10 cm diameter and 1 cm thick; griddle in a hot pan with 1 tbsp oil over medium heat 4–5 minutes per side until golden with dark spots. MADURO + EGGS + SAUSAGES: slice 2 black plantains into 1 cm rounds; fry in 2 tbsp oil over medium heat 2 minutes per side until caramelized; in another skillet, fry 4 raw chorizos 5 minutes per side and 4 morcillas 3 minutes per side; then fry 4 eggs in 1 tsp oil 2 minutes until whites set but yolks runny. ASSEMBLY: on 4 large platters arrange in this order: a mound of rice, a generous ladle of beans, a portion of carne molida, 2 chicharrón pieces, 1 chorizo, 1 morcilla, 1 fried egg on top of the meat, 2 maduro slices, 1/2 avocado, 1 arepa, 1 bread slice, 1 lime wedge; serve immediately — bandeja paisa is eaten with knife and fork, each bite in combination with others."}},{"id":164,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ru":"Венгрия","en":"Hungary","ro":"Ungaria"},"name":{"ru":"Лангош","en":"Lángos","ro":"Lángos"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["500 г муки универсальной или хлебной T550","7 г сухих быстродействующих дрожжей (или 21 г свежих)","1 ч. л. сахарного песка (для подкормки дрожжей)","1,5 ч. л. мелкой соли для теста","300 мл тёплого цельного молока (или воды, традиционно) при 38 °C","100 г варёного размятого картофеля (секрет пушистой текстуры)","2 ст. л. нейтрального масла для теста","1 л подсолнечного или нейтрального масла для фритюра","Для чесночной обмазки: 4 зубчика чеснока, растёртых с 1 ч. л. соли + 1 ст. л. воды в пасту","200 г венгерской сметаны (tejföl)","200 г острого тёртого сыра (чеддер/гауда/эдам)","1 небольшой пучок свежего зелёного лука (шнитт), мелко нарезанного (по желанию)","Соль для финиша","Инвентарь: широкая тяжёлая кастрюля для фритюра + шумовка + решётка"],"en":["500 g all-purpose or T550 bread flour","7 g instant dry yeast (or 21 g fresh yeast)","1 tsp granulated sugar (to feed yeast)","1.5 tsp fine salt for the dough","300 ml warm whole milk (or water, traditional) at 38 °C","100 g boiled mashed potato (the secret to the fluffy texture)","2 tbsp neutral oil for the dough","1 L sunflower or neutral oil for deep-frying","For garlic rub: 4 garlic cloves crushed with 1 tsp salt + 1 tbsp water into a paste","200 g Hungarian sour cream (tejföl)","200 g sharp grated cheese (cheddar/gouda/edam-style)","1 small bunch fresh chives, finely chopped (optional)","Salt for finishing","Equipment: wide heavy pot for frying + slotted spoon + wire rack"],"ro":["500 g făină universală sau de pâine T550","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 linguriță zahăr granulat (pentru hrănirea drojdiei)","1,5 lingurițe sare fină pentru aluat","300 ml lapte integral cald (sau apă, tradițional) la 38 °C","100 g cartof fiert și pasat (secretul texturii pufoase)","2 linguri ulei neutru pentru aluat","1 L ulei de floarea-soarelui sau neutru pentru prăjit","Pentru ungerea cu usturoi: 4 căței de usturoi zdrobiți cu 1 linguriță sare + 1 lingură apă în pastă","200 g smântână ungurească (tejföl)","200 g brânză tare rasă (cheddar/gouda/edam)","1 legăturică mică de ceapă verde proaspătă (arpagic), tocată fin (opțional)","Sare pentru finisare","Echipament: oală grea și lată pentru prăjit + lingură cu fante + grătar de sârmă"]},"howIsMade":{"ru":"АКТИВИРУЙТЕ ДРОЖЖИ: подогрейте 100 мл молока до 38 °C, добавьте 7 г дрожжей и 1 ч; л; сахара, перемешайте и оставьте на 10 минут до образования пены; нет пены = дрожжи мертвы, начните заново. ЗАМЕСИТЕ ТЕСТО: в большой миске смешайте 500 г муки с 1,5 ч; л; соли; сделайте углубление, добавьте дрожжевое молоко, оставшиеся 200 мл тёплого молока, 100 г гладкого картофельного пюре (без комков) и 2 ст; л; масла; месите вручную или в комбайне 10 минут до гладкости, мягкости и лёгкой липкости — мягче, чем хлебное тесто. ПЕРВАЯ РАССТОЙКА: накройте чистым полотенцем и поставьте в тёплое место на 1,5–2 часа до удвоения. ФОРМОВКА: слегка смажьте руки и рабочую поверхность маслом; разделите на 4 равные части (~225 г каждая); скатайте в шарики, накройте и дайте отдохнуть 10 минут; смазанными маслом руками растяните каждый шарик в диск 25 см толщиной около 1 см, чуть тоньше по краям. ВТОРАЯ РАССТОЙКА: положите сформированные диски на смазанный поднос, неплотно накройте и оставьте на 20 минут до пышности. РАЗОГРЕЙТЕ МАСЛО: налейте 1 л масла в широкую тяжёлую кастрюлю до глубины 5 см; нагрейте до 175 °C (средне-сильный огонь) — маленький кусочек теста должен шипеть и подниматься через 5 секунд. ЖАРЬТЕ ЛАНГОШ: осторожно опустите один лангош в горячее масло; через 30 секунд аккуратно прижмите его под масло шумовкой — он сильно вздувается; жарьте 60–90 секунд с каждой стороны до глубокого золотистого цвета; откиньте на проволочную решётку (НЕ на бумажные полотенца, которые размягчают основу паром). НАЧИНКА И ПОДАЧА: смажьте ещё горячую верхушку чесночной пастой (4 зубчика, растёртых с 1 ч; л; соли + 1 ст; л; воды); намажьте 50 г сметаны, посыпьте 50 г тёртого сыра, добавьте нарезанный шнитт-лук и щепотку соли; подавайте в руке или на тарелке, съедайте за 5 минут, пока хлеб хрустящий снаружи и мягкий внутри.","en":"PROOF THE YEAST: warm 100 ml of the milk to 38 °C, add 7 g yeast and 1 tsp sugar, stir and let stand 10 minutes until foamy; no foam = dead yeast, start over. MAKE THE DOUGH: in a large bowl combine 500 g flour with 1.5 tsp salt; make a well, add the foamed yeast-milk, the remaining 200 ml warm milk, 100 g smooth mashed potato (no lumps), and 2 tbsp oil; knead by hand or stand mixer 10 minutes until smooth, soft and slightly sticky — softer than bread dough. FIRST PROOF: cover with a clean towel and rise in a warm place 1.5–2 hours until doubled. SHAPE: lightly oil hands and work surface; divide into 4 equal portions (~225 g each); roll into balls, rest 10 minutes covered; with oiled hands stretch each ball into a 25 cm disc about 1 cm thick, slightly thinner at the edges. SECOND PROOF: place shaped discs on an oiled tray, cover loosely and let rise 20 minutes until puffy. HEAT THE OIL: pour 1 L oil into a wide heavy pot to a 5 cm depth; heat to 175 °C (medium-high) — a small piece of dough should sizzle and rise within 5 seconds. FRY THE LÁNGOS: carefully slide one lángos into the hot oil; after 30 seconds, gently push under with a slotted spoon — it puffs dramatically; fry 60–90 seconds per side until deeply golden brown; drain on a wire rack (NOT paper towels which steam the base soft). TOPPING & SERVE: brush the still-hot top with garlic paste (4 garlic crushed with 1 tsp salt + 1 tbsp water); smear with 50 g sour cream, scatter 50 g grated cheese, sprinkle chopped chives and a pinch of salt; serve in hand or on a plate, eaten within 5 minutes while bread is crisp outside and pillowy inside."}},{"id":165,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"ru":"Индия","en":"India","ro":"India"},"name":{"ru":"Раджма","en":"Rajma","ro":"Rajma"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["350 г сухой красной фасоли (rajma), замоченной на 8–12 ч в холодной воде (ИЛИ 2 × 400 г банок красной фасоли, слитой, как короткий путь)","1,2 л воды для варки фасоли + 1 ч. л. соли + 2 лавровых листа + 4 стручка чёрного кардамона (для варки под давлением)","3 ст. л. гхи или нейтрального масла для масалы","1 ч. л. цельных семян зиры (jeera)","2 средних жёлтых лука (~300 г) очень мелко нарезанных","6 зубчиков чеснока + 4 см свежего имбиря — натёртых в пасту с 1 ст. л. воды","1 зелёный перец чили (или по вкусу), мелко нарезанный","4 средних спелых помидора (~400 г), пюрированных в блендере до гладкой пульпы","1 ст. л. томатной пасты (для плотности)","1 ч. л. молотого кориандра (dhania) + 1 ч. л. молотой зиры (jeera) + 0,5 ч. л. куркумы (haldi) + 1 ч. л. кашмирского чили-порошка + 1 ч. л. соли для масалы","1 ч. л. гарам масала (добавляется в конце, не варится)","1 ч. л. касури методи (сушёные листья пажитника), растёртых в ладони (добавляется в конце)","30 г сливочного масла кубиками (ресторанная отделка)","1 ст. л. жидких сливок или 2 ст. л. жирного йогурта (по желанию, для кремовости)","Свежие листья кориандра (кинза) для украшения + 1 лайм дольками; для подачи: 360 г (2 стакана) риса басмати, сваренного в 540 мл воды с 0,5 ч. л. соли, и наан или jeera rice по желанию"],"en":["350 g dried red kidney beans (rajma) soaked 8–12 h in cold water (OR 2 × 400 g cans drained as a shortcut)","1.2 L cooking water for the beans + 1 tsp salt + 2 bay leaves + 4 black cardamom pods (for pressure-cooking the beans)","3 tbsp ghee or neutral oil for the masala","1 tsp whole cumin seeds (jeera)","2 medium yellow onions (~300 g) very finely diced","6 garlic cloves + 4 cm fresh ginger — grated into a paste with 1 tbsp water","1 green chili (or to taste), finely chopped","4 medium ripe tomatoes (~400 g), pureed in a blender to a smooth pulp","1 tbsp tomato paste (for body)","1 tsp ground coriander (dhania) + 1 tsp ground cumin (jeera) + 0.5 tsp turmeric (haldi) + 1 tsp Kashmiri red chili powder + 1 tsp salt for the masala","1 tsp garam masala (added at end, not boiled)","1 tsp kasuri methi (dried fenugreek leaves), crushed in palm (added at end)","30 g butter cubed (the restaurant-style finish)","1 tbsp single cream or 2 tbsp full-fat yogurt (optional, for creaminess)","Fresh coriander (cilantro) leaves to garnish + 1 lime in wedges; to serve: 360 g (2 cups) basmati rice cooked in 540 ml water with 0.5 tsp salt, and naan or jeera rice if preferred"],"ro":["350 g fasole roșie uscată (rajma) înmuiată 8–12 h în apă rece (SAU 2 × 400 g cutii de fasole roșie scursă ca scurtătură)","1,2 L apă de fierbere pentru fasole + 1 linguriță sare + 2 foi de dafin + 4 păstăi de cardamom negru (pentru fierberea sub presiune)","3 linguri ghee sau ulei neutru pentru masala","1 linguriță semințe întregi de chimion (jeera)","2 cepe galbene medii (~300 g) tocate foarte fin","6 căței de usturoi + 4 cm de ghimbir proaspăt — răzuite în pastă cu 1 lingură de apă","1 ardei iute verde (sau după gust), tocat fin","4 roșii medii coapte (~400 g), pasate la blender până la o pulpă fină","1 lingură pastă de roșii (pentru corp)","1 linguriță coriandru măcinat (dhania) + 1 linguriță chimion măcinat (jeera) + 0,5 linguriță turmeric (haldi) + 1 linguriță Kashmiri chili pudră + 1 linguriță sare pentru masala","1 linguriță garam masala (adăugat la final, nu fiert)","1 linguriță kasuri methi (frunze uscate de schinduf), zdrobite în palmă (adăugat la final)","30 g unt cubulețe (finisajul în stil restaurant)","1 lingură smântână dulce single sau 2 linguri iaurt gras (opțional, pentru cremozitate)","Frunze proaspete de coriandru (cilantro) pentru garnitură + 1 lămâie verde feliată; pentru servire: 360 g (2 căni) orez basmati fiert în 540 ml apă cu 0,5 linguriță sare, plus naan sau jeera rice dacă preferi"]},"howIsMade":{"ru":"ЗАМОЧИТЕ ФАСОЛЬ: промойте 350 г rajma в холодной воде 2–3 раза; залейте холодной водой на 5 см выше и замачивайте 8–12 часов (или на ночь); слейте и промойте; пропуск замачивания даёт недоваренные сердцевины и газообразующую текстуру. ВАРИТЕ ФАСОЛЬ ПОД ДАВЛЕНИЕМ: положите замоченную rajma в скороварку с 1,2 л воды + 1 ч; л; соли + 2 лавровых листа + 4 стручка чёрного кардамона; готовьте под давлением на сильном огне 4–5 свистков, затем уменьшите до малого и варите 25 минут; дайте давлению сойти естественно; фасоль должна быть полностью мягкой — нажмите одну между большим и указательным пальцем; она должна разминаться при лёгком нажатии; (Альтернатива: открытая кастрюля 1,5–2 ч кипячения.) Слейте, оставив 500 мл отвара. БХУНАО — ТЕМПЕРИРОВАНИЕ: в тяжёлой кадхай или глубокой сковороде на среднем огне растопите 3 ст; л; гхи; когда заблестит, добавьте 1 ч; л; семян зиры — они зашипят и потрескают в течение 5 секунд; не дайте им почернеть. ЛУК: добавьте 300 г очень мелко нарезанного лука; готовьте, часто помешивая, 12–15 минут до глубокого золотисто-коричневого цвета — почти карамелизованного; этот длинный, медленный лук-бхунао — то, что отделяет ресторанную rajma от любительских попыток; не торопитесь. ИМБИРЬ-ЧЕСНОК-ЧИЛИ: добавьте пасту имбирь-чеснок и зелёный чили; помешивайте 1–2 минуты, пока сырой запах не исчезнет. ТОМАТНАЯ ОСНОВА: добавьте пюрированную томатную пульпу + 1 ст; л; томатной пасты + 1 ч; л; молотого кориандра + 1 ч; л; молотой зиры + 0,5 ч; л; куркумы + 1 ч; л; кашмирского чили + 1 ч; л; соли; готовьте, часто помешивая, 8–10 минут, пока масло не отделится от масалы по краям сковороды — это визуальный знак, что бхунао завершено и сырой томат проварен. ТУШИТЕ С ФАСОЛЬЮ: добавьте слитую rajma и 500 мл оставленного отвара; аккуратно перемешайте; доведите до кипения и готовьте без крышки 20–25 минут, частично разминая некоторые бобы о стенку сковороды ложкой, чтобы загустить соус; соус должен уменьшиться и покрыть бобы — ни жидкий, ни сухой, как густое рагу, которое держится на ложке. ЗАВЕРШЕНИЕ И ПОДАЧА: вмешайте 1 ч; л; гарам масала + 1 ч; л; растёртой касури методи + 30 г кубиков сливочного масла + 1 ст; л; сливок (по желанию); перемешайте, пока масло не растает; накройте и дайте постоять 5 минут вне огня, чтобы вкусы устоялись; подавайте горячим поверх пареного риса басмати (или jeera rice или наан), посыпав нарезанным свежим кориандром и капнув лайма; лучше на следующий день.","en":"SOAK THE BEANS: rinse 350 g rajma in cold water 2–3 times; cover with cold water by 5 cm and soak 8–12 hours (or overnight); drain and rinse; skipping the soak gives undercooked centers and gassy texture. PRESSURE-COOK THE BEANS: place soaked rajma in a pressure cooker with 1.2 L water + 1 tsp salt + 2 bay leaves + 4 black cardamom pods; pressure-cook on high heat 4–5 whistles, then reduce to low and cook 25 minutes; let the pressure release naturally; beans should be completely tender — press one between thumb and forefinger; it should mash with light pressure; (Alternative: open pot 1.5–2 h simmer.) Drain reserving 500 ml bean cooking liquid. BHUNAO — TEMPER: in a heavy kadhai or deep pan over medium heat, melt 3 tbsp ghee; when shimmering, add 1 tsp cumin seeds — they will sizzle and pop within 5 seconds; do not let them blacken. ONIONS: add 300 g very finely diced onion; cook stirring often 12–15 minutes until deeply golden brown — almost caramelized; this long, slow onion bhunao is what separates restaurant rajma from amateur attempts; do not rush. GINGER-GARLIC-CHILI: add the ginger-garlic paste and green chili; stir 1–2 minutes until the raw smell disappears. TOMATO BASE: add the pureed tomato pulp + 1 tbsp tomato paste + 1 tsp ground coriander + 1 tsp ground cumin + 0.5 tsp turmeric + 1 tsp Kashmiri chili powder + 1 tsp salt; cook stirring frequently 8–10 minutes until the oil separates from the masala on the edges of the pan — this is the visual sign the bhunao is complete and the raw tomato has cooked off. SIMMER WITH BEANS: tip in the drained rajma and 500 ml of reserved bean liquid; stir gently; bring to a simmer and cook uncovered 20–25 minutes, partially mashing some beans against the side of the pan with a spoon to thicken the gravy; the gravy should reduce and coat the beans — neither soupy nor dry, like a thick stew that holds on a spoon. FINISH AND SERVE: stir in 1 tsp garam masala + 1 tsp crushed kasuri methi + 30 g butter cubed + 1 tbsp cream (optional); stir until butter melts; cover and let rest off heat 5 minutes for flavors to settle; serve hot over steamed basmati rice (or jeera rice or naan), topped with chopped fresh coriander and a squeeze of lime; better the next day."}},{"id":166,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"ru":"Куба","en":"Cuba","ro":"Cuba"},"name":{"ru":"Пикадильо","en":"Picadillo","ro":"Picadillo"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["600 г говяжьего фарша (лопатка, ~20% жирности)","2 ст. л. оливкового масла для софрито","1 крупная жёлтая луковица (~200 г), мелко нарезанная кубиками","1 крупный зелёный сладкий перец (~200 г), мелко нарезанный кубиками","6 зубчиков чеснока, измельчённых","1 ч. л. молотого тмина (комино) + 1 ч. л. сушёного орегано + 0,5 ч. л. сладкой копчёной паприки (пиментон) + 1 лавровый лист","400 г измельчённых томатов в банке (или 4 свежих помидора очищенных и натёртых) + 2 ст. л. томатной пасты","100 мл сухого белого вина ИЛИ 50 мл сухого хереса (кубинская традиция — выжигает запах сырого мяса)","100 г зелёных оливок без косточек (мансанилья), разрезанных пополам","60 г светлого или тёмного изюма, замоченного 10 минут в 100 мл горячей воды и затем слитого","100 г замороженного зелёного горошка, размороженного","1 ст. л. каперсов, слитых (по желанию, традиционно)","1,5 ч. л. соли + 0,5 ч. л. свежемолотого чёрного перца","Свежая плосколистная петрушка для украшения","Для подачи: 360 г (2 стакана) белого риса, сваренного в 540 мл воды с 0,5 ч. л. соли + 240 г варёной чёрной фасоли + 2 спелых плантана нарезанных и обжаренных + дольки лайма"],"en":["600 g ground beef (chuck, ~20% fat)","2 tbsp olive oil for the sofrito","1 large yellow onion (~200 g), finely diced","1 large green bell pepper (~200 g), finely diced","6 garlic cloves, minced","1 tsp ground cumin (comino) + 1 tsp dried oregano + 0.5 tsp sweet smoked paprika (pimentón) + 1 bay leaf","400 g can crushed tomatoes (or 4 fresh tomatoes peeled and grated) + 2 tbsp tomato paste","100 ml dry white wine OR 50 ml dry sherry (Cuban traditional — burns off raw-meat smell)","100 g pitted green olives (manzanilla), halved","60 g golden or dark raisins, soaked 10 min in 100 ml hot water then drained","100 g frozen green peas, thawed","1 tbsp capers, drained (optional, traditional)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","Fresh flat-leaf parsley to garnish","To serve: 360 g (2 cups) white rice cooked in 540 ml water with 0.5 tsp salt + 240 g cooked black beans + 2 ripe plantains sliced and fried + lime wedges"],"ro":["600 g carne tocată de vită (gât/cap de piept, ~20% grăsime)","2 linguri ulei de măsline pentru sofrito","1 ceapă galbenă mare (~200 g), tăiată cubulețe fine","1 ardei gras verde mare (~200 g), tăiat cubulețe fine","6 căței de usturoi, tocați mărunt","1 linguriță chimion măcinat (comino) + 1 linguriță oregano uscat + 0,5 linguriță boia dulce afumată (pimentón) + 1 foaie de dafin","400 g roșii zdrobite la conservă (sau 4 roșii proaspete decojite și răzuite) + 2 linguri pastă de roșii","100 ml vin alb sec SAU 50 ml sherry sec (tradițional cubanez — arde mirosul de carne crudă)","100 g măsline verzi fără sâmburi (manzanilla), tăiate în jumătăți","60 g stafide aurii sau negre, înmuiate 10 minute în 100 ml apă caldă, apoi scurse","100 g mazăre verde congelată, dezghețată","1 lingură capere, scurse (opțional, tradițional)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","Pătrunjel verde proaspăt cu frunza lată pentru garnitură","Pentru servire: 360 g (2 căni) orez alb fiert în 540 ml apă cu 0,5 linguriță sare + 240 g fasole neagră fiartă + 2 banane plantain coapte feliate și prăjite + felii de lămâie verde"]},"howIsMade":{"ru":"ОСНОВА СОФРИТО: в тяжёлой кастрюле 5 л нагрейте 2 ст; л; оливкового масла на среднем огне; добавьте 200 г нарезанного кубиками лука + 200 г нарезанного кубиками зелёного перца со щепоткой соли; готовьте, часто помешивая, 8–10 минут, пока не станет мягким и не начнёт золотиться — софрито это душа кубинской кухни; добавьте 6 измельчённых зубчиков чеснока и готовьте ещё 1 минуту до появления аромата. РАСКРОЙТЕ СПЕЦИИ: добавьте 1 ч; л; тмина, 1 ч; л; орегано, 0,5 ч; л; копчёной паприки и 1 лавровый лист в горячую масляно-овощную основу; помешивайте 30 секунд, пока специи не раскроют свой аромат — не подгорите. ОБЖАРЬТЕ ГОВЯДИНУ: увеличьте огонь до средне-сильного; добавьте 600 г говяжьего фарша одним слоем и оставьте нетронутым 2–3 минуты, чтобы образовалась корочка; затем разломайте деревянной ложкой и обжаривайте ещё 6–8 минут, пока не останется розового цвета и выделившаяся жидкость не испарится. ДЕГЛАСИРОВКА: влейте 100 мл сухого белого вина (или 50 мл хереса) и соскребите подгоревшие кусочки со дна кастрюли; кипятите 2–3 минуты, пока не исчезнет запах алкоголя. ТОМАТ + СБОРКА: вмешайте банку измельчённых томатов + 2 ст; л; томатной пасты; готовьте 5 минут, пока смесь не потемнеет и масло не начнёт появляться на поверхности — томат полностью приготовлен, без сырой кислинки. ДОБАВЬТЕ ОЛИВКИ, ИЗЮМ И ПРИПРАВЫ: вмешайте 100 г оливок, разрезанных пополам + 60 г слитого изюма + 1 ст; л; каперсов (если используете) + 1,5 ч; л; соли + 0,5 ч; л; перца; сладко-солёный контраст — уникальная кубинская подпись. ТУШИТЕ: уменьшите огонь до малого, накройте частично и тушите 20–25 минут, помешивая каждые несколько минут; смесь должна загустеть в соусистый хэш — ни сухой, ни жидкий, держащийся на ложке; добавьте 60 мл воды, если станет слишком сухо. ГОРОШЕК И ПОДАЧА: в последние 3 минуты вмешайте 100 г размороженного горошка — только чтобы прогреть, сохраняя его ярко-зелёный цвет; удалите лавровый лист; сняв с огня, посыпьте нарезанной петрушкой; подавайте поверх пареного белого риса с чёрной фасолью сбоку, жареными плантанами и дольками лайма — классическая кубинская тарелка comida criolla.","en":"SOFRITO BASE: in a heavy 5 L pot, heat 2 tbsp olive oil over medium heat; add 200 g diced onion + 200 g diced green pepper with a pinch of salt; cook stirring often 8–10 minutes until soft and beginning to gold — the sofrito is the soul of Cuban cooking; add 6 minced garlic cloves and cook 1 minute more until fragrant. BLOOM THE SPICES: add 1 tsp cumin, 1 tsp oregano, 0.5 tsp smoked paprika and 1 bay leaf to the hot oil-and-vegetable base; stir 30 seconds until the spices release their aroma — do not burn. BROWN THE BEEF: raise heat to medium-high; add 600 g ground beef in a single layer and let it sit undisturbed 2–3 minutes to develop a crust; then break it up with a wooden spoon and brown another 6–8 minutes until no pink remains and any released liquid has evaporated. DEGLAZE: pour in 100 ml dry white wine (or 50 ml sherry) and scrape any browned bits stuck to the bottom of the pot; simmer 2–3 minutes until the alcohol smell disappears. TOMATO + BUILD: stir in the can of crushed tomatoes + 2 tbsp tomato paste; cook 5 minutes until the mixture darkens and oil starts to appear on the surface — tomato fully cooked, no raw acidity. ADD OLIVES, RAISINS & SEASON: stir in 100 g halved green olives + 60 g drained raisins + 1 tbsp capers (if using) + 1.5 tsp salt + 0.5 tsp pepper; the sweet-salty contrast is the unique Cuban signature. SIMMER: reduce heat to low, cover partially, and simmer 20–25 minutes, stirring every few minutes; the mixture should thicken into a saucy hash — neither dry nor soupy, holding together on a spoon; add 60 ml water if it gets too dry. PEAS & SERVE: in the last 3 minutes, stir in 100 g thawed peas — just to warm through, keeping them bright green; remove the bay leaf; off the heat, scatter chopped parsley; serve over steamed white rice with black beans on the side, fried plantains, and lime wedges — the classic Cuban comida criolla plate."}},{"id":167,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Марокко","en":"Morocco","ro":"Maroc"},"name":{"ru":"Тажин с ягненком","en":"Lamb Tagine","ro":"Tagine cu miel"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1 кг бараньей лопатки без кости, нарезанной кубиками 4 см (с небольшим количеством жира для насыщенности)","2 крупные жёлтые луковицы (~400 г), одна мелко нарезана кубиками для основы, другая нарезана толстыми дольками для тушения","6 зубчиков чеснока, измельчённых","4 см свежего имбиря, натёртого","3 ст. л. оливкового масла (или 2 ст. л. масла + 1 ст. л. сливочного масла для традиционной насыщенности)","1 ч. л. молотого тмина + 1 ч. л. молотого кориандра + 1 ч. л. молотой корицы + 0,5 ч. л. молотой куркумы + 0,5 ч. л. сладкой паприки + 0,5 ч. л. молотого имбиря + щепотка нитей шафрана (5–6 нитей, настоянных в 2 ст. л. горячей воды)","1,5 ч. л. рас-эль-ханут (марокканская смесь специй)","1,5 ч. л. соли + 0,5 ч. л. свежемолотого чёрного перца","2 ст. л. томатной пасты","400 г спелых помидоров (4 средних), очищенных и натёртых, или 1 банка 400 г","200 г кураги, нарезанной пополам (турецкой или калифорнийской — не слишком сладкой)","60 г чернослива без косточек или изюма (по желанию, для глубины вкуса)","600 мл горячей воды или куриного бульона с пониженным содержанием соли","1 палочка корицы + 1 лавровый лист","80 г цельного бланшированного миндаля (или с кожурой, обжаренного)","1 ст. л. мёда (добавляется в конце для балансировки сладости)","Свежая кинза + плосколистная петрушка + 1 ст. л. слегка обжаренных семян кунжута для украшения","Для подачи: 400 г кускуса, приготовленного на пару с 400 мл воды + 1 ст. л. сливочного масла + 0,5 ч. л. соли, ИЛИ тёплая лепёшка хобз"],"en":["1 kg boneless lamb shoulder, cut into 4 cm cubes (with some fat on for richness)","2 large yellow onions (~400 g), one finely diced for the base and one cut into thick wedges for the stew","6 garlic cloves, minced","4 cm fresh ginger, grated","3 tbsp olive oil (or 2 tbsp oil + 1 tbsp butter for traditional richness)","1 tsp ground cumin + 1 tsp ground coriander + 1 tsp ground cinnamon + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground ginger + a pinch of saffron threads (5–6 strands, bloomed in 2 tbsp hot water)","1.5 tsp ras el hanout (Moroccan spice blend)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","2 tbsp tomato paste","400 g ripe tomatoes (4 medium), peeled and grated, or 1 × 400 g can","200 g dried apricots, halved (use Turkish or California — not too sweet)","60 g pitted dried prunes or raisins (optional, for depth)","600 ml hot water or low-salt chicken stock","1 cinnamon stick + 1 bay leaf","80 g whole blanched almonds (or skin-on, toasted)","1 tbsp honey (added at the end to balance sweetness)","Fresh coriander + flat-leaf parsley + 1 tbsp lightly toasted sesame seeds to garnish","To serve: 400 g couscous steamed with 400 ml water + 1 tbsp butter + 0.5 tsp salt, OR warm khobz flatbread"],"ro":["1 kg pulpă de miel dezosată (spată), tăiată cuburi de 4 cm (cu puțină grăsime pentru bogăție)","2 cepe galbene mari (~400 g), una tăiată cubulețe fine pentru bază și una tăiată în felii groase pentru tocăniță","6 căței de usturoi, tocați mărunt","4 cm ghimbir proaspăt, ras","3 linguri ulei de măsline (sau 2 linguri ulei + 1 lingură unt pentru bogăție tradițională)","1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 1 linguriță scorțișoară măcinată + 0,5 linguriță turmeric măcinat + 0,5 linguriță boia dulce + 0,5 linguriță ghimbir măcinat + un vârf de șofran (5–6 fire, înflorit în 2 linguri apă caldă)","1,5 linguriță ras el hanout (amestec marocan de condimente)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","2 linguri pastă de roșii","400 g roșii coapte (4 medii), decojite și răzuite, sau 1 cutie × 400 g","200 g caise uscate, tăiate în jumătăți (turcești sau californiene — nu prea dulci)","60 g prune uscate fără sâmburi sau stafide (opțional, pentru profunzime)","600 ml apă fierbinte sau supă de pui cu puțină sare","1 baton de scorțișoară + 1 foaie de dafin","80 g migdale întregi blanșate (sau cu coajă, prăjite)","1 lingură miere (adăugată la final pentru a echilibra dulceața)","Coriandru proaspăt + pătrunjel cu frunza lată + 1 lingură semințe de susan ușor prăjite pentru garnitură","Pentru servire: 400 g couscous aburit cu 400 ml apă + 1 lingură unt + 0,5 linguriță sare, SAU pâine plată khobz caldă"]},"howIsMade":{"ru":"МАРИНУЙТЕ ЯГНЯТИНУ: в большой миске смешайте 1 кг кубиков ягнятины с 1 ч; л; тмина + 1 ч; л; кориандра + 1 ч; л; корицы + 0,5 ч; л; куркумы + 0,5 ч; л; паприки + 0,5 ч; л; имбиря + 1,5 ч; л; рас-эль-ханут + 1,5 ч; л; соли + 0,5 ч; л; перца + 3 из измельчённых зубчиков чеснока и 1 ст; л; оливкового масла; вотрите специи в мясо руками; накройте и оставьте на 30 минут при комнатной температуре (или до 24 ч в холодильнике), чтобы специи проникли. РАСКРОЙТЕ ШАФРАН: поместите 5–6 нитей шафрана в 2 ст; л; горячей воды и настаивайте 10 минут — это раскрывает аромат и цвет; отложите. СОЗДАЙТЕ ОСНОВУ: нагрейте оставшиеся 2 ст; л; масла (и 1 ст; л; сливочного масла, если используете) в тяжёлом тажине или казанке на среднем огне; добавьте 200 г мелко нарезанного лука и готовьте, часто помешивая, 8–10 минут, пока не станет мягким и прозрачным; добавьте оставшиеся 3 измельчённых зубчика чеснока + натёртый имбирь и помешивайте 1 минуту. ОБЖАРЬТЕ ЯГНЯТИНУ: увеличьте огонь до средне-сильного; сдвиньте лук к краям кастрюли и добавьте маринованную ягнятину одним слоем (работайте в 2 партии, если нужно); обжаривайте 3–4 минуты с каждой стороны не двигая, пока не образуется глубокая корочка со всех сторон — корочка важна для богатого вкуса тушёного блюда; смешайте всё вместе, как только ягнятина обжарится. ТОМАТ + ЖИДКОСТЬ: вмешайте 2 ст; л; томатной пасты и готовьте 1 минуту до потемнения; добавьте 400 г натёртых помидоров, шафрановую воду, 1 палочку корицы и 1 лавровый лист; влейте 600 мл горячей воды (или бульона) — жидкость должна доходить примерно до половины мяса, а не покрывать его; доведите до медленного кипения. МЕДЛЕННОЕ ТОМЛЕНИЕ: уменьшите огонь до малого, накройте крышкой тажина (или плотной крышкой казанка) и томите 1,5–2 часа, проверяя каждые 30 минут и осторожно помешивая; ягнятина готова, когда вилка легко входит; добавьте немного горячей воды, если соус слишком быстро уваривается. ДОБАВЬТЕ КУРАГУ + ЛУК: вмешайте 200 г кураги, нарезанной пополам + 60 г чернослива (если используете) + 200 г луковых долек; накройте и томите ещё 25–30 минут, пока фрукты не станут пухлыми, а луковые дольки — мягкими, но сохраняющими форму; соус должен быть глянцевым, обволакивающим заднюю часть ложки; закончите 1 ст; л; мёда, попробуйте, отрегулируйте соль. ЗАВЕРШЕНИЕ И ПОДАЧА: пока тажин отдыхает 5 минут вне огня, обжарьте 80 г цельного миндаля в сухой сковороде на среднем огне 3–4 минуты до золотистого цвета — следите внимательно, они быстро горят; выложите тажин из ягнятины на тёплый кускус (или подайте с хобзом), посыпьте обжаренным миндалём, кунжутом и порцией свежей кинзы и петрушки; ешьте с хлебом, чтобы собрать соус.","en":"MARINATE THE LAMB: in a large bowl combine 1 kg lamb cubes with 1 tsp cumin + 1 tsp coriander + 1 tsp cinnamon + 0.5 tsp turmeric + 0.5 tsp paprika + 0.5 tsp ginger + 1.5 tsp ras el hanout + 1.5 tsp salt + 0.5 tsp pepper + 3 of the minced garlic cloves and 1 tbsp olive oil; rub the spices into the meat with your hands; cover and rest 30 minutes at room temperature (or up to 24 h in the fridge) so the spices penetrate. BLOOM SAFFRON: place 5–6 saffron threads in 2 tbsp hot water and let steep 10 minutes — this releases the flavour and colour; set aside. BUILD THE BASE: heat the remaining 2 tbsp oil (and 1 tbsp butter if using) in a heavy-bottomed tagine or Dutch oven over medium heat; add 200 g finely diced onion and cook stirring often 8–10 minutes until soft and translucent; add the remaining 3 minced garlic + grated ginger and stir 1 minute. SEAR THE LAMB: raise heat to medium-high; push the onions to the sides of the pot and add the marinated lamb in a single layer (work in 2 batches if needed); sear 3–4 minutes per side without moving until deeply browned on all sides — the crust is essential for the rich stew flavour; stir everything together once the lamb is browned. TOMATO + LIQUID: stir in 2 tbsp tomato paste and cook 1 minute until darkened; add the 400 g grated tomatoes, the saffron-water, 1 cinnamon stick and 1 bay leaf; pour in 600 ml hot water (or stock) — the liquid should come about halfway up the meat, not cover it; bring to a gentle simmer. SLOW COOK: reduce heat to low, cover with the tagine lid (or a tight Dutch-oven lid), and simmer 1.5–2 hours, checking every 30 minutes and stirring gently; the lamb is ready when a fork sinks in easily; add a splash of hot water if the sauce reduces too quickly. ADD APRICOTS + ONIONS: stir in 200 g halved dried apricots + 60 g prunes (if using) + the 200 g onion wedges; cover and simmer 25–30 minutes more until the fruit is plump and the onion wedges are tender but still holding shape; the sauce should be glossy, coating the back of a spoon; finish with 1 tbsp honey, taste, adjust salt. FINISH AND SERVE: while the tagine rests off the heat for 5 minutes, toast 80 g whole almonds in a dry pan over medium heat 3–4 minutes until golden — watch carefully, they burn fast; spoon the lamb tagine over warm couscous (or serve with khobz), top with toasted almonds, sesame seeds, and a scatter of fresh coriander and parsley; eat with bread to mop up the sauce."}},{"id":168,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Великобритания","en":"United Kingdom","ro":"Marea Britanie"},"name":{"ru":"Пастуший пирог","en":"Shepherd's Pie","ro":"Plăcintă a ciobanului"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["600 г фарша из ягнятины (~15% жирности — постнее обычного говяжьего фарша, но с достаточным количеством жира для сочности)","1 крупная луковица (~200 г), мелко нарезанная кубиками","2 средние моркови (~200 г), мелко нарезанные кубиками 0,5 см (мелкие кубики — они должны исчезнуть в начинке)","4 зубчика чеснока, измельчённых","1 ст. л. томатной пасты","1 ст. л. соуса Вустершир (секретная глубина вкуса — обязательно)","1 ч. л. сушёного тимьяна (или 2 веточки свежего)","1 ч. л. сушёного розмарина, мелко нарезанного","2 ст. л. пшеничной муки (для загущения соуса)","300 мл горячего бараньего или говяжьего бульона (домашнего или с пониженным содержанием соли)","150 г замороженного горошка","1 ст. л. нейтрального масла","1 ч. л. соли + 0,5 ч. л. свежемолотого чёрного перца для начинки","Для покрытия из пюре: 1 кг рассыпчатого картофеля (Maris Piper, King Edward или Yukon Gold), очищенного и нарезанного кусочками 4 см","60 г несолёного сливочного масла + 100 мл тёплого цельного молока + 2 крупных яичных желтка (желтки придают культовую золотистую хрустящую корочку) + 30 г тёртого выдержанного чеддера (необязательно, но традиционно)","0,5 ч. л. белого перца + 0,5 ч. л. соли для пюре"],"en":["600 g minced lamb (~15% fat — leaner than usual ground beef but with enough fat for moisture)","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), finely diced 0.5 cm (small dice — they should disappear into the filling)","4 garlic cloves, minced","1 tbsp tomato paste","1 tbsp Worcestershire sauce (the secret depth — non-negotiable)","1 tsp dried thyme (or 2 sprigs fresh)","1 tsp dried rosemary, finely chopped","2 tbsp plain flour (to thicken the gravy)","300 ml hot lamb or beef stock (homemade or low-salt)","150 g frozen peas","1 tbsp neutral oil","1 tsp salt + 0.5 tsp freshly ground black pepper for the filling","For the mash topping: 1 kg floury potatoes (Maris Piper, King Edward, or Yukon Gold), peeled and cut into 4 cm chunks","60 g unsalted butter + 100 ml warm whole milk + 2 large egg yolks (the yolks give the iconic golden crisp top) + 30 g grated mature cheddar (optional but traditional)","0.5 tsp white pepper + 0.5 tsp salt for the mash"],"ro":["600 g carne tocată de miel (~15% grăsime — mai slabă decât vita tocată obișnuită, dar cu suficientă grăsime pentru umiditate)","1 ceapă mare (~200 g), tăiată cubulețe fine","2 morcovi medii (~200 g), tăiați cubulețe fine de 0,5 cm (cubulețe mici — trebuie să dispară în umplutură)","4 căței de usturoi, tocați","1 lingură pastă de roșii","1 lingură sos Worcestershire (profunzimea secretă — nenegociabil)","1 linguriță cimbru uscat (sau 2 crenguțe proaspete)","1 linguriță rozmarin uscat, tocat fin","2 linguri făină albă (pentru a îngroșa sosul)","300 ml supă fierbinte de miel sau vită (de casă sau cu sare redusă)","150 g mazăre congelată","1 lingură ulei neutru","1 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat pentru umplutură","Pentru piureul de deasupra: 1 kg cartofi făinoși (Maris Piper, King Edward sau Yukon Gold), curățați și tăiați bucăți de 4 cm","60 g unt nesărat + 100 ml lapte integral cald + 2 gălbenușuri mari (gălbenușurile dau crusta aurie iconică) + 30 g cheddar maturat ras (opțional dar tradițional)","0,5 linguriță piper alb + 0,5 linguriță sare pentru piure"]},"howIsMade":{"ru":"ВАРИТЕ КАРТОФЕЛЬ: положите 1 кг очищенного и нарезанного кубиками картофеля в большую кастрюлю с холодной подсоленной водой (1 ст; соли на 2 л); доведите до кипения, уменьшите до постоянного слабого кипения и варите 15–18 минут, пока нож не будет легко проходить без сопротивления; слейте и верните в кастрюлю без огня на 2 минуты, чтобы испарилась влага — мокрый картофель даёт мокрое пюре; пРИГОТОВЬТЕ ПЮРЕ: пропустите сухой картофель через рисователь (лучше всего для пышного пюре) или разомните ручной мялкой. Вбейте 60 г сливочного масла, пока картофель ещё горячий, затем 100 мл тёплого молока в 3 приёма, взбивая между каждым; без огня вбейте 2 желтка, 0,5 ч; белого перца, 0,5 ч; соли; пюре должно быть глянцевым, гладким и достаточно жёстким, чтобы удерживать гребни — если оно слишком жидкое, верх осядет. Накройте фольгой, чтобы сохранить тепло; тОМИТЕ ОВОЩИ: нагрейте 1 ст; масла в большой тяжёлой сковороде на среднем огне; добавьте 200 г лука кубиками + 200 г моркови кубиками с щепоткой соли; готовьте, часто помешивая, 8–10 минут, пока не станут очень мягкими и морковь не потеряет хруст — они не размягчатся дальше, когда смешаются с мясом. Добавьте 4 измельчённых зубчика чеснока + тимьян + розмарин, готовьте ещё 1 минуту; оБЖАРЬТЕ ЯГНЯТИНУ: увеличьте огонь до средне-сильного; добавьте 600 г фарша из ягнятины и разломайте его деревянной ложкой; готовьте 8–10 минут, пока ягнятина не перестанет быть розовой И выделившийся жир не начнёт хрустеть мелкими кусочками на дне сковороды — это карамелизация Майяра является основой соуса; удалите ложкой весь скопившийся жир сверх 1 ст. (ягнятина выделяет много — слишком много делает пирог жирным); пОСТРОЙТЕ СОУС: вмешайте 1 ст; томатной пасты в ягнятину и готовьте 1 минуту до потемнения; посыпьте 2 ст; муки сверху и помешивайте 1–2 минуты, чтобы прожарить сырой вкус. Влейте 300 мл горячего бульона + 1 ст; соуса Вустершир + 1 ч; соли + 0,5 ч; перца, соскребая дно сковороды, чтобы поднять подрумяненные кусочки; тОМИТЕ + ГОРОШЕК: уменьшите огонь до малого и томите без крышки 15 минут, периодически помешивая, пока соус не загустеет до густой, глянцевой консистенции, обволакивающей мясо — он НЕ должен быть жидким, иначе пюре утонет. Вмешайте 150 г замороженного горошка (он прогреется в духовке); попробуйте и отрегулируйте приправы; сОБИРАЙТЕ: разогрейте духовку до 200 °C; переложите начинку из ягнятины в форму для запекания 23 × 30 см (ёмкость около 2 л); выложите пюре сверху ложкой, затем аккуратно разровняйте лопаткой, запечатывая до краёв. Проведите зубцами вилки длинными линиями по поверхности — эти гребни красиво хрустят в духовке; посыпьте 30 г тёртого чеддера сверху, если используете; зАПЕКАЙТЕ И ДАЙТЕ ОТДОХНУТЬ: поставьте форму на противень (ловит любые пузырящиеся капли); запекайте на средней полке 25–30 минут, пока верх не станет глубоко золотистым, гребни не будут хрустящими, а соус не будет заметно пузыриться по краям; дайте отдохнуть 10 минут перед подачей — начинка схватится и резка будет аккуратнее. Подавайте прямо из формы с зелёным салатом или капустой с маслом сбоку; ещё лучше на следующий день, разогретый до очень горячего состояния.","en":"1. BOIL THE POTATOES: place 1 kg peeled and cubed potatoes in a large pot of cold salted water (1 tbsp salt per 2 L), bring to a boil, then reduce to a steady simmer and cook 15–18 minutes until a knife slides through with no resistance; drain and return to the pot off the heat for 2 minutes to steam off, since wet potatoes make wet mash. 2. MAKE THE MASH: pass the dry potatoes through a ricer (best for fluffy mash) or mash with a hand masher, then beat in 60 g butter while still hot followed by 100 ml warm milk added in 3 stages, beating between each, and off the heat beat in 2 yolks, 0.5 tsp white pepper and 0.5 tsp salt until the mash is glossy, smooth and stiff enough to hold ridges (if it's too loose the topping will sink); cover with foil to keep warm. 3. SWEAT THE VEGETABLES: heat 1 tbsp oil in a large heavy skillet over medium heat, add 200 g diced onion and 200 g diced carrot with a pinch of salt, and cook, stirring often, 8–10 minutes until very soft and the carrots have lost their crunch (they will not soften further once mixed with meat), then stir in 4 minced garlic cloves, thyme and rosemary and cook 1 minute more. 4. BROWN THE LAMB: raise the heat to medium-high, add 600 g minced lamb and break it apart with a wooden spoon, then cook 8–10 minutes until the lamb is no longer pink and the released fat has begun to crisp small bits at the bottom of the pan (this Maillard browning is the foundation of the gravy), and spoon off any pooled fat over 1 tbsp, since lamb sheds a lot and too much makes the pie greasy. 5. BUILD THE GRAVY: stir 1 tbsp tomato paste into the lamb and cook 1 minute until darkened, sprinkle 2 tbsp flour over and stir 1–2 minutes to cook the raw taste out, then pour in 300 ml hot stock, 1 tbsp Worcestershire sauce, 1 tsp salt and 0.5 tsp pepper, scraping the bottom of the pan to lift the browned bits. 6. SIMMER + PEAS: reduce heat to low and simmer uncovered 15 minutes, stirring occasionally, until the gravy has thickened to a thick, glossy consistency that coats the meat (it should not be runny, or the mash will sink), then stir in 150 g frozen peas (they will warm through in the oven) and taste and adjust seasoning. 7. ASSEMBLE: preheat the oven to 200 °C and transfer the lamb filling to a 23 × 30 cm baking dish (about 2 L capacity), spoon the mash on top in dollops and spread carefully with a spatula sealing all the way to the edges, then drag the tines of a fork in long lines across the surface (these ridges crisp up beautifully in the oven) and scatter 30 g grated cheddar over the top if using. 8. BAKE & REST: place the dish on a baking sheet to catch any bubbling drips and bake on the middle rack 25–30 minutes until the top is deeply golden, the ridges are crisp, and the gravy is visibly bubbling around the edges, then rest 10 minutes before serving so the filling sets and slicing is cleaner, and serve straight from the dish with a green salad or buttered cabbage on the side (even better the next day, reheated until piping hot)."}},{"id":169,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Китай","en":"China","ro":"China"},"name":{"ru":"Мапо тофу","en":"Mapo Tofu","ro":"Mapo Tofu"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["600 г мягкого (шёлкового или средне-мягкого) тофу, нарезанного кубиками 2 см — текстура является частью блюда, не используйте твёрдый тофу","200 г фарша из свинины (~20% жирности — небольшое количество добавляет умами, не доминируя)","3 ст. л. нейтрального масла (рапсового или арахисового)","3 ст. л. сычуаньской пасты доубаньцзян Pixian (паста из бобов и чили) — ДУША блюда, не пропускайте и не заменяйте","1 ст. л. дочи (ферментированные чёрные бобы), промытые и крупно нарезанные","2 ч. л. сычуаньской пасты из бобов и чили (la doubanjiang) ИЛИ 1 ч. л. корейского кочуджана в качестве замены","4 зубчика чеснока, мелко нарезанных","4 см свежего имбиря, очищенного и натёртого","6 зелёных луковиц: белые части мелко нарезать для готовки + зелёные верхушки нарезать наискосок для украшения (хранить отдельно)","1,5 ст. л. тёмного соевого соуса (laochou)","1 ч. л. сахарного песка","300 мл горячего несолёного куриного бульона или воды","2 ч. л. сычуаньского перца (huajiao), обжаренного на сухой сковороде 60 сек и измельчённого в ступке","1,5 ст. л. кукурузного крахмала (cornflour), смешанного с 3 ст. л. холодной воды для финального крахмального соуса","2 ч. л. чилийного масла (la yu) для финального аккорда","1 ч. л. жареного кунжутного масла для последнего штриха","Для подачи: 320 г (1,6 стакана сухого) варёного жасминового или короткозерного риса"],"en":["600 g soft (silken or medium-soft) tofu, cut into 2 cm cubes — the texture is part of the dish, do not use firm tofu","200 g ground pork (~20% fat — the small amount adds umami without dominating)","3 tbsp neutral oil (rapeseed or peanut)","3 tbsp Pixian doubanjiang (Sichuan broad-bean chili paste) — the SOUL of the dish, do not skip or substitute","1 tbsp douchi (fermented black beans), rinsed and roughly chopped","2 tsp Sichuan chili bean paste (la doubanjiang) OR 1 tsp Korean gochujang as substitute","4 garlic cloves, finely minced","4 cm fresh ginger, peeled and grated","6 spring onions: the white parts finely chopped for cooking + the green tops cut diagonally for garnish (keep separate)","1.5 tbsp dark soy sauce (laochou)","1 tsp granulated sugar","300 ml hot unsalted chicken stock or water","2 tsp Sichuan peppercorns (huajiao), toasted in a dry pan 60 sec and crushed in a mortar","1.5 tbsp cornstarch (cornflour) mixed with 3 tbsp cold water for the final slurry","2 tsp chili oil (la yu) for finishing","1 tsp toasted sesame oil for the last drizzle","To serve: 320 g (1.6 cups dry) cooked jasmine rice or short-grain rice"],"ro":["600 g tofu moale (mătăsos sau mediu-moale), tăiat în cuburi de 2 cm — textura face parte din preparat, nu folosi tofu ferm","200 g carne tocată de porc (~20% grăsime — cantitatea mică adaugă umami fără a domina)","3 linguri ulei neutru (rapiță sau arahide)","3 linguri doubanjiang Pixian (pastă de fasole-chili din Sichuan) — SUFLETUL preparatului, nu omite și nu substitui","1 lingură douchi (fasole neagră fermentată), clătită și tocată grosier","2 lingurițe pastă de fasole-chili Sichuan (la doubanjiang) SAU 1 linguriță gochujang coreean ca substitut","4 căței de usturoi, tocați fin","4 cm ghimbir proaspăt, curățat și ras","6 cepe verzi: părțile albe tocate fin pentru gătit + vârfurile verzi tăiate oblic pentru ornament (păstrează separat)","1,5 linguri sos de soia închis (laochou)","1 linguriță zahăr granulat","300 ml supă fierbinte de pui nesărată sau apă","2 lingurițe boabe de piper sichuan (huajiao), prăjite într-o tigaie uscată 60 sec și zdrobite în mojar","1,5 linguri amidon de porumb (cornflour) amestecat cu 3 linguri apă rece pentru slurry-ul final","2 lingurițe ulei de chili (la yu) pentru finisare","1 linguriță ulei de susan prăjit pentru ultima stropire","Pentru servire: 320 g (1,6 căni uscat) orez jasmine fiert sau orez cu bob scurt"]},"howIsMade":{"ru":"ПОДГОТОВЬТЕ ТОФУ: доведите небольшую кастрюлю воды с 1 ч; л; соли до лёгкого кипения (не до бурного); аккуратно опустите кубики тофу 2 см и дайте прогреться 2 минуты — это уплотнит поверхность, чтобы они держали форму в соусе; аккуратно слейте и отставьте в тёплой кастрюле без огня. ОБЖАРЬТЕ СЫЧУАНЬСКИЙ ПЕРЕЦ: на сухой сковороде на среднем огне обжарьте 2 ч; л; сычуаньского перца 60 секунд до интенсивного аромата; высыпьте в ступку и крупно разотрите; отложите. ВЫТОПИТЕ СВИНИНУ: нагрейте 2 ст; л; нейтрального масла в воке или тяжёлой сковороде на сильном огне; добавьте 200 г фарша свинины и разломайте лопаткой; жарьте 4–5 минут, пока свинина не перестанет быть розовой, а мелкие кусочки не станут хрустящими и золотисто-коричневыми — разница в текстуре между хрустящей свининой и мягким тофу принципиальна. РАСПУСТИТЕ ДОУБАНЬЦЗЯН: сдвиньте свинину в сторону сковороды и добавьте в свободное пространство ещё 1 ст; л; масла; добавьте 3 ст; л; доубаньцзяна в масло и помешивайте 60–90 секунд, пока масло не станет насыщенно-красным — эта обжарка в масле раскрывает цвет и умами пасты; смешайте со свининой; добавьте нарезанный дочи + измельчённый чеснок + натёртый имбирь + 2 ч; л; la doubanjiang (или кочуджан) и жарьте, помешивая, 60 секунд до интенсивного аромата. ЖИДКОСТЬ: влейте 300 мл горячего бульона + 1,5 ст; л; тёмного соевого соуса + 1 ч; л; сахара; доведите до слабого кипения. ДОБАВЬТЕ ТОФУ: аккуратно опустите тёплые кубики тофу в кипящий соус; нЕ перемешивайте — используйте обратную сторону половника, чтобы погрузить их, затем аккуратно встряхните сковороду, чтобы они улеглись; томите 4–5 минут, иногда поливая верх тофу соусом, чтобы кубики впитали аромат, не ломаясь. ЗАГУСТИТЕ: ещё раз размешайте крахмальную смесь и влейте ПОЛОВИНУ в соус, затем встряхните сковороду и дайте покипеть 30 секунд; соус станет глянцевым и начнёт обволакивать тофу; если он всё ещё жидкий, добавьте оставшуюся часть смеси; готовый соус должен слегка прилипать к тофу, а не быть похожим на суп. ЗАВЕРШИТЕ И ПОДАВАЙТЕ: сняв с огня, сбрызните 2 ч; л; чилийного масла + 1 ч; л; жареного кунжутного масла поверх и посыпьте зелёными верхушками лука + растолчённым сычуаньским перцем; нЕ перемешивайте — горошины перца должны попасть на язык неразбавленными, чтобы дать ощущение ма (онемение); подавайте немедленно с горячим жасминовым рисом; каждый укус: рис + тофу + соус + перец = полный опыт ма-ла.","en":"PREP THE TOFU: bring a small pot of water with 1 tsp salt to a gentle simmer (not boil); slip the 2 cm tofu cubes in carefully and let them warm 2 minutes — this firms the surface so they hold their shape in the sauce; drain gently and set aside in the warm pot off the heat. TOAST SICHUAN PEPPERCORNS: in a dry pan over medium heat, toast 2 tsp Sichuan peppercorns 60 seconds until intensely fragrant; tip into a mortar and crush coarsely; set aside. RENDER THE PORK: heat 2 tbsp neutral oil in a wok or heavy skillet over medium-high heat; add 200 g ground pork and break it apart with a spatula; stir-fry 4–5 minutes until the pork is no longer pink and the small bits are crispy and golden brown — the texture difference between crisp pork and soft tofu is essential. BLOOM THE DOUBANJIANG: push the pork to the side of the pan and add 1 tbsp more oil to the empty space; add 3 tbsp doubanjiang to the oil and stir 60–90 seconds until the oil turns deep red — this oil-frying releases the colour and umami of the paste; stir into the pork; add chopped douchi + minced garlic + grated ginger + 2 tsp la doubanjiang (or gochujang) and stir-fry 60 seconds until intensely aromatic. LIQUID: pour in 300 ml hot stock + 1.5 tbsp dark soy sauce + 1 tsp sugar; bring to a simmer. ADD THE TOFU: slide the warm tofu cubes gently into the simmering sauce; do NOT stir — use the back of a ladle to push them under, then shake the pan gently to settle; simmer 4–5 minutes, basting the tops of the tofu with sauce occasionally, so the cubes absorb flavour without breaking. THICKEN: stir the cornstarch slurry one more time and pour HALF into the sauce, then shake the pan and let it simmer 30 seconds; the sauce will turn glossy and start to coat the tofu; if still thin, add the rest of the slurry; the finished sauce should cling lightly to the tofu, not be soupy. FINISH AND SERVE: off the heat, drizzle 2 tsp chili oil + 1 tsp toasted sesame oil over the surface and scatter the green spring-onion tops + crushed Sichuan peppercorns; do NOT stir — the peppercorns must hit your tongue undiluted for the ma (numbing) sensation; serve immediately with hot jasmine rice; each bite: rice + tofu + sauce + peppercorn = the full ma-la experience."}},{"id":170,"servings":2,"tipType":"veg","pairingsType":"veg","origin":{"ru":"Турция","en":"Turkey","ro":"Turcia"},"name":{"ru":"Менемен","en":"Menemen","ro":"Menemen"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ru":["6 крупных яиц, комнатной температуры","3 ст. л. турецкого или оливкового масла extra-virgin","2 сиври-бибер (длинные зелёные турецкие перцы, слегка острые) ИЛИ 1 зелёный болгарский перец + 1 халапеньо как замена (~150 г в сумме), без семян и мелко нарезанные","4 спелых помидора (~500 г), очищенные от кожуры и грубо натёртые на крупной тёрке (кожица остаётся в руке, только мякоть проходит через тёрку — это турецкая техника)","1 ст. л. томатной пасты (salça) — по желанию, углубляет красный цвет","1 ч. л. pul biber (турецкие хлопья красного перца, стиль Алеппо или Мараш) — добавляет тепло без агрессивной остроты","0,5 ч. л. сушёного орегано","0,5 ч. л. соли + свежемолотый чёрный перец","30 г beyaz peynir (типа феты), раскрошенного (опционально, региональная эгейская добавка)","1 небольшая горсть плосколистной петрушки, мелко нарезанной, для финиша","1 маленький пучок шнитт-лука или зелени зелёного лука, мелко нарезанный (опционально)","Для подачи: 4 толстых ломтика свежего экмека (деревенский хлеб) ИЛИ 2 симита (турецкие кунжутные бублики), крепко заваренный турецкий чёрный чай (çay)","Заметка о региональных дебатах: эта версия БЕЗ лука (стамбульский стиль); для эгейской версии добавьте 1 маленькую луковицу мелко нарезанную и обжарьте 4 мин до перцев"],"en":["6 large eggs, at room temperature","3 tbsp Turkish or extra-virgin olive oil","2 sivri biber (long green Turkish peppers, mildly hot) OR 1 green bell pepper + 1 jalapeño as substitute (~150 g total), seeds removed and finely diced","4 ripe tomatoes (~500 g), peeled and roughly grated on a box grater (the skin holds back, only the pulp grates through — this is the Turkish technique)","1 tbsp tomato paste (salça) — optional, deepens the red","1 tsp pul biber (Turkish red pepper flakes, Aleppo or Maraş-style) — adds warmth without harsh heat","0.5 tsp dried oregano","0.5 tsp salt + freshly ground black pepper","30 g feta-style beyaz peynir, crumbled (optional, regional Aegean addition)","1 small handful flat-leaf parsley, finely chopped, to finish","1 small bunch chives or spring onion green, finely chopped (optional)","To serve: 4 thick slices of fresh ekmek country bread OR 2 simit (Turkish sesame bagels), Turkish black tea (çay) brewed strong","Note on regional debate: this version is WITHOUT onion (Istanbul-style); if making the Aegean-style, add 1 small onion finely diced and cook 4 min before the peppers"],"ro":["6 ouă mari, la temperatura camerei","3 linguri ulei de măsline turcesc sau extravirgin","2 sivri biber (ardei lungi verzi turcești, ușor iuți) SAU 1 ardei gras verde + 1 jalapeño ca substitut (~150 g total), fără semințe și tocați fin","4 roșii coapte (~500 g), opărite și răzuite grosier pe răzătoarea cu găuri mari (coaja rămâne în mână, doar pulpa trece prin răzătoare — aceasta este tehnica turcească)","1 lingură pastă de roșii (salça) — opțional, adâncește roșul","1 linguriță pul biber (fulgi de ardei roșu turcesc, stil Aleppo sau Maraș) — adaugă căldură fără iuțeală agresivă","0,5 linguriță oregano uscat","0,5 linguriță sare + piper negru proaspăt măcinat","30 g beyaz peynir tip feta, fărâmițat (opțional, adaos regional egeean)","1 mână mică de pătrunjel cu frunza lată, tocat fin, pentru finisare","1 legătură mică de arpagic sau partea verde a cepei verzi, tocată fin (opțional)","Pentru servire: 4 felii groase de ekmek proaspăt (pâine de țară) SAU 2 simit (covrigi turcești cu susan), ceai negru turcesc (çay) preparat tare","Notă despre dezbaterea regională: această versiune este FĂRĂ ceapă (stil Istanbul); dacă faci versiunea egeeană, adaugă 1 ceapă mică tocată fin și gătește 4 minute înainte de ardei"]},"howIsMade":{"ru":"ОЧИСТИТЕ И НАТРИТЕ ПОМИДОРЫ: сделайте неглубокий крестообразный надрез на дне каждого из 4 спелых помидоров; опустите в кипящую воду на 30 секунд, затем переложите в ледяную воду; кожица легко снимается; разрежьте каждый помидор пополам горизонтально и потрите срезом о грубую сторону коробчатой тёрки, поставленной над миской — мякоть проходит через тёрку, а пустая кожица остаётся у вас в руке; эта турецкая техника даёт мякотную, сочную томатную основу без кусочков кожуры. ПРИГОТОВЬТЕ ПЕРЦЫ: разогрейте 3 ст; л; оливкового масла в тяжёлой сковороде 24 см (чугунной или керамической sahan традиционно) на среднем огне; добавьте 150 г мелко нарезанных зелёных перцев и готовьте, часто помешивая, 5–6 минут, пока они не размягчатся и слегка не подрумянятся по краям, но всё ещё ярко-зелёные — не дайте им подрумяниться. ДОБАВЬТЕ ТОМАТНУЮ ПАСТУ: вмешайте 1 ст; л; томатной пасты в перцы и готовьте 30 секунд — salça углубляет цвет и умами; (Пропустите этот шаг, если не используете пасту.). ДОБАВЬТЕ НАТЁРТЫЕ ПОМИДОРЫ: влейте натёртую томатную мякоть + 1 ч; л; pul biber + 0,5 ч; л; орегано + 0,5 ч; л; соли и щедрый поворот чёрного перца; доведите до слабого кипения и готовьте 6–8 минут, иногда помешивая, пока помидор не уменьшится наполовину и не будет выглядеть как джем — низ лопатки должен проводить чёткую линию через соус, которая не заполняется сразу. ПОДГОТОВЬТЕ ЯЙЦА: пока помидоры готовятся, разбейте 6 яиц в миску по одному — НЕ взбивайте; яйца идут в сковороду целыми или едва разбитыми, с нетронутыми желтками в начале. ДОБАВЬТЕ ЯЙЦА: когда помидор станет как джем, уменьшите огонь до средне-низкого; аккуратно соскользните яйца на сковороду, разместив их по поверхности; оставьте их на 30 секунд, не трогая, чтобы они схватились на дне. СЛЕГКА ВЗБИВАЙТЕ: деревянной ложкой осторожно проталкивайте яйца через помидоры медленными движениями в форме восьмёрки — НЕ перемешивайте энергично; белки должны схватиться в ленты, а желтки должны разбиться и протянуться через соус золотыми завитками; готовьте всего 90 секунд–2 минуты — менемен должен оставаться глянцевым и едва схватившимся, НЕ сухим, как яичница-болтунья; снимите с огня, пока он ещё слегка влажный — он продолжает готовиться в горячей сковороде. ПОДАВАЙТЕ ИЗ СКОВОРОДЫ: посыпьте 30 г раскрошенной феты + нарезанной петрушкой (и шнитт-луком, если используется); принесите сковороду прямо к столу — менемен всегда едят прямо из сковороды, отрывая хлеб и обмакивая в соус; подавайте с крепким турецким чёрным чаем; лучше всего съесть в течение 5 минут после приготовления, пока он тёплый и глянцевый.","en":"PEEL AND GRATE THE TOMATOES: cut a shallow cross in the bottom of each of 4 ripe tomatoes; drop into boiling water 30 seconds, then transfer to ice water; the skins peel off easily; halve each tomato horizontally and rub the cut sides against the coarse side of a box grater placed over a bowl — the flesh grates through and the empty skin remains in your hand; this Turkish technique gives a pulpy, juicy tomato base with no skin pieces. COOK THE PEPPERS: heat 3 tbsp olive oil in a heavy 24 cm skillet (cast iron or earthenware sahan is traditional) over medium heat; add 150 g finely diced green peppers and cook stirring often 5–6 minutes until softened and slightly blistered at the edges but still bright green — do not let them brown. ADD TOMATO PASTE: stir 1 tbsp tomato paste into the peppers and cook 30 seconds — the salça deepens the colour and umami; (Skip this step if not using paste.). ADD GRATED TOMATOES: pour in the grated tomato pulp + 1 tsp pul biber + 0.5 tsp oregano + 0.5 tsp salt and a generous twist of black pepper; bring to a simmer and cook 6–8 minutes, stirring occasionally, until the tomato has reduced by half and looks jammy — the bottom of the spatula should drag a clear line through the sauce that does not fill in immediately. PREP THE EGGS: while the tomatoes cook, crack 6 eggs into a bowl one at a time — DO NOT beat them; the eggs go into the pan whole or barely broken, with yolks intact at first. ADD THE EGGS: when the tomato is jammy, lower the heat to medium-low; slip the eggs gently into the pan, spaced around the surface; let them sit 30 seconds undisturbed to set on the bottom. SCRAMBLE LIGHTLY: with a wooden spoon, push the eggs gently through the tomato in slow figure-eight motions — DO NOT vigorously stir; the whites should set into ribbons and the yolks should break and streak through the sauce in golden swirls; cook 90 seconds–2 minutes only — the menemen should remain glossy and barely-set, NOT scrambled-egg-dry; take off the heat while still slightly wet — it continues cooking in the hot pan. SERVE FROM THE PAN: scatter 30 g crumbled feta + chopped parsley (and chives if using); bring the pan straight to the table — menemen is always eaten from the pan with bread torn and dipped into the sauce; serve with strong Turkish black tea; best eaten within 5 minutes of cooking, while warm and glossy."}},{"id":171,"servings":4,"tipType":"meat","pairingsType":"soup","origin":{"ru":"Россия","en":"Russia","ro":"Rusia"},"name":{"ru":"Солянка","en":"Solyanka","ro":"Solyanka"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["500 г говяжьей грудинки или голяшки на кости (для бульона)","2 л холодной воды для бульона + 1 луковица + 1 морковь + 2 лавровых листа + 5 горошин чёрного перца + 1 ч. л. соли для бульона","200 г копчёной кильбасы или краковской, нарезанной кружочками 5 мм","150 г варёной ветчины, нарезанной кубиками 1 см (или варёный язык, традиционно)","100 г салями или охотничьих колбасок, нарезанных тонкими ломтиками","2 крупных солёных огурца (~250 г, малосольных или полностью солёных), нарезанных тонкой соломкой; сохраните 100 мл огуречного рассола","1 крупная луковица (~200 г), мелко нарезанная","1 ст. л. томатной пасты","200 г натёртых помидоров (или 1 банка 200 г, без жидкости)","2 ст. л. сливочного масла или 30 г топлёного говяжьего жира для зажарки","80 г маслин без косточек (типа калмата) + 80 г оливок без косточек","2 ст. л. каперсов, без рассола","1 лимон, нарезанный тонкими полумесяцами","1 лавровый лист + 0,5 ч. л. молотого чёрного перца + 1 ч. л. паприки (по желанию, для цвета)","Небольшой пучок свежего укропа, мелко нарезанного","200 г сметаны для подачи","Для подачи: 4 толстых ломтика свежего тёмного ржаного хлеба, по желанию 1 ст. л. хрена"],"en":["500 g beef brisket or shin on the bone (for the broth)","2 L cold water for the broth + 1 onion + 1 carrot + 2 bay leaves + 5 black peppercorns + 1 tsp salt for the stock","200 g smoked kielbasa or krakovskaya, sliced 5 mm thick","150 g cooked ham, cut into 1 cm cubes (or boiled tongue, traditional)","100 g salami or hunting sausage, sliced thin","2 large pickled cucumbers (~250 g, half-sour or fully sour), cut into thin matchsticks; reserve 100 ml of the pickle brine","1 large onion (~200 g), finely diced","1 tbsp tomato paste","200 g grated tomatoes (or 1 × 200 g canned, drained)","2 tbsp butter or 30 g rendered beef fat for the soffritto","80 g pitted black olives (kalamata-style) + 80 g pitted green olives","2 tbsp capers, drained","1 lemon, sliced into thin half-moons","1 bay leaf + 0.5 tsp ground black pepper + 1 tsp paprika (optional, for color)","A small bunch fresh dill, finely chopped","200 g smetana (sour cream) for serving","To serve: 4 thick slices of fresh dark rye bread, optional 1 tbsp horseradish (khren)"],"ro":["500 g piept de vită sau rasol cu os (pentru supă)","2 L apă rece pentru supă + 1 ceapă + 1 morcov + 2 foi de dafin + 5 boabe de piper negru + 1 linguriță sare pentru bulion","200 g kielbasa afumată sau cracovskaya, tăiată felii de 5 mm","150 g șuncă fiartă, tăiată cuburi de 1 cm (sau limbă fiartă, tradițional)","100 g salam sau cârnați de vânătoare, tăiat felii subțiri","2 castraveți murați mari (~250 g, semi-acri sau acri complet), tăiați fâșii subțiri; păstrează 100 ml din zeama de murături","1 ceapă mare (~200 g), tocată fin","1 lingură pastă de roșii","200 g roșii răzuite (sau 1 × 200 g din conservă, scurse)","2 linguri unt sau 30 g grăsime de vită topită pentru sotă","80 g măsline negre fără sâmburi (gen kalamata) + 80 g măsline verzi fără sâmburi","2 linguri capere, scurse","1 lămâie, tăiată felii subțiri în formă de semilună","1 foaie de dafin + 0,5 linguriță piper negru măcinat + 1 linguriță boia (opțional, pentru culoare)","O legăturică mică de mărar proaspăt, tocat fin","200 g smetana (smântână) pentru servire","Pentru servire: 4 felii groase de pâine de secară neagră proaspătă, opțional 1 lingură hrean (khren)"]},"howIsMade":{"ru":"БУЛЬОН: положите 500 г говяжьей грудинки в большую кастрюлю с 2 л холодной воды; доведите до кипения и тщательно снимайте пену в первые 5 минут — это даёт прозрачный бульон; добавьте 1 целую луковицу, разрезанную на четверти + 1 целую морковь + 2 лавровых листа + 5 горошин перца + 1 ч; л; соли; уменьшите до слабого кипения и варите под крышкой 1,5 часа, пока мясо полностью не станет мягким. ПРОЦЕДИТЕ И ИЗМЕЛЬЧИТЕ: достаньте говядину и дайте ей немного остыть; процедите бульон через мелкое сито обратно в чистую кастрюлю — у вас должно получиться около 1,5 л прозрачного, ароматного бульона; нарежьте говядину поперёк волокон на полоски размером с укус, удаляя любые жёсткие жилы. ЗАЖАРКА: в широкой сковороде растопите 2 ст; л; сливочного масла на среднем огне; добавьте 200 г мелко нарезанного лука и обжаривайте 6–8 минут, пока он не станет мягким и прозрачным; вмешайте 1 ст; л; томатной пасты и готовьте 1 минуту, пока она не потемнеет; добавьте 200 г натёртых помидоров и готовьте 4–5 минут, пока смесь не уменьшится, и масло не начнёт появляться на поверхности. ДОБАВЬТЕ СОЛЁНЫЕ ОГУРЦЫ: вмешайте соломку огурцов в зажарку и готовьте 3–4 минуты; огурцы должны прогреться, не перевариться — они должны сохранить немного хруста для контраста текстуры. ОБЖАРЬТЕ КОЛБАСЫ: в отдельной сухой сковороде на среднем огне обжарьте ломтики копчёной кильбасы, кубики ветчины и ломтики салями 4–5 минут, пока они слегка не подрумянятся по краям, и жир не вытопится; этот шаг не подлежит обсуждению — обжаривание мяса перед добавлением в бульон — это то, что даёт солянке её глубокий, копчёный характер. СОБЕРИТЕ СУП: влейте зажарку в процеженный бульон и вмешайте обжаренные колбасы, ветчину, салями и измельчённую говядину; добавьте сохранённые 100 мл огуречного рассола + 1 лавровый лист + 0,5 ч; л; молотого перца + 1 ч; л; паприки; доведите до слабого кипения. ТОМИТЕ: готовьте на низком огне 15–20 минут, частично накрыв крышкой, чтобы ароматы соединились; добавьте маслины + каперсы только в последние 5 минут — они должны прогреться, но сохранить форму; попробуйте и отрегулируйте соль — большая часть солёности приходит от огурцов, каперсов, оливок и рассола, поэтому действуйте осторожно. ПОДАВАЙТЕ: разлейте горячую солянку по глубоким мискам; в каждую миску добавьте 1 тонкий ломтик лимона (целый, с цедрой), щедрую ложку сметаны и щепотку нарезанного укропа; чёрный перец по вкусу; подавайте немедленно с толстыми ломтиками свежего тёмного ржаного хлеба сбоку — солянка это основное блюдо, а не суп-закуска; по русской традиции, это классическое восстанавливающее средство после торжества.","en":"THE BROTH: place 500 g beef brisket in a large pot with 2 L cold water; bring to a boil and skim the foam thoroughly for the first 5 minutes — this gives a clear broth; add 1 whole quartered onion + 1 whole carrot + 2 bay leaves + 5 peppercorns + 1 tsp salt; reduce to a gentle simmer and cook covered 1.5 hours until the meat is fully tender. STRAIN AND SHRED: lift the beef out and let it cool slightly; strain the broth through a fine sieve back into a clean pot — you should have about 1.5 L of clear, savoury broth; cut the beef across the grain into bite-sized strips, discarding any tough sinew. SOFFRITTO: in a wide skillet, melt 2 tbsp butter over medium heat; add 200 g finely diced onion and sauté 6–8 minutes until soft and translucent; stir in 1 tbsp tomato paste and cook 1 minute until darkened; add the 200 g grated tomatoes and cook 4–5 minutes until the mixture has reduced and the oil starts to appear on the surface. ADD PICKLES: stir the cucumber matchsticks into the soffritto and cook 3–4 minutes; the pickles should be warmed through, not over-softened — they need to keep some crunch for texture contrast. FRY THE SAUSAGES: in a separate dry pan over medium heat, fry the smoked kielbasa slices, ham cubes, and salami slices 4–5 minutes until lightly browned at the edges and the fat has rendered; this step is non-negotiable — searing the meats before adding them to the broth is what gives solyanka its deep, smoky character. ASSEMBLE THE SOUP: pour the soffritto into the strained broth and stir in the seared sausages, ham, salami, and shredded beef; add the reserved 100 ml pickle brine + 1 bay leaf + 0.5 tsp ground pepper + 1 tsp paprika; bring to a gentle simmer. SIMMER: cook over low heat 15–20 minutes, partially covered, for the flavours to marry; add the olives + capers in the last 5 minutes only — they should warm through but keep their shape; taste and adjust salt — most of the saltiness comes from the pickles, capers, olives, and brine, so go cautiously. SERVE: ladle the hot solyanka into deep bowls; to each bowl add 1 thin lemon slice (whole, peel on), a generous spoonful of smetana, and a scatter of chopped dill; black pepper to taste; serve immediately with thick slices of fresh dark rye bread on the side — solyanka is a main course, not a starter; in Russian tradition, this is the classic post-celebration restorative."}},{"id":172,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ru":"США","en":"USA","ro":"SUA"},"name":{"ru":"Клэм чаудер","en":"Clam Chowder","ro":"Clam Chowder"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1,5 кг свежих моллюсков littleneck или quahog в раковинах (или 2 × 200 г консервов целых маленьких моллюсков в соку как замена для поваров далеко от моря)","500 мл свежего сока моллюсков или рыбного бульона (сохраните всю жидкость от варки на пару, если используете свежих моллюсков)","150 г толсто нарезанного копчёного бекона, кубиками 0,5 см","1 крупная жёлтая луковица (~250 г), мелко нарезанная","2 средних стебля сельдерея (~120 г), мелко нарезанных","4 зубчика чеснока, измельчённых (по желанию — пуристы Бостона хмурятся, но большинство современных рецептов включают)","30 г несолёного сливочного масла","30 г универсальной муки (для ру)","750 г мучнистого картофеля (Yukon Gold или russet), очищенного и нарезанного кубиками 1,5 см","250 мл цельного молока","250 мл жирных сливок (или пополам для более лёгкой версии)","2 лавровых листа + 1 ч. л. сушёного тимьяна + 0,5 ч. л. свежемолотого чёрного перца","0,5 ч. л. соли (сначала попробуйте — сок моллюсков солёный)","Щепотка кайенского перца или 1 капля острого соуса (по желанию)","Маленький пучок свежего шнитт-лука, мелко нарезанного, и 2 ст. л. свежей петрушки с плоскими листьями для украшения","Для подачи: 4 маленькие выдолбленные булочки из закваски как съедобные миски ИЛИ устричные крекеры (традиционный гарнир Новой Англии); 1 лимон, нарезанный дольками"],"en":["1.5 kg fresh littleneck or quahog clams in shells (or 2 × 200 g cans whole baby clams in juice as substitute for landlocked cooks)","500 ml fresh clam juice or fish stock (reserve all the steaming liquid if using fresh clams)","150 g thick-cut smoked bacon, diced 0.5 cm","1 large yellow onion (~250 g), finely diced","2 medium celery stalks (~120 g), finely diced","4 garlic cloves, minced (optional — Boston purists frown but most modern recipes include)","30 g unsalted butter","30 g all-purpose flour (for the roux)","750 g floury potatoes (Yukon Gold or russet), peeled and cut into 1.5 cm cubes","250 ml whole milk","250 ml heavy cream (or half-and-half for a lighter version)","2 bay leaves + 1 tsp dried thyme + 0.5 tsp freshly ground black pepper","0.5 tsp salt (taste first — clam juice is salty)","A pinch of cayenne or 1 dash hot sauce (optional)","1 small bunch fresh chives, finely chopped, and 2 tbsp fresh flat-leaf parsley to garnish","To serve: 4 small hollowed-out sourdough rolls as edible bread bowls OR oyster crackers (a traditional New England side); 1 lemon, sliced into wedges"],"ro":["1,5 kg scoici proaspete (littleneck sau quahog) în cochilii (sau 2 × 200 g conserve de scoici mici întregi în suc, ca substitut pentru cei departe de mare)","500 ml suc de scoici proaspăt sau fond de pește (rezervă tot lichidul de aburire dacă folosești scoici proaspete)","150 g bacon afumat tăiat gros, cuburi de 0,5 cm","1 ceapă galbenă mare (~250 g), tăiată mărunt","2 tulpini medii de țelină (~120 g), tăiate mărunt","4 căței de usturoi, tocați (opțional — puriștii din Boston dezaprobă, dar majoritatea rețetelor moderne îi includ)","30 g unt nesărat","30 g făină universală (pentru roux)","750 g cartofi făinoși (Yukon Gold sau russet), curățați și tăiați cuburi de 1,5 cm","250 ml lapte integral","250 ml smântână grasă (sau jumătate-jumătate pentru o versiune mai ușoară)","2 foi de dafin + 1 linguriță cimbru uscat + 0,5 linguriță piper negru proaspăt măcinat","0,5 linguriță sare (gustă întâi — sucul de scoici este sărat)","Un vârf de cayenne sau 1 strop de sos iute (opțional)","O legăturică mică de arpagic proaspăt, tocat fin, și 2 linguri de pătrunjel proaspăt cu frunze plate pentru garnitură","Pentru servire: 4 chifle mici de sourdough scobite ca boluri comestibile SAU biscuiți pentru stridii (un acompaniament tradițional al Noii Anglii); 1 lămâie, tăiată felii pentru garnitură"]},"howIsMade":{"ru":"Промойте 1,5 кг свежих моллюсков в холодной воде 2–3 раза, чтобы удалить песок; выбросьте те, что открыты и не закрываются при постукивании; положите их в широкую кастрюлю с 250 мл воды, накройте и готовьте на пару на сильном огне 4–5 минут, пока раковины едва не откроются; выбросьте те, что остались закрытыми; достаньте моллюсков, оставив жидкость от пара. Процедите эту жидкость через мелкое сито, выстеленное влажной марлей, в мерный стакан — у вас должно быть ~400–500 мл чистого бульона из моллюсков; извлеките мясо моллюсков из раковин, крупно нарежьте и отложите; (Если используете консервированных моллюсков, просто слейте, сохранив сок, и используйте 500 мл рыбного бульона + сок из банки.); в тяжёлую кастрюлю 5 л или голландскую печь на среднем огне добавьте 150 г нарезанного кубиками бекона; готовьте, часто помешивая, 6–8 минут, пока бекон не станет глубоко коричневым и большая часть жира не вытопится. Снимите хрустящий бекон шумовкой на бумажное полотенце и отложите для украшения; оставьте 3 ст; жира бекона в кастрюле; добавьте 250 г нарезанного лука + 120 г нарезанного сельдерея в жир бекона с щепоткой соли; готовьте, часто помешивая, 8–10 минут, пока они не станут мягкими и прозрачными, но не подрумяненными — чаудер белый, цвет здесь не нужен. Добавьте 4 измельчённых зубчика чеснока и готовьте ещё 1 минуту; добавьте 30 г сливочного масла и дайте ему растаять; посыпьте 30 г муки на овощи и постоянно помешивайте деревянной ложкой 2 минуты, выпаривая сырой вкус муки, не давая ей потемнеть — это белый ру; вливайте процеженный бульон из моллюсков медленной устойчивой струёй, постоянно взбивая венчиком, чтобы избежать комков; добавьте 750 г кубиков картофеля + 2 лавровых листа + 1 ч. тимьяна + 0,5 ч; чёрного перца; доведите до слабого кипения; готовьте без крышки 15–18 минут, периодически помешивая, пока картофель не станет мягким, но сохранит форму — проткните один ножом, и он должен входить без сопротивления; уменьшите огонь до минимума. Вмешайте 250 мл цельного молока и 250 мл жирных сливок — НЕ давайте кипеть после добавления молочных продуктов, иначе сливки свернутся; прогрейте 3 минуты; вмешайте нарезанное мясо моллюсков и большую часть бекона (сохраните 2 ст; бекона и весь шнитт-лук для украшения); готовьте ещё 3 минуты, пока моллюски не прогреются — переваривание делает их жёсткими и резиновыми. Удалите лавровые листья; попробуйте и отрегулируйте приправу солью и щепоткой кайенского, если хотите; выдолбите 4 маленькие булочки из закваски (или используйте устричные крекеры как традиционный более простой вариант); разлейте горячий чаудер в хлебные миски или глубокие тарелки для супа; украсьте каждую сохранённым хрустящим беконом, щедрой посыпкой шнитт-лука и петрушки и свежим поворотом чёрного перца. Подавайте немедленно с дольками лимона сбоку; ресторан Новой Англии обычно приносит небольшое блюдце устричных крекеров и острый соус для стола.","en":"Rinse 1.5 kg fresh clams in cold water 2-3 times to remove sand and discard any that are open and do not close when tapped, then place them in a wide pot with 250 ml water, cover and steam over high heat for 4-5 minutes until the shells just open, discarding any that stayed shut. Lift the clams out and strain the steaming liquid through a fine sieve lined with damp cheesecloth into a measuring cup, aiming for ~400-500 ml of clean clam broth, then pick the clam meat from the shells, roughly chop it, and set aside (if using canned clams, drain them reserving the juice and use the 500 ml fish stock plus the canned juice). In a heavy 5 L pot or Dutch oven over medium heat, add 150 g diced bacon and cook stirring often for 6-8 minutes until the bacon is deeply browned and most of the fat has rendered, then lift the crispy bacon onto a paper towel and set aside for garnish, leaving 3 tbsp of bacon fat in the pot. Add 250 g diced onion and 120 g diced celery to the bacon fat with a pinch of salt and cook stirring often for 8-10 minutes until soft and translucent but not browned (chowder is white, so you do not want colour here), then add 4 minced garlic cloves and cook 1 minute more. Add 30 g butter and let it melt, then sprinkle 30 g flour over the vegetables and stir constantly with a wooden spoon for 2 minutes, cooking out the raw flour taste without letting it darken to keep a white roux. Pour in the strained clam broth in a slow steady stream while whisking constantly to prevent lumps, add 750 g potato cubes, 2 bay leaves, 1 tsp thyme, and 0.5 tsp black pepper, bring to a gentle simmer, then cook uncovered for 15-18 minutes stirring occasionally until the potatoes are tender but still hold their shape and a knife slides in with no resistance. Lower the heat to its lowest setting and stir in 250 ml whole milk and 250 ml heavy cream, taking care not to let it boil after adding dairy or the cream will curdle, then warm through for 3 minutes before stirring in the chopped clam meat and most of the bacon (saving 2 tbsp of bacon and all the chives for garnish), and simmer 3 more minutes until the clams are just heated through (overcooking turns them tough and rubbery), then remove the bay leaves and taste, adjusting seasoning with salt and a pinch of cayenne if you like. Hollow out 4 small sourdough rolls (or use oyster crackers as a traditional simpler option), ladle the hot chowder into the bread bowls or deep soup plates, top each with the reserved crispy bacon, a generous scatter of chives and parsley, and a fresh twist of black pepper, and serve immediately with lemon wedges on the side, just as a New England restaurant typically brings a small dish of oyster crackers and a side of hot sauce to the table."}},{"id":173,"servings":2,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Германия","en":"Germany","ro":"Germania"},"name":{"ru":"Карривурст","en":"Currywurst","ro":"Currywurst"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["4 берлинские свиные сосиски Bratwurst (~120 г каждая, всего ~480 г) — свежие, не предварительно прожаренные; или замените тонкими Bockwurst или Frankfurter, если Bratwurst недоступны","2 ст. л. нейтрального масла (подсолнечного) для жарки сосисок","Для соуса карри: 200 г качественного томатного кетчупа (Heinz или немецкий Hela)","100 мл пассаты или 1 ст. л. томатной пасты + 80 мл воды как замена","2 ст. л. среднеострого порошка карри (жёлтая смесь стиля Мадрас) — оригинал Герты Хойвер использовал аналогичный британский колониальный порошок карри","1 ч. л. сладкой венгерской паприки","0,5 ч. л. копчёной паприки (по желанию, добавляет глубину)","1 ст. л. соуса Worcestershire (секрет оригинала Хойвер — не подлежит обсуждению)","1 ст. л. яблочного уксуса ИЛИ белого винного уксуса","1 ст. л. белого сахара (помогает сбалансировать уксус и подчеркнуть томат)","0,5 ч. л. молотого душистого перца + 0,5 ч. л. молотого имбиря ('секретная' смесь тёплых специй, которую добавляла Хойвер)","0,5 ч. л. соли + щепотка кайенского перца или острого чили","Для подачи: дополнительный порошок карри для посыпки сверху + 2 порции Pommes Frites (около 400 г горячего хрустящего картофеля фри из духовки или фритюрницы) или 2 маленьких Brötchen; 2 маленькие деревянные вилочки (Pommespieker) для аутентичного берлинского опыта"],"en":["4 Berliner-style Bratwurst pork sausages (~120 g each, total ~480 g) — fresh, not pre-grilled; or substitute fine Bockwurst or Frankfurter if Bratwurst unavailable","2 tbsp neutral oil (sunflower) for frying the sausages","For the curry sauce: 200 g good-quality tomato ketchup (Heinz or German Hela)","100 ml passata or 1 tbsp tomato paste + 80 ml water as substitute","2 tbsp medium-hot curry powder (a yellow Madras-style blend) — Herta Heuwer's original used a similar British colonial curry powder","1 tsp sweet Hungarian paprika","0.5 tsp smoked paprika (optional, adds depth)","1 tbsp Worcestershire sauce (the secret of Heuwer's original — not negotiable)","1 tbsp apple cider vinegar OR white wine vinegar","1 tbsp white sugar (helps balance the vinegar and brings out the tomato)","0.5 tsp ground allspice + 0.5 tsp ground ginger (the 'secret' warm-spice mix Heuwer added)","0.5 tsp salt + a pinch of cayenne or hot chili powder","To serve: extra curry powder for dusting on top + 2 portions of Pommes Frites (about 400 g hot crispy fries from the oven or fryer), or 2 small Brötchen rolls; 2 small wooden forks (Pommespieker) for the authentic Berlin experience"],"ro":["4 cârnați Bratwurst de Berlin din porc (~120 g fiecare, total ~480 g) — proaspeți, nu pre-grătar; sau substituție cu Bockwurst fin sau Frankfurter dacă Bratwurst nu este disponibil","2 linguri ulei neutru (floarea-soarelui) pentru prăjirea cârnaților","Pentru sosul de curry: 200 g ketchup de tomate de bună calitate (Heinz sau german Hela)","100 ml passata sau 1 lingură pastă de tomate + 80 ml apă ca substitut","2 linguri pudră de curry medie-iute (un amestec galben stil Madras) — originalul Herta Heuwer folosea o pudră de curry similară colonială britanică","1 linguriță paprika dulce maghiară","0,5 linguriță paprika afumată (opțional, adaugă profunzime)","1 lingură sos Worcestershire (secretul originalului Heuwer — nu este negociabil)","1 lingură oțet de cidru de mere SAU oțet de vin alb","1 lingură zahăr alb (ajută la echilibrarea oțetului și scoate în evidență tomatele)","0,5 linguriță piment ienibahar + 0,5 linguriță ghimbir măcinat (amestecul 'secret' de mirodenii calde pe care Heuwer le-a adăugat)","0,5 linguriță sare + un vârf de cayenne sau chili iute","Pentru servire: pudră de curry suplimentară pentru presărare deasupra + 2 porții de Pommes Frites (aproximativ 400 g cartofi prăjiți fierbinți și crocanți din cuptor sau friteuză), sau 2 Brötchen mici; 2 furculițe mici de lemn (Pommespieker) pentru experiența autentică berlineză"]},"howIsMade":{"ru":"ПРОКОЛИТЕ СОСИСКИ: достаньте 4 Bratwurst из холодильника за 15 минут до приготовления, чтобы они приблизились к комнатной температуре; проколите каждую сосиску 4–5 раз вилкой — это предотвратит разрыв кожицы на сковороде и позволит части жира вытопиться. ПРИГОТОВЬТЕ СОУС КАРРИ: в маленькой кастрюле смешайте 200 г кетчупа + 100 мл пассаты + 2 ст; л; порошка карри + 1 ч; л; сладкой паприки + 0,5 ч; л; копчёной паприки + 1 ст; л; worcestershire + 1 ст; л; уксуса + 1 ст; л; сахара + 0,5 ч; л; душистого перца + 0,5 ч; л; молотого имбиря + 0,5 ч; л; соли + щепотка кайенского перца; взбейте венчиком для соединения. ТУШИТЕ СОУС: доведите соус карри до слабого кипения на среднем-малом огне; готовьте 8–10 минут, часто помешивая деревянной ложкой, пока соус не станет блестящим и слегка сократится — он должен покрывать тыльную сторону ложки; попробуйте и отрегулируйте: если слишком резкий, добавьте щепотку больше сахара; если слишком сладкий, плеск больше уксуса; держите тёплым на самом малом огне. ЖАРЬТЕ СОСИСКИ: разогрейте 2 ст; л; масла в тяжёлой сковороде на среднем огне; добавьте проколотые сосиски и жарьте 8–10 минут, переворачивая каждые 2 минуты щипцами, пока они не станут глубоко золотисто-коричневыми со всех сторон и кожица не будет хрустящей; внутренняя температура должна достичь 70 °C — сосиски должны быть полностью прожарены. ОТДЫХ 2 МИНУТЫ: переложите сосиски на доску, выстеленную бумажным полотенцем; дайте им отдохнуть 2 минуты — это завершает приготовление и позволяет сокам перераспределиться, чтобы они не вытекали при нарезке. НАРЕЖЬТЕ: острым ножом нарежьте каждую сосиску по диагонали на 8 кусков по 1,5 см; диагональный разрез даёт больше поверхности для соуса и является культовой берлинской подачей. СОБЕРИТЕ: разделите нарезанные сосиски между 2 глубокими бумажными лотками или мелкими мисками (в стиле Берлин Imbiss); щедро полейте сверху горячим соусом карри, чтобы он растекался вокруг ломтиков; посыпьте всю тарелку дополнительной щедрой щепоткой порошка карри — пыльная верхушка — это то, что делает её карривурстом, а не просто сосиской в соусе. ПОДАВАЙТЕ С POMMES: воткните деревянный Pommespieker (маленькая вилочка) в ломтики, положите рядом с лотком кучку золотистых Pommes Frites и небольшой шарик майонеза + кетчупа (немецкий Pommes rot-weiß); ешьте стоя, в идеале на берлинском уличном углу; сочетайте с холодным Pilsner; лучше всего есть в течение 5 минут — радость в контрасте хрустящей кожицы, горячего соуса, пыльного карри и солёных фри.","en":"PRICK THE SAUSAGES: take 4 Bratwurst out of the fridge 15 minutes before cooking to come closer to room temperature; prick each sausage 4–5 times with a fork — this prevents the skin from bursting open in the pan and lets some fat render out. MAKE THE CURRY SAUCE: in a small saucepan, combine 200 g ketchup + 100 ml passata + 2 tbsp curry powder + 1 tsp sweet paprika + 0.5 tsp smoked paprika + 1 tbsp Worcestershire + 1 tbsp vinegar + 1 tbsp sugar + 0.5 tsp allspice + 0.5 tsp ground ginger + 0.5 tsp salt + a pinch of cayenne; whisk to combine. SIMMER THE SAUCE: bring the curry sauce to a gentle simmer over medium-low heat; cook 8–10 minutes, stirring often with a wooden spoon, until the sauce is glossy and slightly reduced — it should coat the back of a spoon; taste and adjust: if too sharp, add a pinch more sugar; if too sweet, a splash more vinegar; keep warm on the lowest heat. FRY THE SAUSAGES: heat 2 tbsp oil in a heavy skillet over medium heat; add the pricked sausages and fry 8–10 minutes, turning every 2 minutes with tongs, until deeply golden brown on all sides and the skin is crisp; the internal temperature should reach 70 °C — sausages must be fully cooked through. REST 2 MINUTES: transfer the sausages onto a board lined with paper towel; let them rest 2 minutes — this finishes cooking and lets the juices redistribute, so they don't gush out when sliced. SLICE: with a sharp knife, slice each sausage diagonally into 8 pieces of 1.5 cm; the diagonal cut gives more surface for the sauce to cling to and is the iconic Berlin presentation. ASSEMBLE: divide the sliced sausages between 2 deep paper-tray plates or shallow bowls (the Berlin Imbiss style); ladle the hot curry sauce generously over the top so it pools around the slices; dust the whole plate with an extra generous pinch of curry powder — the dusty top is what makes it a currywurst, not just a sausage in sauce. SERVE WITH POMMES: stab a wooden Pommespieker (small fork) into the slices, set on the side of the tray a heap of golden Pommes Frites and a small dollop of mayonnaise + ketchup (the German Pommes rot-weiß); eat standing up, ideally on a Berlin street corner; pair with a cold Pilsner; best eaten within 5 minutes — the joy is in the contrast of crisp skin, hot sauce, dusty curry, and salty fries."}},{"id":174,"servings":4,"tipType":"meat","pairingsType":"thai","origin":{"ru":"Таиланд","en":"Thailand","ro":"Thailanda"},"name":{"ru":"Том Кха Гай","en":"Tom Kha Gai","ro":"Tom Kha Gai"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["500 г куриных бёдер без кости и кожи (более ароматные, чем грудка в этом деликатном бульоне), тонко нарезанные поперёк волокон полосками 5 мм","400 мл несладкого жирного кокосового молока (со сливочным слоем, отделённым, см. шаг 2)","600 мл несолёного куриного бульона (домашнего или магазинного с низким содержанием натрия)","1 рука свежего галангала (kha) — ~50 г, очищенного и нарезанного на монетки 5 мм; НЕ заменять имбирём, вкус совершенно другой","3 стебля свежего лемонграсса (takrai) — внешние листья удалены, нижние 10 см размяты тыльной стороной ножа и нарезаны на секции 5 см","6 свежих листьев кафрского лайма (bai makrut), без жилок и порванных (НЕ нарезанных — они выделяют масла при разрывании)","4 маленьких тайских перца чили глаз птицы (prik kee noo) — слегка размятых целыми, не нарезанных, если хочется мягкой остроты (нарезанных для остроты)","4 зубчика чеснока, слегка размятых","2 маленьких шалота (~80 г), тонко нарезанных","200 г соломенных грибов (консервированных, осушенных), разрезанных пополам — или свежих устричных/шиитаке/шампиньонов как заменитель","4 ст. л. тайского рыбного соуса (nam pla) — марки Squid или Tiparos для лучшего вкуса","1 ст. л. пальмового сахара (или светло-коричневого сахара)","60 мл свежего сока лайма (из 2 лаймов) — добавляется в КОНЦЕ, никогда не кипятится","2 ст. л. тайской пасты чили в соевом масле (nam prik pao) — добавляет фирменную копчёную глубину (по желанию, но традиционно)","1 маленький пучок свежего кинзы (кориандра), грубо нарезанной, для гарнира","4 зелёных лука, тонко нарезанных по диагонали, для гарнира","Для подачи: 320 г варёного жасминового риса (80 г сухого на порцию) + 1 лайм, нарезанный дольками"],"en":["500 g boneless skinless chicken thighs (more flavour than breast in this delicate broth), thinly sliced across the grain into 5 mm strips","400 ml unsweetened full-fat coconut milk (the cream layer separated, see step 2)","600 ml unsalted chicken stock (low-sodium homemade or store-bought)","1 hand of fresh galangal (kha) — ~50 g, peeled and cut into 5 mm coin slices; do NOT substitute ginger, the flavour is completely different","3 stalks fresh lemongrass (takrai) — outer leaves removed, lower 10 cm bruised with the back of a knife and cut into 5 cm sections","6 fresh kaffir lime leaves (bai makrut), de-veined and torn (NOT chopped — they release oils when torn)","4 small Thai bird's eye chilies (prik kee noo) — lightly bruised whole, not sliced if you want gentle heat (sliced for hot)","4 garlic cloves, lightly bruised","2 small shallots (~80 g), thinly sliced","200 g straw mushrooms (canned, drained), halved — or fresh oyster/shiitake/button mushrooms as substitute","4 tbsp Thai fish sauce (nam pla) — Squid or Tiparos brand for best flavour","1 tbsp palm sugar (or light brown sugar)","60 ml fresh lime juice (from 2 limes) — added at the END, never boiled","2 tbsp Thai chili paste in soybean oil (nam prik pao) — adds the signature smoky depth (optional but traditional)","1 small bunch fresh cilantro (coriander) leaves, roughly chopped, to garnish","4 spring onions, thinly sliced on the diagonal, to garnish","To serve: 320 g cooked jasmine rice (80 g dry per serving) + 1 lime cut into wedges"],"ro":["500 g pulpe de pui dezosate și fără piele (mai aromate decât pieptul în acest bulion delicat), feliate subțire în benzi de 5 mm contra fibrei","400 ml lapte de cocos integral neîndulcit (cu stratul de smântână separat, vezi pasul 2)","600 ml supă de pui nesărată (de casă sau cumpărată cu conținut scăzut de sodiu)","1 mână de galangal proaspăt (kha) — ~50 g, curățat și tăiat în felii de 5 mm; NU înlocui cu ghimbir, aroma este complet diferită","3 tulpini de lemongrass proaspăt (takrai) — frunzele exterioare îndepărtate, partea inferioară de 10 cm zdrobită cu dosul cuțitului și tăiată în secțiuni de 5 cm","6 frunze de kaffir lime proaspete (bai makrut), cu vinele îndepărtate și rupte (NU tăiate — eliberează uleiurile când sunt rupte)","4 ardei iuți thailandezi mici (prik kee noo) — zdrobiți ușor întregi, nu feliați dacă vrei iuțeală blândă (feliați pentru iute)","4 căței de usturoi, zdrobiți ușor","2 șalote mici (~80 g), feliate subțire","200 g ciuperci de paie (la conservă, scurse), tăiate în jumătăți — sau ciuperci proaspete oyster/shiitake/champignon ca substitut","4 linguri sos de pește thailandez (nam pla) — marca Squid sau Tiparos pentru cea mai bună aromă","1 lingură zahăr de palmier (sau zahăr brun deschis)","60 ml suc de lime proaspăt (din 2 limete) — adăugat la SFÂRȘIT, niciodată fiert","2 linguri pastă thailandeză de ardei iute în ulei de soia (nam prik pao) — adaugă profunzimea afumată caracteristică (opțional dar tradițional)","1 mănunchi mic de coriandru proaspăt (frunze de cilantro), tocat grosier, pentru garnitură","4 cepe verzi, feliate subțire pe diagonală, pentru garnitură","Pentru servire: 320 g orez jasmin fiert (80 g uscat pe porție) + 1 lime tăiat în felii"]},"howIsMade":{"ru":"ПОДГОТОВЬТЕ АРОМАТЫ: очистите и нарежьте 50 г галангала на монетки 5 мм; удалите жёсткие внешние листья с 3 стеблей лемонграсса и разомните нижние 10 см тыльной стороной тяжёлого ножа, чтобы высвободить масла — затем нарежьте на куски 5 см; порвите (не нарезайте) 6 листьев кафрского лайма, чтобы высвободить их масла; слегка разомните 4 перца чили + 4 зубчика чеснока боковой стороной ножа; эти ароматы — душа бульона — никогда не используйте молотые заменители. ОТДЕЛИТЕ КОКОСОВОЕ МОЛОКО: откройте банку 400 мл кокосового молока, не встряхивая её; густые сливки обычно находятся сверху — снимите ложкой около 100 мл густых сливок и отложите в сторону (это ваши hua kati, сливки); остальное — более жидкое молоко (hang kati). РАСПУСТИТЕ СЛИВКИ: в средней кастрюле на среднем огне варите 100 мл кокосовых сливок 3–4 минуты, пока они не разделятся и масло не начнёт видимо отделяться — это концентрирует кокосовый вкус и является традиционным тайским вступительным движением; (Если ваше кокосовое молоко не разделяется чисто, пропустите этот шаг и просто начните со всего в кастрюле.). ИНФУЗИРУЙТЕ АРОМАТЫ: добавьте ломтики галангала, кусочки лемонграсса, порванные листья лайма, размятые перцы чили, чеснок и 80 г нарезанного шалота в горячие кокосовые сливки; перемешивайте 1 минуту, пока не станет интенсивно ароматным; кухня должна явно пахнуть Таиландом — яркими цитрусовыми, перечным галангалом и сладким кокосом. СОСТАВЬТЕ БУЛЬОН: влейте оставшиеся 300 мл кокосового молока + 600 мл куриного бульона + 2 ст; л; nam prik pao (если используете); доведите до слабого кипения (НИКОГДА до сильного кипения — кокосовое молоко некрасиво разделяется при сильном кипении); варите 8 минут без крышки, чтобы ароматы полностью настоялись и бульон имел глубокий и округлый вкус. ДОБАВЬТЕ КУРИЦУ: бросьте 500 г нарезанной курицы в кипящий бульон, осторожно помешивая, чтобы разделить кусочки; варите 4–5 минут, пока курица не будет едва прожарена и не побелеет — переваривание делает её жёсткой; добавьте 200 г разрезанных пополам соломенных грибов и варите ещё 2 минуты. ПРИПРАВЬТЕ: выключите огонь; добавьте 4 ст; л; рыбного соуса + 1 ст; л; пальмового сахара; попробуйте — бульон должен быть солёным, слегка сладким, слабо острым и наполненным цитрусовым ароматом; добавьте чуть больше рыбного соуса или сахара, если необходимо; снять с огня здесь критично. ЛАЙМ В ПОСЛЕДНИЙ МОМЕНТ: добавьте 60 мл свежего сока лайма ТОЛЬКО непосредственно перед подачей — кипячение лаймового сока делает его горьким и тусклым; разложите по глубоким мискам; украсьте свежей кинзой + нарезанным зелёным луком + несколькими дополнительными ломтиками размятого чили для тех, кто любит больше остроты; подавайте горячим с пропаренным жасминовым рисом и дольками лайма; скажите гостям: галангал, лемонграсс и листья лайма — это ароматы, они не съедобны — отодвиньте их к краю миски.","en":"PREP THE AROMATICS: peel and slice 50 g galangal into 5 mm coins; remove the tough outer leaves from 3 lemongrass stalks and bruise the lower 10 cm with the back of a heavy knife to release the oils — then cut into 5 cm pieces; tear (don't chop) 6 kaffir lime leaves to release their oils; lightly bruise 4 chilies + 4 garlic cloves with the side of the knife; these aromatics are the soul of the broth — never use ground substitutes. SEPARATE THE COCONUT MILK: open a 400 ml can of coconut milk without shaking; the thick cream usually sits on top — spoon off about 100 ml of the thick cream and set aside (this is your hua kati, the cream); the rest is the thinner milk (hang kati). BLOOM THE CREAM: in a medium pot over medium heat, simmer the 100 ml coconut cream 3–4 minutes until it splits and the oil starts to separate visibly — this concentrates the coconut flavor and is the traditional Thai opening move; (If your coconut milk doesn't separate cleanly, skip this step and just start with everything in the pot.). INFUSE THE AROMATICS: add the galangal slices, lemongrass pieces, torn lime leaves, bruised chilies, garlic, and 80 g sliced shallots to the hot coconut cream; stir 1 minute until intensely aromatic; the kitchen should smell distinctly of Thai — bright citrus, peppery galangal, and sweet coconut. BUILD THE BROTH: pour in the remaining 300 ml coconut milk + 600 ml chicken stock + 2 tbsp nam prik pao (if using); bring to a gentle simmer (NEVER a hard boil — coconut milk separates ugly if boiled hard); simmer 8 minutes uncovered, so the aromatics infuse fully and the broth tastes deep and rounded. ADD THE CHICKEN: drop the 500 g sliced chicken into the simmering broth, stirring gently to separate the pieces; simmer 4–5 minutes until the chicken is just cooked through and white — overcooking turns it tough; add 200 g halved straw mushrooms and simmer 2 minutes more. SEASON: turn off the heat; stir in 4 tbsp fish sauce + 1 tbsp palm sugar; taste — the broth should be savoury, slightly sweet, mildly hot, and full of citrus aroma; add a splash more fish sauce or sugar if needed; off heat is critical here. LIME AT THE LAST MOMENT: stir in 60 ml fresh lime juice ONLY just before serving — boiling the lime juice turns it bitter and dull; ladle into deep bowls; top with fresh cilantro + sliced spring onions + a few extra slices of bruised chili for those who like more heat; serve hot with steamed jasmine rice on the side and lime wedges; tell guests: the galangal, lemongrass, and lime leaves are aromatics, not edible — fish them to the side of the bowl."}},{"id":175,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"ru":"Кабо-Верде","en":"Cape Verde","ro":"Capul Verde"},"name":{"ru":"Качупа","en":"Cachupa","ro":"Cachupa"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["400 г milho cachupa (белой кукурузы хоминий, треснутый сушёный сорт, специфичный для Кабо-Верде) — замоченной на ночь в большом количестве холодной воды (обязательно)","200 г сушёной красной фасоли — замоченной на ночь","200 г сушёной фасоли лима или нут — замоченной на ночь (смесь бобовых — это кабо-вердийская подпись)","500 г свиной лопатки (cabidela), нарезанной кубиками 3 см","300 г солёных свиных рёбер или свиной грудинки (toucinho), нарезанных кусками — вымочить 1 час в холодной воде, чтобы убрать излишек соли","200 г linguiça или chouriço portuguesa (португальской копчёной колбасы), нарезанной ломтиками 1.5 см","200 г morcela (португальской кровяной колбасы) — по желанию, традиционно","2 крупные жёлтые луковицы (~350 г), одна мелко нарезанная для refogado и одна нарезанная дольками","6 зубчиков чеснока, измельчённых","2 средних спелых помидора (~250 г), очищенных и натёртых, или 1 банка 200 г измельчённых помидоров","1 ст. л. томатной пасты","2 лавровых листа + 1 ч. л. молотого тмина + 1 ч. л. сладкой паприки + 0.5 ч. л. сушёного орегано + 1 ч. л. соли + 0.5 ч. л. чёрного перца","3 ст. л. красного пальмового масла ИЛИ оливкового масла (пальмовое масло более традиционно на некоторых островах)","500 г тыквы или мускатной тыквы, очищенной и нарезанной кубиками 4 см","300 г сладкого картофеля или ямса, очищенного и нарезанного кубиками 4 см","200 г савойской капусты, нарезанной дольками 4 см (добавляется в финальной стадии)","2 л воды (или свиного бульона) + 1 перец чили пири-пири или scotch bonnet (по желанию, для лёгкой остроты островов)","Для подачи: куски свежего белого хлеба, несколько дополнительных ломтиков жареной linguiça, острый соус пири-пири и опция следующего дня 'cachupa guisada' — обжаренная на сковороде с яйцами"],"en":["400 g milho cachupa (white hominy corn, the cracked dried Cape Verdean variety) — soaked overnight in plenty of cold water (mandatory)","200 g dried red kidney beans — soaked overnight","200 g dried butter beans (lima beans) or chickpeas — soaked overnight (the mixture of legumes is the Cape Verdean signature)","500 g pork shoulder (cabidela), cut into 3 cm cubes","300 g salted pork ribs or pork belly (toucinho), cut into chunks — soak 1 hour in cold water to remove excess salt","200 g linguiça or chouriço portuguesa (Portuguese smoked sausage), cut into 1.5 cm slices","200 g morcela (Portuguese blood sausage) — optional, traditional","2 large yellow onions (~350 g), one finely diced for the refogado and one cut into wedges","6 garlic cloves, minced","2 medium ripe tomatoes (~250 g), peeled and grated, or 1 × 200 g can crushed tomatoes","1 tbsp tomato paste","2 bay leaves + 1 tsp ground cumin + 1 tsp sweet paprika + 0.5 tsp dried oregano + 1 tsp salt + 0.5 tsp black pepper","3 tbsp red palm oil OR olive oil (palm oil is more traditional in some islands)","500 g pumpkin or butternut squash, peeled and cut into 4 cm cubes","300 g sweet potato or yam, peeled and cut into 4 cm cubes","200 g savoy cabbage, cut into 4 cm wedges (added in the final stage)","2 L water (or pork stock) + 1 piri-piri or scotch bonnet chili (optional, for the islands' light heat)","To serve: chunks of fresh white bread, a few extra slices of grilled linguiça, hot piri-piri sauce, and the next-day pan-fried 'cachupa guisada' with eggs option mentioned"],"ro":["400 g milho cachupa (porumb hominy alb, varietatea crăpată uscată specifică Capului Verde) — înmuiat peste noapte în multă apă rece (obligatoriu)","200 g fasole roșie uscată — înmuiată peste noapte","200 g fasole untoasă uscată (lima) sau năut — înmuiată peste noapte (amestecul de leguminoase este semnătura capverdiană)","500 g spată de porc (cabidela), tăiată în cuburi de 3 cm","300 g coaste de porc sărate sau burtă de porc (toucinho), tăiate în bucăți — înmuiate 1 oră în apă rece pentru a îndepărta excesul de sare","200 g linguiça sau chouriço portuguesa (cârnat afumat portughez), tăiat în felii de 1.5 cm","200 g morcela (cârnat de sânge portughez) — opțional, tradițional","2 cepe galbene mari (~350 g), una tăiată mărunt pentru refogado și una tăiată în felii mari","6 căței de usturoi, tocați mărunt","2 roșii medii coapte (~250 g), decojite și răzuite, sau 1 cutie de 200 g de roșii zdrobite","1 lingură pastă de roșii","2 foi de dafin + 1 linguriță chimion măcinat + 1 linguriță boia dulce + 0.5 linguriță oregano uscat + 1 linguriță sare + 0.5 linguriță piper negru","3 linguri ulei roșu de palmier SAU ulei de măsline (uleiul de palmier este mai tradițional în unele insule)","500 g dovleac sau dovleac plăcintar, curățat și tăiat în cuburi de 4 cm","300 g cartof dulce sau ignamă, curățat și tăiat în cuburi de 4 cm","200 g varză de Milano, tăiată în felii mari de 4 cm (adăugată în etapa finală)","2 L apă (sau supă de porc) + 1 ardei iute piri-piri sau scotch bonnet (opțional, pentru iuțeala ușoară a insulelor)","Pentru servire: bucăți de pâine albă proaspătă, câteva felii suplimentare de linguiça la grătar, sos iute piri-piri și opțiunea 'cachupa guisada' a doua zi (prăjită în tigaie cu ouă)"]},"howIsMade":{"ru":"ЗАМОЧИТЕ НА НОЧЬ: этот шаг не подлежит обсуждению; накануне вечером перед готовкой положите 400 г кукурузы хоминий + 200 г красной фасоли + 200 г фасоли лима/нут каждый в отдельные миски, покрыв 5 см холодной воды; замочите минимум 12 часов; на следующее утро слейте и промойте; пропуск замачивания даст кукурузу, которая останется крупинчатой после часов варки. ПРЕДВАРИТЕЛЬНО СВАРИТЕ ХОМИНИЙ: положите слитый хоминий в большую кастрюлю с 1.5 л свежей холодной воды + 1 лавровый лист + 1 ч; л; соли; доведите до кипения, затем тушите под крышкой 1 час; кукуруза должна быть частично мягкой, но всё ещё твёрдой в центре — она продолжит вариться в рагу; слейте, сохранив 500 мл варочной жидкости. ПРЕДВАРИТЕЛЬНО СВАРИТЕ ФАСОЛЬ: во вторую кастрюлю положите слитую красную фасоль и фасоль лима вместе со свежей холодной водой, чтобы покрыть на 3 см; доведите до кипения, снимайте пену 5 мин, затем варите 45 мин до состояния al dente — они закончат в рагу; слейте. REFOGADO: в большой тяжёлой 8-литровой кастрюле нагрейте 3 ст; л; пальмового или оливкового масла на среднем огне; добавьте 200 г мелко нарезанного лука + 6 измельчённых зубчиков чеснока и готовьте 8–10 минут, пока они не станут мягкими и золотистыми; вмешайте 1 ст; л; томатной пасты и готовьте 1 мин до потемнения; добавьте 250 г натёртых помидоров + 1 ч; л; паприки + 1 ч; л; тмина + 0.5 ч; л; орегано и готовьте 4–5 мин, пока смесь не уменьшится и масло не отделится на поверхности. ОБЖАРЬТЕ СВИНИНУ: отодвиньте refogado в сторону; поднимите огонь до средне-сильного и добавьте 500 г кубиков свиной лопатки в один слой; обжаривайте 3 минуты с каждой стороны до золотистого цвета, затем вмешайте в refogado; добавьте слитые солёные свиные рёбра/грудинку + 1 ч; л; соли + 0.5 ч; л; перца + 1 оставшийся лавровый лист + опциональный перец пири-пири. СОСТАВЬТЕ РАГУ: добавьте частично сваренный хоминий + слитую фасоль + 2 л воды (или свиного бульона) + 500 мл зарезервированной жидкости от варки кукурузы; доведите до медленного кипения. МЕДЛЕННОЕ ТОМЛЕНИЕ: томите без крышки, помешивая каждые 20–30 минут, 2 часа; через 1 час добавьте 500 г кубиков тыквы + 300 г кубиков сладкого картофеля + ломтики linguiça; через 1.5 часа добавьте 200 г капустных долек + луковые дольки + ломтики morcela (если используете); рагу должно уменьшиться до густой, кашеобразной консистенции, где кукуруза, фасоль, овощи и мясо все мягкие; попробуйте и отрегулируйте соль — солёная свинина и колбасы добавляют много. ОТДЫХ И ПОДАЧА: выключите огонь и дайте cachupa отдохнуть 10 минут — именно тогда она загущается до идеальной консистенции; щедро разложите в глубокие миски со всеми видимыми цветами: жёлтая кукуруза, красная фасоль, оранжевая тыква, зелёная капуста, золотистая колбаса и насыщенная свинина; подавайте с кусками свежего белого хлеба, острым соусом пири-пири на столе и стаканом кабо-вердийского grogue или пива; остатки на следующий день обжариваются на сковороде с жареным яйцом сверху как 'cachupa guisada' — считается даже лучше, чем в первый день.","en":"SOAK OVERNIGHT: this is non-negotiable; the night before cooking, place 400 g hominy corn + 200 g kidney beans + 200 g butter beans/chickpeas each in separate bowls covered by 5 cm of cold water; soak 12 hours minimum; the next morning, drain and rinse; skipping the soak gives a corn that stays gritty after hours of cooking. PRE-COOK THE HOMINY: place the drained hominy in a large pot with 1.5 L fresh cold water + 1 bay leaf + 1 tsp salt; bring to a boil, then simmer covered 1 hour; the corn should be partially tender but still firm at the centre — it will continue cooking in the stew; drain, reserving 500 ml of the cooking liquid. PRE-COOK THE BEANS: in a second pot, place the drained kidney beans and butter beans together with fresh cold water to cover by 3 cm; bring to a boil, skim foam for 5 min, then simmer 45 min until al dente — they will finish in the stew; drain. THE REFOGADO: in a large heavy 8 L pot, heat 3 tbsp palm or olive oil over medium heat; add 200 g finely diced onion + 6 minced garlic and cook 8–10 minutes until soft and golden; stir in 1 tbsp tomato paste and cook 1 min until darkened; add 250 g grated tomato + 1 tsp paprika + 1 tsp cumin + 0.5 tsp oregano and cook 4–5 min until the mixture reduces and the oil separates on the surface. SEAR THE PORK: push the refogado to the side; raise the heat to medium-high and add the 500 g pork shoulder cubes in a single layer; sear 3 minutes per side until golden brown, then stir into the refogado; add the drained salted pork ribs/belly + 1 tsp salt + 0.5 tsp pepper + 1 remaining bay leaf + the optional piri-piri chili. BUILD THE STEW: add the partially-cooked hominy + the drained beans + 2 L water (or pork stock) + the 500 ml reserved corn-cooking liquid; bring to a gentle simmer. SLOW SIMMER: simmer uncovered, stirring every 20–30 minutes, for 2 hours; after 1 hour, add the 500 g pumpkin cubes + 300 g sweet potato cubes + the linguiça slices; after 1.5 hours, add the 200 g cabbage wedges + the onion wedges + the morcela slices (if using); the stew should reduce to a thick, porridge-like consistency where the corn, beans, vegetables, and meats are all tender; taste and adjust salt — the saltpork and sausages add a lot. REST AND SERVE: turn off the heat and let the cachupa rest 10 minutes — this is when it thickens to the perfect consistency; ladle generously into deep bowls with all the colors visible: yellow corn, red beans, orange pumpkin, green cabbage, golden sausage, and rich pork; serve with chunks of fresh white bread, hot piri-piri sauce on the table, and a glass of Cape Verdean grogue or beer; the leftovers next day are pan-fried with a fried egg on top as 'cachupa guisada' — considered even better than the first day."}},{"id":176,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"ru":"Индия","en":"India","ro":"India"},"name":{"ru":"Пав бхаджи","en":"Pav Bhaji","ro":"Pav Bhaji"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500 г мучнистого картофеля, очищенного и нарезанного кубиками 3 см","250 г соцветий цветной капусты (примерно 1/2 маленького кочана)","100 г зелёного горошка (свежего или замороженного)","100 г французской зелёной фасоли, нарезанной кусочками 1 см","1 средняя морковь (~100 г), нарезанная кубиками","100 г несолёного сливочного масла (да — столько, это количества масла уличных торговцев) — разделённого","2 крупные красные луковицы (~300 г) — одна мелко нарезанная для бхаджи, одна мелко нарезанная сырая для гарнира","1 крупный зелёный болгарский перец или капсикум (~150 г), мелко нарезанный","4 спелых помидора (~500 г), измельчённых в блендере","1 ст. л. пасты имбирь-чеснок (или 3 см имбиря + 4 зубчика чеснока, натёртых вместе)","2 ст. л. пав бхаджи масалы (марки Everest или MDH) — специфическая смесь специй, не заменять гарам масалой","1 ч. л. кашмирского красного перца чили (для культового красного цвета, мягкая острота)","0.5 ч. л. куркумы + 1.5 ч. л. соли + 0.5 ч. л. молотого чёрного перца","1 лимон, разрезанный на 4 дольки + рубленый свежий кориандр (кинза), щедро","8 маленьких мягких булочек пав (ладди пав в стиле Мумбаи или заменить булочками бриошь слайдер)","50 г несолёного сливочного масла для обжаривания пава + дополнительный красный чили для посыпки","Для подачи: дополнительный сырой красный лук, свежий кориандр, дольки лимона, 1 маленький зелёный перец чили мелко нарезанный (по желанию)"],"en":["500 g floury potatoes, peeled and cut into 3 cm cubes","250 g cauliflower florets (about 1/2 small head)","100 g green peas (fresh or frozen)","100 g French beans, cut into 1 cm pieces","1 medium carrot (~100 g), diced","100 g unsalted butter (yes — that much, this is street-vendor butter quantities) — divided","2 large red onions (~300 g) — one finely diced for the bhaji, one finely diced raw for the garnish","1 large green bell pepper or capsicum (~150 g), finely diced","4 ripe tomatoes (~500 g), pureed in a blender","1 tbsp ginger-garlic paste (or 3 cm ginger + 4 garlic cloves, grated together)","2 tbsp pav bhaji masala (Everest or MDH brand) — the specific spice blend, do not substitute with garam masala","1 tsp Kashmiri red chili powder (for the iconic red color, mild heat)","0.5 tsp turmeric + 1.5 tsp salt + 0.5 tsp ground black pepper","1 lemon, cut into 4 wedges + chopped fresh coriander (cilantro), generously","8 small soft pav buns (Mumbai-style ladi pav, or substitute with brioche slider buns)","50 g unsalted butter for toasting the pav + extra red chili powder for sprinkling","To serve: extra raw red onion, fresh coriander, lemon wedges, 1 small green chili finely chopped (optional)"],"ro":["500 g cartofi făinoși, curățați și tăiați în cuburi de 3 cm","250 g buchețele de conopidă (aproximativ 1/2 căpățână mică)","100 g mazăre verde (proaspătă sau congelată)","100 g fasole verde franceză, tăiată în bucăți de 1 cm","1 morcov mediu (~100 g), tăiat cubulețe","100 g unt nesărat (da — atât de mult, acestea sunt cantitățile de unt ale vânzătorilor de stradă) — împărțit","2 cepe roșii mari (~300 g) — una tăiată mărunt pentru bhaji, una tăiată mărunt crudă pentru garnitură","1 ardei capia verde mare sau capsicum (~150 g), tăiat mărunt","4 roșii coapte (~500 g), pasate în blender","1 lingură pastă de ghimbir-usturoi (sau 3 cm ghimbir + 4 căței usturoi, răzuiți împreună)","2 linguri pav bhaji masala (marca Everest sau MDH) — amestecul specific de condimente, nu înlocuiți cu garam masala","1 linguriță pudră de chili roșu Kashmiri (pentru culoarea roșie iconică, iuțeală blândă)","0.5 linguriță turmeric + 1.5 linguriță sare + 0.5 linguriță piper negru măcinat","1 lămâie, tăiată în 4 sferturi + coriandru proaspăt (cilantro) tocat, generos","8 chifle pav mici și moi (ladi pav stil Mumbai, sau înlocuiți cu chifle brioche slider)","50 g unt nesărat pentru prăjirea pavului + suplimentar pudră de chili roșu pentru presărat","Pentru servire: ceapă roșie crudă suplimentară, coriandru proaspăt, sferturi de lămâie, 1 ardei iute verde mic tocat mărunt (opțional)"]},"howIsMade":{"ru":"ПРИГОТОВЛЕНИЕ ОВОЩЕЙ В СКОРОВАРКЕ: в скороварке (или большой кастрюле) смешайте 500 г кубиков картофеля + 250 г цветной капусты + 100 г горошка + 100 г французской зелёной фасоли + 100 г нарезанной кубиками моркови + 500 мл воды + 1 ч; л; соли; готовьте под давлением 3 свистка на сильном огне, затем выключите и дайте давлению естественно сбросить (около 15 мин); если используете обычную кастрюлю, накройте и тушите 25–30 минут, пока всё не станет мягким для вилки; слейте, ОСТАВИВ 250 мл воды от варки. РАЗОМНИТЕ ОВОЩИ: толкушкой для картофеля энергично разомните варёные овощи прямо в кастрюле, пока не получите грубое пюре — должна остаться какая-то текстура, это НЕ гладкий суп; отложите. РАСКРОЙТЕ АРОМАТЫ: разогрейте 50 г масла на большой тяжёлой сковороде или кадхае на среднем огне, пока не растает и не запенится; добавьте 150 г мелко нарезанного красного лука и готовьте, часто помешивая, 5–6 минут, пока не станет мягким и слегка золотистым по краям. ИМБИРЬ-ЧЕСНОК + ПЕРЕЦ: добавьте 1 ст; л; пасты имбирь-чеснок и мешайте 1 минуту, пока не исчезнет сырой запах; добавьте 150 г нарезанного зелёного болгарского перца и готовьте 3–4 минуты, пока он не станет слегка мягким, но всё ещё ярко-зелёным. РАСКРОЙТЕ СПЕЦИИ: добавьте 2 ст; л; пав бхаджи масалы + 1 ч; л; кашмирского чили + 0.5 ч; л; куркумы; мешайте 30 секунд, пока специи не станут интенсивно ароматными — не сжигайте, при необходимости немного уменьшите огонь. СОЗДАЙТЕ БХАДЖИ: влейте измельчённые помидоры + 0.5 ч; л; молотого перца + 0.5 ч; л; соли; готовьте, часто помешивая, 6–8 минут, пока помидор не уменьшится и масло не начнёт отделяться по краям сковороды — это визуальный признак того, что масала готова; добавьте оставленные 250 мл овощной воды + размятые овощи; энергично перемешайте для соединения. ТУШИТЕ + БОЛЬШЕ РАЗМИНАЙТЕ: тушите бхаджи 10–12 минут, часто помешивая и продолжая разминать толкушкой для картофеля прямо в сковороде; бхаджи должен стать густым, тёмно-красным, блестящим и интенсивно ароматным; отрегулируйте приправу — уличные торговцы Мумбаи любят его солёным и острым; вмешайте ещё 30 г масла и 1 ст; л; рубленого кориандра; выжмите сок половины лимона. ОБЖАРЬТЕ ПАВ И ПОДАВАЙТЕ: разрежьте 8 булочек пав горизонтально, не разрезая полностью (книжный стиль); разогрейте широкую сковороду на среднем огне; добавьте 30 г масла + щепотку пав бхаджи масалы + щепотку кашмирского чили, покрутите; прижмите открытые булочки пав в горячем масле и обжарьте 30–60 секунд с каждой стороны до золотистости и аромата; подавайте немедленно: щедрая горка горячего бхаджи, увенчанная кусочком масла, нарезанным сырым красным луком, рубленым кориандром, долькой лимона и опциональным нарезанным зелёным чили; подавайте с 2 поджаренными пав на человека рядом; разорвите пав, окуните в бхаджи, выжмите лимон на каждый кусочек — уличная еда Мумбаи дома.","en":"PRESSURE-COOK THE VEGETABLES: in a pressure cooker (or large pot) combine 500 g potato cubes + 250 g cauliflower + 100 g peas + 100 g French beans + 100 g diced carrot + 500 ml water + 1 tsp salt; pressure cook 3 whistles on high, then turn off and let the pressure release naturally (about 15 min); if using a regular pot, cover and simmer 25–30 minutes until everything is fork-tender; drain, RESERVING 250 ml of the cooking water. MASH THE VEGETABLES: with a potato masher, vigorously mash the boiled vegetables right in the pot until you have a coarse purée — some texture should remain, this is NOT a smooth soup; set aside. BLOOM THE AROMATICS: heat 50 g butter in a large heavy skillet or kadhai over medium heat until melted and foaming; add 150 g finely diced red onion and cook stirring often 5–6 minutes until soft and just turning golden at the edges. GINGER-GARLIC + BELL PEPPER: add 1 tbsp ginger-garlic paste and stir 1 minute until the raw smell disappears; add 150 g diced green bell pepper and cook 3–4 minutes until just softened but still bright green. SPICES BLOOM: add 2 tbsp pav bhaji masala + 1 tsp Kashmiri chili powder + 0.5 tsp turmeric; stir 30 seconds until the spices are intensely fragrant — do not burn, lower the heat slightly if needed. BUILD THE BHAJI: pour in the pureed tomatoes + 0.5 tsp ground pepper + 0.5 tsp salt; cook stirring often 6–8 minutes until the tomato has reduced and the butter starts to separate around the edges of the pan — this is the visual sign that the masala is ready; add the reserved 250 ml vegetable water + the mashed vegetables; stir vigorously to combine. SIMMER + MASH MORE: simmer the bhaji 10–12 minutes, stirring frequently and mashing more with a potato masher right in the pan; the bhaji should become thick, dark red, glossy, and intensely fragrant; adjust seasoning — Mumbai street vendors love it salty and spicy; stir in another 30 g butter and 1 tbsp chopped coriander; squeeze in juice of half a lemon. TOAST THE PAV AND SERVE: slice 8 pav buns horizontally without cutting all the way through (book-style); heat a wide skillet over medium heat; add 30 g butter + a pinch of pav bhaji masala + a pinch of Kashmiri chili powder, swirl; press the open pav buns into the hot butter and toast 30–60 seconds per side until golden and fragrant; plate immediately: a generous mound of hot bhaji topped with a knob of butter, chopped raw red onion, chopped coriander, a lemon wedge, and optional chopped green chili; serve with 2 toasted pav per person on the side; tear the pav, dip into the bhaji, squeeze the lemon over each bite — Mumbai street food at home."}},{"id":177,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Финляндия","en":"Finland","ro":"Finlanda"},"name":{"ru":"Карельское рагу","en":"Karelian stew","ro":"Karjalanpaisti"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["400 г говяжьей лопатки (chuck), нарезанной кубиками 3 см","400 г свиной лопатки, нарезанной кубиками 3 см","400 г бараньей лопатки, нарезанной кубиками 3 см (или оленины в Лапландии)","2 крупные жёлтые луковицы (~400 г), нарезанные толстыми кольцами","4 средних моркови (~400 г), нарезанных кусочками 3 см","1 ч. л. целых горошин чёрного перца","4 лавровых листа","6 целых ягод можжевельника (финская подпись, слегка смолистая — обязательна)","6 целых ягод душистого перца","2 ч. л. соли","1 л холодной воды (или слабого говяжьего бульона — традиционно используется вода)","1 ст. л. нейтрального масла ИЛИ 50 г сливочного масла для опционального этапа обжарки","Для подачи: 800 г варёного молодого картофеля с маслом и укропом, маринованный огурец, варенье из брусники (puolukkahillo), тёмный ржаной хлеб и стакан холодного молока или пива"],"en":["400 g beef chuck, cubed 3 cm","400 g pork shoulder, cubed 3 cm","400 g lamb shoulder, cubed 3 cm (or reindeer in Lapland)","2 large yellow onions (~400 g), thickly sliced","4 medium carrots (~400 g), cut into 3 cm chunks","1 tsp whole black peppercorns","4 bay leaves","6 whole juniper berries (the Finnish signature, slightly piny — non-negotiable)","6 whole allspice berries","2 tsp salt","1 L cold water (or weak beef stock — traditional is water)","1 tbsp neutral oil OR 50 g butter for the optional searing step","To serve: 800 g boiled new potatoes with butter and dill, pickled cucumber, lingonberry jam (puolukkahillo), dark rye bread, and a glass of cold milk or beer"],"ro":["400 g pulpă de vită (chuck), tăiată în cuburi de 3 cm","400 g spată de porc, tăiată în cuburi de 3 cm","400 g spată de miel, tăiată în cuburi de 3 cm (sau ren în Laponia)","2 cepe galbene mari (~400 g), tăiate în felii groase","4 morcovi medii (~400 g), tăiați în bucăți de 3 cm","1 linguriță boabe întregi de piper negru","4 foi de dafin","6 boabe întregi de ienupăr (semnătura finlandeză, ușor rășinos — non-negociabil)","6 boabe întregi de ienibahar","2 lingurițe sare","1 L apă rece (sau supă slabă de vită — tradițional este apa)","1 lingură ulei neutru SAU 50 g unt pentru pasul opțional de rumenire","Pentru servire: 800 g cartofi noi fierți cu unt și mărar, castravete murat, gem de merișoare lingonberry (puolukkahillo), pâine neagră de secară și un pahar de lapte rece sau bere"]},"howIsMade":{"ru":"РАЗОГРЕЙТЕ ДУХОВКУ до 125 °C — очень низкая медленная духовка является ПОДПИСЬЮ Karjalanpaisti, блюда, которое определяет его тающую текстуру. ОЧИСТИТЕ И НАРЕЖЬТЕ: очистите 400 г говядины + 400 г свинины + 400 г баранины от всех жил; нарежьте равномерными кубиками 3 см — НЕ режьте мельче; это 5-часовое приготовление, и более крупные кубики держат форму; мелкие куски растворяются в нити. ВЫБЕРИТЕ СВОЙ СТИЛЬ — ТРАДИЦИОННЫЙ: пропустите обжаривание; уложите всё слоями сырым и позвольте духовке сделать работу, как карельские бабушки делали веками; сОВРЕМЕННЫЙ: разогрейте 1 ст; л; масла в чугунной кастрюле на сильном огне, обжарьте мясо в 3 партии по 2 мин с каждой стороны для добавления вкуса Майяра, затем выньте; оба метода дают отличные результаты. УЛОЖИТЕ СЛОЯМИ В КАСТРЮЛЕ: в большой чугунной кастрюле или казане постройте чередующиеся слои в таком порядке: говядина внизу, нарезанный лук, свинина, кусочки моркови, баранина сверху; распределите 4 лавровых листа + 6 ягод можжевельника + 6 ягод душистого перца + 1 ч; л; горошин перца + 2 ч; л; соли между слоями — никогда только сверху. ДОБАВЬТЕ ЖИДКОСТЬ: налейте 1 л холодной воды (или слабого говяжьего бульона) так, чтобы она доходила до половины мяса — НЕ покрывая его; мясо выделяет собственные соки во время долгого приготовления, и соус концентрируется естественным образом. ЗАПЕЧАТАЙТЕ И ТУШИТЕ МЕДЛЕННО: накройте плотно прилегающей крышкой; переложите в духовку при 125 °C на 4–5 часов — да, пять часов, в этом весь смысл; нЕ открывайте крышку, кроме одного раза каждые 1.5 часа для проверки жидкости; если она уменьшается слишком быстро, добавьте немного горячей воды; мясо готово, когда вилка входит без усилий. ОТДЫХ В ДУХОВКЕ: выключите духовку и оставьте karjalanpaisti отдыхать в закрытой тёплой духовке ещё 30 минут — ароматы углубляются, и мясо расслабляется в соусе. ПОДАЧА: переложите нежное мясо в тёплые глубокие тарелки; полейте сверху бульонистыми концентрированными соками; ягоды можжевельника и душистый перец могут остаться для смелых или быть выловлены; подавайте с варёным молодым картофелем, заправленным маслом и укропом, маринованным огурцом сбоку, щедрой ложкой брусничного варенья (сладко-кислый контрапункт), ломтиками тёмного ржаного хлеба и стаканом холодного молока или пива — традиционный финский ужинный аккомпанемент.","en":"PREHEAT THE OVEN to 125 °C — the very low slow oven is the SIGNATURE of Karjalanpaisti, the dish that defines its melting texture. TRIM AND CUBE: trim 400 g beef + 400 g pork + 400 g lamb of any sinew; cut into uniform 3 cm cubes — DO NOT cut smaller; this is a 5 h cook and larger cubes hold up; smaller pieces dissolve into shreds. CHOOSE YOUR STYLE — TRADITIONAL: skip browning; layer everything raw and let the oven do the work, as Karelian grandmothers have done for centuries; mODERN: heat 1 tbsp oil in a Dutch oven over high heat, brown the meat in 3 batches 2 min per side for added Maillard flavour, then lift out; both methods produce excellent results. LAYER THE POT: in a large Dutch oven or cast-iron casserole, build alternating layers in this order: beef on the bottom, sliced onion, pork, carrot chunks, lamb on top; distribute 4 bay leaves + 6 juniper berries + 6 allspice + 1 tsp peppercorns + 2 tsp salt between the layers — never just on top. ADD LIQUID: pour in 1 L cold water (or weak beef stock) so it comes halfway up the meat — NOT covering; the meats release their own juices during the long cook and the sauce concentrates naturally. SEAL AND SLOW-COOK: cover with a tight-fitting lid; transfer to the 125 °C oven for 4–5 hours — yes, five hours, that is the point; do NOT open the lid except once every 1.5 hours to check the liquid; if reducing too fast, add a splash of hot water; the meat is ready when a fork sinks in effortlessly. REST IN THE OVEN: turn off the oven and let the karjalanpaisti rest in the closed warm oven another 30 minutes — the flavours deepen and the meat relaxes into the sauce. SERVE: lift the tender meat into warm deep plates; spoon over the brothy concentrated juices; the juniper berries and allspice can stay in for the brave, or be fished out; serve with boiled new potatoes tossed in butter and dill, pickled cucumber on the side, a generous dollop of lingonberry jam (the sweet-tart counterpoint), slices of dark rye bread, and a glass of cold milk or beer — the traditional Finnish dinner accompaniment."}},{"id":178,"servings":6,"tipType":"meat","pairingsType":"french","origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Бёф бургиньон","en":"Boeuf Bourguignon","ro":"Boeuf Bourguignon"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1.5 кг говяжьей лопатки или голяшки, нарезанной кубиками 4 см (с некоторой мраморностью для насыщенности)","200 г лардонов (копчёная свиная грудинка, нарезанная 1 см × 3 см) ИЛИ 200 г толстого бекона кубиками","750 мл полнотелого красного бургундского вина (Пино Нуар) — НЕ используйте дешёвое вино","200 мл говяжьего бульона","2 ст. л. томатной пасты","1 большая луковица (~250 г), мелко нарезанная для маринада и тушения","2 средних моркови (~250 г), нарезанных кусочками 2 см","4 зубчика чеснока, измельчённых","30 г несолёного сливочного масла + 2 ст. л. оливкового масла для обжарки","3 ст. л. универсальной муки","1 букет гарни: 3 веточки тимьяна + 2 лавровых листа + 6 стеблей петрушки, связанных кулинарной верёвкой","250 г жемчужного лука (silverskin), очищенного","250 г грибов кремини или шампиньонов, разрезанных пополам или на четвертинки","30 г дополнительного масла для гарнира из грибов и жемчужного лука","1.5 ч. л. соли + 1 ч. л. свежемолотого чёрного перца","2 ст. л. коньяка ИЛИ бренди для опционального фламбирования","Свежая петрушка с плоскими листьями + багет + варёный молодой картофель или яичная лапша со сливочным маслом для подачи"],"en":["1.5 kg beef chuck or shin, cubed 4 cm (some marbling for richness)","200 g lardons (smoked pork belly cut 1 cm × 3 cm) OR 200 g thick-cut bacon diced","750 ml full-bodied Burgundy red wine (Pinot Noir) — DO NOT use cheap wine","200 ml beef stock","2 tbsp tomato paste","1 large onion (~250 g), finely diced for the marinade and braise","2 medium carrots (~250 g), cut into 2 cm chunks","4 garlic cloves, minced","30 g unsalted butter + 2 tbsp olive oil for searing","3 tbsp all-purpose flour","1 bouquet garni: 3 thyme sprigs + 2 bay leaves + 6 parsley stems tied with kitchen string","250 g pearl onions (silverskin), peeled","250 g cremini or button mushrooms, halved or quartered","30 g extra butter for the mushroom-and-pearl-onion garnish","1.5 tsp salt + 1 tsp freshly ground black pepper","2 tbsp Cognac OR brandy for optional flambé","Fresh flat-leaf parsley + baguette + boiled new potatoes or buttered egg noodles to serve"],"ro":["1.5 kg pulpă de vită (chuck) sau gambă, tăiată în cuburi de 4 cm (cu ceva marmurare pentru bogăție)","200 g lardoni (piept de porc afumat tăiat 1 cm × 3 cm) SAU 200 g bacon gros tăiat cubulețe","750 ml vin roșu Burgundia robust (Pinot Noir) — NU folosi vin ieftin","200 ml supă de vită","2 linguri pastă de roșii","1 ceapă mare (~250 g), tăiată mărunt pentru marinadă și pentru tocană","2 morcovi medii (~250 g), tăiați în bucăți de 2 cm","4 căței de usturoi, tocați mărunt","30 g unt nesărat + 2 linguri ulei de măsline pentru rumenire","3 linguri făină universală","1 buchet garni: 3 crenguțe cimbru + 2 foi de dafin + 6 cozi de pătrunjel legate cu sfoară de bucătărie","250 g ceapă perlată (silverskin), curățată","250 g ciuperci cremini sau champignon, tăiate în jumătăți sau sferturi","30 g unt suplimentar pentru garnitura de ciuperci și ceapă perlată","1.5 linguriță sare + 1 linguriță piper negru proaspăt măcinat","2 linguri Cognac SAU brandy pentru flambare opțională","Pătrunjel proaspăt cu frunza plată + baghetă + cartofi noi fierți sau tăiței cu unt pentru servire"]},"howIsMade":{"ru":"ЗАМАРИНУЙТЕ ГОВЯДИНУ (за 12–24 ч заранее, не подлежащее обсуждению правило Джулии Чайлд): поместите 1.5 кг кубиков говядины в не реактивную миску с 750 мл красного бургундского + 1 нарезанная луковица + 1 нарезанная морковь + 4 зубчика чеснока + букет гарни + 1 ч; перца; накройте и поставьте в холодильник на 12–24 часа; слейте через сито, СОХРАНЯЯ вино; очень тщательно обсушите говядину бумажным полотенцем — мокрое мясо тушится на пару, никогда не обжаривается; вЫТОПИТЕ ЛАРДОНЫ: в тяжёлой чугунной кастрюле на среднем огне готовьте 200 г лардонов 6–8 мин до хрустящей золотистой корочки и полного вытапливания жира. Выньте шумовкой на тарелку; оставьте 2 ст; жира в кастрюле; оБЖАРЬТЕ ГОВЯДИНУ: увеличьте огонь до сильного; добавьте 1 ст; оливкового масла + 15 г сливочного масла. Работая в 3–4 партии без перенасыщения, обжаривайте сухие кубики говядины по 2–3 мин с каждой стороны до глубокого подрумянивания со всех сторон — около 8 мин на партию; переложите каждую партию на поднос; тёмная корочка, прилипшая ко дну кастрюли, является основой вкуса — оставьте её; сОФРИТО + ФЛАМБЕ: уменьшите огонь до среднего; добавьте в кастрюлю 250 г нарезанного лука + 250 г кусочков моркови; готовьте 5 мин до начала размягчения. Вмешайте 4 измельчённых зубчика чеснока + 2 ст; томатной пасты и готовьте 1 мин; влейте 2 ст; коньяка и осторожно подожгите (пламя гаснет за 30 с); или пропустите фламбе и просто добавьте коньяк как деглазирование; сТРОИТЕ ТУШЁНОЕ БЛЮДО: посыпьте овощи 3 ст. муки и перемешивайте 1 мин, чтобы убрать сырой вкус; медленно влейте зарезервированное вино, помешивая и соскребая дно для подъёма корочки; добавьте 200 мл говяжьего бульона + букет гарни + 1.5 ч; соли + 1 ч; перца; верните в кастрюлю говядину + лардоны — жидкость должна едва покрывать всё. МЕДЛЕННОЕ ТУШЕНИЕ: доведите до лёгкого кипения; накройте крышкой, слегка приоткрытой, и переложите в духовку при 160 °C (или тушите на плите на минимальном огне) на 2.5–3 часа, помешивая каждые 45 мин, до тех пор, пока говядина не станет распадающейся на куски нежной, а соус не загустеет до блестящей обволакивающей ложку насыщенности; выбросите букет гарни; гАРНИР ИЗ ЖЕМЧУЖНОГО ЛУКА + ГРИБОВ: в отдельной сковороде растопите 15 г сливочного масла на среднем огне; добавьте 250 г очищенного жемчужного лука + 1 ст; воды + 1 ч. сахара + щепотку соли, накройте и готовьте 15 мин, затем откройте и подрумяньте 5 мин до глянцевого золотистого цвета; в той же сковороде добавьте ещё 15 г сливочного масла и 250 г грибов, обжаривайте 6–8 мин в 2 партии до глубокого золотисто-коричневого цвета — никогда не переполняйте сковороду; сОБЕРИТЕ И ПОДАВАЙТЕ: вмешайте жемчужный лук + грибы в тушёное блюдо; прогрейте вместе 5 мин; попробуйте и отрегулируйте соль; дайте тушёному блюду отдохнуть 10 мин вне огня — ароматы драматически углубляются. Подавайте щедрыми порциями в глубоких тарелках поверх варёного молодого картофеля (или яичной лапши со сливочным маслом), с хрустящим багетом для собирания соуса, посыпайте свежей нарезанной петрушкой; вСЕГДА лучше на следующий день — ароматы вступают в брак за ночь; выпейте бутылку того же бургундского, с которым вы готовили.","en":"Place 1.5 kg cubed beef in a non-reactive bowl with the 750 ml red Burgundy, 1 chopped onion, 1 chopped carrot, 4 garlic cloves, the bouquet garni and 1 tsp pepper, then cover and refrigerate for 12-24 hours; drain through a sieve while reserving the wine, and pat the beef very dry with paper towel so it sears rather than steams. In a heavy Dutch oven over medium heat, cook 200 g lardons for 6-8 minutes until crisp and golden and the fat is fully rendered, then lift them out with a slotted spoon and leave 2 tbsp of rendered fat behind in the pot. Raise the heat to high and add 1 tbsp olive oil plus 15 g butter, then sear the dried beef cubes in 3-4 uncrowded batches for 2-3 minutes per side (about 8 minutes per batch) until deeply browned on all sides; transfer each batch to a tray and leave the dark fond stuck to the pot as your flavour base. Reduce the heat to medium, add 250 g diced onion and 250 g carrot chunks and cook 5 minutes until starting to soften, then stir in 4 minced garlic cloves and 2 tbsp tomato paste and cook 1 minute; pour in 2 tbsp Cognac and ignite carefully (the flames die in 30 seconds), or skip the flambe and simply use the Cognac to deglaze. Sprinkle 3 tbsp flour over the vegetables and stir for 1 minute to cook out the raw taste, then pour in the reserved wine slowly while scraping the bottom to lift the fond, add 200 ml beef stock, the bouquet garni, 1.5 tsp salt and 1 tsp pepper, and return the beef and lardons to the pot so the liquid barely covers everything. Bring to a gentle simmer, cover with the lid slightly ajar and transfer to a 160 °C oven (or simmer on the lowest stovetop heat) for 2.5-3 hours, stirring every 45 minutes until the beef is fall-apart tender and the sauce has thickened to a glossy coats-the-spoon consistency; discard the bouquet garni. In a separate skillet, melt 15 g butter over medium heat, add 250 g peeled pearl onions with 1 tbsp water, 1 tsp sugar and a pinch of salt, cover and cook 15 minutes, then uncover and brown 5 minutes until glossy and golden; in the same skillet add another 15 g butter and 250 g mushrooms and saute 6-8 minutes in 2 batches until deeply golden brown, never crowding the pan. Fold the pearl onions and mushrooms into the braise and warm together 5 minutes, then taste and adjust the salt and let the braise rest 10 minutes off the heat so the flavours deepen; serve generous portions in deep plates over boiled new potatoes (or buttered egg noodles), scatter with chopped fresh flat-leaf parsley and offer crusty baguette to mop up the sauce -- it is always better the next day, and pairs perfectly with a bottle of the same Burgundy you cooked with."}},{"id":179,"servings":2,"tipType":"veg","pairingsType":"middle-eastern","origin":{"ru":"Тунис","en":"Tunisia","ro":"Tunisia"},"name":{"ru":"Чакчука","en":"Chakchouka","ro":"Chakchouka"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["4 крупных яйца комнатной температуры","4 ст. л. оливкового масла extra-virgin (тунисского или средиземноморского)","1 средняя жёлтая луковица (~150 г), мелко нарезанная","2 сладких красных болгарских перца (~300 г), очищенных от семян и нарезанных кубиками 1 см","1 маленький красный перец чили, мелко нарезанный ИЛИ 1 ч. л. тунисской пасты харисса (более традиционный выбор)","4 зубчика чеснока, измельчённых","1 ч. л. молотого тмина (kamoun) — тёплая пряная основа","1 ч. л. молотого тмина обыкновенного / каравая (karwiya) — ОПРЕДЕЛЯЮЩАЯ тёплая пряность Туниса, НЕ то же самое, что зира, несмотря на схожий вид; заменить семенем фенхеля, если недоступно","1 ч. л. сладкой паприки","0.5 ч. л. молотого кориандра","400 г измельчённых помидоров в банке (или 4 спелых помидора, очищенных и натёртых)","1 ст. л. томатной пасты для тела","1 ч. л. соли + 0.5 ч. л. свежемолотого чёрного перца + щепотка сахара для баланса кислотности","60 г сыра типа фета (тунисского или болгарского, раскрошенного, по желанию) + свежая плосколистная петрушка + кинза + дольки лимона + свежий багет или тунисский хобз табуна для подачи"],"en":["4 large eggs at room temperature","4 tbsp extra-virgin olive oil (Tunisian or Mediterranean)","1 medium yellow onion (~150 g), finely diced","2 mild red bell peppers (~300 g), seeded and cut into 1 cm dice","1 small red chili finely chopped OR 1 tsp Tunisian harissa paste (the more traditional choice)","4 garlic cloves, minced","1 tsp ground cumin (kamoun) — the warm spice base","1 tsp ground caraway (karwiya) — Tunisia's DEFINING warm spice, NOT the same as cumin despite looking similar; substitute fennel seed if unavailable","1 tsp sweet paprika","0.5 tsp ground coriander","400 g can crushed tomatoes (or 4 ripe tomatoes peeled and grated)","1 tbsp tomato paste for body","1 tsp salt + 0.5 tsp freshly ground black pepper + a pinch of sugar to balance acidity","60 g feta-style cheese (Tunisian or Bulgarian-style, crumbled, optional) + fresh flat-leaf parsley + cilantro + lemon wedges + fresh baguette or Tunisian khobz tabouna to serve"],"ro":["4 ouă mari la temperatura camerei","4 linguri ulei de măsline extravirgin (tunisian sau mediteranean)","1 ceapă galbenă medie (~150 g), tăiată mărunt","2 ardei graşi roşii blânzi (~300 g), curăţaţi de seminţe şi tăiaţi în cuburi de 1 cm","1 ardei iute roşu mic tocat mărunt SAU 1 linguriţă pastă de harissa tunisiană (alegerea mai tradiţională)","4 căţei de usturoi, tocaţi mărunt","1 linguriţă chimion măcinat (kamoun) — baza de mirodenii calde","1 linguriţă chimen măcinat (karwiya) — mirodenia caldă DEFINITORIE a Tunisiei, NU acelaşi lucru cu chimionul deşi arată asemănător; înlocuieşte cu sămânţă de fenicul dacă nu este disponibil","1 linguriţă boia dulce","0.5 linguriţă coriandru măcinat","400 g roşii zdrobite la cutie (sau 4 roşii coapte decojite şi rase)","1 lingură pastă de roşii pentru corp","1 linguriţă sare + 0.5 linguriţă piper negru proaspăt măcinat + un vârf de zahăr pentru echilibrul acidităţii","60 g brânză tip feta (tunisiană sau bulgărească, sfărâmată, opţional) + pătrunjel proaspăt cu frunza lată + coriandru + felii de lămâie + baghetă proaspătă sau khobz tabouna tunisian pentru servire"]},"howIsMade":{"ru":"ПОДГОТОВЬТЕ АРОМАТНЫЕ ИНГРЕДИЕНТЫ: чакчука готовится быстро — mise-en-place не подлежит обсуждению; нарежьте кубиками 150 г лука + 300 г красного болгарского перца + 1 красный перец чили; измельчите 4 зубчика чеснока; отмерьте квартет специй — тмин + каравай + паприку + кориандр — в маленькую миску; караваи делает это блюдо тунисским, а не израильской или левантийской шакшукой. РАЗОГРЕЙТЕ МАСЛО: нагрейте 4 ст; л; оливкового масла в тяжёлой сковороде 24 см (чугун идеально — глиняный тажин самый традиционный тунисский) на среднем огне до мерцания. SOFFRITTO: добавьте 150 г нарезанного лука со щепоткой соли и готовьте 6–8 мин, пока он не станет очень мягким и прозрачным — НЕ подрумяненным; тунисская чакчука требует сладости медленно пропотевшего лука, а не карамелизации. ПЕРЦЫ + ЧИЛИ + ЧЕСНОК: добавьте 300 г нарезанного красного болгарского перца + 1 нарезанный красный чили (или 1 ч; л; хариссы); готовьте 6–8 мин, пока перец не станет мягким, но всё ещё ярко-красным; добавьте 4 измельчённых зубчика чеснока и готовьте 1 мин до появления аромата. ОТКРОЙТЕ СПЕЦИИ: добавьте смесь специй (1 ч; л; тмина + 1 ч; л; каравая + 1 ч; л; паприки + 0.5 ч; л; кориандра) прямо в горячую масло-овощную основу; помешивайте 30 секунд до интенсивного аромата — не сожгите, иначе блюдо станет горьким. ПОСТРОЙТЕ СОУС: вмешайте 1 ст; л; томатной пасты и готовьте 1 мин; влейте 400 г измельчённых помидоров + 1 ч; л; соли + 0.5 ч; л; перца + щепотку сахара; тушите 8–10 мин, периодически помешивая, пока соус не загустеет — ложка, проведённая по поверхности, должна оставлять чёткий след, который не заполняется сразу. ДОБАВЬТЕ ЯЙЦА: тыльной стороной ложки сделайте 4 углубления в кипящем соусе; разбейте по 1 яйцу в каждое углубление — сохраняйте желтки целыми; посыпьте щепоткой соли белки и поверните мельницу с перцем над желтками; накройте сковороду крышкой и готовьте на средне-малом огне 4–6 мин, пока белки не схватятся, а желтки останутся жидкими — заглядывайте под крышку; белки должны быть непрозрачными, а желтки всё ещё ярко-оранжевыми и дрожащими. ЗАВЕРШИТЕ И ПОДАЙТЕ: посыпьте сверху 60 г раскрошенной феты + щедрую горсть нарезанной петрушки и кинзы; подавайте сковороду прямо к столу — чакчука всегда общая, едят прямо со сковороды; каждый отрывает кусок свежего багета или khobz tabouna и использует его, чтобы собирать соус и разбивать желток; выжмите дольку лимона на свою порцию; лучше всего в течение 10 минут после приготовления, пока желтки ещё расплавлены.","en":"PREP THE AROMATICS: chakchouka cooks fast — mise-en-place is non-negotiable; dice 150 g onion + 300 g red bell peppers + 1 red chili; mince 4 garlic; measure the spice quartet — cumin + caraway + paprika + coriander — into a small bowl; the caraway is what makes this Tunisian and not Israeli or Levantine shakshuka. WARM THE OIL: heat 4 tbsp olive oil in a heavy 24 cm skillet (cast iron is ideal — earthenware tagine is the most traditional Tunisian) over medium heat until shimmering. SOFFRITTO: add 150 g diced onion with a pinch of salt and cook 6–8 min until very soft and translucent — NOT browned; tunisian chakchouka wants the sweetness of slowly-sweated onions, not caramelization. PEPPERS + CHILI + GARLIC: add 300 g diced red bell peppers + 1 chopped red chili (or 1 tsp harissa); cook 6–8 min until peppers are softened but still bright red; add 4 minced garlic and cook 1 min until fragrant. BLOOM THE SPICES: add the spice mix (1 tsp cumin + 1 tsp caraway + 1 tsp paprika + 0.5 tsp coriander) directly into the hot oil-and-vegetable base; stir 30 seconds until intensely aromatic — do not burn, or the dish turns bitter. BUILD THE SAUCE: stir in 1 tbsp tomato paste and cook 1 min; pour in 400 g crushed tomatoes + 1 tsp salt + 0.5 tsp pepper + a pinch of sugar; simmer 8–10 min, stirring occasionally, until the sauce has thickened — a spoon dragged through the surface should leave a clear trail that does not immediately fill back in. ADD EGGS: with the back of a spoon, make 4 wells in the simmering sauce; crack 1 egg into each well — keep yolks intact; sprinkle a pinch of salt over the whites and a twist of pepper over the yolks; cover the skillet with a lid and cook over medium-low heat 4–6 min, until the whites are just set but the yolks remain runny — peek through the lid; the whites should be opaque and the yolks still bright orange and trembling. FINISH AND SERVE: scatter 60 g crumbled feta + a generous handful of chopped parsley and cilantro over the top; bring the pan straight to the table — chakchouka is always communal, eaten from the skillet; each diner tears off a piece of fresh baguette or khobz tabouna and uses it to mop up the sauce and break into a yolk; squeeze a lemon wedge over your own portion; best within 10 minutes of cooking, while the yolks are still molten."}},{"id":180,"origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Окономияки","en":"Okonomiyaki","ro":"Okonomiyaki"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"ru":["200г простой муки (или кондитерской муки)","240мл холодного бульона даши (или воды + 1 ч.л. порошка даши)","2 крупных яйца","400г белокочанной капусты, мелко нашинкованной","200г тонко нарезанной свиной грудинки (бута-бара), нарезанной кусочками по 5 см","2 ст.л. тэнкасу (обрезки темпуры, по желанию)","½ ч.л. разрыхлителя","4 ст.л. японского майонеза (Kewpie)","4 ст.л. соуса окономияки (марки Otafuku)","1 ч.л. соуса Вустершир","кацуобуси (стружка сушёного тунца) для подачи","аонори (порошок из водорослей) для подачи"],"en":["200g plain flour (or cake flour)","240ml cold dashi stock (or water + 1 tsp dashi powder)","2 large eggs","400g white cabbage, finely shredded","200g thinly sliced pork belly (buta bara), cut into 5 cm pieces","2 tbsp tenkasu (tempura scraps, optional)","½ tsp baking powder","4 tbsp Japanese mayonnaise (Kewpie)","4 tbsp okonomiyaki sauce (e.g. Otafuku brand)","1 tsp Worcestershire sauce","katsuobushi (dried bonito flakes) to serve","aonori (powdered seaweed) to serve"],"ro":["200g făină albă simplă (sau făină pentru prăjituri)","240ml supă dashi (rece; sau apă + 1 linguriță pudră dashi)","2 ouă mari","400g varză albă, tăiată fin","200g burta de porc feliată subțire (buta bara), tăiată în bucăți de 5 cm","2 linguri tenkasu (firimituri de tempura, opțional)","½ linguriță praf de copt","4 linguri maioneză Kewpie (japoneză)","4 linguri sos okonomiyaki (ex. Otafuku)","1 linguriță sos Worcestershire","katsuobushi (fulgi de ton uscat), pentru servire","aonori (alge marine pudră), pentru servire"]},"howIsMade":{"ru":"В большой миске смешайте муку, разрыхлитель, яйца и холодный бульон даши, не перемешивая слишком долго. Добавьте капусту и тэнкасу, аккуратно вмешивая лопаткой; тесто должно быть густым. Разогрейте антипригарную сковороду на среднем огне, смажьте тонким слоем масла. Вылейте тесто и сформируйте круг толщиной ~2 см. Положите ломтики свинины поверх. Жарьте 5–6 минут на среднем-малом огне, пока края не схватятся и низ не станет золотистым. Переверните двумя лопатками, слегка прижав; жарьте ещё 5–6 минут до хрустящей свинины. Смажьте мясную сторону соусом окономияки, нанесите майонез зигзагом, посыпьте кацуобуси и аонори. Подавайте немедленно.","en":"In a large bowl whisk together flour, baking powder, eggs, and cold dashi until just combined — do not overmix. Fold in shredded cabbage and tenkasu with a spatula; the batter should be thick and mounded with cabbage. Heat a non-stick pan over medium heat, brush with a thin layer of oil. Pour batter into the pan and shape into a disc about 2 cm thick. Lay pork belly slices over the entire top surface. Cook 5–6 minutes on medium-low until the edges look set and the underside is golden-brown. Flip carefully using two spatulas, pressing lightly; cook another 5–6 minutes until pork is crisp and batter is cooked through. Brush the pork side with okonomiyaki sauce, drizzle Kewpie in a zigzag, scatter katsuobushi and aonori. Serve immediately from the pan."}},{"id":181,"servings":2,"tipType":"meat","timeMins":{"total":780,"active":120},"pairingsType":"japanese","origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Тонкоцу Рамен","en":"Tonkotsu Ramen","ro":"Ramen Tonkotsu"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1,2 кг свиных мозговых костей, бланшированных","300г свежей тонкой лапши рамен","3 ст.л. тёмного соевого соуса (для тарэ)","2 ст.л. мирина","200г чашу из свиной грудинки, нарезанной ломтиками 1 см","2 мягко сваренных яйца рамен, разрезанных пополам","80г побегов бамбука (менма), обсушенных","2 листа нори, разрезанных пополам","2 пера зелёного лука, тонко нарезанных","4 зубчика чеснока, раздавленных","30г свежего имбиря, очищенного и нарезанного","1 ч.л. поджаренного кунжутного масла"],"en":["1.2kg pork marrow bones, blanched","300g fresh thin ramen noodles","3 tbsp dark soy sauce (for tare)","2 tbsp mirin","200g chashu pork belly, sliced 1cm thick","2 soft-boiled ramen eggs, halved","80g bamboo shoots (menma), drained","2 sheets nori, halved","2 spring onions, thinly sliced","4 cloves garlic, crushed","30g fresh ginger, peeled and sliced","1 tsp toasted sesame oil"],"ro":["1,2 kg oase de porc (măduvă), opărite","300g tăiței ramen proaspeți subțiri","3 linguri sos de soia închis (pentru tare)","2 linguri mirin","200g burtă de porc chashu, feliată la 1 cm grosime","2 ouă ramen fierte moale, tăiate în jumătate","80g lăstari de bambus (menma), scurși","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate subțire","4 căței usturoi, zdrobiți","30g ghimbir proaspăt, curățat și feliat","1 linguriță ulei de susan prăjit"]},"howIsMade":{"ru":"Бланшировать кости в кипящей воде 10 минут, слить и промыть холодной водой. В большую кастрюлю с 3L холодной воды, довести до бурного кипения и держать 10–12 часов, подливая воду; интенсивное кипение белит бульон. Плотно скрутить свиную грудинку, перевязать, обжарить со всех сторон в сухой сковороде, тушить на самом слабом огне в 3 ст.л. соевого соуса, 2 ст.л. мирина, 1 ст.л. саке и 100мл воды 90 минут; отдохнуть 20 минут, нарезать по 1 см. Тарэ: 4 ст.л. соевого + 2 ст.л. мирина, кипятить 3 минуты, остудить. Сварить лапшу, откинуть. По 2 ст.л. тарэ в каждую миску, 400мл горячего бульона, чашу, яйцо, менму, нори, зелёный лук и кунжутное масло.","en":"Blanch pork bones in boiling water for 10 minutes, drain and rinse under cold water. Transfer to a large pot with 3L cold water, bring to a rolling boil and hold it there — not a simmer — for 10 to 12 hours, topping up with water as needed; the hard boil breaks down collagen and turns the broth white. Roll pork belly tightly, tie with kitchen string, sear all sides in a dry pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on the lowest heat for 90 minutes; rest 20 minutes, slice 1cm thick. Make tare: 4 tbsp soy sauce + 2 tbsp mirin, simmer 3 minutes, cool. Cook noodles per packet, drain. Spoon 2 tbsp tare into each bowl, ladle 400ml hot broth, then top with chashu slices, halved egg, bamboo shoots, nori and spring onion. Finish with sesame oil."}},{"id":182,"servings":2,"tipType":"meat","timeMins":{"total":360,"active":90},"pairingsType":"japanese","origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Сёю Рамен","en":"Shoyu Ramen","ro":"Ramen Shoyu"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["1,5 л куриного костного бульона","2 ст.л. соевого соуса","1 ст.л. мирина","1 ст.л. саке","400г свиной грудинки, свёрнутой и перевязанной","4 крупных яйца","300г свежей лапши рамен","100г побегов бамбука (менма), промытых","4 листа нори","3 пера зелёного лука, тонко нарезанных","4 кружка рыбного пирога нарутомаки","1 ч.л. кунжутного масла"],"en":["1.5L chicken bone stock","2 tbsp soy sauce","1 tbsp mirin","1 tbsp sake","400g pork belly, rolled and tied with kitchen string","4 large eggs","300g fresh ramen noodles","100g bamboo shoots (menma), rinsed","4 sheets nori","3 spring onions, thinly sliced","4 slices narutomaki fish cake","1 tsp sesame oil"],"ro":["1,5 L supă de oase de pui","2 linguri sos de soia","1 lingură mirin","1 lingură sake","300g burtă de porc, rulată și legată","4 ouă mari","300g tăiței ramen proaspeți","100g lăstari de bambus (menma), clătiți","4 foi alge nori","3 cepe verzi, feliate subțire","4 felii pastă de pește narutomaki","1 linguriță ulei de susan"]},"howIsMade":{"ru":"Варите костный куриный бульон с имбирём, чесноком и зелёным луком 3–4 часа, процедите. Смешайте соевый соус, мирин и саке в маленькой кастрюле, варите 5 минут — это shoyu tare. Свиную грудинку плотно скрутите, перевяжите кулинарной нитью, обжарьте со всех сторон, затем тушите в соевом соусе, мирине, саке и воде на малом огне 1,5 часа; дайте отдохнуть 15 минут, нарежьте кружками 1 см. Варите яйца ровно 6,5 минут, охладите в холодной воде, очистите и замаринуйте в жидкости от чашу не менее 4 часов. Сварите лапшу, откиньте; разлейте горячий бульон по мискам (2 ст.л. тare на миску), добавьте лапшу и разложите топпинги: чашу, половинку яйца, менму, нори, зелёный лук, нарутомаки и каплю кунжутного масла.","en":"Simmer chicken bone stock with a 5cm piece of ginger, 3 garlic cloves and 2 spring onions for 3–4 hours, strain and discard solids. Mix soy sauce, mirin and sake in a small pan, simmer 5 minutes to cook off the alcohol — this is the shoyu tare. Roll pork belly tightly, tie with kitchen string, sear on all sides in a hot pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on low heat for 1.5 hours; rest 15 minutes before slicing into 1cm rounds. Soft-boil eggs exactly 6.5 minutes, cool in cold water, peel and submerge in the remaining chashu braising liquid for at least 4 hours. Cook noodles per packet, drain; ladle hot broth into bowls (2 tbsp shoyu tare per bowl), add noodles and top with sliced chashu, halved egg, bamboo shoots, nori, spring onions, narutomaki and a drizzle of sesame oil."}},{"id":183,"servings":2,"tipType":"def","pairingsType":"japanese","origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Мисо Рамен","en":"Miso Ramen","ro":"Ramen Miso"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["1,5L куриного или свиного костного бульона","3 ст.л. красной или белой пасты мисо","300г свежей лапши рамен","150г свиного фарша","80г консервированной кукурузы, обсушенной","1 ст.л. несолёного сливочного масла","60г побегов бамбука, обсушенных и нарезанных","2 мягко сваренных маринованных яйца рамен, разрезанных пополам","2 листа нори, разрезанных пополам","2 пера зелёного лука, нарезанных","1 ч.л. поджаренных семян кунжута","80г свежих ростков фасоли, бланшированных"],"en":["1.5L chicken or pork bone broth","3 tbsp red or white miso paste","300g fresh ramen noodles","150g ground pork","80g canned corn kernels, drained","1 tbsp unsalted butter","60g bamboo shoots, drained and sliced","2 soft-boiled ramen eggs, halved","2 sheets nori, halved","2 spring onions, sliced","1 tsp toasted sesame seeds","80g fresh bean sprouts, blanched"],"ro":["1,5L supă de oase de pui sau porc","3 linguri pastă miso roșu sau alb","300g tăiței ramen proaspeți","150g carne tocată de porc","80g porumb din conservă, scurs","1 lingură unt nesărat","60g lăstari de bambus, scurși și feliați","2 ouă fierte moale, marinate, tăiate în jumătate","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate","1 linguriță semințe de susan prăjit","80g muguri de fasole proaspeți, opăriți"]},"howIsMade":{"ru":"Обжарьте чеснок и свиной фарш в воке на сильном огне, разминая мясо, пока оно не перестанет быть розовым. Добавьте пасту мисо и жарьте 60 секунд до слабого потемнения. Влейте горячий бульон и доведите до лёгкого кипения — не кипятить сильно после добавления мисо. Добавьте масло, перемешайте до растворения. Сварите лапшу отдельно, откиньте. Разложите лапшу по мискам, залейте бульоном мисо. Сверху выложите кукурузу, ростки, маринованное яйцо, менму, нори и зелёный лук. Посыпьте кунжутом в последний момент.","en":"Sauté garlic and ground pork in a wok over high heat, breaking up the meat as it cooks, until no pink remains. Add miso paste and stir-fry 60 seconds until it darkens slightly. Pour in hot broth and bring to a low simmer — do not boil hard once miso is in or it loses its fermented edge. Add butter and stir until melted. Cook noodles per packet, drain. Divide noodles between two bowls, ladle miso broth over. Top with corn, bean sprouts, halved ramen egg, bamboo shoots, nori and spring onion. Scatter sesame seeds last."}},{"id":184,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":480,"prot":22,"carb":38,"fat":26,"fib":3},"origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Темпура","en":"Tempura","ro":"Tempura"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["400 г крупных креветок (8–12 шт. с головой, очищенных, но с хвостами), без кишечной вены, обсушенных насухо","1 небольшая японская сладкая картофель (~200 г), очищенная, нарезанная кружками толщиной 5 мм","200 г тыквы кабоча, нарезанной полумесяцами по 5 мм (с кожицей)","1 японский баклажан, нарезанный наискось ломтиками 1 см","6 свежих грибов шиитаке, без ножек, на шляпках сделаны крестообразные надрезы","100 г перцев шишито или тонких зелёных перцев, наколотых вилкой, чтобы не лопнули","Для кляра (замешивать В ПОСЛЕДНЮЮ ОЧЕРЕДЬ, прямо перед жаркой): 1 крупное яйцо, 250 мл ледяной газированной воды, 150 г просеянной пшеничной муки","30 г дополнительной муки для обваливания кусочков перед погружением в кляр","1,5 л нейтрального масла для фритюра (рисового или растительного)","Для соуса тэнцую: 200 мл даси, 60 мл соевого соуса, 60 мл мирина","30 г дайкона, мелко натёртого и слегка отжатого","10 г свежего имбиря, мелко натёртого","Мелкая морская соль и дольки лимона — для подачи"],"en":["400 g large prawns (8–12 head-on, peeled but tails on), deveined and patted bone-dry","1 small Japanese sweet potato (~200 g), peeled and cut into 5 mm rounds","200 g kabocha squash, cut into 5 mm half-moons (skin left on)","1 Japanese eggplant, cut on the bias into 1 cm slices","6 fresh shiitake mushrooms, stems trimmed, caps scored with an X","100 g shishito or thin green peppers, each pricked with a fork so they don't burst","For the batter (mix LAST, just before frying): 1 large egg, 250 ml ice-cold sparkling water, 150 g plain (cake) flour, sifted","30 g extra plain flour for dusting the pieces before dipping","1.5 L neutral oil for deep-frying (rice bran or vegetable)","For the tentsuyu dipping sauce: 200 ml dashi, 60 ml soy sauce, 60 ml mirin","30 g daikon, finely grated and lightly squeezed","10 g fresh ginger, finely grated","Fine sea salt and lemon wedges, to serve"],"ro":["400 g creveți mari (8–12 bucăți cu cap, decojiți dar cu coadă), curățați de vinișor și șterși bine de umiditate","1 cartof dulce japonez mic (~200 g), curățat și tăiat rondele de 5 mm","200 g dovleac kabocha, tăiat semilune de 5 mm (cu coajă)","1 vânătă japoneză, tăiată oblic în felii de 1 cm","6 ciuperci shiitake proaspete, fără picioare, capul crestat în X","100 g ardei shishito sau ardei verzi subțiri, fiecare înțepat cu furculița ca să nu plesnească","Pentru aluat (se amestecă LA FINAL, chiar înainte de prăjit): 1 ou mare, 250 ml apă minerală foarte rece, 150 g făină simplă cernută","30 g făină simplă suplimentară pentru pudrat bucățile înainte de înmuierea în aluat","1.5 L ulei neutru pentru prăjit (de orez sau vegetal)","Pentru sosul tentsuyu: 200 ml dashi, 60 ml sos de soia, 60 ml mirin","30 g daikon, ras fin și stors ușor","10 g ghimbir proaspăt, ras fin","Sare fină de mare și felii de lămâie, pentru servit"]},"howIsMade":{"ru":"Промокните креветки и овощи насухо, затем сделайте три неглубоких надреза на брюшке каждой креветки и слегка прижмите вдоль спинки, чтобы они жарились прямо, не сворачиваясь.\n\nДля тэнцую коротко доведите даси, соевый соус и мирин до кипения, чтобы испарился алкоголь, разлейте по маленьким пиалам, а тёртый дайкон и имбирь поставьте рядом.\n\nРазогрейте масло в тяжёлой кастрюле до 175°C, измеряя термометром-щупом.\n\nПрямо перед жаркой взбейте яйцо в ледяной газировке в охлаждённой миске, всыпьте всю просеянную муку разом и сделайте всего пять-восемь движений палочками — в кляре должны оставаться полоски сухой муки.\n\nЛегко обваляйте каждый кусочек в дополнительной муке, окуните в кляр и опустите в масло по четыре-пять штук за раз; креветкам и шиитаке нужно около 90 секунд, баклажану и кабоче — 2 минуты, батату — 3 минуты, шишито — около минуты, а корочка должна оставаться бледно-кремовой.\n\nПереложите на решётку с бумагой под ней и подавайте сразу — с тэнцую, дайконом и имбирём для размешивания, либо с овощами под щепотку мелкой соли и каплю лимона.","en":"Pat the prawns and vegetables completely dry, then make three shallow cuts on the underside of each prawn and press gently along the spine so they fry straight rather than curling.\n\nFor the tentsuyu, bring the dashi, soy sauce and mirin briefly to a simmer to cook off the alcohol, then divide between small dipping bowls and set the grated daikon and ginger alongside.\n\nHeat the oil in a heavy pot to 175°C, measured with a probe thermometer.\n\nJust before frying, beat the egg into the ice-cold sparkling water in a chilled bowl, tip in the sifted flour all at once and stir only five to eight strokes — the batter should still show streaks of dry flour.\n\nDust each piece lightly with the extra flour, dip into the batter, and slip into the oil four or five at a time; prawns and shiitake take about 90 seconds, eggplant and kabocha 2 minutes, sweet potato 3 minutes, shishito a minute, and the crust should stay pale ivory.\n\nLift onto a wire rack set over paper and serve straight away, with the tentsuyu, daikon and ginger to stir in, or the vegetables with a pinch of fine salt and a squeeze of lemon."}},{"id":185,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":280,"prot":7,"carb":52,"fat":4,"fib":2},"origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Онигири","en":"Onigiri","ro":"Onigiri"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["500 г японского короткозёрного риса (Koshihikari или рис для суши)","600 мл свежей холодной воды для варки (рис:вода ~1:1,1)","Для тэдзу (вода для рук): 200 мл тёплой воды + 1,5 ч. л. мелкой морской соли","4 листа поджаренного нори, нарезанных полосками ~3 см шириной × длина листа","Начинка 1 — тунец с майонезом: 80 г консервированного тунца (откинутого), 1,5 ст. л. японского майонеза, ½ ч. л. соевого соуса","Начинка 2 — умэбоси: 60 г солёных слив без косточек, слегка размятых вилкой","Начинка 3 — сиодзакэ (солёный лосось на гриле): 100 г филе лосося на гриле, без кожи, разобранного хлопьями","Начинка 4 — окака: 8 г стружки бонито, смешанной с 1 ч. л. соевого соуса","Для рисовых шариков без начинки: 2 ст. л. фурикакэ (приправа для риса) для обкатки снаружи","По желанию: несколько кунжутных семян на поверхность"],"en":["500 g Japanese short-grain rice (Koshihikari or sushi rice)","600 ml fresh cold water for cooking (rice to water ratio ~1:1.1)","For the tezu (finger water): 200 ml warm water + 1.5 tsp fine sea salt","4 sheets toasted nori, cut into strips about 3 cm wide × the length of the sheet","Filling option 1 — tuna mayo: 80 g canned tuna (drained), 1.5 tbsp Japanese mayonnaise, ½ tsp soy sauce","Filling option 2 — umeboshi: 60 g pitted salted plums, lightly mashed with a fork","Filling option 3 — shiozake (grilled salted salmon): 100 g salmon fillet grilled and flaked, with the skin removed","Filling option 4 — okaka: 8 g bonito flakes mixed with 1 tsp soy sauce","For plain onigiri: 2 tbsp furikake (rice seasoning), to coat the outside","Optional: a few sesame seeds for the surface of plain ones"],"ro":["500 g orez japonez cu bobul scurt (Koshihikari sau orez pentru sushi)","600 ml apă rece proaspătă pentru fiert (raport orez:apă ~1:1.1)","Pentru tezu (apa de mâini): 200 ml apă caldă + 1.5 linguriță sare fină de mare","4 foi de nori prăjit, tăiate fâșii de ~3 cm lățime × lungimea foii","Umplutură opțiunea 1 — ton cu maioneză: 80 g ton la conservă (scurs), 1.5 lingură maioneză japoneză, ½ linguriță sos de soia","Umplutură opțiunea 2 — umeboshi: 60 g prune sărate fără sâmburi, ușor strivite cu furculița","Umplutură opțiunea 3 — shiozake (somon sărat la grătar): 100 g file de somon făcut la grătar, fără piele, fărâmițat","Umplutură opțiunea 4 — okaka: 8 g fulgi de bonito amestecați cu 1 linguriță sos de soia","Pentru onigiri simplu: 2 linguri furikake (condiment pentru orez), pentru exterior","Opțional: câteva semințe de susan pentru exterior"]},"howIsMade":{"ru":"Промойте рис в холодной воде четыре-пять раз, пока вода не станет почти прозрачной, дайте стечь в сите 20 минут, затем сварите с 600 мл свежей воды в тяжёлой кастрюле или рисоварке и после варки оставьте под крышкой ещё на 10 минут.\n\nПока рис отдыхает, разомните умэбоси вилкой, смешайте тунец с японским майонезом в кремовую пасту и разберите на хлопья жареный лосось — на один онигири нужна лишь столовая ложка начинки.\n\nРастворите соль в тёплой воде, чтобы получить тэдзу — воду для рук, которая не даёт рису липнуть к ладоням и слегка солит наружный слой.\n\nВыложите горячий рис на широкий поднос, аккуратно распушите его деревянной лопаткой и дайте остыть до температуры, при которой он только-только удобен для лепки.\n\nСмочите ладони в тэдзу, возьмите около 100 г риса, сделайте углубление в центре, положите столовую ложку начинки и соберите рис вокруг неё; сожмите ладонь и придайте треугольнику с тремя плоскими гранями — твёрдо, но не сминая в брикет.\n\nОберните полоску нори у основания каждого треугольника прямо перед едой, чтобы водоросль осталась хрустящей; для онигири без начинки обваляйте поверхность в фурикакэ. Ешьте при комнатной температуре в течение 4 часов.","en":"Rinse the rice in cold water four or five times until the water runs almost clear, drain in a strainer for 20 minutes, then cook with the 600 ml of fresh water in a heavy pot or rice cooker; once cooked, rest off the heat with the lid on for 10 minutes.\n\nWhile the rice rests, mash the umeboshi with a fork, mix the tuna with the Japanese mayonnaise into a creamy paste, and flake the grilled salmon — each onigiri needs only about a tablespoon of filling.\n\nDissolve the salt in the warm water to make the tezu; this is the finger water that keeps the rice from sticking to your palms and lightly salts the outside.\n\nTip the hot rice onto a wide tray, fluff gently with a wooden paddle and let it cool until just warm enough to handle.\n\nWet your palms in the tezu, take about 100 g of rice in your palm, press a hollow in the centre, drop in a tablespoon of filling and gather the rice around it; cup your hand and press into a triangle with three flat faces, firm but not crushed.\n\nWrap a strip of nori around the base of each triangle just before eating so the seaweed stays crisp; for plain onigiri, roll the outside in furikake instead. Eat at room temperature within 4 hours."}},{"id":186,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":360,"prot":36,"carb":8,"fat":18,"fib":1},"origin":{"ru":"Япония","en":"Japan","ro":"Japonia"},"name":{"ru":"Якитори","en":"Yakitori","ro":"Yakitori"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["600 г куриных бёдер без кости с кожей, нарезанных кубиками 2,5 см","6 толстых зелёных луковиц (или 2 неги), белые и светло-зелёные части — кусочками по 3 см (~150 г)","16 коротких бамбуковых шпажек (15 см), вымоченных в холодной воде 30 минут","Для тарэ: 120 мл тёмного соевого соуса, 120 мл мирина, 60 мл саке, 30 г светло-коричневого сахара","Мелкая морская соль для шпажек сио","1 ч. л. нейтрального масла для решётки","Шичими тогараши — для подачи","Дольки лимона — для подачи"],"en":["600 g boneless, skin-on chicken thighs, cut into 2.5 cm cubes","6 fat spring onions (or 2 negi), white and pale green parts cut into 3 cm pieces (~150 g total)","16 short bamboo skewers (15 cm), soaked in cold water for 30 minutes","For the tare: 120 ml dark soy sauce, 120 ml mirin, 60 ml sake, 30 g light brown sugar","Fine sea salt for the shio skewers","1 tsp neutral oil for the grate","Shichimi togarashi, to serve","Lemon wedges, to serve"],"ro":["600 g pulpe de pui dezosate cu piele, tăiate cuburi de 2.5 cm","6 cepe verzi mari (sau 2 negi), partea albă și verde-deschis tăiată bucățele de 3 cm (~150 g)","16 frigărui scurte de bambus (15 cm), înmuiate în apă rece 30 de minute","Pentru tare: 120 ml sos de soia închis, 120 ml mirin, 60 ml sake, 30 g zahăr brun deschis","Sare fină de mare pentru frigăruile shio","1 linguriță ulei neutru pentru grătar","Shichimi togarashi, pentru servit","Felii de lămâie, pentru servit"]},"howIsMade":{"ru":"Нарежьте куриное бедро кубиками 2,5 см, белые части зелёного лука — кусочками по 3 см и замочите бамбуковые шпажки в холодной воде на 30 минут, чтобы они не сгорели на гриле.\n\nДля тарэ соедините в небольшом сотейнике соевый соус, мирин, саке и коричневый сахар, варите примерно 10 минут до лёгкой сиропообразной консистенции и остудите.\n\nСобирайте шпажки в двух стилях: негима чередует курицу, лук, курицу, лук, курицу; момо — это только кубики курицы, плотно посаженные, но не сдавленные.\n\nРазогрейте угольный гриль или тяжёлую грилл-сковороду на сильном огне и слегка смажьте решётку маслом.\n\nВыложите шпажки кожей или жирной стороной вниз и жарьте 3–4 минуты до густого золотистого цвета, затем переверните и готовьте ещё 2–3 минуты.\n\nДля шпажек с тарэ обмакните их в холодный соус, верните на гриль на 30 секунд для глазури и повторите ещё раз; шпажки сио посолите щепоткой соли прямо с гриля. Подавайте сразу с шичими тогараши и лимоном.","en":"Cut the chicken thigh into 2.5 cm cubes and the white parts of the spring onions into 3 cm pieces, then soak the bamboo skewers in cold water for 30 minutes so they don't burn on the grill.\n\nFor the tare, simmer the soy sauce, mirin, sake and brown sugar in a small pan for about 10 minutes until lightly syrupy, then let it cool to room temperature.\n\nThread the skewers in two styles: negima alternates chicken, scallion, chicken, scallion, chicken; momo is just chicken cubes packed close together but not squashed.\n\nHeat a charcoal grill or a heavy grill pan over high heat and lightly oil the grate.\n\nLay the skewers down with the skin or fattiest side first and grill for 3–4 minutes until deep golden, then flip and cook another 2–3 minutes.\n\nFor tare skewers, dip in the cooled sauce, return to the grill for 30 seconds to glaze, then dip and glaze once more; season the shio skewers with a pinch of salt straight off the heat. Serve at once with shichimi togarashi and lemon."}},{"id":187,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":520,"prot":38,"carb":22,"fat":28,"fib":6},"origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Моле побла́но","en":"Mole Poblano","ro":"Mole Poblano"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["80 г сухих перцев чили в смеси — 3 анчо + 3 мулато + 2 пасилья — без плодоножек и семян","1 перец чипотле в адобо, плюс 1 ст. л. соуса от него","100 г бланшированного миндаля и 80 г сырого арахиса","30 г сырых кунжутных семян (плюс ещё для украшения) и 60 г изюма","2 крупных спелых помидора, разрезанных пополам; 1 небольшая белая луковица, нарезанная на четверти; 3 зубчика чеснока в кожуре","1 палочка корицы, 2 бутона гвоздики, 1 звёздочка бадьяна и 6 горошин чёрного перца","2 кукурузные тортильи, разорванные на кусочки — традиционный загуститель","60 г мексиканского шоколада, поломанного (или 50 г тёмного шоколада + 1 ч. л. корицы + 1 ст. л. светло-коричневого сахара)","1.2 л несолёного куриного бульона, тёплого","3 ст. л. свиного смальца (manteca) или нейтрального масла","4 куриных бедра на кости, проваренных в подсоленной воде 25 минут и обсушенных","1 ч. л. мелкой морской соли и маленькая щепотка сахара","Для подачи: варёный белый рис, тёплые кукурузные тортильи, листья свежей кинзы"],"en":["80 g mixed dried chiles — 3 ancho + 3 mulato + 2 pasilla — stemmed and seeded","1 chipotle chile in adobo, plus 1 tbsp of its sauce","100 g blanched almonds and 80 g raw peanuts","30 g raw sesame seeds (plus extra to garnish) and 60 g raisins","2 large ripe tomatoes, halved; 1 small white onion, quartered; 3 garlic cloves, unpeeled","1 cinnamon stick, 2 cloves, 1 star anise and 6 black peppercorns","2 corn tortillas, torn into pieces — the traditional thickener","60 g Mexican chocolate, broken up (or 50 g dark chocolate + 1 tsp cinnamon + 1 tbsp light brown sugar)","1.2 L unsalted chicken stock, kept warm","3 tbsp lard (manteca) or neutral oil","4 bone-in chicken thighs, poached in salted water for 25 minutes and patted dry","1 tsp fine sea salt and a small pinch of sugar","To serve: cooked white rice, warm corn tortillas, fresh coriander leaves"],"ro":["80 g de ardei iuți uscați amestecați — 3 ancho + 3 mulato + 2 pasilla — fără codiță și seminţe","1 ardei chipotle în sos adobo, plus 1 lingură din sosul lui","100 g de migdale blanşate și 80 g de arahide crude","30 g de seminţe de susan crude (plus în plus pentru garnitură) și 60 g de stafide","2 roșii mari coapte, tăiate jumătăți; 1 ceapă albă mică, tăiată sferturi; 3 căţei de usturoi, necurăţaţi","1 baton de scorţișoară, 2 cuișoare, 1 stea de anason și 6 boabe de piper negru","2 tortilla de porumb, rupte în bucăţi — îngroșătorul tradiţional","60 g de ciocolată mexicană, fărâmiţată (sau 50 g de ciocolată neagră + 1 linguriţă de scorţișoară + 1 lingură de zahăr brun deschis)","1.2 L de supă de pui nesărată, ţinută caldă","3 linguri de untură (manteca) sau ulei neutru","4 pulpe de pui cu os, fierte în apă sărată 25 de minute și șterse","1 linguriţă de sare fină de mare și un vârf mic de zahăr","Pentru servit: orez alb fiert, tortilla de porumb calde, frunze de coriandru proaspăt"]},"howIsMade":{"ru":"Подсушите сухие перцы чили на сухой тяжёлой сковороде на среднем огне примерно 30 секунд с каждой стороны до появления аромата, переложите в миску, залейте горячей водой и оставьте на 20 минут.\n\nВ той же сковороде небольшими партиями подсушите миндаль, арахис, кунжут, изюм и цельные специи до лёгкой золотистости — около 2 минут каждую — и отложите.\n\nОбожгите половинки помидоров, четвертинки лука и нечищеный чеснок прямо над огнём или под раскалённым грилем до чёрных пятен, затем очистите чеснок, когда он остынет.\n\nСлейте воду с перцев (сохранив её) и смешайте их в блендере с обожжёнными овощами, чипотле и его соусом, поджаренными орехами и семенами, изюмом, специями и кусочками тортильи, добавив около 500 мл тёплого бульона до однородной тёмной пасты.\n\nРазогрейте смалец в тяжёлой кастрюле на среднем огне, влейте пасту и непрерывно мешайте 10–15 минут — моле темнеет, густеет и становится глянцевым по мере того, как ароматы поджариваются вместе.\n\nВведите оставшиеся 700 мл бульона и поломанный шоколад, томите 30–40 минут на медленном огне, часто помешивая, пока соус не начнёт обволакивать тыльную сторону ложки; приправьте солью и щепоткой сахара.\n\nПогрузите проваренные куриные бедра в моле и потомите ещё 10 минут, чтобы они напитались соусом.\n\nПодайте курицу в глубоких тарелках, щедро полейте моле и завершите кунжутом, листьями кинзы, белым рисом и тёплыми кукурузными тортильями.","en":"Toast the dried chiles in a dry heavy pan over medium heat for about 30 seconds per side until fragrant, then transfer to a bowl, cover with hot water and soak for 20 minutes.\n\nIn the same pan, toast the almonds, peanuts, sesame seeds, raisins and whole spices in small batches until just golden — about 2 minutes each — and set aside.\n\nChar the tomato halves, onion quarters and unpeeled garlic directly over a flame or under a hot broiler until blackened in patches, then peel the garlic once cool enough to handle.\n\nDrain the chiles (keeping the soaking water) and blend them with the charred vegetables, chipotle and its sauce, toasted nuts and seeds, raisins, spices and torn tortillas, adding about 500 ml of warm chicken stock to make a smooth dark paste.\n\nHeat the lard in a heavy pot over medium-high heat, pour in the paste and stir constantly for 10–15 minutes; the mole will darken, thicken and turn glossy as the flavours fry together.\n\nStir in the remaining 700 ml of chicken stock and the broken chocolate, then simmer gently for 30–40 minutes, stirring often, until the sauce coats the back of a spoon; season with the salt and a small pinch of sugar.\n\nSlide the poached chicken thighs into the mole and simmer 10 minutes more so they take on the sauce.\n\nServe the chicken in shallow bowls, ladle generous mole over the top, and finish with the reserved sesame seeds, coriander leaves, white rice and warm corn tortillas on the side."}},{"id":188,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":480,"prot":18,"carb":38,"fat":28,"fib":6},"origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Чилакилес","en":"Chilaquiles","ro":"Chilaquiles"},"category":{"ru":"Завтрак","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ru":["200 г кукурузных тортилий вчерашних, разрезанных на восемь частей (или готовых тотопос)","500 мл нейтрального масла для фритюра (или 4 ст. л. для жарки в малом количестве)","Для сальсы рохи: 6 спелых помидоров (~600 г), 2 перца гуахильо + 1 перец де арболь (без хвостиков и семян), 1 зубчик чеснока, ½ небольшой белой луковицы","1 ч. л. мелкой морской соли и 1 ст. л. нейтрального масла для сальсы","4 крупных яйца, жаренных глазуньей (по желанию, но классика)","100 мл мексиканской кремы (или сметана, разбавленная молоком)","80 г кесо фреско, раскрошенного (или мягкая фета)","½ небольшой красной луковицы, нарезанной очень тонко","Небольшой пучок свежей кинзы, только листья","1 спелое авокадо, нарезанное прямо перед подачей","Маринованные халапеньо, по вкусу"],"en":["200 g day-old corn tortillas, cut into eighths (or store-bought totopos)","500 ml neutral oil for frying (or 4 tbsp for shallow-frying)","For the salsa roja: 6 ripe tomatoes (~600 g), 2 guajillo chiles + 1 chile de árbol (stemmed and seeded), 1 garlic clove, ½ small white onion","1 tsp fine sea salt and 1 tbsp neutral oil for the salsa","4 large eggs, fried sunny-side-up (optional but classic)","100 ml Mexican crema (or sour cream thinned with milk)","80 g queso fresco, crumbled (or mild feta)","½ small red onion, very thinly sliced","A small handful of fresh coriander, leaves picked","1 ripe avocado, sliced just before serving","Pickled jalapeños, to taste"],"ro":["200 g tortilla de porumb de o zi, tăiate în opt (sau totopos cumpărate)","500 ml ulei neutru pentru prăjit (sau 4 linguri pentru prăjit superficial)","Pentru salsa roja: 6 roșii coapte (~600 g), 2 ardei guajillo + 1 ardei de árbol (fără codiță și semințe), 1 cățel de usturoi, ½ ceapă albă mică","1 linguriță sare fină de mare și 1 lingură ulei neutru pentru salsa","4 ouă mari, ochiuri (opțional dar tradițional)","100 ml crema mexicană (sau smântână subțiată cu lapte)","80 g queso fresco, sfărâmat (sau feta blândă)","½ ceapă roșie mică, tăiată felii foarte subțiri","Un mic mănunchi de coriandru proaspăt, doar frunzele","1 avocado copt, feliat chiar înainte de servit","Jalapeños murați, după gust"]},"howIsMade":{"ru":"Нарежьте вчерашние тортильи на восемь частей и обжарьте либо во фритюре при 175°C до золотистого хруста — около 90 секунд за партию — либо в 4 ст. л. масла на сковороде; обсушите на решётке и слегка посолите, пока тёплые.\n\nДля сальсы подсушите перцы гуахильо и де арболь в сухой сковороде по 20 секунд с каждой стороны до аромата, затем замочите в горячей воде на 10 минут; одновременно обожгите помидоры, чеснок и лук под раскалённым грилем или прямо над огнём до чёрных пятен.\n\nСлейте перцы и взбейте их в блендере с обожжёнными овощами, 1 ч. л. соли и парой ложек воды от замачивания до однородности.\n\nРазогрейте 1 ст. л. масла в широкой сковороде, влейте сальсу и проварите её около 5 минут, помешивая, пока цвет не углубится и она не станет глянцевой.\n\nВысыпьте хрустящие тортильи и аккуратно перемешайте их в сальсе на среднем огне минуту-две — они должны впитать соус, сохранив часть хруста.\n\nПодавайте сразу: сверху положите яичницу, если используете, полейте кремой и посыпьте кесо фреско, тонко нарезанным красным луком, кинзой, авокадо и маринованными халапеньо.","en":"Cut the day-old tortillas into eighths and either deep-fry them at 175°C until golden and crisp, about 90 seconds per batch, or shallow-fry in 4 tablespoons of oil; drain on a rack and salt lightly while still warm.\n\nFor the salsa, toast the guajillo and árbol chiles in a dry pan for 20 seconds per side until fragrant, then soak in hot water for 10 minutes; meanwhile, char the tomatoes, garlic and onion under a hot broiler or directly over a flame until blackened in patches.\n\nDrain the chiles and blend with the charred vegetables, 1 teaspoon of salt and a splash of the chile-soaking water until smooth.\n\nHeat 1 tablespoon of oil in a wide pan, pour in the salsa and simmer for about 5 minutes, stirring, until it deepens in colour and looks glossy.\n\nTip in the crisp tortillas and gently fold them through the salsa over medium heat for a minute or two — they should soak up sauce while keeping some bite.\n\nPlate at once, top with the fried eggs if using, drizzle with crema, and scatter queso fresco, sliced red onion, coriander, avocado and pickled jalapeños over the top."}},{"id":189,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":9,"carb":70,"fat":24,"fib":1},"origin":{"ru":"Мексика","en":"Mexico","ro":"Mexic"},"name":{"ru":"Торт Трес Лечес","en":"Tres Leches Cake","ro":"Tort Tres Leches"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["5 крупных яиц, разделённых на белки и желтки, комнатной температуры","200 г мелкого сахара, плюс 30 г для взбитых сливок","200 г муки и 1 ч. л. разрыхлителя, просеянные вместе","1 ч. л. ванильного экстракта для бисквита, плюс ½ ч. л. для крема","1 банка (397 г) сгущённого молока с сахаром","1 банка (340 г) сгущённого молока без сахара (evaporated milk)","200 мл цельного молока и 50 мл сливок (тройной молочный соус)","250 мл холодных сливок для взбивания, плюс молотая корица для посыпки"],"en":["5 large eggs, separated, at room temperature","200 g caster sugar, plus 30 g for the whipped cream","200 g plain flour and 1 tsp baking powder, sifted together","1 tsp vanilla extract for the sponge, plus ½ tsp for the cream","1 can (397 g) sweetened condensed milk","1 can (340 g) evaporated milk","200 ml whole milk and 50 ml heavy cream (the three-milk soak)","250 ml cold heavy cream for whipping, plus ground cinnamon for dusting"],"ro":["5 ouă mari, separate, la temperatura camerei","200 g zahăr tos, plus 30 g pentru frișcă","200 g făină albă și 1 linguriță praf de copt, cernute împreună","1 linguriță esență de vanilie pentru blat, plus ½ linguriță pentru frișcă","1 cutie (397 g) lapte condensat îndulcit","1 cutie (340 g) lapte evaporat","200 ml lapte integral și 50 ml smântână pentru frișcă (amestec pentru îmbibare)","250 ml smântână rece pentru frișcă (35% grăsime), plus scorțișoară măcinată pentru pudrat"]},"howIsMade":{"ru":"Разогрейте духовку до 175°C и смажьте маслом и присыпьте мукой форму 23×33 см, затем взбейте белки со щепоткой соли до мягких пиков, по ложке добавляя 100 г сахара, до глянцевых устойчивых пиков.\n\nВзбейте желтки с оставшимися 100 г сахара и ванилью 3–4 минуты до бледности и троекратного объёма, просейте муку с разрыхлителем сверху и аккуратно вмешайте лопаткой, затем введите меренгу в три приёма, сохраняя воздух.\n\nПерелейте в форму, разровняйте верх и выпекайте 25–30 минут, пока бисквит не станет глубоко золотистым и не будет пружинить при нажатии, затем остудите в форме не менее 30 минут.\n\nВ кувшине соедините сгущённое молоко, evaporated milk и смесь молока со сливками, проткните остывший бисквит тонкой шпажкой до самого дна по всей поверхности и налейте смесь в три-четыре медленных захода — жидкости покажется слишком много, но бисквит впитает всё; накройте и уберите в холодильник минимум на 4 часа, лучше на ночь.\n\nПрямо перед подачей взбейте холодные сливки с 30 г сахара и оставшейся ванилью до мягких пиков, выложите на охлаждённый торт и щедро посыпьте молотой корицей.","en":"Heat the oven to 175°C and butter and flour a 23×33 cm baking dish, then whisk the whites with a pinch of salt to soft peaks, beating in 100 g of the sugar a spoonful at a time until glossy and stiff.\n\nWhip the yolks with the remaining 100 g sugar and the vanilla for 3–4 minutes until pale and tripled, sift the flour and baking powder over them and fold in gently, then fold in the meringue in three additions, keeping as much air as you can.\n\nPour into the dish, level the top and bake 25–30 minutes until deep golden and springy at the centre, then cool in the dish for at least 30 minutes.\n\nWhisk the three milks together in a jug, pierce the cooled cake all over to the base with a thin skewer and pour the mixture across the surface in three or four slow passes — it looks like too much liquid, but the sponge drinks every drop; cover and refrigerate at least 4 hours, ideally overnight.\n\nJust before serving, whip the cold cream with the 30 g sugar and the remaining vanilla to soft peaks, spread it over the chilled cake and dust generously with ground cinnamon."}},{"id":190,"servings":6,"tipType":"fish","pairingsType":"french","nutrition":{"cal":480,"prot":50,"carb":30,"fat":18,"fib":4},"origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Буйабес","en":"Bouillabaisse","ro":"Bouillabaisse"},"category":{"ru":"Рыба","en":"Fish","ro":"Pește"},"ingredients":{"ru":["800 г мелкой средиземноморской каменной рыбы (рашкас, морской дракон, губан — для бульона), выпотрошенной","1,2 кг плотной средиземноморской рыбы кусками (рашкас, морской чёрт, солнечник, морской угорь, морской петух — минимум четыре вида), с кожей, очищенной от чешуи","1 крупная луковица, 2 порея (только белая часть), 1 клубень фенхеля, 4 спелых помидора, 6 зубчиков чеснока","Букет гарни: тимьян, лавровый лист, стебли петрушки, полоска сушёной апельсиновой цедры, чайная ложка семян фенхеля","1 г шафрана (хорошая щепотка), 2 ст. л. пастиса (Pernod), добавленных в конце","100 мл оливкового масла, 1 ч. л. соли, свежемолотый перец","2 л воды (или лёгкий рыбный фумет)","12–15 ломтиков подсушенного багета и руй (3 зубчика чеснока, ½ ч. л. шафрана, ¼ ч. л. кайенского перца, 1 желток, 200 мл оливкового масла, соль, кусочек хлеба, размоченный в бульоне)"],"en":["800 g small Mediterranean rockfish (rascasse, weever, wrasse — for the broth), gutted","1.2 kg firm Mediterranean fish in chunks (rascasse, monkfish, John Dory, conger, gurnard — at least four species), skin on, scaled","1 large onion, 2 leeks (white parts only), 1 fennel bulb, 4 ripe tomatoes, 6 garlic cloves","Bouquet garni: thyme, bay, parsley stalks, a strip of dried orange peel, a teaspoon of fennel seeds","1 g saffron threads (a generous pinch), 2 tbsp pastis (Pernod) stirred in at the end","100 ml olive oil, 1 tsp salt, freshly ground pepper","2 L water (or light fish fumet)","12–15 slices of toasted day-old baguette and rouille (3 garlic cloves, ½ tsp saffron, ¼ tsp cayenne, 1 egg yolk, 200 ml olive oil, salt, a small piece of bread soaked in the broth)"],"ro":["800 g pești mici mediteraneeni de stâncă (rascassa, năsărel, vrana — pentru fond), eviscerați","1,2 kg pește mediteranean ferm tăiat bucăți (rascassa, lotă, Saint-Pierre, congru, grondin — minim patru specii), cu piele, scuamat","1 ceapă mare, 2 praz (doar partea albă), 1 bulb de fenicul, 4 roșii coapte, 6 căței de usturoi","Buchet garni: cimbru, foi de dafin, codițe de pătrunjel, coajă uscată de portocală, o linguriță de semințe de fenicul","1 g șofran (un vârf bun), 2 linguri de pastis (Pernod) adăugat la final","100 ml ulei de măsline, 1 linguriță sare, piper proaspăt măcinat","2 l apă (sau fumet uşor de pește)","12–15 felii de baghetă uscată prăjită și rouille (3 căței usturoi, ½ linguriță șofran, ¼ linguriță cayenne, 1 gălbenuș, 200 ml ulei de măsline, sare, o bucată de pâine înmuiată în fond)"]},"howIsMade":{"ru":"Очистите, выпотрошите и сполосните всю рыбу — крупную нарежьте кусками по 3 см, оставив головы и кости для бульона, а мелкая каменная рыба идёт в кастрюлю целиком.\n\nВ большой кастрюле с толстым дном разогрейте 4 столовых ложки оливкового масла на среднем огне и пассеруйте лук, порей и фенхель без зарумянивания около 10 минут, затем добавьте порубленные помидоры и 5 зубчиков чеснока и тушите ещё 5 минут до пюреобразной консистенции.\n\nПоложите мелкую рыбу и головы с костями крупной, залейте 2 л воды, добавьте букет гарни (тимьян, лавр, петрушка, цедра апельсина, семена фенхеля) и варите на сильном огне 30–40 минут, пока мелкая рыба полностью не разварится, затем процедите всё через крупное сито или жерновок, сильно отжимая — кости, травы и мякоть выбрасываются — доведите процеженный бульон снова до бурного кипения, попробуйте на соль и вмешайте шафран.\n\nСначала опустите плотную рыбу (морской чёрт, угорь) и варите 5–6 минут, затем добавьте более деликатную (рашкас, солнечник) и варите ещё 3–4 минуты — она должна быть едва матовой, никогда не разваливаться — и, сняв с огня, влейте пастис.\n\nДля руй разотрите оставшийся зубчик чеснока в ступке с солью и шафраном, добавьте размоченный в бульоне и отжатый хлеб, затем желток, и в самом конце тонкой струйкой влейте оливковое масло, непрерывно взбивая до консистенции майонеза, после чего подавайте в два приёма: сначала бульон поверх ломтиков подсушенного багета с ложкой руй, затем рыбу на отдельной тарелке, с дополнительным руй сбоку.","en":"Scale, gut and rinse all the fish — cut the larger ones into 3 cm chunks and keep the heads and bones for the broth, while the small rockfish go whole into the pot.\n\nIn a large heavy pot, heat 4 tablespoons of olive oil over medium heat and sweat the chopped onion, leeks and fennel without colour for about 10 minutes, then add the chopped tomatoes and 5 garlic cloves and cook another 5 minutes to a pulp.\n\nTip in the small fish and the heads and bones of the larger ones, cover with the 2 L of water, drop in the bouquet garni (thyme, bay, parsley, orange peel, fennel seeds) and simmer hard for 30–40 minutes until the small fish completely break down, then pass everything through a coarse sieve or food mill, pressing hard to extract every drop — bones, herbs and pulp discarded — bring the strained broth back to a rolling boil, taste for salt and stir in the saffron.\n\nSlip the firm fish (monkfish, conger) into the broth first and poach 5–6 minutes, then add the more delicate ones (rascasse, John Dory) for another 3–4 — they should be just opaque, never falling apart — and off the heat, swirl in the pastis.\n\nFor the rouille, pound the last garlic clove with the salt and saffron in a mortar, work in the bread (dipped in broth and squeezed), then the yolk, then olive oil in a thin stream, whisking constantly until thick like mayonnaise, then serve in two courses: the broth first, ladled over toasted baguette with a spoonful of rouille on top; the fish after, on a separate plate, with more rouille alongside."}},{"id":191,"servings":4,"tipType":"meat","pairingsType":"french","nutrition":{"cal":650,"prot":30,"carb":40,"fat":38,"fib":2},"origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Крок-месье","en":"Croque Monsieur","ro":"Croque Monsieur"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["8 толстых ломтиков pain de mie (мягкий белый сэндвичный хлеб), вчерашних","80 г несолёного сливочного масла, размягчённого, плюс 30 г для бешамеля","200 г Грюйера или Конте, мелко натёртого","4 ломтика jambon de Paris (~120 г всего)","2 ч. л. дижонской горчицы","30 г муки и 300 мл цельного молока (для бешамеля)","Мелкая морская соль, белый перец, щепотка свеженатёртого мускатного ореха"],"en":["8 thick slices of pain de mie (soft white sandwich bread), one day old","80 g unsalted butter, softened, plus 30 g for the béchamel","200 g Gruyère or Comté, finely grated","4 slices of jambon de Paris (~120 g total)","2 tsp Dijon mustard","30 g plain flour and 300 ml whole milk (for the béchamel)","Fine sea salt, white pepper, a grating of nutmeg"],"ro":["8 felii groase de pain de mie (pâine albă fină de sandviș), o zi vechi","80 g unt nesărat, înmuiat, plus 30 g pentru béchamel","200 g Gruyère sau Comté, ras fin","4 felii de jambon de Paris (~120 g în total)","2 lingurițe muștar Dijon","30 g făină albă și 300 ml lapte integral (pentru béchamel)","Sare fină, piper alb, un sfert de nucușoară rasă"]},"howIsMade":{"ru":"Растопите 30 г сливочного масла для бешамеля в небольшой кастрюле на среднем огне, всыпьте муку и пассеруйте 1–2 минуты без зарумянивания, затем влейте тёплое молоко тонкой струйкой, непрерывно взбивая венчиком, и томите на слабом огне 4–5 минут, часто помешивая, пока соус не загустеет настолько, чтобы держать пик на ложке — приправьте солью, белым перцем и мускатным орехом и держите тёплым.\n\nРазогрейте верхний гриль (broiler) духовки до максимума, намажьте обе стороны каждого ломтика хлеба размягчённым маслом и тонко смажьте дижонской горчицей внутреннюю сторону одной половинки каждого сэндвича.\n\nПоложите 4 намасленных ломтика на застеленный пергаментом противень, на каждый — тонкий слой тёртого Грюйера (~60 г оставьте на верх), ломтик ветчины и ещё тонкий слой сыра, накройте оставшимися 4 ломтиками горчицей вовнутрь и слегка прижмите.\n\nРаспределите по 2 столовых ложки с горкой бешамеля на каждый сэндвич до самых краёв, чтобы хлеб был полностью покрыт и соус слегка стекал по бокам, посыпьте сверху оставшимся Грюйером и поставьте противень под горячий гриль на 4–6 минут, внимательно следя, пока бешамель не закипит и не подрумянится глубоко местами, а сыр полностью не расплавится — снизу хлеб становится хрустящим благодаря уже схватившемуся маслу.\n\nДостаньте, дайте отдохнуть 30 секунд — иначе сыр прилипнет к рукам — и разрежьте по диагонали; для крок-мадам пожарьте по яйцу-глазунье в небольшом количестве сливочного масла, пока сэндвичи стоят под грилем, и положите его сверху прямо перед подачей.","en":"Melt the 30 g béchamel butter in a small saucepan over medium heat, whisk in the flour and cook 1–2 minutes without colouring, then pour the warm milk in gradually while whisking constantly and simmer gently 4–5 minutes, stirring often, until thick enough to hold a peak on the spoon — season with salt, white pepper and nutmeg and keep warm.\n\nPreheat the broiler (top grill) to high, butter both sides of every bread slice with the softened butter, then thinly spread Dijon on the inner face of one slice per sandwich.\n\nLay 4 buttered slices on a lined tray, top each with a thin layer of grated Gruyère (hold ~60 g back for the top), a slice of ham and another thin layer of cheese, then close with the remaining 4 slices, mustard side in, and press lightly.\n\nSpoon 2 heaped tablespoons of béchamel over each sandwich right to the edges so the bread is fully covered and the sauce runs a little down the sides, scatter the reserved Gruyère on top and slide the tray under the hot broiler for 4–6 minutes, watching closely, until the béchamel is bubbling and deeply browned in patches and the cheese is molten — the bread crisps from below from the butter already gripped to its underside.\n\nLift out, rest 30 seconds — the cheese would stick to you otherwise — and cut on the diagonal; for a croque madame, fry an egg in a little butter while the sandwiches are under the broiler and slip it on top just before serving."}},{"id":192,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":420,"prot":13,"carb":60,"fat":14,"fib":1},"origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Крепы","en":"Crêpes","ro":"Crêpes"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["250 г пшеничной муки (T45 или T55), просеянной","4 крупных яйца, комнатной температуры","500 мл цельного молока (или 350 мл молока + 150 мл воды для более лёгких блинов)","50 г несолёного сливочного масла, растопленного до орехового цвета (beurre noisette)","30 г сахара и щедрая щепотка мелкой соли","1 ст. л. тёмного рома или цветочной воды апельсина (или 1 ч. л. ванильного экстракта)","Дополнительное масло для смазывания сковороды (~30 г, наносить кистью)","Для подачи: сахарная пудра, дольки лимона, по желанию джем, Nutella или ломтики банана"],"en":["250 g plain flour (T45 or T55), sifted","4 large eggs, at room temperature","500 ml whole milk (or 350 ml milk + 150 ml water for lighter crêpes)","50 g unsalted butter, melted until it browns to beurre noisette","30 g sugar and a good pinch of fine salt","1 tbsp dark rum or orange-flower water (or 1 tsp vanilla extract)","Extra butter for the pan (~30 g, kept on a brush)","To serve: caster sugar, lemon wedges, optionally jam, Nutella or sliced banana"],"ro":["250 g făină albă (T45 sau T55), cernută","4 ouă mari, la temperatura camerei","500 ml lapte integral (sau 350 ml lapte + 150 ml apă pentru crêpes mai ușoare)","50 g unt nesărat, topit până devine beurre noisette (alunizat)","30 g zahăr și un vârf bun de sare fină","1 lingură de rom închis sau apă de flori de portocal (sau 1 linguriță extract de vanilie)","Unt în plus pentru ungerea tigăii (~30 g, ținut cu o pensulă)","Pentru servit: zahăr tos, felii de lămâie, opțional gem, Nutella sau banane"]},"howIsMade":{"ru":"Растопите 50 г сливочного масла в маленькой кастрюле на среднем огне и держите до орехового аромата и тёмно-золотого цвета, затем процедите в миску, оставив тёмный осадок — это beurre noisette, ароматическая подпись кондитерских блинчиков.\n\nПросейте муку с солью в большую миску, сделайте углубление в центре, разбейте туда яйца и добавьте треть молока вместе с сахаром, затем венчиком ведите от центра к краям, постепенно подбирая муку, пока не получится густая гладкая паста без комков, разведите оставшимся молоком тонкой струйкой и наконец добавьте остывшее масло и ром; тесто должно быть консистенции жидких сливок.\n\nНакройте и оставьте тесто в холодильнике минимум на 30 минут, лучше на час — клейковина оседает, и блинчики получаются тонкими и податливыми, а не резиновыми.\n\nРазогрейте антипригарную сковороду 22–24 см или crêpière на среднесильном огне, кистью нанесите тончайший слой масла и влейте ~50 мл теста, сразу же поверните сковороду, чтобы оно покрыло дно тонким диском, затем готовьте 50–60 секунд, пока края не отойдут, а низ не станет золотистым и кружевным, переверните тонкой лопаткой (или коротким броском сковороды) ещё на 25–30 секунд, сдвиньте на тарелку и накройте чистым полотенцем — продолжайте, смазывая сковороду маслом каждые один-два блинчика, пока тесто не закончится.\n\nПодавайте тёплыми, посыпав сахарной пудрой и сбрызнув лимонным соком, сложенными в четверть — классика парижских лотков — sucre, sucre-citron, фруктовый джем, Nutella или банан с Nutella.","en":"Melt the 50 g of butter in a small saucepan over medium heat and keep cooking until it smells nutty and turns deep gold, then strain into a bowl leaving the dark sediment behind — that's beurre noisette, the signature flavour of bakery-grade crêpes.\n\nSift the flour and salt into a large bowl, make a well in the middle, crack in the eggs and add a third of the milk with the sugar, then whisk from the centre outwards drawing in the flour until you have a thick smooth paste with no lumps, thin with the rest of the milk in a slow stream and finally add the cooled brown butter and the rum; the batter should be the consistency of single cream.\n\nCover and rest the batter in the fridge at least 30 minutes, ideally an hour — the gluten settles and the crêpes turn out thin and flexible rather than elastic.\n\nHeat a 22–24 cm non-stick pan or crêpière over medium-high heat, brush with a very thin film of butter and pour in about 50 ml of batter, immediately swirling so it covers the base in a thin disc, then cook 50–60 seconds until the edges lift and the underside is lacy golden, flip with a thin spatula (or a quick toss of the pan) for another 25–30 seconds, slide onto a plate and cover with a clean cloth — carry on, brushing the pan with a little butter every one or two crêpes, until the batter is gone.\n\nServe warm, scattered with caster sugar and a squeeze of lemon, folded into quarters — the Parisian street-stand alternatives are sucre, sucre-citron, fruit jam, Nutella, or banana with Nutella."}},{"id":193,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":5,"carb":65,"fat":28,"fib":3},"origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Тарт Татен","en":"Tarte Tatin","ro":"Tarte Tatin"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["8–10 плотных кисловатых яблок (рене де ренет, голден делишес или ханикрисп), очищенных, разрезанных пополам и без сердцевины — около 1,5 кг","150 г несолёного сливочного масла кубиками, комнатной температуры","200 г белого сахара (коричневый не используется в классическом тарте татене)","1 ст. л. свежевыжатого лимонного сока","Круг слоёного теста (pâte feuilletée), ~250 г, раскатанный до 26 см и толщиной 3 мм","Щепотка fleur de sel","Для подачи: 200 мл crème fraîche, не мороженое — солоньская традиция"],"en":["8–10 firm tart apples (reine de reinette, golden delicious or honeycrisp), peeled, halved and cored — about 1.5 kg","150 g unsalted butter, cut into cubes, at room temperature","200 g white granulated sugar (do not use brown sugar for a classic tatin)","1 tbsp fresh lemon juice","1 round of puff pastry (pâte feuilletée), ~250 g, rolled to 26 cm and 3 mm thick","A pinch of fleur de sel","To serve: 200 ml crème fraîche, not ice cream — the Sologne tradition"],"ro":["8–10 mere ferme și ușor acrișoare (reine de reinette, golden delicious sau honeycrisp), curățate, înjumătățite și fără cotor — în jur de 1,5 kg","150 g unt nesărat, tăiat cuburi, la temperatura camerei","200 g zahăr alb tos (nu se folosește zahăr brun pentru un tatin clasic)","1 lingură suc proaspăt de lămâie","Un disc de aluat de foitaj (pâte feuilletée), ~250 g, rulat la 26 cm diametru și 3 mm grosime","Un vârf de fleur de sel","Pentru servit: 200 ml smântână grasă (crème fraîche), nu înghețată — tradiția din Sologne"]},"howIsMade":{"ru":"Сбрызните яблоки лимонным соком, чтобы они не темнели, растопите 50 г сливочного масла в тяжёлой сковороде с жаропрочной ручкой (или в специальной форме для татен) диаметром 22–24 см, равномерно посыпьте сверху сахаром и оставьте на среднем огне без помешивания, пока сахар не растворится и не превратится в карамель глубокого янтарного цвета — около 8–10 минут — потому что светлая карамель теряет цвет в духовке и вкус остаётся плоским.\n\nСнимите сковороду с огня и выложите оставшиеся 100 г масла кубиками поверх карамели — она зашипит сильно — покачайте сковороду, чтобы масло равномерно растопилось в глянцевый соус, затем уложите половинки яблок срезом вверх плотно прижатыми друг к другу по спирали от центра к краю (поместятся), верните на средний огонь и готовьте без крышки 25–30 минут, время от времени наклоняя сковороду, чтобы собрать карамель с краёв, пока нижняя сторона яблок не пропитается карамелью и они не начнут размягчаться.\n\nТем временем разогрейте духовку до 200°C и раскатайте слоёное тесто в круг чуть больше сковороды, выключите огонь под яблоками и дайте им отдохнуть минуту, затем накройте яблоки тестом и заправьте края внутрь сковороды, между яблоками и стенкой — корочка схватит фрукты при переворачивании — и несколько раз проколите тесто вилкой.\n\nВыпекайте 25–30 минут, пока тесто не станет полностью золотистым и карамель не забурлит по краям, затем дайте отдохнуть ровно 10 минут — достаточно, чтобы карамель осела, но не застыла.\n\nПоставьте на тесто сервировочное блюдо больше сковороды, возьмите сковороду через плотное полотенце и переверните одним решительным движением — если какое-то яблоко осталось в сковороде, верните его на тарт лопаткой — посыпьте щепоткой fleur de sel и подавайте тёплым, с щедрой ложкой crème fraîche на каждой тарелке.","en":"Toss the apples with the lemon juice so they don't brown, melt 50 g of the butter in a heavy 22–24 cm oven-safe pan with an ovenproof handle (or a proper tatin pan), scatter the sugar over it in an even layer and leave on medium heat without stirring until the sugar dissolves and caramelises to a deep amber — about 8–10 minutes — because pale caramel bleeds out in the oven and tastes flat.\n\nTake the pan off the heat and drop the remaining 100 g butter in cubes onto the caramel — it will hiss hard — swirl until the butter melts evenly into a glossy buttery sauce, then pack the apple halves cut-side-up, tight against each other in a spiral from the centre outwards (they will fit), return to medium heat and cook uncovered for 25–30 minutes, tilting the pan now and then to catch the caramel from the edges, until the underside of the apples has drunk the caramel and they just start to soften.\n\nMeanwhile heat the oven to 200°C and roll the puff pastry to a disc a little larger than the pan, cut the heat under the apples and let them settle a minute, then drape the pastry over the top and tuck the edges down inside the pan between the apples and the wall — the crust will grip the fruit when you flip — and prick the pastry a few times with a fork.\n\nBake 25–30 minutes until the pastry is fully golden and the caramel bubbles around the edges, then rest exactly 10 minutes — long enough for the caramel to settle without setting hard.\n\nPlace a serving plate wider than the pan over the pastry, hold the pan with a thick cloth and invert in one decisive motion — if any apple stays stuck to the pan, lift it back onto the tart with a spatula — scatter a pinch of fleur de sel over the top and serve warm with a generous spoonful of crème fraîche on each plate."}},{"id":194,"servings":6,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":28,"carb":28,"fat":10,"fib":1},"origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Авголемоно","en":"Avgolemono","ro":"Avgolemono"},"category":{"ru":"Суп","en":"Soup","ro":"Supă"},"ingredients":{"ru":["1,5 кг целой курицы (или 1 кг куриных бёдер на кости)","2 моркови, 1 луковица, 2 черешка сельдерея (для бульона)","1 лавровый лист, пучок стеблей петрушки, 8 горошин чёрного перца","150 г длиннозерного риса (или орзо, если предпочитаете)","3 крупных яйца комнатной температуры","Сок 2 лимонов (около 80 мл)","Соль и белый перец","Свежий укроп или петрушка для подачи"],"en":["1.5 kg whole chicken (or 1 kg bone-in chicken thighs)","2 carrots, 1 onion, 2 celery stalks (for the broth)","1 bay leaf, a handful of parsley stems, 8 black peppercorns","150 g long-grain rice (or orzo if you prefer)","3 large eggs, at room temperature","Juice of 2 lemons (about 80 ml)","Salt and white pepper","Fresh dill or parsley to finish"],"ro":["1,5 kg pui întreg (sau 1 kg pulpe de pui cu os)","2 morcovi, 1 ceapă, 2 tulpini de țelină (pentru fond)","1 frunză de dafin, un mănunchi de codițe de pătrunjel, 8 boabe de piper negru","150 g orez cu bob lung (sau orzo, dacă preferi)","3 ouă mari, la temperatura camerei","Zeama de la 2 lămâi (aproximativ 80 ml)","Sare și piper alb","Mărar sau pătrunjel proaspăt pentru a încheia"]},"howIsMade":{"ru":"Положите курицу в тяжёлую кастрюлю с морковью, луком, сельдереем, лавровым листом, стеблями петрушки и горошинами перца, залейте 2,5 л холодной воды и доведите до мягкого кипения. Снимите пенку и варите без крышки около 90 минут, пока мясо не начнёт отходить от костей.\n\nДостаньте курицу, процедите бульон в чистую кастрюлю и овощи отложите. Снимите мясо с костей, разберите на кусочки, верните в бульон, снова доведите до кипения и всыпьте рис; варите 15–18 минут, пока рис не станет мягким.\n\nВзбейте яйца в миске до пышности и светлого цвета, вмешайте лимонный сок. Темперируйте: медленно влейте в них половник горячего бульона, не переставая взбивать, потом ещё один, пока миска не станет тёплой на ощупь.\n\nСняв с огня, верните темперированную смесь в кастрюлю тонкой ровной струёй, непрерывно помешивая — суп больше не должен кипеть, иначе яйца свернутся. Поправьте соль и белый перец и подавайте сразу, посыпав укропом или петрушкой.","en":"Simmer the chicken in 2.5 L cold water with the carrots, onion, celery, bay leaf, parsley stems and peppercorns. Skim any foam and cook uncovered for about 90 minutes, until the meat falls from the bones.\n\nLift the chicken out, strain the broth into a clean pot and discard the vegetables. Shred the meat off the bones, return it to the broth, bring back to a simmer and stir in the rice; cook 15–18 minutes until tender.\n\nWhisk the eggs in a bowl until light and foamy, then whisk in the lemon juice. Temper them by slowly ladling a cup of hot broth in while whisking, then another, until the bowl is warm to the touch.\n\nOff the heat, pour the tempered eggs back into the pot in a slow steady stream, stirring continuously — never let the soup boil again. Season with salt and white pepper and serve immediately, finished with dill or parsley."}},{"id":195,"servings":4,"tipType":"meat","pairingsType":"mediterranean","nutrition":{"cal":620,"prot":38,"carb":52,"fat":28,"fib":4},"origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Гирос","en":"Gyros","ro":"Gyros"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["1 кг свиной шеи, нарезанной полосками 1 см толщиной поперёк волокон (или куриные бёдра без кости)","4 зубчика чеснока, измельчить","2 ст. л. греческого оливкового масла","1 ст. л. красного винного уксуса","1 ст. л. сушёного орегано (по возможности греческий ригани)","1 ч. л. сладкой паприки","1 ч. л. соли, ½ ч. л. чёрного перца","4 больших мягких греческих питы (плоская лепёшка без кармана, не питакарман)","Для подачи: 200 мл дзадзики, 1 спелый помидор кружками, ½ красной луковицы тонкими полукольцами, орегано, дольки лимона, по желанию картофель фри"],"en":["1 kg pork shoulder, sliced into 1 cm thick strips against the grain (or boneless chicken thighs)","4 garlic cloves, minced","2 tbsp Greek olive oil","1 tbsp red wine vinegar","1 tbsp dried oregano (Greek rigani if possible)","1 tsp sweet paprika","1 tsp salt, ½ tsp black pepper","4 large soft Greek pitas (the unfilled flatbread, not pocket pita)","To serve: 200 ml tzatziki, 1 ripe tomato sliced, ½ red onion thinly sliced, oregano, lemon wedges, optional French fries"],"ro":["1 kg ceafă de porc, tăiată în fâșii de 1 cm grosime contra fibrei (sau pulpe de pui dezosate)","4 căței de usturoi, tocați","2 linguri ulei de măsline grecesc","1 lingură oțet de vin roșu","1 lingură oregano uscat (rigani grecesc, dacă ai)","1 linguriță boia dulce","1 linguriță sare, ½ linguriță piper negru","4 lipii grecești mari și moi (turtă plată neumplută, nu pita cu buzunar)","Pentru servit: 200 ml tzatziki, 1 roșie coaptă feliată, ½ ceapă roșie tăiată subțire, oregano, felii de lămâie, opțional cartofi prăjiți"]},"howIsMade":{"ru":"Смешайте чеснок, оливковое масло, уксус, орегано, паприку, соль и перец в большой миске, добавьте полоски свинины и хорошо перемешайте. Накройте и маринуйте минимум 3 часа, лучше ночь.\n\nРаскалите тяжёлую сковороду или гриль-сковороду на сильном огне, пока не пойдёт дым. Выложите полоски в один слой, при необходимости в несколько подходов, и обжаривайте, не двигая, 2–3 минуты с каждой стороны, пока края не подрумянятся глубоко, а центр едва не приготовится; не перегружайте сковороду, иначе мясо потушится, а не подрумянится. Каждую готовую порцию переложите на тарелку, пока жарите следующую.\n\nРазогрейте лепёшки питы по одной на той же сковороде, по 20 секунд с каждой стороны, лишь до мягкости. Намажьте по центру каждой пите столовую ложку дзадзики, выложите горячую свинину, добавьте несколько ломтиков помидора, колец красного лука — и, если придерживаться афинской традиции, небольшую горсть картофеля фри сверху.\n\nЗаверните плотно в бумагу, защипнув один конец, и подавайте сразу с дополнительным орегано, долькой лимона и оставшимся дзадзики отдельно.","en":"Whisk the garlic, olive oil, vinegar, oregano, paprika, salt and pepper in a large bowl, add the pork strips and toss until every piece is coated. Cover and marinate at least 3 hours, ideally overnight.\n\nHeat a large heavy skillet or griddle pan over high heat until smoking. Lay the strips down in a single layer, in batches if needed, and sear without moving for 2–3 minutes per side, until the edges are deeply browned and the centre just cooked through; don't crowd the pan or the meat will steam instead of caramelise. Rest each batch on a plate while you cook the next.\n\nWarm the pitas one at a time on the same hot skillet for 20 seconds per side, just until pliable. Spread a heaped tablespoon of tzatziki down the centre of each, lay the hot pork on top, add a few tomato slices and rings of red onion, and — if you're being faithful to Athens — a small handful of French fries on top.\n\nWrap tightly in paper with one end pinched closed, and serve immediately with extra oregano, a wedge of lemon, and the rest of the tzatziki on the side."}},{"id":196,"servings":8,"tipType":"pasta","pairingsType":"mediterranean","nutrition":{"cal":680,"prot":30,"carb":62,"fat":32,"fib":4},"origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Пастицио","en":"Pastitsio","ro":"Pastitsio"},"category":{"ru":"Паста","en":"Pasta","ro":"Paste"},"ingredients":{"ru":["500 г пасты для пастицио (длинные трубчатые №2; буккатини — хорошая замена)","600 г говяжьего фарша (или половина говяжьего, половина из ягнятины)","1 крупная луковица, мелко нарезанная","3 зубчика чеснока, измельчить","400 г рубленых томатов (консервированных)","2 ст. л. томатной пасты","150 мл сухого красного вина","1 палочка корицы, 4 целых гвоздики, 1 лавровый лист, 1 ч. л. сушёного орегано","100 г Кефалотири или Пекорино, мелко натереть (в крайнем случае Пармезан)","Для бешамеля: 100 г сливочного масла, 100 г муки, 1 л цельного молока, 4 желтка, щепотка свеженатёртого мускатного ореха","Соль, перец, оливковое масло"],"en":["500 g pastitsio noodles (long, tubular #2; bucatini is a fair substitute)","600 g beef mince (or half beef, half lamb)","1 large onion, finely chopped","3 garlic cloves, minced","400 g chopped tomatoes (canned)","2 tbsp tomato paste","150 ml dry red wine","1 cinnamon stick, 4 whole cloves, 1 bay leaf, 1 tsp dried oregano","100 g Kefalotyri or Pecorino, finely grated (Parmesan works at a pinch)","For the béchamel: 100 g butter, 100 g flour, 1 L whole milk, 4 egg yolks, a grating of nutmeg","Salt and pepper, olive oil"],"ro":["500 g paste tip pastitsio (lungi, tubulare nr. 2; bucatini este o alternativă bună)","600 g carne tocată de vită (sau jumătate vită, jumătate miel)","1 ceapă mare, tocată mărunt","3 căței de usturoi, tocați","400 g roșii tocate (la conservă)","2 linguri pastă de roșii","150 ml vin roșu sec","1 baton de scorțișoară, 4 cuișoare întregi, 1 frunză de dafin, 1 linguriță oregano uscat","100 g Kefalotyri sau Pecorino, ras fin (Parmezan se poate la nevoie)","Pentru béchamel: 100 g unt, 100 g făină, 1 l lapte integral, 4 gălbenușuri, puțină nucușoară rasă","Sare, piper, ulei de măsline"]},"howIsMade":{"ru":"Разогрейте 3 столовые ложки оливкового масла в тяжёлой сковороде и пассеруйте нарезанный лук 8–10 минут, добавьте чеснок на 30 секунд, затем выложите фарш. Разомните его деревянной ложкой и дайте глубоко подрумяниться, около 10 минут. Вмешайте томатную пасту, обжаривайте до кирпичного цвета, влейте вино и уварите на половину, прежде чем добавить помидоры, палочку корицы, гвоздику, лавровый лист и орегано. Щедро посолите и поперчите и тушите без крышки на слабом огне минимум 45 минут; целые специи извлеките перед сборкой.\n\nПока готовится мясо, сделайте бешамель: растопите масло в широкой кастрюле, всыпьте муку и помешивайте 1–2 минуты без цвета, тонкой струйкой влейте тёплое молоко, не переставая взбивать, и варите 5–7 минут, пока соус не покроет тыльную сторону ложки. Снимите с огня, по одному вбейте желтки, добавьте мускатный орех и половину тёртого сыра и посолите.\n\nОтварите макароны в хорошо подсоленной воде на 2 минуты меньше, чем указано на упаковке — они дойдут в духовке — слейте и перемешайте с оставшимся сыром и половником мясного соуса, чтобы не слипались.\n\nВ форме 25×35 см выложите половину макарон в одном направлении, равномерно распределите мясной соус, накройте оставшимися макаронами, выровненными так же. Залейте бешамелем, разровняйте и запекайте при 180°C 45–50 минут, пока сверху не появится золотистая, бурлящая корочка.\n\nДайте постоять не менее 20 минут, прежде чем нарезать — нарезанный горячим, паститсио разваливается.","en":"Heat 3 tablespoons of olive oil in a heavy pan and brown the chopped onion for 8–10 minutes, add the garlic for 30 seconds, then crumble in the mince. Break it up with a wooden spoon and let it brown deeply, about 10 minutes. Stir in the tomato paste, fry until brick-red, deglaze with the wine and let it reduce by half before adding the tomatoes, cinnamon stick, cloves, bay leaf and oregano. Season generously and simmer uncovered on low heat for at least 45 minutes; fish out the whole spices before assembling.\n\nWhile the meat cooks, make the béchamel: melt the butter in a wide saucepan, whisk in the flour for a couple of minutes without colour, pour in the warm milk in a slow stream while whisking, then simmer 5–7 minutes until it coats the back of a spoon. Off the heat, beat in the egg yolks one at a time, add the nutmeg and half the grated cheese, and season.\n\nBoil the pasta in well-salted water 2 minutes less than the package says — it'll finish in the oven — drain and toss with the remaining cheese and a ladle of meat sauce so the noodles don't stick.\n\nIn a 25×35 cm baking dish, lay half the pasta in one direction, spread the meat sauce evenly over it, then top with the rest of the pasta aligned the same way. Pour the béchamel over, smooth it level, and bake at 180°C for 45–50 minutes until golden and bubbling.\n\nLet it rest at least 20 minutes before cutting; sliced too hot, the layers collapse."}},{"id":197,"servings":6,"tipType":"veg","pairingsType":"mediterranean","nutrition":{"cal":280,"prot":5,"carb":35,"fat":14,"fib":3},"origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Долмадес","en":"Dolmades","ro":"Dolmades"},"category":{"ru":"Закуска","en":"Appetizer","ro":"Aperitiv"},"ingredients":{"ru":["1 банка (450 г) виноградных листьев в рассоле, слить и промыть (или 60 свежих, бланшированных)","200 г длиннозерного риса (арборио тоже подойдёт)","1 крупная луковица, мелко нарезанная","6 стрелок зелёного лука, тонкими кружками","Большой пучок свежего укропа, нарубленный","Маленький пучок свежей мяты, нарубленный","Маленький пучок плоской петрушки, нарубленный","Сок 2 лимонов","150 мл оливкового масла extra virgin","1 ч. л. соли, свежемолотый чёрный перец","По желанию, но традиционно: 1 натёртый помидор"],"en":["1 jar (450 g) preserved grape leaves, drained and rinsed (or 60 fresh blanched leaves)","200 g long-grain rice (arborio works)","1 large onion, finely chopped","6 spring onions, thinly sliced","A large bunch of fresh dill, chopped","A small bunch of fresh mint, chopped","A small bunch of flat-leaf parsley, chopped","Juice of 2 lemons","150 ml extra-virgin olive oil","1 tsp salt, freshly ground black pepper","Optional but traditional: 1 grated tomato"],"ro":["1 borcan (450 g) de frunze de viță conservate, scurse și clătite (sau 60 de frunze proaspete opărite)","200 g orez cu bob lung (merge și arborio)","1 ceapă mare, tocată mărunt","6 fire de ceapă verde, tăiate subțire","Un mănunchi mare de mărar proaspăt, tocat","Un mănunchi mic de mentă proaspătă, tocată","Un mănunchi mic de pătrunjel cu frunza plată, tocat","Zeama de la 2 lămâi","150 ml ulei de măsline extravirgin","1 linguriță sare, piper negru proaspăt măcinat","Opțional dar tradițional: 1 roșie rasă"]},"howIsMade":{"ru":"Замочите рис в холодной воде на 15 минут и слейте. Разогрейте 3 столовые ложки оливкового масла в широкой сковороде и пассеруйте нарезанный лук 8 минут до прозрачности, без цвета. Добавьте зелёный лук, все травы, отжатый рис, половину лимонного сока и щедрую щепотку соли; перемешайте минуту, чтобы раскрылись ароматы, затем выложите начинку на тарелку и остудите до комнатной температуры.\n\nПоложите виноградный лист на стол прожилками вверх, черешком к себе. Выложите чайную ложку с горкой начинки у черешка, заверните нижний край на начинку, подверните бока внутрь и плотно скатайте небольшим цилиндром. Не переполняйте — рис разбухает при варке, и слишком тугие долмадес лопнут.\n\nДно тяжёлой кастрюли застелите рваными или потрёпанными листьями, чтобы ничего не пригорало. Уложите долмадес плотными кольцами швом вниз — так они держат друг друга. Полейте оставшимся маслом и лимонным соком, налейте холодной воды до уровня долмадес и прижмите сверху термостойкой тарелкой, чтобы они оставались под водой.\n\nМедленно доведите до кипения, накройте и варите на самом маленьком огне 50–60 минут, пока рис не станет мягким, а жидкость почти не впитается. Дайте остыть прямо в кастрюле — подают холодными или при комнатной температуре, с долькой лимона и густым йогуртом. Приготовленные накануне, на следующий день они заметно вкуснее.","en":"Soak the rice in cold water for 15 minutes and drain. Heat 3 tablespoons of olive oil in a wide pan and sweat the chopped onion for 8 minutes until translucent, no colour. Add the spring onions, all the herbs, the drained rice, half the lemon juice and a generous pinch of salt; stir for a minute to bloom the aromas, then tip onto a plate to cool to room temperature.\n\nLay a grape leaf on the work surface vein-side up, stem at the bottom. Place a heaped teaspoon of the rice mixture near the stem, fold the bottom edge up and over, fold both sides in, and roll up tightly into a small cigar. Don't overfill — the rice swells as it cooks and packed too tightly the dolma will split.\n\nLine the bottom of a heavy pot with torn or broken leaves to prevent sticking. Pack the rolled dolmades in concentric circles, seam-side down, snug enough to hold each other in place. Pour over the remaining olive oil and lemon juice, add cold water just to the top of the dolmades, and press a heatproof plate directly on the surface to keep them submerged.\n\nBring slowly to a simmer, cover, and cook on the lowest heat for 50 minutes to an hour, until the rice is tender and the liquid mostly absorbed. Leave to cool in the pot — they're served cold or at room temperature, with a wedge of lemon and a bowl of thick yoghurt. Made the day before, they taste markedly better."}},{"id":198,"servings":12,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":380,"prot":7,"carb":48,"fat":18,"fib":1},"origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Галактобуреко","en":"Galaktoboureko","ro":"Galaktoboureko"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["500 г теста фило, размороженного","200 г несолёного сливочного масла, растопленного","1 л цельного молока","200 г мелкого сахара (для крема)","150 г мелкой манной крупы","4 крупных яйца","1 ч. л. ванильного экстракта","Цедра 1 лимона","Для сиропа: 400 г сахара, 250 мл воды, сок половины лимона, полоска апельсиновой цедры, 1 палочка корицы"],"en":["500 g phyllo pastry, thawed","200 g unsalted butter, melted","1 L whole milk","200 g caster sugar (for the custard)","150 g fine semolina","4 large eggs","1 tsp vanilla extract","Zest of 1 lemon","For the syrup: 400 g caster sugar, 250 ml water, juice of half a lemon, a strip of orange peel, 1 stick of cinnamon"],"ro":["500 g foi de plăcintă (phyllo), dezghețate","200 g unt nesărat, topit","1 l lapte integral","200 g zahăr tos (pentru cremă)","150 g griș fin","4 ouă mari","1 linguriță extract de vanilie","Coaja rasă de la 1 lămâie","Pentru sirop: 400 g zahăr, 250 ml apă, zeama de la o jumătate de lămâie, o fâșie de coajă de portocală, 1 baton de scorțișoară"]},"howIsMade":{"ru":"Начните сироп заранее — он должен быть холодным, когда горячий пирог выйдет из духовки — соедините сахар, воду, лимонный сок, апельсиновую цедру и корицу в маленькой кастрюле, доведите до кипения, затем варите 4 минуты, снимите с огня и дайте полностью остыть. Для крема нагрейте молоко в широкой кастрюле с сахаром и лимонной цедрой, пока оно едва не задымится (не давайте кипеть), всыпьте манку тонкой равномерной струйкой при постоянном помешивании, затем продолжайте взбивать на слабом огне 5–6 минут, пока не загустеет до жидкого пудинга; сняв с огня, вмешайте яйца по одному (смесь должна быть тёплой, но не настолько горячей, чтобы свернуть их) и ваниль, затем прижмите плёнку прямо к поверхности, чтобы предотвратить образование плёнки. Смажьте форму 22×30 см растопленным маслом, выложите 7 листов фило на дно, обильно смазывая каждый маслом и оставляя края свисать по бокам (эти клапаны потом загнётся обратно поверх), влейте ещё тёплый крем, разровняйте его, загните свисающие клапаны внутрь и смажьте их маслом, затем накройте ещё 7 листами фило (снова смазывая каждый) и обрежьте или подоткните края, чтобы пирог был полностью запечатан. Надрежьте верхнее фило ромбами или квадратами острым ножом — режьте до конца, чтобы сироп позже мог проникнуть — обильно смажьте поверхность остатком масла, и запекайте при 170°C 45–55 минут, пока верх не станет глубоко золотисто-коричневым. В момент, когда он выходит из духовки, равномерно полейте холодным сиропом горячий пирог — он зашипит и задымится — дайте отстояться минимум 4 часа, идеально на ночь, прежде чем нарезать по линиям и подавать при комнатной температуре.","en":"Start the syrup well in advance — it must be cold when the hot pie comes out of the oven — combine the sugar, water, lemon juice, orange peel and cinnamon in a small saucepan, bring to a boil then simmer 4 minutes, take off the heat and leave to cool completely. For the custard, heat the milk in a wide saucepan with the sugar and lemon zest until just steaming (do not let it boil), sprinkle the semolina in a fine even stream while whisking constantly, then keep whisking on low heat for 5–6 minutes until it thickens to a loose pudding; off the heat, beat in the eggs one at a time (the mixture should be warm but not hot enough to scramble them) and the vanilla, then press clingfilm directly onto the surface to stop a skin forming. Brush a 22×30 cm baking dish with melted butter, lay 7 sheets of phyllo across the bottom brushing each generously with butter and letting the edges hang over the sides (those flaps will fold back over the top later), pour in the still-warm custard, smooth it level, fold the overhanging flaps inward and brush them with butter, then cover with another 7 sheets of phyllo (again buttering each) and trim or tuck the edges so the pie is fully sealed. Score the top phyllo into diamonds or squares with a sharp knife — cut all the way through so the syrup can later penetrate — brush the surface lavishly with the last of the butter, and bake at 170°C for 45–55 minutes until the top is deeply golden brown. The moment it comes out of the oven, pour the cold syrup evenly over the hot pie — it will sizzle and steam — leave to settle at least 4 hours, ideally overnight, before cutting along the score lines and serving at room temperature."}},{"id":199,"servings":4,"tipType":"def","pairingsType":"italian","nutrition":{"cal":740,"prot":28,"carb":88,"fat":30,"fib":4},"origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Пицца Маргарита","en":"Pizza Margherita","ro":"Pizza Margherita"},"category":{"ru":"Пицца","en":"Pizza","ro":"Pizza"},"ingredients":{"ru":["Для теста (4 пиццы): 500 г муки 00 (или хлебной), 325 мл холодной воды, 10 г соли, 1 г свежих дрожжей (или ¼ ч. л. сухих)","На каждую пиццу: 80 г томатов San Marzano (консервированных, размятых руками), щепотка соли, немного оливкового масла","100 г моцареллы fior di latte на пиццу, разорвать руками (или моцарелла из молока буйволицы)","Несколько листьев свежего базилика на пиццу","Оливковое масло extra virgin для финиша","Манка или мука для формовки и для пиццы-лопаты"],"en":["For the dough (4 pizzas): 500 g 00 flour (or bread flour), 325 ml cold water, 10 g salt, 1 g fresh yeast (or ¼ tsp dried)","For each pizza: 80 g San Marzano tomatoes (canned, hand-crushed), a pinch of salt, a drizzle of olive oil","100 g fior di latte mozzarella per pizza, torn into pieces (or buffalo mozzarella)","A few fresh basil leaves per pizza","Extra-virgin olive oil to finish","Semolina or flour for shaping and the peel"],"ro":["Pentru aluat (4 pizza): 500 g făină 00 (sau pentru pâine), 325 ml apă rece, 10 g sare, 1 g drojdie proaspătă (sau ¼ linguriță uscată)","Pentru fiecare pizza: 80 g roșii San Marzano (la conservă, sfărâmate cu mâna), un praf de sare, un fir de ulei de măsline","100 g mozzarella fior di latte per pizza, ruptă în bucățele (sau mozzarella de bivoliță)","Câteva frunze de busuioc proaspăt pentru fiecare pizza","Ulei de măsline extravirgin pentru finalizare","Griș sau făină pentru modelare și pentru lopată"]},"howIsMade":{"ru":"Для теста растворите дрожжи в холодной воде, затем вмешайте муку и соль до образования лохматой массы, замесите вручную 10 минут (или 6 минут стационарным миксером с крюком) до гладкости и эластичности, накройте и оставьте при комнатной температуре на час, затем поставьте в холодильник минимум на 24 часа, идеально на 48–72 — долгая холодная расстойка даёт неаполитанскому тесту эту пузырчатую обугленную корку и воздушную структуру. За два часа до выпечки достаньте тесто, разделите на четыре шара по 210 г, посыпьте мукой, накройте влажным полотенцем и дайте дойти до комнатной температуры, тем временем разогрейте духовку до максимума (250°C или выше) с камнем для пиццы или тяжёлым стальным листом внутри минимум 45 минут; без серьёзного жара под пиццей корка никогда не успеет схватиться. Растяните один шар руками на хорошо посыпанной мукой поверхности — кончиками пальцев придавите центр плоско, оставляя приподнятый бортик, затем мягко потяните и растяните диск примерно до 28 см — никогда не используйте скалку, она разрушает газовые карманы в корке — и переложите на присыпанную мукой лопату. Положите 80 г раздавленных томатов в центр и распределите спиралью обратной стороной ложки, остановившись в 2 см от края, слегка посолите томаты, сбрызните оливковым маслом и разложите сверху разорванную моцареллу (не слишком много, иначе пицца зальётся). Сдвиньте пиццу на камень и пеките, пока корка не станет вздутой и обугленной местами, сыр не растает в лужицы, а бортик не станет тёмно-золотистым — 4–6 минут в домашней духовке на полную, 90 секунд в дровяной неаполитанской печи — вытащите, разорвите сверху листья базилика (которые сгорели бы в духовке), сбрызните последней нитью оливкового масла и ешьте немедленно.","en":"For the dough, dissolve the yeast in the cold water then mix in the flour and salt until you have a shaggy mass, knead by hand for 10 minutes (or 6 minutes with a stand mixer and dough hook) until smooth and elastic, cover and rest at room temperature for an hour, then refrigerate for at least 24 hours and ideally 48 to 72 — the long cold proof is what gives Neapolitan dough its blistered char and airy structure. Two hours before baking, take the dough out, divide into four 210 g balls, dust with flour, cover with a damp cloth and let them come to room temperature, meanwhile heat the oven as hot as it goes (250°C or above) with a pizza stone or heavy steel sheet inside for at least 45 minutes; without serious heat under the pizza, the crust will never set in time. Hand-stretch one ball on a well-floured surface — press the centre flat with your fingertips leaving a raised lip, then gently pull and stretch the disc to about 28 cm across — never use a rolling pin, which collapses the gas pockets in the crust — and slide it onto a floured peel. Spoon 80 g of crushed tomato into the centre and spread it in a spiral with the back of the spoon stopping 2 cm from the edge, salt the tomato lightly, drizzle a little olive oil, and scatter the torn mozzarella over the top (not too much, or the pizza floods). Slide the pizza onto the stone and bake until the crust is puffed and charred in spots, the cheese has melted into pools and the rim is dark gold — 4 to 6 minutes in a domestic oven at full blast, 90 seconds in a wood-fired Neapolitan oven — pull it out, tear over the basil leaves (which would scorch in the oven), drizzle a final thread of olive oil, and eat immediately."}},{"id":200,"servings":6,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":720,"prot":36,"carb":58,"fat":36,"fib":4},"origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Лазанья по-болонски","en":"Lasagne alla Bolognese","ro":"Lasagne alla Bolognese"},"category":{"ru":"Паста","en":"Pasta","ro":"Paste"},"ingredients":{"ru":["Для рагу: 400 г говяжьего фарша, 200 г свиного фарша, 80 г панчетты мелкими кубиками, 1 луковица + 1 морковь + 1 черешок сельдерея — всё мелко нарезать, 200 мл сухого красного вина, 400 г пассаты или рубленых томатов, 250 мл цельного молока, 1 лавровый лист, соль и перец, оливковое масло","Для бешамеля: 80 г сливочного масла, 80 г муки, 1 л цельного молока, соль, щепотка свеженатёртого мускатного ореха","300 г свежих яичных листов лазаньи (или 250 г сухих, бланшированных)","150 г Пармиджано-Реджано, мелко натёртого","Сливочное масло для формы"],"en":["For the ragù: 400 g beef mince, 200 g pork mince, 80 g pancetta finely diced, 1 onion + 1 carrot + 1 celery stalk all finely diced, 200 ml dry red wine, 400 g passata or chopped tomatoes, 250 ml whole milk, 1 bay leaf, salt and pepper, olive oil","For the béchamel: 80 g butter, 80 g flour, 1 L whole milk, salt, a grating of nutmeg","300 g fresh egg lasagne sheets (or 250 g dried, blanched)","150 g Parmigiano Reggiano, finely grated","Butter for the dish"],"ro":["Pentru ragù: 400 g vită tocată, 200 g porc tocat, 80 g pancetta tăiată cubulețe, 1 ceapă + 1 morcov + 1 țelină — toate tocate mărunt, 200 ml vin roșu sec, 400 g passata sau roșii tocate, 250 ml lapte integral, 1 frunză de dafin, sare și piper, ulei de măsline","Pentru béchamel: 80 g unt, 80 g făină, 1 l lapte integral, sare, puțină nucușoară rasă","300 g foi proaspete de lasagne cu ou (sau 250 g uscate, opărite)","150 g Parmigiano Reggiano, ras fin","Unt pentru vasul de copt"]},"howIsMade":{"ru":"Вытопите панчетту мягко в тяжёлой кастрюле с каплей оливкового масла на среднем-низком огне 5 минут, пока жир не станет прозрачным, добавьте нарубленное софритто (лук, морковь, сельдерей) и готовьте 10 минут, пока не размягчится и края не подзолотятся, затем раскрошите оба вида мяса и хорошо подрумяньте — терпение: первые 3 минуты не мешайте, затем разломайте и готовьте ещё 10 минут, пока дно сковороды глубоко не карамелизуется. Влейте вино, соскребите осадок с дна деревянной ложкой и уварите вдвое, затем добавьте помидоры, молоко (фирменная нота Болоньи — округляет кислоту и стягивает текстуру), лавровый лист и чайную ложку соли; доведите до едва заметного кипения, частично накройте, и варите на самом слабом возможном огне минимум 2 часа, идеально 3, изредка помешивая и добавляя каплю воды, если грозит высохнуть — готовый рагу должен быть глянцевым, глубокого коричнево-красного цвета и почти пастой, никогда не супом. Пока рагу заканчивается, сделайте бешамель: растопите масло, вмешайте муку на 2 минуты без цвета, влейте тёплое молоко тонкой струйкой при помешивании и варите 5 минут до густоты, затем приправьте солью и щедрой щепоткой мускатного ореха. Если используете сухие листы лазаньи, бланшируйте их в подсоленной кипящей воде минуту и выложите на влажные полотенца — свежие листы идут сырыми — нагрейте духовку до 180°C и смажьте маслом форму 25×35 см, затем распределите тонкий слой бешамеля на дне, затем слой пасты, затем рагу, затем бешамель, затем снежную пыль пармезана, и повторите, пока не используете всё (шесть-семь слоёв — это болонская цель), завершите бешамелем и более обильным душем пармезана. Запекайте 35–40 минут, пока верх не станет бронзовым и не забулькает, затем дайте отдохнуть 20 минут перед нарезкой — горячая нарезанная лазанья расползается, отдохнувшая держит слои.","en":"Render the pancetta gently in a heavy pot with a splash of olive oil over medium-low heat for 5 minutes until the fat runs clear, add the chopped soffritto (onion, carrot, celery) and cook 10 minutes until soft and just gilded at the edges, then crumble in both meats and brown them properly — patience: do not stir for the first 3 minutes, then break them up and cook 10 more minutes until the pan bottom is deeply caramelised. Pour in the wine, scrape the fond from the pan with a wooden spoon and reduce by half, then add the tomatoes, the milk (the Bolognese signature — it rounds the acid and tightens the texture), the bay leaf and a teaspoon of salt; bring to a bare simmer, partially cover, and cook on the lowest possible heat for at least 2 hours and ideally 3, stirring occasionally and adding a splash of water if it threatens to dry — the finished ragù should be glossy, deep brown-red and almost a paste, never a soup. While the ragù finishes, make the béchamel: melt the butter, whisk in the flour for 2 minutes without colour, pour in the warm milk in a slow stream while whisking and simmer 5 minutes until thick, then season with salt and a generous grating of nutmeg. If using dried lasagne sheets blanch them in salted boiling water for a minute and lay on damp tea towels — fresh sheets go in raw — heat the oven to 180°C and butter a 25×35 cm baking dish, then spread a thin layer of béchamel on the bottom, then a layer of pasta, then ragù, then béchamel, then a snowy dusting of Parmigiano, and repeat until you have used everything (six to seven layers is the Bolognese target), finishing with béchamel and a heavier shower of Parmigiano. Bake 35–40 minutes until the top is bronzed and bubbling, then rest 20 minutes before cutting — lasagne sliced hot slides apart, lasagne rested holds its layers."}},{"id":201,"servings":4,"tipType":"meat","pairingsType":"italian","nutrition":{"cal":580,"prot":42,"carb":18,"fat":32,"fib":3},"origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Оссобуко по-милански","en":"Osso Buco alla Milanese","ro":"Osso Buco alla Milanese"},"category":{"ru":"Основное","en":"Main","ro":"Fel principal"},"ingredients":{"ru":["4 толстых среза телячьей голяшки (3–4 см толщиной, около 350 г каждый), обвязанные кулинарной нитью по окружности","Соль и свежемолотый чёрный перец","Мука для обваливания","4 ст. л. несолёного сливочного масла, 2 ст. л. оливкового масла","1 луковица + 1 морковь + 1 черешок сельдерея, всё мелко нарезать","200 мл сухого белого вина","400 г рубленых томатов","500 мл телячьего или куриного бульона","1 лавровый лист, несколько веточек тимьяна","Для гремолаты: цедра 1 лимона, 2 зубчика чеснока очень мелко измельчить, маленький пучок плоской петрушки мелко нарубленной"],"en":["4 thick-cut veal shanks (3–4 cm thick, about 350 g each), tied around the circumference with kitchen string","Salt and freshly ground black pepper","Plain flour for dusting","4 tbsp unsalted butter, 2 tbsp olive oil","1 onion + 1 carrot + 1 celery stalk, all finely diced","200 ml dry white wine","400 g chopped tomatoes","500 ml veal or chicken stock","1 bay leaf, a few sprigs of thyme","For the gremolata: zest of 1 lemon, 2 garlic cloves finely minced, a small bunch of flat-leaf parsley finely chopped"],"ro":["4 rasoluri groase de vițel (3–4 cm grosime, aproximativ 350 g fiecare), legate cu sfoară de bucătărie pe circumferință","Sare și piper negru proaspăt măcinat","Făină albă pentru tăvălit","4 linguri unt nesărat, 2 linguri ulei de măsline","1 ceapă + 1 morcov + 1 țelină, toate tocate mărunt","200 ml vin alb sec","400 g roșii tocate","500 ml fond de vițel sau pui","1 frunză de dafin, câteva fire de cimbru","Pentru gremolata: coaja rasă de la 1 lămâie, 2 căței de usturoi tocați fin, un mănunchi mic de pătrunjel cu frunza plată, tocat fin"]},"howIsMade":{"ru":"Обсушите голяшки — мокрое мясо паруется вместо обжарки — обильно посолите и поперчите и слегка обваляйте в муке, стряхнув излишек, затем разогрейте половину сливочного масла и всё растительное в тяжёлой жаровне на среднем-высоком огне до пены, выложите голяшки и не трогайте 4 минуты, пока низ не подрумянится глубоко, переверните для второй стороны, затем переложите на тарелку. Уменьшите огонь до среднего, добавьте оставшееся масло и софритто, и томите аккуратно 10 минут, пока не размягчится и не подзолотится по краям, затем влейте вино, увеличьте огонь и уварите вдвое, соскребая карамелизованные кусочки со дна. Вмешайте помидоры, лавровый лист и тимьян, верните голяшки в жаровню одним слоем, и влейте бульон, чтобы он покрыл мясо примерно на две трети — кости должны оставаться открытыми, чтобы костный мозг не вытек — и доведите до едва заметного кипения. Накройте и тушите на самом слабом огне или в духовке 160°C 2–2½ часа, аккуратно переворачивая голяшки каждые 30 минут для равномерного приготовления — они готовы, когда мясо отваливается от кости при нажатии ложкой и соус загустел до глянцевой глазури — затем достаньте их осторожно, поскольку кости и мозг хрупки в этот момент. Пока голяшки отдыхают, смешайте лимонную цедру, чеснок и петрушку для гремолаты, положите голяшку на каждую тарелку, полейте обильным соусом, и увенчайте щедрой щепоткой сырой гремолаты — её резкость прорезает жирность и это то, что делает osso buco по-милански, а не просто тушёной телятиной — подавайте с ризотто алла миланезе, полентой или куском хлеба для мозга.","en":"Pat the shanks dry — wet meat steams instead of searing — season aggressively with salt and pepper and dust lightly in flour knocking off the excess, then heat half the butter and all the oil in a heavy braising pan over medium-high heat until foaming, lay the shanks in and do not touch them for 4 minutes until the bottom is deeply browned, flip and do the second side, then lift onto a plate. Lower the heat to medium, add the rest of the butter and the soffritto, and cook gently for 10 minutes until soft and golden at the edges, then pour in the wine, raise the heat, and reduce by half while scraping up the caramelised bits from the bottom of the pan. Stir in the tomatoes, bay leaf and thyme, return the shanks to the pan in a single layer, and pour in just enough stock to come about two-thirds of the way up the meat — the bones should stay exposed so the marrow stays in — and bring to a bare simmer. Cover and braise on the lowest heat or in a 160°C oven for 2 to 2½ hours, turning the shanks gently every 30 minutes so they cook evenly — they are done when the meat slumps off the bone at the press of a spoon and the sauce has thickened to a glossy gravy — then lift them out carefully because the bones and marrow are fragile at this point. While the shanks rest, stir together the lemon zest, garlic and parsley to make the gremolata, place a shank on each plate, spoon over plenty of sauce, and crown with a generous pinch of the raw gremolata — its sharpness cuts the richness and is what makes osso buco Milanese rather than just braised veal — serve with risotto alla milanese, polenta, or a piece of bread for the marrow."}},{"id":202,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":540,"prot":9,"carb":42,"fat":36,"fib":1},"origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Тирамису","en":"Tiramisu","ro":"Tiramisu"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["500 г маскарпоне, комнатной температуры","5 крупных яиц, разделить на белки и желтки, комнатной температуры","100 г мелкого сахара","250 мл крепкого холодного эспрессо (около 5 порций)","2 ст. л. сладкой Марсалы или тёмного рома (по желанию, традиционно в Тревизо)","300 г савоярди (итальянское дамское печенье — твёрдое, не мягкое)","Несладкое какао-порошок для посыпки","Кусочек тёмного шоколада для стружки (по желанию)","Щепотка соли для белков"],"en":["500 g mascarpone, at room temperature","5 large eggs, separated, at room temperature","100 g caster sugar","250 ml strong cold espresso (about 5 shots)","2 tbsp Marsala (sweet) or dark rum (optional, traditional in Treviso)","300 g savoiardi (Italian ladyfingers — the firm kind, not the soft kind)","Unsweetened cocoa powder for dusting","A small piece of dark chocolate for shaving (optional)","Pinch of salt for the egg whites"],"ro":["500 g mascarpone, la temperatura camerei","5 ouă mari, separate, la temperatura camerei","100 g zahăr tos","250 ml espresso tare rece (aproximativ 5 ceșcuțe)","2 linguri Marsala dulce sau rom închis (opțional, tradițional la Treviso)","300 g savoiardi (pișcoturi italiene — cele ferme, nu cele moi)","Cacao amară pentru pudrare","O bucățică de ciocolată neagră pentru ras (opțional)","Un praf de sare pentru albușuri"]},"howIsMade":{"ru":"Взбейте желтки с сахаром в большой миске 4–5 минут — вручную или электрическим венчиком — до бледного, пенистого состояния, объёмом увеличенного в три раза; сахар должен быть полностью растворён, когда вы трёте немного между пальцами, недомешивание здесь даёт зернистый тирамису позже. Добавьте маскарпоне в три приёма, аккуратно взбивая после каждого, пока крем не станет гладким и блестящим, затем в отдельной чистой миске взбейте белки со щепоткой соли до твёрдых блестящих пиков, которые держат форму при поднятии венчика, и вмешайте белки в маскарпоне в три добавления большой лопаткой, складывая от центра наружу, чтобы сохранить воздух внутри — готовый крем должен быть лёгким, почти текучим, но держать мягкие пики. Смешайте холодный эспрессо и марсалу в неглубокой посуде, затем окунайте савоярди по одному — лишь кратко, максимум 2 секунды с каждой стороны — это губки, и чрезмерно вымоченные дамские пальчики превращаются в кашу и плачут сквозь крем, и положите их плотным одним слоем на дно формы 22×30 см. Распределите половину крема маскарпоне по савоярди ровным слоем, затем повторите — ещё один плотный слой замоченных савоярди, затем остальной крем сверху, разглаженный лопаткой. Накройте плёнкой и поставьте в холодильник минимум на 6 часов, идеально на ночь — тирамису, съеденный в тот же день, имеет вкус своих частей, тирамису, отдохнувший за ночь, имеет вкус одного десерта — прямо перед подачей обильно посыпьте сверху какао, пропущенным через мелкое сито, натрите немного тёмного шоколада если хотите, и нарежьте горячим ножом, вытираемым между ломтиками.","en":"Whisk the egg yolks with the sugar in a large bowl for 4–5 minutes — by hand or with an electric beater — until pale, foamy and dramatically tripled in volume; the sugar should be completely dissolved when you rub a little between your fingers, undermixing here gives you a grainy tiramisu later. Add the mascarpone in three batches, whisking gently after each, until the cream is smooth and glossy, then in a separate clean bowl whisk the egg whites with a pinch of salt to firm glossy peaks that hold their shape when the whisk is lifted, and fold the whites into the mascarpone in three additions with a large spatula, folding from the centre outwards to keep the air in — the finished cream should be light, almost pourable but holding soft peaks. Mix the cold espresso and Marsala in a shallow dish, then dip the savoiardi one at a time — just briefly, 2 seconds per side at most — they are sponges, and oversoaked ladyfingers turn to mush and weep through the cream, and lay them in a tight single layer in the bottom of a 22×30 cm dish. Spread half the mascarpone cream over the ladyfingers in an even layer, then repeat — another tight layer of dipped savoiardi, then the rest of the cream on top, smoothed level with the spatula. Cover with clingfilm and refrigerate at least 6 hours, ideally overnight — tiramisu eaten the same day tastes like its parts, tiramisu rested overnight tastes like one dessert — just before serving dust the top generously with cocoa pushed through a fine sieve, shave over a little dark chocolate if you like, and cut with a hot knife wiped between slices."}},{"id":203,"servings":4,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":520,"prot":22,"carb":76,"fat":14,"fib":3},"origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Качо э пепе","en":"Cacio e Pepe","ro":"Cacio e Pepe"},"category":{"ru":"Паста","en":"Pasta","ro":"Paste"},"ingredients":{"ru":["400 г тоннарелли или плотных спагетти","200 г Пекорино Романо, мелко натереть на тёрке-microplane (никакого Пармезана — он плавится иначе)","1 столовая ложка с горкой целых горошин чёрного перца, свежеперебитых в ступке (не молотых заранее)","Морская соль для воды (меньше обычного, сыр сам по себе солёный)"],"en":["400 g tonnarelli or thick spaghetti","200 g Pecorino Romano, finely grated on a microplane (no Parmesan — it doesn't melt the same way)","1 heaped tablespoon whole black peppercorns, freshly cracked in a mortar (not pre-ground)","Sea salt for the pasta water (less than usual, since the cheese is salty)"],"ro":["400 g tonnarelli sau spaghete groase","200 g Pecorino Romano, ras fin pe microplane (fără Parmezan — nu se topește la fel)","1 lingură plină de boabe întregi de piper negru, proaspăt zdrobite în mojaru (nu măcinat în prealabil)","Sare de mare pentru apa pastelor (mai puțină decât de obicei, fiindcă brânza este sărată)"]},"howIsMade":{"ru":"Подсушите дроблёный перец в широкой сухой сковороде на среднем огне 30 секунд — пока он не начнёт остро бить в нос — и плесните полполовника холодной воды, чтобы остановить нагрев и получить пряную взвесь. Снимите с огня.\n\nДоведите 3 л слегка подсолённой воды до кипения и сварите пасту чуть недо al dente, минуты на 1 меньше, чем указано на упаковке; в Риме паста доходит в соусе, а не в кастрюле.\n\nПока паста варится, наберите кружку крахмалистой воды из кастрюли. В широкой миске взбейте тёртый Пекорино с примерно 4 ст. л. горячей воды — дайте ей сначала пару секунд остыть: кипяток на сыре моментально сворачивает его в комки — до густой, как рикотта, пасты; разведите ещё ложкой воды, если слишком плотно.\n\nЩипцами переложите пасту прямо из кастрюли в перечную сковороду (не сливая), плесните половник крахмалистой воды и энергично перемешайте на слабом огне 30 секунд, пока паста не станет глянцевой и хорошо покрытой.\n\nСнимите сковороду с огня — Пекорино выше точки кипения схватывается нитяными комками — влейте сырную пасту и быстро вмешайте, добавляя воду от пасты по ложке при необходимости, пока соус не превратится в кремовую эмульсию, цепляющуюся за каждую нить. Подавайте сразу, ещё одной мельницей свежего перца сверху; cacio e pepe остывает быстро, поэтому тарелки должны быть тёплыми, а едоки за столом.","en":"Toast the cracked pepper in a wide dry pan over medium heat for 30 seconds — until you can smell it sharply — and add half a ladle of cold water to stop the cooking and create a peppery slurry. Set aside off the heat.\n\nBring 3 L of lightly salted water to a boil and cook the pasta until just shy of al dente, about a minute less than the package says; in Rome the pasta finishes cooking in the sauce, not in the pot.\n\nWhile the pasta cooks, scoop out a mug of starchy water from the pot. In a wide bowl, whisk the grated Pecorino with about 4 tablespoons of the hot pasta water — let it cool a few seconds first, since boiling water on cheese clumps it instantly — until you have a thick, ricotta-like paste; loosen with another spoonful of water if it's too stiff.\n\nLift the pasta from the pot with tongs straight into the peppered pan (don't drain it), splash in a ladle of starchy water, and toss vigorously over low heat for 30 seconds, until the pasta is glossy and well coated.\n\nTake the pan off the heat — Pecorino above boiling point seizes into stringy clumps — pour over the cheese paste and toss again, fast, adding more pasta water by the spoonful if needed, until the sauce becomes a creamy emulsion that clings to every strand. Plate immediately with another crack of pepper on top; cacio e pepe cools quickly, so plates should be warm and diners at the table."}},{"id":204,"servings":4,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":720,"prot":42,"carb":28,"fat":48,"fib":4},"origin":{"ru":"Индия","en":"India","ro":"India"},"name":{"ru":"Баттер чикен (Мург Маханни)","en":"Butter Chicken (Murgh Makhani)","ro":"Butter Chicken (Murgh Makhani)"},"category":{"ru":"Карри","en":"Curry","ro":"Curry"},"ingredients":{"ru":["800 г куриных бёдер без кости, нарезанных кусками по 4 см","Для маринада: 200 г жирного йогурта, 2 ст. л. пасты из имбиря и чеснока, 1 ч. л. кашмирского красного перца, 1 ч. л. гарам масала, сок половины лимона, 2 ст. л. нейтрального масла, 1 ч. л. соли","Для соуса: 800 г спелых томатов (или 1 большая банка рубленых томатов), 60 г сырых кешью, 1 крупная луковица четвертинками, 4 зубчика чеснока, 3 см имбиря, 4 коробочки зелёного кардамона, 1 палочка корицы, 4 гвоздики, 1 лавровый лист","80 г несолёного сливочного масла, 200 мл жирных сливок","1 ст. л. касури мети (сушёные листья пажитника)","1 ч. л. кашмирского перца, 1 ч. л. гарам масала, 1 ч. л. сахара, соль","Свежая кинза для подачи"],"en":["800 g boneless chicken thighs, cut into 4 cm pieces","For the marinade: 200 g full-fat yoghurt, 2 tbsp ginger-garlic paste, 1 tsp Kashmiri red chilli powder, 1 tsp garam masala, juice of half a lemon, 2 tbsp neutral oil, 1 tsp salt","For the gravy: 800 g ripe tomatoes (or 1 large can chopped tomatoes), 60 g raw cashews, 1 large onion quartered, 4 garlic cloves, 3 cm piece of ginger, 4 green cardamom pods, 1 cinnamon stick, 4 cloves, 1 bay leaf","80 g unsalted butter, 200 ml double cream","1 tbsp kasoori methi (dried fenugreek leaves)","1 tsp Kashmiri red chilli powder, 1 tsp garam masala, 1 tsp sugar, salt","Fresh coriander to finish"],"ro":["800 g pulpe de pui dezosate, tăiate în bucăți de 4 cm","Pentru marinadă: 200 g iaurt gras, 2 linguri pastă de ghimbir-usturoi, 1 linguriță boia Kashmiri, 1 linguriță garam masala, zeama de la o jumătate de lămâie, 2 linguri ulei neutru, 1 linguriță sare","Pentru sosul de bază: 800 g roșii coapte (sau o cutie mare de roșii tocate), 60 g caju crud, 1 ceapă mare în sferturi, 4 căței de usturoi, 3 cm bucată de ghimbir, 4 capsule de cardamom verde, 1 baton de scorțișoară, 4 cuișoare, 1 frunză de dafin","80 g unt nesărat, 200 ml smântână grasă","1 lingură kasoori methi (frunze uscate de schinduf)","1 linguriță boia Kashmiri, 1 linguriță garam masala, 1 linguriță zahăr, sare","Coriandru proaspăt pentru a încheia"]},"howIsMade":{"ru":"Смешайте маринад в широкой миске, добавьте курицу и переверните каждый кусок, пока хорошо не покроется, затем накройте и охладите минимум 4 часа, идеально на ночь. Для подливы замочите кешью в 100 мл горячей воды на 20 минут; положите помидоры, лук, чеснок, имбирь и целые специи в тяжёлую кастрюлю с 200 мл воды, доведите до кипения и варите под крышкой 20–25 минут, пока помидоры не развалятся, а лук не станет полностью мягким, затем выловите корицу, кардамон, гвоздику и лавровый лист, и пюрируйте всё — включая замоченные кешью и их воду — до бархатистой пюре и пропустите через сито. Разогрейте гриль на максимум, выстелите противень фольгой, выложите маринованную курицу в один слой с пространством между кусками и обжарьте на расстоянии 5–6 см от источника 6–8 минут с каждой стороны, пока края не обуглятся, а мясо едва не прожарится — пусть края станут по-настоящему тёмными. Растопите масло в широкой сковороде на среднем огне, влейте процеженную подливу и добавьте чилийский порошок, сахар и чайную ложку соли, варите на лёгком огне 10 минут, часто помешивая, пока цвет не углубится до насыщенного кирпично-оранжевого; влейте сливки, помешивая, пока подлива не станет бархатной, затем опустите обугленную курицу с соками с противня и дайте всему вместе побулькать ещё 4–5 минут. Разотрите касури мети между ладоней над сковородой, вмешайте гарам масалу и попробуйте на соль и сахар, посыпьте сверху листьями кинзы и подавайте с наном или басмати.","en":"Mix the marinade in a wide bowl, add the chicken and turn each piece until well coated, then cover and chill at least 4 hours, ideally overnight. For the gravy, soak the cashews in 100 ml of hot water for 20 minutes; put the tomatoes, onion, garlic, ginger and whole spices into a heavy pan with 200 ml of water, bring to a simmer and cook covered for 20–25 minutes until the tomatoes have collapsed and the onion is fully soft, then fish out the cinnamon, cardamom, cloves and bay leaf, and blend everything — including the soaked cashews and their water — to a velvety purée and pass through a sieve. Heat the broiler high, line a tray with foil, spread the marinated chicken in a single layer with space between the pieces and broil 5–6 cm from the heat for 6–8 minutes per side, until the edges are charred and the meat is just cooked through — let the edges go genuinely dark. Melt the butter in a wide pan over medium heat, pour in the strained gravy and add the chilli powder, sugar and a teaspoon of salt, simmer gently for 10 minutes stirring often until the colour deepens to a rich brick-orange; pour in the cream, stir until the gravy turns velvet, then slide in the charred chicken with any juices from the tray and let everything bubble together for 4–5 minutes more. Crush the kasoori methi between your palms over the pan, stir in the garam masala and taste for salt and sugar, scatter coriander leaves on top, and serve with naan or basmati rice."}},{"id":205,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":780,"prot":38,"carb":78,"fat":32,"fib":3},"origin":{"ru":"Индия","en":"India","ro":"India"},"name":{"ru":"Хайдарабадский бирьяни из ягнятины","en":"Hyderabadi Lamb Biryani","ro":"Biryani de miel din Hyderabad"},"category":{"ru":"Основное","en":"Main","ro":"Fel principal"},"ingredients":{"ru":["800 г баранины (лопатка или нога) на кости, нарезанной кусками по 4 см","500 г басмати, замоченного на 30 минут в холодной воде и слитого","4 крупных луковицы, нарезанных очень тонко (около 600 г)","200 г жирного йогурта","50 г ги + 80 мл нейтрального масла","3 ст. л. пасты из имбиря и чеснока","2 зелёных перца чили, надрезанных вдоль","2 ч. л. кашмирского перца, 1 ч. л. куркумы, 1 ч. л. соли","Целые специи: 1 палочка корицы, 4 коробочки зелёного кардамона + 2 чёрного, 4 гвоздики, 1 лавровый лист, 1 ч. л. шахи джиры, 1 ч. л. горошин чёрного перца","Щепотка шафрана, настоянная в 60 мл тёплого цельного молока","Сок 1 лимона","2 ст. л. рубленой мяты и 2 ст. л. рубленой кинзы","1 ст. л. розовой воды (по желанию, традиционно)","Кусок мягкого теста или плотный лист фольги для герметизации"],"en":["800 g bone-in lamb shoulder or leg, cut into 4 cm pieces","500 g basmati rice, soaked 30 minutes in cold water and drained","4 large onions, very thinly sliced (about 600 g)","200 g full-fat yoghurt","50 g ghee + 80 ml neutral oil","3 tbsp ginger-garlic paste","2 green chillies, slit lengthwise","2 tsp Kashmiri red chilli powder, 1 tsp turmeric, 1 tsp salt","Whole spices: 1 cinnamon stick, 4 green cardamom + 2 black cardamom, 4 cloves, 1 bay leaf, 1 tsp shahi jeera, 1 tsp black peppercorns","A pinch of saffron infused in 60 ml warm whole milk","Juice of 1 lemon","2 tbsp chopped mint and 2 tbsp chopped coriander","1 tbsp rose water (optional, traditional)","A piece of soft dough or a sheet of heavy foil for sealing"],"ro":["800 g spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","500 g orez basmati, înmuiat 30 de minute în apă rece și scurs","4 cepe mari, tăiate foarte subțire (aproximativ 600 g)","200 g iaurt gras","50 g ghee + 80 ml ulei neutru","3 linguri pastă de ghimbir-usturoi","2 ardei iuți verzi, despicați pe lungime","2 lingurițe boia Kashmiri, 1 linguriță turmeric, 1 linguriță sare","Mirodenii întregi: 1 baton de scorțișoară, 4 capsule cardamom verde + 2 cardamom negru, 4 cuișoare, 1 frunză de dafin, 1 linguriță shahi jeera, 1 linguriță boabe de piper negru","Un vârf de șofran infuzat în 60 ml lapte cald","Sucul de la 1 lămâie","2 linguri mentă tocată și 2 linguri coriandru tocat","1 lingură apă de trandafiri (opțional, tradițional)","O bucată de aluat moale sau o folie groasă pentru sigilare"]},"howIsMade":{"ru":"Разогрейте ги и масло в широкой тяжёлой сковороде на среднем огне и медленно обжаривайте нарезанный лук 25–30 минут, часто помешивая, пока он не станет глубоко золотисто-коричневым (бириста), затем откиньте на бумагу, оставьте масло в сковороде и сохраните половину лука для слоёв. Смешайте баранину с йогуртом, пастой имбирь-чеснок, половиной обжаренного лука, раздавленного в руке, чилийским порошком, куркумой, солью, лимонным соком и чайной ложкой шахи джиры, тщательно перемешайте и оставьте мариноваться минимум 2 часа или на ночь в холодильнике; верните маринованную баранину в зарезервированное луковое масло, добавьте корицу, кардамон, гвоздику и лавровый лист, и готовьте под крышкой на слабом огне час — час с четвертью, пока баранина не станет мягкой, а соус не сократится до густого покрытия. Доведите глубокую кастрюлю хорошо подсоленной воды до энергичного кипения вместе с остальными целыми специями и столовой ложкой масла, добавьте замоченный басмати и варите всего 4–5 минут, пока зёрна не удлинятся и не будут готовы примерно на три четверти — они дойдут на пару — затем быстро и аккуратно слейте. В той же сковороде поверх баранины распределите рис равномерно, посыпьте сверху оставшимся жареным луком, рубленой мятой и кинзой и зелёным перцем, затем медленными струями полейте шафрановое молоко по поверхности и розовую воду, если используете. Запечатайте крышку полоской влажного теста или плотной фольгой, поставьте на самый слабый огонь на 25–30 минут, затем выключите пламя, не поднимая крышку, и оставьте под печатью ещё 10 минут — сорвите печать за столом и погрузите длинную ложку до дна, поднимая прямо вверх, чтобы каждая порция вышла с рисом и мясом вместе, никогда не перемешанным.","en":"Heat the ghee and oil in a wide heavy pan over medium heat and fry the sliced onions slowly for 25–30 minutes, stirring often, until deeply golden brown (birista), then drain on paper, reserve the oil in the pan and keep half the onions for layering. Combine the lamb with the yoghurt, ginger-garlic paste, half of the fried onions crushed in your hand, chilli powder, turmeric, salt, lemon juice and a teaspoon of the shahi jeera, mix thoroughly and rest at least 2 hours or overnight in the fridge; tip the marinated lamb back into the reserved onion oil, add the cinnamon, cardamom, cloves and bay leaf, and cook covered over low heat for an hour to an hour and a quarter, until the lamb is tender and the gravy has reduced to a thick coating. Bring a deep pot of well-salted water to a rolling boil with the rest of the whole spices and a tablespoon of oil, add the soaked basmati and cook just 4–5 minutes until the grains have lengthened and are about three-quarters done — they finish in the steam — then drain quickly and gently. In the same pan over the lamb, spread the rice evenly, scatter the remaining fried onions, chopped mint and coriander, and the green chillies on top, then drizzle the saffron milk in slow streaks across the surface and the rose water if using. Seal the lid with a strip of wet dough or a tight wrap of foil, set on the lowest heat for 25–30 minutes, then turn off the flame without lifting the lid and rest sealed for another 10 minutes — break the seal at the table and plunge a long spoon to the bottom to lift straight up, so each portion comes out with both rice and meat, never stirred together."}},{"id":206,"servings":4,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":480,"prot":22,"carb":18,"fat":36,"fib":5},"origin":{"ru":"Индия","en":"India","ro":"India"},"name":{"ru":"Палак панир","en":"Palak Paneer","ro":"Palak Paneer"},"category":{"ru":"Карри","en":"Curry","ro":"Curry"},"ingredients":{"ru":["500 г свежего шпината (или 250 г замороженного, размороженного)","250 г панира, нарезанного кубиками 2 см","1 крупная луковица, мелко нарезанная","2 спелых помидора, нарезанных (или 200 г рубленых томатов)","3 зубчика чеснока и 2 см имбиря, измельчить вместе","2 зелёных перца чили","1 ч. л. семян зиры","1 ч. л. молотого кориандра, 1 ч. л. кашмирского перца, ½ ч. л. куркумы, 1 ч. л. гарам масала","1 ст. л. касури мети","80 мл жирных сливок, 3 ст. л. ги","Соль по вкусу","Маленький кусочек свежего имбиря соломкой для подачи"],"en":["500 g fresh spinach (or 250 g frozen, defrosted)","250 g paneer, cut into 2 cm cubes","1 large onion, finely chopped","2 ripe tomatoes, chopped (or 200 g chopped tomatoes)","3 garlic cloves and 2 cm piece of ginger, minced together","2 green chillies","1 tsp cumin seeds","1 tsp coriander powder, 1 tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp garam masala","1 tbsp kasoori methi (dried fenugreek leaves)","80 ml double cream, 3 tbsp ghee","Salt to taste","A small piece of fresh ginger, julienned, to finish"],"ro":["500 g spanac proaspăt (sau 250 g congelat, dezghețat)","250 g paneer, tăiat cuburi de 2 cm","1 ceapă mare, tocată mărunt","2 roșii coapte, tocate (sau 200 g roșii tocate)","3 căței de usturoi și o bucată de 2 cm de ghimbir, tocate împreună","2 ardei iuți verzi","1 linguriță semințe de chimion","1 linguriță coriandru pudră, 1 linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță garam masala","1 lingură kasoori methi (frunze uscate de schinduf)","80 ml smântână grasă, 3 linguri ghee","Sare după gust","O bucățică mică de ghimbir proaspăt, tăiată julien, pentru finisat"]},"howIsMade":{"ru":"Доведите большую кастрюлю воды до кипения, бланшируйте шпинат 90 секунд и сразу переложите в миску с ледяной водой, затем слейте, аккуратно отожмите и пюрируйте до гладкости вместе с одним из зелёных перцев и парой ложек холодной воды. Разогрейте столовую ложку ги в широкой сковороде и обжарьте кубики панира на среднем огне 2–3 минуты с каждой стороны до лёгкой золотистости, затем выложите на бумагу или опустите в миску с тёплой подсоленной водой, пока готовится остальное. В ту же сковороду добавьте оставшееся ги и семена зиры и дайте им подсиплеть 30 секунд, всыпьте лук и обжаривайте 8–10 минут до мягкости и золотистых краёв, затем добавьте пасту имбирь-чеснок и второй надрезанный зелёный перец и готовьте ещё минуту. Вмешайте нарезанный помидор с кориандром, чилийским порошком, куркумой и чайной ложкой соли и готовьте 6–8 минут, пока масала не станет джемообразной и масло не начнёт отделяться по краям, затем влейте пюре шпината и 100 мл воды, хорошо размешайте и потомите 5 минут на лёгком огне. Опустите кубики панира в соус, вмешайте сливки, разотрите касури мети между ладоней над сковородой и присыпьте гарам масалой, прогрейте ещё 2 минуты, попробуйте на соль, завершите имбирной соломкой сверху и подавайте с наном, паратхой или басмати.","en":"Bring a large pot of water to a boil, blanch the spinach for 90 seconds and transfer immediately to a bowl of ice water, then drain, squeeze gently and blend to a smooth purée with one of the green chillies and a few tablespoons of cold water. Heat a tablespoon of ghee in a wide pan and fry the paneer cubes over medium heat for 2–3 minutes per side until lightly gold, then lift onto paper or slip them into a bowl of warm salted water while everything else cooks. In the same pan add the remaining ghee and the cumin seeds and let them sizzle for 30 seconds, tip in the onion and cook 8–10 minutes until soft and golden at the edges, then add the ginger-garlic paste and the second slit green chilli and cook a minute more. Stir in the chopped tomato with the coriander, chilli powder, turmeric and a teaspoon of salt and cook 6–8 minutes until the masala is jammy and the oil starts to separate at the edges, then pour in the spinach purée and 100 ml of water, stir well and simmer gently for 5 minutes. Slide the paneer cubes into the gravy, swirl in the cream, crush the kasoori methi between your palms over the pan and sprinkle the garam masala, heat through for another 2 minutes, taste for salt, finish with julienned ginger on top, and serve with naan, paratha or basmati."}},{"id":207,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":620,"prot":40,"carb":12,"fat":44,"fib":2},"origin":{"ru":"Индия","en":"India","ro":"India"},"name":{"ru":"Роган джош","en":"Rogan Josh","ro":"Rogan Josh"},"category":{"ru":"Карри","en":"Curry","ro":"Curry"},"ingredients":{"ru":["1 кг баранины (лопатка или нога) на кости, нарезанной кусками по 4 см","4 ст. л. горчичного масла","200 г жирного йогурта, гладко взбитого","4 сушёных кашмирских красных перца, замочить 20 минут в тёплой воде и измельчить в пасту (или 2 ст. л. кашмирского перца в порошке)","1 ч. л. молотого фенхеля","1 ч. л. сушёного имбиря в порошке (сонт)","½ ч. л. асафетиды (хинг)","Целые специи: 8 коробочек зелёного кардамона + 2 чёрного, 1 палочка корицы, 6 гвоздик, 1 лавровый лист","1 ч. л. соли","Щепотка шафрана, настоянная в 2 ст. л. тёплого молока"],"en":["1 kg bone-in lamb shoulder or leg, cut into 4 cm pieces","4 tbsp mustard oil","200 g full-fat yoghurt, whisked smooth","4 dried Kashmiri red chillies, soaked in warm water 20 minutes and ground to a paste (or 2 tbsp Kashmiri chilli powder)","1 tsp fennel powder","1 tsp dried ginger powder (sonth)","½ tsp asafoetida (hing)","Whole spices: 8 green cardamom + 2 black cardamom, 1 cinnamon stick, 6 cloves, 1 bay leaf","1 tsp salt","A pinch of saffron, soaked in 2 tbsp warm milk"],"ro":["1 kg spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","4 linguri ulei de muștar","200 g iaurt gras, bătut neted","4 ardei roșii Kashmiri uscați, înmuiați 20 de minute în apă caldă și pisați pastă (sau 2 linguri boia Kashmiri)","1 linguriță pudră de fenicul","1 linguriță pudră de ghimbir uscat (sonth)","½ linguriță asafoetida (hing)","Mirodenii întregi: 8 capsule cardamom verde + 2 cardamom negru, 1 baton de scorțișoară, 6 cuișoare, 1 frunză de dafin","1 linguriță sare","Un vârf de șofran, infuzat în 2 linguri lapte cald"]},"howIsMade":{"ru":"Разогрейте горчичное масло в тяжёлой кастрюле, пока оно не начнёт чуть дымить, затем на мгновение снимите с огня — дымок нейтрализует жёсткость без пригорания — верните на средний огонь, добавьте целые специи и лавровый лист и дайте им ароматизировать масло 30 секунд. Добавьте баранину в один слой и хорошо подрумяньте со всех сторон 8–10 минут (это единственное обжаривание блюда, так что дайте цвету развиться по-настоящему), вмешайте асафетиду, имбирный и фенхельный порошок и дайте им обволочь мясо в горячем масле ещё минуту. Взбейте йогурт с кашмирской пастой и столовой ложкой холодной воды, затем добавляйте его в кастрюлю по половнику, непрерывно помешивая после каждого — медленно, йогурт не сворачивается — посолите, убавьте огонь и тушите под крышкой 10 минут, пока йогурт не растворится в глянцевую красную основу. Влейте 500 мл горячей воды, верните к лёгкому кипению, затем сделайте огонь минимальным и тушите под крышкой 1 час 20 минут, помешивая каждые 20 минут, пока ягнятина не станет уступать ложке, а соус — жидким, глянцевым и глубокого красного дерева; влейте шафрановое молоко за 5 минут до конца, лишь слегка вмешав. Дайте отдохнуть 10 минут вне огня перед подачей с басмати на пару — Роган джош должен быть почти как суп, ярко окрашенным и ароматным, а не острым, жар идёт от мяса, цвет — от перцев, аромат — от всего остального.","en":"Heat the mustard oil in a heavy pan until it just begins to smoke, then pull it off the heat for a moment — letting it smoke neutralises the raw pungency without scorching — and return to medium heat, add the whole spices and bay leaf, and let them perfume the oil for 30 seconds. Add the lamb in a single layer and brown well on all sides for 8–10 minutes (this is the only browning the dish gets, so let the colour develop properly), then stir in the asafoetida, ginger powder and fennel powder and let them coat the meat in the hot oil for another minute. Whisk the yoghurt with the Kashmiri chilli paste and a tablespoon of cold water, then add it to the pan a ladleful at a time stirring continuously after each addition — going slowly keeps the yoghurt from splitting — add the salt, lower the heat and cook covered for 10 minutes until the yoghurt has melted into a glossy red base. Pour in 500 ml of hot water, bring back to a simmer, then drop the heat to its lowest and braise covered for an hour and 20 minutes, stirring every 20 minutes, until the lamb yields to a spoon and the gravy is thin, glossy and a deep mahogany red; swirl the saffron milk through 5 minutes before the end without fully stirring it out. Rest off the heat for 10 minutes before serving with steamed basmati — Rogan Josh is meant to be soup-like, brilliantly coloured and aromatic rather than spicy hot, the heat supplied by the meat, the colour by the chillies, and the perfume by everything else."}},{"id":208,"servings":8,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":280,"prot":6,"carb":32,"fat":14,"fib":3},"origin":{"ru":"Индия","en":"India","ro":"India"},"name":{"ru":"Самоса","en":"Samosa","ro":"Samosa"},"category":{"ru":"Закуска","en":"Snack","ro":"Gustare"},"ingredients":{"ru":["Для теста: 300 г муки, 1 ч. л. семян аджвайна, ½ ч. л. соли, 60 мл ги или нейтрального масла, 120 мл холодной воды","Для начинки: 500 г рассыпчатого картофеля, 100 г замороженного зелёного горошка, 2 ст. л. нейтрального масла, 1 ч. л. семян зиры, 1 зелёный перец чили — измельчить, 2 см имбиря — измельчить","1 ч. л. молотого кориандра, 1 ч. л. гарам масала, ½ ч. л. кашмирского перца, ½ ч. л. куркумы, 1 ч. л. амчура (порошок сушёного манго), 1 ч. л. соли","Горсть свежей кинзы, нарубленной","Около 1 л нейтрального масла для фритюра","Для подачи: чатни из тамаринда и из мяты с кинзой"],"en":["For the pastry: 300 g plain flour, 1 tsp ajwain (carom) seeds, ½ tsp salt, 60 ml ghee or neutral oil, 120 ml cold water","For the filling: 500 g floury potatoes (Maris Piper or Russet), 100 g frozen peas, 2 tbsp neutral oil, 1 tsp cumin seeds, 1 green chilli minced, 2 cm piece of ginger minced","1 tsp coriander powder, 1 tsp garam masala, ½ tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp amchur (dried mango powder), 1 tsp salt","A handful of fresh coriander, chopped","About 1 L neutral oil for deep-frying","To serve: tamarind chutney and mint-coriander chutney"],"ro":["Pentru aluat: 300 g făină albă, 1 linguriță semințe de ajwain (chimen-aristotel), ½ linguriță sare, 60 ml ghee sau ulei neutru, 120 ml apă rece","Pentru umplutură: 500 g cartofi făinoși (Maris Piper sau Russet), 100 g mazăre congelată, 2 linguri ulei neutru, 1 linguriță semințe de chimion, 1 ardei iute verde tocat, 2 cm bucată de ghimbir tocat","1 linguriță coriandru pudră, 1 linguriță garam masala, ½ linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță amchur (pudră de mango uscat), 1 linguriță sare","Un mănunchi de coriandru proaspăt, tocat","Aproximativ 1 l ulei neutru pentru prăjit","Pentru servit: chutney de tamarind și chutney de mentă-coriandru"]},"howIsMade":{"ru":"Втирайте ги в муку, аджвайн и соль кончиками пальцев, пока смесь не станет похожа на грубую крошку — именно количество жира даёт оболочке самосы её пузырчатую, бисквитную хрусткость — добавляйте затем холодную воду по ложке, замешивая плотное гладкое тесто (мягче чапати, но плотнее хлебного) и оставьте под крышкой на 30 минут. Отварите картофель в кожуре до едва мягкости, слейте, очистите и крупно разомните вилкой (вам нужна текстура, а не пюре); разогрейте масло в широкой сковороде, добавьте семена зиры и дайте им подсиплеть, затем имбирь и зелёный перец на 30 секунд, вмешайте сухие специи и обжарьте коротко, добавьте картофель, горошек, соль, амчур и кинзу и готовьте 4–5 минут, переворачивая всё вместе, пока специи не покроют каждый кусок — остудите до комнатной температуры перед формовкой. Разделите тесто на 8 шаров, раскатайте один в тонкий овал длиной около 18 см и разрежьте поперёк пополам, две половинки; возьмите одну, проведите тонкую полоску воды по прямому краю и сверните в конус, соединив два угла прямого края с нахлёстом в 1 см, сильно прижмите шов для герметичности. Держите конус в одной руке, наполните его картофелем на три четверти, затем сложите открытый край маленькой складкой на одной стороне и запечатайте кромку влажным пальцем — эта складка создаёт характерное боковое ребро самосы и помогает ей стоять при жарке — повторите с остальными. Разогрейте масло до 150°C (ниже, чем ожидаешь, но именно медленный подъём даёт оболочке её пузыри), опускайте самосы партиями по 3–4 и жарьте 6–7 минут, аккуратно переворачивая, до бледно-золотистого, поднимите температуру до 180°C и жарьте ещё 3–4 минуты до глубокого золотистого и настоящей хрусткости, откиньте на решётку и подавайте горячими с тамариндовым и мятным чатни.","en":"Rub the ghee into the flour, ajwain and salt with your fingertips until the mixture resembles coarse breadcrumbs — the amount of fat is what gives samosa pastry its blistered, biscuit-crisp shell — then add the cold water a tablespoon at a time, mixing into a stiff smooth dough (softer than chapati but firmer than bread dough) and rest it covered for 30 minutes. Boil the potatoes in their skins until just tender, drain, peel and crush coarsely with the back of a fork (you want texture, not mash); heat the oil in a wide pan, add the cumin seeds and let them sizzle, then the ginger and green chilli for 30 seconds, stir in the dry spices and fry briefly, tip in the potato, peas, salt, amchur and coriander, and cook 4–5 minutes turning everything until the spices coat every piece — cool to room temperature before shaping. Divide the dough into 8 balls, roll one into a thin oval about 18 cm long and cut across the middle to make two half-circles; take one half, brush a thin line of water along the straight edge, and fold into a cone by bringing the two corners of the straight edge together so they overlap by 1 cm, pinching the seam tightly to seal. Hold the cone in one hand, fill it three-quarters with potato, then pleat the open edge by folding a small tuck on one side and sealing the rim shut with a damp finger — the tucked pleat creates the samosa's signature side ridge and helps it sit upright while cooking — and repeat with the rest. Heat the frying oil to 150°C (lower than you might expect, but the slow climb is what gives the shell its blisters), slip in the samosas in batches of 3 or 4 and fry 6–7 minutes turning gently until pale gold, then raise the heat to 180°C and fry another 3–4 minutes until deep golden and properly crisp, draining on a rack and serving hot with tamarind and mint chutneys."}},{"id":209,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":620,"prot":32,"carb":22,"fat":44,"fib":5},"origin":{"ru":"Таиланд","en":"Thailand","ro":"Thailanda"},"name":{"ru":"Зелёный карри (Gaeng Khiao Wan)","en":"Green Curry (Gaeng Khiao Wan)","ro":"Curry verde (Gaeng Khiao Wan)"},"category":{"ru":"Карри","en":"Curry","ro":"Curry"},"ingredients":{"ru":["4 ст. л. зелёной карри-пасты (домашней или хорошей тайской марки, например Mae Ploy)","400 мл жирного кокосового молока (идеален Aroy-D)","200 мл кокосовых сливок (плотный верхний слой из банки, или 100 мл плюс собранные сливки)","500 г куриных бёдер, нарезанных кусками по 3 см","4 тайских баклажана, разрезанных на четвертинки (или 1 небольшой азиатский кубиками)","Маленькая горсть гороховых баклажанов (в основном для украшения, по желанию)","100 г побегов бамбука, нарезанных","4 листа каффирского лайма, разорванных (без черешка)","2 длинных красных перца чили, тонкими косыми ломтиками","1 ст. л. пальмового сахара (или светлого коричневого)","2 ст. л. тайского рыбного соуса","Маленькая горсть листьев тайского базилика (хорапха)","Жасминовый рис для подачи"],"en":["4 tbsp green curry paste (homemade, or a good Thai brand like Mae Ploy)","400 ml full-fat coconut milk (Aroy-D is ideal)","200 ml coconut cream (the thick top layer from the can, or 100 ml plus the skimmed cream)","500 g chicken thighs, cut into 3 cm pieces","4 Thai eggplants, quartered (or 1 small Asian eggplant cubed)","A small handful of pea eggplants (mainly garnish, optional)","100 g bamboo shoots, sliced","4 kaffir lime leaves, torn (stem removed)","2 long red chillies, sliced thinly on the bias","1 tbsp palm sugar (or light brown sugar)","2 tbsp Thai fish sauce","A small handful of Thai basil leaves (horapha)","Jasmine rice to serve"],"ro":["4 linguri pastă curry verde (de casă sau o marcă thailandeză bună precum Mae Ploy)","400 ml lapte de cocos gras (ideal Aroy-D)","200 ml smântână de cocos (stratul gros de deasupra cutiei, sau 100 ml plus crema rămasă)","500 g pulpe de pui, tăiate în bucăți de 3 cm","4 vinete thailandeze, tăiate în sferturi (sau 1 vânătă asiatică mică, cuburi)","Un mic mănunchi de vinete-mazăre (în principal pentru garnitură, opțional)","100 g vârfuri de bambus, feliate","4 frunze de lămâi kaffir, rupte (codița înlăturată)","2 ardei roșii lungi, feliați subțire în diagonală","1 lingură zahăr de palmier (sau zahăr brun deschis)","2 linguri sos de pește thailandez","Un mic mănunchi de busuioc thailandez (horapha)","Orez iasomie pentru servit"]},"howIsMade":{"ru":"В воке или тяжёлой сковороде на среднем огне выложите кокосовые сливки и томите 4–5 минут, периодически помешивая, пока масло не отделится и сливки не приобретут жирный блеск — этот фундаментальный шаг и есть то, что отделяет ресторанный тайский зелёный карри от водянистой домашней версии. Добавьте зелёную карри-пасту в разделившиеся сливки и обжаривайте 2–3 минуты, непрерывно помешивая, пока паста не потемнеет, не выпустит аромат галангала, лемонграсса и тайского базилика, а масло не станет ярко-зелёным — кухня запахнет бангкокским переулком. Опустите курицу и переверните куски в пасте до покрытия, готовьте 3–4 минуты, пока мясо не побелеет наполовину, затем влейте кокосовое молоко и доведите до лёгкого кипения; добавьте баклажаны, побеги бамбука и порванные листья каффирского лайма и томите без крышки 10–12 минут, пока баклажаны не станут мягкими, а курица — едва прожаренной. Приправьте рыбным соусом и пальмовым сахаром, пробуя по ходу — карри должен бить одновременно солёным, сладким, травянистым и чистой зелёной чили-остротой — затем вмешайте красный перец и тайский базилик, качните сковороду один раз и снимите с огня через 30 секунд, чтобы базилик остался ярким в тарелке. Подавайте в неглубоких мисках с жасминовым рисом сбоку.","en":"In a wok or heavy pan over medium heat, spoon in the coconut cream and let it cook for 4–5 minutes, stirring occasionally, until the oil cracks out and the cream takes on a slick sheen — this foundation step is what separates Thai-restaurant green curry from the watery home version. Add the green curry paste to the split cream and fry for 2–3 minutes, stirring constantly, until the paste darkens, releases its perfume of galangal, lemongrass and Thai basil, and the oil turns a vivid green — the kitchen will smell like a Bangkok back street. Slide in the chicken and turn the pieces in the paste until coated, cook 3–4 minutes until the meat is half-sealed, then pour in the coconut milk and bring to a gentle simmer; add the eggplants, bamboo shoots and torn kaffir lime leaves, and simmer uncovered for 10–12 minutes until the eggplants are tender and the chicken is just cooked through. Season with the fish sauce and palm sugar, tasting as you go — the curry should hit salty, sweet, herbaceous and a clean green chilli heat all at once — then stir in the sliced red chillies and Thai basil, swirl the pan once and take it off the heat after 30 seconds so the basil stays bright in the bowl. Serve in shallow bowls with jasmine rice on the side."}},{"id":210,"servings":6,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":680,"prot":36,"carb":38,"fat":42,"fib":6},"origin":{"ru":"Таиланд","en":"Thailand","ro":"Thailanda"},"name":{"ru":"Карри массаман","en":"Massaman Curry","ro":"Massaman"},"category":{"ru":"Карри","en":"Curry","ro":"Curry"},"ingredients":{"ru":["4 ст. л. карри-пасты Массаман (Mae Ploy надёжен)","1 кг говяжьей голяшки или лопатки, нарезанной кубиками 5 см","800 мл жирного кокосового молока","200 мл кокосовых сливок","500 г восковидного картофеля (Charlotte или Yukon Gold), очищенного и нарезанного на куски 4 см","2 небольшие луковицы, очищенные и нарезанные на четвертинки","100 г обжаренного несолёного арахиса (несколько раздавить для подачи)","Целые специи: 5 коробочек кардамона, 1 палочка корицы, 4 гвоздики, 1 звёздочка бадьяна, 1 лавровый лист","3 ст. л. тамариндовой пасты (или сок 1 лайма как замена)","3 ст. л. пальмового сахара","3 ст. л. тайского рыбного соуса","4 листа каффирского лайма, разорванных","Жасминовый рис для подачи"],"en":["4 tbsp Massaman curry paste (Mae Ploy is reliable)","1 kg beef shin or chuck, cut into 5 cm cubes","800 ml full-fat coconut milk","200 ml coconut cream","500 g waxy potatoes (Charlotte or Yukon Gold), peeled and cut into 4 cm chunks","2 small onions, peeled and quartered","100 g roasted unsalted peanuts (a few crushed for garnish)","Whole spices: 5 cardamom pods, 1 cinnamon stick, 4 cloves, 1 star anise, 1 bay leaf","3 tbsp tamarind paste (or juice of 1 lime as a back-up)","3 tbsp palm sugar","3 tbsp Thai fish sauce","4 kaffir lime leaves, torn","Jasmine rice to serve"],"ro":["4 linguri pastă Massaman (Mae Ploy este o alegere sigură)","1 kg rasol sau pulpă de vită, tăiată în cuburi de 5 cm","800 ml lapte de cocos gras","200 ml smântână de cocos","500 g cartofi cu textură fermă (Charlotte sau Yukon Gold), curățați și tăiați în bucăți de 4 cm","2 cepe mici, curățate și tăiate în sferturi","100 g arahide prăjite nesărate (câteva zdrobite pentru ornat)","Mirodenii întregi: 5 capsule cardamom, 1 baton de scorțișoară, 4 cuișoare, 1 anason stelat, 1 frunză de dafin","3 linguri pastă de tamarind (sau zeama de la 1 lime de rezervă)","3 linguri zahăr de palmier","3 linguri sos de pește thailandez","4 frunze de lămâi kaffir, rupte","Orez iasomie pentru servit"]},"howIsMade":{"ru":"Положите кокосовые сливки в тяжёлую кастрюлю на среднем огне и томите 5 минут, помешивая, пока масло не отделится, а сливки не станут глянцевыми и слегка зернистыми. Добавьте пасту Массаман и целые специи и обжаривайте 3 минуты — паста потемнеет, а кухня запахнет корицей, кардамоном и поджаренной зирой; это раннее раскрытие специй и даёт Массаману его глубину персидского отзвука. Добавьте говядину и переверните её в пасте, пока каждый кусок не покроется тёмно-красным, влейте кокосовое молоко, тамариндовую пасту и листья каффирского лайма, доведите до едва заметного кипения и тушите с приоткрытой крышкой полтора часа, помешивая каждые 20 минут — говядина готова, когда легко поддаётся ложке, но ещё держит форму. Добавьте картофель, лук и арахис и продолжайте варить без крышки ещё 30 минут, пока картофель не станет мягким, а соус не загустеет до глянцевого насыщенно-коричневого; в конце вмешайте рыбный соус и пальмовый сахар, балансируя треугольник солёное-сладкое-кислое, пока вкус не станет глубоким и округлым, не слишком сладким и не слишком резким. Дайте отдохнуть 10 минут вне огня, затем подавайте в неглубоких мисках с жасминовым рисом, посыпав сверху раздавленным арахисом — Массаман это тайский карри, который за ночь набирает глубину, и остатки на следующий день вкуснее.","en":"Spoon the coconut cream into a heavy pot over medium heat and let it cook for 5 minutes, stirring, until the oil separates and the cream looks glossy and slightly grainy. Add the Massaman paste and the whole spices and fry for 3 minutes — the paste will darken and the kitchen should smell of cinnamon, cardamom and roasted cumin; this early bloom of the spices is what gives Massaman its Persian-inflected depth. Add the beef and turn it in the paste until every piece is dark red, pour in the coconut milk, tamarind paste and kaffir lime leaves, bring to a bare simmer and braise gently with the lid ajar for an hour and a half, stirring every 20 minutes — the beef is ready when it gives easily to a spoon but still holds its shape. Slide in the potatoes, onions and peanuts and continue cooking uncovered for another 30 minutes until the potatoes are tender and the gravy has thickened to a glossy rich brown; stir in the fish sauce and palm sugar at the end, balancing the salt-sweet-sour triangle until it tastes deep and round, neither too sweet nor too sharp. Rest off the heat for 10 minutes, then serve in shallow bowls with jasmine rice, scattered with a few crushed peanuts on top — Massaman is the Thai curry that gains depth overnight, and any leftovers taste better the next day."}},{"id":211,"servings":4,"tipType":"veg","pairingsType":"thai","nutrition":{"cal":180,"prot":6,"carb":28,"fat":6,"fib":4},"origin":{"ru":"Таиланд","en":"Thailand","ro":"Thailanda"},"name":{"ru":"Сом Там","en":"Som Tam","ro":"Som Tam"},"category":{"ru":"Салат","en":"Salad","ro":"Salată"},"ingredients":{"ru":["400 г зелёной (неспелой) папайи, очищенной и нарезанной очень тонкой соломкой","4 помидора черри, разрезанных пополам","2 длинных фасоли (yardlong) или 4 стручка зелёной фасоли, нарезанных кусочками по 4 см","2 зубчика чеснока, очищенных","2 перчика чили bird's eye (или по вкусу)","2 ст. л. пальмового сахара","2 ст. л. тайского рыбного соуса","Сок 1 лайма","1 ст. л. тамариндового концентрата","1 ст. л. сушёных креветок","2 ст. л. жареного арахиса (часть толчёного, часть целого)","Листья айсберга или капусты для подачи (по желанию, традиционно)"],"en":["400 g green (unripe) papaya, peeled and finely julienned","4 cherry tomatoes, halved","2 long beans (yardlong) or 4 green beans, cut into 4 cm lengths","2 garlic cloves, peeled","2 bird's eye chillies (or to taste)","2 tbsp palm sugar","2 tbsp Thai fish sauce","Juice of 1 lime","1 tbsp tamarind concentrate","1 tbsp dried shrimp","2 tbsp roasted peanuts (some crushed, some whole)","Iceberg lettuce or cabbage leaves to serve (optional, traditional)"],"ro":["400 g papaya verde (necoaptă), curățată și tăiată julienne foarte fin","4 roșii cherry, tăiate în jumătăți","2 fasole lungă (yardlong) sau 4 fire de fasole verde, tăiate în bucăți de 4 cm","2 căței de usturoi, curățați","2 ardei iuți bird's eye (sau după gust)","2 linguri zahăr de palmier","2 linguri sos de pește thailandez","Sucul de la 1 lime","1 lingură concentrat de tamarind","1 lingură creveți uscați","2 linguri arahide prăjite (unele zdrobite, altele întregi)","Frunze de salată iceberg sau varză pentru servit (opțional, tradițional)"]},"howIsMade":{"ru":"В глиняной ступке (krok) или прочной каменной разотрите чеснок и чили вместе до раскрытия, а не до пыли, затем добавьте пальмовый сахар и пробейте ещё несколько раз, чтобы он разошёлся в чилийном масле. Влейте рыбный соус, сок лайма и тамаринд, помешайте пестиком, чтобы растворить сахар, затем добавьте сушёные креветки и пробейте пару раз, расплющив их в заправке. Добавьте длинную фасоль и половинки помидоров и слегка постучите — по пять-шесть ударов на каждую часть, ровно столько, чтобы помять их и выпустить соки в заправку — пестик здесь инструмент приправы, а не разрушения. Введите тёртую папайю в два приёма, чередуя лёгкие удары пестика с перемешиванием ложкой, пока каждая полоска не заблестит от заправки, оставаясь хрустящей, затем добавьте арахис (целый для хруста, толчёный для тела) и переверните в последний раз. Попробуйте — Сом Там должен бить одновременно по четырём вкусам: кислому, солёному, сладкому и яростно-перечному — затем накладывайте горкой в неглубокие миски или на листья салата и ешьте сразу же с клейким рисом или жареной курицей.","en":"In a clay krok or sturdy stone mortar, pound the garlic and chillies together until bruised — not pulverised, just opened up — then add the palm sugar and pound a few more times to dissolve it into the chilli oil. Pour in the fish sauce, lime juice and tamarind, stir with the pestle until the sugar dissolves, then tip in the dried shrimp and pound a couple of times to flatten them into the dressing. Add the long beans and tomato halves and pound gently — five or six taps each, just enough to bruise them and release their juices into the dressing — the pestle here is a tool of seasoning, not destruction. Tip in the shredded papaya in two batches, alternating light pounding with turning everything with a spoon until each strand is glossy with the dressing but still crisp, then add the peanuts (whole for crunch, crushed for body) and toss one last time. Taste — Som Tam should hit four flavours at once: sour, salty, sweet and chilli-fierce — then pile into shallow bowls or onto lettuce leaves and eat immediately with sticky rice or grilled chicken."}},{"id":212,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":720,"prot":32,"carb":60,"fat":38,"fib":4},"origin":{"ru":"Таиланд","en":"Thailand","ro":"Thailanda"},"name":{"ru":"Кхао Сой","en":"Khao Soi","ro":"Khao Soi"},"category":{"ru":"Лапша в бульоне","en":"Noodle soup","ro":"Tăiței în supă"},"ingredients":{"ru":["4 ст. л. северо-тайской карри-пасты для кхао сой (или 3 ст. л. красной карри-пасты + 1 ч. л. порошка карри + 1 ч. л. молотой куркумы)","500 г куриных бёдер на кости или ножек, нарезанных кусками","800 мл жирного кокосового молока","200 мл кокосовых сливок","500 мл куриного бульона","2 ст. л. тайского рыбного соуса","1 ст. л. пальмового сахара","400 г свежей яичной лапши (или 300 г сухой)","Нейтральное масло для жарки горсти лапши во фритюре","Сок 2 лаймов, добавляется за столом","Гарниры: нарезанный шалот, маринованная горчичная зелень, свежая кинза, дольки лайма, чили-масло"],"en":["4 tbsp Northern Thai khao soi curry paste (or 3 tbsp red curry paste + 1 tsp curry powder + 1 tsp ground turmeric)","500 g bone-in chicken thighs or chicken legs cut into pieces","800 ml full-fat coconut milk","200 ml coconut cream","500 ml chicken stock","2 tbsp Thai fish sauce","1 tbsp palm sugar","400 g fresh egg noodles (or 300 g dried)","Neutral oil for deep-frying a handful of noodles","Juice of 2 limes, added at the table","Garnishes: sliced shallots, pickled mustard greens, fresh coriander, lime wedges, chilli oil"],"ro":["4 linguri pastă de curry Khao Soi din nordul Thailandei (sau 3 linguri pastă curry roșu + 1 linguriță curry pudră + 1 linguriță turmeric)","500 g pulpe de pui cu os sau pulpe întregi tăiate în bucăți","800 ml lapte de cocos gras","200 ml smântână de cocos","500 ml fond de pui","2 linguri sos de pește thailandez","1 lingură zahăr de palmier","400 g tăiței de ouă proaspeți (sau 300 g uscați)","Ulei neutru pentru a prăji o mână de tăiței","Sucul de la 2 lime, adăugat la masă","Garnituri: șalote feliate, frunze de muștar murate, coriandru proaspăt, felii de lime, ulei de chili"]},"howIsMade":{"ru":"Прогрейте кокосовые сливки в тяжёлой кастрюле на среднем огне 4–5 минут, пока масло не отделится, а сливки не станут глянцевыми, затем вмешайте пасту кхао сой и обжаривайте 2–3 минуты, пока она не потемнеет и не запахнет глубоко и поджаренно — тяжелее и землистее, чем у центрально-тайских карри, потому что эта паста опирается на сухие специи. Добавьте куски курицы и переворачивайте их в пасте, влейте кокосовое молоко и бульон, доведите до лёгкого кипения и варите с приоткрытой крышкой 30–35 минут, пока курица не станет совсем мягкой, а бульон чуть не уварится; к концу приправьте рыбным соусом и пальмовым сахаром, чтобы бульон был насыщенным, мягко сладким и чуть кислым от самой пасты карри. Пока карри томится, возьмите небольшую горсть свежей яичной лапши, стряхните излишек воды и обжарьте во фритюре при 180°C 30–45 секунд, до вздувшейся золотой хрусткости — это коронка для каждой тарелки — затем откиньте на бумагу. Остальную лапшу отварите в обычной воде до едва готовности, быстро слейте и разложите по глубоким мискам, сверху налейте горячий карри с хотя бы одним куском курицы на порцию и увенчайте жареной лапшой. Передавайте гарниры по столу — лук шалот, маринованную горчичную зелень, кинзу, дольку лайма, чтобы выжать в самом конце, и ложку чили-масла — блюдо живёт на контрасте (шёлковый бульон, мягкая лапша внизу, хрустящая лапша сверху, прикус сырого шалота, кислинка маринада, свет лайма) и каждая миска собирается прямо за столом.","en":"Heat the coconut cream in a heavy pot over medium heat for 4–5 minutes until the oil cracks out and the cream looks slick, then stir in the khao soi paste and fry for 2–3 minutes until it darkens and smells deeply toasted — heavier and earthier than central-Thai curries because the paste leans on dry spices. Add the chicken pieces and turn them in the paste until coated, pour in the coconut milk and stock, bring to a gentle simmer and cook with the lid ajar for 30–35 minutes until the chicken is meltingly tender and the broth has reduced a little; season with fish sauce and palm sugar towards the end so the broth is rich, gently sweet and faintly sour from the curry paste itself. While the curry simmers, take a small handful of the fresh egg noodles, shake off any excess water, and deep-fry in 180°C oil for 30–45 seconds until puffed and golden — the crispy crown for every bowl — then drain on paper. Boil the remaining noodles in plain water until just tender, drain quickly and divide between deep bowls, ladle over the hot curry with at least one piece of chicken per portion, and top with the fried noodles. Pass the garnishes round the table — sliced shallots, pickled mustard greens, coriander, a lime wedge to squeeze in last, and a spoon of chilli oil — the dish lives on contrast (silky soup, soft noodles below, crisp on top, raw shallot bite, pickle tang, lime brightness) and each bowl is built at the table."}},{"id":213,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":520,"prot":6,"carb":92,"fat":16,"fib":4},"origin":{"ru":"Таиланд","en":"Thailand","ro":"Thailanda"},"name":{"ru":"Клейкий рис с манго (Khao Niao Mamuang)","en":"Mango Sticky Rice (Khao Niao Mamuang)","ro":"Orez glutinos cu mango (Khao Niao Mamuang)"},"category":{"ru":"Десерт","en":"Dessert","ro":"Desert"},"ingredients":{"ru":["300 г тайского клейкого риса, замоченного в холодной воде минимум на 4 часа или на ночь","400 мл жирного кокосового молока","80 г пальмового сахара (или светлого коричневого)","½ ч. л. соли","1 лист пандана, завязанный узлом (по желанию, традиционно)","2 спелых жёлтых манго (Nam Dok Mai или Ataulfo), очищенных и нарезанных","2 ст. л. жареных семян кунжута или лущёного маша для подачи","1 ч. л. рисовой муки (по желанию, для загущения солёной заливки)"],"en":["300 g Thai glutinous (sticky) rice, soaked in cold water at least 4 hours or overnight","400 ml full-fat coconut milk","80 g palm sugar (or light brown sugar)","½ tsp salt","1 pandan leaf, tied in a knot (optional, traditional)","2 ripe yellow mangoes (Nam Dok Mai or Ataulfo), peeled and sliced","2 tbsp toasted sesame seeds or split mung beans, for garnish","1 tsp rice flour (optional, for thickening the salty topping)"],"ro":["300 g orez glutinos thailandez (lipicios), pus la înmuiat în apă rece minim 4 ore sau peste noapte","400 ml lapte de cocos gras","80 g zahăr de palmier (sau zahăr brun deschis)","½ linguriță sare","1 frunză de pandan, legată în nod (opțional, tradițional)","2 mango galbene coapte (Nam Dok Mai sau Ataulfo), curățate și feliate","2 linguri semințe de susan prăjite sau mazăre mungo decorticată, pentru garnitură","1 linguriță făină de orez (opțional, pentru a îngroșa topping-ul sărat)"]},"howIsMade":{"ru":"Слейте воду с замоченного риса; выстелите пароварку марлей или банановым листом, всыпьте рис и варите под крышкой над умеренно кипящей водой 20–25 минут, на середине времени поднимая ткань, чтобы перевернуть рисовую гору и она пропарилась равномерно — готово, когда зёрна полупрозрачные, блестящие и упруго-нежные насквозь. Пока рис варится, нагрейте 300 мл кокосового молока в небольшой кастрюле с пальмовым сахаром, солью и листом пандана, помешивая ровно столько, чтобы растворить сахар и не довести до кипения; оставшиеся 100 мл оставьте для солёной заливки. Когда рис будет горячим из пароварки, переложите его в широкую миску, лопаткой вмешайте две трети тёплого сладкого кокосового молока, пока каждое зёрнышко не заблестит, затем накройте и оставьте на 15–20 минут, чтобы рис впитал молоко и набух до консистенции мягкого жемчужного пудинга. Для солёной заливки потомите оставшиеся 100 мл кокосового молока с щедрой щепоткой соли и чайной ложкой рисовой муки 2 минуты, пока заливка слегка не загустеет. Выложите тёплый кокосовый рис горкой на тарелку с ломтиками манго рядом, полейте сверху солёным кокосовым кремом, посыпьте жареным кунжутом или лущёным машем и ешьте ложкой, по немного риса и манго в каждый кусок — контраст тёплой кокосовой сладости и прохладного резкого фрукта и есть это блюдо.","en":"Drain the soaked rice; line a steamer basket with cheesecloth or banana leaf, tip in the rice and steam covered over a moderate boil for 20–25 minutes, lifting the cloth halfway to flip the mound so it cooks evenly — done when the grains are translucent, glossy and chewy-tender all the way through. While the rice steams, warm 300 ml of the coconut milk in a small saucepan with the palm sugar, salt and pandan leaf, stirring just enough to dissolve the sugar without bringing it to a boil; reserve the remaining 100 ml for the salty topping. When the rice comes hot off the steamer, tip it into a wide bowl, fold through two-thirds of the warm sweet coconut milk with a spatula until each grain glistens, then cover and rest 15–20 minutes so the rice drinks the milk and swells to a soft pearl-pudding consistency. For the salty topping, simmer the remaining 100 ml coconut milk with a generous pinch of salt and the teaspoon of rice flour for 2 minutes, just until it thickens lightly. Mound the warm coconut rice on a plate with the mango slices alongside, drizzle the salty coconut cream across the top, scatter toasted sesame seeds or split mung beans, and eat with a spoon, a little rice and a little mango in every bite — warm coconut-sweet against cool fruit-sharp is the dish itself."}},{"id":214,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Международное","en":"International","ro":"Internațional"},"name":{"ru":"Тушёная баранина","en":"Lamb Stew","ro":"Tocăniță de miel"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["800 г бараньей лопатки, кубиками","2 луковицы","3 моркови","3 картофелины","2 зубчика чеснока","2 ст. л. томатной пасты","500 мл говяжьего бульона","тимьян, лавровый лист","соль, перец, оливковое масло"],"en":["800 g lamb shoulder, cubed","2 onions","3 carrots","3 potatoes","2 garlic cloves","2 tbsp tomato paste","500 ml beef stock","thyme, bay leaf","salt, pepper, olive oil"],"ro":["800 g pulpă de miel, cuburi","2 cepe","3 morcovi","3 cartofi","2 căței usturoi","2 linguri pastă de tomate","500 ml supă de carne","frunze de cimbru, dafin","sare, piper, ulei de măsline"]},"howIsMade":{"ru":"Нарежьте лопатку ягнёнка кубиками примерно по 4 см — достаточно крупными, чтобы они остались нежными после долгой тушки и не развалились. Полностью обсушите, щедро посолите, поперчите и совсем легко обваляйте в муке, чтобы соус загустел. Раскалите тяжёлую чугунную кастрюлю с тонкой плёнкой масла до мерцания и обжарьте баранину тремя-четырьмя порциями, не перегружая — иначе мясо парится и теряет корочку. Каждую порцию выкладывайте на тарелку. В том же жире обжарьте мелко нарезанный лук и чеснок до прозрачности, добавьте томатную пасту и прогрейте минуту, пока её аромат не округлится. Верните мясо с соком, влейте горячий бульон, чтобы едва покрыть, добавьте несколько веточек тимьяна и лавровый лист, доведите до тихого кипения и убавьте огонь до самого малого. Накройте и тушите девяносто минут — не давайте бурлить, только мягко булькать — помешав один раз. Добавьте морковь по диагонали и восковой картофель крупными кусками и готовьте ещё тридцать-сорок минут, пока баранина не будет распадаться от прикосновения вилки, а картофель не сохранит форму. Попробуйте, подсолите при необходимости, выньте лавр. Подавайте в глубоких тарелках с хрустящим хлебом, дав тушёному отдохнуть десять минут вне огня, чтобы бульон собрался.","en":"Cut the lamb shoulder into roughly 4 cm cubes — large enough to stay tender through a long simmer without falling apart. Pat them completely dry and season generously with salt and pepper, then dust very lightly with flour to help the sauce thicken. Heat a heavy casserole or Dutch oven with a film of oil until it shimmers, and brown the lamb in three or four batches without crowding the pan — crowding steams the meat and you lose the deep crust. Set each batch aside on a plate. In the same fat, sweat finely chopped onion and garlic until translucent, then stir in tomato paste and let it cook a minute until it smells rounder. Return the lamb with any resting juices, pour in enough hot stock to just cover, add a few sprigs of thyme and a bay leaf, bring to a gentle simmer and lower the heat to the smallest possible. Cover and cook for ninety minutes — never let it boil, only bubble — stirring once. Add carrots cut on the bias and waxy potatoes in large chunks and cook another thirty to forty minutes, until the lamb pulls apart at the touch of a fork and the potatoes hold their shape. Taste, adjust salt, and lift out the bay. Serve in deep bowls with crusty bread, after letting the stew rest off the heat for ten minutes so the broth pulls together."}},{"id":215,"tipType":"salad","pairingsType":"salad","origin":{"ru":"Греция","en":"Greece","ro":"Grecia"},"name":{"ru":"Греческий салат","en":"Greek Salad","ro":"Salată grecească"},"category":{"ru":"Салат","en":"Salad","ro":"Salate"},"ingredients":{"ru":["4 спелых помидора, толстыми ломтиками","1 крупный огурец, ломтиками","1 зелёный перец","1 красная луковица, тонкими кольцами","200 г феты бруском","100 г маслин Каламата","2 ст. л. оливкового масла экстра вирджин","1 ч. л. сушёного греческого орегано","крупная соль"],"en":["4 ripe tomatoes, thickly sliced","1 large cucumber, sliced","1 green pepper","1 red onion, thinly ringed","200 g block feta","100 g Kalamata olives","2 tbsp extra-virgin olive oil","1 tsp dried Greek oregano","coarse salt"],"ro":["4 roșii coapte, tăiate felii groase","1 castravete mare, tăiat felii","1 ardei verde","1 ceapă roșie, tăiată rondele subțiri","200 g feta în bloc","100 g măsline Kalamata","2 linguri ulei de măsline extravirgin","1 linguriță oregano grecesc uscat","sare grunjoasă"]},"howIsMade":{"ru":"Нарежьте спелые помидоры толсто — не тоньше пальца — дольками или кружками, чтобы они держали сок, а не превращались в пюре. Огурец полумесяцами, зелёный перец тонкими кольцами, красный лук как можно тоньше; если он острый, опустите кольца на десять минут в ледяную воду, чтобы смягчить резкость, сохранив хруст. Сложите всё в широкую низкую миску с щепоткой крупной соли и не перемешивайте — греки собирают этот салат слоями, никогда не размешанным. Рассыпьте маслины Каламата целиком, с косточками. Положите фету сверху одним целым куском, точно как подают в критской таверне. Полейте щедро оливковым маслом extra virgin, затем посыпьте сухим орегано, растёртым между ладонями для аромата. Подавайте сразу, с хрустящим хлебом, чтобы вымакивать сок.","en":"Slice ripe tomatoes thick — at least a finger across — into wedges or rounds, so they hold their juice rather than collapse into purée. Cut the cucumber into half-moons, the green pepper into thin rings, and the red onion paper-thin; if sharp, soak the rings in iced water for ten minutes to soften the bite while keeping the crunch. Combine in a wide, shallow bowl with a pinch of coarse salt and resist tossing — Greeks build this salad in layers, never mixed. Scatter the Kalamata olives whole, with their stones. Lay the feta on top as a single uncut slab, exactly as you'd be served in a Cretan taverna. Drizzle generously with extra-virgin olive oil, then shower with dried oregano rubbed between your palms to release the aroma. Serve immediately with crusty bread for mopping the juices."}},{"id":216,"tipType":"salad","pairingsType":"italian","origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Капрезе","en":"Caprese Salad","ro":"Salată Caprese"},"category":{"ru":"Салат","en":"Salad","ro":"Salate"},"ingredients":{"ru":["3 спелых помидора, кружочками","250 г моцареллы из буйволиного молока","свежий базилик","оливковое масло экстра вирджин","крупная соль","свежемолотый чёрный перец","бальзамический уксус (по желанию)"],"en":["3 ripe tomatoes, sliced","250 g buffalo mozzarella","fresh basil leaves","extra-virgin olive oil","coarse salt","freshly ground black pepper","balsamic vinegar (optional)"],"ro":["3 roșii coapte, tăiate felii","250 g mozzarella di bufala","frunze de busuioc proaspăt","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt măcinat","oțet balsamic (opțional)"]},"howIsMade":{"ru":"Достаньте моцареллу из холодильника минимум за тридцать минут — холодная теряет кремовость, вкус остаётся плоским. Выбирайте спелые, ароматные помидоры — от Cuore di Bue до коктейльных на ветке, — лишь бы пахли летом, — и нарежьте их кружками толщиной около сантиметра. Моцареллу нарежьте ломтиками той же толщины. На большой плоской тарелке выложите чередующимися рядами кружок помидора и ломтик моцареллы, слегка нахлёстывая, и между каждой парой положите целый лист базилика, чтобы зелень была видна. Полейте оливковым маслом extra virgin так, чтобы оно собиралось у основания, приправьте несколькими хлопьями морской соли и поворотом мельницы свежемолотого чёрного перца. Подавайте сразу при комнатной температуре, с хрустящим хлебом. Пуристы отвергают бальзамик — Капрезе родилась без него и работает лучше всего именно так.","en":"Take the mozzarella out of the fridge at least thirty minutes before serving — fridge-cold it loses its creaminess and the flavour stays flat. Choose ripe, fragrant tomatoes — anything from Cuore di Bue to cherries on the vine, as long as they smell of summer — and slice them about a centimetre thick. Cut the mozzarella into slices of the same thickness. On a large flat plate, alternate one slice of tomato with one of mozzarella in a single, slightly overlapping row, tucking a whole basil leaf between each pair so the green shows. Drizzle with extra-virgin olive oil until it pools at the base, season with a few flakes of sea salt and a turn of freshly cracked black pepper. Serve immediately at room temperature, with crusty bread. Purists refuse balsamic vinegar — Caprese was born without it and works best that way."}},{"id":217,"tipType":"pasta","pairingsType":"italian","origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Лазанья","en":"Lasagna","ro":"Lasagna"},"category":{"ru":"Паста","en":"Pasta","ro":"Paste"},"ingredients":{"ru":["300 г листов лазаньи","500 г говяжьего фарша","1 луковица","2 зубчика чеснока","400 г томатного соуса","300 мл соуса бешамель","150 г тёртого Пармиджано","150 г моцареллы","соль, перец, оливковое масло"],"en":["300 g lasagna sheets","500 g beef mince","1 onion","2 garlic cloves","400 g tomato sauce","300 ml béchamel sauce","150 g Parmigiano grated","150 g mozzarella","salt, pepper, olive oil"],"ro":["300 g foi de lasagna","500 g vită tocată","1 ceapă","2 căței usturoi","400 g sos de roșii","300 ml sos béchamel","150 g Parmigiano ras","150 g mozzarella","sare, piper, ulei de măsline"]},"howIsMade":{"ru":"Начните с рагу: на оливковом масле и кусочке сливочного масла десять минут томите мелко нарезанные лук, морковь и сельдерей — soffritto это основа всего вкуса. Прибавьте огонь, добавьте говяжий фарш и хорошо обжарьте, разбивая обратной стороной ложки. Влейте бокал красного вина и дайте выпариться, затем добавьте томатное пассата, щепотку соли и натёртой мускатного ореха. Тушите без крышки на самом малом огне минимум час — два, если есть время — иногда помешивая. Параллельно сделайте бешамель: растопите масло, всыпьте муку, прогрейте минуту, затем постепенно вливайте тёплое молоко, взбивая венчиком до гладкой густой массы; посолите и приправьте мускатом. Разогрейте духовку до 180°C. На дно глубокой формы выложите тонкий слой бешамели, чтобы паста не прилипала, и собирайте слои в таком порядке: листы теста, рагу, бешамель, щедрая стружка пармезана. Повторите минимум пять слоёв, заканчивая бешамелью и финальным дождём пармезана. Запекайте 35–40 минут, пока верх не станет золотистым, а края не запузырятся. Перед нарезкой обязательно дайте отдохнуть пятнадцать минут — иначе слои поедут.","en":"Start with the ragù: gently soften finely chopped onion, carrot and celery in olive oil and a knob of butter for ten minutes — the soffritto is the base of all the flavour. Raise the heat, add the minced beef and brown it deeply, breaking it up with the back of a spoon. Pour in a glass of red wine and let it evaporate, then add the tomato passata, a pinch of salt and a grating of nutmeg. Cook uncovered on the lowest flame for at least one hour — two if you have time — stirring every so often. Meanwhile, make the béchamel: melt butter, whisk in flour, cook a minute, then gradually pour in warm milk while whisking until smooth and thickened; season with salt and a touch of nutmeg. Heat the oven to 180°C. Spoon a thin layer of béchamel into the base of a deep dish to prevent sticking, then layer in this order: pasta sheets, ragù, béchamel, a generous grating of Parmigiano. Repeat for at least five layers, ending with béchamel and a final shower of Parmigiano. Bake 35–40 minutes until the top is golden and the edges bubble. Rest fifteen minutes before cutting — this is non-negotiable, or the layers slide."}},{"id":218,"tipType":"salad","pairingsType":"salad","origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Салат нисуаз","en":"Salade Niçoise","ro":"Salată Niçoise"},"category":{"ru":"Салат","en":"Salad","ro":"Salate"},"ingredients":{"ru":["200 г консервированного тунца в масле","4 яйца вкрутую","200 г зелёной фасоли","300 г молодого картофеля","12 маслин Niçoise","4 филе анчоусов","2 помидора","2 ст. л. оливкового масла","винный уксус, соль, перец"],"en":["200 g tinned tuna in oil","4 hard-boiled eggs","200 g green beans","300 g new potatoes","12 Niçoise olives","4 anchovy fillets","2 tomatoes","2 tbsp olive oil","wine vinegar, salt, pepper"],"ro":["200 g ton la conservă în ulei","4 ouă fierte tari","200 g fasole verde","300 g cartofi noi","12 măsline Niçoise","4 file de hamsii","2 roșii","2 linguri ulei de măsline","oțet de vin, sare, piper"]},"howIsMade":{"ru":"Сварите яйца восемь минут от холодной воды, затем сразу опустите в ледяную воду, чтобы остановить варку и оставить желток едва схватившимся. Молодой картофель отварите целиком в подсоленной воде, пока кончик ножа не войдёт без сопротивления, около пятнадцати минут, и разрежьте пополам ещё тёплым, чтобы он впитал заправку. Зелёную фасоль бланшируйте три минуты в большом количестве кипящей подсоленной воды, затем остудите в ледяной воде, чтобы она осталась хрустящей и ярко-зелёной. На широкой плоской тарелке выложите подушку из листьев и расположите всё группами, не перемешивая — яйца четвертинками, половинки картофеля, фасоль, дольки помидоров, тунец кусочками, маслины, филе анчоусов крест-накрест сверху. Взбейте оливковое масло с каплей винного уксуса, приправьте и полейте салат непосредственно перед подачей. На стол прохладным, но не ледяным.","en":"Boil the eggs eight minutes from cold, then plunge straight into iced water to stop the cooking and keep the yolk just set. Cook the new potatoes whole in salted water until a knife tip slides in cleanly, around fifteen minutes, then halve them while still warm so they soak up the dressing. Blanch the green beans for three minutes in plenty of boiling salted water, then refresh in iced water so they stay snappy and bright. On a wide, flat plate, lay a bed of greens and arrange everything in groups rather than tossing — quartered eggs, potato halves, beans, tomato wedges, the tuna broken into chunks, olives, anchovy fillets draped across the top. Whisk olive oil with a splash of wine vinegar, season, and spoon over only just before serving. Bring to the table cool, not fridge-cold."}},{"id":219,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Россия","en":"Russia","ro":"Rusia"},"name":{"ru":"Бефстроганов","en":"Beef Stroganoff","ro":"Boeuf Stroganoff"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["600 г говяжьей вырезки, нарезанной полосками","300 г шампиньонов","1 луковица","2 зубчика чеснока","200 мл сметаны","2 ст. л. горчицы","200 мл говяжьего бульона","2 ст. л. сливочного масла","соль, перец, петрушка"],"en":["600 g beef tenderloin, sliced into strips","300 g button mushrooms","1 onion","2 garlic cloves","200 ml sour cream","2 tbsp mustard","200 ml beef stock","2 tbsp butter","salt, pepper, parsley"],"ro":["600 g mușchi de vită, tăiat fâșii","300 g ciuperci champignon","1 ceapă","2 căței usturoi","200 ml smântână","2 linguri muștar","200 ml supă de vită","2 linguri unt","sare, piper, pătrunjel"]},"howIsMade":{"ru":"Нарежьте говяжью вырезку поперёк волокон полосками не толще карандаша — более толстые куски останутся жёсткими за короткое время готовки. Полностью обсушите, посолите, поперчите и слегка обваляйте в муке. Раскалите широкую сковороду очень сильно, добавьте кусочек масла с растительным и обжарьте мясо в два-три захода, не перегружая сковороду — по тридцать секунд с каждой стороны, до коричневой корочки снаружи и розового внутри. Переложите на тарелку и дайте отдохнуть. В той же сковороде убавьте огонь, спассеруйте тонко нарезанный лук на масле, добавьте грибы и дайте им хорошо подрумяниться, не перемешивая первые три минуты. Влейте говяжий бульон и каплю коньяка, если есть, соскоблите все румяные следы со дна и уварите наполовину. Снимите сковороду полностью с огня — критический шаг — и вмешайте сметану с горчицей до гладкости; если закипит сейчас, сметана свернётся. Верните мясо и его сок, прогрейте, проверьте на соль, посыпьте рубленой петрушкой. Подавайте сразу на лапше с маслом, пюре или паровом рисе.","en":"Cut the beef tenderloin into strips against the grain, no thicker than a pencil — thicker pieces stay tough in the short cook time. Pat them completely dry, season with salt and pepper, then dust lightly with flour. Heat a wide pan very hot, add a knob of butter and oil, and sear the beef in two or three batches without crowding the pan, just thirty seconds a side, until browned outside and still pink within. Lift onto a plate and rest. In the same pan, lower the heat and soften finely sliced onion in butter, then add the mushrooms and let them brown deeply without stirring for the first three minutes. Pour in the beef stock and a splash of brandy if you have it, scrape up every brown bit from the base, and reduce by half. Take the pan completely off the heat — the critical step — and stir in the sour cream and the mustard until smooth; if it boils now, the cream splits. Return the beef and any resting juices to the pan, swirl through to warm, taste for salt, and shower with chopped parsley. Serve immediately over buttered noodles, mash, or steamed rice."}},{"id":222,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Кок-о-вэн","en":"Coq au Vin","ro":"Coq au vin"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1 целая курица, разделанная на 8 частей","200 г панчетты или бекона","250 г шампиньонов","200 г жемчужного лука","1 бутылка красного бургундского вина","2 зубчика чеснока","2 моркови","тимьян, лавровый лист","сливочное масло, мука, соль, перец, петрушка"],"en":["1 whole chicken, cut into 8 pieces","200 g pancetta or bacon","250 g button mushrooms","200 g pearl onions","1 bottle red Burgundy wine","2 garlic cloves","2 carrots","thyme, bay leaf","butter, flour, salt, pepper, parsley"],"ro":["1 pui întreg, tăiat în 8 bucăți","200 g pancetta sau bacon","250 g ciuperci champignon","200 g ceapă mică","1 sticlă vin roșu Burgundia","2 căței usturoi","2 morcovi","cimbru, dafin","unt, făină, sare, piper, pătrunjel"]},"howIsMade":{"ru":"Накануне разделайте курицу на восемь частей и погрузите в красное бургундское с лавром, тимьяном, разрезанной пополам луковицей и несколькими горошинами перца; накройте и оставьте в холодильнике на ночь, чтобы вино проникло в мясо, а маринад впитал аромат птицы. На следующий день выньте курицу и тщательно обсушите каждую часть — мокрая кожа не подрумянится, это здесь смертный грех. Маринад сохраните. В тяжёлой чугунной кастрюле вытопите нарезанную панчетту до хрусткости; снимите её и подрумяньте курицу в этом жире двумя порциями, начиная кожей вниз, до цвета красного дерева. Отложите. В той же кастрюле спассеруйте мелко нарезанный лук, чеснок и морковь, посыпьте столовой ложкой муки с горкой, помешайте минуту, затем влейте сохранённый маринад и половник тёмного куриного бульона, соскребая со дна каждый румяный след. Верните курицу и панчетту, доведите до тихого кипения, накройте и томите на самом малом огне — или в духовке при 160°C — шестьдесят минут, пока мясо не станет нежным, но всё ещё держится за кость. Пока тушится, отдельно обжарьте жемчужный лук в масле до янтарного цвета, а грибы в другой сковороде до глубокой румяности — никогда вместе, иначе они парят друг друга. Добавьте оба в кастрюлю за последние пятнадцать минут, посолите по вкусу, в конце снимите с огня и вмешайте кусочек холодного сливочного масла, посыпьте петрушкой. Подавайте с картофельным пюре или лапшой с маслом, чтобы поймать каждую каплю соуса.","en":"The night before, joint the chicken into eight pieces and submerge in red Burgundy with bay, thyme, a halved onion and a few peppercorns; cover and refrigerate overnight so the wine penetrates the flesh and the marinade takes on the bird's perfume. Next day, lift the chicken out and pat each piece bone-dry — wet skin will not brown, which is the cardinal sin here. Reserve the marinade. In a heavy cast-iron pot, render diced pancetta until crisp; lift it out and brown the chicken in the rendered fat in two batches, skin-side first, until each piece is mahogany. Set aside. In the same pot, sweat finely chopped onion, garlic and carrot, scatter a heaped spoonful of flour over and stir for a minute, then pour in the reserved marinade and a ladle of dark chicken stock, scraping every brown trace from the bottom. Return the chicken and pancetta, bring to a gentle simmer, cover and cook on the lowest flame — or in a 160°C oven — for sixty minutes, until the meat is tender but still clings to the bone. While it cooks, sauté the pearl onions in butter until amber and the mushrooms in a separate pan until deeply browned — never together, or they steam each other. Slip both into the pot for the last fifteen minutes, taste for salt, finish with a knob of cold butter swirled in off the heat and a shower of parsley. Serve with mashed potato or buttered noodles to catch every drop of sauce."}},{"id":223,"tipType":"meat","pairingsType":"meat","origin":{"ru":"Польша","en":"Poland","ro":"Polonia"},"name":{"ru":"Бигос","en":"Bigos","ro":"Bigos"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["500 г квашеной капусты, отжатой","300 г свежей капусты, нашинкованной","400 г свиной лопатки, кубиками","200 г копчёной колбасы (кельбаса)","150 г бекона","1 луковица","2 зубчика чеснока","3 чернослива","душистый перец, лавровый лист, паприка, соль, перец"],"en":["500 g sauerkraut, drained","300 g fresh cabbage, shredded","400 g pork shoulder, cubed","200 g smoked sausage (kielbasa)","150 g bacon","1 onion","2 garlic cloves","3 dried prunes","allspice, bay leaf, paprika, salt, pepper"],"ro":["500 g varză murată, scurtă","300 g varză proaspătă, tăiată","400 g porc (umăr), cuburi","200 g cârnați afumați (kielbasa)","150 g bacon","1 ceapă","2 căței usturoi","3 prune uscate","ienibahar, dafin, boia, sare, piper"]},"howIsMade":{"ru":"Бигос строится слоями — у каждого польского повара свой порядок, но принцип один: терпение. В тяжёлой кастрюле на среднем огне вытопите нарезанный кубиками бекон, пока жир не потечёт, а кусочки не подрумянятся; снимите и отложите. Обжарьте свиную лопатку кубиками в этом жире двумя порциями, не перегружая, до глубокого золотистого цвета и тоже снимите. В том же жире спассеруйте мелко нарезанный лук с чесноком, верните мясо вместе с беконом. Слейте и быстро ополосните квашеную капусту, если очень кислая, и добавьте её вместе с тонко нашинкованной свежей капустой, нарезанной кёлбасой, черносливом без косточек, несколькими лавровыми листьями, раздавленными в ладони ягодами можжевельника, душистым перцем и сладкой паприкой. Залейте водой так, чтобы едва покрыть, доведите до тихого кипения, убавьте до минимума, накройте и забудьте о кастрюле на два-три часа, перемешивая каждые полчаса и притапливая капусту в отвар. В конце поправьте на соль. Честный секрет бигоса: остудите его на ночь в холодильнике, а наутро медленно прогрейте — ароматы поженятся, копчёность углубится, бульон сгустится.","en":"Bigos is built in layers — every cook in Poland has their own order, but the principle is patience. In a heavy pot, render diced bacon over medium heat until the fat runs and the pieces crisp, then lift them out and reserve. Brown the cubed pork shoulder in the bacon fat in two batches without crowding, until each side is deeply golden, and remove. Soften finely chopped onion and garlic in the same fat, then return the meat with the bacon. Drain and rinse the sauerkraut briefly if very sour, and pile it in with the shredded fresh cabbage, the sliced kielbasa, the pitted prunes, a few bay leaves, several juniper berries crushed in the palm, allspice and sweet paprika. Pour in just enough water to barely cover, bring to a gentle simmer, then lower the heat right down, cover, and forget about it for two to three hours, stirring every half hour and pushing the cabbage down into the liquor. Taste and adjust salt at the end. The honest secret of bigos: cool it overnight in the fridge, then warm slowly the next day — the flavours marry, the smoke deepens, the broth concentrates."}},{"id":226,"tipType":"asian","pairingsType":"asian","origin":{"ru":"Вьетнам","en":"Vietnam","ro":"Vietnam"},"name":{"ru":"Вьетнамские свежие роллы","en":"Vietnamese Spring Rolls","ro":"Rulouri vietnameze proaspete"},"category":{"ru":"Обед","en":"Lunch","ro":"Prânz"},"ingredients":{"ru":["12 листов рисовой бумаги (bánh tráng)","200 г варёных очищенных креветок","200 г варёной свиной грудинки, ломтиками","100 г варёной рисовой вермишели","1 огурец","листья салата","свежая мята","свежая кинза","соус хойсин или nước chấm для соуса"],"en":["12 rice paper wrappers (bánh tráng)","200 g cooked prawns, peeled","200 g cooked pork belly, sliced","100 g cooked rice vermicelli","1 cucumber","lettuce leaves","fresh mint leaves","fresh coriander leaves","hoisin or nước chấm sauce for dipping"],"ro":["12 foi de orez (bánh tráng)","200 g creveți fierți, decojiți","200 g piept de porc fiert, feliat","100 g tăiței de orez fierți","1 castravete","frunze de salată","frunze de mentă proaspătă","frunze de coriandru","sos hoisin sau nước chấm pentru servit"]},"howIsMade":{"ru":"Подготовьте всё до того, как начнёте крутить — как только начнёте, остановиться нельзя. Сварите рисовую вермишель по пакету, ополосните под холодной водой до полного остывания и хорошо обсушите. Нарежьте варёную грудинку тонкими ломтиками; разрежьте варёные креветки вдоль так, чтобы розовая сторона смотрела на лист — красивее. Огурец нарежьте тонкой соломкой. Соберите травы, листья салата без черешков, лапшу, огурец и белок на поднос под рукой. Налейте в неглубокую миску тёплой — не горячей — воды. Окуните рисовый лист всего на пять секунд; он должен оставаться упругим, когда вы кладёте его на чуть влажное полотенце, и доразмягчится за время сборки. На ближайшую к вам треть положите небольшой лист салата, несколько листьев мяты и кинзы, щепотку лапши, соломку огурца и ломтик свинины. Загните нижний край на начинку, заверните бока, а перед последним оборотом положите две половинки креветки розовой стороной вниз — они проявятся сквозь рулет. Закатайте плотно, чтобы запечатать. Готовые рулеты накройте влажным полотенцем, чтобы не сохли, и подавайте с соусом хойсин-арахис или nước chấm.","en":"Prep everything before you start rolling — once you begin you can't pause. Cook the rice vermicelli per the packet, rinse under cold water until completely cool, and drain well. Slice the cooked pork belly thinly; have the cooked prawns split lengthwise so the pink side faces the wrapper for presentation. Cut the cucumber into matchsticks. Pile the herbs, lettuce leaves with their stems removed, vermicelli, cucumber and proteins on a tray within easy reach. Fill a shallow bowl with warm — not hot — water. Dip one rice paper for just five seconds; it should still feel firm when you lay it on a slightly damp tea towel, and it will finish softening as you build the roll. On the third closest to you, lay a small lettuce leaf, then a few mint and coriander leaves, a pinch of vermicelli, cucumber matchsticks and a slice of pork. Fold the bottom edge up over the filling, then fold the two sides in, and as you start the final roll lay two prawn halves pink-side-down on the wrapper so they show through the finished roll. Roll tightly to seal. Cover finished rolls with a damp cloth so they don't dry, and serve with hoisin-peanut sauce or nước chấm."}},{"id":227,"tipType":"fish","pairingsType":"seafood","origin":{"ru":"Средиземноморье","en":"Mediterranean","ro":"Mediterana"},"name":{"ru":"Дорада на гриле","en":"Grilled Sea Bream","ro":"Dorada la grătar"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["2 целые дорады (около 500 г каждая)","2 лимона","4 зубчика чеснока","свежий укроп и петрушка","тимьян","оливковое масло экстра вирджин","крупная соль","свежемолотый чёрный перец"],"en":["2 whole sea bream (about 500 g each)","2 lemons","4 garlic cloves","fresh dill and parsley","thyme","extra-virgin olive oil","coarse salt","freshly ground black pepper"],"ro":["2 dorade întregi (cca 500 g fiecare)","2 lămâi","4 căței usturoi","mărar și pătrunjel proaspăt","cimbru","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt"]},"howIsMade":{"ru":"Купите самую свежую дораду, какую найдёте — ясные глаза, ярко-красные жабры, упругое мясо, которое возвращается под пальцем. Очистите от чешуи и выпотрошите, если торговец этого не сделал, оставив голову и хвост. Острым ножом сделайте по три диагональных надреза на коже с каждой стороны, почти до хребта — они позволяют жару проникать ровно и не дают коже скручиваться на решётке. Щедро посолите внутри брюха и по коже за двадцать минут до жарки, чтобы соль успела приправить мясо и подсушить поверхность для хрустящей корочки. Набейте брюхо ломтиками лимона, раздавленным чесноком, укропом, петрушкой и веточками тимьяна. Снаружи смажьте оливковым маслом extra virgin. Разожгите жаркие угли и жарьте по 6–8 минут с каждой стороны, переворачивая лишь когда рыба чисто отстаёт от решётки — иначе сорвёте кожу. Мясо готово, когда отделяется от кости кончиком вилки. Снимите с огня, дайте две минуты отдыха и вынесите рыбу целиком на доске, с дольками лимона, струёй нового масла и греческим салатом рядом.","en":"Buy the freshest sea bream you can find — clear eyes, bright red gills, firm flesh that springs back when pressed. Scale and gut the fish if your fishmonger hasn't, leaving head and tail on. With a sharp knife, score three diagonal slashes through the skin on each side, almost to the bone — they let the heat penetrate evenly and stop the skin from curling on the grill. Salt generously inside the cavity and on the skin, twenty minutes before cooking, so the salt has time to season the flesh and dry the surface for crisp browning. Stuff the belly with lemon slices, smashed garlic cloves, dill, parsley and a few sprigs of thyme. Brush the outside with extra-virgin olive oil. Build a hot charcoal fire and grill 6–8 minutes per side, flipping only when the fish releases cleanly from the grate — force it and the skin tears. The flesh is ready when it lifts off the bone with the tip of a fork. Rest two minutes off the heat, then carry the whole fish to the table on a board with extra lemon wedges, a drizzle of new olive oil, and a Greek salad alongside."}},{"id":228,"tipType":"fish","pairingsType":"seafood","origin":{"ru":"Франция","en":"France","ro":"Franța"},"name":{"ru":"Сибас по-провансальски","en":"Sea Bass Provençal","ro":"Lup de mare provensal"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["2 филе сибаса (около 200 г каждое)","400 г черри-помидоров","12 чёрных маслин Niçoise","2 зубчика чеснока","1 ст. л. каперсов","1 веточка розмарина","свежий тимьян","оливковое масло, сухое белое вино","соль, перец, базилик"],"en":["2 sea bass fillets (about 200 g each)","400 g cherry tomatoes","12 black Niçoise olives","2 garlic cloves","1 tbsp capers","1 sprig rosemary","fresh thyme","olive oil, dry white wine","salt, pepper, basil"],"ro":["2 fileuri de lup de mare (cca 200 g fiecare)","400 g roșii cherry","12 măsline negre Niçoise","2 căței usturoi","1 lingură capere","1 ramură rozmarin","cimbru proaspăt","ulei de măsline, vin alb sec","sare, piper, busuioc"]},"howIsMade":{"ru":"Начните с рыбы: если используете филе с кожей, достаньте его из холодильника за тридцать минут, чтобы оно дошло до комнатной температуры, и тщательно обсушите каждый кусок бумажными полотенцами — холодная и мокрая рыба готовится неравномерно и не подрумянится. Слегка посолите с обеих сторон и отложите. Разогрейте духовку до 200°C. В широкую, смазанную маслом форму выложите помидоры черри половинками срезом вверх, целые маслины Niçoise, промытые каперсы, несколько тонко нарезанных зубчиков чеснока, веточки тимьяна и одну веточку розмарина. Щедро полейте оливковым маслом, влейте бокал сухого белого вина, приправьте солью и свежемолотым перцем. Отправьте в духовку на десять минут — помидоры должны лопнуть и отдать сок, вино выпарится наполовину, а чеснок потеряет резкость; так строится ароматная подстилка, которая примет рыбу. Выньте форму, выложите филе кожей вверх между помидорами и польните сверху ложкой соуса со дна. Верните в духовку на восемь-десять минут, пока мякоть не станет матовой и не начнёт расслаиваться от кончика вилки, а кожа не получит несколько золотистых пятен. Проверьте центр кончиком ножа: если он входит без сопротивления — готово. Дайте отдохнуть две минуты, посыпьте порванными руками листьями базилика и подайте форму к столу с хрустящим хлебом, чтобы вымакивать провансальский соус — без него половина блюда останется в форме.","en":"Start with the fish: if using skin-on fillets, take them out of the fridge thirty minutes ahead to temper, and pat each piece bone-dry with kitchen paper — cold, wet fish cooks unevenly and won't brown. Salt lightly on both sides and set aside. Heat the oven to 200°C. In a wide oiled dish, lay halved cherry tomatoes cut-side up, whole Niçoise olives, rinsed capers, a few thinly sliced garlic cloves, thyme sprigs and a single sprig of rosemary. Drizzle generously with more olive oil, pour in a glass of dry white wine, season with salt and freshly cracked pepper. Slide into the oven for ten minutes — the tomatoes need to burst and release their juices, the wine reduces by half, and the garlic loses its sharpness; this is how the aromatic bed for the fish is built. Pull the dish out, lay the fillets skin-up among the tomatoes and spoon some of the pan juices over them. Return for eight to ten minutes, until the flesh turns opaque and flakes at the tip of a fork, and the skin takes on a few golden patches. Check the centre with a knife tip: if it slides in without resistance, it is done. Rest two minutes, scatter torn basil leaves on top, and bring the dish to the table with crusty bread to mop the Provençal sauce — without it, half the meal stays in the pan."}},{"id":229,"tipType":"meat","pairingsType":"italian","origin":{"ru":"Италия","en":"Italy","ro":"Italia"},"name":{"ru":"Курица алла дьявола","en":"Roast Chicken Diavola","ro":"Pui la cuptor alla diavola"},"category":{"ru":"Ужин","en":"Dinner","ro":"Cină"},"ingredients":{"ru":["1 целая курица, распластанная (спатчкок)","4 зубчика чеснока, раздавленных","2 ст. л. хлопьев чили (пеперончино)","1 ч. л. копчёной паприки","1 лимон (сок и цедра)","3 ст. л. оливкового масла","тимьян и розмарин","крупная соль, чёрный перец"],"en":["1 whole chicken, spatchcocked","4 garlic cloves, crushed","2 tbsp crushed chilli flakes (peperoncino)","1 tsp smoked paprika","1 lemon (juice and zest)","3 tbsp olive oil","thyme and rosemary","coarse salt, black pepper"],"ro":["1 pui întreg, despicat (spatchcocked)","4 căței usturoi zdrobiți","2 linguri ardei iute zdrobit (peperoncino)","1 linguriță boia afumată","1 lămâie (suc și coajă)","3 linguri ulei de măsline","cimbru și rozmarin","sare grunjoasă, piper negru"]},"howIsMade":{"ru":"Распластайте курицу (спатчкок), если мясник этого не сделал: положите грудкой вниз, прочными кухонными ножницами вырежьте позвоночник по обеим сторонам, переверните и сильно надавите на грудину, пока она не хрустнет и птица не ляжет плоско. В широкой миске взбейте оливковое масло, раздавленный чеснок, копчёную паприку, крупную соль, сок и цедру лимона и дерзкое количество хлопьев чили — вся личность блюда. Втирайте маринад с обеих сторон и в каждую складку кожи, затем оставьте на час при комнатной температуре или на ночь в холодильнике для более глубокого пропитывания. Разогрейте духовку до 220°C с тяжёлым противнем внутри, чтобы курица попала на шипящую поверхность. Положите курицу кожей вверх на раскалённый противень и придавите второй тяжёлой сковородой или кирпичом в фольге — настоящий пресс диавола, прижимающий кожу к жару для максимальной хрусткости. Запекайте 35–40 минут, пока кожа не станет цвета красного дерева, а термометр в бедре у кости не покажет 75°C. Дайте десять минут отдохнуть под фольгой, разделите по суставам и подавайте с дольками лимона, поливая соком со сковороды.","en":"Spatchcock the chicken if your butcher hasn't: lay it breast-down, snip out the backbone along both sides with sturdy kitchen shears, flip and press firmly on the breastbone until it cracks and the bird lies flat. In a wide bowl whisk olive oil, crushed garlic, smoked paprika, coarse salt, lemon juice and zest, and a defiant amount of crushed chilli flakes — the dish's whole personality. Rub the marinade into both sides and into every fold of the skin, then leave the bird at least one hour at room temperature, or overnight covered in the fridge for deeper penetration. Heat the oven to 220°C with a heavy roasting tray inside, so the chicken hits a sizzling surface. Lay the chicken skin-up on the hot tray and weigh it down with a second heavy pan or a foil-wrapped brick — the authentic diavola press, which forces the skin into contact with the heat for maximum crispness. Roast 35–40 minutes until the skin is mahogany and a probe in the thigh near the bone reads 75°C. Rest ten minutes loosely tented with foil, carve through the joints, and serve with extra lemon wedges and the pan juices spooned over."}}];export default recipes;